INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (1, 91, 'セルフブランディング', '選ばれる営業になる', '{"icon": "star", "name": "ブランド構築者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["がむしゃらに頑張る", "数字で現状を把握", "転職を考える", "休む"], "question": "スランプ脱出の第一歩は？", "explanation": "感覚ではなく数字で現状を把握することが第一歩でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 指名される営業", "content": "（ある日、電話が鳴る）\n\n電話の相手:「山本さんをお願いしたいのですが」\n\n受付:「山本ですね。少々お待ちください」\n\n（同じ日、もう1件）\n\n電話の相手:「山本さんにお会いしたくて」\n\n健太:「先輩、また指名ですか...\n　　どうしてそんなに指名されるんですか？」\n\n山本先輩:「セルフブランディングを意識してるからかな」\n\n健太:「セルフブランディング...？」\n\n山本先輩:「『あの営業さんから買いたい』と\n　　　思ってもらえるように、\n　　　自分をブランド化することだよ」", "duration": 45}, {"title": "シーン2: なぜセルフブランディングが重要か", "content": "山本先輩:「今の時代、セルフブランディングが重要な理由がある」\n\n【セルフブランディングが重要な理由】\n\n1️⃣ 商品の差別化が難しい時代\n同じような商品・サービスが溢れている\n\n2️⃣ 「誰から買うか」が決め手になる\n信頼できる人から買いたいというニーズ\n\n3️⃣ 価格競争から脱却できる\n「この人から買いたい」は価格を超える\n\n4️⃣ 紹介が増える\n「○○さんに相談するといいよ」と言われる存在になれる\n\n山本先輩:「商品力だけじゃなく、\n　　　『人』で選ばれる時代なんだ」", "duration": 45}, {"title": "シーン3: セルフブランドの3要素", "content": "山本先輩:「セルフブランドは3つの要素でできている」\n\n【セルフブランドの3要素】\n\n1️⃣ 専門性（What）\n何の専門家か？\n「中古車販売店のIT導入なら○○さん」\n「自動車業界の業務効率化の専門家」\n\n2️⃣ 人柄（Who）\nどんな人か？\n誠実、親身、明るい、頼りになる、話しやすい\n\n3️⃣ 約束（Promise）\n何を約束するか？\n「必ず成果を出す」「最後まで責任を持つ」\n「困った時はいつでも相談に乗る」\n\n山本先輩:「この3つが明確で一貫していると、\n　　　『この人に頼みたい』と思われる」", "duration": 50}], "part2": [{"title": "シーン4: セルフブランディングの実践", "content": "健太:「具体的にどうすればいいですか？」\n\n山本先輩:「5つのステップで実践しよう」\n\n【セルフブランディング実践5ステップ】\n\n① 自分の強みを棚卸しする\n過去の成功体験、顧客からの感謝、得意な領域を書き出す\n\n② 一言で表現する\n「○○の専門家」「△△ならお任せください」という\nキャッチフレーズを作る\n\n③ 一貫性を持つ\n名刺、メール署名、SNS、会話で一貫したメッセージを発信\n\n④ 発信する\n業界知識、ノウハウ、成功事例を発信\nメール、SNS、勉強会などで\n\n⑤ 実績を積む\nブランドは実績で裏付けられる\n成功事例を増やし、信頼を高める", "duration": 50}, {"title": "シーン5: 健太のセルフブランド構築", "content": "（1週間後、健太が山本先輩に相談）\n\n健太:「先輩、考えてみました。\n　　僕の強みは...」\n\n【健太のセルフブランド】\n専門性: 中古車販売店向けDX支援\n人柄: 親身で粘り強い、困った時に頼りになる\n約束: 導入後も伴走し、必ず成果につなげる\n\nキャッチフレーズ:\n「中古車販売店のDXパートナー、佐々木です」\n\n山本先輩:「いいじゃないか。\n　　　これを名刺、メール署名、\n　　　商談の自己紹介で一貫して使え。\n　　　あと、業界の情報を定期的に発信しろ」\n\n健太:「毎週、業界ニュースをまとめて\n　　顧客にメールしてみます」", "duration": 45}, {"title": "シーン6: ブランドの確立", "content": "（6ヶ月後）\n\n新規顧客:「佐々木さん、評判聞きましたよ。\n　　　　中古車販売店に詳しいって」\n\n健太:「ありがとうございます！」\n\n（別の日、紹介の電話）\n\n紹介者:「佐々木さんに相談するといいよって\n　　　言われて、電話しました」\n\n（オフィスで）\n\n山本先輩:「指名が増えてきたな」\n\n健太:「はい！『中古車DXなら佐々木』って\n　　覚えてもらえてるみたいです」\n\n山本先輩:「それがセルフブランディングの成果だ。\n　　　商品じゃなく、君自身が選ばれてる」\n\n【今日の学び】\n「選ばれる営業になる」", "duration": 35}]}', '{"title": "セルフブランドの3要素", "content": "1. 専門性（What）: 何の専門家か\n2. 人柄（Who）: どんな人か\n3. 約束（Promise）: 何を約束するか", "audioText": "セルフブランディングとは、自分自身を「選ばれる存在」として確立することです。専門性、人柄、約束の3要素を明確にしましょう。", "highlight": "一貫したメッセージを発信し続け、実績で裏付ける"}', '[{"options": ["商品が売れるから", "「誰から買うか」が決め手になる時代だから", "上司に褒められるから", "転職に有利だから"], "question": "セルフブランディングが重要な理由は？", "explanation": "同じような商品が溢れる時代、「人」で選ばれることが重要です。", "correctIndex": 1}, {"options": ["価格・品質・納期", "専門性・人柄・約束", "学歴・経験・資格", "見た目・話し方・名刺"], "question": "セルフブランドの3要素は？", "explanation": "専門性（What）、人柄（Who）、約束（Promise）の3要素です。", "correctIndex": 1}]', '{"text": "Your brand is what other people say about you when you''re not in the room.", "author": "ジェフ・ベゾス", "textJa": "ブランドとは、あなたがいない部屋で人々があなたについて何を言うかである。"}', '[{"options": [{"text": "「ファブリカホールディングスの佐々木です」", "points": 5, "feedback": "会社名と名前だけでは印象に残りません。", "isCorrect": false}, {"text": "「中古車販売店のDXを支援している佐々木です。御社の業務効率化のお手伝いをさせてください」", "points": 30, "feedback": "専門性と提供価値が伝わる良い自己紹介です。", "isCorrect": true}, {"text": "「10年のベテラン営業、佐々木です」", "points": 10, "feedback": "経験年数より、何ができるかを伝えましょう。", "isCorrect": false}], "situation": "初めての顧客との商談で自己紹介します。", "customerLine": "初めまして。今日はよろしくお願いします"}, {"options": [{"text": "自社製品の宣伝ばかり", "points": 0, "feedback": "宣伝ばかりでは読まれなくなります。価値ある情報を発信しましょう。", "isCorrect": false}, {"text": "業界ニュース、成功事例、お役立ち情報", "points": 30, "feedback": "顧客にとって価値ある情報発信がブランド構築につながります。", "isCorrect": true}, {"text": "プライベートの話題", "points": 5, "feedback": "専門性を示す情報を優先しましょう。", "isCorrect": false}], "situation": "顧客に定期的な情報発信をしようと思います。何を発信しますか？", "customerLine": "（発信内容を選ぶ場面）"}]', '{"question": "あなたは顧客からどんな存在として認識されていますか？理想の認識は？", "placeholder": "例: 今は「システム屋さん」。理想は「業務改善の相談相手」として認識されたい"}', '["自分のキャッチフレーズを作り、自己紹介で使う", "名刺、メール署名に専門性を入れる", "顧客に定期的に価値ある情報を発信する", "成功事例を積み重ね、ブランドを裏付ける"]', '{"title": "セルフブランド設計シート", "fields": [{"label": "専門性（What）: 何の専門家か", "placeholder": "例: 中古車販売店向けDX支援、業務効率化"}, {"label": "人柄（Who）: どんな人か", "placeholder": "例: 親身、粘り強い、頼りになる、明るい"}, {"label": "約束（Promise）: 何を約束するか", "placeholder": "例: 導入後も伴走し、必ず成果につなげる"}, {"label": "キャッチフレーズ（一言で表現）", "placeholder": "例: 中古車販売店のDXパートナー"}], "description": "あなたのセルフブランドを設計しましょう。"}', NULL, '2026-01-21 17:45:11.729609+00', '2026-01-21 17:45:11.729609+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (2, 92, '高度な交渉シミュレーション', 'Win-Winを創り出す交渉力', '{"icon": "scale", "name": "交渉の達人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["価格・品質・納期", "専門性・人柄・約束", "学歴・経験・資格", "見た目・話し方・名刺"], "question": "セルフブランドの3要素は？", "explanation": "専門性（What）、人柄（Who）、約束（Promise）でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 難航する交渉", "content": "（商談終了後、疲れた様子の健太）\n\n健太:「先輩、今日の商談、\n　　価格交渉がきつかったです...\n　　20%値引きを要求されて、\n　　結局15%で合意しましたけど...」\n\n山本先輩:「その値引き、必要だったか？」\n\n健太:「え？お客さんが『高い』って\n　　言うから...」\n\n山本先輩:「『高い』と言われたら\n　　すぐ値引きするのは、\n　　交渉じゃない。譲歩だ。\n　　交渉の基本を教えよう」", "duration": 45}, {"title": "シーン2: 交渉の基本原則", "content": "山本先輩:「交渉には4つの基本原則がある」\n\n【交渉の4つの基本原則】\n\n1️⃣ 人と問題を分離する\n相手を攻撃するのではなく、問題に焦点を当てる\n\n2️⃣ 立場ではなく利害に焦点を当てる\n「何が欲しいか」ではなく「なぜ欲しいか」を探る\n「10%値引き」→「なぜ値引きが必要か？」\n\n3️⃣ お互いの利益になる選択肢を生み出す\nパイを奪い合うのではなく、パイを大きくする\n\n4️⃣ 客観的な基準を使う\n感情ではなく、市場価格、前例、公平な基準で判断\n\n山本先輩:「交渉は『勝ち負け』じゃない。\n　　　　『Win-Win』を創り出すことだ」", "duration": 50}, {"title": "シーン3: BATNA - 交渉の代替案", "content": "山本先輩:「交渉で最も重要な概念を教えよう。\n　　　　BATNAだ」\n\n【BATNAとは】\nBest Alternative To a Negotiated Agreement\n= 交渉が決裂した場合の最善の代替案\n\n【BATNAの重要性】\n自分のBATNAが強い → 強気の交渉ができる\n自分のBATNAが弱い → 譲歩が必要になる\n\n山本先輩:「さっきの商談、\n　　　　お客さんのBATNAは何だった？」\n\n健太:「...競合のA社ですかね？」\n\n山本先輩:「そう。A社の条件がわかっていれば、\n　　　　どこまで譲歩すべきか判断できた。\n　　　　交渉前に、相手のBATNAを把握しておくことが大事だ」", "duration": 50}], "part2": [{"title": "シーン4: シナリオ別の対応", "content": "山本先輩:「よくある交渉シナリオと対応を教えよう」\n\n【価格交渉】\n「高い」と言われたら...\n→ 価格の根拠（価値）を説明\n→ 単純な値引きではなく、条件交換を提案\n　「長期契約いただければ、10%オフ可能です」\n\n【競合比較】\n「A社の方が安い」と言われたら...\n→ 競合の悪口は言わない\n→ 自社の強み、顧客の課題との適合性で勝負\n　「A社さんも良い製品ですが、御社の課題には弊社が最適です」\n\n【クレーム対応】\nまず謝罪と共感 → 原因と対策を説明\n→ 逃げずに向き合う姿勢が大切\n\n【納期・条件交渉】\nできないことは正直に伝える\n→ 代替案を提示\n　「その納期は難しいですが、○○なら可能です」", "duration": 55}, {"title": "シーン5: 交渉シミュレーション", "content": "山本先輩:「ロールプレイしてみよう。\n　　　　俺がお客さん役をやる」\n\n山本先輩（顧客役）:「御社の見積もり、\n　　　　　　　　高すぎるよ。20%引いてくれ」\n\n健太:「ご検討ありがとうございます。\n　　20%の値引きのご要望ですね。\n　　ちなみに、どのような点で高いと感じられましたか？」\n\n山本先輩:「A社は御社より15%安いんだよ」\n\n健太:「A社さんですね。\n　　弊社の価格には、24時間サポートと\n　　導入後3ヶ月の伴走支援が含まれています。\n　　A社さんの条件はいかがですか？」\n\n山本先輩:「...サポートは別料金だな」\n\n健太:「でしたら、トータルコストで\n　　比較いただけますか？\n　　また、3年契約いただければ、\n　　10%のお値引きは可能です」\n\n山本先輩:「（素に戻って）いいね。\n　　　　価値を説明して、条件交換を提案できた」", "duration": 55}, {"title": "シーン6: 交渉の達人へ", "content": "（後日、健太の商談後）\n\n健太:「先輩！今日の交渉、\n　　値引きなしで契約取れました！」\n\n山本先輩:「どうやった？」\n\n健太:「『高い』と言われた時、\n　　すぐ値引きせずに理由を聞きました。\n　　そしたら、導入後のサポートが\n　　心配だったみたいで...\n　　サポート体制を詳しく説明したら、\n　　納得いただけました」\n\n山本先輩:「価格じゃなく、価値で勝負できたな。\n　　　　それがWin-Winの交渉だ」\n\n【今日の学び】\n「Win-Winを創り出す交渉力」", "duration": 35}]}', '{"title": "交渉の4つの基本原則", "content": "1. 人と問題を分離する\n2. 立場ではなく利害に焦点を当てる\n3. お互いの利益になる選択肢を生み出す\n4. 客観的な基準を使う", "audioText": "交渉の目的は相手を負かすことではなく、お互いが満足する解決策を見つけることです。", "highlight": "交渉は勝ち負けではなく、Win-Winを創り出すこと"}', '[{"options": ["Best Agreement for Total Negotiation Ability", "Best Alternative To a Negotiated Agreement", "Basic Approach To Negotiation Advantage", "Business And Trade Negotiation Alliance"], "question": "BATNAとは何の略？", "explanation": "Best Alternative To a Negotiated Agreement = 交渉が決裂した場合の最善の代替案です。", "correctIndex": 1}, {"options": ["すぐ値引きする", "「高くない」と反論する", "なぜ高いと感じるか理由を聞く", "商談を終える"], "question": "「高い」と言われた時の最適な対応は？", "explanation": "理由を聞くことで、価格以外の懸念（サポート、品質など）が見つかることがあります。", "correctIndex": 2}]', '{"text": "The most important thing in negotiation is to put yourself in the other person''s shoes.", "author": "ハーバード流交渉術より", "textJa": "交渉において最も重要なのは、相手の靴を履いてみることだ。相手の立場を理解して初めて、Win-Winの解決策が見えてくる。"}', '[{"options": [{"text": "「わかりました、20%引きます」", "points": 0, "feedback": "すぐ譲歩すると、さらに値引きを求められることがあります。", "isCorrect": false}, {"text": "「20%は無理です」と断る", "points": 5, "feedback": "断るだけでは交渉が進みません。理由を聞きましょう。", "isCorrect": false}, {"text": "「20%のご要望ですね。どのような点で高いと感じられましたか？」", "points": 30, "feedback": "理由を聞くことで、本当の懸念を把握できます。", "isCorrect": true}], "situation": "顧客から「20%値引きしてほしい」と言われました。", "customerLine": "御社の見積もり、20%値引きしてもらえないかな"}, {"options": [{"text": "「A社は品質が悪いですよ」", "points": 0, "feedback": "競合の悪口は信頼を失います。", "isCorrect": false}, {"text": "「15%値引きします」", "points": 5, "feedback": "価格だけで勝負すると利益を失います。価値で差別化しましょう。", "isCorrect": false}, {"text": "「A社さんの条件にはサポートは含まれていますか？トータルコストで比較いただけますか」", "points": 30, "feedback": "価格以外の価値を含めた比較を促す良い対応です。", "isCorrect": true}], "situation": "「競合A社の方が15%安い」と言われました。", "customerLine": "A社は御社より15%安いんだよね"}, {"options": [{"text": "「やってみます！」と安請け合いする", "points": 0, "feedback": "できない約束は信頼を失います。", "isCorrect": false}, {"text": "「無理です」と断る", "points": 5, "feedback": "断るだけでなく、代替案を提示しましょう。", "isCorrect": false}, {"text": "「来週月曜は難しいですが、水曜なら可能です。また、先行して一部機能を月曜にお渡しすることは可能ですが、いかがですか」", "points": 30, "feedback": "正直に伝えつつ、代替案を提示する良い交渉です。", "isCorrect": true}], "situation": "「来週までに納品してほしい」と無理な納期を求められました。", "customerLine": "来週の月曜には使いたいんだ。間に合う？"}]', '{"question": "最近の交渉で「もっとうまくできた」と思う場面はありますか？", "placeholder": "例: すぐ値引きしてしまった。次回は理由を聞いて、価値を説明してから条件交換を提案する"}', '["「高い」と言われたら、まず理由を聞く", "値引きの前に条件交換を提案する", "交渉前に相手と自分のBATNAを把握する", "競合の悪口を言わず、自社の価値で勝負する"]', '{"title": "交渉準備シート", "fields": [{"label": "相手のBATNA（代替案）は何か", "placeholder": "例: 競合A社の提案、現状維持、内製化"}, {"label": "自分のBATNA（代替案）は何か", "placeholder": "例: 他の見込み客、条件変更の余地、長期契約提案"}, {"label": "価格以外で提供できる価値", "placeholder": "例: 24時間サポート、導入伴走、追加トレーニング、保証延長"}, {"label": "条件交換の選択肢", "placeholder": "例: 長期契約で10%オフ、一括払いで5%オフ、紹介で特典"}], "description": "次回の交渉に向けて準備しましょう。"}', NULL, '2026-01-21 17:45:13.026072+00', '2026-01-21 17:45:13.026072+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (3, 93, '1on1面談設計', '1on1は部下のための時間', '{"icon": "users", "name": "1on1マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["価格・品質・納期", "専門性・人柄・約束", "学歴・経験・資格", "見た目・話し方・名刺"], "question": "セルフブランドの3要素は？", "explanation": "専門性（What）、人柄（Who）、約束（Promise）でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 形だけの1on1", "content": "（マネージャーに昇進した山本）\n\n山本:「鈴木課長、部下との1on1を始めたんですが、\n　　何を話せばいいかわからなくて...」\n\n鈴木課長:「今はどんな感じでやってる？」\n\n山本:「『最近どう？』って聞いて、\n　　業務の進捗を確認して、\n　　気づいたらほとんど俺が話してて...」\n\n鈴木課長:「それは1on1じゃなく、\n　　　業務報告会になってるな」\n\n山本:「え...？」\n\n鈴木課長:「1on1は『部下のための時間』だ。\n　　　上司が話す場じゃない」", "duration": 45}, {"title": "シーン2: 1on1の目的", "content": "鈴木課長:「1on1の目的を整理しよう」\n\n【1on1の目的】\n\n1️⃣ 部下の成長支援\nキャリア、スキルアップの相談\n\n2️⃣ 信頼関係の構築\n何でも話せる関係を作る\n\n3️⃣ 早期の問題発見\n困っていることを早めにキャッチ\n\n4️⃣ モチベーション向上\n承認、感謝、期待を伝える\n\n5️⃣ 心理的安全性の醸成\n本音で話せる環境を作る\n\n鈴木課長:「業務報告を聞くだけなら、\n　　　メールやチャットで済む。\n　　　1on1はもっと深い話をする場だ」", "duration": 50}, {"title": "シーン3: 効果的な1on1の設計", "content": "鈴木課長:「効果的な1on1の設計を教えよう」\n\n【1on1の設計ポイント】\n\n頻度: 週1回または隔週\n　→ 月1回では少なすぎる。問題が溜まる\n\n時間: 30分〜1時間\n　→ 短すぎると深い話ができない\n\n場所: 個室やオンライン\n　→ 周囲を気にせず話せる環境\n\nアジェンダ: 部下が主体的に設定\n　→ 上司が決めるのではなく、部下に考えさせる\n\n記録: 話した内容と次のアクションをメモ\n　→ 継続性を持たせる。約束を忘れない\n\n鈴木課長:「特に大事なのは『部下が話す時間』を\n　　　確保すること。8割は部下が話すくらいでいい」", "duration": 50}], "part2": [{"title": "シーン4: 話すべきテーマ", "content": "山本:「具体的に何を話せばいいですか？」\n\n鈴木課長:「5つのテーマを意識するといい」\n\n【1on1で話すべき5つのテーマ】\n\n1️⃣ 業務の進捗・課題\n「困っていることはない？」\n「何かサポートできることは？」\n\n2️⃣ キャリア・成長\n「どんなスキルを伸ばしたい？」\n「半年後、どうなっていたい？」\n\n3️⃣ 人間関係\n「チームメンバーとの関係はどう？」\n「誰かと困っていることはない？」\n\n4️⃣ 体調・メンタル\n「最近の調子はどう？」\n「睡眠は取れてる？」\n\n5️⃣ 会社・チームへの意見\n「改善してほしいことはある？」\n「チームに対して思うことは？」", "duration": 50}, {"title": "シーン5: 上司の姿勢", "content": "鈴木課長:「1on1での上司の姿勢が大事だ」\n\n【NGな姿勢】❌\n「最近どう？」で始まり、上司が8割話す\n業務報告を求める\nアドバイスをすぐにする\nスマホを見ながら聞く\n時間を守らない（遅刻、早めに切り上げ）\n\n【OKな姿勢】✅\n「今日話したいことは？」で始まり、部下が8割話す\n傾聴に徹する\n質問で考えを引き出す\n目を見て聴く\n時間を確保し、集中する\n\n鈴木課長:「俺も最初は話しすぎてた。\n　　　『聴く』ことに徹するのは難しいけど、\n　　　意識すれば変われる」", "duration": 45}, {"title": "シーン6: 山本の1on1改善", "content": "（1ヶ月後）\n\n健太:「山本さん、最近の1on1、\n　　すごく話しやすくなりました」\n\n山本:「そうか？何が変わった？」\n\n健太:「前は報告を求められてる感じでしたけど、\n　　今は『聴いてもらえてる』って感じます。\n　　キャリアの相談もできるようになって...」\n\n山本:「よかった。俺も意識して\n　　聴く側に回るようにしたんだ」\n\n（鈴木課長に報告）\n\n鈴木課長:「いいね。部下が『話しやすくなった』と\n　　　　感じてるなら、1on1が機能してる証拠だ」\n\n【今日の学び】\n「1on1は部下のための時間」", "duration": 35}]}', '{"title": "効果的な1on1の設計", "content": "頻度: 週1回または隔週\n時間: 30分〜1時間\n場所: 個室やオンライン\nアジェンダ: 部下が設定\n記録: 内容とアクションをメモ", "audioText": "1on1は業務報告ではなく、部下のための時間です。上司は聴く側に回り、部下が8割話すことを意識しましょう。", "highlight": "上司2割、部下8割。聴くことに徹する"}', '[{"options": ["上司8割、部下2割", "上司5割、部下5割", "上司2割、部下8割", "上司10割"], "question": "1on1で上司と部下の話す割合として適切なのは？", "explanation": "1on1は部下のための時間。部下が8割話すことを目指しましょう。", "correctIndex": 2}, {"options": ["年1回", "四半期に1回", "月1回", "週1回または隔週"], "question": "1on1の適切な頻度は？", "explanation": "週1回または隔週が適切。月1回では問題が溜まってしまいます。", "correctIndex": 3}]', '{"text": "People begin to feel heard when you listen to them with your full attention.", "author": "スティーブン・R・コヴィー", "textJa": "人は話を聞いてもらえたと感じた時、初めて心を開く。"}', '[{"options": [{"text": "「最近どう？」", "points": 10, "feedback": "漠然とした質問では深い話になりません。", "isCorrect": false}, {"text": "「今週の進捗を報告して」", "points": 0, "feedback": "業務報告になってしまいます。1on1は報告の場ではありません。", "isCorrect": false}, {"text": "「今日話したいことはある？」", "points": 30, "feedback": "部下主体の1on1が始められる良い質問です。", "isCorrect": true}], "situation": "部下との1on1が始まりました。最初に何と言いますか？", "customerLine": "（1on1開始の場面）"}, {"options": [{"text": "「じゃあ今日は短めに終わろう」", "points": 5, "feedback": "話すことがないわけではなく、話しにくいのかもしれません。", "isCorrect": false}, {"text": "「最近チームの雰囲気はどう感じてる？」と別の角度から聞く", "points": 30, "feedback": "テーマを変えて質問することで、話を引き出せます。", "isCorrect": true}, {"text": "「じゃあ俺から話すことがあるんだけど...」", "points": 5, "feedback": "上司が話し始めると、部下の時間ではなくなります。", "isCorrect": false}], "situation": "部下が「特に話すことはありません」と言いました。", "customerLine": "特に今日は話すことないです..."}]', '{"question": "現在の1on1で改善すべき点は何ですか？", "placeholder": "例: 自分が話しすぎている。次回から質問を増やして、部下に考えさせる"}', '["週1回または隔週で1on1を設定する", "「今日話したいことは？」で1on1を始める", "聴く側に徹し、部下が8割話すことを目指す", "1on1の内容と次のアクションを記録する"]', '{"title": "1on1設計シート", "fields": [{"label": "頻度と時間", "placeholder": "例: 毎週火曜14時〜14時30分"}, {"label": "話すテーマの例", "placeholder": "例: 業務の課題、キャリア、チームへの意見"}, {"label": "自分が意識すること", "placeholder": "例: 聴く側に徹する、アドバイスを急がない"}], "description": "自分の1on1を設計しましょう。"}', NULL, '2026-01-21 17:45:13.918982+00', '2026-01-21 17:45:13.918982+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (4, 94, '評価・フィードバックの技術', 'フィードバックは育成のツール', '{"icon": "message-circle", "name": "フィードバック名人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["上司8割、部下2割", "上司5割、部下5割", "上司2割、部下8割", "上司10割"], "question": "1on1で上司と部下の話す割合として適切なのは？", "explanation": "1on1は部下のための時間。部下が8割話すことを目指しましょう。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 伝わらないフィードバック", "content": "（評価面談後、落ち込む健太）\n\n山本:「健太、どうした？」\n\n健太:「今日の評価面談で『もっと頑張れ』って\n　　言われたんですけど、\n　　何を頑張ればいいかわからなくて...」\n\n山本:「具体的に何を改善すべきか、\n　　言われなかったのか？」\n\n健太:「『全体的にもう少し』とか\n　　『積極性が足りない』とか...」\n\n山本:「それは困るな。\n　　俺も昔、同じ経験をした。\n　　だから、フィードバックの技術を\n　　ちゃんと学んだんだ」", "duration": 45}, {"title": "シーン2: 評価の目的", "content": "山本:「まず、評価の目的を理解しよう」\n\n【評価の4つの目的】\n\n1️⃣ 育成\n強みを伸ばし、弱みを改善する機会を提供\n\n2️⃣ 動機づけ\n努力と成果を認め、モチベーションを高める\n\n3️⃣ 期待の明確化\n何を求められているかを明確にする\n\n4️⃣ 処遇決定（二次的）\n昇給・昇格・賞与の根拠とする\n\n山本:「評価は『査定』じゃなく『育成』のツールだ。\n　　部下が成長するためのフィードバックを\n　　するのが上司の役割なんだ」", "duration": 45}, {"title": "シーン3: フィードバックの基本原則", "content": "山本:「効果的なフィードバックには5つの原則がある」\n\n【フィードバックの5原則】\n\n1️⃣ タイムリー\nできごとの直後に伝える\n→ 時間が経つと効果が薄れる\n\n2️⃣ 具体的\n「良かった」ではなく\n「○○の場面で△△したのが良かった」\n\n3️⃣ 行動に焦点\n人格ではなく行動を対象にする\n× 「君は怠慢だ」 ○ 「報告が遅れた」\n\n4️⃣ バランス\nポジティブとネガティブのバランス（3:1以上）\n→ 叱るばかりでは聞く耳を持たない\n\n5️⃣ 双方向\n一方的に伝えるのではなく、対話する\n→ 相手の考えも聞く", "duration": 50}], "part2": [{"title": "シーン4: SBI法", "content": "山本:「具体的なフィードバックには『SBI法』を使う」\n\n【SBI法（フィードバックの型）】\n\nS（Situation）状況\nいつ、どこで、どんな場面で\n「先週の商談で」「今日の会議で」\n\nB（Behavior）行動\n具体的に何をしたか\n「顧客の質問に対して、事例を交えて説明していた」\n\nI（Impact）影響\nその行動がどんな影響を与えたか\n「顧客が納得し、契約に繋がった」\n\n山本:「『良かったよ』じゃなく、\n　　『先週の商談で、事例を使って説明したのが\n　　顧客の納得につながった。あれは良かった』\n　　と伝える。これなら何が良かったかわかる」", "duration": 50}, {"title": "シーン5: ネガティブフィードバック", "content": "山本:「難しいのはネガティブフィードバックだな」\n\n【ネガティブフィードバックの伝え方】\n\n1. 人前ではなく、1対1で伝える\n→ 恥をかかせない\n\n2. 人格否定ではなく、行動の改善を求める\n× 「君はダメだ」\n○ 「この行動を改善してほしい」\n\n3. 「なぜできないのか」ではなく「どうすればできるか」\n× 「なんでできないの？」\n○ 「どうすればできそう？」\n\n4. 期待していることを伝える\n「あなたならできると信じている」\n\n5. 改善のサポートを約束する\n「一緒に考えよう」「何かあったら相談して」\n\n山本:「叱るのが目的じゃない。\n　　成長してもらうのが目的だ」", "duration": 50}, {"title": "シーン6: 実践と成果", "content": "（山本が部下にフィードバック）\n\n山本:「健太、先週の提案書の件でフィードバックがある」\n\n健太:「はい...」\n\n山本:「提出期限に間に合わなかった。\n　　お客さんを待たせてしまった。これは改善が必要だ」\n\n健太:「すみません...」\n\n山本:「責めてるんじゃない。\n　　どうすれば期限に間に合わせられそう？」\n\n健太:「...早めに着手して、途中で確認を入れれば...」\n\n山本:「いいね。次回からそうしよう。\n　　途中確認、俺も協力するから。\n　　健太なら絶対できる」\n\n健太:「ありがとうございます！」\n\n【今日の学び】\n「フィードバックは育成のツール」", "duration": 40}]}', '{"title": "SBI法（フィードバックの型）", "content": "S（Situation）: 状況を伝える\nB（Behavior）: 行動を伝える\nI（Impact）: 影響を伝える", "audioText": "フィードバックはSBI法で具体的に。状況、行動、影響を明確に伝えましょう。", "highlight": "具体的な状況・行動・影響を伝えることで、納得感が高まる"}', '[{"options": ["1:1", "1:3", "3:1以上", "10:1"], "question": "ポジティブとネガティブのフィードバックの適切な比率は？", "explanation": "ポジティブ3に対してネガティブ1以上のバランスが効果的です。", "correctIndex": 2}, {"options": ["Business（ビジネス）", "Behavior（行動）", "Benefit（利益）", "Base（基盤）"], "question": "SBI法のBは何を指す？", "explanation": "B=Behavior（行動）。具体的に何をしたかを伝えます。", "correctIndex": 1}]', '{"text": "Feedback is the breakfast of champions.", "author": "ケン・ブランチャード", "textJa": "フィードバックは朝食のチャンピオンである。"}', '[{"options": [{"text": "「よくやった！」", "points": 10, "feedback": "漠然としていて、何が良かったかわかりません。", "isCorrect": false}, {"text": "「今日の商談で、顧客の課題を深掘りした質問が良かった。それで顧客が納得して契約につながったね」", "points": 30, "feedback": "SBI法で具体的にフィードバックできています。", "isCorrect": true}, {"text": "「契約おめでとう。でも次はもっと早く決めてね」", "points": 5, "feedback": "ポジティブフィードバックの後にすぐネガティブを言うと効果が薄れます。", "isCorrect": false}], "situation": "部下が良い成果を出しました。フィードバックします。", "customerLine": "（部下が契約を獲得した場面）"}, {"options": [{"text": "「なんで報告しなかったの？ダメだよ」", "points": 0, "feedback": "責めるだけでは改善につながりません。", "isCorrect": false}, {"text": "「報告が漏れてたね。次からどうすれば忘れないようにできそう？」", "points": 30, "feedback": "行動に焦点を当て、改善策を一緒に考える良いフィードバックです。", "isCorrect": true}, {"text": "みんなの前で指摘する", "points": 0, "feedback": "ネガティブフィードバックは1対1で行いましょう。", "isCorrect": false}], "situation": "部下が報告を忘れていました。フィードバックします。", "customerLine": "（部下が報告を忘れた場面）"}]', '{"question": "最近のフィードバックで「もっと具体的に伝えればよかった」と思う場面はありますか？", "placeholder": "例: 「良かったよ」とだけ言った。次回はSBI法で何が良かったか具体的に伝える"}', '["フィードバックはSBI法で具体的に伝える", "ポジティブ3:ネガティブ1以上のバランスを意識する", "ネガティブフィードバックは1対1で行う", "「どうすればできるか」を一緒に考える"]', '{"title": "SBI法フィードバック作成", "fields": [{"label": "S（状況）: いつ、どこで", "placeholder": "例: 先週の金曜日の商談で"}, {"label": "B（行動）: 具体的に何をしたか", "placeholder": "例: 顧客の質問に対して、事例を3つ挙げて説明していた"}, {"label": "I（影響）: どんな影響があったか", "placeholder": "例: 顧客が納得し、その場で契約の意思表示をしてくれた"}], "description": "部下へのフィードバックをSBI法で作成しましょう。"}', NULL, '2026-01-21 17:45:15.352355+00', '2026-01-21 17:45:15.352355+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (5, 95, '個別育成計画（IDP）の策定', '育成は計画的に', '{"icon": "clipboard", "name": "育成プランナー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Business", "Behavior", "Benefit", "Base"], "question": "SBI法のBは何を指す？", "explanation": "B=Behavior（行動）。具体的に何をしたかを伝えましたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 場当たり的な育成", "content": "（人事部との面談で）\n\n人事:「山本さん、部下の育成計画はありますか？」\n\n山本:「育成計画...ですか？\n　　日々の業務の中で教えてるつもりですが...」\n\n人事:「『つもり』では育成は進みません。\n　　一人ひとりに合わせた\n　　個別育成計画が必要です」\n\n山本:「個別育成計画...」\n\n人事:「IDP（Individual Development Plan）と言います。\n　　部下の強み・課題・キャリア志向を踏まえて、\n　　計画的に育成する方法です」", "duration": 45}, {"title": "シーン2: IDPとは", "content": "人事:「IDPに含める要素を説明しますね」\n\n【IDP（個別育成計画）の要素】\n\n1. 現状の強み・課題\n客観的な評価\n\n2. 目指す姿（6ヶ月後、1年後）\n本人のキャリア志向と組織ニーズをすり合わせ\n\n3. 必要なスキル・経験\n目指す姿に必要なもの\n\n4. 具体的な育成施策\nどうやって育成するか\n\n5. マイルストーン・振り返りタイミング\nいつ、どこで進捗を確認するか\n\n人事:「場当たり的に教えるのではなく、\n　　計画を立てて、振り返りながら育成する。\n　　それがIDPの考え方です」", "duration": 50}, {"title": "シーン3: IDP策定の5ステップ", "content": "人事:「IDP策定は5ステップで行います」\n\n【IDP策定の5ステップ】\n\n1️⃣ 現状把握\n強み、課題、スキルレベルを客観的に評価\n\n2️⃣ 目標設定\n本人のキャリア志向と組織ニーズをすり合わせ\n「1年後にリーダーになりたい」\n「組織としては大型案件を任せたい」\n\n3️⃣ ギャップ分析\n現状と目標のギャップを明確化\n「リーダーには○○が足りない」\n\n4️⃣ 施策立案\nギャップを埋めるための具体的施策を決定\n\n5️⃣ 実行・振り返り\n定期的に進捗を確認し、計画を修正", "duration": 50}], "part2": [{"title": "シーン4: 70:20:10の法則", "content": "人事:「育成施策を考える時、\n　　70:20:10の法則を意識してください」\n\n【育成の70:20:10の法則】\n\n70%: 経験（OJT）\n実際の仕事を通じた学び\n・挑戦的なアサインメント\n・プロジェクト参加\n・新しい業務への挑戦\n\n20%: 他者からの学び\n上司・先輩からのフィードバック\n・メンタリング\n・ロールモデルの観察\n\n10%: 研修・自己学習\n・集合研修、eラーニング\n・読書、資格取得\n\n人事:「研修だけでは育たない。\n　　70%は経験から学ぶ。\n　　だから、挑戦的なアサインメントが重要なんです」", "duration": 50}, {"title": "シーン5: 健太のIDP作成", "content": "（山本が健太のIDPを作成）\n\n山本:「健太、一緒にIDPを作ろう」\n\n【健太のIDP】\n\n現状:\n・強み: 顧客対応力、粘り強さ\n・課題: 大型案件の経験不足、提案書作成スキル\n\n目指す姿（1年後）:\n・大型案件を一人で担当できる\n・後輩に教えられる\n\nギャップ:\n・大型案件の経験\n・複数ステークホルダーへの対応力\n\n育成施策:\n・70%（経験）: 大型案件への同行、サブ担当として参加\n・20%（他者）: 山本からの週次フィードバック\n・10%（研修）: 提案書作成研修の受講\n\n振り返り: 月1回の1on1で進捗確認", "duration": 50}, {"title": "シーン6: IDPの効果", "content": "（6ヶ月後）\n\n健太:「山本さん、大型案件、\n　　一人で提案書作れるようになりました！」\n\n山本:「成長したな。IDPで計画したことが\n　　ちゃんと身についてる」\n\n健太:「最初は大型案件怖かったですけど、\n　　同行から始めて、少しずつ任せてもらえて...\n　　段階的に経験できたのが良かったです」\n\n山本:「それがIDPの効果だ。\n　　場当たり的にやってたら、\n　　こんなに早く成長できなかった。\n　　計画を立てて、振り返りながら育成する。\n　　それが部下を伸ばす秘訣だ」\n\n【今日の学び】\n「育成は計画的に」", "duration": 35}]}', '{"title": "育成の70:20:10の法則", "content": "70%: 経験（OJT、挑戦的アサインメント）\n20%: 他者からの学び（フィードバック、メンタリング）\n10%: 研修・自己学習", "audioText": "人の成長の70%は経験から。挑戦的な仕事を任せることが最も効果的な育成です。", "highlight": "研修だけでは育たない。70%は経験から。挑戦的なアサインメントが重要"}', '[{"options": ["研修", "他者からの学び", "経験（OJT）", "自己学習"], "question": "70:20:10の法則で最も大きな割合を占めるのは？", "explanation": "70%は経験から学びます。挑戦的なアサインメントが最も効果的です。", "correctIndex": 2}, {"options": ["研修を決める", "現状把握", "目標設定", "施策立案"], "question": "IDP策定で最初にすべきことは？", "explanation": "まず現状（強み、課題、スキルレベル）を客観的に把握します。", "correctIndex": 1}]', '{"text": "The greatest leader is not the one who does great things, but the one who gets others to do great things.", "author": "ピーター・ドラッカー", "textJa": "優れたリーダーは、部下の強みを活かし、弱みを無力化する。"}', '[{"options": [{"text": "研修をたくさん受けさせる", "points": 10, "feedback": "研修は10%。経験（70%）を重視しましょう。", "isCorrect": false}, {"text": "挑戦的な仕事を任せ、フィードバックを行う", "points": 30, "feedback": "経験（70%）と他者からの学び（20%）を組み合わせた良い施策です。", "isCorrect": true}, {"text": "本を読ませる", "points": 5, "feedback": "自己学習は10%。経験を積ませることが重要です。", "isCorrect": false}], "situation": "部下の育成施策を考えています。何を重視しますか？", "customerLine": "（育成施策を選ぶ場面）"}, {"options": [{"text": "組織ニーズを優先する", "points": 10, "feedback": "本人の志向を無視すると、モチベーションが下がります。", "isCorrect": false}, {"text": "本人の希望を優先する", "points": 10, "feedback": "組織ニーズも考慮しないと、キャリアが停滞する可能性があります。", "isCorrect": false}, {"text": "対話してすり合わせ、両立できる目標を設定する", "points": 30, "feedback": "本人の志向と組織ニーズをすり合わせることが大切です。", "isCorrect": true}], "situation": "部下のキャリア志向と組織ニーズが異なります。どうしますか？", "customerLine": "（目標設定の場面）"}]', '{"question": "部下の育成で「場当たり的になっている」と感じることはありますか？", "placeholder": "例: 忙しくて計画的に育成できていない。まずIDPを作成し、月1回の振り返りを設定する"}', '["部下一人ひとりのIDPを作成する", "70:20:10の法則を意識した育成施策を立てる", "月1回の振り返りで進捗を確認する", "挑戦的なアサインメントを意識的に与える"]', '{"title": "部下のIDP作成", "fields": [{"label": "部下の強みと課題", "placeholder": "例: 強み-顧客対応力、粘り強さ / 課題-大型案件経験不足、提案書スキル"}, {"label": "1年後の目指す姿", "placeholder": "例: 大型案件を一人で担当できる、後輩に教えられる"}, {"label": "育成施策（70:20:10）", "placeholder": "例: 70%-大型案件同行 / 20%-週次FB / 10%-提案書研修"}], "description": "部下の個別育成計画を作成しましょう。"}', NULL, '2026-01-21 17:45:15.907726+00', '2026-01-21 17:45:15.907726+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (6, 96, '採用基準とオンボーディング', '採用で妥協しない、受け入れで放置しない', '{"icon": "user-plus", "name": "採用の達人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["研修", "他者からの学び", "経験（OJT）", "自己学習"], "question": "70:20:10の法則で最も大きな割合は？", "explanation": "70%は経験から学びましたね。挑戦的なアサインメントが重要でした。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 採用の失敗", "content": "（チームミーティングで）\n\n山本:「先月入社した田中さん、もう辞めるって...」\n\n鈴木課長:「えっ、まだ1ヶ月だぞ。何があった？」\n\n山本:「『思っていた仕事と違った』って...\n　　面接では良さそうだったんですが...」\n\n鈴木課長:「採用のミスマッチだな。\n　　採用基準は明確だったか？\n　　オンボーディングはしっかりやったか？」\n\n山本:「...正直、人手が足りなくて、\n　　　採用を急いでしまいました」\n\n鈴木課長:「採用で妥協すると、\n　　　こういうことが起きる。\n　　　採用基準とオンボーディング、\n　　　ちゃんと見直そう」", "duration": 45}, {"title": "シーン2: 採用基準の設計", "content": "鈴木課長:「採用基準は3つに分けて設計する」\n\n【採用基準の設計】\n\n1️⃣ Must（必須）\nこれがないと採用しない。最低限の要件\n・基本的なコミュニケーション力\n・目標達成への意欲\n・誠実さ\n\n2️⃣ Want（あれば望ましい）\nあれば加点。なくても育成可能\n・業界経験\n・特定のスキル\n・即戦力性\n\n3️⃣ Negative（不採用要件）\nこれがあると採用しない\n・嘘をつく\n・約束を守らない\n・他責思考が強い\n\n鈴木課長:「『良さそう』という感覚ではなく、\n　　　基準に照らして判断する。\n　　　それが採用の精度を上げる」", "duration": 50}, {"title": "シーン3: 営業職で見るべきポイント", "content": "鈴木課長:「営業職の採用では、\n　　　特に見るべきポイントがある」\n\n【営業職の採用で見るべき5ポイント】\n\n1️⃣ コミュニケーション力\n質問に的確に答えられるか\n相手の話を傾聴できるか\n\n2️⃣ ストレス耐性\n断られることへの耐性\nネガティブな経験からの学び\n\n3️⃣ 目標達成意欲\n過去に目標を追いかけた経験があるか\n結果にこだわる姿勢があるか\n\n4️⃣ 誠実さ\n嘘をつかない、約束を守る姿勢\n→ 顧客からの信頼に直結\n\n5️⃣ 成長意欲\n学び続ける姿勢があるか\nフィードバックを受け入れられるか", "duration": 50}], "part2": [{"title": "シーン4: オンボーディングの重要性", "content": "鈴木課長:「採用したら終わりじゃない。\n　　　オンボーディングが重要だ」\n\n【オンボーディングの重要性】\n\n新入社員の30%は入社90日以内に\n離職を決意すると言われている\n\n→ 最初の90日で「この会社で頑張ろう」と\n　思ってもらえるかが勝負\n\n【オンボーディングの3つの目的】\n\n1️⃣ 早期戦力化\n成果を出せる状態にする\n\n2️⃣ 組織への適応\n文化・人間関係の理解\n\n3️⃣ 心理的安全性の確保\n質問・相談しやすい環境\n\n鈴木課長:「放置したら辞める。\n　　　丁寧に受け入れることが大事だ」", "duration": 50}, {"title": "シーン5: 90日オンボーディングプラン", "content": "鈴木課長:「90日で戦力化するプランを作ろう」\n\n【90日オンボーディングプラン】\n\n■ 1週目: 基礎理解\n・会社・チーム・製品の説明\n・メンターのアサイン\n・ツール・システムの設定\n・チームメンバーとの顔合わせ\n\n■ 2-4週目: OJT開始\n・先輩同行（見て学ぶ）\n・ロールプレイ\n・基礎研修の受講\n・週次振り返り\n\n■ 2ヶ月目: 一人立ち開始\n・サポート付きで実践\n・週次の1on1\n・課題の早期発見と対処\n\n■ 3ヶ月目: 完全一人立ち\n・目標設定\n・定期1on1の開始\n・90日振り返り面談", "duration": 55}, {"title": "シーン6: 採用とオンボーディングの改善", "content": "（3ヶ月後、新メンバー入社後）\n\n新人:「山本さん、メンターの佐藤さんに\n　　毎日フォローしてもらって、\n　　不安なく仕事を覚えられました」\n\n山本:「良かった。困ったことはない？」\n\n新人:「最初は覚えることが多くて大変でしたが、\n　　90日プランがあったので、\n　　自分がどこにいるかわかって安心しました」\n\n（鈴木課長に報告）\n\n鈴木課長:「今回は採用基準もオンボーディングも\n　　　ちゃんと設計したからな。\n　　　採用で妥協しない、受け入れで放置しない。\n　　　それが定着率を上げる秘訣だ」\n\n【今日の学び】\n「採用で妥協しない、受け入れで放置しない」", "duration": 40}]}', '{"title": "90日オンボーディングプラン", "content": "1週目: 基礎理解、メンターアサイン\n2-4週目: OJT開始、先輩同行\n2ヶ月目: 一人立ち開始（サポート付き）\n3ヶ月目: 完全一人立ち、目標設定", "audioText": "採用後の90日が勝負。計画的なオンボーディングで早期戦力化と定着を実現しましょう。", "highlight": "新入社員の30%は90日以内に離職を決意。オンボーディングが鍵"}', '[{"options": ["30日以内", "90日以内", "180日以内", "1年以内"], "question": "新入社員が離職を決意するのは入社後いつまでが多い？", "explanation": "30%の新入社員は90日以内に離職を決意します。オンボーディングが重要です。", "correctIndex": 1}, {"options": ["あれば望ましい条件", "必須条件", "不採用条件", "追加条件"], "question": "採用基準の「Must」とは？", "explanation": "Must=必須条件。これがないと採用しません。", "correctIndex": 1}]', '{"text": "A players hire A players. B players hire C players.", "author": "スティーブ・ジョブズ", "textJa": "採用で妥協してはならない。Aクラスの人材がAクラスを連れてくる。Bクラスの人材はCクラスを連れてくる。"}', '[{"options": [{"text": "人手不足だから採用する", "points": 0, "feedback": "採用で妥協すると、ミスマッチで早期離職のリスクがあります。", "isCorrect": false}, {"text": "Must要件を満たしているか確認し、満たしていれば採用を検討", "points": 30, "feedback": "基準に照らして判断することが大切です。", "isCorrect": true}, {"text": "スキルが低いから不採用", "points": 10, "feedback": "スキルはWant要件かもしれません。Must要件を確認しましょう。", "isCorrect": false}], "situation": "人手不足で、スキルは低いが「良い人」が応募してきました。", "customerLine": "（採用判断の場面）"}, {"options": [{"text": "すぐに営業に出してもらう", "points": 0, "feedback": "基礎理解なく実践させると、失敗体験が増え自信を失います。", "isCorrect": false}, {"text": "会社・チーム・製品の説明、メンターアサイン、ツール設定", "points": 30, "feedback": "最初の1週間は基礎理解とサポート体制の構築が重要です。", "isCorrect": true}, {"text": "研修だけ受けさせて放置", "points": 5, "feedback": "研修だけでは不十分。メンターをつけ、人間関係も構築しましょう。", "isCorrect": false}], "situation": "新入社員が入社しました。最初の1週間で何をしますか？", "customerLine": "（オンボーディング開始の場面）"}]', '{"question": "過去の採用やオンボーディングで「失敗した」と感じた経験はありますか？", "placeholder": "例: 急いで採用してミスマッチが起きた。次回は基準を明確にして判断する"}', '["採用基準（Must/Want/Negative）を明文化する", "90日オンボーディングプランを作成する", "新入社員にメンターをアサインする", "週次の1on1で早期に課題を発見する"]', '{"title": "採用基準とオンボーディングプラン作成", "fields": [{"label": "Must（必須）条件", "placeholder": "例: コミュニケーション力、目標達成意欲、誠実さ"}, {"label": "Want（あれば望ましい）条件", "placeholder": "例: 業界経験、営業経験、特定のスキル"}, {"label": "90日オンボーディングの概要", "placeholder": "例: 1週目-基礎研修、2-4週目-OJT同行、2ヶ月目-実践、3ヶ月目-一人立ち"}], "description": "自チームの採用基準とオンボーディングプランを作成しましょう。"}', NULL, '2026-01-21 17:45:16.697827+00', '2026-01-21 17:45:16.697827+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (7, 97, 'コーチング・メンタリング', '教えるのではなく引き出す', '{"icon": "compass", "name": "コーチ"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["30日以内", "90日以内", "180日以内", "1年以内"], "question": "新入社員が離職を決意するのは入社後いつまでが多い？", "explanation": "30%が90日以内に離職を決意。オンボーディングが重要でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 教えても育たない", "content": "（山本が悩んでいる）\n\n山本:「鈴木課長、健太に何度も教えてるのに、\n　　なかなか成長しなくて...」\n\n鈴木課長:「どうやって教えてる？」\n\n山本:「『こうやるんだ』『これを覚えろ』って\n　　丁寧に説明してるんですが...」\n\n鈴木課長:「それが問題かもしれないな」\n\n山本:「え？丁寧に教えるのがダメなんですか？」\n\n鈴木課長:「『教える』だけでは、\n　　　自分で考える力がつかない。\n　　　『引き出す』アプローチも必要だ」", "duration": 45}, {"title": "シーン2: 3つの育成アプローチ", "content": "鈴木課長:「育成には3つのアプローチがある」\n\n【3つの育成アプローチ】\n\n1️⃣ ティーチング（Teaching）\n知識・スキルを教える\n「これはこうやるんだよ」\n→ 新人や未経験者に効果的\n\n2️⃣ コーチング（Coaching）\n質問で気づきを引き出す\n「どうすればうまくいくと思う？」\n→ 経験者の成長に効果的\n\n3️⃣ メンタリング（Mentoring）\n経験を共有し、キャリアを支援する\n「私はこんな経験をしたよ」\n→ 長期的な成長に効果的\n\n鈴木課長:「状況に応じて使い分けることが大事だ」", "duration": 50}, {"title": "シーン3: GROWモデル", "content": "鈴木課長:「コーチングの基本はGROWモデルだ」\n\n【GROWモデル（コーチングの型）】\n\nG（Goal）目標\n何を達成したいか？\n「どんな状態を目指している？」\n「この商談のゴールは？」\n\nR（Reality）現状\n今どんな状況か？\n「今の状況を教えて」\n「何が障害になっている？」\n\nO（Options）選択肢\nどんな方法があるか？\n「他にどんな方法がある？」\n「もし制限がなかったら？」\n\nW（Will）意志\n何をするか？\n「いつまでに、何をする？」\n「最初の一歩は？」", "duration": 55}], "part2": [{"title": "シーン4: コーチング質問例", "content": "鈴木課長:「コーチングでは質問が命だ」\n\n【コーチング質問例】\n\n■ オープンクエスチョン\n「どう思う？」\n「何が原因だと思う？」\n→ 相手に考えさせる\n\n■ スケーリング\n「10点満点で今何点？」\n「あと2点上げるには？」\n→ 現状を数値化する\n\n■ 仮定の質問\n「もし失敗を恐れないとしたら？」\n「もし何でもできるとしたら？」\n→ 制限を外して考えさせる\n\n■ リフレーミング\n「別の見方をするとどうなる？」\n「それを強みと捉えると？」\n→ 視点を変えさせる\n\n鈴木課長:「答えを教えるのではなく、\n　　　質問で相手の中から引き出すんだ」", "duration": 50}, {"title": "シーン5: 状況に応じた使い分け", "content": "鈴木課長:「部下の状態に応じて使い分けよう」\n\n【状況に応じた使い分け】\n\n■ スキル低 × 意欲高（新人）\n→ ティーチング中心\n丁寧に教える。やり方を示す\n\n■ スキル中 × 意欲中（若手）\n→ コーチング中心\n質問で引き出す。自分で考えさせる\n\n■ スキル高 × 意欲低（ベテラン）\n→ メンタリング\n経験を共有し、新しい挑戦を促す\n\n■ スキル高 × 意欲高（エース）\n→ 権限委譲\n任せて見守る。必要な時だけサポート\n\n鈴木課長:「全員に同じアプローチは効かない。\n　　　相手を見て使い分けるんだ」", "duration": 50}, {"title": "シーン6: コーチング実践", "content": "（山本が健太にコーチング）\n\n山本:「健太、商談うまくいかなかったんだって？」\n\n健太:「はい...提案が刺さらなくて...」\n\n山本:「（以前なら『こうすればよかった』と言ってた）\n　　何が原因だと思う？」\n\n健太:「...顧客の課題を深掘りできてなかった\n　　かもしれません」\n\n山本:「いいね。次はどうする？」\n\n健太:「質問を増やして、課題を深掘りしてから\n　　提案します」\n\n山本:「それでいこう。応援してる」\n\n健太:「ありがとうございます！\n　　（自分で気づけて、やる気が出た）」\n\n【今日の学び】\n「教えるのではなく引き出す」", "duration": 40}]}', '{"title": "GROWモデル", "content": "G（Goal）: 目標を明確にする\nR（Reality）: 現状を把握する\nO（Options）: 選択肢を出す\nW（Will）: 行動を決める", "audioText": "コーチングはGROWモデルで。目標、現状、選択肢、行動を質問で引き出しましょう。", "highlight": "答えを教えるのではなく、質問で引き出す"}', '[{"options": ["答えを教える", "質問で引き出す", "経験を共有する", "任せて見守る"], "question": "コーチングで重要なのは？", "explanation": "コーチングは質問で気づきを引き出すアプローチです。", "correctIndex": 1}, {"options": ["Growth（成長）", "Goal（目標）", "Good（良い）", "Grade（評価）"], "question": "GROWモデルのGは何？", "explanation": "G=Goal。まず目標を明確にすることから始めます。", "correctIndex": 1}]', '{"text": "Coaching is unlocking people''s potential to maximize their own performance.", "author": "ジョン・ウィットモア", "textJa": "コーチングとは、人が自分自身の答えを見つける手助けをすることである。"}', '[{"options": [{"text": "「こうすればいいよ」とアドバイスする", "points": 10, "feedback": "すぐにアドバイスすると、自分で考える力がつきません。", "isCorrect": false}, {"text": "「何が原因だと思う？」と質問する", "points": 30, "feedback": "質問で引き出すコーチングアプローチです。", "isCorrect": true}, {"text": "「大丈夫、頑張れ」と励ます", "points": 5, "feedback": "励ますだけでは解決策が見つかりません。", "isCorrect": false}], "situation": "部下が「商談がうまくいかない」と相談してきました。", "customerLine": "最近、商談がうまくいかなくて..."}, {"options": [{"text": "「どうすればいいと思う？」と質問する", "points": 10, "feedback": "新人で知識がない場合は、まず教える（ティーチング）が必要です。", "isCorrect": false}, {"text": "丁寧にやり方を教える", "points": 30, "feedback": "新人にはティーチングが効果的です。状況に応じた使い分けが大切です。", "isCorrect": true}, {"text": "自分で調べるよう言う", "points": 0, "feedback": "基本的なことは教えましょう。放置は心理的安全性を損ないます。", "isCorrect": false}], "situation": "新入社員が基本的な業務のやり方を聞いてきました。", "customerLine": "この業務、どうやればいいですか？"}]', '{"question": "部下への育成で「教えすぎている」と感じることはありますか？", "placeholder": "例: すぐに答えを言ってしまう。次回は質問で引き出すことを意識する"}', '["すぐにアドバイスせず、まず質問で引き出す", "GROWモデルを使ってコーチングする", "部下の状況（スキル×意欲）に応じてアプローチを変える", "「どう思う？」「何が原因だと思う？」を口癖にする"]', '{"title": "GROWモデル実践シート", "fields": [{"label": "G（Goal）: 目標を引き出す質問", "placeholder": "例: どんな状態を目指している？ / この商談のゴールは？"}, {"label": "R（Reality）: 現状を把握する質問", "placeholder": "例: 今の状況は？ / 何が障害になっている？"}, {"label": "O（Options）: 選択肢を出す質問", "placeholder": "例: 他にどんな方法がある？ / もし制限がなかったら？"}, {"label": "W（Will）: 行動を決める質問", "placeholder": "例: いつまでに何をする？ / 最初の一歩は？"}], "description": "部下との対話をGROWモデルで設計しましょう。"}', NULL, '2026-01-21 17:45:17.435195+00', '2026-01-21 17:45:17.435195+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (8, 98, '心理的安全性の醸成', '本音で話せるチームを作る', '{"icon": "shield", "name": "安全な場の創造者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Growth", "Goal", "Good", "Grade"], "question": "GROWモデルのGは何？", "explanation": "G=Goal。まず目標を明確にすることから始めましたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 沈黙のチーム", "content": "（チームミーティングで）\n\n山本:「何か意見ある人？」\n\n（...沈黙...）\n\n山本:「じゃあ、このまま進めるぞ」\n\n（ミーティング後、メンバー同士の会話）\n\n健太:「さっきの方針、ちょっと無理があると思うんだけど...」\n\n後輩:「俺もそう思った。でも、言えなかったな...」\n\n（山本が偶然聞いてしまう）\n\n山本:「...言えなかった？\n　　なんで会議で言ってくれなかったんだ？」\n\n健太:「すみません...\n　　でも、前に意見したら否定されて...」", "duration": 50}, {"title": "シーン2: 心理的安全性とは", "content": "（鈴木課長に相談）\n\n山本:「チームが本音を言ってくれなくて...」\n\n鈴木課長:「心理的安全性が低いんだな」\n\n【心理的安全性とは】\nチームの中で自分の意見を言っても、\n質問をしても、失敗しても、\n罰せられたり恥をかいたりしないと\n感じられる状態\n\n鈴木課長:「Googleの研究で、\n　　　高業績チームの最も重要な要素として\n　　　特定されたんだ」\n\n【心理的安全性が高いチームでは】\n・本音で議論できる\n・失敗を恐れず挑戦できる\n・わからないことを聞ける\n・ミスを隠さず報告できる", "duration": 50}, {"title": "シーン3: 心理的安全性を下げる行動", "content": "鈴木課長:「まず、心理的安全性を下げる行動を確認しよう」\n\n【心理的安全性を下げる行動】❌\n\n1. 発言を否定・無視する\n「それは違う」「そんなことより...」\n\n2. 失敗を責める\n「なんでできないの？」「誰の責任？」\n\n3. 質問を馬鹿にする\n「そんなことも知らないの？」\n\n4. 意見を言った人を攻撃する\n人格否定、陰口\n\n5. 完璧主義を強要する\n「失敗は許されない」\n\n山本:「...思い当たることがあります。\n　　健太の意見を『それは違う』って\n　　否定したことがあって...」\n\n鈴木課長:「自覚できたなら、変われる」", "duration": 50}], "part2": [{"title": "シーン4: 心理的安全性を高める行動", "content": "鈴木課長:「次に、心理的安全性を高める行動だ」\n\n【心理的安全性を高める行動】✅\n\n1. 自ら弱みを見せる\n「私も昔失敗した」「わからないから教えて」\n→ リーダーが弱みを見せると、メンバーも安心する\n\n2. 発言に感謝する\n「意見をくれてありがとう」「指摘してくれて助かった」\n→ 反対意見でも感謝する\n\n3. 失敗を学びに変える\n「何を学んだ？」「次はどうする？」\n→ 責めるのではなく、学びを引き出す\n\n4. 全員に発言機会を作る\n「○○さんはどう思う？」\n→ 発言しやすい人だけでなく、全員に聞く\n\n5. 批判ではなく好奇心で聞く\n「なぜそう思った？」「もっと教えて」\n→ 否定ではなく、興味を持って聞く", "duration": 55}, {"title": "シーン5: 山本の変化", "content": "（次のチームミーティング）\n\n山本:「今日は、みんなの本音を聞きたい。\n　　反対意見も大歓迎だ。\n　　正直、俺も今回のプランに自信がない」\n\n（自ら弱みを見せた）\n\n健太:「...実は、ちょっと気になる点があって...」\n\n山本:「ありがとう、健太。聞かせて」\n\n健太:「このスケジュールだと、\n　　品質を担保できないかもしれません」\n\n山本:「なるほど。具体的に教えてくれる？」\n\n（批判ではなく好奇心で聞いた）\n\n後輩:「私も同じこと思ってました...」\n\n山本:「みんな、意見をくれてありがとう。\n　　おかげで見落としに気づけた」\n\n（発言に感謝した）", "duration": 50}, {"title": "シーン6: チームの変化", "content": "（3ヶ月後）\n\n鈴木課長:「山本のチーム、最近活気があるな」\n\n山本:「メンバーが本音を言ってくれるようになって、\n　　問題の早期発見ができるようになりました」\n\n健太:「山本さんが変わったんですよ。\n　　前は意見言いにくかったけど、\n　　今は何でも相談できます」\n\n山本:「俺が変わったというより、\n　　チームの心理的安全性を意識するようになった。\n　　責めるより学ぶ、否定より好奇心。\n　　それだけで、チームがこんなに変わるんだな」\n\n【今日の学び】\n「本音で話せるチームを作る」", "duration": 40}]}', '{"title": "心理的安全性を高める5つの行動", "content": "1. 自ら弱みを見せる\n2. 発言に感謝する\n3. 失敗を学びに変える\n4. 全員に発言機会を作る\n5. 批判ではなく好奇心で聞く", "audioText": "心理的安全性は高業績チームの最重要要素。リーダーが弱みを見せ、発言に感謝することから始めましょう。", "highlight": "「責める」から「学ぶ」へ、「否定」から「好奇心」へ"}', '[{"options": ["失敗を責める", "発言を否定する", "自ら弱みを見せる", "完璧を求める"], "question": "心理的安全性を高める行動は？", "explanation": "リーダーが弱みを見せることで、メンバーも安心して発言できるようになります。", "correctIndex": 2}, {"options": ["Amazon", "Apple", "Google", "Microsoft"], "question": "心理的安全性は何の研究で重要性が特定された？", "explanation": "Googleの「Project Aristotle」で、高業績チームの最重要要素として特定されました。", "correctIndex": 2}]', '{"text": "Psychological safety is not about being nice. It''s about candor.", "author": "エイミー・エドモンドソン", "textJa": "心理的安全性は、ぬるま湯ではない。むしろ、率直に意見を言い合える厳しい環境である。"}', '[{"options": [{"text": "「なんでそんなミスするの？」と責める", "points": 0, "feedback": "責めると、次からミスを隠すようになります。", "isCorrect": false}, {"text": "「報告してくれてありがとう。何を学んだ？次はどうする？」", "points": 30, "feedback": "報告に感謝し、学びに変える良い対応です。", "isCorrect": true}, {"text": "「気にしなくていいよ」と流す", "points": 10, "feedback": "流すだけでは学びになりません。原因と対策を一緒に考えましょう。", "isCorrect": false}], "situation": "部下が失敗を報告してきました。どう対応しますか？", "customerLine": "すみません、ミスをしてしまいました..."}, {"options": [{"text": "「意見がないなら進めます」と言う", "points": 5, "feedback": "意見がないのではなく、言えないのかもしれません。", "isCorrect": false}, {"text": "「○○さん、どう思う？」と指名して聞く", "points": 30, "feedback": "全員に発言機会を作ることで、意見を引き出せます。", "isCorrect": true}, {"text": "自分の意見を話し続ける", "points": 0, "feedback": "一方的に話すと、さらに発言しにくくなります。", "isCorrect": false}], "situation": "会議で誰も発言しません。どうしますか？", "customerLine": "（沈黙が続く会議）"}]', '{"question": "最近、部下の発言を否定したり、失敗を責めたりしたことはありますか？", "placeholder": "例: 先週、部下の意見を『それは違う』と否定した。次回は『なぜそう思った？』と好奇心で聞く"}', '["自分から弱みを見せる（「私も昔失敗した」）", "発言には必ず感謝する（反対意見でも）", "失敗を責めず、学びに変える", "会議では全員に発言機会を作る"]', '{"title": "心理的安全性チェックリスト", "fields": [{"label": "チームでミスをしても責められないか？", "placeholder": "例: 最近、ミスを報告した時に責められた経験がある/ない"}, {"label": "メンバーが本音を言えているか？", "placeholder": "例: 会議で反対意見が出る/出ない"}, {"label": "改善するために自分ができること", "placeholder": "例: 発言に感謝する、失敗を責めない、弱みを見せる"}], "description": "自分のチームの心理的安全性をチェックしましょう。"}', NULL, '2026-01-21 17:45:18.185408+00', '2026-01-21 17:45:18.185408+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (9, 99, 'チーム目標設計とKPI運用', '測定できないものは改善できない', '{"icon": "target", "name": "KPIマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["失敗を責める", "発言を否定する", "自ら弱みを見せる", "完璧を求める"], "question": "心理的安全性を高める行動は？", "explanation": "リーダーが弱みを見せることで、メンバーも安心できましたね。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 目標なきチーム", "content": "（四半期レビューで）\n\n部長:「山本チーム、今期の結果はどうだった？」\n\n山本:「えーと、みんな頑張ったんですが、\n　　数字としては...目標未達でした」\n\n部長:「そもそも目標は明確だったのか？\n　　KPIは設定していたか？」\n\n山本:「...売上目標はありましたが、\n　　KPIは特に...」\n\n部長:「目標がなければ、成果は出ない。\n　　KPIがなければ、途中で軌道修正できない。\n　　チーム目標とKPI、ちゃんと設計し直そう」", "duration": 45}, {"title": "シーン2: KGIとKPI", "content": "部長:「まず、KGIとKPIの違いを理解しよう」\n\n【KGIとKPI】\n\n■ KGI（Key Goal Indicator）\n最終目標指標。達成すべきゴール\n例: 年間売上1億円、新規契約50件\n\n■ KPI（Key Performance Indicator）\n重要業績評価指標。KGI達成のための先行指標\n例: 月間商談数、アポ獲得率、成約率\n\n【関係性】\nKGIが「結果」、KPIは「過程」\n\nKPIを管理することで、\nKGI達成の確度を高める\n\n部長:「売上（KGI）だけ見ていても、\n　　結果が出てからでは遅い。\n　　KPIで過程を管理するんだ」", "duration": 50}, {"title": "シーン3: 良いKPIの条件", "content": "部長:「良いKPIには5つの条件がある」\n\n【良いKPIの5条件】\n\n1️⃣ 測定可能\n数値で測定できる\n× 「頑張る」 ○ 「商談20件」\n\n2️⃣ コントロール可能\n自分たちの行動で変えられる\n× 「市場環境」 ○ 「訪問数」\n\n3️⃣ 先行指標\n結果が出る前に状況がわかる\n売上の前に「商談数」「成約率」を見る\n\n4️⃣ シンプル\n3〜5個に絞る。多すぎると管理できない\n\n5️⃣ KGIとの因果関係\nKPIが上がればKGIも上がる関係\n「商談数」↑ → 「売上」↑\n\n部長:「この条件を満たすKPIを設定しよう」", "duration": 55}], "part2": [{"title": "シーン4: 営業チームのKPI例", "content": "山本:「具体的にどんなKPIを設定すればいいですか？」\n\n部長:「営業チームのKPIは4種類ある」\n\n【営業チームのKPI例】\n\n■ 行動量KPI\n・テレアポ数\n・訪問数\n・商談数\n→ 量を確保しているか\n\n■ 効率KPI\n・アポ獲得率（テレアポ→アポ）\n・商談化率（アポ→商談）\n・成約率（商談→成約）\n→ 効率よく進められているか\n\n■ 金額KPI\n・平均単価\n・1件あたり売上\n→ 単価を上げられているか\n\n■ 顧客KPI\n・新規顧客数\n・リピート率\n・紹介数\n→ 顧客基盤は健全か", "duration": 50}, {"title": "シーン5: PDCAサイクル", "content": "部長:「KPIは設定して終わりじゃない。\n　　PDCAサイクルで運用する」\n\n【KPI運用のPDCAサイクル】\n\n■ Plan（計画）\nKGI/KPIを設定し、アクションプランを立てる\n「今月の商談目標は20件。週5件ペースで進める」\n\n■ Do（実行）\n計画に基づいて行動する\n日々の活動を記録する\n\n■ Check（評価）\n週次・月次でKPIを確認\n「なぜ達成できたか」「なぜ未達か」を深掘り\n\n■ Act（改善）\n分析結果を踏まえて、次のアクションを決める\n成功パターンは横展開、失敗パターンは改善\n\n部長:「週次で振り返りをして、\n　　早めに軌道修正することが大事だ」", "duration": 50}, {"title": "シーン6: KPI運用の成果", "content": "（次の四半期レビュー）\n\n部長:「山本チーム、今期はどうだった？」\n\n山本:「目標達成しました！\n　　KPIを設定して週次で振り返った結果、\n　　早めに問題を発見して対処できました」\n\n部長:「具体的には？」\n\n山本:「月半ばで商談数が未達だったので、\n　　テレアポを増やして軌道修正しました。\n　　以前なら月末に気づいて手遅れでしたが、\n　　KPIを見ていたので早めに動けました」\n\n部長:「それがKPI運用の効果だ。\n　　測定できないものは改善できない。\n　　これからも続けてくれ」\n\n【今日の学び】\n「測定できないものは改善できない」", "duration": 40}]}', '{"title": "KPI運用のPDCAサイクル", "content": "Plan: KGI/KPIを設定\nDo: 計画に基づいて実行\nCheck: 週次・月次で振り返り\nAct: 改善策を実行", "audioText": "売上（KGI）だけ見ていては手遅れ。KPIで過程を管理し、早めに軌道修正しましょう。", "highlight": "KGIが「結果」、KPIは「過程」。KPIで早めに軌道修正する"}', '[{"options": ["KGIとKPIは同じ", "KGIが過程、KPIが結果", "KGIが結果、KPIが過程", "KGIはKPIより重要"], "question": "KGIとKPIの関係で正しいのは？", "explanation": "KGIが「結果」（最終目標）、KPIが「過程」（先行指標）です。", "correctIndex": 2}, {"options": ["測定可能", "コントロール可能", "複雑で詳細", "KGIとの因果関係"], "question": "良いKPIの条件として正しくないのは？", "explanation": "KPIはシンプルに3〜5個に絞ります。複雑すぎると管理できません。", "correctIndex": 2}]', '{"text": "What gets measured gets managed. What gets managed gets improved.", "author": "ピーター・ドラッカー", "textJa": "測定できないものは管理できない。管理できないものは改善できない。"}', '[{"options": [{"text": "「市場環境」「競合の動き」", "points": 0, "feedback": "自分たちでコントロールできないものはKPIに適しません。", "isCorrect": false}, {"text": "「商談数」「成約率」「平均単価」", "points": 30, "feedback": "測定可能でコントロール可能な良いKPIです。", "isCorrect": true}, {"text": "思いつくKPIを10個以上設定", "points": 5, "feedback": "KPIは3〜5個に絞りましょう。多すぎると管理できません。", "isCorrect": false}], "situation": "チームのKPIを設定します。どれを選びますか？", "customerLine": "（KPI設定の場面）"}, {"options": [{"text": "月末まで様子を見る", "points": 0, "feedback": "月末では手遅れです。早めに対策を打ちましょう。", "isCorrect": false}, {"text": "原因を分析し、すぐにアクションを増やす", "points": 30, "feedback": "早期発見・早期対処がKPI運用の効果です。", "isCorrect": true}, {"text": "KPIの目標を下げる", "points": 5, "feedback": "安易に目標を下げると成長しません。まず対策を考えましょう。", "isCorrect": false}], "situation": "月半ばでKPIが未達です。どうしますか？", "customerLine": "（商談数が目標の40%しか達成していない）"}]', '{"question": "現在、チームでKPIを設定・運用できていますか？できていない場合、何が障壁ですか？", "placeholder": "例: KPIを設定していなかった。まず3つのKPIを設定し、週次で振り返りを始める"}', '["KGI（最終目標）とKPI（先行指標）を明確に設定する", "KPIは3〜5個にシンプルに絞る", "週次でKPIを振り返り、早めに軌道修正する", "「なぜ達成できたか」「なぜ未達か」を深掘りする"]', '{"title": "チームKPI設計シート", "fields": [{"label": "KGI（最終目標）", "placeholder": "例: 四半期売上3000万円、新規契約15件"}, {"label": "KPI（先行指標）3〜5個", "placeholder": "例: 月間商談数20件、成約率30%、平均単価200万円"}, {"label": "振り返りのタイミング", "placeholder": "例: 毎週月曜の朝会でKPIをチェック"}], "description": "自チームのKGIとKPIを設計しましょう。"}', NULL, '2026-01-21 17:45:19.978992+00', '2026-01-21 17:45:19.978992+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (10, 100, '営業カルチャーの浸透', 'カルチャーは戦略を食べる', '{"icon": "flag", "name": "カルチャーリーダー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["KGIとKPIは同じ", "KGIが過程、KPIが結果", "KGIが結果、KPIが過程", "KGIはKPIより重要"], "question": "KGIとKPIの関係で正しいのは？", "explanation": "KGIが「結果」、KPIが「過程」でしたね。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: バラバラのチーム", "content": "（チーム会議後、山本が悩んでいる）\n\n山本:「鈴木課長、最近チームがバラバラで...\n　　みんな好き勝手にやってる感じがして...」\n\n鈴木課長:「どういう意味だ？」\n\n山本:「ある人は売上至上主義で強引に売り、\n　　別の人は顧客対応は良いけど売れない。\n　　チームとしての一体感がないんです」\n\n鈴木課長:「それは『カルチャー』が浸透していないな」\n\n山本:「カルチャー...？」\n\n鈴木課長:「チームで共有される『価値観』や\n　　　　『行動規範』のことだ。\n　　　　これが浸透していないと、\n　　　　みんなバラバラに動いてしまう」", "duration": 50}, {"title": "シーン2: カルチャーとは", "content": "鈴木課長:「ドラッカーの有名な言葉がある」\n\n\"Culture eats strategy for breakfast\"\n「カルチャーは戦略を朝食に食べる」\n\n鈴木課長:「どんなに良い戦略も、\n　　　カルチャーが伴わなければ機能しない」\n\n【カルチャーとは】\n組織やチームで共有される\n「価値観」「信念」「行動規範」\n\n「上司がいなくても、\n　メンバーがどう判断・行動するか」\nを決めるもの\n\n鈴木課長:「ルールは『やってはいけないこと』を決めるが、\n　　　カルチャーは『どう行動すべきか』を\n　　　自然と導く。だから強力なんだ」", "duration": 50}, {"title": "シーン3: 営業カルチャーの要素", "content": "鈴木課長:「営業チームのカルチャーとして\n　　　大事な要素を整理しよう」\n\n【営業カルチャーの6つの要素】\n\n1️⃣ 顧客志向\n顧客の成功を第一に考える\n\n2️⃣ 誠実さ\n嘘をつかない、約束を守る\n\n3️⃣ 成果へのこだわり\n目標達成に執念を持つ\n\n4️⃣ チームワーク\n個人プレーではなく、協力し合う\n\n5️⃣ 学習・成長\n常に学び、改善し続ける\n\n6️⃣ 挑戦\n失敗を恐れず、新しいことに挑戦する\n\n鈴木課長:「この中から、\n　　　チームで特に大事にする価値観を\n　　　明確にして、言語化するんだ」", "duration": 50}], "part2": [{"title": "シーン4: カルチャーを浸透させる方法", "content": "鈴木課長:「カルチャーを浸透させるには\n　　　6つの方法がある」\n\n【カルチャー浸透の6つの方法】\n\n1️⃣ 言語化する\n価値観を明文化し、チームで共有する\n「我々は顧客の成功を第一に考える」\n\n2️⃣ リーダーが体現する\n自らが価値観に沿った行動を取る\n→ 言行一致が最も重要\n\n3️⃣ 評価に組み込む\nカルチャーに沿った行動を評価する\n「成果」だけでなく「行動」も評価\n\n4️⃣ ストーリーを語る\n良い行動の事例を共有・称賛する\n「健太が顧客のためにこんな対応をした」\n\n5️⃣ 採用で選ぶ\nカルチャーフィットする人を採用する\n\n6️⃣ 儀式を作る\n朝礼、週次MTG、表彰などで繰り返し伝える", "duration": 55}, {"title": "シーン5: カルチャーを壊す行動", "content": "鈴木課長:「注意すべきは、\n　　　カルチャーを壊す行動だ」\n\n【カルチャーを壊す行動】❌\n\n1. 言行不一致\n言っていることとやっていることが違う\n「顧客第一」と言いながら、売上のために強引に売る\n\n2. 例外を許す\nカルチャーに反する行動を見逃す\n「あの人は数字を出してるから許される」\n\n3. 成果至上主義\n結果さえ出せば、やり方は問わない\n→ 短期的には成果が出ても、長期的には崩壊する\n\n4. 属人化\n特定の人だけに適用される/適用されない\n→ 不公平感がカルチャーを壊す\n\n鈴木課長:「特に『例外を許す』が危険だ。\n　　　一人でも許すと、カルチャーは崩れる」", "duration": 50}, {"title": "シーン6: チームカルチャーの確立", "content": "（3ヶ月後、チーム会議）\n\n山本:「今日は、我々のチームカルチャーを確認しよう」\n\n【山本チームのカルチャー】\n1. 顧客の成功を第一に考える\n2. 嘘をつかない、約束を守る\n3. 困ったら助け合う\n\n山本:「先週、健太が顧客のために\n　　自分の休日返上で対応してくれた。\n　　これが『顧客の成功を第一に』だ。\n　　みんなで称えよう」\n\n（拍手）\n\n健太:「チームの価値観が明確になって、\n　　迷った時の判断基準ができました」\n\n山本:「カルチャーは戦略を食べる。\n　　価値観が共有されたチームは強い」\n\n【今日の学び】\n「カルチャーは戦略を食べる」", "duration": 45}]}', '{"title": "カルチャー浸透の6つの方法", "content": "1. 言語化する\n2. リーダーが体現する\n3. 評価に組み込む\n4. ストーリーを語る\n5. 採用で選ぶ\n6. 儀式を作る", "audioText": "カルチャーは言語化し、リーダーが体現し、例外を許さないことで浸透します。", "highlight": "「言行一致」が最も重要。例外を許さない"}', '[{"options": ["戦略が最も重要", "カルチャーより戦略を優先", "カルチャーは戦略より強い影響力を持つ", "朝食が大事"], "question": "ドラッカーの言葉「Culture eats strategy for breakfast」の意味は？", "explanation": "どんなに良い戦略も、カルチャーが伴わなければ機能しないという意味です。", "correctIndex": 2}, {"options": ["言語化しない", "例外を許す", "儀式を作らない", "ストーリーを語らない"], "question": "カルチャーを壊す行動として最も危険なのは？", "explanation": "一人でも例外を許すと、カルチャーは崩れます。公平性が重要です。", "correctIndex": 1}]', '{"text": "Company culture is determined by who you hire and fire.", "author": "マーク・ザッカーバーグ", "textJa": "企業文化は、採用と解雇によって決まる。"}', '[{"options": [{"text": "数字を出しているので見逃す", "points": 0, "feedback": "例外を許すとカルチャーが崩壊します。", "isCorrect": false}, {"text": "1対1で話し、カルチャーの重要性を伝え、改善を求める", "points": 30, "feedback": "トップセールスでも例外は許さない。カルチャーを守る対応です。", "isCorrect": true}, {"text": "チーム全員の前で叱る", "points": 5, "feedback": "ネガティブフィードバックは1対1で。心理的安全性を損ないます。", "isCorrect": false}], "situation": "トップセールスがカルチャーに反する強引な売り方をしています。", "customerLine": "（対応を決める場面）"}, {"options": [{"text": "ポスターを貼る", "points": 5, "feedback": "ポスターだけでは浸透しません。リーダーの行動が重要です。", "isCorrect": false}, {"text": "まず自分が価値観を体現し、良い行動を称賛する", "points": 30, "feedback": "リーダーの言行一致とストーリー共有が最も効果的です。", "isCorrect": true}, {"text": "ルールブックを作って配布する", "points": 10, "feedback": "ルールだけでは行動は変わりません。体現とストーリーが大切です。", "isCorrect": false}], "situation": "チームのカルチャーを浸透させたいです。何から始めますか？", "customerLine": "（浸透方法を選ぶ場面）"}]', '{"question": "自チームに「カルチャー」はありますか？言語化されていますか？", "placeholder": "例: 暗黙の了解はあるが言語化されていない。チームで話し合って明文化したい"}', '["チームの価値観を言語化し、共有する", "自分が価値観を体現する（言行一致）", "良い行動のストーリーを称賛・共有する", "カルチャーに反する行動は例外なく指摘する"]', '{"title": "チームカルチャー設計シート", "fields": [{"label": "チームで大切にする価値観（3つ）", "placeholder": "例: 顧客の成功第一、誠実さ、助け合い"}, {"label": "価値観を体現するための自分の行動", "placeholder": "例: 顧客対応を最優先する、約束は必ず守る"}, {"label": "良い行動のストーリー（最近あった例）", "placeholder": "例: 健太が顧客のために休日対応した"}], "description": "自チームのカルチャーを言語化しましょう。"}', NULL, '2026-01-21 17:45:20.698615+00', '2026-01-21 17:45:20.698615+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (11, 101, 'マーケティングとは何か', '売れる仕組みを作れ', '{"icon": "lightbulb", "name": "マーケティング入門者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["広告を出すこと", "セールスを不要にすること", "価格を下げること", "競合に勝つこと"], "question": "マーケティングの目的は何でしょうか？（ドラッカーの定義）", "explanation": "ドラッカーは「マーケティングの目的はセールスを不要にすること」と定義しています。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 営業とマーケの対立", "content": "（営業部のフロア）\n\n健太:「また問い合わせが少ないな...\n      マーケは何やってるんだ」\n\n山本先輩:「おいおい、そう言うなよ」\n\n健太:「でも、リードが全然来ないんですよ。\n      マーケがちゃんとやってくれれば...」\n\n山本先輩:「健太、マーケティングって何か説明できる？」\n\n健太:「えっと...広告を出したり、\n      ホームページを作ったりすることですか？」\n\n山本先輩:「それはマーケティングの\"一部\"だな」", "duration": 45}, {"title": "シーン2: マーケティングの本質", "content": "山本先輩:「ドラッカーの言葉を知ってるか？」\n\n健太:「ドラッカー...経営学の人ですよね？」\n\n山本先輩:「そう。彼はこう言った。\n        『マーケティングの目的は、\n          セールスを不要にすることである』」\n\n健太:「セールスを不要に...？\n      じゃあ営業いらなくなるんですか？」\n\n山本先輩:「違う違う。\n        お客さんが『欲しい』と思う状態を作り出す、\n        ってことだよ」\n\n【マーケティングの目的】\n✓ 顧客が「欲しい」と思う状態を作る\n✓ 営業が「売り込む」必要がない状態が理想\n✓ 顧客自ら「これが欲しい」と言ってくれる", "duration": 45}, {"title": "シーン3: 営業とマーケの役割分担", "content": "山本先輩:「じゃあ、マーケと営業の\n        役割分担を整理してみようか」\n\n【マーケティングの役割】\n・市場調査・分析（誰が顧客か？）\n・製品企画・価格設定\n・認知獲得・リード創出\n・ブランド構築\n\n【営業の役割】\n・顧客との直接対話（ニーズの深掘り）\n・提案・クロージング\n・関係構築・維持\n・市場情報のフィードバック\n\n山本先輩:「マーケが『見込み客を集めて』、\n        営業が『クロージングする』。\n        どっちが欠けてもダメなんだ」\n\n健太:「対立じゃなくて、連携なんですね」", "duration": 30}], "part2": [{"title": "シーン4: 営業がマーケを学ぶ意義", "content": "健太:「でも、営業が\n      マーケティングを学ぶ必要あるんですか？」\n\n山本先輩:「大ありだよ。理由は3つある」\n\n【営業がマーケを学ぶ意義】\n\n1. 戦略の理解\n「なぜこのターゲットか」「なぜこの価格か」\n→ 理解すれば提案に説得力が生まれる\n\n2. 共通言語の獲得\nMQL、CVR、リードナーチャリング...\n→ マーケ部門と円滑にコミュニケーションできる\n\n3. 顧客視点の強化\n「売り手目線」から「顧客目線」へ\n→ 営業の質が上がる", "duration": 45}, {"title": "シーン5: マーケ部門との会話", "content": "（マーケ部門のフロアで）\n\nマーケ担当:「先月のMQLは50件でした。\n         CVRは3%で、SQLは15件に」\n\n健太:「えっと...MQL、CVR、SQL...？」\n\nマーケ担当:「（ため息）営業さんは\n         こういう用語わからないですよね」\n\n健太（心の声）:「やばい、全然わからない...」\n\n〜帰り道〜\n\n健太:「先輩、MQLとかSQLって何ですか？」\n\n山本先輩:「MQLはMarketing Qualified Lead、\n        マーケが『営業対象』と判断した見込み客。\n        SQLはSales Qualified Lead、\n        営業が『商談化可能』と判断した見込み客だよ」\n\n健太:「マーケと営業で共通言語があるんですね」", "duration": 30}, {"title": "シーン6: 気づき", "content": "山本先輩:「マーケを理解している営業は、\n        戦略的に動ける。\n        『なぜこの顧客にアプローチするのか』\n        『なぜこの価格なのか』\n        理由がわかれば、提案も変わる」\n\n健太:「確かに、今まで何も考えずに\n      言われたリストに電話してました...」\n\n山本先輩:「それじゃ作業だな。\n        マーケを知れば、営業が\"戦略\"になる」\n\n【今日の学び】\n「マーケティングを知る営業は、\n  戦略を持って戦える」", "duration": 15}]}', '{"title": "マーケティングと営業の関係", "content": "マーケティング = 売れる仕組みを作る\n営業 = 顧客に価値を届ける", "audioText": "マーケティングは売れる仕組みを作り、営業は顧客に価値を届ける。両者の連携が成果を生みます。", "highlight": "対立ではなく連携"}', '[{"options": ["広告を増やすこと", "セールスを不要にすること"], "question": "ドラッカーによるマーケティングの目的は？", "explanation": "顧客が自ら「欲しい」と思う状態を作ることが目的です。", "correctIndex": 1}, {"options": ["マーケ部門の仕事を奪える", "戦略的な営業活動ができる"], "question": "営業がマーケティングを学ぶメリットは？", "explanation": "マーケを理解すれば「なぜ」がわかり、提案に説得力が生まれます。", "correctIndex": 1}]', '{"text": "The aim of marketing is to make selling superfluous.", "author": "ピーター・ドラッカー", "textJa": "マーケティングの目的は、セールスを不要にすることである。"}', '[{"options": [{"text": "「MQLって何ですか？」と聞く", "points": 0, "feedback": "基本用語は事前に学んでおきましょう。MQL=マーケ認定リード、SQL=営業認定リードです。", "isCorrect": false}, {"text": "「リードの質が悪いんじゃないですか？」と反論する", "points": 5, "feedback": "対立ではなく連携が大切。まず原因を一緒に分析しましょう。", "isCorrect": false}, {"text": "「どんなリードが商談化しやすいか、一緒に分析しませんか？」と提案", "points": 30, "feedback": "素晴らしい！マーケと営業の連携で改善策を見つける姿勢です。", "isCorrect": true}, {"text": "「営業は頑張ってます」と言い訳する", "points": 0, "feedback": "数字に基づいた建設的な対話をしましょう。", "isCorrect": false}], "situation": "マーケ部門から「先月のMQLからのSQL化率が低いです」と言われました。", "customerLine": "MQLからのSQL化率が20%しかないんです。何が問題でしょうか？"}, {"options": [{"text": "「会社が決めた価格なので...」と答える", "points": 0, "feedback": "マーケ戦略を理解していない回答です。価格の根拠を説明できるようになりましょう。", "isCorrect": false}, {"text": "「値引きできます！」と即答する", "points": 0, "feedback": "価値を説明する前に値引きは避けましょう。", "isCorrect": false}, {"text": "「この価格で、○○という価値を提供できるからです」と価値を説明", "points": 30, "feedback": "価格戦略を理解した上で、価値ベースで説明できています。", "isCorrect": true}, {"text": "「確認して折り返します」と答える", "points": 5, "feedback": "価格の根拠は営業として理解しておくべきです。", "isCorrect": false}], "situation": "顧客から「なぜこの価格なんですか？」と聞かれました。", "customerLine": "他社より少し高いですね。なぜこの価格なんですか？"}]', '{"question": "自社のマーケティング活動について、どの程度理解していますか？もっと知りたいことは？", "placeholder": "例: リードがどうやって獲得されているか、なぜこのターゲットなのか、価格設定の根拠など"}', '["マーケ部門に「リード獲得の仕組み」を聞いてみる", "MQL、SQL、CVRなどの基本用語を覚える", "「なぜこのターゲットか」を上司に聞いてみる", "自社の価格設定の根拠を確認する"]', NULL, NULL, '2026-01-21 17:45:22.12424+00', '2026-01-21 17:45:22.12424+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (12, 102, '市場分析の基本 - 3C分析', '敵を知り己を知れば百戦危うからず', '{"icon": "search", "name": "市場分析者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["広告を出すこと", "セールスを不要にすること", "価格を下げること", "ノルマを達成すること"], "question": "マーケティングの目的は何でしたか？（ドラッカーの定義）", "explanation": "「セールスを不要にすること」＝顧客が自ら欲しいと思う状態を作ることでしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 商談前の準備不足", "content": "（商談先に向かう車の中）\n\n健太:「今日の○○モータースさん、\n      どんな会社なんだろう...」\n\n山本先輩:「え、調べてないの？」\n\n健太:「一応ホームページは見ましたけど...」\n\n山本先輩:「競合は？市場の状況は？」\n\n健太:「えっと...それは...」\n\n山本先輩:「商談は\"準備\"で8割決まるんだぞ」", "duration": 45}, {"title": "シーン2: 3C分析とは", "content": "山本先輩:「3C分析って知ってる？」\n\n健太:「3C...？」\n\n山本先輩:「市場環境を分析するフレームワークだよ」\n\n【3C分析】（大前研一 1982年）\n\nCustomer（顧客）\n・市場のニーズ、購買行動\n・意思決定プロセス\n\nCompetitor（競合）\n・競合他社の強み・弱み\n・競合の戦略\n\nCompany（自社）\n・自社の強み・弱み\n・リソース\n\n山本先輩:「この3つの\"交点\"に勝機がある」", "duration": 45}, {"title": "シーン3: 3Cの交点", "content": "山本先輩:「3Cの交点っていうのは、こういうことだ」\n\n【3Cの交点 = 勝機】\n\n顧客ニーズを満たし\n ↓\n競合より優れていて\n ↓\n自社の強みが活きる\n\nこの3つが重なるところで戦えば勝てる\n\n山本先輩:「例えば、Symphonyの場合...\n\n顧客ニーズ: 中古車業界に特化したシステムが欲しい\n競合の弱み: 汎用システムで業界特化が弱い\n自社の強み: 中古車業界に特化した機能\n\nこの交点で戦えば、競合に勝てる」", "duration": 30}], "part2": [{"title": "シーン4: Customer（顧客）分析", "content": "山本先輩:「じゃあ、今日の○○モータースさんを\n        3C分析してみよう。まずCustomer」\n\n【Customer分析のポイント】\n・顧客は誰か？（業種、規模、地域）\n・顧客のニーズは何か？（課題、欲求）\n・購買の意思決定者は誰か？\n・購買プロセスはどうなっているか？\n・購買基準は何か？\n\n健太:「○○モータースさんは...\n      地方の中規模店で、在庫50台くらい。\n      社長が決裁者で、効率化を求めてる...」\n\n山本先輩:「いいね、それが顧客理解だ」", "duration": 45}, {"title": "シーン5: Competitor（競合）分析", "content": "山本先輩:「次はCompetitor。競合分析だ」\n\n【Competitor分析のポイント】\n・競合は誰か？（直接競合、間接競合）\n・競合の強みは何か？\n・競合の弱みは何か？\n・競合のシェア、価格帯は？\n・競合の戦略は？\n\n健太:「競合はA社とB社...\n      A社は大手で知名度がある、\n      B社は価格が安い...」\n\n山本先輩:「じゃあSymphonyの勝ち筋は？」\n\n健太:「えっと...業界特化で、\n      大手より柔軟で、B社よりサポートが手厚い...」\n\n山本先輩:「そう、それが差別化だ」", "duration": 30}, {"title": "シーン6: Company（自社）分析と実践", "content": "山本先輩:「最後にCompany。自社分析」\n\n【Company分析のポイント】\n・自社の強みは何か？\n・自社の弱みは何か？\n・自社のリソース（人材、資金、技術）は？\n・自社の独自性は何か？\n\n山本先輩:「商談前に顧客の3Cを調べる習慣をつけろ。\n        それだけで商談の質が全然違う」\n\n健太:「準備で8割決まる、ですね」\n\n【今日の学び】\n「3Cの交点に勝機がある」\n商談前に顧客の3Cを調べる習慣を持つ", "duration": 15}]}', '{"title": "3C分析", "content": "Customer（顧客）× Competitor（競合）× Company（自社）", "audioText": "3C分析は顧客、競合、自社の3つの視点から市場を分析するフレームワークです。", "highlight": "3つの交点に勝機がある"}', '[{"options": ["Cost, Conversion, Click", "Customer, Competitor, Company"], "question": "3Cの「C」は何の頭文字？", "explanation": "顧客、競合、自社の3つの視点で市場を分析します。", "correctIndex": 1}, {"options": ["自社の強みだけを押し出すところ", "3つのCが重なる交点"], "question": "3C分析で「勝機」があるのは？", "explanation": "顧客ニーズを満たし、競合より優れ、自社の強みが活きる交点が勝機です。", "correctIndex": 1}]', '{"text": "Know thy enemy and know yourself; in a hundred battles you will never be in peril.", "author": "孫子", "textJa": "敵を知り己を知れば百戦危うからず。"}', '[{"options": [{"text": "ホームページのデザインをチェックする", "points": 0, "feedback": "見た目より、事業内容や課題を調べましょう。", "isCorrect": false}, {"text": "顧客の事業内容、課題、競合状況を調べる（3C分析）", "points": 30, "feedback": "素晴らしい！3C分析で商談の質が大きく変わります。", "isCorrect": true}, {"text": "自社製品のカタログを読み直す", "points": 10, "feedback": "自社製品の理解も大事ですが、まず顧客を知ることが先です。", "isCorrect": false}, {"text": "特に調べない。現場で聞けばいい", "points": 0, "feedback": "準備不足は商談の質を下げます。3C分析で準備しましょう。", "isCorrect": false}], "situation": "商談前日、顧客企業の情報を調べています。何を優先的に調べますか？", "customerLine": "（準備の場面）"}, {"options": [{"text": "「機能が豊富なところです」", "points": 5, "feedback": "顧客視点がありません。顧客のニーズに対する強みを伝えましょう。", "isCorrect": false}, {"text": "「御社のような中古車販売店に特化しているところです」", "points": 30, "feedback": "顧客の業界・課題に紐づけた強みの説明ができています。", "isCorrect": true}, {"text": "「価格が安いところです」", "points": 0, "feedback": "価格訴求だけでは差別化になりません。", "isCorrect": false}, {"text": "「何でもできるところです」", "points": 0, "feedback": "具体性がありません。顧客のニーズに対する強みを伝えましょう。", "isCorrect": false}], "situation": "顧客から「御社の強みは？」と聞かれました。どう答えますか？", "customerLine": "Symphonyさんの強みは何ですか？"}]', '{"question": "次の商談で、3C分析をどのように活用しますか？", "placeholder": "例: 事前に顧客の業界状況と競合を調べ、自社の強みを活かせるポイントを準備する"}', '["商談前に顧客企業をネットで調べる習慣をつける", "競合製品の情報を定期的にアップデートする", "自社の強み・弱みを整理しておく", "3Cの交点を意識した提案を心がける"]', '{"title": "3C分析ワークシート", "fields": [{"label": "Customer（顧客）: 顧客のニーズ・課題は？", "placeholder": "例: 業務効率化、人手不足の解消、コスト削減"}, {"label": "Competitor（競合）: 競合の強み・弱みは？", "placeholder": "例: A社は知名度高い、B社は価格安い、でもサポートが弱い"}, {"label": "Company（自社）: 自社の強み・弱みは？", "placeholder": "例: 業界特化、サポート充実、でも知名度は低い"}, {"label": "勝ち筋（3Cの交点）: どこで戦えば勝てる？", "placeholder": "例: 業界特化×手厚いサポートで、大手との差別化"}], "description": "次の商談先について、3C分析を行ってみましょう。"}', NULL, '2026-01-21 17:45:22.692944+00', '2026-01-21 17:45:22.692944+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (13, 103, 'STP戦略 - 誰に売るかを決める技術', '全員に好かれようとすれば、誰にも好かれない', '{"icon": "target", "name": "ターゲティングマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Cost, Click, Conversion", "Customer, Competitor, Company", "Content, Context, Channel", "Create, Connect, Close"], "question": "3C分析の「3つのC」は何でしたか？", "explanation": "Customer（顧客）、Competitor（競合）、Company（自社）の3つでしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 誰にでも売ろうとする", "content": "（営業会議にて）\n\n鈴木課長:「健太、今月のターゲットリストを見せてくれ」\n\n健太:「はい。中古車販売店を片っ端から...」\n\n鈴木課長:「片っ端から？」\n\n健太:「はい、どこでもいいから売れればと...」\n\n鈴木課長:「それじゃ効率悪いだろ。\n        全員に好かれようとすれば、\n        誰にも好かれない。\n        ターゲットを絞れ」", "duration": 45}, {"title": "シーン2: STP戦略とは", "content": "山本先輩:「STP戦略って知ってる？」\n\n健太:「STP...？」\n\n山本先輩:「マーケティングの基本フレームワークだ」\n\n【STP戦略】（Philip Kotler）\n「誰に」「どんな価値を」届けるかを決める\n\nS: Segmentation（セグメンテーション）\n → 市場を細分化する\n\nT: Targeting（ターゲティング）\n → 狙う市場を選ぶ\n\nP: Positioning（ポジショニング）\n → 競合との違いを明確にする\n\n山本先輩:「まず市場を分けて、狙う場所を選んで、\n        そこでの立ち位置を決める」", "duration": 45}, {"title": "シーン3: セグメンテーションの軸", "content": "山本先輩:「市場を分ける軸はいくつかある」\n\n【セグメンテーションの軸】\n\n地理的変数（Geographic）\n・地域、都市規模、気候など\n\n人口統計的変数（Demographic）\n・業種、企業規模、従業員数など\n\n心理的変数（Psychographic）\n・価値観、課題意識、導入意欲など\n\n行動変数（Behavioral）\n・購買頻度、使用状況、ロイヤルティなど\n\n健太:「いろんな切り口で分けられるんですね」\n\n山本先輩:「そう。どの軸で分けるかが大事だ」", "duration": 30}], "part2": [{"title": "シーン4: ターゲティングの基準", "content": "山本先輩:「セグメントを分けたら、\n        どこを狙うか決める。これがターゲティング」\n\n【ターゲット選定の基準】\n\n市場規模: 十分な売上が見込めるか？\n成長性: 今後伸びる市場か？\n競合状況: 勝てる余地があるか？\n自社適合性: 自社の強みが活きるか？\nアクセス可能性: アプローチできるか？\n\n山本先輩:「例えば、Symphonyの場合...\n        『従業員5〜30人の中古車販売店』がターゲット。\n        なぜだと思う？」\n\n健太:「えっと...大手すぎず、小さすぎず...」\n\n山本先輩:「そう。自社の強みが活きて、\n        競合に勝てる規模感だからだ」", "duration": 45}, {"title": "シーン5: ポジショニング", "content": "山本先輩:「最後はポジショニング。\n        顧客の頭の中で、自社を\n        競合とは異なる独自の位置に置くことだ」\n\n【ポジショニングマップ】\n縦軸: 高機能 ←→ シンプル\n横軸: 低価格 ←→ 高価格\n\n大手A社: 高機能×高価格\nB社: シンプル×低価格\nSymphony: 業界特化×適正価格\n\n山本先輩:「『中古車業界特化×コスパ良い』\n        これがSymphonyのポジション。\n        大手とも価格勝負とも違う立ち位置だ」\n\n健太:「なるほど、独自のポジションを取るんですね」", "duration": 30}, {"title": "シーン6: 営業への活用", "content": "山本先輩:「STP戦略を理解すると、\n        営業の仕方も変わる」\n\n【営業へのSTP活用】\n\n✓ 誰にアプローチするか明確になる\n  → 効率的なターゲティング\n\n✓ 何を伝えるか明確になる\n  → ポジショニングに基づく訴求\n\n✓ なぜ自社なのか説明できる\n  → 差別化ポイントの明確化\n\n健太:「『誰にでも売る』じゃなく、\n      『この人に売る』を決めるんですね」\n\n山本先輩:「そう。それがマーケティング思考だ」\n\n【今日の学び】\n「全員に好かれようとすれば、誰にも好かれない」\nターゲットを絞り、ポジションを明確にする", "duration": 15}]}', '{"title": "STP戦略", "content": "Segmentation → Targeting → Positioning", "audioText": "STPは市場を細分化し、狙う市場を選び、競合との違いを明確にするフレームワークです。", "highlight": "誰に、どんな価値を届けるかを決める"}', '[{"options": ["Technology", "Targeting"], "question": "STPの「T」は何の略？", "explanation": "Targeting=狙う市場を選ぶことです。", "correctIndex": 1}, {"options": ["価格を下げること", "競合との違いを明確にすること"], "question": "ポジショニングとは？", "explanation": "顧客の頭の中で、自社を独自の位置に置くことです。", "correctIndex": 1}]', '{"text": "If you try to please everyone, you''ll end up pleasing no one.", "author": "マーケティングの格言", "textJa": "全員を喜ばせようとすれば、結局誰も喜ばせられない。"}', '[{"options": [{"text": "中古車販売店を片っ端からリストアップする", "points": 0, "feedback": "効率が悪いです。STPに基づいてターゲットを絞りましょう。", "isCorrect": false}, {"text": "自社の強みが活きるセグメント（例: 従業員5-30人の店舗）に絞る", "points": 30, "feedback": "素晴らしい！STPに基づいたターゲティングができています。", "isCorrect": true}, {"text": "前月と同じリストを使う", "points": 5, "feedback": "戦略的な見直しが必要です。", "isCorrect": false}, {"text": "大手企業だけをリストアップする", "points": 5, "feedback": "自社の強みが活きるかどうかを考えましょう。", "isCorrect": false}], "situation": "上司から「今月のターゲットリストを作って」と言われました。どう作りますか？", "customerLine": "今月のターゲットリストを作ってくれ"}, {"options": [{"text": "「うちの方が安いです」", "points": 5, "feedback": "価格だけでは差別化になりません。ポジショニングを伝えましょう。", "isCorrect": false}, {"text": "「中古車業界に特化しており、御社の業務にぴったりです」", "points": 30, "feedback": "ポジショニング（業界特化）を明確に伝えられています。", "isCorrect": true}, {"text": "「正直、あまり変わらないです」", "points": 0, "feedback": "自社のポジショニングを理解し、違いを説明しましょう。", "isCorrect": false}, {"text": "「機能が多いです」", "points": 5, "feedback": "機能の多さより、顧客にとっての価値を伝えましょう。", "isCorrect": false}], "situation": "顧客から「御社と他社の違いは？」と聞かれました。", "customerLine": "御社とA社、B社との違いは何ですか？"}]', '{"question": "自社のターゲット顧客とポジショニングを説明できますか？", "placeholder": "例: ターゲットは従業員5-30人の中古車販売店。ポジショニングは業界特化×コスパ"}', '["自社のターゲット顧客を確認する", "自社のポジショニング（競合との違い）を整理する", "商談で「なぜ自社か」を説明できるようにする", "ターゲット外の顧客に時間を使いすぎていないか振り返る"]', NULL, NULL, '2026-01-21 17:45:23.521444+00', '2026-01-21 17:45:23.521444+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (14, 104, 'マーケティングミックス - 4Pと4C', '4Pではなく4Cで考えよ', '{"icon": "grid", "name": "4Cマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Product", "Positioning", "Promotion", "Price"], "question": "STPの「P」は何の略でしたか？", "explanation": "Positioning=競合との違いを明確にすることでしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 商品説明の失敗", "content": "（商談にて）\n\n健太:「弊社のSymphonyは、\n      在庫管理機能が充実していて、\n      月額28,000円で、\n      WEBからお申し込みいただけます」\n\n店長:「ふーん...で？」\n\n健太:「え、ですから、機能が...」\n\n店長:「それがうちにどう役立つの？」\n\n健太:「...」\n\n（帰り道）\n\n健太:「先輩、何がダメだったんですか？」", "duration": 45}, {"title": "シーン2: 4P vs 4C", "content": "山本先輩:「4Pって知ってる？」\n\n健太:「はい、Product、Price、Place、Promotion...」\n\n山本先輩:「そう。でもそれは『売り手目線』なんだ」\n\n【4P（売り手目線）】\nProduct（製品）: 何を売る？\nPrice（価格）: いくらで売る？\nPlace（流通）: どこで売る？\nPromotion（販促）: どう伝える？\n\n山本先輩:「これを『買い手目線』に変えたのが4C」\n\n【4C（買い手目線）】\nCustomer Value（顧客価値）: 顧客にとっての価値は？\nCost（顧客コスト）: 顧客の総負担は？\nConvenience（利便性）: 顧客にとって便利か？\nCommunication（コミュニケーション）: 顧客との対話は？", "duration": 45}, {"title": "シーン3: 視点の転換", "content": "山本先輩:「さっきの商談を4Cで考えてみよう」\n\n【健太の説明（4P視点）】\nProduct: 在庫管理機能が充実\nPrice: 月額28,000円\nPlace: WEBから申込\nPromotion: 機能を説明\n\n【4Cに変換すると】\nCustomer Value: 在庫管理の手間が半分に\nCost: 月額28,000円で年間○万円の人件費削減\nConvenience: 導入も操作も簡単\nCommunication: 御社の課題に合わせて提案\n\n山本先輩:「『機能が充実』じゃなくて、\n        『御社の手間が半分になる』と言えば\n        相手は『それいいね』ってなる」", "duration": 30}], "part2": [{"title": "シーン4: 顧客価値で伝える", "content": "山本先輩:「4Cの中で一番大事なのは\n        Customer Value（顧客価値）だ」\n\n【Product → Customer Value】\n✕「在庫管理機能が充実」\n○「在庫管理の手間が半分に」\n○「売れ筋が一目でわかる」\n○「欠品・過剰在庫がなくなる」\n\n健太:「『何ができるか』じゃなくて、\n      『どう良くなるか』を伝えるんですね」\n\n山本先輩:「そう。お客さんは機能が欲しいんじゃない。\n        問題解決、つまり『良くなること』が欲しいんだ」", "duration": 45}, {"title": "シーン5: コストの考え方", "content": "山本先輩:「Cost（コスト）も単なる価格じゃない」\n\n【Price → Cost】\n価格だけじゃなく、顧客の総負担を考える\n\n・初期費用\n・月額費用\n・学習コスト（使い方を覚える時間）\n・移行コスト（データ移行の手間）\n・心理的コスト（変化への抵抗）\n\n山本先輩:「だから『安いです』だけじゃ響かない。\n        『導入も簡単で、1週間で使いこなせます』\n        って言えば、学習コストの低さが伝わる」\n\n健太:「価格以外のコストも考えるんですね」", "duration": 30}, {"title": "シーン6: 実践編", "content": "山本先輩:「営業は4Pの最前線にいる。\n        でも、お客さんに伝える時は4Cで考えろ」\n\n【4Cで伝え直す】\n\n✕「機能が充実してます」\n○「御社の○○という課題が解決します」\n\n✕「月額28,000円です」\n○「月28,000円で、年間○万円のコスト削減に」\n\n✕「WEBから申し込めます」\n○「今日から使い始められます」\n\n✕「説明させてください」\n○「御社の状況を教えてください」\n\n【今日の学び】\n「4Pではなく4Cで考えよ」\n顧客視点で価値を伝える", "duration": 15}]}', '{"title": "4P → 4C", "content": "売り手目線から買い手目線へ", "audioText": "4Pは売り手目線、4Cは買い手目線。営業は4Cで顧客に価値を伝えましょう。", "highlight": "顧客にとっての価値で伝える"}', '[{"options": ["Cost", "Customer Value"], "question": "4Pの「Product」を4Cに変換すると？", "explanation": "製品を「顧客にとっての価値」として伝えることが大切です。", "correctIndex": 1}, {"options": ["価格だけ", "価格＋学習コスト＋移行コストなど総負担"], "question": "Cost（顧客コスト）に含まれるものは？", "explanation": "価格以外にも、学習コストや移行コストなど総負担を考慮します。", "correctIndex": 1}]', '{"text": "Think 4C, not 4P.", "author": "ロバート・ラウターボーン", "textJa": "マーケティングは4Pではなく、4Cで考えよ。"}', '[{"options": [{"text": "「在庫管理機能、売上管理機能、顧客管理機能があります」", "points": 5, "feedback": "4P（製品機能）の説明です。4C（顧客価値）で伝えましょう。", "isCorrect": false}, {"text": "「在庫管理の手間が半分になり、売れ筋が一目でわかります」", "points": 30, "feedback": "4C（顧客価値）で伝えられています。素晴らしい！", "isCorrect": true}, {"text": "「月額28,000円で、他社より安いです」", "points": 5, "feedback": "価格訴求だけでは差別化になりません。", "isCorrect": false}, {"text": "「最新のクラウド技術を使っています」", "points": 0, "feedback": "技術より、顧客にとっての価値を伝えましょう。", "isCorrect": false}], "situation": "顧客に製品を説明する場面です。どう伝えますか？", "customerLine": "御社の製品の特徴を教えてください"}, {"options": [{"text": "「値引きします」と即答", "points": 0, "feedback": "価値を説明する前に値引きは避けましょう。", "isCorrect": false}, {"text": "「この価格で、年間○万円のコスト削減効果があります」", "points": 30, "feedback": "総コストと価値のバランスで説明できています。", "isCorrect": true}, {"text": "「他社と比較しても適正価格です」", "points": 10, "feedback": "競合比較より、顧客にとっての価値を伝えましょう。", "isCorrect": false}, {"text": "「これが正規価格なので...」", "points": 0, "feedback": "価値を説明しましょう。", "isCorrect": false}], "situation": "「価格が高い」と言われました。どう返しますか？", "customerLine": "ちょっと高いな...もう少し安くならない？"}]', '{"question": "自社製品を「4C」で説明できますか？Customer Valueは何ですか？", "placeholder": "例: 在庫管理の手間が半分に、売れ筋が一目でわかる、欠品・過剰在庫がなくなる"}', '["製品説明を「機能」から「顧客価値」に変える", "価格を「コスト削減効果」とセットで伝える", "「導入の簡単さ」（学習コストの低さ）をアピールする", "説明より「対話」を意識する"]', NULL, NULL, '2026-01-21 17:45:24.26829+00', '2026-01-21 17:45:24.26829+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (15, 105, '顧客理解の深め方 - ペルソナとジャーニー', '顧客を知ることは、売ることの始まり', '{"icon": "users", "name": "顧客理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Customer Value", "Cost", "Competition", "Communication"], "question": "4Cの「C」に含まれないものは？", "explanation": "4CはCustomer Value, Cost, Convenience, Communicationです。Competitionは含まれません。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 顧客像が曖昧", "content": "（営業会議にて）\n\n鈴木課長:「健太、ターゲット顧客はどんな人だ？」\n\n健太:「えっと...中古車販売店の人です」\n\n鈴木課長:「もっと具体的に」\n\n健太:「...社長さん？」\n\n鈴木課長:「年齢は？何に困ってる？\n        どんな性格？どこで情報を得てる？」\n\n健太:「...わかりません」\n\n鈴木課長:「それじゃ刺さる提案はできないぞ」", "duration": 45}, {"title": "シーン2: ペルソナとは", "content": "山本先輩:「ペルソナって知ってる？」\n\n健太:「ゲームの？」\n\n山本先輩:「違う違う。マーケティング用語だよ」\n\n【ペルソナとは】\nターゲット顧客を「1人の人物」として\n具体的に描いたもの\n\n・基本情報: 年齢、役職、会社規模、地域\n・性格・価値観: 慎重派か積極派か\n・課題・悩み: 何に困っているか\n・情報収集方法: どこで情報を得るか\n・意思決定ポイント: 何があれば決断するか\n\n山本先輩:「抽象的な『ターゲット』を\n        生きた人間として想像するんだ」", "duration": 45}, {"title": "シーン3: ペルソナの例", "content": "山本先輩:「例えば、こんなペルソナだ」\n\n【田中 誠一（52歳）】\n役職: 代表取締役（創業者）\n会社: 田中自動車販売（創業25年、従業員5名、在庫30台）\n地域: 埼玉県郊外\n\n性格: 堅実で慎重。新しいものには懐疑的。\n     人情に厚く、長年の顧客を大切にする。\n\n課題: 紙とExcelでの管理が限界。\n     若手がすぐ辞める（業務が非効率）。\n\n情報収集: 同業者の口コミを重視。\n        展示会には年1回参加。\n\n決断ポイント: 信頼できる人からの紹介。\n          「同業者も使っている」という安心感。\n\n山本先輩:「この人に提案するなら、どうする？」", "duration": 30}], "part2": [{"title": "シーン4: カスタマージャーニーマップ", "content": "山本先輩:「もう一つ重要なのが\n        カスタマージャーニーマップだ」\n\n【カスタマージャーニーマップ】\n顧客が「認知」から「購入」「継続利用」に至るまでの\n体験を時系列で可視化したもの\n\n【フェーズ】\n認知 → 興味 → 検討 → 購入 → 継続\n\n【各フェーズでの顧客行動】\n認知: 展示会、口コミで知る\n興味: WEB検索、資料請求\n検討: デモ、比較検討\n購入: 契約、導入\n継続: 利用、サポート\n\n山本先輩:「営業がアプローチするのは\n        主に『検討』『購入』フェーズだ」", "duration": 45}, {"title": "シーン5: フェーズに応じた対応", "content": "山本先輩:「フェーズによって、\n        顧客の状態が違う」\n\n【各フェーズでの顧客心理】\n認知: 「何それ？」\n興味: 「面白そう」\n検討: 「本当に大丈夫？比較したい」\n購入: 「決めた」\n継続: 「使いこなしたい」\n\n【営業のアプローチ】\n認知期: 存在を知ってもらう（これはマーケの仕事）\n興味期: 資料提供、軽い説明\n検討期: デモ、事例紹介、競合比較\n購入期: クロージング、契約\n継続期: オンボーディング、サポート\n\n健太:「相手がどのフェーズにいるかで\n      アプローチが変わるんですね」", "duration": 30}, {"title": "シーン6: 実践への活用", "content": "山本先輩:「ペルソナを思い浮かべながら\n        商談に臨むと、提案の質が変わる」\n\n【実践のポイント】\n\n✓ 商談前にペルソナを想像する\n  「この人はどんな人だろう？」\n\n✓ 相手のフェーズを見極める\n  「今どの段階にいる？」\n\n✓ フェーズに応じたアプローチ\n  「検討期なら事例と比較情報を」\n\n健太:「顧客を深く理解することが、\n      売ることの始まりなんですね」\n\n山本先輩:「その通り」\n\n【今日の学び】\n「顧客を知ることは、売ることの始まりである」", "duration": 15}]}', '{"title": "ペルソナとカスタマージャーニー", "content": "顧客を「1人の人物」として具体的に理解する", "audioText": "ペルソナで顧客像を具体化し、ジャーニーで購買プロセスを理解しましょう。", "highlight": "顧客を知ることは、売ることの始まり"}', '[{"options": ["架空のキャラクター", "ターゲット顧客を具体的な1人の人物として描いたもの"], "question": "ペルソナとは？", "explanation": "抽象的なターゲットを、生きた人間として具体的に想像します。", "correctIndex": 1}, {"options": ["認知・興味フェーズ", "検討・購入フェーズ"], "question": "営業が主にアプローチするフェーズは？", "explanation": "認知・興味はマーケ、検討・購入は営業が主に担当します。", "correctIndex": 1}]', '{"text": "To know your customer is the beginning of sales.", "author": "Symphony Training Academy", "textJa": "顧客を知ることは、売ることの始まりである。"}', '[{"options": [{"text": "「では今すぐ契約しましょう！」", "points": 0, "feedback": "まだ興味フェーズです。いきなりクロージングは早すぎます。", "isCorrect": false}, {"text": "「資料をお送りしましょうか？」", "points": 30, "feedback": "興味フェーズに適したアプローチです。次のステップに進めます。", "isCorrect": true}, {"text": "「他社と比較して、弊社は...」", "points": 10, "feedback": "まだ検討フェーズではありません。まず興味を深めましょう。", "isCorrect": false}, {"text": "「どんな課題をお持ちですか？」", "points": 15, "feedback": "課題ヒアリングは良いですが、まず資料を見てもらう方が先です。", "isCorrect": false}], "situation": "初めての顧客に電話しました。相手がどのフェーズか見極めています。", "customerLine": "あ、Symphonyさん？前に展示会で見たな。ちょっと興味あるんだよね"}, {"options": [{"text": "「他社より安いです」", "points": 5, "feedback": "価格だけでは差別化になりません。", "isCorrect": false}, {"text": "「他社のことは詳しくないので...」", "points": 0, "feedback": "競合情報は把握しておくべきです。", "isCorrect": false}, {"text": "「中古車業界に特化しているので、御社の業務にぴったりです」", "points": 30, "feedback": "検討フェーズに適した差別化ポイントの説明ができています。", "isCorrect": true}, {"text": "「導入事例をお見せしましょうか？」", "points": 20, "feedback": "事例紹介は良いアプローチですが、まず強みを伝えましょう。", "isCorrect": false}], "situation": "検討フェーズの顧客から「他社も検討している」と言われました。", "customerLine": "A社とB社も検討してるんだよね。御社の強みは？"}]', '{"question": "今担当している顧客は、どのフェーズにいますか？", "placeholder": "例: A社は検討フェーズ、B社は興味フェーズ、C社は購入直前"}', '["商談前にペルソナを想像してから臨む", "相手のフェーズを見極める質問をする", "フェーズに応じた資料・情報を準備する", "検討フェーズの顧客には事例を紹介する"]', '{"title": "ペルソナ作成ワーク", "fields": [{"label": "基本情報（年齢、役職、会社規模）", "placeholder": "例: 52歳、代表取締役、従業員5名"}, {"label": "性格・価値観", "placeholder": "例: 堅実で慎重、新しいものには懐疑的"}, {"label": "課題・悩み", "placeholder": "例: 紙とExcelでの管理が限界、若手がすぐ辞める"}, {"label": "意思決定のポイント", "placeholder": "例: 同業者の口コミ、信頼できる人からの紹介"}], "description": "自社のターゲット顧客のペルソナを作成してみましょう。"}', NULL, '2026-01-21 17:45:24.995908+00', '2026-01-21 17:45:24.995908+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (16, 106, 'ブランディングの基礎', '営業は歩くブランド', '{"icon": "award", "name": "ブランドアンバサダー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["仮面", "ターゲット顧客を具体的な1人の人物として描いたもの", "ゲームのキャラクター", "複数の顧客セグメント"], "question": "ペルソナとは何でしたか？", "explanation": "ターゲット顧客を「1人の人物」として具体的に描いたものでしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: ブランドの力", "content": "（商談にて）\n\n店長:「あ、Symphonyさん？\n      先月、同業の田中さんから聞いたよ。\n      良いって言ってたね」\n\n健太:「あ、ありがとうございます！」\n\n店長:「実は他社も検討してたんだけど、\n      田中さんの紹介なら安心かなと思って」\n\n〜商談後〜\n\n健太:「先輩、なんか商談しやすかったです」\n\n山本先輩:「それがブランドの力だよ」", "duration": 45}, {"title": "シーン2: ブランドとは", "content": "山本先輩:「ブランドって何だと思う？」\n\n健太:「えっと...ロゴとか？」\n\n山本先輩:「それも一部だけど、本質は違う」\n\n【ブランドとは】\n「顧客の頭の中にある、\n  その企業・製品に対するイメージ」\n\nブランド = ロゴ + 製品 + 体験 + 評判 + 感情\n\n山本先輩:「つまり、お客さんが\n        『Symphony』と聞いた時に\n        何を思い浮かべるか。それがブランドだ」", "duration": 45}, {"title": "シーン3: ブランドがある会社 vs ない会社", "content": "山本先輩:「ブランドがあるとどうなる？」\n\n【ブランドがあると】\n✓ 価格競争に巻き込まれにくい\n✓ 指名買いされる（検討期間が短い）\n✓ 紹介が生まれやすい\n✓ 優秀な人材が集まる\n✓ 営業しやすい（話を聞いてもらえる）\n\n【ブランドがないと】\n✕ 常に価格で比較される\n✕ 説明に時間がかかる\n✕ 信頼獲得に時間がかかる\n\n健太:「さっきの商談が楽だったのは、\n      Symphonyのブランドがあったから...」\n\n山本先輩:「そう。先人たちが築いてくれたものだ」", "duration": 30}], "part2": [{"title": "シーン4: 営業は歩くブランド", "content": "山本先輩:「大事なことを言うぞ。\n        営業担当者は『歩くブランド』なんだ」\n\n【営業 = 歩くブランド】\n\n顧客にとって、\n営業の印象 = 会社の印象\n\n・遅刻する営業 → 「この会社は時間にルーズ」\n・約束を守らない → 「この会社は信用できない」\n・丁寧な対応 → 「この会社は信頼できる」\n\n山本先輩:「お客さんは製品を見る前に、\n        営業である君を見ている。\n        君の印象が、会社の印象になるんだ」", "duration": 45}, {"title": "シーン5: ブランドを体現する行動", "content": "山本先輩:「ブランドを体現する行動を意識しろ」\n\n【ブランドを体現する行動】\n\n■ 約束を守る\n「明日までに資料を送ります」→ 必ず送る\n\n■ 一貫性を持つ\n言うことが毎回違う → ブランド毀損\n\n■ プロフェッショナルであり続ける\n身だしなみ、言葉遣い、知識\nすべてがブランドを作る\n\n■ 顧客の成功にコミットする\n売って終わりではなく、成果が出るまで支援\n\n健太:「一つ一つの行動が\n      ブランドを作っていくんですね」", "duration": 30}, {"title": "シーン6: 約束と信頼", "content": "山本先輩:「ブランドって結局、\n        『約束を守り続けた結果』なんだよ」\n\n【ブランド構築の方程式】\n小さな約束を守る × 積み重ね = 信頼 = ブランド\n\n「資料を送ります」→ 送る\n「折り返します」→ 折り返す\n「〇日までに回答します」→ 回答する\n\nこの積み重ねが、\n「Symphonyの営業は信頼できる」\nという ブランドになる\n\n健太:「『Symphonyの営業は信頼できる』...\n      それが最高のブランド資産ですね」\n\n【今日の学び】\n「営業は歩くブランド」\n約束を守り続けることがブランドを作る", "duration": 15}]}', '{"title": "営業とブランド", "content": "営業の印象 = 会社の印象", "audioText": "顧客にとって、営業担当者の印象がそのまま会社の印象になります。", "highlight": "営業は歩くブランド"}', '[{"options": ["ロゴやデザイン", "顧客の頭の中にあるイメージ"], "question": "ブランドとは何？", "explanation": "ブランドは顧客の頭の中にあるイメージの総体です。", "correctIndex": 1}, {"options": ["マーケティング部門だけ", "営業を含む全ての接点"], "question": "ブランドを作るのは？", "explanation": "営業担当者も「歩くブランド」としてブランドを体現します。", "correctIndex": 1}]', '{"text": "A brand is a promise kept.", "author": "マーケティングの格言", "textJa": "ブランドとは、約束を守り続けた結果である。"}', '[{"options": [{"text": "忙しいから明後日に送る", "points": 0, "feedback": "約束を守らないとブランドが毀損されます。", "isCorrect": false}, {"text": "今日中に必ず送る", "points": 30, "feedback": "約束を守ることがブランド構築の基本です。", "isCorrect": true}, {"text": "連絡なしに遅れる", "points": 0, "feedback": "最悪のパターンです。信頼を大きく損ないます。", "isCorrect": false}, {"text": "遅れそうなら事前に連絡する", "points": 15, "feedback": "次善策としては正しいですが、まず約束を守ることを優先しましょう。", "isCorrect": false}], "situation": "顧客に「明日までに資料を送ります」と約束しました。でも今日は忙しい...", "customerLine": "（自分との約束の場面）"}, {"options": [{"text": "「ありがとうございます。機能が豊富です」", "points": 5, "feedback": "機能説明より、信頼に応える姿勢を見せましょう。", "isCorrect": false}, {"text": "「ご紹介ありがとうございます。期待に応えられるよう全力でサポートします」", "points": 30, "feedback": "ブランドへの信頼に応える姿勢が伝わります。", "isCorrect": true}, {"text": "「そうですか。で、ご予算は？」", "points": 0, "feedback": "せっかくの信頼を台無しにしています。", "isCorrect": false}, {"text": "「どなたからのご紹介ですか？」", "points": 10, "feedback": "聞くのは良いですが、まず感謝を伝えましょう。", "isCorrect": false}], "situation": "新規顧客から「御社の評判を聞いて連絡しました」と言われました。", "customerLine": "同業者から評判を聞いて連絡しました。どんな会社ですか？"}]', '{"question": "「ブランドを体現する行動」として、明日から何を意識しますか？", "placeholder": "例: 小さな約束を必ず守る、期日を守る、丁寧な対応を心がける"}', '["約束したことは必ず守る", "期日を守る（遅れそうなら事前連絡）", "一貫性のある対応を心がける", "身だしなみ、言葉遣いに気を配る"]', NULL, NULL, '2026-01-21 17:45:25.883203+00', '2026-01-21 17:45:25.883203+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (17, 107, '競合分析の技術 - SWOT分析', '強みを活かせる場所で戦え', '{"icon": "grid", "name": "戦略分析者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["企業", "歩く", "個人", "製品"], "question": "「営業は○○ブランド」。○○に入る言葉は？", "explanation": "営業担当者は「歩くブランド」。営業の印象が会社の印象になります。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 競合に負ける", "content": "（商談後の報告）\n\n健太:「すみません、A社に負けました...」\n\n鈴木課長:「なぜ負けたかわかるか？」\n\n健太:「えっと...価格が高かったから？」\n\n鈴木課長:「本当にそれだけか？\n        競合のことをどれだけ知ってた？」\n\n健太:「...あまり詳しくは...」\n\n鈴木課長:「敵を知らずに戦ったら、そりゃ負けるよ」", "duration": 45}, {"title": "シーン2: SWOT分析とは", "content": "山本先輩:「SWOT分析って知ってる？」\n\n健太:「なんとなく...」\n\n山本先輩:「自社と競合を分析するフレームワークだ」\n\n【SWOT分析】\n\n内部環境（自社でコントロール可能）\nStrengths（強み）: 競合に対する優位性\nWeaknesses（弱み）: 競合に対する劣位性\n\n外部環境（自社でコントロール不可）\nOpportunities（機会）: 市場のチャンス\nThreats（脅威）: 市場のリスク\n\n山本先輩:「この4つを整理すると、\n        戦略が見えてくる」", "duration": 45}, {"title": "シーン3: SymphonyのSWOT", "content": "山本先輩:「SymphonyをSWOT分析してみよう」\n\n【Strengths（強み）】\n・中古車業界に特化した機能設計\n・販売管理・整備・業販の連携\n・競争力のある価格設定\n・導入後のサポート体制\n\n【Weaknesses（弱み）】\n・大手競合に比べて知名度が低い\n・営業リソースが限られている\n・大規模企業向けの機能が弱い\n\n【Opportunities（機会）】\n・中古車業界のDX化ニーズの高まり\n・人手不足による業務効率化需要\n\n【Threats（脅威）】\n・大手ITベンダーの参入\n・無料・低価格ツールの台頭", "duration": 30}], "part2": [{"title": "シーン4: SWOTから戦略へ", "content": "山本先輩:「SWOTを整理したら、\n        次は戦略を考える」\n\n【SWOT → 戦略】\n\n強み × 機会 → 攻めの戦略\n「業界特化×DX需要」で中規模店を積極開拓\n\n強み × 脅威 → 差別化戦略\n「サポート力」で大手にない安心感を訴求\n\n弱み × 機会 → 改善戦略\n認知度向上のためWEBマーケティング強化\n\n弱み × 脅威 → 防衛戦略\n既存顧客の満足度向上で離反防止\n\n健太:「自社の強みと市場の機会が\n      重なるところで戦えばいいんですね」", "duration": 45}, {"title": "シーン5: 商談での活用", "content": "山本先輩:「商談では、\n        『顧客の課題 × 自社の強み』を\n        マッチングさせるんだ」\n\n【商談での活用例】\n\n顧客の課題: 業務効率化したい\n自社の強み: 業界特化、使いやすい\n\n→ 「中古車業界に特化しているので、\n   御社の業務にすぐフィットします」\n\n顧客の課題: サポートが心配\n自社の強み: 手厚いサポート\n\n→ 「導入後も専任スタッフがサポートします。\n   大手にはない安心感があります」\n\n健太:「弱みを隠すんじゃなくて、\n      強みで勝負するんですね」", "duration": 30}, {"title": "シーン6: 競合との差別化", "content": "山本先輩:「競合に勝つには、\n        正面から戦わないことが大事だ」\n\n【競合との戦い方】\n\n✕ 正面突破\n「A社より機能が多いです！」\n→ 機能競争は消耗戦\n\n○ 差別化\n「A社は汎用的ですが、弊社は御社の業界に特化」\n→ 別の土俵で戦う\n\n山本先輩:「『強みを活かせる場所で戦え』\n        これが鉄則だ」\n\n【今日の学び】\n「強みを活かせる場所で戦え」\nSWOT分析で自社の勝ち筋を見つける", "duration": 15}]}', '{"title": "SWOT分析", "content": "強み・弱み × 機会・脅威 で戦略を導く", "audioText": "SWOT分析で自社と市場を整理し、強みを活かせる場所で戦いましょう。", "highlight": "強みを活かせる場所で戦え"}', '[{"options": ["Organization", "Opportunities"], "question": "SWOTの「O」は何の略？", "explanation": "Opportunities=市場の機会、チャンスのことです。", "correctIndex": 1}, {"options": ["価格で勝負する", "強みを活かせる場所で戦う"], "question": "競合に勝つための基本戦略は？", "explanation": "正面からの価格競争は消耗戦。差別化で戦いましょう。", "correctIndex": 1}]', '{"text": "Fight where your strengths can win.", "author": "戦略の格言", "textJa": "強みを活かせる場所で戦え。"}', '[{"options": [{"text": "「いえ、弊社も機能は多いです」と反論", "points": 5, "feedback": "機能競争は消耗戦です。別の土俵で戦いましょう。", "isCorrect": false}, {"text": "「弊社は御社の業界に特化しているので、必要な機能に絞っています」", "points": 30, "feedback": "自社の強み（業界特化）で差別化できています。", "isCorrect": true}, {"text": "「そうですね...」と認める", "points": 0, "feedback": "強みを伝えましょう。", "isCorrect": false}, {"text": "「でも弊社の方が安いです」", "points": 5, "feedback": "価格競争に持ち込むのは避けましょう。", "isCorrect": false}], "situation": "顧客から「A社の方が機能が多いですね」と言われました。", "customerLine": "A社は機能が多いみたいですけど、御社は？"}, {"options": [{"text": "「弱みはありません」", "points": 0, "feedback": "不誠実に見えます。正直に答えましょう。", "isCorrect": false}, {"text": "「大手に比べて知名度は低いですが、その分、手厚いサポートが強みです」", "points": 30, "feedback": "弱みを認めつつ、強みで補っている説明ができています。", "isCorrect": true}, {"text": "「いろいろあります...」", "points": 5, "feedback": "曖昧すぎます。具体的に、かつ強みとセットで伝えましょう。", "isCorrect": false}, {"text": "「競合の方が詳しいかもしれません」", "points": 0, "feedback": "自信を持って自社を説明しましょう。", "isCorrect": false}], "situation": "「御社の弱みは何ですか？」と聞かれました。", "customerLine": "正直に教えてください。御社の弱みは？"}]', '{"question": "次の商談で、自社のどの「強み」を活かしますか？", "placeholder": "例: 業界特化という強みを活かし、汎用ツールとの差別化を図る"}', '["自社のSWOTを整理しておく", "競合の強み・弱みを調査する", "商談では「強み × 顧客課題」をマッチング", "弱みを聞かれたら、強みとセットで回答"]', '{"title": "SWOT分析ワークシート", "fields": [{"label": "Strengths（強み）", "placeholder": "例: 業界特化、サポート充実、価格競争力"}, {"label": "Weaknesses（弱み）", "placeholder": "例: 知名度が低い、営業リソースが限られる"}, {"label": "Opportunities（機会）", "placeholder": "例: DX化ニーズの高まり、人手不足"}, {"label": "Threats（脅威）", "placeholder": "例: 大手の参入、無料ツールの台頭"}], "description": "自社のSWOT分析をしてみましょう。"}', NULL, '2026-01-21 17:45:26.664241+00', '2026-01-21 17:45:26.664241+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (18, 108, '価格戦略の基本', '価格ではなく価値で勝負せよ', '{"icon": "banknote", "name": "価値提案者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["防衛戦略", "改善戦略", "攻めの戦略", "撤退戦略"], "question": "SWOT分析で「強み × 機会」から導かれる戦略は？", "explanation": "強み × 機会 = 攻めの戦略でしたね。積極的に市場を開拓します。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 価格交渉に負ける", "content": "（商談にて）\n\n店長:「うーん、ちょっと高いな」\n\n健太:「え、えっと...少しなら値引きできますが...」\n\n店長:「B社はもっと安いよ？」\n\n健太:「で、では10%引きで...」\n\n店長:「もう少し何とかならない？」\n\n健太:「...上司に相談します」\n\n〜帰り道〜\n\n山本先輩:「それ、値引きしすぎだろ」", "duration": 45}, {"title": "シーン2: 価格設定の3つのアプローチ", "content": "山本先輩:「価格設定には3つのアプローチがある」\n\n【1. コストベース価格設定】\n原価 + 利益 = 価格\n✓ 計算しやすい、赤字になりにくい\n✕ 顧客価値を反映していない\n\n【2. 競合ベース価格設定】\n競合価格を参考に、同等 or 安く設定\n✓ 市場相場に合う\n✕ 価格競争に巻き込まれやすい\n\n【3. 価値ベース価格設定】★おすすめ\n顧客が感じる「価値」に基づいて価格設定\n✓ 高い利益率、差別化につながる\n✕ 価値の説明が必要\n\n山本先輩:「Symphonyは『価値ベース』で売る」", "duration": 45}, {"title": "シーン3: 価値の可視化", "content": "山本先輩:「『高い』と言われたら、\n        価値を可視化して伝えるんだ」\n\n【価値の可視化トーク例】\n\n「御社の場合、月20時間の業務削減が見込めます。\n 時給1,500円で計算すると、月30,000円のコスト削減。\n 年間にすると360,000円の効果です。\n\n Symphonyの月額費用は28,000円ですから、\n 年間336,000円のご負担で、360,000円の効果。\n 初年度から投資回収できる計算になります」\n\n健太:「数字で価値を示すんですね」\n\n山本先輩:「そう。『安い』より『価値がある』の方が\n        強い説得力を持つ」", "duration": 30}], "part2": [{"title": "シーン4: 価格ではなく価値で勝負", "content": "山本先輩:「価格勝負は消耗戦だ」\n\n【価格勝負の問題】\n✕「うちは他社より安いです」\n→ 「じゃあもっと安いところを探そう」\n→ 価格競争のループに入る\n\n【価値勝負のメリット】\n○「この価格で、これだけの価値が得られます」\n→ 「なるほど、価値があるな」\n→ 価格ではなく価値で選んでもらえる\n\n山本先輩:「『価格が高い』と言われたら、\n        それは『価値が伝わっていない』サイン。\n        値引きじゃなく、価値を再説明するんだ」", "duration": 45}, {"title": "シーン5: 値引きのルール", "content": "山本先輩:「とはいえ、値引きが\n        必要な場面もある。ルールを決めておけ」\n\n【値引きのルール】\n\n1. 理由なき値引きはしない\n   「安くしてほしい」だけでは応じない\n\n2. 値引きには交換条件\n   「年間契約なら○%引き」\n   「3店舗以上なら○%引き」\n\n3. 値引き幅の上限を決める\n   上司と事前に握っておく\n\n4. 安易な値引きはブランド毀損\n   「値引きすれば売れる」は麻薬\n\n山本先輩:「値引きは最後の手段。\n        まず価値で勝負しろ」", "duration": 30}, {"title": "シーン6: 実践", "content": "（後日の商談）\n\n店長:「やっぱりちょっと高いな...」\n\n健太:「おっしゃることはわかります。\n      ただ、御社の場合、月20時間の業務削減で\n      年間36万円の効果が見込めます。\n      \n      年間33万円のご投資で36万円の効果。\n      初年度から投資回収できる計算です」\n\n店長:「なるほど...そう考えると妥当か」\n\n健太:「はい。価格以上の価値をお届けします」\n\n【今日の学び】\n「価格ではなく価値で勝負せよ」\n『高い』は『価値が伝わっていない』サイン", "duration": 15}]}', '{"title": "価格戦略", "content": "コストベース vs 競合ベース vs 価値ベース", "audioText": "価格競争は消耗戦。価値ベースで提案し、価格以上の価値を伝えましょう。", "highlight": "価格ではなく価値で勝負"}', '[{"options": ["すぐに値引きする", "価値を再説明する"], "question": "「高い」と言われた時の正しい対応は？", "explanation": "「高い」は「価値が伝わっていない」サイン。値引きより価値説明が先です。", "correctIndex": 1}, {"options": ["原価に利益を乗せる", "顧客が感じる価値に基づいて設定"], "question": "価値ベース価格設定とは？", "explanation": "顧客にとっての価値を基準に価格を設定します。", "correctIndex": 1}]', '{"text": "Price is what you pay. Value is what you get.", "author": "ウォーレン・バフェット", "textJa": "価格は払うもの。価値は得るもの。"}', '[{"options": [{"text": "「わかりました、10%引きます」", "points": 0, "feedback": "安易な値引きはブランド毀損。まず価値を説明しましょう。", "isCorrect": false}, {"text": "「この価格で、年間○万円の効果が見込めます」と価値を説明", "points": 30, "feedback": "価値を再説明することで、価格への納得感を高められます。", "isCorrect": true}, {"text": "「これが定価なので...」", "points": 5, "feedback": "価値を説明しましょう。", "isCorrect": false}, {"text": "「上司に相談します」", "points": 10, "feedback": "まず自分で価値を説明してから、必要なら相談しましょう。", "isCorrect": false}], "situation": "顧客から「もう少し安くならない？」と言われました。", "customerLine": "もう少し安くしてくれたら決めるんだけど..."}, {"options": [{"text": "「では同じ価格にします」", "points": 0, "feedback": "価格競争は消耗戦です。差別化で勝負しましょう。", "isCorrect": false}, {"text": "「価格だけでなく、サポート体制や業界特化の点で価値があります」", "points": 30, "feedback": "価格以外の価値で差別化できています。", "isCorrect": true}, {"text": "「B社は品質が低いです」", "points": 0, "feedback": "競合批判は避けましょう。自社の価値を伝えます。", "isCorrect": false}, {"text": "「そうですか...」", "points": 0, "feedback": "価値を伝えましょう。", "isCorrect": false}], "situation": "「B社はもっと安いよ」と競合比較されました。", "customerLine": "B社は御社より20%安いんだけど"}]', '{"question": "自社製品の「価値」を数字で説明できますか？", "placeholder": "例: 月20時間の業務削減 × 時給1,500円 = 月3万円、年間36万円の効果"}', '["「高い」と言われたら、価値を数字で説明する", "ROI（投資対効果）を計算できるようにする", "値引きは最後の手段、まず価値で勝負", "値引きには交換条件（年契約など）をつける"]', NULL, NULL, '2026-01-21 17:45:27.489535+00', '2026-01-21 17:45:27.489535+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (19, 109, 'プロモーション戦略', '最高のマーケティングは満足した顧客の口コミ', '{"icon": "megaphone", "name": "プロモーション理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["値引きする", "価値を再説明する", "諦める", "上司に相談する"], "question": "「高い」と言われた時、まず何をすべき？", "explanation": "「高い」は「価値が伝わっていない」サイン。価値を再説明しましょう。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 問い合わせの経路", "content": "（営業会議にて）\n\n鈴木課長:「先月の問い合わせ経路を見てみよう」\n\n【問い合わせ経路の内訳】\nWEB検索経由: 40%\n展示会: 25%\n紹介: 20%\n広告: 10%\nその他: 5%\n\n健太:「WEB検索が一番多いんですね」\n\n鈴木課長:「そう。お客さんは営業に会う前に\n        WEBで情報収集してるんだ」", "duration": 45}, {"title": "シーン2: AIDMA / AISASモデル", "content": "山本先輩:「顧客の購買行動モデルを知ってる？」\n\n【AIDMA（伝統的モデル）】\nA: Attention（注意）→ 知る\nI: Interest（興味）→ 興味を持つ\nD: Desire（欲求）→ 欲しくなる\nM: Memory（記憶）→ 覚えておく\nA: Action（行動）→ 購入する\n\n【AISAS（デジタル時代モデル）】\nA: Attention（注意）→ 知る\nI: Interest（興味）→ 興味を持つ\nS: Search（検索）→ 調べる ★WEBで情報収集\nA: Action（行動）→ 購入する\nS: Share（共有）→ 口コミする ★SNSで拡散\n\n山本先輩:「今の顧客は『検索』してから買う」", "duration": 45}, {"title": "シーン3: 各段階での施策", "content": "山本先輩:「各段階で施策が違う」\n\n【各段階での施策】\n\nAttention（認知）\n→ 広告、展示会、PR\n→ マーケ主導\n\nInterest（興味）\n→ HP、資料、セミナー\n→ 問い合わせ対応\n\nSearch（検索）\n→ SEO、比較サイト\n→ 検索で見つかる情報提供\n\nAction（購入）\n→ 営業提案、デモ、見積、契約\n→ ★営業の主戦場\n\nShare（共有）\n→ 導入事例、口コミ\n→ 顧客満足→紹介依頼", "duration": 30}], "part2": [{"title": "シーン4: 営業の役割", "content": "山本先輩:「営業は主に『Action』段階だ。\n        でも、『Share』を生み出すことで\n        次の『Attention』に繋げられる」\n\n【営業の役割】\n\nAction段階\n・デモ、提案、クロージング\n・顧客の課題解決\n\nShare段階を生み出す\n・顧客満足の追求\n・導入後のフォロー\n・紹介依頼\n\n山本先輩:「満足した顧客が口コミしてくれれば、\n        次の顧客が自然に来る。\n        これが最強のマーケティングだ」", "duration": 45}, {"title": "シーン5: 紹介の依頼", "content": "山本先輩:「紹介を依頼するタイミングと\n        フレーズを覚えておけ」\n\n【紹介依頼のタイミング】\n・導入後、効果が出た時\n・顧客から「良かった」と言われた時\n・定期訪問で関係が深まった時\n\n【紹介依頼のフレーズ】\n\n「ご満足いただけて嬉しいです。\n もしよろしければ、同業のお知り合いで\n 同じような課題をお持ちの方が\n いらっしゃったらご紹介いただけませんか？」\n\n「○○さんにご紹介いただけると、\n 御社と同じように喜んでいただけると思います」\n\n健太:「紹介は最強の新規開拓ですね」", "duration": 30}, {"title": "シーン6: 口コミを生む", "content": "山本先輩:「最高のマーケティングは、\n        満足した顧客の口コミだ」\n\n【口コミを生むために】\n\n✓ 期待以上の価値を提供\n  「思った以上に良かった」と言わせる\n\n✓ 導入後のフォロー\n  売って終わりにしない\n\n✓ 困った時にすぐ対応\n  「いつも助かる」と思ってもらう\n\n✓ 紹介しやすい状態を作る\n  「こういう人がいたら紹介して」と具体的に\n\n【今日の学び】\n「最高のマーケティングは、\n  満足した顧客の口コミである」", "duration": 15}]}', '{"title": "AISAS", "content": "認知 → 興味 → 検索 → 購入 → 共有", "audioText": "満足した顧客の口コミが、次の顧客を連れてきます。", "highlight": "Share（口コミ）が次のAttention（認知）を生む"}', '[{"options": ["Sale と Service", "Search と Share"], "question": "AISASの「S」は何の略？", "explanation": "Search（検索）とShare（共有）です。デジタル時代の特徴です。", "correctIndex": 1}, {"options": ["Attention（認知）", "Action（購入）"], "question": "営業が主に活躍するフェーズは？", "explanation": "営業は主にAction段階で、提案・クロージングを担当します。", "correctIndex": 1}]', '{"text": "The best marketing is a satisfied customer.", "author": "マーケティングの格言", "textJa": "最高のマーケティングは、満足した顧客の口コミである。"}', '[{"options": [{"text": "「ありがとうございます」で終わる", "points": 5, "feedback": "紹介依頼のチャンスを逃しています。", "isCorrect": false}, {"text": "「ありがとうございます。同業のお知り合いで同じ課題をお持ちの方がいたらご紹介いただけませんか？」", "points": 30, "feedback": "絶好のタイミングで紹介依頼ができています。", "isCorrect": true}, {"text": "「じゃあもっと機能を使ってください」", "points": 0, "feedback": "まず感謝を伝え、紹介依頼をしましょう。", "isCorrect": false}, {"text": "「アップグレードしませんか？」", "points": 10, "feedback": "タイミング的に紹介依頼が先です。", "isCorrect": false}], "situation": "導入後、顧客から「良かったよ」と言われました。", "customerLine": "Symphony、導入して良かったよ。業務がだいぶ楽になった"}, {"options": [{"text": "「広告ですね」", "points": 5, "feedback": "事実を伝えましょう。紹介が多いなら、それを伝えることで信頼感が増します。", "isCorrect": false}, {"text": "「既存のお客様からのご紹介が多いです」", "points": 30, "feedback": "口コミの多さは信頼の証。伝えることで安心感を与えられます。", "isCorrect": true}, {"text": "「いろいろです」", "points": 0, "feedback": "具体的に答えましょう。", "isCorrect": false}, {"text": "「わかりません」", "points": 0, "feedback": "自社のマーケティング状況は把握しておきましょう。", "isCorrect": false}], "situation": "新規顧客から「どうやって御社を知ったか」聞かれました。", "customerLine": "そういえば、他のお客さんはどうやって御社を知るんですか？"}]', '{"question": "最近、顧客に紹介を依頼しましたか？どんなタイミングで依頼できそう？", "placeholder": "例: 先月導入した○○社が効果を実感しているので、次回訪問時に紹介を依頼する"}', '["顧客満足度を高め、口コミを生む", "「良かった」と言われたら紹介を依頼する", "紹介依頼のフレーズを準備しておく", "問い合わせ経路を確認し、効果的なチャネルを把握"]', NULL, NULL, '2026-01-21 17:45:28.179033+00', '2026-01-21 17:45:28.179033+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (20, 110, 'マーケティングと営業の連携', '対立ではなく連携で改善する', '{"icon": "handshake", "name": "マーケ連携マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Sale（販売）", "Share（口コミ）", "Support（サポート）", "Service（サービス）"], "question": "AISASの最後の「S」（Share）は何を意味する？", "explanation": "Share=口コミ・共有です。満足した顧客の口コミが次の認知を生みます。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: マーケへの不満", "content": "（営業フロアにて）\n\n健太:「またリードの質が悪い...\n      資料請求しただけで、全然買う気ない」\n\n同僚:「わかる。マーケは数だけ追ってるよな」\n\n健太:「リードの質を上げてほしいよ」\n\n〜その頃、マーケ部門では〜\n\nマーケ担当A:「せっかくリード渡しても、\n         営業がフォローしないんだよな」\n\nマーケ担当B:「商談結果もフィードバックしてくれないし」", "duration": 45}, {"title": "シーン2: リードの分類", "content": "山本先輩:「リードの分類、ちゃんと理解してる？」\n\n【リードのステージ】\n\nリード（Lead）\n→ 何らかの接点を持った見込み客\n\n↓\n\nMQL（Marketing Qualified Lead）\n→ マーケが「営業対象」と判断\n例: 資料DL、セミナー参加、問い合わせ\n\n↓\n\nSQL（Sales Qualified Lead）\n→ 営業が「商談化可能」と判断\n例: 予算あり、時期明確、決裁者アクセス可\n\n↓\n\n商談（Opportunity）→ 受注（Customer）", "duration": 45}, {"title": "シーン3: リードナーチャリング", "content": "山本先輩:「すべてのリードがすぐ買うわけじゃない」\n\n【衝撃のデータ】\n「今すぐ客」は全体の3%\n残り97%は「そのうち客」または「まだまだ客」\n\n【リードナーチャリング（見込み客育成）】\nすぐに購入しない見込み客を、\n継続的にフォローし、\n購買意欲が高まった時に商談化する活動\n\n【ナーチャリングの手法】\n・メールマガジン配信\n・セミナー・ウェビナー案内\n・事例・コンテンツ提供\n・定期的な情報提供\n\n山本先輩:「『買う気がない』んじゃなく、\n        『まだ買う時期じゃない』かもしれない」", "duration": 30}], "part2": [{"title": "シーン4: マーケと営業の連携ポイント", "content": "山本先輩:「マーケと営業の連携が大事だ」\n\n【マーケ → 営業】\n・リード情報の共有\n  （いつ、何に興味を持ったか）\n・MQLの定義を明確に\n・コンテンツ・ツールの提供\n\n【営業 → マーケ】\n・商談結果のフィードバック\n  （なぜ受注/失注したか）\n・顧客の生の声\n・リードの質に対するフィードバック\n\n健太:「お互いに情報共有が大事なんですね」\n\n山本先輩:「対立じゃなく連携。\n        一緒に改善していくんだ」", "duration": 45}, {"title": "シーン5: フィードバックの仕方", "content": "山本先輩:「営業からマーケへの\n        フィードバックも大事だぞ」\n\n【良いフィードバック例】\n\n「○○業界のリードは商談化しやすいです。\n もっと増やせませんか？」\n\n「資料請求だけのリードより、\n セミナー参加者の方が確度が高いです」\n\n「顧客から『○○の情報が欲しい』と\n 言われることが多いので、\n そういうコンテンツがあると助かります」\n\n【悪いフィードバック例】\n\n「リードの質が悪い」（具体性がない）\n「数だけ多くても意味ない」（批判だけ）", "duration": 30}, {"title": "シーン6: 連携ミーティング", "content": "（マーケ・営業の連携ミーティング）\n\nマーケ:「先月のMQLからのSQL化率は20%でした。\n     どんなリードが商談化しやすいですか？」\n\n健太:「セミナー参加者は確度高いです。\n     あと、○○業界のリードは商談化しやすいです」\n\nマーケ:「なるほど。○○業界向けの\n     セミナーを増やしましょうか」\n\n健太:「それは助かります！」\n\n【今日の学び】\n「マーケが悪い、営業が悪い、ではなく、\n  一緒に改善する」\n連携してPDCAを回す", "duration": 15}]}', '{"title": "マーケと営業の連携", "content": "リード → MQL → SQL → 商談 → 受注", "audioText": "マーケと営業は対立ではなく連携。お互いにフィードバックしてPDCAを回しましょう。", "highlight": "対立ではなく連携で改善"}', '[{"options": ["30%", "3%"], "question": "「今すぐ客」は全体の何%？", "explanation": "今すぐ客は3%。残り97%はナーチャリングで育てる必要があります。", "correctIndex": 1}, {"options": ["同じ意味", "MQLはマーケ認定、SQLは営業認定"], "question": "MQLとSQLの違いは？", "explanation": "MQLはマーケティングが認定、SQLは営業が認定したリードです。", "correctIndex": 1}]', '{"text": "Don''t blame marketing. Don''t blame sales. Improve together.", "author": "Symphony Training Academy", "textJa": "マーケが悪い、営業が悪い、ではなく、一緒に改善する。"}', '[{"options": [{"text": "「リードの質が悪いです」と言う", "points": 0, "feedback": "具体性がありません。どんなリードが良い/悪いか伝えましょう。", "isCorrect": false}, {"text": "「問題ないです」と無難に答える", "points": 5, "feedback": "改善のチャンスを逃しています。具体的にフィードバックしましょう。", "isCorrect": false}, {"text": "「セミナー参加者は確度高いです。○○業界のリードも商談化しやすいです」", "points": 30, "feedback": "具体的で建設的なフィードバックです。マーケの施策改善に活かせます。", "isCorrect": true}, {"text": "「もっと数を増やしてください」", "points": 5, "feedback": "質のフィードバックが求められています。", "isCorrect": false}], "situation": "マーケ部門から「リードの質についてフィードバックがほしい」と言われました。", "customerLine": "最近のリードの質、どうですか？率直に教えてください"}, {"options": [{"text": "「わかりました、失礼します」で終わる", "points": 5, "feedback": "次のアクションに繋げましょう。ナーチャリング対象です。", "isCorrect": false}, {"text": "「いつ頃検討されそうですか？その時期にまたご連絡します」", "points": 30, "feedback": "ナーチャリングの姿勢です。時期を確認して次に繋げています。", "isCorrect": true}, {"text": "「でも良い製品なので聞いてください」と売り込む", "points": 0, "feedback": "押し売りは逆効果です。相手のタイミングを尊重しましょう。", "isCorrect": false}, {"text": "「リードの質が悪い」とマーケに苦情を言う", "points": 0, "feedback": "「今は」検討してないだけ。ナーチャリング対象として扱いましょう。", "isCorrect": false}], "situation": "MQLとして渡されたリードに電話したら「今は検討してない」と言われました。", "customerLine": "あ、資料請求したけど、今は特に検討してないんだよね"}]', '{"question": "マーケ部門との連携で、改善できそうなことは？", "placeholder": "例: 商談結果を定期的にフィードバックする、どんなリードが欲しいか具体的に伝える"}', '["商談結果をマーケにフィードバックする", "「リードの質が悪い」ではなく具体的に伝える", "「今すぐ客」以外もナーチャリング対象として扱う", "マーケと定期的に情報共有の場を持つ"]', '{"title": "マーケへのフィードバック作成", "fields": [{"label": "商談化しやすいリードの特徴", "placeholder": "例: セミナー参加者、○○業界、従業員10名以上"}, {"label": "商談化しにくいリードの特徴", "placeholder": "例: 資料請求のみ、個人事業主、予算がない"}, {"label": "欲しいコンテンツ・ツール", "placeholder": "例: 導入事例、ROI計算シート、業界別の資料"}], "description": "マーケ部門に伝えたいフィードバックを整理しましょう。"}', NULL, '2026-01-21 17:45:28.81533+00', '2026-01-21 17:45:28.81533+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (21, 111, 'WEBマーケティング概論', '顧客はすでにWEBで学んでいる', '{"icon": "globe", "name": "WEBマーケ入門者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["競争", "連携", "分離", "統合"], "question": "マーケと営業の関係は「対立」ではなく何でしたか？", "explanation": "マーケと営業は「連携」して一緒に改善していく関係でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 顧客の変化", "content": "（商談にて）\n\n健太:「弊社のSymphonyは...」\n\n店長:「あ、それはWEBで見たよ。\n      機能も価格も大体わかってる。\n      競合のA社とB社も調べた」\n\n健太:「え、そうなんですか...」\n\n店長:「で、御社を選ぶメリットは何？\n      WEBに載ってない情報を教えてよ」\n\n〜帰り道〜\n\n健太:「先輩、お客さん、めちゃくちゃ詳しかったです」", "duration": 45}, {"title": "シーン2: B2B購買行動の変化", "content": "山本先輩:「衝撃のデータを教えてやる」\n\n【衝撃のデータ】\nB2B購買者の57%は、\n営業に会う前にWEBで情報収集を完了している\n（出典：CEB/Gartner調査）\n\n【購買プロセスの変化】\n\n以前:\n課題認識 → 営業に相談 → 情報収集 → 比較検討 → 購入\n（営業が主導）\n\n現在:\n課題認識 → WEBで検索 → 情報収集 → 比較検討 → 営業に相談\n（営業の出番は後半）\n\n山本先輩:「顧客は営業に会う前に、\n        かなりの情報を持っている。\n        だからWEBを理解する必要があるんだ」", "duration": 45}, {"title": "シーン3: WEBマーケティングとは", "content": "山本先輩:「WEBマーケティングの全体像を整理しよう」\n\n【WEBマーケティングとは】\nインターネットを活用したマーケティング活動の総称\n\n【WEBマーケティングの手法】\n\n集客: 見込み客を集める\n→ SEO、広告、SNS、PR\n\n接客: 興味を持ってもらう\n→ WEBサイト、LP、コンテンツ、チャット\n\n追客: 継続的にフォロー\n→ メール、リマーケティング、MA\n\n山本先輩:「お客さんがWEBで何を見て、\n        何を考えているかを理解することが大事だ」", "duration": 30}], "part2": [{"title": "シーン4: 営業がWEBマーケを学ぶ意義", "content": "健太:「でも、WEBマーケは\n      マーケ部門の仕事じゃないですか？」\n\n山本先輩:「営業がWEBマーケを理解するメリットは大きい」\n\n【営業がWEBマーケを理解する意義】\n\n1. 顧客の情報レベルを把握できる\n「この顧客はどこまで調べているか？」\n→ 説明の深さを調整できる\n\n2. 顧客の流入経路がわかる\n「何を検索してうちに来たか？」\n→ 関心ポイントを予測できる\n\n3. WEBコンテンツを営業に活用できる\n「この事例記事、参考になりますよ」\n→ 説得力のある提案ができる\n\n4. マーケ部門と連携しやすくなる\n「こういうコンテンツがあると助かる」\n→ 改善提案ができる", "duration": 45}, {"title": "シーン5: 流入経路を聞く", "content": "山本先輩:「商談で必ず聞くことがある」\n\n【必ず聞く質問】\n「どうやって弊社を知りましたか？」\n\n【聞く理由】\n・顧客の関心ポイントを把握できる\n・効果的なチャネルがわかる\n・マーケへのフィードバックになる\n\n【回答例と対応】\n「○○で検索して」\n→ 検索キーワードから関心を推測\n\n「展示会で見て」\n→ 展示会での情報を覚えているか確認\n\n「知人の紹介で」\n→ 紹介者との関係、紹介理由を確認\n\n山本先輩:「流入経路を聞くだけで、\n        商談の質が変わる」", "duration": 30}, {"title": "シーン6: WEBの先を提供する", "content": "山本先輩:「顧客はすでにWEBで学んでいる。\n        営業は『その先』を提供するんだ」\n\n【WEBでわかること】\n・機能一覧\n・価格\n・導入事例（一般的な情報）\n\n【営業が提供すべき「その先」】\n・御社特有の課題への提案\n・WEBにない詳細情報\n・他社との比較（公平な視点）\n・導入後のイメージ\n・担当者の信頼感\n\n健太:「WEBで調べた上で来てる人には、\n      それ以上の価値を提供しないといけないんですね」\n\n【今日の学び】\n「顧客はすでにWEBで学んでいる。\n  営業はその先を提供せよ」", "duration": 15}]}', '{"title": "B2B購買行動の変化", "content": "57%の購買者は営業に会う前にWEBで情報収集を完了", "audioText": "顧客はすでにWEBで学んでいます。営業はWEB以上の価値を提供しましょう。", "highlight": "営業はWEBの先を提供する"}', '[{"options": ["27%", "57%"], "question": "B2B購買者の何%が営業に会う前にWEBで情報収集を完了？", "explanation": "57%の購買者は営業に会う前にWEBで情報収集を完了しています。", "correctIndex": 1}, {"options": ["マーケ部門の仕事を奪える", "顧客の情報レベルを把握できる"], "question": "営業がWEBマーケを学ぶメリットは？", "explanation": "顧客がどこまで調べているかを把握し、説明の深さを調整できます。", "correctIndex": 1}]', '{"text": "Customers have already learned on the web. Sales must provide beyond.", "author": "Symphony Training Academy", "textJa": "顧客はすでにWEBで学んでいる。営業はその先を提供せよ。"}', '[{"options": [{"text": "「では改めて機能を説明します」", "points": 0, "feedback": "WEBで見た情報の繰り返しは時間の無駄です。", "isCorrect": false}, {"text": "「御社特有の課題に対して、どう活用できるかをお話しします」", "points": 30, "feedback": "WEBにない「御社向け」の情報を提供できています。", "isCorrect": true}, {"text": "「何かご質問ありますか？」", "points": 10, "feedback": "受け身すぎます。こちらから価値を提供しましょう。", "isCorrect": false}, {"text": "「WEBの情報は古いかもしれないので...」", "points": 0, "feedback": "自社のWEBを否定するのは不適切です。", "isCorrect": false}], "situation": "商談で顧客から「御社のことはWEBで調べました」と言われました。", "customerLine": "Symphonyさんのこと、WEBで調べたんで大体わかってます。で、何を話してくれるの？"}, {"options": [{"text": "「ありがとうございます」で終わる", "points": 5, "feedback": "検索キーワードから関心ポイントを深掘りしましょう。", "isCorrect": false}, {"text": "「効率化に関心をお持ちなんですね。具体的にどんな業務を効率化したいですか？」", "points": 30, "feedback": "検索キーワードから関心を読み取り、深掘りできています。", "isCorrect": true}, {"text": "「SEOがんばってます」", "points": 0, "feedback": "顧客には関係ない情報です。", "isCorrect": false}, {"text": "「他のサイトも見ましたか？」", "points": 10, "feedback": "競合を意識しすぎです。まず顧客の関心を深掘りしましょう。", "isCorrect": false}], "situation": "新規顧客に「どうやって弊社を知りましたか？」と聞いています。", "customerLine": "『中古車 販売管理 効率化』で検索して見つけました"}]', '{"question": "商談で「どうやって弊社を知りましたか？」と聞いていますか？", "placeholder": "例: 毎回聞いている/聞いていない。聞くようにして、流入経路と関心を把握したい"}', '["商談で「どうやって知りましたか？」を必ず聞く", "顧客がWEBで調べた情報の「先」を提供する", "自社のWEBサイトをお客さん目線で見てみる", "流入経路をマーケにフィードバックする"]', NULL, NULL, '2026-01-21 17:45:30.098946+00', '2026-01-21 17:45:30.098946+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (22, 112, 'SEOの基礎', '検索されなければ、存在しないのと同じ', '{"icon": "search", "name": "SEO理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["27%", "57%", "77%", "97%"], "question": "B2B購買者の何%が営業に会う前にWEBで情報収集を完了している？", "explanation": "57%の購買者は営業に会う前にWEBで情報収集を完了しています。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 検索の重要性", "content": "（マーケ部門との会話）\n\nマーケ担当:「先月のSEO順位、\n         『中古車 販売管理』で3位に上がりました」\n\n健太:「SEO...検索で上位に出るやつですよね。\n      それって営業に関係あるんですか？」\n\nマーケ担当:「大ありですよ。\n         検索で見つからなければ、\n         問い合わせも来ないんですから」\n\n山本先輩:「SEOの基本は知っておいた方がいいぞ」", "duration": 45}, {"title": "シーン2: SEOとは", "content": "山本先輩:「SEOって何の略か知ってる？」\n\n健太:「えっと...」\n\n【SEOとは】\nSEO = Search Engine Optimization\n（検索エンジン最適化）\n\nGoogleなどの検索結果で、\n自社サイトを上位に表示させるための施策\n\n【なぜSEOが重要か？】\n検索結果の1位 → クリック率 約30%\n検索結果の2位 → クリック率 約15%\n検索結果の3位 → クリック率 約10%\n2ページ目以降 → ほぼ見られない\n\n山本先輩:「検索上位に出ないと、\n        見込み客との接点が生まれない」", "duration": 45}, {"title": "シーン3: 検索エンジンの仕組み", "content": "山本先輩:「検索エンジンの仕組みを簡単に説明するぞ」\n\n【3つのステップ】\n\n1. クロール（Crawl）\nGoogleのロボットがサイトを巡回・発見\n\n2. インデックス（Index）\n発見したページの内容をデータベースに登録\n\n3. ランキング（Ranking）\n検索クエリに対して、関連性の高い順に表示\n\n【Googleが評価するポイント】\n・コンテンツの質\n （ユーザーの疑問に答えているか）\n・E-E-A-T\n （経験・専門性・権威性・信頼性）\n・ユーザー体験\n （読みやすさ、表示速度、モバイル対応）\n・被リンク\n （他サイトからリンクされているか）", "duration": 30}], "part2": [{"title": "シーン4: 顧客の検索行動", "content": "山本先輩:「営業として大事なのは、\n        『顧客がどんなキーワードで検索するか』を\n        想像できることだ」\n\n【顧客の検索キーワード例】\n\n■ 課題系キーワード\n「中古車 在庫管理 効率化」\n「中古車販売店 業務改善」\n「エクセル 在庫管理 限界」\n\n■ 解決策系キーワード\n「中古車 販売管理システム」\n「中古車 業販 プラットフォーム」\n「自動車販売店 DX」\n\n■ 比較系キーワード\n「中古車 販売管理 比較」\n「Symphony 評判」\n「A社 vs B社」\n\n山本先輩:「課題系→解決策系→比較系の順で\n        検索する傾向がある」", "duration": 45}, {"title": "シーン5: 検索キーワードを商談に活かす", "content": "山本先輩:「検索キーワードを知ると、\n        顧客の関心がわかる」\n\n【商談での活用】\n\n顧客:「『中古車 在庫管理 効率化』で検索して\n     御社を見つけました」\n\n→ 顧客の関心は「在庫管理の効率化」\n→ 在庫管理の課題を深掘りする\n→ 効率化の事例を紹介する\n\n顧客:「『Symphony 評判』で検索しました」\n\n→ 顧客は比較検討段階\n→ 導入事例や顧客の声を紹介\n→ 競合との違いを説明\n\n健太:「検索キーワードで\n      商談の方向性が見えるんですね」", "duration": 30}, {"title": "シーン6: 営業ができること", "content": "山本先輩:「営業ができるSEO貢献もある」\n\n【営業ができるSEO貢献】\n\n1. 顧客の検索キーワードをマーケにフィードバック\n「『○○』で検索して来た人が多いです」\n\n2. 顧客からよく聞く課題をコンテンツ化の提案\n「○○という質問が多いので、\n FAQ記事があると良いかも」\n\n3. 導入事例の取材協力\n「○○社さん、事例取材OKです」\n\n4. 顧客の生の声を共有\n「お客さんはこういう言葉を使ってます」\n\n【今日の学び】\n「検索されなければ、存在しないのと同じ」\n顧客の検索行動を理解し、商談に活かす", "duration": 15}]}', '{"title": "SEOと検索順位", "content": "1位: 30% / 2位: 15% / 3位: 10% / 2ページ目以降: ほぼゼロ", "audioText": "検索上位に表示されないと、見込み客との接点が生まれません。", "highlight": "検索上位=見込み客との接点"}', '[{"options": ["Sales Engine Optimization", "Search Engine Optimization"], "question": "SEOとは何の略？", "explanation": "Search Engine Optimization=検索エンジン最適化です。", "correctIndex": 1}, {"options": ["約10%", "約30%"], "question": "検索結果1位のクリック率は約何%？", "explanation": "1位は約30%、2位は約15%、3位は約10%です。", "correctIndex": 1}]', '{"text": "If you can''t be found in search, you don''t exist.", "author": "WEBマーケティングの格言", "textJa": "検索されなければ、存在しないのと同じ。"}', '[{"options": [{"text": "「わかりません」", "points": 0, "feedback": "自社のマーケティング状況は把握しておきましょう。", "isCorrect": false}, {"text": "「『中古車 販売管理』などで検索して見つける方が多いです」", "points": 30, "feedback": "自社の集客経路を理解し、説明できています。", "isCorrect": true}, {"text": "「SEOをがんばっています」", "points": 5, "feedback": "顧客には具体的な情報を伝えましょう。", "isCorrect": false}, {"text": "「広告を出しています」", "points": 5, "feedback": "SEO（自然検索）と広告は別です。", "isCorrect": false}], "situation": "顧客から「どんなキーワードで御社を見つける人が多いですか？」と聞かれました。", "customerLine": "他のお客さんは、どうやって御社を見つけるんですか？"}, {"options": [{"text": "「特にないです」", "points": 0, "feedback": "日々の商談で顧客が使う言葉を意識しましょう。", "isCorrect": false}, {"text": "「『効率化』『人手不足』『エクセル限界』というワードをよく聞きます」", "points": 30, "feedback": "営業現場の生の声は、SEOやコンテンツ作成に非常に有用です。", "isCorrect": true}, {"text": "「そういうのはマーケの仕事では？」", "points": 0, "feedback": "営業とマーケの連携が大切です。", "isCorrect": false}, {"text": "「Symphonyで検索してほしいです」", "points": 5, "feedback": "課題系キーワードから入る顧客も多いです。", "isCorrect": false}], "situation": "マーケ担当から「営業現場でよく聞くキーワードを教えて」と言われました。", "customerLine": "お客さんがよく使う言葉とか、検索しそうなキーワードってありますか？"}]', '{"question": "顧客がよく使う言葉（検索しそうなキーワード）は何ですか？", "placeholder": "例: 効率化、人手不足、エクセル限界、業販ネットワーク"}', '["顧客がどんなキーワードで検索するか想像する", "流入経路（検索キーワード）を商談で聞く", "顧客がよく使う言葉をマーケにフィードバック", "自社のWEBサイトを検索してみる"]', NULL, NULL, '2026-01-21 17:45:30.640426+00', '2026-01-21 17:45:30.640426+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (23, 113, 'コンテンツマーケティング', 'コンテンツは営業の最強の武器', '{"icon": "file-text", "name": "コンテンツ活用者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["約10%", "約30%", "約50%", "約70%"], "question": "検索結果1位のクリック率は約何%？", "explanation": "1位は約30%、2位は約15%、3位は約10%でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 説明に苦労する", "content": "（商談にて）\n\n健太:「弊社のSymphonyを導入すると、\n      業務効率が上がって...」\n\n店長:「うーん、具体的にどうなるの？」\n\n健太:「えっと、在庫管理が楽になって...」\n\n店長:「それはわかるけど、\n      実際にどれくらい効果あるの？\n      他の会社の事例とかないの？」\n\n健太:「事例は...えっと...」\n\n〜帰り道〜\n\n健太:「先輩、うまく説明できませんでした」", "duration": 45}, {"title": "シーン2: コンテンツマーケティングとは", "content": "山本先輩:「コンテンツマーケティングって知ってる？」\n\n【コンテンツマーケティングとは】\n価値あるコンテンツを作成・配信することで、\n見込み客を引きつけ、信頼を構築し、\n最終的に購買につなげるマーケティング手法\n\n「売り込む」のではなく「役立つ情報を提供する」\n\n【コンテンツの種類】\n・ブログ記事: 認知・興味（初期）\n・ホワイトペーパー: 興味・検討（中期）\n・導入事例: 検討・比較（中〜後期）\n・製品資料: 比較・購入（後期）\n・ウェビナー: 興味・検討（中期）\n・動画: 全段階\n\n山本先輩:「これらを営業に活用するんだ」", "duration": 45}, {"title": "シーン3: コンテンツを営業に活用", "content": "山本先輩:「コンテンツは営業の武器になる」\n\n【営業がコンテンツを活用する方法】\n\n■ 商談前\n事前に関連コンテンツを送付\n「商談の前に、こちらの事例をご覧いただけると\n 話が早いと思います」\n\n■ 商談中\n口頭説明の代わりにコンテンツを見せる\n「この課題については、こちらの記事が詳しいです」\n\n■ 商談後\nフォローメールでコンテンツを添付\n「本日お話しした件、こちらの事例も参考になります」\n\n■ 検討中顧客へ\n定期的に役立つコンテンツを送る\n「業界動向のレポートを作成しましたのでお送りします」", "duration": 30}], "part2": [{"title": "シーン4: 事例コンテンツの威力", "content": "山本先輩:「特に導入事例は最強のコンテンツだ」\n\n【導入事例の威力】\n\n✓ 第三者の声は信頼される\n  「御社が言うより、お客さんが言う方が響く」\n\n✓ 具体的な効果がわかる\n  「導入後、業務時間が50%削減」\n\n✓ 自分ごと化しやすい\n  「うちと似た会社が成功してる」\n\n✓ 比較検討の材料になる\n  「この事例があれば、社内説明しやすい」\n\n山本先輩:「商談で行き詰まったら、\n        『似た事例があります』と言えば、\n        話が進むことが多い」", "duration": 45}, {"title": "シーン5: コンテンツを使った商談", "content": "（後日の商談）\n\n健太:「御社と同じ規模の○○モータースさんの\n      事例をお持ちしました」\n\n店長:「お、見せて」\n\n健太:「導入前は在庫管理に月20時間かかっていたのが、\n      導入後は8時間に短縮。\n      年間で144時間、約18日分の削減です」\n\n店長:「へえ、それはすごいな」\n\n健太:「御社も同じような効果が見込めると思います」\n\n店長:「なるほど、社長にも見せてみるよ」\n\n〜帰り道〜\n\n健太:「先輩、コンテンツの威力、わかりました！」", "duration": 30}, {"title": "シーン6: コンテンツを増やす貢献", "content": "山本先輩:「営業がコンテンツ作りに貢献することもできる」\n\n【営業ができる貢献】\n\n✓ 導入事例の取材協力\n「○○社さん、事例取材OKです」\n\n✓ 顧客の課題をコンテンツ化提案\n「○○という質問が多いので、\n FAQ記事があると助かります」\n\n✓ 商談で使えるコンテンツのリクエスト\n「比較表があると説明しやすいです」\n\n✓ コンテンツの効果をフィードバック\n「この事例、めちゃくちゃ刺さりました」\n\n【今日の学び】\n「コンテンツは営業の最強の武器」\nコンテンツを活用し、コンテンツ作りにも貢献する", "duration": 15}]}', '{"title": "コンテンツの種類と役割", "content": "ブログ→ホワイトペーパー→事例→製品資料", "audioText": "コンテンツは営業の最強の武器。商談前・中・後で活用しましょう。", "highlight": "購買段階に応じたコンテンツを活用"}', '[{"options": ["売り込むこと", "役立つ情報を提供すること"], "question": "コンテンツマーケティングの本質は？", "explanation": "売り込むのではなく、役立つ情報を提供して信頼を構築します。", "correctIndex": 1}, {"options": ["自社の宣伝だから", "第三者の声で信頼されるから"], "question": "導入事例が強力な理由は？", "explanation": "自社が言うより、お客さんの声の方が信頼されます。", "correctIndex": 1}]', '{"text": "Content is the strongest weapon for sales.", "author": "Symphony Training Academy", "textJa": "コンテンツは営業の最強の武器である。"}', '[{"options": [{"text": "「今は手元にないです」", "points": 0, "feedback": "事例は事前に準備しておきましょう。", "isCorrect": false}, {"text": "「御社と同じ規模の○○モータースさんの事例があります」", "points": 30, "feedback": "顧客が自分ごと化しやすい事例を提示できています。", "isCorrect": true}, {"text": "「うちの実績は多いです」", "points": 5, "feedback": "具体的な事例を見せましょう。", "isCorrect": false}, {"text": "「事例は秘密です」", "points": 0, "feedback": "公開可能な事例は積極的に活用しましょう。", "isCorrect": false}], "situation": "顧客から「他社の事例はありますか？」と聞かれました。", "customerLine": "うちと似た会社の事例ってありますか？"}, {"options": [{"text": "「ありがとうございました」だけ送る", "points": 5, "feedback": "コンテンツを添付して、検討材料を提供しましょう。", "isCorrect": false}, {"text": "「本日の内容に関連した事例と資料をお送りします」", "points": 30, "feedback": "商談の内容に関連したコンテンツを提供できています。", "isCorrect": true}, {"text": "「いつ契約できますか？」と聞く", "points": 0, "feedback": "まず検討材料を提供しましょう。", "isCorrect": false}, {"text": "全製品のカタログを大量に送る", "points": 5, "feedback": "関連するコンテンツに絞って送りましょう。", "isCorrect": false}], "situation": "商談後のフォローメールを送ります。何を添付しますか？", "customerLine": "（商談後のフォロー場面）"}]', '{"question": "商談で使えるコンテンツ（事例、資料等）を把握していますか？", "placeholder": "例: 事例3本、製品資料、FAQ記事など。もっと事例が欲しい"}', '["自社の事例・コンテンツを把握する", "商談前に関連コンテンツを送る", "商談後のフォローにコンテンツを添付", "「こんなコンテンツが欲しい」をマーケにリクエスト"]', NULL, NULL, '2026-01-21 17:45:31.200958+00', '2026-01-21 17:45:31.200958+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (24, 114, 'SNSマーケティング', 'SNSは営業の延長線上にある', '{"icon": "share-2", "name": "SNS理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["売り込むこと", "役立つ情報を提供すること", "広告を出すこと", "SEOを上げること"], "question": "コンテンツマーケティングの本質は？", "explanation": "売り込むのではなく、役立つ情報を提供して信頼を構築することでしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: SNSでの発見", "content": "（営業フロアにて）\n\n同僚:「健太、X（Twitter）やってる？」\n\n健太:「プライベートではやってますけど...\n      仕事では使ってないです」\n\n同僚:「俺、業界の情報収集に使ってるよ。\n      あと、この前お客さんがXで\n      Symphonyのこと呟いてくれてさ」\n\n健太:「え、そうなんですか？」\n\n同僚:「『導入して良かった』って。\n      それ見て問い合わせ来た人もいるらしい」", "duration": 45}, {"title": "シーン2: 各SNSの特性", "content": "山本先輩:「SNSの特性を理解しておくといい」\n\n【各SNSプラットフォームの特性】\n\n■ X（旧Twitter）\n特性: リアルタイム、拡散力、業界情報収集\nB2B活用: 業界ニュース発信、専門家ブランディング\n\n■ Facebook\n特性: 実名制、コミュニティ、中高年層\nB2B活用: 企業ページ運営、広告配信、グループ\n\n■ LinkedIn\n特性: ビジネス特化、B2Bに強い、決裁者アクセス\nB2B活用: 企業ブランディング、リード獲得、採用\n\n■ YouTube\n特性: 動画、検索エンジン、長期資産\nB2B活用: 製品紹介動画、ハウツー、ウェビナー", "duration": 45}, {"title": "シーン3: B2BでのSNS活用", "content": "山本先輩:「B2BでもSNSは使われてる」\n\n【B2BでのSNS活用実態】\n\n・情報収集: 業界トレンド、競合動向\n・ブランディング: 企業・個人の専門性アピール\n・リード獲得: 特にLinkedInは有効\n・顧客とのコミュニケーション: ゆるやかな関係維持\n\n【LinkedInの重要性】\n・ビジネス特化SNS\n・決裁者にアクセスしやすい\n・B2Bマーケティングに最適\n・海外では当たり前に使われている\n\n山本先輩:「特にLinkedInは\n        B2B営業なら知っておくべきだな」", "duration": 30}], "part2": [{"title": "シーン4: 営業個人のSNS活用", "content": "山本先輩:「営業個人としてSNSを活用する方法もある」\n\n【営業個人のSNS活用】\n\n1. 業界情報をキャッチ\n・業界ニュースをフォロー\n・トレンドを把握\n・顧客との会話のネタになる\n\n2. 専門家としての発信\n・業界知識の発信\n・信頼性の構築\n・「あの人は詳しい」と思われる\n\n3. 顧客との関係維持\n・ゆるやかなつながり\n・コメント、いいねで存在感\n・ダイレクトメッセージでの連絡\n\n4. 競合の動向を把握\n・競合のSNSをチェック\n・新製品、キャンペーン情報", "duration": 45}, {"title": "シーン5: SNS活用の注意点", "content": "山本先輩:「SNS活用には注意点もある」\n\n【SNS活用の注意点】\n\n■ 会社のルールを確認\n・SNSポリシーがあるか確認\n・会社名を出す場合のルール\n\n■ プライベートとの線引き\n・仕事用アカウントを分ける\n・不適切な投稿は避ける\n\n■ 炎上リスク\n・批判的な投稿は避ける\n・競合の悪口は絶対NG\n\n■ 時間の使いすぎ\n・業務時間中の過度な利用は避ける\n・目的を持って使う\n\n山本先輩:「SNSは諸刃の剣。\n        うまく使えば武器になる」", "duration": 30}, {"title": "シーン6: まず情報収集から", "content": "山本先輩:「いきなり発信しなくていい。\n        まず情報収集から始めろ」\n\n【SNS活用のステップ】\n\nStep 1: 情報収集\n・業界インフルエンサーをフォロー\n・競合アカウントをフォロー\n・業界ニュースをチェック\n\nStep 2: 反応する\n・役立つ情報に「いいね」\n・コメントで存在感を出す\n\nStep 3: 発信する（任意）\n・業界知識の共有\n・イベント参加レポート\n・顧客との共感ポイント\n\n【今日の学び】\n「SNSは営業の延長線上にある」\nまず情報収集から始めてみる", "duration": 15}]}', '{"title": "各SNSの特性", "content": "X=拡散力 / Facebook=コミュニティ / LinkedIn=B2B / YouTube=動画", "audioText": "各SNSの特性を理解し、まず情報収集から始めましょう。", "highlight": "LinkedInはB2Bに特に有効"}', '[{"options": ["Instagram", "LinkedIn"], "question": "B2Bに特に有効なSNSは？", "explanation": "LinkedInはビジネス特化で、決裁者にアクセスしやすいです。", "correctIndex": 1}, {"options": ["いきなり発信する", "まず情報収集から始める"], "question": "営業がSNSを活用する最初のステップは？", "explanation": "まず業界情報の収集から始め、徐々に活用の幅を広げましょう。", "correctIndex": 1}]', '{"text": "SNS is an extension of sales.", "author": "Symphony Training Academy", "textJa": "SNSは営業の延長線上にある。"}', '[{"options": [{"text": "「あまり詳しくないです」", "points": 0, "feedback": "SNSで業界情報を収集しておきましょう。", "isCorrect": false}, {"text": "「そうですね、Xで○○さんがこんな投稿をしていて...」", "points": 30, "feedback": "SNSでの情報収集が商談に活きています。", "isCorrect": true}, {"text": "「SNSは見ないんで...」", "points": 0, "feedback": "情報収集ツールとしてSNSを活用しましょう。", "isCorrect": false}, {"text": "「ネットで調べてみます」", "points": 5, "feedback": "日頃からの情報収集が大切です。", "isCorrect": false}], "situation": "顧客との商談で、業界の最新トレンドの話題になりました。", "customerLine": "最近、業界でDXの話題が多いですよね。何か情報ありますか？"}, {"options": [{"text": "スルーする", "points": 0, "feedback": "良い口コミには感謝を伝えましょう。", "isCorrect": false}, {"text": "「いいね」と感謝のコメントをする", "points": 30, "feedback": "顧客との関係維持につながります。", "isCorrect": true}, {"text": "「もっと宣伝してください」とDMする", "points": 0, "feedback": "押し付けがましいです。自然な感謝を伝えましょう。", "isCorrect": false}, {"text": "勝手にリツイートして宣伝に使う", "points": 5, "feedback": "許可を取ってから活用しましょう。", "isCorrect": false}], "situation": "既存顧客がSNSでSymphonyについて良い投稿をしてくれました。", "customerLine": "（SNS上での場面）「Symphony導入して業務効率上がった！おすすめ」"}]', '{"question": "SNSで業界情報を収集していますか？フォローしているアカウントは？", "placeholder": "例: 業界メディア、競合企業、インフルエンサーなど"}', '["業界のインフルエンサーをSNSでフォローする", "競合のSNSアカウントをチェックする", "LinkedInのプロフィールを整える", "顧客のSNS投稿に「いいね」やコメントをする"]', NULL, NULL, '2026-01-21 17:45:31.912487+00', '2026-01-21 17:45:31.912487+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (25, 115, 'リスティング広告の基礎', '検索している人は、今すぐ客の可能性が高い', '{"icon": "mouse-pointer", "name": "広告理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Instagram", "LinkedIn", "TikTok", "Pinterest"], "question": "B2Bに特に有効なSNSは？", "explanation": "LinkedInはビジネス特化で、B2Bに特に有効でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 広告経由の問い合わせ", "content": "（営業フロアにて）\n\n鈴木課長:「健太、この問い合わせ対応してくれ。\n        広告経由だから、早めに連絡して」\n\n健太:「広告経由...って何か違うんですか？」\n\n鈴木課長:「検索して来た人だからな。\n        ニーズが明確で、比較検討中の可能性が高い。\n        スピード勝負だ」\n\n健太:「わかりました、すぐ電話します」", "duration": 45}, {"title": "シーン2: リスティング広告とは", "content": "山本先輩:「リスティング広告を説明するぞ」\n\n【リスティング広告とは】\n検索キーワードに連動して表示される広告\n（Google広告、Yahoo広告）\n\n【仕組み】\n1. 広告主がキーワードを設定\n2. ユーザーがそのキーワードで検索\n3. 検索結果の上部・下部に広告が表示\n4. クリックされると課金（CPC: Cost Per Click）\n\n【特徴】\n・検索意図が明確なユーザーにアプローチ\n・クリック課金型（表示だけなら無料）\n・即効性がある（SEOより早く効果が出る）\n・費用をかければ上位表示可能", "duration": 45}, {"title": "シーン3: 広告とSEOの違い", "content": "山本先輩:「広告とSEOの違いを整理しよう」\n\n【リスティング広告 vs SEO】\n\n■ リスティング広告\n表示位置: 検索結果の上部（広告枠）\n費用: クリック課金（有料）\n即効性: 高い（すぐに表示される）\n継続性: 費用を止めると表示されなくなる\n\n■ SEO（自然検索）\n表示位置: 検索結果の本文（オーガニック枠）\n費用: 直接費用はかからない\n即効性: 低い（上位表示まで時間がかかる）\n継続性: 上位を維持すれば継続的に流入\n\n山本先輩:「広告は『即効性』、\n        SEOは『継続性』が強み」", "duration": 30}], "part2": [{"title": "シーン4: 広告経由リードの特徴", "content": "山本先輩:「広告経由のリードには特徴がある」\n\n【広告経由リードの傾向】\n\n1. 検索意図が明確\n「○○ システム」と検索して来ている\n→ ニーズが顕在化している\n\n2. 比較検討中が多い\n複数の広告をクリックしている可能性\n→ 競合も見ている\n\n3. スピード勝負\n検討が進んでいる段階\n→ 早めの対応が重要\n\n山本先輩:「広告経由は『今すぐ客』の\n        可能性が高い。だから早く動け」", "duration": 45}, {"title": "シーン5: 広告経由リードへの対応", "content": "山本先輩:「広告経由リードへの対応ポイントだ」\n\n【対応ポイント】\n\n■ 初回連絡を早く\n問い合わせ後、24時間以内に連絡\n（できれば数時間以内）\n\n■ 検索キーワードを確認\n「何を検索してうちに来たか？」\n→ 関心ポイントを把握\n\n■ 競合比較を想定\n「他社も見ていますか？」\n→ 差別化ポイントを準備\n\n■ 比較検討に役立つ情報を提供\n事例、比較表、ROI計算\n→ 検討材料を素早く提供", "duration": 30}, {"title": "シーン6: スピードの重要性", "content": "山本先輩:「広告経由の対応が遅いとどうなるか」\n\n【対応が遅いと...】\n・競合に先を越される\n・顧客の熱が冷める\n・「対応が遅い会社」という印象\n\n【ハーバードビジネスレビューの調査】\n問い合わせから5分以内に連絡した企業は、\n30分後に連絡した企業より、\n商談化率が21倍高い\n\n健太:「21倍...スピードって大事なんですね」\n\n山本先輩:「検索している人は、今すぐ客。\n        その瞬間を逃すな」\n\n【今日の学び】\n「検索している人は、今すぐ客の可能性が高い」\n広告経由リードは早めに対応", "duration": 15}]}', '{"title": "リスティング広告", "content": "検索キーワード → 広告表示 → クリック課金", "audioText": "リスティング広告経由の問い合わせは比較検討中。スピード対応が重要です。", "highlight": "広告経由は今すぐ客、スピード対応"}', '[{"options": ["表示課金", "クリック課金"], "question": "リスティング広告の課金方式は？", "explanation": "クリックされた時だけ課金される方式です。", "correctIndex": 1}, {"options": ["じっくり検討させる", "スピード対応"], "question": "広告経由リードへの対応で大切なことは？", "explanation": "5分以内の連絡で商談化率が21倍高いというデータがあります。", "correctIndex": 1}]', '{"text": "People who are searching are likely ready to buy.", "author": "WEBマーケティングの格言", "textJa": "検索している人は、今すぐ客の可能性が高い。"}', '[{"options": [{"text": "明日の朝に連絡する", "points": 0, "feedback": "遅すぎます。競合に先を越される可能性があります。", "isCorrect": false}, {"text": "今すぐ（数時間以内に）連絡する", "points": 30, "feedback": "スピード対応が重要。5分以内で商談化率21倍です。", "isCorrect": true}, {"text": "資料だけ送っておく", "points": 10, "feedback": "資料送付だけでなく、電話でコンタクトしましょう。", "isCorrect": false}, {"text": "他の仕事が終わってから", "points": 5, "feedback": "広告経由は優先度高。早めに対応しましょう。", "isCorrect": false}], "situation": "広告経由の問い合わせが来ました。いつ連絡しますか？", "customerLine": "（問い合わせフォーム）Symphonyに興味があります。資料ください"}, {"options": [{"text": "「いつ契約できますか？」", "points": 0, "feedback": "いきなりクロージングは早すぎます。", "isCorrect": false}, {"text": "「どんなキーワードで検索されましたか？」", "points": 30, "feedback": "検索キーワードから関心ポイントを把握できます。", "isCorrect": true}, {"text": "「他社も見てますか？」", "points": 10, "feedback": "まず関心ポイントを聞いてから。", "isCorrect": false}, {"text": "「弊社の機能を説明します」", "points": 5, "feedback": "まず顧客の関心を聞きましょう。", "isCorrect": false}], "situation": "広告経由の顧客に電話しました。最初に何を聞きますか？", "customerLine": "あ、Symphonyさん？問い合わせした者です"}]', '{"question": "広告経由の問い合わせに、どれくらいの時間で対応していますか？", "placeholder": "例: 当日中に対応している / 翌日になることもある"}', '["広告経由の問い合わせは即日対応を心がける", "「どうやって知りましたか？」を必ず聞く", "比較検討を想定した資料を準備しておく", "対応スピードを意識する"]', NULL, NULL, '2026-01-21 17:45:32.967659+00', '2026-01-21 17:45:32.967659+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (26, 116, 'ディスプレイ広告とリマーケティング', '広告は顧客体験の一部', '{"icon": "repeat", "name": "リマーケ理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["2倍", "5倍", "10倍", "21倍"], "question": "問い合わせから5分以内に連絡すると、30分後より商談化率は何倍？", "explanation": "5分以内の連絡で商談化率が21倍高いというデータがありましたね。", "correctIndex": 3}', '{"part1": [{"title": "シーン1: 追いかけてくる広告", "content": "（営業フロアにて）\n\n健太:「先輩、この前競合のサイトを見たら、\n      その後ずっと競合の広告が出てくるんですよ」\n\n山本先輩:「それはリマーケティング広告だな」\n\n健太:「追いかけてくるみたいで、\n      ちょっと怖いですね...」\n\n山本先輩:「お客さんも同じ体験をしてるぞ。\n        うちのサイトを見た人にも、\n        リマーケ広告を出してる」", "duration": 45}, {"title": "シーン2: ディスプレイ広告とは", "content": "山本先輩:「まずディスプレイ広告を説明するぞ」\n\n【ディスプレイ広告とは】\nWEBサイトやアプリ上に表示されるバナー広告\n\n【リスティング広告との違い】\nリスティング: 検索している人に表示（プル型）\nディスプレイ: ブラウジング中の人に表示（プッシュ型）\n\n【ターゲティング方法】\n・コンテンツターゲット\n  関連するサイトに表示\n\n・オーディエンスターゲット\n  特定の興味関心を持つ人に表示\n\n・リマーケティング\n  過去にサイトを訪問した人に表示", "duration": 45}, {"title": "シーン3: リマーケティングの仕組み", "content": "山本先輩:「リマーケティングの仕組みを説明するぞ」\n\n【リマーケティング（追跡型広告）】\n一度サイトを訪問したユーザーに、\nその後も広告を表示する手法\n\n【仕組み】\n1. ユーザーがサイトを訪問\n2. Cookie（追跡情報）が保存される\n3. 他のサイトを見ている時にも広告が表示\n\n【効果】\n・検討中の顧客に再アプローチ\n・ブランド想起の維持\n・検討期間の長いB2Bに有効\n\n山本先輩:「B2Bは検討期間が長いから、\n        リマーケティングが効果的なんだ」", "duration": 30}], "part2": [{"title": "シーン4: 顧客心理の理解", "content": "山本先輩:「顧客がどう感じているか、\n        想像することが大事だ」\n\n【顧客の体験】\n\n「あのサイトを見た後、\n 広告が追いかけてくる...」\n\n【顧客心理】\n肯定的: 「忘れてたけど、そういえば検討してたな」\n中立的: 「よく見かけるな、覚えておこう」\n否定的: 「しつこいな、追われてる感じ」\n\n【営業への示唆】\n・顧客は広告を見ている前提で話す\n・「広告ご覧になりましたか？」と聞いてもいい\n・しつこい印象を持たれていないか注意", "duration": 45}, {"title": "シーン5: 商談での活用", "content": "山本先輩:「リマーケティングを商談に活かす方法」\n\n【商談での活用】\n\n■ 認知度の確認\n「弊社の広告、ご覧になったことありますか？」\n→ どれくらい接触しているか把握\n\n■ 検討段階の推測\n広告をよく見ている = 検討が進んでいる可能性\n→ 比較検討の情報を準備\n\n■ 印象の確認\n「広告、しつこくなかったですか？」\n→ 顧客体験の確認、フィードバック材料\n\n健太:「広告も営業活動の一部として\n      捉えるんですね」", "duration": 30}, {"title": "シーン6: 顧客体験として捉える", "content": "山本先輩:「広告は顧客体験の一部だ」\n\n【広告を顧客体験として捉える】\n\n✓ 広告は「営業の代わり」に働いている\n  → 営業がいない時も顧客に接触\n\n✓ 広告の印象 = 会社の印象\n  → クリエイティブの質が大事\n\n✓ しつこすぎると逆効果\n  → 適切な頻度のコントロールが必要\n\n✓ 広告と営業の一貫性\n  → 広告で言っていることと営業の説明が違うとNG\n\n【今日の学び】\n「広告は顧客体験の一部である」\n顧客がどんな広告体験をしているか想像する", "duration": 15}]}', '{"title": "リマーケティング", "content": "サイト訪問 → Cookie保存 → 追跡広告表示", "audioText": "リマーケティングは一度訪問した人を追跡する広告。B2Bに効果的です。", "highlight": "B2Bは検討期間が長いので効果的"}', '[{"options": ["新規ユーザーに表示する広告", "サイト訪問者を追跡して表示する広告"], "question": "リマーケティング広告とは？", "explanation": "一度サイトを訪問したユーザーに、その後も広告を表示する手法です。", "correctIndex": 1}, {"options": ["費用が安いから", "検討期間が長いから"], "question": "リマーケティングがB2Bに効果的な理由は？", "explanation": "B2Bは検討期間が長いため、継続的な接触が効果的です。", "correctIndex": 1}]', '{"text": "Advertising is part of the customer experience.", "author": "WEBマーケティングの格言", "textJa": "広告は顧客体験の一部である。"}', '[{"options": [{"text": "「そうですか」で終わる", "points": 5, "feedback": "会話を広げましょう。広告接触は検討が進んでいる証拠かも。", "isCorrect": false}, {"text": "「ご関心をお持ちいただいているんですね。具体的に何か気になる点はありますか？」", "points": 30, "feedback": "広告接触を商談に繋げられています。", "isCorrect": true}, {"text": "「しつこくてすみません」と謝る", "points": 5, "feedback": "否定的に受け取らなくても大丈夫です。", "isCorrect": false}, {"text": "「マーケがやってるんで、僕は知りません」", "points": 0, "feedback": "広告も営業活動の一部として理解しましょう。", "isCorrect": false}], "situation": "顧客から「御社の広告、最近よく見ます」と言われました。", "customerLine": "Symphonyさんの広告、最近よく見かけるんですよね"}, {"options": [{"text": "「わかりません」", "points": 0, "feedback": "広告と営業は連携が大切。現場の声を伝えましょう。", "isCorrect": false}, {"text": "「広告を見て来た人は、比較検討が進んでいる印象です」", "points": 30, "feedback": "現場の感触をフィードバックできています。", "isCorrect": true}, {"text": "「広告はマーケの仕事では？」", "points": 0, "feedback": "広告と営業は連携が大切です。", "isCorrect": false}, {"text": "「効果ないんじゃないですか」", "points": 0, "feedback": "建設的なフィードバックをしましょう。", "isCorrect": false}], "situation": "マーケ担当から「広告の効果について、営業の感触を教えて」と聞かれました。", "customerLine": "広告経由のお客さん、どんな印象ですか？"}]', '{"question": "自社の広告を見たことがありますか？顧客はどんな印象を持っていそう？", "placeholder": "例: リマーケ広告をよく見る / 顧客から「広告見た」と言われることがある"}', '["自社の広告を顧客目線で見てみる", "顧客に「広告見ましたか？」と聞いてみる", "広告と営業の説明に一貫性があるか確認", "広告への反応をマーケにフィードバック"]', NULL, NULL, '2026-01-21 17:45:33.548992+00', '2026-01-21 17:45:33.548992+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (27, 117, 'ランディングページ（LP）の設計', 'LPは24時間働く営業マン', '{"icon": "layout", "name": "LP理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["新規ユーザー向け広告", "サイト訪問者を追跡する広告", "テレビCM", "チラシ広告"], "question": "リマーケティング広告とは？", "explanation": "一度サイトを訪問したユーザーに、その後も広告を表示する手法でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: LPを見てくる顧客", "content": "（商談にて）\n\n店長:「LP見ましたよ。\n      『業務効率50%改善』って書いてあったけど、\n      本当にそんなに変わるの？」\n\n健太:「LP...えっと、どのページですか？」\n\n店長:「広告クリックしたら出てきたページ。\n      長い1ページのやつ」\n\n健太:「あ、はい...（見たことないな...）」\n\n〜帰り道〜\n\n健太:「先輩、LPって何ですか？」", "duration": 45}, {"title": "シーン2: LPとは", "content": "山本先輩:「LPを説明するぞ」\n\n【ランディングページ（LP）とは】\n広告やメールからの流入を受け、\n特定のアクション（問い合わせ、資料請求等）に\n導くための1枚完結型のページ\n\n【LPの特徴】\n・1ページで完結（他ページへの遷移を減らす）\n・1つの目的（問い合わせ、資料DL等）に特化\n・訴求力のあるデザイン・コピー\n\n【LPの構成】\n1. ファーストビュー: キャッチコピー、メインビジュアル\n2. 課題提起: 「こんなお悩みありませんか？」\n3. 解決策: 製品・サービスの紹介\n4. 実績・事例: 信頼性の証明\n5. CTA: 問い合わせボタン、フォーム", "duration": 45}, {"title": "シーン3: LPは24時間働く営業マン", "content": "山本先輩:「LPは『24時間働く営業マン』だ」\n\n【LPの役割】\n\n✓ 営業がいない時も働いている\n  → 夜中でも問い合わせを獲得\n\n✓ 大量の人に同時にアプローチ\n  → 1人の営業より多くの人に説明\n\n✓ 一定の品質で説明\n  → 営業のスキル差に左右されない\n\n【LPと営業の関係】\nLP: 興味を持たせ、問い合わせに導く\n営業: LPでは伝えきれない部分を説明\n\n山本先輩:「だからLPを見ておくのは大事だ。\n        顧客が何を見て来たかわかるからな」", "duration": 30}], "part2": [{"title": "シーン4: CVR向上のポイント", "content": "山本先輩:「LPの効果を測る指標はCVRだ」\n\n【CVR（Conversion Rate）】\n訪問者のうち、目標アクション（問い合わせ等）を\nした人の割合\n\nCVR = コンバージョン数 ÷ 訪問者数 × 100\n\n【CVR向上のポイント】\n\n1. ファーストビューで離脱させない\n  何のページか3秒で伝わるか\n\n2. ベネフィットを明確に\n  「何ができるか」ではなく「どう良くなるか」\n\n3. 信頼性の証明\n  導入実績、顧客の声、メディア掲載\n\n4. CTAの最適化\n  ボタンの文言、色、位置\n\n5. フォームの最適化\n  入力項目は最小限に", "duration": 45}, {"title": "シーン5: 営業視点でのLP改善", "content": "山本先輩:「営業がLPにフィードバックできることも多い」\n\n【営業がフィードバックできること】\n\n✓ 顧客からよく聞く課題\n  → LPの課題提起に反映\n\n✓ 刺さるトーク\n  → キャッチコピーに反映\n\n✓ よくある質問\n  → FAQに追加\n\n✓ 競合との比較ポイント\n  → 差別化訴求に反映\n\n山本先輩:「営業の知見がLP改善に活きて、\n        CVR向上 → リード増加 → 営業機会増加\n        という好循環が生まれる」", "duration": 30}, {"title": "シーン6: LPを見て商談に備える", "content": "山本先輩:「商談前に自社のLPを見ておけ」\n\n【商談前にLPを確認する理由】\n\n1. 顧客が何を見て来たかわかる\n  「LPには○○と書いてありましたよね」\n  → 話がスムーズに進む\n\n2. LPとの一貫性を保てる\n  LPと違うことを言うと混乱させる\n  → 同じメッセージで安心感\n\n3. LPにない情報を補足できる\n  「LPには書いてませんが、実は...」\n  → 付加価値を提供\n\n【今日の学び】\n「LPは24時間働く営業マンである」\nLPを理解し、営業に活かす", "duration": 15}]}', '{"title": "LP（ランディングページ）", "content": "ファーストビュー→課題提起→解決策→実績→CTA", "audioText": "LPは特定のアクションに導く1枚完結型ページ。24時間働く営業マンです。", "highlight": "LPは24時間働く営業マン"}', '[{"options": ["Long Page", "Landing Page"], "question": "LPとは何の略？", "explanation": "Landing Page=着地ページ。広告などから流入する先のページです。", "correctIndex": 1}, {"options": ["クリック率", "コンバージョン率"], "question": "CVRとは？", "explanation": "Conversion Rate=訪問者のうち目標アクションをした人の割合です。", "correctIndex": 1}]', '{"text": "A landing page is a 24-hour salesperson.", "author": "WEBマーケティングの格言", "textJa": "LPは24時間働く営業マンである。"}', '[{"options": [{"text": "「LP見てないのでわかりません」", "points": 0, "feedback": "自社のLPは必ず見ておきましょう。", "isCorrect": false}, {"text": "「はい、○○社の事例では50%改善しました。御社でも同様の効果が期待できます」", "points": 30, "feedback": "LPの内容を理解し、具体的に説明できています。", "isCorrect": true}, {"text": "「それはマーケが書いたことなので...」", "points": 0, "feedback": "LPの内容も営業として責任を持ちましょう。", "isCorrect": false}, {"text": "「大げさに書いてるだけです」", "points": 0, "feedback": "自社のLPを否定するのは不適切です。", "isCorrect": false}], "situation": "顧客から「LPに書いてあった○○って本当？」と聞かれました。", "customerLine": "LP見たんだけど、『業務効率50%改善』って本当ですか？"}, {"options": [{"text": "「特にないです」", "points": 0, "feedback": "現場の声はLP改善に貴重です。", "isCorrect": false}, {"text": "「顧客から『○○が知りたい』とよく聞くので、その情報を追加するといいかも」", "points": 30, "feedback": "営業現場の知見をフィードバックできています。", "isCorrect": true}, {"text": "「全部作り直した方がいい」", "points": 0, "feedback": "具体的な改善点を伝えましょう。", "isCorrect": false}, {"text": "「LPは見てません」", "points": 0, "feedback": "自社のLPは必ず見ておきましょう。", "isCorrect": false}], "situation": "マーケ担当から「LPの改善点を教えて」と聞かれました。", "customerLine": "LPをリニューアルするんですけど、営業視点で改善点ありますか？"}]', '{"question": "自社のLPを見たことがありますか？改善できそうな点は？", "placeholder": "例: 見たことがない / ○○の情報を追加するといいかも"}', '["自社のLPを顧客目線で見てみる", "LPの内容を理解し、商談で一貫した説明をする", "顧客からよく聞く質問をマーケにフィードバック", "「LPにない情報」を商談で提供する"]', NULL, NULL, '2026-01-21 17:45:34.353106+00', '2026-01-21 17:45:34.353106+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (28, 118, 'メールマーケティング', 'メールは許可を得た顧客との対話', '{"icon": "mail", "name": "メールマーケ理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["会社概要を説明", "特定のアクションに導く", "商品一覧を表示", "採用情報を掲載"], "question": "LP（ランディングページ）の役割は？", "explanation": "LPは問い合わせや資料請求など、特定のアクションに導くページでしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: メルマガの効果", "content": "（営業フロアにて）\n\n健太:「あれ、この問い合わせ、\n      前に名刺交換した人だ」\n\n山本先輩:「お、久しぶりの反応だな。\n        何がきっかけだ？」\n\n健太:「メルマガを見て、とのことです。\n      『事例記事が参考になった』って」\n\n山本先輩:「メルマガが効いたな。\n        今すぐ客じゃなくても、\n        接点を持ち続けることが大事なんだ」", "duration": 45}, {"title": "シーン2: メールマーケティングの種類", "content": "山本先輩:「メールマーケティングには種類がある」\n\n【メールマーケティングの種類】\n\n■ メルマガ（メールマガジン）\n定期的に配信する情報発信型メール\n目的: 関係維持、情報提供、ブランディング\n例: 月1回の業界ニュース、新機能のお知らせ\n\n■ ステップメール\n特定のアクション後に自動配信されるシナリオ型メール\n目的: リードナーチャリング、購買促進\n例: 資料DL後 → 3日後に事例紹介 → 7日後にセミナー案内\n\n■ 営業からの個別メール\n1対1のパーソナライズされたメール\n目的: 関係構築、商談化、フォロー\n例: 商談後のお礼、個別の情報提供", "duration": 45}, {"title": "シーン3: メールの役割分担", "content": "山本先輩:「メルマガと営業メールは役割が違う」\n\n【役割の違い】\n\n■ メルマガ（マーケ担当）\n・1対多の配信\n・定期的な情報提供\n・ブランド認知、関係維持\n・「忘れられない」ためのタッチポイント\n\n■ 営業からの個別メール\n・1対1の対話\n・パーソナライズされた内容\n・商談化、クロージング\n・「この人のための」メッセージ\n\n山本先輩:「メルマガは『広く浅く』、\n        営業メールは『狭く深く』。\n        両方が必要なんだ」", "duration": 30}], "part2": [{"title": "シーン4: 開封率・クリック率の改善", "content": "山本先輩:「メールの効果を測る指標を知っておけ」\n\n【メールの効果指標】\n開封率: 配信数のうち開封された割合\nクリック率: 開封数のうちリンクをクリックした割合\n\n【開封率・クリック率を上げるポイント】\n\n■ 件名\n・短く、メリットを明確に\n・数字を入れる（「3つのポイント」等）\n・緊急性を出す（「本日まで」等）\n\n■ 配信時間\n・B2Bは平日午前中が効果的\n\n■ パーソナライズ\n・名前、会社名を入れる\n\n■ CTA\n・1メール1アクションに絞る", "duration": 45}, {"title": "シーン5: 営業メールのポイント", "content": "山本先輩:「営業からの個別メールのポイントだ」\n\n【営業メールのポイント】\n\n■ 件名で用件を明確に\n✕「お世話になっております」\n○「【ご提案】○○の件について」\n\n■ 相手にとってのメリットを先に\n✕「弊社の新機能をご紹介します」\n○「○○の課題を解決する方法をご紹介します」\n\n■ 長すぎない\n・スクロールなしで読める長さ\n・詳細はPDF添付\n\n■ CTAを明確に\n「ご都合いかがでしょうか？」より\n「○日○時はいかがでしょうか？」", "duration": 30}, {"title": "シーン6: メールと電話の使い分け", "content": "山本先輩:「メールと電話、使い分けが大事だ」\n\n【メールが適している場面】\n・資料送付、確認事項\n・日程調整\n・記録に残したい内容\n・相手の都合が読めない時\n\n【電話が適している場面】\n・急ぎの用件\n・複雑な説明\n・感情を伝えたい時（お詫び等）\n・早く決めたい時\n\n【今日の学び】\n「メールは許可を得た顧客との対話である」\nメルマガで関係維持、営業メールで商談化", "duration": 15}]}', '{"title": "メールマーケティング", "content": "メルマガ=広く浅く / 営業メール=狭く深く", "audioText": "メルマガは関係維持、営業メールは商談化。役割の違いを理解しましょう。", "highlight": "両方が必要"}', '[{"options": ["同じ役割", "メルマガは1対多、営業メールは1対1"], "question": "メルマガと営業メールの違いは？", "explanation": "メルマガは広く浅く、営業メールは狭く深く、役割が異なります。", "correctIndex": 1}, {"options": ["週末の夜", "平日の午前中"], "question": "B2Bメールの配信時間で効果的なのは？", "explanation": "B2Bは平日午前中の配信が開封率が高い傾向があります。", "correctIndex": 1}]', '{"text": "Email is a dialogue with customers who have given permission.", "author": "WEBマーケティングの格言", "textJa": "メールは許可を得た顧客との対話である。"}', '[{"options": [{"text": "「お世話になっております」", "points": 0, "feedback": "件名で用件がわかりません。開封されにくいです。", "isCorrect": false}, {"text": "「【ご提案資料】○○様 在庫管理効率化のご提案」", "points": 30, "feedback": "件名で用件が明確で、パーソナライズもできています。", "isCorrect": true}, {"text": "「こんにちは」", "points": 0, "feedback": "件名で用件を明確にしましょう。", "isCorrect": false}, {"text": "「重要」", "points": 5, "feedback": "何が重要か伝わりません。具体的な件名にしましょう。", "isCorrect": false}], "situation": "商談後のフォローメールを送ります。件名は何にしますか？", "customerLine": "（メール作成場面）"}, {"options": [{"text": "「その後いかがですか？」だけ送る", "points": 5, "feedback": "価値のある情報を提供しましょう。", "isCorrect": false}, {"text": "「御社の課題に関連する事例記事をお送りします」", "points": 30, "feedback": "相手にとって価値のある情報を提供できています。", "isCorrect": true}, {"text": "「早く決めてください」と催促", "points": 0, "feedback": "押し付けがましいです。価値を提供しましょう。", "isCorrect": false}, {"text": "「値引きします」と伝える", "points": 5, "feedback": "価格交渉の前に、価値を伝えましょう。", "isCorrect": false}], "situation": "検討中の顧客にフォローメールを送ります。何を送りますか？", "customerLine": "（メール作成場面）"}]', '{"question": "検討中の顧客に、どんなフォローメールを送っていますか？", "placeholder": "例: 事例を送っている / 定期的に情報提供している / あまり送っていない"}', '["件名で用件を明確にする", "相手にとってのメリットを先に書く", "検討中顧客に定期的に価値ある情報を送る", "メールと電話を使い分ける"]', NULL, NULL, '2026-01-21 17:45:35.05999+00', '2026-01-21 17:45:35.05999+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (29, 119, 'アクセス解析の基礎', 'データは顧客の声なき声', '{"icon": "bar-chart", "name": "データ理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["「お世話になっております」", "用件を明確にした内容"], "question": "営業メールで件名に入れるべきものは？", "explanation": "件名で用件を明確にすることで、開封率が上がります。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: データから顧客を知る", "content": "（マーケ部門との会話）\n\nマーケ担当:「健太さん、今度商談する○○社さん、\n         うちのサイトを結構見てますよ」\n\n健太:「え、そんなことわかるんですか？」\n\nマーケ担当:「アクセス解析で見えるんです。\n         価格ページと事例ページを\n         何度も見てますね」\n\n健太:「じゃあ、価格と事例に関心があるんだ...」\n\nマーケ担当:「そうですね。商談の参考にしてください」", "duration": 45}, {"title": "シーン2: アクセス解析の重要指標", "content": "山本先輩:「アクセス解析の基本指標を覚えておけ」\n\n【トラフィック系指標】\nPV（Page View）: ページが閲覧された回数\nUU（Unique User）: 訪問したユーザー数（重複除く）\nセッション: サイト訪問の回数\n\n【エンゲージメント系指標】\n直帰率: 1ページだけ見て離脱した割合\n平均滞在時間: サイト内にいた時間\nページ/セッション: 1回の訪問で見たページ数\n\n【コンバージョン系指標】\nCV（Conversion）: 目標達成数（問い合わせ、資料DL等）\nCVR（Conversion Rate）: 訪問者のうちCVした割合\nCPA（Cost Per Acquisition）: 1件のCV獲得にかかった費用", "duration": 45}, {"title": "シーン3: データから顧客行動を読み解く", "content": "山本先輩:「データから顧客行動が見える」\n\n【流入元の分析】\nどこから来たか？\n→ 検索、広告、SNS、直接\n→ 効果的なチャネルを把握\n\n【閲覧ページの分析】\nどのページを見たか？\n→ 顧客の関心ポイントを把握\n\n【コンバージョン経路の分析】\nどのルートでCVに至ったか？\n→ 効果的な導線を把握\n\n山本先輩:「『この顧客は○○ページを見てから\n        問い合わせた』とわかれば、\n        関心ポイントを予測して商談に臨める」", "duration": 30}], "part2": [{"title": "シーン4: 営業がデータを活用する", "content": "山本先輩:「営業がデータを活用する方法を教えるぞ」\n\n【営業でのデータ活用】\n\n■ 商談前の準備\n「この顧客は価格ページを何度も見ている」\n→ 価格への関心が高い、ROI説明を準備\n\n「事例ページをよく見ている」\n→ 同業他社の事例を用意\n\n■ 商談中の会話\n「御社のような業界の事例にご関心ありますか？」\n→ 閲覧データを元に仮説を立てて質問\n\n■ フォロー判断\n「最近サイトを見ていない」\n→ 関心が薄れている？アプローチ方法を変える\n\n「また頻繁に見始めた」\n→ 検討が再開した？連絡するタイミング", "duration": 45}, {"title": "シーン5: マーケ部門との連携", "content": "山本先輩:「データを持っているのはマーケ部門だ。\n        連携することで営業に活かせる」\n\n【マーケ部門に聞いてみること】\n\n・「○○社さん、最近サイト見てますか？」\n・「どのページを見てますか？」\n・「問い合わせ前にどんな経路で来ましたか？」\n・「どのコンテンツがよく見られてますか？」\n\n【営業からマーケへのフィードバック】\n\n・「価格ページを見てた人は、価格に敏感でした」\n・「事例ページを見てた人は成約率高いです」\n・「○○ページを見てほしいので、導線を強化できませんか？」", "duration": 30}, {"title": "シーン6: データ活用の心得", "content": "山本先輩:「データ活用の心得を教えるぞ」\n\n【データ活用の心得】\n\n✓ データは「参考」であり「絶対」ではない\n  → 実際の顧客との対話で確認する\n\n✓ プライバシーへの配慮\n  → 「ストーカーみたい」と思われない使い方\n\n✓ データだけでなく「なぜ」を考える\n  → 数字の背景にある顧客心理を想像\n\n✓ マーケ部門との連携\n  → データを持っている部門と協力\n\n【今日の学び】\n「データは顧客の声なき声である」\nデータを活用して、より良い提案を", "duration": 15}]}', '{"title": "アクセス解析の指標", "content": "PV/UU/セッション → 直帰率/滞在時間 → CV/CVR/CPA", "audioText": "アクセス解析のデータから、顧客の関心ポイントを把握できます。", "highlight": "データから顧客の関心がわかる"}', '[{"options": ["ページ閲覧数", "訪問者のうちCVした割合"], "question": "CVRとは？", "explanation": "Conversion Rate=コンバージョン率。目標達成した割合です。", "correctIndex": 1}, {"options": ["価格に関心がない", "価格に関心が高い可能性"], "question": "顧客が価格ページを何度も見ていたら？", "explanation": "閲覧データから関心ポイントを推測できます。", "correctIndex": 1}]', '{"text": "Data is the voice of customers without words.", "author": "WEBマーケティングの格言", "textJa": "データは顧客の声なき声である。"}', '[{"options": [{"text": "「そうですか」で終わる", "points": 5, "feedback": "データを商談に活かしましょう。", "isCorrect": false}, {"text": "「価格に関心が高そうですね。ROI説明を準備しておきます」", "points": 30, "feedback": "データを商談準備に活かせています。", "isCorrect": true}, {"text": "「見られてるの、ちょっと怖いですね」", "points": 0, "feedback": "データ活用の視点を持ちましょう。", "isCorrect": false}, {"text": "「データは当てにならないです」", "points": 0, "feedback": "データは顧客理解の参考になります。", "isCorrect": false}], "situation": "マーケ担当から「○○社さん、価格ページを何度も見てます」と聞きました。", "customerLine": "○○社さん、価格ページを5回見てますよ"}, {"options": [{"text": "放置する", "points": 0, "feedback": "関心が薄れているサインかも。アプローチを変えましょう。", "isCorrect": false}, {"text": "「役立つ情報を送って、関心を取り戻す」", "points": 30, "feedback": "コンテンツを送ってナーチャリングするアプローチです。", "isCorrect": true}, {"text": "「営業電話をかけまくる」", "points": 5, "feedback": "しつこいと逆効果です。価値ある情報を提供しましょう。", "isCorrect": false}, {"text": "「諦める」", "points": 5, "feedback": "まだナーチャリングで復活の可能性があります。", "isCorrect": false}], "situation": "検討中の顧客が、最近サイトを見ていないようです。どうしますか？", "customerLine": "（データ確認場面）○○社さん、1ヶ月サイト訪問ないですね"}]', '{"question": "マーケ部門にアクセスデータを聞いたことがありますか？", "placeholder": "例: 聞いたことがない / 時々聞いている / 定期的に共有してもらっている"}', '["マーケ部門にアクセスデータを聞いてみる", "商談前に顧客のサイト閲覧状況を確認", "閲覧データから顧客の関心を推測して準備", "データの背景にある「なぜ」を考える"]', NULL, NULL, '2026-01-21 17:45:35.932523+00', '2026-01-21 17:45:35.932523+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (30, 120, 'MA（マーケティングオートメーション）と営業連携', 'MAは魔法の杖ではない。使いこなす人間が重要', '{"icon": "cpu", "name": "MA連携マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["ページ閲覧数", "訪問者のうちCVした割合", "広告クリック数", "離脱率"], "question": "アクセス解析でわかる「CVR」とは？", "explanation": "CVR=Conversion Rate=訪問者のうち目標達成した割合でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: MAからのアラート", "content": "（営業フロアにて）\n\nマーケ担当:「健太さん、○○社さんの\n         スコアが上がってます。\n         アプローチした方がいいかも」\n\n健太:「スコア...？」\n\nマーケ担当:「MAのリードスコアリングです。\n         価格ページを3回見て、\n         事例もダウンロードしてます」\n\n健太:「え、それってかなり検討が進んでる？」\n\nマーケ担当:「そうですね。今が連絡のタイミングかと」", "duration": 45}, {"title": "シーン2: MAとは", "content": "山本先輩:「MAを説明するぞ」\n\n【MA（Marketing Automation）とは】\nマーケティング活動を自動化・効率化するためのツール\n\n【主な機能】\n・リード管理: 見込み客情報の一元管理\n・メール配信: 自動でのステップメール配信\n・スコアリング: 見込み度合いの数値化\n・行動追跡: WEB上での行動を記録\n・レポート: 効果測定・分析\n\n【代表的なMAツール】\nHubSpot、Marketo、Pardot、SATORI等\n\n山本先輩:「MAはリードを『見える化』して、\n        適切なタイミングでアプローチできる\n        ようにするツールだ」", "duration": 45}, {"title": "シーン3: リードスコアリング", "content": "山本先輩:「MAの核となる機能がスコアリングだ」\n\n【リードスコアリングとは】\n見込み客の「購買意欲」を数値化する仕組み\n\n【スコアリングの例】\n\n■ 属性スコア\n・役職が部長以上 → +20点\n・従業員数50人以上 → +10点\n\n■ 行動スコア\n・資料をダウンロード → +15点\n・価格ページを閲覧 → +20点\n・3回以上サイト訪問 → +10点\n\n【スコアの活用】\n・50点以上 → MQL（マーケ認定リード）として営業にパス\n・80点以上 → 優先度高として即アプローチ", "duration": 30}], "part2": [{"title": "シーン4: MA情報を営業に活用", "content": "山本先輩:「MAの情報を営業に活かす方法だ」\n\n【MAから得られる情報】\n・いつサイトを訪問したか\n・どのページを見たか\n・どの資料をダウンロードしたか\n・メールを開封したか、クリックしたか\n\n【営業での活用例】\n\n「先日、価格ページをご覧いただいたようですが、\n ご検討状況はいかがでしょうか？」\n\n「○○の事例をダウンロードいただきましたが、\n 同様の課題をお持ちでしょうか？」\n\n山本先輩:「顧客の行動を把握した上でアプローチ\n        すると、的確な提案ができる」", "duration": 45}, {"title": "シーン5: 営業とMAの連携", "content": "山本先輩:「MAを活かすには、営業との連携が不可欠だ」\n\n【連携のポイント】\n\n■ マーケ → 営業\n・スコアが上がったリードを通知\n・顧客の行動履歴を共有\n・ホットなタイミングをアラート\n\n■ 営業 → マーケ\n・商談結果のフィードバック\n （受注/失注、失注理由）\n・スコアリングの精度へのフィードバック\n （高スコアでも商談化しないパターン等）\n\n山本先輩:「MAはツールでしかない。\n        マーケと営業の連携があって\n        初めて効果を発揮する」", "duration": 30}, {"title": "シーン6: MAの限界と人間の役割", "content": "山本先輩:「MAにも限界がある」\n\n【MAの限界】\n・スコアが高くても買わない人もいる\n・スコアが低くても急に買う人もいる\n・数字だけでは見えない顧客心理がある\n\n【人間（営業）の役割】\n・データを「参考」にしつつ、最終判断は人間\n・顧客との対話で本当のニーズを把握\n・信頼関係は自動化できない\n\n【今日の学び】\n「MAは魔法の杖ではない。使いこなす人間が重要」\nデータを活用しつつ、最後は人間が判断・行動する", "duration": 15}]}', '{"title": "MAと営業連携", "content": "MA（スコアリング・行動追跡）→ 営業（的確なアプローチ）", "audioText": "MAは見込み客を数値化するツール。営業との連携で効果を発揮します。", "highlight": "ツールを活かすのは人間"}', '[{"options": ["売上を計算すること", "見込み客の購買意欲を数値化すること"], "question": "MAの「スコアリング」とは？", "explanation": "リードスコアリングは見込み度合いを数値化する機能です。", "correctIndex": 1}, {"options": ["ツールに任せきりにする", "マーケと営業の連携"], "question": "MAを活かすために必要なことは？", "explanation": "MAはツール。人間同士の連携があって効果を発揮します。", "correctIndex": 1}]', '{"text": "MA is not a magic wand. The people who use it matter.", "author": "WEBマーケティングの格言", "textJa": "MAは魔法の杖ではない。使いこなす人間が重要。"}', '[{"options": [{"text": "「へー」で終わる", "points": 0, "feedback": "ホットなリードです。すぐにアクションしましょう。", "isCorrect": false}, {"text": "「今すぐ連絡してみます。価格の話を中心にアプローチします」", "points": 30, "feedback": "スコアとページ閲覧情報を活かしたアプローチです。", "isCorrect": true}, {"text": "「スコアは当てにならないので無視します」", "points": 0, "feedback": "参考情報として活用しましょう。", "isCorrect": false}, {"text": "「来週連絡します」", "points": 5, "feedback": "ホットなうちに連絡しましょう。", "isCorrect": false}], "situation": "マーケから「○○社のスコアが80点に上がりました」と連絡がありました。", "customerLine": "○○社さん、スコア80点になりました。価格ページを3回見てます"}, {"options": [{"text": "「MAは役に立たない」と批判", "points": 0, "feedback": "建設的なフィードバックをしましょう。", "isCorrect": false}, {"text": "「スコアは高かったが○○の理由で商談化しなかった」とマーケにフィードバック", "points": 30, "feedback": "フィードバックでスコアリングの精度向上に貢献できます。", "isCorrect": true}, {"text": "何もしない", "points": 5, "feedback": "フィードバックで改善につなげましょう。", "isCorrect": false}, {"text": "「自分の営業力が足りなかった」と自分を責める", "points": 10, "feedback": "スコアリングの精度の問題かもしれません。フィードバックしましょう。", "isCorrect": false}], "situation": "高スコアのリードに連絡しましたが、商談化しませんでした。どうしますか？", "customerLine": "（商談化しなかった後の場面）"}]', '{"question": "MA（またはそれに近いツール）を活用していますか？活用できそうな場面は？", "placeholder": "例: MAは導入されているが活用できていない / スコア情報を商談に活かしたい"}', '["マーケ部門にMA情報を聞いてみる", "高スコアリードには優先的にアプローチ", "顧客の行動履歴を商談の準備に活用", "商談結果をマーケにフィードバック"]', NULL, NULL, '2026-01-21 17:45:37.105974+00', '2026-01-21 17:45:37.105974+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (31, 121, 'SaaSビジネスモデルの基礎', '契約はゴールではなく、スタートである', '{"icon": "cloud", "name": "SaaS入門者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["高価なツールを導入する", "マーケと営業の連携", "全てを自動化する", "データを無視する"], "question": "MAを活かすために最も重要なことは？", "explanation": "MAはツール。人間同士の連携があって効果を発揮しますね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 全体会議での発表", "content": "（四半期の全体会議にて）\n\n社長:「今期のMRRは前期比120%成長。\n      解約率も2.5%まで改善しました」\n\n健太（心の声）:「MRR...解約率...\n         ちゃんと理解してないな...」\n\n〜会議後〜\n\n健太:「先輩、MRRとか解約率とか、\n      よく聞くんですけど、\n      ちゃんと理解した方がいいですか？」\n\n山本先輩:「当然だろ。自分の仕事が\n        会社にどう貢献してるか、\n        わかってないと意味ないぞ」", "duration": 45}, {"title": "シーン2: SaaSとは", "content": "山本先輩:「まず、SaaSって何か説明できるか？」\n\n【SaaS（Software as a Service）とは】\nインターネット経由でソフトウェアを提供し、\n利用料（サブスクリプション）を得るビジネスモデル\n\n【従来モデル（売り切り）との違い】\n従来: ライセンス販売 → 一括購入 → 関係薄い\nSaaS: 月額/年額課金 → 継続利用 → 関係が続く\n\n山本先輩:「Symphonyもこのモデルだ。\n        お客さんが毎月使い続けてくれることで、\n        会社が成り立っている」", "duration": 45}, {"title": "シーン3: 積み上げ型の収益構造", "content": "山本先輩:「SaaSの特徴は『積み上げ型』だ」\n\n【ストック型収益のイメージ】\n1月: 新規10社 → MRR 10万円\n2月: 新規10社 → MRR 20万円（解約0）\n3月: 新規10社 → MRR 30万円（解約0）\n12月: MRR 120万円（解約0）\n\n解約がなければ収益は積み上がる\n\n山本先輩:「でも1社でも解約があれば減る。\n        穴の空いたバケツに水を入れるようなもの」", "duration": 30}], "part2": [{"title": "シーン4: 営業の役割の変化", "content": "山本先輩:「SaaSで営業の役割はどう変わった？」\n\n【SaaS営業の役割】\n1. 新規獲得: 新しい顧客を獲得する\n2. オンボーディング支援: 導入初期の定着を支援\n3. アップセル/クロスセル: 既存顧客の契約拡大\n4. 解約防止: 顧客の成功を支援し、継続利用を促す\n5. 顧客の声のフィードバック: 製品改善につなげる\n\n山本先輩:「売り切りなら売ったら保守部門の仕事。\n        SaaSは違う。顧客が成功するまで支援する」", "duration": 45}, {"title": "シーン5: 自分の貢献を理解する", "content": "山本先輩:「自分の仕事がどう会社に貢献してるか、\n        数字で理解しておけ」\n\n【営業の貢献の見方】\n\n■ 新規獲得\n「今月○○万円のMRRを獲得した」\n\n■ 解約阻止\n「解約しそうだった顧客を引き留めた」\n\n■ アップセル\n「既存顧客のプランアップで○○万円増」\n\n健太:「自分の仕事が会社の成長に\n      どう繋がってるか、見えてきました」", "duration": 30}, {"title": "シーン6: 契約はスタート", "content": "山本先輩:「一番大事なことを言うぞ」\n\n【SaaSの真実】\n契約はゴールではなく、スタートである\n\n売り切りモデル: 契約 = ゴール\nSaaSモデル: 契約 = スタート\n\n山本先輩:「お客さんが『使って良かった』と\n        思い続けてくれなければ、解約される。\n        だから契約後のフォローが大事なんだ」\n\n【今日の学び】\n「契約はゴールではなく、スタートである」", "duration": 15}]}', '{"title": "SaaSビジネスモデル", "content": "継続課金 × 積み上げ型収益 × 顧客成功", "audioText": "SaaSは継続課金のビジネス。契約後の顧客成功が重要です。", "highlight": "契約はゴールではなくスタート"}', '[{"options": ["一括で大きな売上", "毎月積み上がる継続収益"], "question": "SaaSの収益構造の特徴は？", "explanation": "SaaSは毎月の継続課金が積み上がるストック型ビジネスです。", "correctIndex": 1}, {"options": ["ゴール（終わり）", "スタート（始まり）"], "question": "SaaSで「契約」は何を意味する？", "explanation": "契約後から顧客との関係が本格的に始まります。", "correctIndex": 1}]', '{"text": "In SaaS, the contract is not the goal but the starting line.", "author": "SaaSビジネスの格言", "textJa": "SaaSでは、契約はゴールではなくスタートラインである。"}', '[{"options": [{"text": "「3件契約を取りました」", "points": 10, "feedback": "件数だけでなく、MRRへの貢献を説明しましょう。", "isCorrect": false}, {"text": "「新規3件で月額9万円のMRRです」", "points": 30, "feedback": "SaaSの指標で自分の貢献を説明できています。", "isCorrect": true}, {"text": "「とにかく頑張りました」", "points": 0, "feedback": "数字で具体的に説明しましょう。", "isCorrect": false}, {"text": "「把握できていません」", "points": 0, "feedback": "自分の貢献は数字で把握しておきましょう。", "isCorrect": false}], "situation": "上司から「今月の貢献は？」と聞かれました。", "customerLine": "健太、今月の自分の貢献を説明してみて"}]', '{"question": "自分の今月の貢献をMRR（月額収益）で説明できますか？", "placeholder": "例: 新規○件で月額○万円のMRRを獲得"}', '["自分の貢献をMRRで把握する習慣をつける", "契約後のフォローを意識する", "会社のKPI報告を理解する", "「売って終わり」の意識を変える"]', NULL, NULL, '2026-01-21 17:45:39.11734+00', '2026-01-21 17:45:39.11734+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (32, 122, 'SaaSの重要指標 - MRR/ARR', 'MRRはSaaSビジネスの心臓の鼓動', '{"icon": "trending-up", "name": "MRR理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["ゴール（終わり）", "スタート（始まり）"], "question": "SaaSで「契約」は何を意味する？", "explanation": "契約後から顧客との関係が本格的に始まりますね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 会議での数字", "content": "（週次の営業会議にて）\n\n鈴木課長:「今月のNet New MRRは目標の85%。\n        Churn MRRが予想より大きかった」\n\n健太（心の声）:「Net New MRR...Churn MRR...\n         正確には説明できないな...」\n\n〜会議後〜\n\n健太:「先輩、MRRの種類って\n      いくつかあるんですか？」\n\n山本先輩:「ああ、詳しく説明するぞ」", "duration": 45}, {"title": "シーン2: MRRとARR", "content": "【MRR（Monthly Recurring Revenue）】\n月次経常収益 = 毎月繰り返し得られる収益の合計\n\n計算: MRR = 月額単価 × 顧客数\n例: 月額3万円 × 100社 = MRR 300万円\n\n【ARR（Annual Recurring Revenue）】\n年次経常収益 = MRR × 12\n\n例: MRR 300万円 × 12 = ARR 3,600万円\n\n山本先輩:「MRRは月単位、ARRは年単位。\n        投資家への報告ではARRがよく使われる」", "duration": 45}, {"title": "シーン3: MRRの構成要素", "content": "【MRRの構成要素】\n\n■ New MRR（新規MRR）\n新規顧客からの収益\n\n■ Expansion MRR（拡大MRR）\n既存顧客のアップグレードによる増加\n\n■ Contraction MRR（縮小MRR）\n既存顧客のダウングレードによる減少\n\n■ Churn MRR（解約MRR）\n解約による減少", "duration": 30}], "part2": [{"title": "シーン4: Net New MRR", "content": "山本先輩:「一番重要なのがNet New MRRだ」\n\n【Net New MRR】\nNet New MRR = New MRR + Expansion MRR\n             - Contraction MRR - Churn MRR\n\nこれが「純増分」= 本当の成長\n\n【例】\nNew: 30万円 + Expansion: 15万円\n- Contraction: 6万円 - Churn: 6万円\n= Net New MRR: 33万円\n\n山本先輩:「新規を30万円取っても、\n        解約で減ると、純増は33万円」", "duration": 45}, {"title": "シーン5: 営業としてのMRR意識", "content": "【営業がMRRを意識する意義】\n\n■ 自分の貢献を数字で把握\n「今月○○万円のNew MRRを獲得」\n\n■ 解約の影響を理解\n「1社解約 = ○○万円のMRR減少」\n\n■ 会社の成長を実感\n「MRRが前月比○%成長」\n\n健太:「数字で見ると、自分の仕事の\n      インパクトがわかりますね」", "duration": 30}, {"title": "シーン6: MRRを日々意識する", "content": "山本先輩:「毎日MRRを意識しろ」\n\n契約を取った時:\n「今日、○○万円のNew MRRを獲得した」\n\nアップセルした時:\n「○○万円のExpansion MRRを創出した」\n\n解約の連絡を受けた時:\n「○○万円のChurn MRRが発生する」\n\n【今日の学び】\n「MRRはSaaSビジネスの心臓の鼓動」\n日々の活動をMRRで捉える", "duration": 15}]}', '{"title": "MRRの構成", "content": "Net New MRR = New + Expansion - Contraction - Churn", "audioText": "MRRは4つの要素で構成されます。Net New MRRが純増分です。", "highlight": "純増分が本当の成長"}', '[{"options": ["New MRR のみ", "New + Expansion - Contraction - Churn"], "question": "Net New MRRの計算式は？", "explanation": "新規＋拡大－縮小－解約 = 純増分です。", "correctIndex": 1}, {"options": ["ARR = MRR ÷ 12", "ARR = MRR × 12"], "question": "ARRとMRRの関係は？", "explanation": "ARR（年次）= MRR（月次）× 12ヶ月です。", "correctIndex": 1}]', '{"text": "MRR is the heartbeat of a SaaS business.", "author": "SaaSビジネスの格言", "textJa": "MRRはSaaSビジネスの心臓の鼓動である。"}', '[{"options": [{"text": "「今週は2件契約しました」", "points": 5, "feedback": "MRRで報告しましょう。", "isCorrect": false}, {"text": "「Net New MRRは8万円です」", "points": 30, "feedback": "MRRの構成要素で報告できています。", "isCorrect": true}, {"text": "「計算方法がわかりません」", "points": 0, "feedback": "MRRの計算方法を覚えましょう。", "isCorrect": false}, {"text": "「とにかく頑張りました」", "points": 0, "feedback": "数字で報告しましょう。", "isCorrect": false}], "situation": "週次会議で「今週のNet New MRRを報告して」と言われました。", "customerLine": "健太、今週の貢献をNet New MRRで報告して"}]', '{"question": "今月のNet New MRRを計算できますか？", "placeholder": "例: New MRR ○万円 + Expansion ○万円 - Churn ○万円 = ○万円"}', '["契約をMRRで把握する習慣をつける", "アップセルの効果をExpansion MRRで認識", "解約のインパクトをChurn MRRで理解", "週次でNet New MRRを振り返る"]', NULL, NULL, '2026-01-21 17:45:40.18936+00', '2026-01-21 17:45:40.18936+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (33, 123, '顧客獲得コスト - CAC', '効率よく獲得することが、会社の健全性を支える', '{"icon": "calculator", "name": "CAC理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["New MRR のみ", "New + Expansion - Contraction - Churn"], "question": "Net New MRRの計算式は？", "explanation": "新規＋拡大－縮小－解約 = 純増分でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 経営会議からの共有", "content": "（朝礼にて）\n\n鈴木課長:「経営から共有があった。\n        今期のCAC、目標より高いらしい。\n        営業効率の改善が必要だ」\n\n健太:「先輩、CACって何ですか？\n      営業の自分に関係あるんですか？」\n\n山本先輩:「大ありだよ。\n        営業効率が会社の健全性に直結する」", "duration": 45}, {"title": "シーン2: CACとは", "content": "【CAC（Customer Acquisition Cost）】\n顧客獲得コスト = 1社を獲得するための費用\n\n【計算方法】\nCAC = (営業コスト + マーケコスト) ÷ 新規獲得顧客数\n\n【例】\n営業人件費: 500万円/月\nマーケ費用: 200万円/月\n新規獲得: 10社/月\n\nCAC = 700万円 ÷ 10社 = 70万円/社\n\n山本先輩:「1社獲得するのに70万円かかっている」", "duration": 45}, {"title": "シーン3: CACに含まれるコスト", "content": "【CACに含まれるコスト】\n\n■ 営業コスト\n・営業人件費（給与、社会保険等）\n・交通費、出張費\n・営業ツール費用\n\n■ マーケティングコスト\n・広告費\n・展示会費\n・コンテンツ制作費\n\n山本先輩:「お前の給料も、交通費も、\n        全部CACに含まれている」", "duration": 30}], "part2": [{"title": "シーン4: CACを下げる意味", "content": "【CACが高いと】\n・獲得コストが収益を圧迫\n・投資回収に時間がかかる\n\n【CACが低いと】\n・効率的に顧客を獲得\n・投資回収が早い\n\n【健全なビジネスの条件】\nLTV（顧客生涯価値） > CAC（獲得コスト）\n\nこの関係が崩れると、\n獲得すればするほど赤字になる", "duration": 45}, {"title": "シーン5: 営業ができるCAC改善", "content": "【営業ができるCAC改善】\n\n■ 成約率を上げる\n同じ商談数で受注が増える → CAC低下\n・提案力の向上\n・顧客理解の深化\n\n■ 商談サイクルを短縮\n受注までの期間が短くなる → 効率向上\n\n■ 紹介を獲得 ★最強のCAC改善\n紹介はCACほぼゼロの新規獲得\n\n健太:「紹介ってそんなに効果あるんですか？」\n\n山本先輩:「広告費ゼロ、アポ取りゼロ、\n        信頼関係もある程度ある。\n        これ以上効率的な獲得方法はない」", "duration": 30}, {"title": "シーン6: 紹介を獲得する方法", "content": "山本先輩:「紹介は待つんじゃなく、仕掛けるんだ」\n\n【紹介を獲得する5つのステップ】\n\n① まず顧客を成功させる\n→ 満足していない顧客は紹介してくれない\n\n② タイミングを見極める\n→ 成果が出た時、感謝された時がベスト\n\n③ 具体的にお願いする\n「同業の方でお困りの方、いらっしゃいませんか？」\n→ 漠然と「誰かいませんか？」はNG\n\n④ 紹介のハードルを下げる\n「まず私から連絡してもいいですか？」\n「お名前を出さずにお声がけすることも可能です」\n\n⑤ 必ずお礼と報告をする\n→ 紹介してくれた方への感謝を忘れない", "duration": 45}, {"title": "シーン7: 紹介依頼のトーク例", "content": "山本先輩:「実際のトークを教えてやる」\n\n【紹介依頼のトーク例】\n\n「○○さん、いつもありがとうございます。\n おかげさまで御社の業務効率化に\n 貢献できていると感じています。\n\n 実は、○○さんのような\n △△に課題をお持ちの会社様を\n もっとお手伝いしたいと思っています。\n\n 同業の方やお知り合いで、\n 同じようなお悩みをお持ちの方は\n いらっしゃいませんか？」\n\n健太:「こうやって具体的に言えばいいんですね」\n\n山本先輩:「そう。遠慮せずに、堂々と聞け」", "duration": 30}, {"title": "シーン8: 効率の意識", "content": "山本先輩:「『とにかく件数』じゃなく、\n        『効率よく獲得する』意識を持て」\n\n【効率の意識】\n\n✕ 無駄な訪問、無駄な商談 → CACを上げている\n○ ターゲットを絞った活動 → 効率的なCAC\n\n✕ とにかく数を追う → 疲弊してCAC悪化\n○ 質の高い商談に集中 → 成約率向上でCAC改善\n\n✕ 紹介を待っている → 機会損失\n○ 紹介を仕掛ける → CACゼロの獲得\n\n【今日の学び】\n「効率よく獲得することが、会社の健全性を支える」\n特に紹介獲得はCAC改善の最強の武器", "duration": 15}]}', '{"title": "CAC（顧客獲得コスト）", "content": "CAC = (営業コスト + マーケコスト) ÷ 新規獲得数", "audioText": "CACは1社獲得にかかるコスト。営業効率がCACに直結します。", "highlight": "LTV > CAC が健全の条件"}', '[{"options": ["製品開発費", "営業人件費とマーケティング費用"], "question": "CACに含まれるものは？", "explanation": "CACには営業とマーケの費用が含まれます。", "correctIndex": 1}, {"options": ["紹介料がかかるから", "獲得コストがほぼゼロだから"], "question": "紹介獲得がCACに良い理由は？", "explanation": "紹介は広告費や営業工数が少なく、CACがほぼゼロです。", "correctIndex": 1}]', '{"text": "Efficient acquisition supports the health of the company.", "author": "SaaSビジネスの格言", "textJa": "効率よく獲得することが、会社の健全性を支える。"}', '[{"options": [{"text": "「よかったです。また何かあれば」", "points": 5, "feedback": "紹介を依頼する絶好のタイミングを逃しています。", "isCorrect": false}, {"text": "「同業でお困りの方いませんか？」", "points": 30, "feedback": "成果が出た良いタイミングで紹介を依頼できています。", "isCorrect": true}, {"text": "「誰か紹介してください」", "points": 10, "feedback": "漠然としすぎです。具体的に伝えましょう。", "isCorrect": false}, {"text": "「紹介は申し訳ないので...」", "points": 0, "feedback": "遠慮は不要です。相手も助かる可能性があります。", "isCorrect": false}], "situation": "既存顧客への定期訪問。導入から3ヶ月、成果も出ています。", "customerLine": "おかげさまで業務がだいぶ楽になりました。ありがとうございます"}, {"options": [{"text": "「無理にとは言いません」で終わる", "points": 5, "feedback": "紹介のハードルを下げる提案をしましょう。", "isCorrect": false}, {"text": "「私から連絡しましょうか？お名前を出さずにも可能です」", "points": 30, "feedback": "紹介のハードルを下げる提案ができています。", "isCorrect": true}, {"text": "「連絡先だけ教えてください」", "points": 5, "feedback": "相手の懸念を解消せずに進めています。", "isCorrect": false}, {"text": "「どうしても紹介してください」", "points": 0, "feedback": "押し付けると関係が悪化します。", "isCorrect": false}], "situation": "「知り合いはいるけど、勝手に紹介していいか...」と言われました。", "customerLine": "○○さんという人はいるけど、勝手に紹介していいか分からないな..."}, {"options": [{"text": "「いいですね」で終わる", "points": 10, "feedback": "具体的に進めましょう。CACゼロの獲得です。", "isCorrect": false}, {"text": "「ぜひ！どんなお困りですか？連絡先も」", "points": 30, "feedback": "紹介を確実に進め、事前情報も確認しています。", "isCorrect": true}, {"text": "「紹介は苦手なので...」", "points": 0, "feedback": "紹介は最も効率的な新規獲得です。", "isCorrect": false}, {"text": "「自分で探すので大丈夫です」", "points": 0, "feedback": "紹介の機会を逃さないでください。", "isCorrect": false}], "situation": "既存顧客から「知り合いを紹介したい」と言われました。", "customerLine": "同業の○○さんも困ってるみたい。紹介しようか？"}, {"options": [{"text": "特に報告しない", "points": 0, "feedback": "報告とお礼は必須。次の紹介につながりません。", "isCorrect": false}, {"text": "「ご紹介で契約できました。ありがとうございます」", "points": 30, "feedback": "感謝と報告で次の紹介にもつながります。", "isCorrect": true}, {"text": "「契約できました」とだけ伝える", "points": 10, "feedback": "感謝の気持ちをしっかり伝えましょう。", "isCorrect": false}, {"text": "「次も紹介してください」", "points": 5, "feedback": "まずは感謝を伝えましょう。催促は逆効果です。", "isCorrect": false}], "situation": "紹介で契約成立。紹介者にどう報告しますか？", "customerLine": "（紹介者への報告）"}]', '{"question": "自分の営業活動で、効率を上げられそうなポイントは？", "placeholder": "例: 成約率を上げる、商談サイクルを短縮、紹介を増やす"}', '["成約率を上げるために提案力を磨く", "商談サイクルを短縮する", "紹介依頼を習慣化する", "無駄な商談・訪問を減らす"]', NULL, NULL, '2026-01-21 17:45:40.88721+00', '2026-01-21 17:45:40.88721+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (34, 124, '顧客生涯価値 - LTV', 'LTVを高めることは、顧客を幸せにすることと同義', '{"icon": "heart", "name": "LTV理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["値引きを増やす", "成約率を上げる、紹介を獲得する"], "question": "CACを下げるために営業ができることは？", "explanation": "成約率向上と紹介獲得はCACを下げる効果的な方法です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 長く使ってくれる顧客", "content": "（営業フロアにて）\n\n鈴木課長:「○○モータースさん、\n        もう5年も使ってくれてるんだな」\n\n健太:「5年...長いですね」\n\n鈴木課長:「1社が5年使ってくれると、\n        会社にとってどれだけの価値か、\n        わかるか？」\n\n健太:「えっと...月額×60ヶ月？」\n\n鈴木課長:「そう、それがLTVだ」", "duration": 45}, {"title": "シーン2: LTVとは", "content": "【LTV（Lifetime Value）】\n顧客生涯価値 = 1社から取引期間全体で得られる収益の総額\n\n【計算方法（簡易版）】\nLTV = 月額単価 × 平均継続月数\n\n例: 月額3万円 × 平均36ヶ月 = LTV 108万円\n\n【計算方法（詳細版）】\nLTV = ARPA ÷ 月次解約率\n\n例: ARPA 3万円 ÷ 解約率2.5% = LTV 120万円", "duration": 45}, {"title": "シーン3: LTVとCACの関係", "content": "【LTV > CAC が健全なビジネスの条件】\n\nLTV（顧客から得られる収益）\n  > CAC（獲得にかかったコスト）\n\n【LTV/CAC比率の目安】\n・1未満: 赤字\n・1〜3: 要改善\n・3以上: 健全\n・5以上: 優秀\n\n例: LTV 120万円、CAC 40万円\nLTV/CAC = 3.0 → 健全", "duration": 30}], "part2": [{"title": "シーン4: LTVを高める方法", "content": "【LTVを高める方法】\n\n■ 解約率を下げる（継続期間を延ばす）\n・顧客満足度を高める\n・オンボーディングを充実させる\n→ 継続月数が増える → LTV増加\n\n■ ARPA（単価）を上げる\n・アップセル（上位プランへの移行）\n・クロスセル（追加サービスの提案）\n→ 月額収益が増える → LTV増加\n\n健太:「解約防止とアップセル、\n      両方大事なんですね」", "duration": 45}, {"title": "シーン5: 営業としてのLTV意識", "content": "【営業のLTV意識】\n\n■ 獲得時の意識\n「長く使ってくれそうな顧客か？」\n→ すぐ解約しそうな顧客を獲得しても意味ない\n\n■ 契約後の意識\n「この顧客に成功してもらうには？」\n→ 顧客の成功 = 継続 = LTV向上\n\n■ アップセルの意識\n「この顧客の課題をもっと解決できないか？」\n→ 顧客の課題解決 = アップセル = LTV向上", "duration": 30}, {"title": "シーン6: 顧客の成功がLTVを生む", "content": "【LTVの本質】\n\n顧客が成功する\n  ↓\n「使い続けたい」と思う\n  ↓\n解約しない、むしろ拡大したい\n  ↓\nLTVが高まる\n\n山本先輩:「数字を追いかけるんじゃなく、\n        顧客の成功を追いかければ、\n        結果としてLTVが高まる」\n\n【今日の学び】\n「LTVを高めることは、顧客を幸せにすることと同義」", "duration": 15}]}', '{"title": "LTV（顧客生涯価値）", "content": "LTV = 月額単価 × 平均継続月数", "audioText": "LTVは顧客から得られる総収益。顧客の成功がLTVを高めます。", "highlight": "LTV/CAC = 3以上が健全"}', '[{"options": ["価格を下げる", "解約率を下げる＋単価を上げる"], "question": "LTVを高める方法は？", "explanation": "継続期間を延ばし、単価を上げることでLTVが高まります。", "correctIndex": 1}, {"options": ["1以上", "3以上"], "question": "LTV/CAC比率の健全な目安は？", "explanation": "LTV/CAC = 3以上が健全な水準です。", "correctIndex": 1}]', '{"text": "Increasing LTV is synonymous with making customers happy.", "author": "SaaSビジネスの格言", "textJa": "LTVを高めることは、顧客を幸せにすることと同義である。"}', '[{"options": [{"text": "「残念ながらできません」", "points": 0, "feedback": "アップセルの機会かもしれません。", "isCorrect": false}, {"text": "「上位プランなら可能です」", "points": 30, "feedback": "顧客の課題解決とアップセルを結びつけています。", "isCorrect": true}, {"text": "「開発に要望を出します」", "points": 10, "feedback": "既存の上位プランで解決できないか確認しましょう。", "isCorrect": false}, {"text": "「別のサービスがいいかも」", "points": 0, "feedback": "まず自社でできることを提案しましょう。", "isCorrect": false}], "situation": "既存顧客が「もっとこういうことができたらいいのに」と言っています。", "customerLine": "Symphonyで○○もできたらいいんだけどな"}]', '{"question": "担当顧客のLTVを意識したことはありますか？", "placeholder": "例: 定期フォローで解約防止、課題をヒアリングしてアップセル提案"}', '["契約時に「長く使ってもらえるか」を意識する", "契約後のフォローで解約を防止する", "顧客の新たな課題を発見し、アップセル提案", "「顧客の成功」を自分のゴールにする"]', NULL, NULL, '2026-01-21 17:45:42.240509+00', '2026-01-21 17:45:42.240509+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (35, 125, '解約率 - チャーンレート', '解約は穴の空いたバケツ。新規を入れる前に穴を塞げ', '{"icon": "alert-triangle", "name": "チャーン理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["価格を下げる", "解約率を下げる＋単価を上げる"], "question": "LTVを高める方法は？", "explanation": "継続期間を延ばし、単価を上げることでLTVが高まりますね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 解約の衝撃", "content": "（朝のミーティング）\n\n鈴木課長:「今月の解約が5件...\n        これは痛い。\n        Net New MRRが帳消しになりかけてる」\n\n健太:「5件って、新規10件に対して\n      半分じゃないですか...」\n\n鈴木課長:「そうだ。穴の空いたバケツに\n        水を入れてるようなもんだ」", "duration": 45}, {"title": "シーン2: チャーンレートとは", "content": "【チャーンレート（Churn Rate）】\n解約率 = 一定期間内に解約した顧客の割合\n\n【カスタマーチャーン（顧客数ベース）】\n月次解約率 = 当月解約顧客数 ÷ 月初顧客数 × 100\n\n例: 月初100社、当月解約3社\n月次解約率 = 3%\n\n【レベニューチャーン（収益ベース）】\n月次MRR解約率 = 当月解約MRR ÷ 月初MRR × 100", "duration": 45}, {"title": "シーン3: 解約の複利効果", "content": "【解約率のわずかな差が大きな差に】\n\n月次3%解約の年間影響:\n月初100社 × (1-0.03)^12 = 69社\n→ 年間で31%の顧客を失う\n\n月次5%解約の年間影響:\n月初100社 × (1-0.05)^12 = 54社\n→ 年間で46%の顧客を失う\n\n【チャーン率の目安（BtoB SaaS）】\n・月次1%以下: 優秀\n・月次2-3%: 平均的\n・月次5%以上: 危険水準", "duration": 30}], "part2": [{"title": "シーン4: ネガティブチャーン", "content": "【Net Revenue Churn】\nNet Revenue Churn = \n  (解約MRR + 縮小MRR - 拡大MRR) ÷ 月初MRR\n\n【ネガティブチャーンとは】\n拡大MRR > 解約MRR + 縮小MRR の場合\n→ マイナスの解約率\n→ 既存顧客だけで成長できる理想状態\n\n例:\n解約30万 + 縮小10万 - 拡大50万 = -10万\n→ ネガティブチャーン（既存だけで純増）", "duration": 45}, {"title": "シーン5: 解約防止は営業の仕事", "content": "【営業ができる解約防止】\n\n■ 契約時\n・顧客の期待値を適切に設定\n・「合わない顧客」を無理に獲得しない\n\n■ 導入初期（オンボーディング）\n・初期の定着をサポート\n\n■ 継続中\n・定期的な状況確認\n・追加の価値提案\n\n■ 解約の兆候を感じたら\n・早めに対応、原因をヒアリング", "duration": 30}, {"title": "シーン6: 穴を塞いでから水を入れる", "content": "【穴の空いたバケツ】\n新規獲得 = バケツに水を入れること\n解約 = バケツに空いた穴\n\n穴が空いたまま水を入れても、溜まらない。\nまず穴を塞いでから、水を入れる。\n\n【営業としての意識】\n・新規獲得も大事\n・でも、既存顧客を守ることも同じくらい大事\n・1社の解約 = 新規1社分の努力が無駄になる\n\n【今日の学び】\n「解約は穴の空いたバケツ。新規を入れる前に穴を塞げ」", "duration": 15}]}', '{"title": "チャーンレート（解約率）", "content": "月次3%の解約 → 年間31%の顧客を失う", "audioText": "解約率のわずかな差が、長期では大きな差になります。", "highlight": "ネガティブチャーンが理想状態"}', '[{"options": ["約10%", "約31%"], "question": "月次解約率3%だと、年間でどれくらい失う？", "explanation": "月次3%の複利効果で、年間約31%の顧客を失います。", "correctIndex": 1}, {"options": ["解約率がマイナス＝既存だけで成長", "解約がとても多い状態"], "question": "ネガティブチャーンとは？", "explanation": "拡大が解約を上回り、既存顧客だけで成長できる状態です。", "correctIndex": 0}]', '{"text": "Churn is a leaky bucket. Plug the hole before adding water.", "author": "SaaSビジネスの格言", "textJa": "解約は穴の空いたバケツ。新規を入れる前に穴を塞げ。"}', '[{"options": [{"text": "「解約手続きをご案内します」", "points": 0, "feedback": "まず原因をヒアリングし、解決策を提示しましょう。", "isCorrect": false}, {"text": "「どこが難しいですか？一緒に解決しましょう」", "points": 30, "feedback": "解約原因を把握し、解決に動く姿勢は正しいです。", "isCorrect": true}, {"text": "「上司に相談してみます」", "points": 10, "feedback": "まず自分で原因をヒアリングしましょう。", "isCorrect": false}, {"text": "「残念ですが仕方ないですね」", "points": 0, "feedback": "解約防止のアクションを取りましょう。", "isCorrect": false}], "situation": "担当顧客から「解約を検討している」と連絡がありました。", "customerLine": "ちょっと使いこなせてなくて、解約を考えてるんだけど..."}]', '{"question": "担当顧客で、解約リスクがありそうな顧客はいますか？", "placeholder": "例: ○○社はあまり使っていない様子、△△社は不満を言っていた"}', '["解約リスクのある顧客を洗い出す", "定期的なフォローで関係を維持する", "解約の兆候を感じたら早めに対応", "解約理由を分析し、次に活かす"]', NULL, NULL, '2026-01-21 17:45:43.377324+00', '2026-01-21 17:45:43.377324+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (36, 126, 'ユニットエコノミクス - 事業の健全性', 'ユニットエコノミクスが成り立たなければ、成長は砂上の楼閣', '{"icon": "scale", "name": "ユニットエコノミクス理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["約10%", "約31%"], "question": "月次解約率3%だと、年間で約何%の顧客を失う？", "explanation": "月次3%の複利効果で、年間約31%の顧客を失いますね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 投資家向け説明資料", "content": "（社内勉強会にて）\n\nCFO:「今日はユニットエコノミクスについて解説します。\n    営業の皆さんにも知っておいてほしい」\n\n健太:「先輩、ユニットエコノミクスって\n      営業に関係あるんですか？」\n\n山本先輩:「大ありだよ。自分の仕事の\n        意味がわかるようになる」", "duration": 45}, {"title": "シーン2: ユニットエコノミクスとは", "content": "【ユニットエコノミクス（Unit Economics）】\n1顧客あたりの経済性\n= 1社の顧客を獲得・維持することが、\n  経済的に成り立っているかを判断する指標群\n\n【主要指標】\n・LTV（顧客生涯価値）\n・CAC（顧客獲得コスト）\n・LTV/CAC比率\n・CAC Payback Period（投資回収期間）\n\n山本先輩:「これらを見ると、\n        ビジネスが健全かどうかわかる」", "duration": 45}, {"title": "シーン3: LTV/CAC比率", "content": "【LTV/CAC比率】\nLTV/CAC = 顧客生涯価値 ÷ 顧客獲得コスト\n\n【目安】\n・1未満: 赤字（投資回収できない）\n・1〜3: 要改善\n・3以上: 健全\n・5以上: 優秀\n\n例: LTV 120万円、CAC 40万円\nLTV/CAC = 3.0 → 健全\n\n山本先輩:「LTV/CACが1未満だと、\n        獲得すればするほど赤字になる」", "duration": 30}], "part2": [{"title": "シーン4: CAC Payback Period", "content": "【CAC Payback Period（CAC回収期間）】\nCAC Payback = CAC ÷ 月額ARPA\n= 顧客獲得コストを何ヶ月で回収できるか\n\n【目安】\n・6ヶ月以内: 優秀\n・12ヶ月以内: 健全\n・18ヶ月以上: 要改善\n\n例: CAC 40万円、月額ARPA 3万円\nCAC Payback = 13.3ヶ月\n→ 約13ヶ月で投資回収、それ以降が利益", "duration": 45}, {"title": "シーン5: 営業への示唆", "content": "【ユニットエコノミクスからの示唆】\n\n■ LTV/CACを改善するには\n・LTVを上げる: 解約防止、アップセル\n・CACを下げる: 成約率向上、紹介獲得\n\n■ CAC Paybackを改善するには\n・早期解約を防ぐ\n・初期のアップセル\n\n■ 営業が意識すべきこと\n「すぐ解約しそうな顧客を獲得しても意味がない」", "duration": 30}, {"title": "シーン6: 健全な成長のために", "content": "【ユニットエコノミクスの本質】\n\n成長が注目されがちだが、\n「健全な成長」でなければ意味がない。\n\nユニットエコノミクスが成り立たない状態で成長\n= 赤字を拡大しているだけ\n= 砂上の楼閣\n\n【今日の学び】\n「ユニットエコノミクスが成り立たなければ、成長は砂上の楼閣」\n自分の効率が会社の健全性を支える", "duration": 15}]}', '{"title": "ユニットエコノミクス", "content": "LTV/CAC = 3以上が健全 / CAC Payback = 12ヶ月以内", "audioText": "ユニットエコノミクスが成り立たなければ、成長しても意味がありません。", "highlight": "健全な成長の条件"}', '[{"options": ["1以上", "3以上"], "question": "LTV/CAC比率の健全な目安は？", "explanation": "LTV/CAC = 3以上が健全な水準です。", "correctIndex": 1}, {"options": ["24ヶ月以内", "12ヶ月以内"], "question": "CAC Paybackの健全な目安は？", "explanation": "12ヶ月以内に投資回収できるのが健全です。", "correctIndex": 1}]', '{"text": "Without sound unit economics, growth is a castle built on sand.", "author": "SaaSビジネスの格言", "textJa": "ユニットエコノミクスが成り立たなければ、成長は砂上の楼閣。"}', '[{"options": [{"text": "「正直よくわからないんだ」", "points": 0, "feedback": "SaaSビジネスの基本指標は理解しておきましょう。", "isCorrect": false}, {"text": "「収益と獲得コストの比率。3以上が健全」", "points": 30, "feedback": "ユニットエコノミクスの本質を説明できています。", "isCorrect": true}, {"text": "「投資家向けだから営業には関係ない」", "points": 0, "feedback": "営業の効率がLTV/CACに直結します。", "isCorrect": false}, {"text": "「難しい話だから気にしなくていい」", "points": 5, "feedback": "自分の仕事の意味を理解するために必要です。", "isCorrect": false}], "situation": "同期から「LTV/CACって何？」と聞かれました。", "customerLine": "LTV/CACって何？なんで大事なの？"}]', '{"question": "自社のLTV/CAC比率を知っていますか？", "placeholder": "例: 知らない / 約3倍と聞いたことがある"}', '["自社のユニットエコノミクスを確認する", "「件数」だけでなく「質」も意識する", "早期解約されない顧客を獲得する", "LTVを高める活動を意識"]', NULL, NULL, '2026-01-21 17:45:44.083217+00', '2026-01-21 17:45:44.083217+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (37, 127, 'カスタマーサクセスと営業の連携', '顧客が成功しなければ、私たちも成功しない', '{"icon": "users", "name": "CS連携マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["1以上", "3以上"], "question": "LTV/CAC比率の健全な目安は？", "explanation": "LTV/CAC = 3以上が健全な水準でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: CS部門との会話", "content": "（社内にて）\n\nCS担当:「健太さん、先月契約した○○社さん、\n     全然使ってくれてないんですが、\n     何か情報ありますか？」\n\n健太:「え、契約したから僕の仕事は\n      終わりだと思ってました...」\n\nCS担当:「引き継ぎ情報がないと、\n     オンボーディングがうまくいかないんです」", "duration": 45}, {"title": "シーン2: カスタマーサクセスとは", "content": "【カスタマーサクセス（CS）とは】\n顧客の成功を能動的に支援する活動・部門\n\n【カスタマーサポートとの違い】\nサポート: 「受動的」に問い合わせ対応\nサクセス: 「能動的」に成功を働きかける\n\n【カスタマーサクセスの目的】\n・顧客の成功（導入目的の達成）\n・解約防止（チャーン削減）\n・収益拡大（アップセル/クロスセル）\n・顧客の声の収集（製品改善）", "duration": 45}, {"title": "シーン3: CSの活動内容", "content": "【CSの主な活動】\n\n■ オンボーディング\n導入初期の定着支援\n\n■ ヘルススコア管理\n顧客の利用状況を監視、リスクの早期発見\n\n■ 定期的なタッチポイント\nQBR（四半期ビジネスレビュー）等\n\n■ アップセル/クロスセル\n顧客の新たな課題発見と追加提案", "duration": 30}], "part2": [{"title": "シーン4: 営業からCSへの引き継ぎ", "content": "【引き継ぎで伝えるべき情報】\n\n■ 顧客の導入目的・期待値\n「○○という課題を解決したくて導入」\n\n■ 意思決定者・キーパーソン\n「社長が決裁者、店長が現場の推進者」\n\n■ 商談で出た懸念・リスク\n「ITに苦手意識がある」\n\n■ 特別な約束事項\n「○○は月内に対応すると伝えた」\n\n山本先輩:「この情報がないと、\n        CSはゼロからヒアリングになる」", "duration": 45}, {"title": "シーン5: CSから営業へのフィードバック", "content": "【CSから営業へのフィードバック】\n\n■ アップセル/クロスセルの機会\n「○○社さん、追加機能に興味あるみたいです」\n\n■ 顧客の新たなニーズ\n「こんなことがしたいと言ってました」\n\n■ 解約リスクの情報\n「○○社さん、最近使ってないです」\n\n■ 製品改善の要望\n「こういう機能が欲しいという声が多いです」", "duration": 30}, {"title": "シーン6: 顧客の成功を共通のゴールに", "content": "【共通のゴール】\n顧客が成功すること\n\n営業: 顧客の課題を解決できる提案をする\nCS: 顧客が成果を出せるよう支援する\n\n【顧客が成功すると】\n・解約しない → LTV向上\n・拡大してくれる → アップセル\n・紹介してくれる → 新規獲得\n\n【今日の学び】\n「顧客が成功しなければ、私たちも成功しない」\n営業とCSが連携して顧客を成功に導く", "duration": 15}]}', '{"title": "営業とCSの連携", "content": "営業（獲得）→ 引き継ぎ → CS（成功支援）→ フィードバック → 営業（拡大）", "audioText": "営業とCSが連携して、顧客の成功を支援しましょう。", "highlight": "顧客の成功が共通のゴール"}', '[{"options": ["同じ意味", "サポートは受動的、サクセスは能動的"], "question": "カスタマーサポートとカスタマーサクセスの違いは？", "explanation": "サポートは問い合わせ対応、サクセスは能動的に成功を支援します。", "correctIndex": 1}, {"options": ["契約金額だけ", "導入目的、期待値、キーパーソン、懸念点など"], "question": "営業からCSへの引き継ぎで伝えるべきことは？", "explanation": "CSがオンボーディングするために必要な情報を伝えます。", "correctIndex": 1}]', '{"text": "If our customers don''t succeed, neither do we.", "author": "SaaSビジネスの格言", "textJa": "顧客が成功しなければ、私たちも成功しない。"}', '[{"options": [{"text": "「契約書を送っておきます」", "points": 5, "feedback": "顧客理解に必要な情報を伝えましょう。", "isCorrect": false}, {"text": "「導入目的や懸念点をまとめて共有します」", "points": 30, "feedback": "CSがオンボーディングに必要な情報を伝えています。", "isCorrect": true}, {"text": "「特に引き継ぎはないです」", "points": 0, "feedback": "引き継ぎがないとCSは困ります。", "isCorrect": false}, {"text": "「忙しいのであとで対応します」", "points": 0, "feedback": "早めの引き継ぎが顧客の成功につながります。", "isCorrect": false}], "situation": "契約が決まりました。CSへの引き継ぎで何を伝えますか？", "customerLine": "○○社さんの契約、決まりました。CSに引き継いでください"}]', '{"question": "CS部門との連携で、改善できそうなことはありますか？", "placeholder": "例: 引き継ぎを丁寧にする、CSからの情報を活かす"}', '["契約後のCS引き継ぎを丁寧に行う", "CSからのアップセル情報を活かす", "顧客の解約リスク情報を共有してもらう", "「顧客の成功」を共通のゴールにする"]', NULL, NULL, '2026-01-21 17:45:44.804611+00', '2026-01-21 17:45:44.804611+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (38, 128, 'SaaS営業のセールスファネル', 'ファネルを管理できる者が、売上を管理できる', '{"icon": "filter", "name": "ファネルマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["同じ意味", "サポートは受動的、サクセスは能動的"], "question": "カスタマーサポートとカスタマーサクセスの違いは？", "explanation": "サポートは問い合わせ対応、サクセスは能動的に成功を支援しますね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: ファネル管理の会話", "content": "（週次の営業会議にて）\n\n鈴木課長:「今月のパイプライン、見せてくれ」\n\n健太:「パイプライン...えっと、\n      商談中が5件で...」\n\n鈴木課長:「各ステージの内訳は？\n        MQL何件、SQL何件、\n        提案何件、交渉何件？」\n\n健太:「...すみません、\n      そこまで整理できてません」", "duration": 45}, {"title": "シーン2: セールスファネルとは", "content": "【セールスファネル（Sales Funnel）】\n見込み客が「認知」から「購入」に至るまでの\nプロセスを漏斗（ファネル）で表現したもの\n\n【ファネルのイメージ】\n        リード（100人）\n           ↓\n        MQL（50人）\n           ↓\n        SQL（20人）\n           ↓\n        商談（10人）\n           ↓\n        受注（3人）\n\n山本先輩:「各段階で絞り込まれていく」", "duration": 45}, {"title": "シーン3: 各ステージの定義", "content": "【ファネルの各ステージ】\n\n■ リード（Lead）\n何らかの接点を持った見込み客\n\n■ MQL（Marketing Qualified Lead）\nマーケが「営業対象」と判断したリード\n\n■ SQL（Sales Qualified Lead）\n営業が「商談化可能」と判断したリード\n\n■ 商談（Opportunity）\n具体的な提案・検討が進んでいる状態\n\n■ 受注（Won）\n契約締結", "duration": 30}], "part2": [{"title": "シーン4: コンバージョン率", "content": "【コンバージョン率（CVR）】\n各ステージから次のステージへの移行率\n\n例:\nMQL → SQL: 40%\nSQL → 商談: 50%\n商談 → 受注: 30%\n\n【CVRを改善するには】\nMQL→SQL: リードの質向上\nSQL→商談: ヒアリング力向上\n商談→受注: 提案力・クロージング力向上\n\n山本先輩:「どのステージのCVRが低いかを\n        把握すると、改善ポイントがわかる」", "duration": 45}, {"title": "シーン5: パイプライン管理", "content": "【パイプライン管理】\n進行中の商談を金額・ステージ別に管理すること\n\n【パイプラインカバレッジ】\n目標達成に必要なパイプラインの倍率\n\nパイプラインカバレッジ = パイプライン金額 ÷ 目標金額\n\n目安: 3倍以上\n（CVR 30%なら、3倍のパイプラインで目標達成）\n\n山本先輩:「パイプラインが目標の3倍なければ、\n        達成は難しい」", "duration": 30}, {"title": "シーン6: ファネルを管理する", "content": "【ファネル管理のポイント】\n\n✓ 各ステージの件数・金額を把握\n✓ コンバージョン率を把握\n✓ ボトルネックを特定\n✓ パイプラインカバレッジを確認\n\n【今日の学び】\n「ファネルを管理できる者が、売上を管理できる」\n常にパイプラインを把握する", "duration": 15}]}', '{"title": "セールスファネル", "content": "リード → MQL → SQL → 商談 → 受注", "audioText": "ファネルの各ステージとコンバージョン率を管理しましょう。", "highlight": "パイプラインカバレッジ3倍以上"}', '[{"options": ["マーケが認定したリード", "営業が商談化可能と判断したリード"], "question": "SQLとは？", "explanation": "Sales Qualified Lead=営業が認定したリードです。", "correctIndex": 1}, {"options": ["目標の1倍", "目標の3倍以上"], "question": "パイプラインカバレッジの目安は？", "explanation": "CVRを考慮すると、目標の3倍以上のパイプラインが必要です。", "correctIndex": 1}]', '{"text": "Those who manage the funnel can manage revenue.", "author": "SaaS営業の格言", "textJa": "ファネルを管理できる者が、売上を管理できる。"}', '[{"options": [{"text": "「頑張れば達成できると思います」", "points": 0, "feedback": "ファネルに基づいた具体的な見込みを報告しましょう。", "isCorrect": false}, {"text": "「商談5件で見込み○○万円です」", "points": 30, "feedback": "ファネルに基づいた具体的な見込みを報告できています。", "isCorrect": true}, {"text": "「正直わかりません」", "points": 0, "feedback": "パイプラインを把握しておきましょう。", "isCorrect": false}, {"text": "「5件商談中です」", "points": 10, "feedback": "金額と確度も含めて報告しましょう。", "isCorrect": false}], "situation": "上司から「今月の見込みを報告して」と言われました。", "customerLine": "今月の着地見込みを報告して"}]', '{"question": "自分のパイプライン（各ステージの件数・金額）を把握していますか？", "placeholder": "例: 把握している（SQL ○件、商談 ○件）/ 把握できていない"}', '["各ステージの件数・金額を常に把握する", "自分のコンバージョン率を計算する", "パイプラインカバレッジを確認する", "ボトルネックを特定し、改善する"]', NULL, NULL, '2026-01-21 17:45:45.405774+00', '2026-01-21 17:45:45.405774+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (39, 129, 'SaaSの価格戦略と契約形態', '年額契約は顧客にも会社にもメリットがある', '{"icon": "tag", "name": "価格戦略理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["目標の1倍", "目標の3倍以上"], "question": "パイプラインカバレッジの目安は？", "explanation": "CVRを考慮すると、目標の3倍以上のパイプラインが必要でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 月額か年額か", "content": "（営業フロアにて）\n\n健太:「先輩、お客さんから\n      『月額と年額どっちがいい？』って\n      聞かれたんですけど...」\n\n山本先輩:「結論から言うと、年額を勧めろ」\n\n健太:「年額の方がいいんですか？\n      月額の方が気軽に始められそうですけど...」\n\n山本先輩:「顧客にとっても会社にとっても、\n        年額の方がメリットが大きいんだ」", "duration": 45}, {"title": "シーン2: SaaSの価格モデル", "content": "【SaaSの価格モデル】\n\n■ フラットレート（定額制）\n月額○○円で全機能利用可能\n\n■ ユーザー数課金（Per Seat）\n1ユーザーあたり○○円\n\n■ 利用量課金（Usage Based）\n利用量に応じて課金\n\n■ ティアード（段階制）\n機能や容量に応じた複数プラン\n例: Basic / Pro / Enterprise", "duration": 45}, {"title": "シーン3: 月額 vs 年額", "content": "【月額契約】\nメリット: 柔軟性が高い\nデメリット: 解約されやすい、キャッシュフロー不安定\n\n【年額契約】\nメリット: \n・割引あり（顧客にとってお得）\n・解約されにくい\n・キャッシュフロー改善（前払い）\n・顧客のコミットメント向上\n\nデメリット:\n・初期負担が大きい（顧客側）", "duration": 30}], "part2": [{"title": "シーン4: 年額を勧めるトーク", "content": "【年額を勧めるトーク】\n\n「年額契約なら、月額より○ヶ月分お得になります」\n「年間でお支払いいただくと、実質月○○円です」\n「多くのお客様が年額を選ばれています」\n\n【月額を希望された場合】\n「まず月額で始めて、\n 効果を実感されたら年額に切り替えることも可能です」\n\n山本先輩:「無理に押し付けるのではなく、\n        メリットを説明して選んでもらう」", "duration": 45}, {"title": "シーン5: アップセル/クロスセル", "content": "【アップセル】\n既存顧客に上位プランを提案\n例: Basic → Pro → Enterprise\n\nタイミング:\n・顧客が成長した時\n・新機能が必要になった時\n・利用量が上限に近づいた時\n\n【クロスセル】\n既存顧客に関連製品・サービスを提案\n\n【ポイント】\n顧客の課題解決 = アップセル/クロスセルの機会", "duration": 30}, {"title": "シーン6: 契約更新の重要性", "content": "【年額契約の更新】\n・1年後に更新のタイミングが来る\n・更新されなければ解約（Churn）\n・更新＋アップグレードなら拡大（Expansion）\n\n【更新を成功させるには】\n・1年間で成果を出す\n・更新の3ヶ月前から準備\n・成果を可視化して提示\n\n【今日の学び】\n「年額契約は顧客にも会社にもメリットがある」\n契約後の更新・拡大も見据える", "duration": 15}]}', '{"title": "月額 vs 年額", "content": "年額: 割引＋コミット＋キャッシュフロー改善", "audioText": "年額契約は顧客にとってもお得で、会社にとっても安定収益になります。", "highlight": "年額契約を推奨"}', '[{"options": ["解約されやすい", "解約されにくい＋キャッシュフロー改善"], "question": "年額契約のメリットは？", "explanation": "年額は1年間使ってもらえ、前払いでキャッシュフローも改善します。", "correctIndex": 1}, {"options": ["新規顧客獲得", "既存顧客に上位プランを提案"], "question": "アップセルとは？", "explanation": "既存顧客のプランをアップグレードすることです。", "correctIndex": 1}]', '{"text": "Annual contracts benefit both customers and the company.", "author": "SaaS営業の格言", "textJa": "年額契約は顧客にも会社にもメリットがある。"}', '[{"options": [{"text": "「どちらでもお選びいただけます」", "points": 5, "feedback": "年額のメリットを説明しましょう。", "isCorrect": false}, {"text": "「年額なら2ヶ月分お得ですよ」", "points": 30, "feedback": "年額のメリットを具体的に伝えられています。", "isCorrect": true}, {"text": "「月額の方がおすすめです」", "points": 0, "feedback": "年額の方が顧客にも会社にもメリットがあります。", "isCorrect": false}, {"text": "「年額しか選べません」", "points": 0, "feedback": "選択肢を示した上で、年額を推奨しましょう。", "isCorrect": false}], "situation": "顧客から「月額と年額、どっちがいいですか？」と聞かれました。", "customerLine": "月額と年額、どちらがおすすめですか？"}]', '{"question": "担当顧客で、アップセルの機会がありそうな顧客はいますか？", "placeholder": "例: ○○社は利用量が増えてきた、△△社は新機能に興味を示していた"}', '["年額契約のメリットを説明できるようにする", "既存顧客のアップセル機会を探す", "契約更新の3ヶ月前から準備する", "顧客の成長に合わせたプラン提案をする"]', NULL, NULL, '2026-01-21 17:45:45.990467+00', '2026-01-21 17:45:45.990467+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (40, 130, 'SaaS営業の成功指標とKPI', '測定できるものは改善できる。KPIは成長の羅針盤', '{"icon": "compass", "name": "KPIマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["解約されやすい", "解約されにくい＋キャッシュフロー改善"], "question": "年額契約のメリットは？", "explanation": "年額は1年間使ってもらえ、前払いでキャッシュフローも改善しますね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: KPIの振り返り", "content": "（月末の1on1ミーティング）\n\n鈴木課長:「健太、今月のKPIを振り返ろう」\n\n健太:「えっと...3件受注しました」\n\n鈴木課長:「それだけ？\n        活動量は？コンバージョン率は？\n        MRRは？」\n\n健太:「...すみません、\n      そこまで整理できてません」\n\n鈴木課長:「KPIを振り返らなければ、\n        改善もできないぞ」", "duration": 45}, {"title": "シーン2: SaaS営業のKPI一覧", "content": "【活動指標（Input）】\n・コール数/メール数\n・アポイント獲得数\n・商談数\n・デモ実施数\n\n【成果指標（Output）】\n・新規MRR/ARR\n・受注件数\n・受注金額\n・成約率（CVR）\n\n【効率指標】\n・平均商談単価\n・平均商談期間\n・CAC\n・営業1人あたり生産性", "duration": 45}, {"title": "シーン3: KPIの階層構造", "content": "【KPIの階層構造】\n\n最終目標: 新規MRR ○○万円\n   ↑\n成果指標: 受注件数 × 平均単価\n   ↑\nプロセス指標: 商談数 × 成約率\n   ↑\n活動指標: アポ数 × 商談化率\n   ↑\n行動指標: コール数 × アポ獲得率\n\n山本先輩:「各指標を分解すると、\n        どこに課題があるかが見える」", "duration": 30}], "part2": [{"title": "シーン4: 課題の特定", "content": "【例：新規MRRが足りない場合】\n\n新規MRR = 受注件数 × 平均単価\nQ. 受注件数が少ない？単価が低い？\n\n受注件数 = 商談数 × 成約率\nQ. 商談数が少ない？成約率が低い？\n\n商談数 = アポ数 × 商談化率\nQ. アポが取れていない？商談化できていない？\n\n山本先輩:「こうやって分解すると、\n        改善ポイントがわかる」", "duration": 45}, {"title": "シーン5: 振り返りの習慣", "content": "【週次で振り返るべき指標】\n・活動量（コール数、アポ数、商談数）\n・パイプライン状況\n・今週の受注見込み\n\n【月次で振り返るべき指標】\n・新規MRR達成率\n・各ステージのコンバージョン率\n・平均商談単価・期間\n\n【振り返りのポイント】\n・数字を見る\n・原因を分析する\n・改善アクションを決める\n・実行する", "duration": 30}, {"title": "シーン6: 測定できるものは改善できる", "content": "【KPIの本質】\n「測定できるものは改善できる」\n\n数字で把握しなければ、改善もできない。\n感覚ではなく、データで判断する。\n\n【KPIは成長の羅針盤】\n・現在地がわかる\n・目標との差がわかる\n・どこを改善すればいいかわかる\n・成長を実感できる\n\n【今日の学び】\n「測定できるものは改善できる。KPIは成長の羅針盤」", "duration": 15}]}', '{"title": "SaaS営業のKPI階層", "content": "行動指標 → 活動指標 → プロセス指標 → 成果指標 → 最終目標", "audioText": "KPIを階層で理解し、課題を特定して改善しましょう。", "highlight": "分解すると課題が見える"}', '[{"options": ["複雑にするため", "課題を特定するため"], "question": "KPIを分解する目的は？", "explanation": "分解することで、どこに課題があるかが見えます。", "correctIndex": 1}, {"options": ["数字が全て", "数字で把握しなければ改善もできない"], "question": "「測定できるものは改善できる」の意味は？", "explanation": "感覚ではなく、データで把握することが改善の第一歩です。", "correctIndex": 1}]', '{"text": "What gets measured gets improved. KPIs are the compass for growth.", "author": "経営の格言", "textJa": "測定できるものは改善できる。KPIは成長の羅針盤である。"}', '[{"options": [{"text": "「一生懸命頑張りました」", "points": 0, "feedback": "具体的な数字で振り返りましょう。", "isCorrect": false}, {"text": "「成約率○%、MRR○万円。課題は○○」", "points": 30, "feedback": "数字に基づいた振り返りができています。", "isCorrect": true}, {"text": "「3件受注しました」", "points": 10, "feedback": "活動量やコンバージョン率も含めて振り返りましょう。", "isCorrect": false}, {"text": "「把握できていません」", "points": 0, "feedback": "自分のKPIは把握しておきましょう。", "isCorrect": false}], "situation": "上司から「今月の振り返りをして」と言われました。", "customerLine": "今月のKPIを振り返って報告して"}]', '{"question": "自分のKPIの「課題」はどこにありますか？どう改善しますか？", "placeholder": "例: 商談数は足りているが成約率が低い → クロージングを改善する"}', '["週次でKPIを振り返る習慣をつける", "KPIを分解して課題を特定する", "課題に対する改善アクションを実行する", "PDCAサイクルを回し続ける"]', '{"title": "KPI振り返りシート", "fields": [{"label": "活動量（コール数、アポ数、商談数）", "placeholder": "例: コール○件、アポ○件、商談○件"}, {"label": "成果（受注件数、新規MRR）", "placeholder": "例: 受注○件、新規MRR○万円"}, {"label": "コンバージョン率", "placeholder": "例: アポ→商談 ○%、商談→受注 ○%"}, {"label": "課題と改善策", "placeholder": "例: 成約率が低い → 提案の質を改善する"}], "description": "今月の自分のKPIを整理してみましょう。"}', NULL, '2026-01-21 17:45:46.538429+00', '2026-01-21 17:45:46.538429+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (41, 1, '営業とは問題解決である', '売るな、解決しろ', '{"icon": "search", "name": "問題解決者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["商品を売ること", "顧客の問題を解決すること", "ノルマを達成すること", "競合に勝つこと"], "question": "営業の本質とは何でしょうか？", "explanation": "営業の本質は商品を売ることではなく、顧客の問題を解決することです。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 売り込み営業の失敗", "content": "健太:「弊社のシステムは業界No.1の機能を搭載しており、\n      導入実績も500社以上ございます！」\n店長:「...で、それがうちに何の関係があるの？」\n健太:「え...」\n店長:「忙しいから、もういいよ」\n\n健太（心の声）:「なんでダメなんだ...\n         こんなにいいシステムなのに...」", "duration": 45}, {"title": "シーン2: 山本先輩のアドバイス", "content": "山本先輩:「健太、さっきの商談どうだった？」\n健太:「ダメでした...商品の良さを伝えたのに...」\n山本先輩:「商品の良さを伝えた？」\n健太:「はい、機能とか実績とか」\n山本先輩:「相手の困ってることは聞いた？」\n健太:「...いえ」\n山本先輩:「それが問題だよ。営業は\"売る\"んじゃない、\n         \"解決する\"んだ」", "duration": 45}, {"title": "シーン3: 問題解決営業とは", "content": "山本先輩:「お客さんは商品が欲しいんじゃない。\n         問題を解決したいんだ」\n\n【営業の2つのアプローチ】\n\n売り込み営業:\n商品 → 顧客 「これ買ってください！」\n結果: 拒否される\n\n問題解決営業:\n顧客の問題 → 解決策として商品を提案\n結果: 「それなら聞いてみよう」\n\n山本先輩:「まず相手の話を聞く。\n         困っていることを理解する。\n         そこに解決策を提案する。これが営業だ」", "duration": 30}], "part2": [{"title": "シーン4: リベンジ商談", "content": "健太:「本日はお時間いただきありがとうございます。\n      まず、現在のお仕事で困っていることを\n      教えていただけますか？」\n店長:「そうだな...人手不足で事務作業が回らないんだよ」\n健太:「事務作業というと、具体的には？」\n店長:「毎日の売上集計とか、在庫管理とか。\n      閉店後に2時間はかかってる」\n健太:「毎日2時間...それは大変ですね」", "duration": 45}, {"title": "シーン5: 解決策の提案", "content": "健太:「実は、その事務作業を自動化できるシステムがあります」\n店長:「自動化？」\n健太:「はい。売上集計は自動で、在庫管理もリアルタイムで。\n      導入いただいた店舗では、閉店後の作業が\n      30分に短縮されています」\n店長:「2時間が30分に...？」\n健太:「はい。浮いた時間で、スタッフの教育や\n      接客の質向上に使えます」\n店長:「...詳しく聞かせてくれ」\n健太:「ありがとうございます！」", "duration": 30}, {"title": "シーン6: 気づき", "content": "山本先輩:「どうだった？」\n健太:「アポが取れました！」\n山本先輩:「何が変わった？」\n健太:「商品を売ろうとするんじゃなく、\n      相手の問題を聞いて、解決策を提案しました」\n山本先輩:「それが営業だよ。\n         売るな、解決しろ。覚えておいて」\n\n【今日の学び】\n「営業 = 問題解決」", "duration": 15}, {"title": "シーン7: 自分で解決できない時は", "content": "健太:「先輩、もし聞き出した課題に対して、\n      自分で解決策が分からない時はどうすれば...？」\n\n山本先輩:「いい質問だな。新人のうちは当然そういう場面がある。\n         大事なのは、課題をしっかり聞き出すことだ」\n\n山本先輩:「聞き出した課題を持ち帰って、\n         先輩や上司に相談すればいい」\n\n【課題を持ち帰るための言い回し】\n\n「貴重なお話をありがとうございます。\n 一度社内で最適なご提案を検討させてください。\n 〇日までにご連絡させていただきます」\n\n「御社の状況をしっかり理解できました。\n より具体的なご提案をするために、\n 専門のスタッフと相談してまいります」\n\n山本先輩:「『分かりません』じゃなく、\n         『確認して改めてご提案します』だ。\n         これも立派な問題解決のプロセスだよ」", "duration": 45}, {"title": "シーン8: 先輩への相談の仕方", "content": "山本先輩:「持ち帰った後の相談の仕方も大事だぞ」\n\n【先輩・上司への相談フレーズ】\n\n「○○社の店長様から、△△という課題をお聞きしました。\n どのような解決策をご提案すべきでしょうか？」\n\n「お客様が□□でお困りとのことでした。\n 弊社の製品で対応できる範囲を教えていただけますか？」\n\n「本日の商談で、××というご要望がありました。\n アドバイスをいただけると助かります」\n\n健太:「課題を具体的に伝えることが大事なんですね」\n\n山本先輩:「そう。『商談うまくいきませんでした』じゃなく、\n         『お客様は〇〇という課題を抱えていて、\n          △△を求めていました』と伝える。\n         具体的な情報があれば、\n         具体的なアドバイスができるからな」\n\n【ポイント】\n・聞き出した課題を具体的にメモ\n・5W1H（いつ・どこで・誰が・何を・なぜ・どうやって）で整理\n・「相談」は成長の証。遠慮せず頼ろう", "duration": 45}]}', '{"title": "営業の本質", "content": "売り込み営業 vs 問題解決営業", "audioText": "営業は商品を売る仕事ではありません。顧客の問題を解決する仕事です。", "highlight": "売るな、解決しろ"}', '[{"options": ["商品の説明をする", "顧客の課題を聞く"], "question": "営業で最初にすべきことは？", "explanation": "まず顧客の課題を聞き、理解することが営業の第一歩です。", "correctIndex": 1}, {"options": ["優れた機能を持つ商品", "自分の問題の解決"], "question": "顧客が本当に欲しいのは？", "explanation": "顧客は商品そのものではなく、問題が解決されることを望んでいます。", "correctIndex": 1}]', '{"text": "People don''t want to buy a quarter-inch drill. They want a quarter-inch hole.", "author": "セオドア・レビット", "textJa": "人々は1/4インチのドリルを買いたいのではない。1/4インチの穴が欲しいのだ。"}', '[{"options": [{"text": "「弊社のシステムの機能をご説明させてください！」", "points": 0, "feedback": "売り込み営業になっています。まず相手の話を聞きましょう。", "isCorrect": false}, {"text": "「お忙しいところすみません。今、一番困っていることは何ですか？」", "points": 30, "feedback": "素晴らしい！まず顧客の課題を聞く姿勢が大切です。", "isCorrect": true}, {"text": "「他社より安いのでお得ですよ！」", "points": 0, "feedback": "価格訴求も売り込みです。顧客の課題を理解してからです。", "isCorrect": false}, {"text": "「また来ます」と帰る", "points": 0, "feedback": "チャンスを逃しています。一言でも課題を聞いてみましょう。", "isCorrect": false}], "situation": "初回訪問で店長と話しています。店長は忙しそうです。", "customerLine": "何の用？手短にね"}, {"options": [{"text": "「それは弊社では対応できないですね...」と正直に言う", "points": 0, "feedback": "課題を聞き出せたのに、可能性を閉ざしてしまっています。まず詳しく聞いてから判断しましょう。", "isCorrect": false}, {"text": "「たぶん弊社のシステムで解決できると思います！」と言い切る", "points": 0, "feedback": "根拠なく言い切るのは危険です。後で信頼を失う原因になります。", "isCorrect": false}, {"text": "「詳しくお聞かせください。社内で最適なご提案を検討させてください」", "points": 30, "feedback": "素晴らしい！課題を深掘りし、持ち帰って先輩に相談する姿勢です。これも立派な問題解決です。", "isCorrect": true}, {"text": "話題を変えて、自分が説明できる機能の話をする", "points": 0, "feedback": "お客様の課題から逃げています。わからないことは持ち帰る勇気を持ちましょう。", "isCorrect": false}], "situation": "店長から「うちは仕入れ先との取引条件が厳しくて、キャッシュフローが回らないんだよ」と言われました。あなたはこの課題に対する解決策がすぐに思い浮かびません。", "customerLine": "仕入れ先との取引条件が厳しくて、キャッシュフローが回らないんだよ"}, {"options": [{"text": "「今日の商談、難しかったです...」", "points": 0, "feedback": "抽象的すぎます。何が難しかったのか具体的に伝えないと、アドバイスができません。", "isCorrect": false}, {"text": "「○○モータースの店長様から、仕入れ先との取引条件によるキャッシュフロー問題をお聞きしました。弊社で対応できる解決策を教えていただけますか？」", "points": 30, "feedback": "具体的で素晴らしい！課題を明確に伝えれば、先輩も具体的なアドバイスができます。", "isCorrect": true}, {"text": "「キャッシュフローの話をされたんですが、よくわかりませんでした」", "points": 5, "feedback": "「わからない」で終わらせず、何をどこまで聞けたか整理して伝えましょう。", "isCorrect": false}, {"text": "相談せずに、自分でネットで調べる", "points": 5, "feedback": "自己解決の姿勢は良いですが、新人のうちは先輩の経験を借りる方が効率的です。", "isCorrect": false}], "situation": "商談後、会社に戻って山本先輩に相談します。どう伝えますか？", "customerLine": "（先輩に報告する場面です）"}]', '{"question": "明日から「売り込み」ではなく「問題解決」するために、何を意識しますか？", "placeholder": "商品の説明より先に、相手の困っていることを聞くようにする。わからないことは持ち帰って先輩に相談する。"}', '["商談の最初に「困っていることは何ですか？」と聞く", "商品説明の前に、相手の話を5分以上聞く", "提案は「御社の○○という課題に対して」から始める", "わからない課題は「社内で検討します」と持ち帰る", "商談後、聞き出した課題を5W1Hで整理してメモする", "持ち帰った課題は当日中に先輩に相談する"]', '{"title": "相談フレーズ練習", "fields": [{"label": "お客様に「持ち帰ります」と伝えるフレーズ", "placeholder": "例: 貴重なお話をありがとうございます。一度社内で最適なご提案を検討させてください。○日までにご連絡させていただきます。"}, {"label": "先輩・上司に相談するフレーズ", "placeholder": "例: ○○社の店長様から、△△という課題をお聞きしました。どのような解決策をご提案すべきでしょうか？"}, {"label": "聞き出した課題のメモ（5W1Hで整理）", "placeholder": "例: 【誰が】店長が【何を】仕入れ先との取引条件【なぜ】キャッシュフローが回らない【いつから】半年前から【どうしたい】条件改善か運転資金確保"}], "description": "課題を持ち帰る時と、先輩に相談する時のフレーズを練習しましょう。"}', '{"title": "営業とは問題解決である", "sections": [{"title": "第1章 経営学の父が説いた「顧客起点」の哲学", "content": "**Peter Druckerとは**\n\nPeter Ferdinand Drucker（1909-2005）は、「現代経営学の父」と呼ばれるオーストリア生まれの経営学者です。その思想は、IBM、GE、トヨタをはじめとする世界中の企業に影響を与え、「目標管理（MBO）」や「知識労働者」といった概念を生み出しました。\n\n> \"企業の目的として有効な定義は一つしかない。それは「顧客を創造すること」である。\"\n> — Peter Drucker\n\n**「売る」から「買いたくなる」へ**\n\nDruckerの営業・マーケティング観で最も重要なのは、視点の転換です。従来の営業は「私たちは何を売りたいか」から出発していました。しかしDruckerは、これを根本から覆します。\n\n> \"真のマーケティングは顧客から始まる。その属性、現実、ニーズ、価値観から始まる。『何を売りたいか』ではなく『顧客は何を買いたいか』を問うのである。\"\n\n**視点の転換ポイント**\n- 【従来】商品の特徴を説明する → 【新】顧客の課題を理解する\n- 【従来】なぜこの商品が良いか → 【新】なぜこの顧客にとって価値があるか\n- 【従来】競合との比較優位 → 【新】顧客の現状との比較（Before/After）\n- 【従来】クロージングで決める → 【新】顧客が自ら「欲しい」と思う状態を作る\n\n**「営業を不要にする」という究極の目標**\n\n> \"マーケティングの目的は、セリング（売り込み）を不要にすることである。\"\n> — Peter Drucker『The Essential Drucker』\n\n顧客を深く理解し、その課題に対する最適な解決策を提示できれば、「売り込み」は必要なくなる——これがDruckerの理想とする営業の姿です。"}, {"title": "第2章 科学が証明した「売れる営業」の真実", "content": "**SPIN Sellingとは**\n\n1988年に出版された『SPIN Selling』は、営業の世界に革命をもたらしました。著者のNeil Rackhamは、イギリスの心理学者であり、Huthwaite社の創設者です。\n\nこの本の最大の特徴は、「勘」や「経験」ではなく、徹底的なデータ分析に基づいている点です。\n\n**SPIN Selling 研究の規模**\n- 調査期間：12年間\n- 投資額：100万ドル以上\n- 分析した商談数：35,000件以上\n- 対象営業担当者：10,000人以上\n- 調査国数：23カ国以上\n\n**衝撃の発見：「従来の常識」は間違っていた**\n\n研究は、営業における多くの「常識」を覆しました：\n\n- 【誤】クロージングテクニックを多用すれば成約率が上がる\n  → 【真】大型商談では逆効果。買い手の抵抗を招く\n- 【誤】商品のベネフィットを強調すべき\n  → 【真】大型商談では効果が薄い。むしろ反論を招くことも\n- 【誤】オープンクエスチョンはクローズドより効果的\n  → 【真】質問の「種類」より「目的」が重要\n\n**SPINの4つの質問タイプ**\n\n- **S (Situation)**：状況質問 — 顧客の現状を把握する質問\n- **P (Problem)**：問題質問 — 顧客の課題や不満を探る質問\n- **I (Implication)**：示唆質問 — 問題を放置した場合の影響を考えさせる質問\n- **N (Need-payoff)**：解決質問 — 解決した場合の価値を顧客自身に語らせる質問\n\n> \"人々が本当に望んでいることを明確にする手助けをすること、それが私の考える最良の関係構築法である。それがSPINモデルの核心だ。\"\n> — Neil Rackham\n\n**なぜ「質問」が効果的なのか**\n\n人は、他人から言われたことより、自分で気づいたことに強く動機づけられます。これは「自己説得効果」と呼ばれる心理現象であり、SPINモデルはこれを体系的に活用しています。"}, {"title": "第3章 「売る」から「解決する」へ", "content": "**Solution Sellingの誕生**\n\nMichael T. Bosworthは、XeroxでNeil RackhamとともにSPINセリングプロジェクトに携わった経験を持つ営業トレーナーです。1983年、彼はその経験を基に「Solution Selling（ソリューション営業）」という方法論を創設しました。\n\n**「Spray and Pray」からの脱却**\n\nBosworthは、従来型の営業を「Spray and Pray（撒き散らして祈る）」と表現しました。\n\n> \"多くの営業担当者は、見込み客に焦点を当てる代わりに、製品やサービスの機能と利点のリストをまくし立てる。その製品が買い手の問題を解決するかどうか？たぶん。営業担当者は知らないし、気にもしない。\"\n> — Michael T. Bosworth『Solution Selling』\n\nSolution Sellingは、このアプローチを根本から変えることを提唱します。商品の説明から始めるのではなく、「診断」から始めるのです。\n\n**Solution Sellingの3つのフェーズ**\n\n- **Phase 1：信頼獲得** — 顧客の信頼を得て、ニーズを明確化する手助けをする\n- **Phase 2：解決策の提示** — 自社の製品・サービスが理想的な解決策であることを示す\n- **Phase 3：価値の確認** — 顧客が期待する価値が実現されることを確認し、関係を維持する\n\n重要なのは、このプロセスは営業側の都合ではなく、顧客の購買プロセスに合わせて設計されているということです。"}, {"title": "第4章 「ベンダー」から「パートナー」へ", "content": "**Consultative Selling（コンサルティング営業）とは**\n\nMack Hananは、1970年代から「Consultative Selling」という概念を提唱してきました。彼の著書は8版を重ね、40年以上にわたり世界中の営業プロフェッショナルに影響を与え続けています。\n\n> \"あなたはもはや『ベンダー（売り手）』ではない。顧客に製品を売り込む存在ではなく、顧客のビジネスパートナーなのだ。\"\n> — Mack Hanan『Consultative Selling』\n\n**Vendor Selling vs Consultative Selling**\n\n| Vendor Selling | Consultative Selling |\n|----------------|---------------------|\n| 製品を売る | 利益改善を売る |\n| 価格競争に巻き込まれる | 価値に基づく価格設定 |\n| 一回限りの取引 | 長期的なパートナーシップ |\n| 購買担当者と交渉 | 意思決定者と対話 |\n| 製品機能で差別化 | 顧客への貢献で差別化 |\n\n**Win-Winの関係構築**\n\n> \"顧客の利益を改善する手助けをすれば、Win-Winのソリューションが生まれ、互いにメリットのある長期的なビジネス関係につながる。\"\n> — Mack Hanan\n\nこの考え方は、自動車販売においても重要な示唆を与えます。単に「良い車を安く売る」のではなく、「お客様のカーライフをどれだけ豊かにできるか」を考え、提案することで、長期的な関係を築くことができるのです。"}, {"title": "第5章 3つの理論の統合", "content": "**共通する核心**\n\nSPIN Selling、Solution Selling、Consultative Selling——この3つの理論は、異なる視点から営業を研究していますが、いずれも同じ結論に到達しています。\n\n**3つの理論に共通する核心**\n- **顧客起点**：商品ではなく、顧客の課題から出発する\n- **診断的アプローチ**：まず理解し、それから提案する\n- **価値の共創**：顧客と共に解決策を見出す\n- **長期的関係**：一回の取引ではなく、継続的なパートナーシップを目指す\n- **自己説得**：顧客自身が価値を認識するよう導く\n\n**「問題解決型営業」の全体像**\n\n| 段階 | 目的 | 主な活動 |\n|------|------|----------|\n| 1. 信頼構築 | 顧客との信頼関係を築く | 傾聴、共感、誠実な態度 |\n| 2. 状況把握 | 顧客の現状を深く理解する | 状況質問（SPIN: S） |\n| 3. 問題発見 | 顧客の課題を明確化する | 問題質問（SPIN: P） |\n| 4. 影響認識 | 問題の深刻さを認識させる | 示唆質問（SPIN: I） |\n| 5. 価値提案 | 解決策の価値を顧客自身に語らせる | 解決質問（SPIN: N） |\n| 6. 関係継続 | 長期的なパートナーシップを築く | フォローアップ、継続的な価値提供 |"}, {"title": "第6章 Symphonyへの適用", "content": "**なぜSymphonyユーザーに「問題解決型営業」が重要か**\n\nSymphony研修が「問題解決型営業」を基盤に据えているのには、明確な理由があります。自動車販売、特に中古車ビジネスは、まさに「顧客の課題解決」が価値の源泉となる領域だからです。\n\n**自動車販売における「問題解決」の具体例**\n- 「家族が増えたので、もっと広い車が欲しい」→ ライフステージの変化への対応\n- 「燃費の悪い車に乗っていて、毎月のガソリン代が負担」→ 経済的課題の解決\n- 「子供の送り迎えに使いやすい車を探している」→ 日常の利便性向上\n- 「今の車が古くなって、故障が心配」→ 安心・安全への不安解消\n- 「法人の営業車を効率よく運用したい」→ ビジネス効率の改善\n\nこれらはすべて「顧客の課題」です。そして、この課題を的確に把握し、最適な解決策を提案できる営業担当者こそが、顧客に選ばれるのです。\n\n**Symphonyで実現できること**\n- 顧客の購買履歴や嗜好を把握し、個別最適な提案ができる\n- 商談の進捗を可視化し、適切なタイミングでのアプローチが可能\n- フォローアップを自動化し、「売りっぱなし」を防止\n- チーム全体で顧客情報を共有し、一貫したサービスを提供\n- データに基づく意思決定で、営業活動の質を継続的に改善\n\n**実践への架け橋**\n\n理論を学ぶことと、実践することは異なります。本書で紹介した知見を、日々の営業活動に活かすためには、継続的な学習と振り返りが必要です。\n\nSymphony研修プログラムでは、本書の内容をベースに、ロールプレイングやAIシミュレーションを通じて、実践的なスキルを身につけていきます。「知っている」を「できる」に変えること——それがSymphony研修の目指すゴールです。"}], "subtitle": "世界の営業研究が証明する「顧客中心主義」の真実", "conclusion": "本書では、Peter Drucker、Neil Rackham、Michael T. Bosworth、Mack Hananという4人の先駆者の知見を通じて、「営業とは問題解決である」という考え方の理論的背景を探ってきました。\n\n彼らの研究と実践が示しているのは、「売る力」ではなく「理解する力」、「説得する技術」ではなく「共感する姿勢」こそが、真に優れた営業担当者の条件だということです。\n\n> \"優れた営業とは、顧客に何かを売りつけることではない。顧客自身が本当に望んでいることを明確にする手助けをすることである。そのとき、製品やサービスは自然と選ばれる。\"\n\n自動車業界が大きな変革期を迎える中、私たちに求められているのは、単なる「クルマを売る人」ではなく、「お客様のモビリティに関するあらゆる課題を解決するパートナー」として進化することです。\n\nその第一歩が、「営業とは問題解決である」という認識の転換です。この認識を持って日々の営業活動に臨むとき、私たちの仕事は単なる「販売」から「価値創造」へと昇華するのです。", "references": ["Peter Drucker『Management: Tasks, Responsibilities, Practices』(1973)", "Peter Drucker『The Essential Drucker』(2001)", "Neil Rackham『SPIN Selling』(1988)", "Michael T. Bosworth『Solution Selling』(1993)", "Mack Hanan『Consultative Selling』(1970/2018, 8th Edition)"], "introduction": "自動車業界は今、100年に一度の大変革期を迎えています。電動化、自動運転、コネクテッド、シェアリング——いわゆるCASEの波が、従来のビジネスモデルを根底から揺さぶっています。\n\nこのような時代において、「良いクルマを仕入れて、適正価格で売る」という従来型の営業スタイルだけでは、もはや競争優位を築くことは困難です。お客様が求めているのは、単なる「商品」ではなく、「自分の課題を解決してくれるパートナー」だからです。\n\n本書では、世界的な営業研究の成果を紐解きながら、「営業とは問題解決である」という考え方の理論的背景と実践的な意義を深く掘り下げていきます。"}', '2026-01-21 17:48:06.405005+00', '2026-01-21 17:48:06.405005+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (42, 2, '第一印象の科学', '最初の5秒で勝負は決まる', '{"icon": "sparkles", "name": "第一印象マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["商品を売ること", "顧客の問題を解決すること", "価格で勝負すること", "競合に勝つこと"], "question": "営業の本質は何でしたか？", "explanation": "「売るな、解決しろ」でしたね。顧客の課題を解決することが営業の本質です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 第一印象での失敗", "content": "（朝9時。商談先に向かう健太）\n\n健太（心の声）:「ヤバい、寝坊した！」\n\n（息を切らして到着。髪はボサボサ、シャツはシワだらけ）\n\n健太:「す、すみません！遅れました！」\n\n佐藤社長:「...」（表情が硬い）\n\n健太:「本日はお時間いただき...」\n\n佐藤社長:「忙しいから、5分で終わらせて」\n\n健太（心の声）:「なんでこんなに冷たいんだ...」", "duration": 45}, {"title": "シーン2: メラビアンの法則", "content": "山本先輩:「健太、知ってる？\n         第一印象は3〜5秒で決まるんだ」\n\n健太:「3秒...！？」\n\n山本先輩:「メラビアンの法則って聞いたことある？」\n\n【メラビアンの法則】\n視覚情報（見た目、表情、姿勢）: 55%\n聴覚情報（声のトーン、話し方）: 38%\n言語情報（話の内容）: 7%\n\n山本先輩:「話の内容はたった7%。\n         それより、見た目と話し方が93%を占める。\n         つまり、何を話すかより、\n         どう見えるかが大事なんだ」", "duration": 45}, {"title": "シーン3: 第一印象の改善", "content": "山本先輩:「今日の君はどうだった？」\n\n健太:「遅刻して、髪もボサボサで...」\n\n山本先輩:「それが原因だな。商談の内容以前に、\n         第一印象で『この人に任せて大丈夫か？』\n         って思われてる」\n\n健太:「見た目で...」\n\n山本先輩:「営業は\"信頼される人\"になることが大事。\n         第一印象を良くするには、\n         ・10分前には到着\n         ・清潔感のある身だしなみ\n         ・明るい表情と声\n         基本だけど、これで印象は大きく変わる」", "duration": 30}], "part2": [{"title": "シーン4: 翌日のリベンジ", "content": "（翌日。10分前に到着した健太）\n\n健太（心の声）:「今日は準備万端だ」\n\n（身だしなみをチェック。深呼吸）\n\n佐藤社長の秘書:「佐々木さんですね。お待ちしてました」\n\n（会議室に通される）\n\n佐藤社長:「おお、来たか」\n\n健太:「おはようございます！\n      本日はお時間いただきありがとうございます」\n      （明るい声、しっかりしたお辞儀）\n\n佐藤社長:「ん、今日は元気がいいな」", "duration": 45}, {"title": "シーン5: 信頼の獲得", "content": "健太:「早速ですが、昨日の続きで...」\n\n佐藤社長:「うん、聞こうか」\n       （前日より柔らかい表情）\n\n健太（心の声）:「昨日と全然違う...\n         話を聞いてもらえてる！」\n\n〜商談後〜\n\n佐藤社長:「来週、もう一度詳しく聞かせてくれ」\n\n健太:「ありがとうございます！」", "duration": 30}, {"title": "シーン6: 学び", "content": "山本先輩:「どうだった？」\n\n健太:「昨日と全然違いました！\n      話を聞いてもらえました」\n\n山本先輩:「何を変えた？」\n\n健太:「10分前に到着して、身だしなみを整えて、\n      明るい声で挨拶しました」\n\n山本先輩:「それだけで結果が変わっただろ？\n         第一印象は、営業の\"入口\"なんだ。\n         入口で躓いたら、中には入れない」\n\n【今日の学び】\n「最初の5秒で勝負は決まる」", "duration": 15}]}', '{"title": "メラビアンの法則", "content": "第一印象を決める3要素", "audioText": "第一印象は3〜5秒で決まります。視覚情報が55%、話の内容はわずか7%です。", "highlight": "最初の5秒で勝負は決まる"}', '[{"options": ["1秒", "3〜5秒", "30秒", "1分"], "question": "第一印象は何秒で決まる？", "explanation": "第一印象は3〜5秒という短い時間で決まってしまいます。", "correctIndex": 1}, {"options": ["話の内容（言語）", "見た目・表情（視覚）"], "question": "メラビアンの法則で最も影響が大きいのは？", "explanation": "視覚情報が55%で最も大きな影響を与えます。話の内容は7%です。", "correctIndex": 1}]', '{"text": "You never get a second chance to make a first impression.", "author": "ウィル・ロジャース", "textJa": "第一印象をやり直す機会は二度とない。"}', '[{"options": [{"text": "ギリギリまで近くのカフェで時間を潰す", "points": 0, "feedback": "余裕を持って到着しましょう。焦りは第一印象に現れます。", "isCorrect": false}, {"text": "身だしなみをチェックし、深呼吸してから入る", "points": 30, "feedback": "完璧です！準備万端で臨むことで、良い第一印象を与えられます。", "isCorrect": true}, {"text": "スマホを見ながら待つ", "points": 5, "feedback": "集中力を高める時間に使いましょう。", "isCorrect": false}, {"text": "早く着きすぎたので、少し遅れて入る", "points": 0, "feedback": "10分前到着は基本です。早すぎることはありません。", "isCorrect": false}], "situation": "商談の10分前。あなたは会社の前にいます。", "customerLine": ""}]', '{"question": "明日の商談で、第一印象を良くするために何を準備しますか？", "placeholder": "10分前に到着し、身だしなみを整え、明るい声で挨拶する"}', '["商談の10分前には到着する", "出発前に鏡で身だしなみをチェックする", "入室時は明るい声で挨拶する"]', NULL, NULL, '2026-01-21 17:48:07.458382+00', '2026-01-21 17:48:07.458382+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (43, 3, '断られることへの心構え', '断られるのは"失敗"ではなく"進捗"', '{"icon": "shield", "name": "不屈の心"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["1秒", "3〜5秒", "30秒", "1分"], "question": "第一印象は何秒で決まる？", "explanation": "「最初の5秒で勝負は決まる」でしたね！", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 断られ続ける健太", "content": "健太:「お忙しいところ失礼します！\n      ファブリカホールディングスの—」\n店長:「間に合ってるから」ガチャッ\n健太:「...また断られた...」\n\n（テレアポ100件、アポ0件の画面表示）\n\n健太の心の声:「俺、向いてないのかな...」", "duration": 45}, {"title": "シーン2: 落ち込む健太と先輩の言葉", "content": "山本先輩:「健太、今日何件かけた？」\n健太:「...100件です。でも全部断られて...」\n山本先輩:「100件！すごいじゃん」\n健太:「え？でも1件もアポ取れてないですよ？」\n山本先輩:「俺が新人の時、1日50件が限界だった。\n         で、アポ取れたの何件だと思う？」\n健太:「...5件くらいですか？」\n山本先輩:「ゼロだよ、ゼロ。最初の1ヶ月、1件も取れなかった」\n健太:「え...！」", "duration": 45}, {"title": "シーン3: マインドセットの転換", "content": "山本先輩:「断られるのが普通。\n         100件かけて3件アポが取れたら上出来。\n         つまり、97回は断られるのが\"仕事\"なんだよ」\n\n（画面に数字が表示）\n  一般的なアポ獲得率: 1〜3%\n  100件中97件は断られる = 正常\n\n山本先輩:「断られた数だけ、アポに近づいてる。\n         さっきの100件は、明日のアポの\"種まき\"だと思えばいい」\n\n健太の表情が少し明るくなる", "duration": 30}], "part2": [{"title": "シーン4: 翌日の健太", "content": "健太（心の声）:「断られるのが仕事...\n           97回は断られて当然...」\n\n店長:「忙しいから」\n健太:「承知しました！お忙しいところ失礼しました。\n      また改めてご連絡させてください」\n\n（以前より声が明るい）\n\n次の電話...\n店長:「間に合ってるよ」\n健太:「そうでしたか！ちなみに今お使いのサービスで\n      何かお困りのことはありますか？」\n店長:「...まあ、手数料が高いのは気になってるけど」\n健太:「！」", "duration": 45}, {"title": "シーン5: 初アポ獲得", "content": "健太:「実は弊社のワンプラは業界最安の手数料でして...\n      15分だけお話聞いていただけませんか？」\n店長:「...まあ、来週なら時間あるけど」\n健太:「ありがとうございます！来週の火曜日か木曜日、\n      どちらがご都合よろしいですか？」\n店長:「じゃあ火曜の午後で」\n健太:「ありがとうございます！火曜日の14時に伺います！」\n\n電話を切った後...\n健太:「よっしゃああああ！」", "duration": 30}, {"title": "シーン6: 先輩との振り返り", "content": "山本先輩:「どうだった？」\n健太:「47件です」\n山本先輩:「47件中1件アポ。約2%。上出来じゃん」\n健太:「はい！46回断られましたけど、\n      それが\"仕事\"ですからね」\n山本先輩:「（笑）いいね、その調子」\n\n画面に表示:\n「断られた数 = 成功への階段」", "duration": 15}]}', '{"title": "断られることの科学", "content": "テレアポ成功率の現実\n      \n97% 断られる\n3% 成功！", "audioText": "100件中3件アポが取れたら上出来。つまり、断られることは\"仕事\"なんです。", "highlight": "断られるのは「失敗」ではなく「進捗」"}', '[{"options": ["「自分のトークが悪かったんだ...」", "「タイミングが合わなかっただけ」"], "question": "断られた時の正しい考え方は？", "explanation": "断りは「今じゃない」のサイン。あなたの価値が否定されたわけではありません。", "correctIndex": 1}, {"options": ["大失敗。やり方を変えるべき", "正常。もう1件で成功の可能性あり"], "question": "100件テレアポして99件断られた。この結果は？", "explanation": "1〜3%がアポ獲得の相場。99件は「種まき」完了です。", "correctIndex": 1}]', '{"text": "I have not failed. I''ve just found 10,000 ways that won''t work.", "author": "トーマス・エジソン", "textJa": "私は失敗したことがない。うまくいかない1万通りの方法を見つけただけだ。"}', '[{"options": [{"text": "「すみません、失礼しました...」と電話を切る", "points": 0, "feedback": "店長は「忙しい」と言っただけで、「興味がない」とは言っていません。断られても、次のアクションに繋げましょう！", "isCorrect": false}, {"text": "「でも、本当にお得なんです！聞いてください！」", "points": 0, "feedback": "「でも」は相手を否定する言葉。「承知しました」から始めましょう。", "isCorrect": false}, {"text": "「承知しました。来週でしたらいつがご都合よろしいですか？」", "points": 30, "feedback": "断られても、次の日程を提案することでチャンスを繋げられます！", "isCorrect": true}, {"text": "「お忙しいところ失礼しました。資料だけお送りしてもよろしいですか？」", "points": 20, "feedback": "次に繋げた点は良いです。資料送付+再電話の約束ができればベストです。", "isCorrect": false}], "situation": "テレアポで「忙しいから」と断られました", "customerLine": "忙しいから、また今度にして"}, {"options": [{"text": "「そうですか...失礼しました」", "points": 0, "feedback": "チャンスを逃しています。課題を探る質問をしてみましょう。", "isCorrect": false}, {"text": "「ちなみに、今お使いのサービスで何かお困りの点はありますか？」", "points": 30, "feedback": "完璧です！課題を探る質問で、会話を続けられます。", "isCorrect": true}, {"text": "「でも弊社のサービスは他社より安いんです！」", "points": 0, "feedback": "「でも」で始めると相手を否定することになります。", "isCorrect": false}, {"text": "「わかりました。また3ヶ月後にご連絡します」", "points": 10, "feedback": "次に繋げる姿勢は良いですが、今できることを探りましょう。", "isCorrect": false}], "situation": "店長から「間に合ってるから」と言われました", "customerLine": "間に合ってるから"}]', '{"question": "今日の研修で一番印象に残ったことは？", "placeholder": "断られても落ち込まない。次に繋げることが大事"}', '["断られても「次のアクション」を必ず提案する", "断られた回数をカウントして「進捗」として捉える", "「承知しました」から切り返しを始める"]', NULL, NULL, '2026-01-21 17:48:08.427418+00', '2026-01-21 17:48:08.427418+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (44, 4, '目標設定の技術', '目標は"SMART"に設定せよ', '{"icon": "target", "name": "目標達成マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["30〜50%", "10〜20%", "1〜3%", "0.1%以下"], "question": "テレアポの一般的なアポ獲得率は？", "explanation": "97%断られるのが「普通」でしたね！", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 月初のミーティング", "content": "（会議室。鈴木課長、山本先輩、健太が座っている）\n\n鈴木課長:「さて、今月の目標を確認するぞ。\n         山本、お前の今月の目標は？」\n\n山本先輩:「はい。新規訪問20件、アポ5件、契約2件です。\n         内訳は、ワンプラ新規登録1件、\n         Symphony導入1件を狙います。\n         \n         週ごとに訪問5件、アポ1〜2件ペースで進めます。\n         第1週は〇〇エリア、第2週は△△エリアを重点的に」\n\n鈴木課長:「よし、具体的だな。健太は？」\n\n健太:「え、えっと...頑張ります！」\n\n鈴木課長:「...具体的には？」\n\n健太:「たくさん訪問して...契約を取ります！」\n\n鈴木課長:「たくさんって何件だ？契約は何件狙う？」\n\n健太:「えーと...できるだけ多く...」\n\n鈴木課長:「（ため息）それじゃ目標じゃない。願望だ」", "duration": 50}, {"title": "シーン2: 曖昧な目標の問題", "content": "（1ヶ月後。月末ミーティング）\n\n鈴木課長:「結果報告。山本は？」\n\n山本先輩:「新規訪問22件、アポ6件、契約2件。\n         目標達成です」\n\n鈴木課長:「素晴らしい。健太は？」\n\n健太:「えっと...訪問は...たぶん15件くらいで...\n      アポが...3件くらい？で、契約は...0件です」\n\n鈴木課長:「\"たぶん\"？\"くらい\"？\n         自分の数字も正確に把握してないのか？」\n\n健太:「す、すみません...」\n\n鈴木課長:「目標が曖昧だから、行動も曖昧になる。\n         結果、数字も曖昧になる。\n         山本の報告との違い、わかるか？」", "duration": 40}, {"title": "シーン3: 先輩との会話", "content": "（オフィスの隅で、山本先輩と健太）\n\n山本先輩:「健太、目標の立て方、教えようか」\n\n健太:「お願いします...\n      先輩はなんであんなに具体的に言えるんですか？」\n\n山本先輩:「SMARTの法則って知ってる？」\n\n健太:「スマート...？賢いってことですか？」\n\n山本先輩:「違う。目標を立てる時のフレームワークだよ。\n         5つの頭文字を取って\"SMART\"。\n         これを使えば、曖昧な目標が\n         達成できる目標に変わる」\n\n健太:「5つ...？」\n\n山本先輩:「Specific、Measurable、Achievable、\n         Relevant、Time-bound。\n         順番に説明するな」", "duration": 30}], "part2": [{"title": "シーン4: SMARTで目標を作る", "content": "山本先輩:「じゃあ、健太の来月の目標をSMARTで作ろう」\n\n健太:「はい！えっと...\n      S、具体的に...新規訪問と契約獲得...\n      M、測定可能...20件訪問、2件契約...」\n\n山本先輩:「いいね。A、達成可能は？」\n\n健太:「今月15件訪問できたから、\n      20件なら頑張れば届きそうです」\n\n山本先輩:「そう。簡単すぎず、無理すぎず。\n         ちょっと背伸びするくらいがいい」\n\n健太:「R、関連性...チームの目標が月10件契約だから、\n      僕が2件取れば20%貢献できます。\n      T、期限...来月末までに！」\n\n山本先輩:「完璧。これでSMARTな目標ができた」", "duration": 30}, {"title": "シーン5: 目標を週・日に分解", "content": "山本先輩:「でも、月の目標だけだと、まだ遠いだろ？\n         これを週と日に分解するんだ」\n\n【目標の分解】\n月間目標: 訪問20件、契約2件\n  ↓ 4週間で割る\n週間目標: 訪問5件、商談2件キープ\n  ↓ 5日間で割る\n日次目標: 訪問1件、テレアポ20件\n\n山本先輩:「月の目標を週に、週を日に分解する。\n         そうすれば、\"今日何をすればいいか\"が\n         明確になる」\n\n健太:「今日はテレアポ20件と訪問1件...\n      これなら何をすればいいかわかります！」", "duration": 30}, {"title": "シーン6: 目標管理の習慣", "content": "山本先輩:「あとは、毎日数字を記録すること。\n         今日何件電話した、何件訪問した、\n         アポ何件取れた...全部記録する」\n\n健太:「記録...」\n\n山本先輩:「記録すると、自分の現在地がわかる。\n         今週の目標に対して、進んでるのか遅れてるのか。\n         遅れてたら、残りの日で挽回できる。\n         \n         でも、記録しないと、月末になって\n         『あれ、全然足りない...』ってなる」\n\n健太:「先輩、毎日記録してるんですか？」\n\n山本先輩:「もちろん。目標を立てて、分解して、\n         毎日記録する...これが\"達成できる目標管理\"なんだ」", "duration": 30}]}', '{"title": "SMARTの法則", "content": "S - Specific（具体的に）\nM - Measurable（測定可能に）\nA - Achievable（達成可能に）\nR - Relevant（関連性を持たせて）\nT - Time-bound（期限を決めて）", "audioText": "この5つを満たせば、\"願望\"が\"目標\"に変わります。具体的、測定可能、達成可能、関連性、期限。覚えておきましょう。", "highlight": "曖昧な目標は、曖昧な結果しか生まない"}', '[{"options": ["Motivation（モチベーション）", "Measurable（測定可能）", "Maximum（最大）", "Monthly（月次）"], "question": "SMARTの「M」は何の略？", "explanation": "「数字で測れるか」がポイントです。", "correctIndex": 1}, {"options": ["「今月は営業を頑張る」", "「今年中に1000件契約を取る」", "「今月末までに新規訪問20件、契約2件」", "「できるだけ多く電話する」"], "question": "SMARTな目標はどれ？", "explanation": "Cだけが5要素を満たしています。", "correctIndex": 2}]', '{"text": "A goal without a plan is just a wish.", "author": "アントワーヌ・ド・サン＝テグジュペリ", "textJa": "計画のない目標は、ただの願望にすぎない。"}', '[{"options": [{"text": "S（具体性）が足りない", "points": 20, "feedback": "正解！「できるだけ多く」は曖昧です。数字を入れましょう。", "isCorrect": true}, {"text": "A（達成可能性）が足りない", "points": 0, "feedback": "達成可能性は、具体的な数字がないと判断できません。", "isCorrect": false}, {"text": "R（関連性）が足りない", "points": 0, "feedback": "関連性はこの文だけでは判断できません。", "isCorrect": false}, {"text": "問題ない", "points": 0, "feedback": "具体的な数字がなく、測定もできません。", "isCorrect": false}], "situation": "以下の目標、何が足りない？「今月、できるだけ多くの新規顧客を獲得する」", "customerLine": ""}, {"options": [{"text": "第1週に20件全部終わらせる", "points": 0, "feedback": "前半に集中すると品質が下がります。均等に分解しましょう。", "isCorrect": false}, {"text": "毎週5件ずつ訪問する", "points": 30, "feedback": "均等に分解することで、無理なく達成できます。", "isCorrect": true}, {"text": "第4週に追い込みで20件訪問", "points": 0, "feedback": "後半に追い込むと達成できないリスクが高まります。", "isCorrect": false}, {"text": "週ごとの目標は決めない", "points": 0, "feedback": "月の目標だけでは進捗管理ができません。", "isCorrect": false}], "situation": "月間目標「訪問20件」を達成するための週次目標は？（稼働4週間）", "customerLine": ""}]', '{"question": "「目標設定」で一番大切だと思ったことは？", "placeholder": "数字で測れるようにすること、週と日に分解すること"}', '["今日中に来月の目標をSMARTで設定する", "目標を週・日に分解してみる", "明日から毎日の活動を記録する"]', '{"title": "あなたの目標をSMARTに設定しよう", "fields": [{"label": "S（Specific）何を達成しますか？", "placeholder": "例: 新規訪問、テレアポ、契約獲得"}, {"label": "M（Measurable）数字で表すと？", "placeholder": "例: 訪問15件、テレアポ400件、契約1件"}, {"label": "A（Achievable）なぜ達成できそう？", "placeholder": "例: 今月10件訪問できたので、15件は+50%で挑戦可能"}, {"label": "R（Relevant）チーム目標との関係は？", "placeholder": "例: チーム目標5件のうち1件を担当"}, {"label": "T（Time-bound）いつまでに？", "placeholder": "例: 来月末（〇月〇日）まで"}], "description": "来月の目標を、SMARTの5要素で設定してください。"}', NULL, '2026-01-21 17:48:10.148004+00', '2026-01-21 17:48:10.148004+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (45, 5, '時間管理の基本', '緊急より重要を優先せよ', '{"icon": "clock", "name": "時間の魔術師"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Simple（シンプル）", "Specific（具体的）", "Strong（強い）", "Smart（賢い）"], "question": "SMARTの「S」は何の略？", "explanation": "目標は「具体的に」立てるんでしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 健太の1日", "content": "（朝9時。健太がデスクに着く）\n\n健太（心の声）:「よし、今日こそテレアポ頑張るぞ！」\n\n（電話が鳴る）\n健太:「はい、佐々木です」\n同僚:「健太、この資料コピーしといて」\n健太:「あ、はい」\n\n（コピー機へ。戻ってくる）\n\n（メールの通知）\n健太:「あ、メール返さなきゃ...」\n\n（メールを書いている間に）\n同僚:「健太、会議の準備手伝って」\n健太:「え、あ、はい」\n\n（会議の準備）\n\n（気づいたらお昼）\n健太:「あれ...もう12時？\n      テレアポ1件もしてない...」", "duration": 45}, {"title": "シーン2: 忙しいけど成果ゼロ", "content": "（夕方6時。疲れた表情の健太）\n\n健太（心の声）:「今日も1日が終わった...\n         朝から夜まで忙しかったのに、\n         テレアポは10件しかできなかった...\n         \n         なんでこんなに忙しいのに、\n         成果が出ないんだろう...」\n\n（山本先輩が声をかける）\n山本先輩:「健太、今日どうだった？」\n\n健太:「忙しかったです...でも、\n      テレアポ10件しかできなくて」\n\n山本先輩:「何に忙しかったの？」\n\n健太:「えーと、資料コピーとか、\n      メール返信とか、会議準備とか...」\n\n山本先輩:「なるほど。ちょっと聞いていい？\n         そのうち、\"成果に直結する仕事\"は\n         どれくらいあった？」\n\n健太:「成果に直結...？」", "duration": 35}, {"title": "シーン3: 気づき", "content": "山本先輩:「健太の目標は\"契約を取る\"こと。\n         契約を取るためには、テレアポや訪問が必要。\n         \n         でも今日やった仕事を見ると、\n         コピー、メール、会議準備...\n         どれも\"契約\"には直結しないよな」\n\n健太:「...確かに」\n\n山本先輩:「それは\"忙しい\"けど\"生産的\"じゃない。\n         時間を使ってるけど、成果には繋がらない」\n\n健太:「じゃあ、どうすれば...？」\n\n山本先輩:「\"緊急なこと\"と\"重要なこと\"を\n         区別するんだ。\n         アイゼンハワー・マトリクスって知ってる？」\n\n健太:「アイゼン...？」\n\n山本先輩:「時間管理のフレームワークだよ。\n         これを知ると、何に時間を使うべきか\n         明確になる」", "duration": 40}], "part2": [{"title": "シーン4: 4象限で整理", "content": "山本先輩:「じゃあ、今日の健太の仕事を\n         4象限に分類してみよう」\n\n【健太の今日の仕事】\n・資料コピー → 第3象限（依頼された）\n・メール返信 → 第3象限（緊急に見える）\n・会議準備 → 第3象限（急な依頼）\n・テレアポ → 第2象限（重要！）\n・SNSチェック → 第4象限（暇つぶし）\n\n山本先輩:「見てわかる通り、第3象限ばっかりだ。\n         唯一の第2象限であるテレアポは10件だけ」\n\n健太:「確かに...重要なことに時間を使えてない」", "duration": 35}, {"title": "シーン5: 第2象限を先に確保", "content": "山本先輩:「解決策は簡単。\n         \"第2象限の時間を先に確保\"するんだ」\n\n健太:「先に確保？」\n\n山本先輩:「朝一番に、テレアポの時間を2時間ブロック。\n         その時間は電話もメールも見ない。\n         会議も入れない。テレアポだけに集中する」\n\n健太:「でも、急な依頼が来たら...」\n\n山本先輩:「\"急ぎ\"に見えても、本当に急ぎか考えてみろ。\n         資料コピーは1時間後でも問題ない。\n         メールも2時間後に返しても大丈夫なことが多い。\n         \n         第3象限は\"緊急に見える\"だけで、\n         実は後でもいいことが多いんだ」", "duration": 35}, {"title": "シーン6: 健太の変化", "content": "（翌日の朝。健太がデスクに着く）\n\n健太:「よし、9時から11時はテレアポの時間。\n      電話もメールも後で対応しよう」\n\n（集中してテレアポする健太）\n\n（11時）\n健太:「よし、2時間で40件かけられた！\n      昨日の4倍だ」\n\n健太（心の声）:「緊急より重要を優先する...\n         第2象限を先に確保する...\n         これで時間の使い方が変わる！」", "duration": 20}]}', '{"title": "アイゼンハワー・マトリクス（時間管理の4象限）", "content": "第1象限: 緊急×重要 → 今すぐやる\n第2象限: 重要×緊急でない → 計画的にやる（最重要！）\n第3象限: 緊急×重要でない → 委任・後回し\n第4象限: 緊急でない×重要でない → やらない", "audioText": "第2象限（重要だが緊急でない仕事）に時間を使うことが、成果を出す秘訣です。", "highlight": "成果を出す人は「第2象限」に多くの時間を使っている"}', '[{"options": ["第1象限（緊急×重要）", "第2象限（重要×緊急でない）", "第3象限（緊急×重要でない）", "第4象限（緊急でない×重要でない）"], "question": "成果を出す人が最も時間を使う象限は？", "explanation": "第2象限を意識的に確保することが大切です。", "correctIndex": 1}, {"options": ["第1象限（緊急×重要）", "第2象限（重要×緊急でない）", "第3象限（緊急×重要でない）", "第4象限（緊急でない×重要でない）"], "question": "「新規開拓のテレアポ」はどの象限？", "explanation": "テレアポは成果に直結する「重要」な仕事。でも「今日やらなくても」という意味で緊急ではない。だから後回しにされやすいんです！", "correctIndex": 1}]', '{"text": "The key is not to prioritize what''s on your schedule, but to schedule your priorities.", "author": "スティーブン・コヴィー", "textJa": "重要なのは、スケジュールの優先順位をつけることではなく、優先事項をスケジュールに入れることだ。"}', '[{"options": [{"text": "A → B → C → D", "points": 10, "feedback": "クレーム対応（第1象限）は最優先です。", "isCorrect": false}, {"text": "C → A → B （Dはやらない）", "points": 30, "feedback": "C: 第1象限（重要×緊急）→ 最優先\nA: 第2象限（重要×緊急でない）→ 計画的に\nB: 第3象限 → 隙間時間で\nD: 第4象限 → やらない（または休憩時間に）", "isCorrect": true}, {"text": "D → A → C → B", "points": 0, "feedback": "第4象限（SNS）を最初にやるのは避けましょう。", "isCorrect": false}, {"text": "気分で決める", "points": 0, "feedback": "4象限で優先順位を決めましょう。", "isCorrect": false}], "situation": "朝9時。以下の4つのタスクがあります。どの順番でやりますか？\nA) 新規開拓のテレアポ（今週の目標達成に必要）\nB) 先輩から頼まれた資料コピー（急ぎではない）\nC) 昨日のクレーム客への謝罪電話（対応必須）\nD) SNSで業界ニュースをチェック（気になる）", "customerLine": ""}, {"options": [{"text": "「はい、すぐやります」とテレアポを中断", "points": 0, "feedback": "「急ぎ」と言われても、本当に急ぎか確認しましょう。", "isCorrect": false}, {"text": "「今テレアポ中なので、11時以降でもいいですか？」", "points": 30, "feedback": "自分の「第2象限」を守りつつ、相手にも配慮した対応ができます。", "isCorrect": true}, {"text": "「無理です」と断る", "points": 5, "feedback": "断り方が強すぎます。代替案を提示しましょう。", "isCorrect": false}, {"text": "無視する", "points": 0, "feedback": "コミュニケーションは大切です。", "isCorrect": false}], "situation": "テレアポに集中している時、同僚から「この資料をコピーして」と頼まれました。", "customerLine": "健太、この資料コピーしといて。急ぎで"}]', '{"question": "「時間管理」で一番大切だと思ったことは？", "placeholder": "第2象限の時間を先に確保すること"}', '["明日の朝、第2象限の時間を2時間ブロックする", "メールチェックを1日3回に減らす", "「急ぎの依頼」が来たら「本当に急ぎか」確認する"]', NULL, NULL, '2026-01-21 17:48:11.202377+00', '2026-01-21 17:48:11.202377+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (46, 6, '報連相のマスター', '結論→理由→詳細の順で', '{"icon": "megaphone", "name": "報連相の達人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["第1象限（緊急×重要）", "第2象限（重要×緊急でない）", "第3象限（緊急×重要でない）", "第4象限"], "question": "成果を出す人が最も時間を使う象限は？", "explanation": "第2象限を意識的に確保しましょう。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 商談後の報告", "content": "（オフィス。健太が鈴木課長のデスクへ）\n\n健太:「鈴木課長、オートショップ佐藤さんの\n      商談から戻りました」\n\n鈴木課長:「おう、どうだった？」\n\n健太:「えーと、今日は朝10時にお伺いして、\n      最初に名刺交換をして、\n      それから応接室に通されまして、\n      佐藤社長が『最近忙しくてね』と\n      おっしゃっていて、\n      それで在庫の話になって、\n      在庫が30台あるとおっしゃっていて、\n      でも回転が悪いみたいで、\n      それでワンプラの話をしたら\n      興味を持ってくれて、\n      でも今すぐは難しいとおっしゃっていて、\n      来月また検討したいと...」\n\n鈴木課長:「（イライラ）健太、結論は何だ？」\n\n健太:「え？えーと、来月また訪問します」\n\n鈴木課長:「それを最初に言え。\n         俺が知りたいのは\"結果\"だ」", "duration": 50}, {"title": "シーン2: 上司の本音", "content": "鈴木課長:「健太、報告の仕方を覚えろ。\n         上司は忙しいんだ。\n         経緯から聞きたいんじゃない。\n         \"結果\"と\"次のアクション\"を\n         まず知りたいんだ」\n\n健太:「結果と次のアクション...」\n\n鈴木課長:「お前の報告は、小説を読んでるみたいだ。\n         起承転結の\"結\"が最後に来る。\n         でも、仕事の報告は\"結\"を最初に持ってこい」\n\n健太:「結論が先...」\n\n鈴木課長:「そう。『アポ取れました』『失注しました』\n         『来月再訪問します』\n         まず結論。理由や詳細はその後だ」", "duration": 35}, {"title": "シーン3: 先輩に相談", "content": "（山本先輩に相談する健太）\n\n健太:「先輩、報告の仕方がダメだって言われました...」\n\n山本先輩:「ああ、\"結論から話す\"ってやつな。\n         PREP法って知ってる？」\n\n健太:「プレップ...？」\n\n山本先輩:「報告や説明をわかりやすくする\n         フレームワークだよ。\n         \n         Point（結論）\n         Reason（理由）\n         Example（具体例）\n         Point（結論の再強調）\n         \n         この順番で話すと、相手に伝わりやすくなる」\n\n健太:「結論を最初に...」\n\n山本先輩:「そう。上司は結論を聞いてから、\n         『なぜ？』と思ったら理由を聞く。\n         『詳しく』と思ったら詳細を聞く。\n         \n         最初から全部話す必要はないんだ」", "duration": 35}], "part2": [{"title": "シーン4: 報連相の違い", "content": "山本先輩:「ついでに、報連相の使い分けも教えておくな」\n\n健太:「報連相...報告、連絡、相談ですよね」\n\n山本先輩:「そう。でも、それぞれ目的が違う」\n\n【報連相の使い分け】\n\n報告（ホウ）: 過去の結果を伝える\n「〇〇の件、完了しました」\n\n連絡（レン）: 事実を共有する\n「〇〇の予定が変更になりました」\n\n相談（ソウ）: 判断を仰ぐ、意見を求める\n「〇〇の件、どう進めればいいですか？」\n\n山本先輩:「報告と連絡は\"事後\"、相談は\"事前\"。\n         ここを間違えると、\n         『なんで先に言わなかったんだ』ってなる」", "duration": 35}, {"title": "シーン5: 相談のタイミング", "content": "健太:「相談のタイミング...」\n\n山本先輩:「例えば、値引きの判断が必要な時。\n         自分で勝手に決めて、後から報告したら\n         怒られるだろ？」\n\n健太:「確かに...」\n\n山本先輩:「でも、値引き幅を決めてもらう\"相談\"を\n         事前にしておけば、スムーズに進む。\n         \n         困った時、迷った時は、\n         一人で抱え込まずに相談。\n         これが報連相の基本だ」", "duration": 25}, {"title": "シーン6: 健太の報告リベンジ", "content": "（翌日。健太が鈴木課長に報告）\n\n健太:「鈴木課長、オートプラザ田中の商談結果を\n      報告します」\n\n鈴木課長:「おう」\n\n健太:「結論から申し上げますと、\n      来週に契約の可能性が出てきました。\n      \n      理由としては、在庫回転の課題に\n      ワンプラがマッチしたからです。\n      \n      具体的には、現在の在庫40台のうち\n      10台を業販したいとのことで、\n      来週、詳細な見積もりを持っていく予定です」\n\n鈴木課長:「...いいじゃないか。\n         わかりやすいな」\n\n健太:「ありがとうございます！」", "duration": 30}]}', '{"title": "PREP法 — わかりやすく伝えるフレームワーク", "content": "P - Point（結論）「結果は△△でした」\nR - Reason（理由）「なぜなら□□だからです」\nE - Example（具体例）「具体的には◇◇ということが」\nP - Point（結論の再強調）「したがって△△です」", "audioText": "報告は結論から。上司が知りたいのは「結果」と「次のアクション」です。", "highlight": "結論→理由→詳細の順で伝える"}', '[{"options": ["Plan（計画）", "Point（結論）", "Problem（問題）", "Process（プロセス）"], "question": "PREP法の「P」は何の略？", "explanation": "最初と最後に「結論」を述べます。", "correctIndex": 1}, {"options": ["経緯（何があったか）", "理由（なぜそうなったか）", "結論（結果・次のアクション）", "感想（どう思ったか）"], "question": "報告の最初に言うべきことは？", "explanation": "上司がまず知りたいのは「結果」です。", "correctIndex": 2}]', '{"text": "The single biggest problem in communication is the illusion that it has taken place.", "author": "ジョージ・バーナード・ショー", "textJa": "コミュニケーションにおける最大の問題は、それが行われたという錯覚である。"}', '[{"options": [{"text": "「今日は朝から商談に行きまして、最初は良い雰囲気だったんですが、途中で競合の話が出てきて、価格で負けてしまいまして...失注しました」", "points": 10, "feedback": "経緯から始まっていて冗長です。結論を最初に言いましょう。", "isCorrect": false}, {"text": "「鈴木商事の件、失注しました。理由は価格です。競合より10%高かったようです。次回は価格面での事前調査を徹底します」", "points": 30, "feedback": "PREP法に沿った報告です！結論→理由→次のアクションが明確です。", "isCorrect": true}, {"text": "「鈴木商事の件ですが...ちょっと言いにくいのですが...あの、実は...失注してしまいまして...すみません」", "points": 5, "feedback": "結論がなかなか出てこないです。悪い報告ほど早く、端的に伝えましょう。", "isCorrect": false}, {"text": "「失注しました」（それだけ）", "points": 10, "feedback": "結論は言えていますが、情報が足りません。理由と次のアクションも伝えましょう。", "isCorrect": false}], "situation": "商談から戻って、課長に報告します。結果は「失注」でした。良い報告はどれ？", "customerLine": ""}, {"options": [{"text": "報告:「15%値引きしました」と事後報告", "points": 0, "feedback": "権限を超える判断を勝手にするのはNGです。事前に相談しましょう。", "isCorrect": false}, {"text": "連絡:「15%の値引き要請がありました」と情報共有", "points": 10, "feedback": "連絡だけでは判断が得られません。相談しましょう。", "isCorrect": false}, {"text": "相談:「15%の値引き要請があります。10%で対応するか、15%にするか、ご判断いただけますか？」", "points": 30, "feedback": "完璧です！権限を超える判断が必要な時は「相談」。選択肢を示すと上司も判断しやすくなります。", "isCorrect": true}, {"text": "何もしない（自分で判断する）", "points": 0, "feedback": "権限を超える判断は、必ず事前に相談しましょう。", "isCorrect": false}], "situation": "お客様から「15%値引きしてほしい」と言われました。通常の値引き権限は10%まで。上司に対して何をすべき？", "customerLine": ""}]', '{"question": "「報連相」で一番気をつけたいことは？", "placeholder": "結論から話す、悪い報告ほど早く"}', '["次の報告は「結論から」始める", "悪いことがあったら、すぐに報告する", "迷ったら、事前に上司に相談する"]', NULL, NULL, '2026-01-21 17:48:11.924962+00', '2026-01-21 17:48:11.924962+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (47, 7, '自己管理とモチベーション', 'モチベーションは"作る"もの', '{"icon": "battery", "name": "セルフマネジャー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["経緯", "理由", "結論", "詳細"], "question": "PREP法で最初に言うべきことは？", "explanation": "「結論→理由→詳細の順で」でしたね！", "correctIndex": 2}', '{"part1": [{"title": "シーン1: やる気が出ない月曜日", "content": "（月曜日の朝。健太のデスク）\n\n健太（心の声）:「はぁ...なんかやる気が出ない...\n         先週は契約0件だったし...\n         今週もダメなんじゃ...」\n\n（ぼんやりとパソコンを見つめる健太）\n\n山本先輩:「健太、どうした？」\n\n健太:「あ、先輩...なんか、やる気が出なくて...」\n\n山本先輩:「スランプか。営業してたら誰でもあるよ」\n\n健太:「先輩もありますか？」\n\n山本先輩:「もちろん。大事なのは、\n         そこからどう立ち直るかだ」", "duration": 40}, {"title": "シーン2: やる気は待っても来ない", "content": "山本先輩:「健太、やる気ってどうやって出る？」\n\n健太:「えっと...自然に出てくるのを待つ？」\n\n山本先輩:「それがよくある間違いなんだ。\n         やる気は\"待つ\"んじゃない。\n         \"作る\"んだ」\n\n健太:「作る...？」\n\n山本先輩:「\"作業興奮\"って知ってる？\n         脳科学の話なんだけど、\n         やる気は行動の\"後\"に来るんだ」\n\n【作業興奮の法則】\nやる気 → 行動 ❌\n行動 → やる気 ✅\n\n山本先輩:「まず5分だけ動いてみる。\n         そうすると、脳が興奮して\n         やる気が後からついてくる」", "duration": 40}, {"title": "シーン3: 5分だけスタート", "content": "山本先輩:「俺もやる気が出ない時は、\n         \"5分だけ\"って決めてスタートする」\n\n健太:「5分だけ？」\n\n山本先輩:「5分だけテレアポする、\n         5分だけメールを書く、\n         5分だけ資料を見る。\n         \n         で、5分経ったら続けるか決める。\n         不思議なことに、5分やると\n         もっとやりたくなるんだ」\n\n健太:「5分だけなら、できそう...」\n\n山本先輩:「それでいい。\n         モチベーションは\"作る\"もの。\n         行動が先、やる気は後。\n         これを覚えておいて」", "duration": 40}], "part2": [{"title": "シーン4: 小さな成功を記録する", "content": "山本先輩:「もう一つ、モチベーションを維持するコツがある」\n\n健太:「何ですか？」\n\n山本先輩:「小さな成功を記録すること」\n\n健太:「小さな成功？」\n\n山本先輩:「今日1件アポが取れた、\n         お客さんに『ありがとう』と言われた、\n         先輩に褒められた...\n         \n         そういう小さな成功を、\n         毎日ノートやアプリに書いておく」\n\n健太:「それが何に？」\n\n山本先輩:「落ち込んだ時に見返すと、\n         『俺、こんなにできてるじゃん』って\n         思えるんだ。\n         \n         自分の成長が可視化されると、\n         モチベーションが続く」", "duration": 35}, {"title": "シーン5: モチベーショントリガー", "content": "山本先輩:「あとは、自分の\"モチベーショントリガー\"を\n         知っておくといい」\n\n健太:「トリガー？」\n\n山本先輩:「やる気が出るきっかけのこと。\n         人によって違うんだ。\n         \n         音楽を聴く、\n         コーヒーを飲む、\n         散歩する、\n         好きな名言を読む...\n         \n         自分なりの\"やる気スイッチ\"を\n         見つけておくと、\n         スランプから抜け出しやすくなる」\n\n健太:「自分のやる気スイッチ...考えたことなかった」\n\n山本先輩:「今日から探してみろ。\n         何をしたらやる気が出るか、\n         意識してみて」", "duration": 35}, {"title": "シーン6: 健太の行動", "content": "（健太、5分だけテレアポを始める）\n\n健太:「5分だけ...5分だけ...」\n\n（5分後）\n\n健太:「あれ、もう5分経った。\n      でも、なんかもう少しできそう」\n\n（さらに続ける健太）\n\n（1時間後）\n\n健太:「20件かけられた...！\n      やる気、出てきた」\n\n健太（心の声）:「モチベーションは\"作る\"もの...\n         まず動く、やる気は後からついてくる...\n         これ、本当だ」", "duration": 20}]}', '{"title": "作業興奮の法則", "content": "やる気は待っても来ない\nまず5分だけ動く → やる気が後からついてくる", "audioText": "脳科学では、やる気は行動の後に来ることがわかっています。まず5分だけ動いてみましょう。", "highlight": "モチベーションは\"待つ\"のではなく\"作る\"もの"}', '[{"options": ["やる気が出るまで待つ", "まず5分だけ動いてみる"], "question": "やる気が出ない時、正しい対処法は？", "explanation": "作業興奮の法則：行動が先、やる気は後からついてきます。", "correctIndex": 1}, {"options": ["大きな成功だけを目指す", "小さな成功を記録して振り返る"], "question": "モチベーションを維持するために効果的なのは？", "explanation": "小さな成功を記録することで、自己効力感が高まります。", "correctIndex": 1}]', '{"text": "The secret of getting ahead is getting started.", "author": "マーク・トウェイン", "textJa": "先に進む秘訣は、まず始めることだ。"}', '[{"options": [{"text": "やる気が出るまでSNSを見て待つ", "points": 0, "feedback": "やる気は待っても来ません。まず動きましょう。", "isCorrect": false}, {"text": "「5分だけ」と決めて、テレアポリストを開く", "points": 30, "feedback": "「作業興奮の法則」を思い出してください。まず5分だけ動く → やる気が後からついてきます。", "isCorrect": true}, {"text": "コーヒーを3杯飲んでカフェインでテンションを上げる", "points": 5, "feedback": "一時的な効果はありますが、根本的な解決にはなりません。", "isCorrect": false}, {"text": "同僚に愚痴を言って発散する", "points": 5, "feedback": "発散も大事ですが、行動に繋げましょう。", "isCorrect": false}], "situation": "月曜日の朝。先週は契約0件でした。今日もやる気が出ません。まず何をしますか？", "customerLine": ""}, {"options": [{"text": "今日は調子が悪いので、明日に回す", "points": 0, "feedback": "一度止めると、また始めるのが大変になります。", "isCorrect": false}, {"text": "「断られるのは進捗」と思い出し、あと5件だけやる", "points": 30, "feedback": "研修No.3を思い出してください！小さな目標を設定して乗り越えましょう。", "isCorrect": true}, {"text": "上司に「今日は無理です」と相談する", "points": 5, "feedback": "5件で諦めるのは早いです。もう少し粘りましょう。", "isCorrect": false}, {"text": "気分転換に30分散歩する", "points": 10, "feedback": "気分転換も大事ですが、5件で長い休憩は避けましょう。", "isCorrect": false}], "situation": "テレアポを始めましたが、5件連続で断られました。どう対処しますか？", "customerLine": ""}]', '{"question": "やる気が出ない時、あなたはどうしますか？", "placeholder": "5分だけテレアポリストを開く、まず1件だけ電話する"}', '["やる気が出ない時は「5分だけ」と決めてスタートする", "毎日の小さな成功をメモする", "自分なりの「やる気スイッチ」を見つける"]', '{"title": "自分のモチベーショントリガーを発見しよう", "fields": [{"label": "どんな時にやる気が出る？", "placeholder": "例: 朝コーヒーを飲んだ時、音楽を聴いている時"}, {"label": "5分でできる「スタートアクション」は？", "placeholder": "例: まずテレアポリストを開くだけ、まず1件だけ電話する"}, {"label": "落ち込んだ時に思い出したい成功体験は？", "placeholder": "例: 初めてアポが取れた時、お客様に感謝された時"}], "description": "やる気が出ない時に効果的な行動を見つけましょう。"}', NULL, '2026-01-21 17:48:12.829897+00', '2026-01-21 17:48:12.829897+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (48, 8, '失敗から学ぶ姿勢', '失敗は"授業料"、学べば元が取れる', '{"icon": "flame", "name": "不死鳥"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["やる気が出るまで待つ", "まず5分だけ動いてみる"], "question": "やる気が出ない時、正しい対処法は？", "explanation": "「モチベーションは作るもの」でしたね！", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 大型案件の獲得チャンス", "content": "鈴木課長:「健太、オートモール鈴木から問い合わせがあった。\n         在庫100台以上の大型店だ。\n         お前に担当させる」\n\n健太:「100台！？ありがとうございます！」\n\n健太（心の声）:「これは大チャンスだ！\n         成約したら、今月の目標一気に達成できる！」", "duration": 30}, {"title": "シーン2: 提案当日", "content": "（オートモール鈴木の会議室。鈴木専務と担当者が2名）\n\n健太:「本日はお時間いただきありがとうございます。\n      早速ですが、弊社のSymphonyについてご説明します」\n\n（資料を配り、説明を始める健太）\n\n健太:「Symphonyは在庫管理から顧客管理まで一元化できまして...\n      ワンプラでは業販も可能です...\n      手数料はレギュラー15,000円、プラチナ10,000円...」\n\n（30分間、一方的に説明する健太）\n\n鈴木専務:「...なるほど」（表情が硬い）\n\n健太:「いかがでしょうか？」\n\n鈴木専務:「検討して、また連絡します」", "duration": 40}, {"title": "シーン3: 失注の連絡", "content": "（1週間後。電話が鳴る）\n\n健太:「はい、佐々木です」\n\n担当者:「オートモール鈴木の田中です。\n       先日の件ですが、今回は見送らせていただきます」\n\n健太:「え...？なぜでしょうか...？」\n\n担当者:「他社さんの方が、うちの課題に合っている提案でしたので」\n\n健太:「そ、そうですか...ありがとうございました...」\n\n（電話を切る。呆然とする健太）\n\n健太（心の声）:「なんで...あんなに準備したのに...\n         うちの課題に合っている提案...？\n         俺、何がダメだったんだ...」", "duration": 35}], "part2": [{"title": "シーン4: KPTで振り返り", "content": "山本先輩:「じゃあ、KPTで振り返ろう。\n         まず、K。良かったことは？」\n\n健太:「えっと...資料は準備できてました。\n      時間通りに到着もできました」\n\n山本先輩:「OK。じゃあP、問題点は？」\n\n健太:「...課題を聞かずに、説明を始めてしまいました。\n      研修No.1で学んだのに...」\n\n山本先輩:「大型案件だからって、張り切りすぎたな」\n\n健太:「はい...」\n\n山本先輩:「じゃあT。次に試すことは？」\n\n健太:「次は、最初に必ずヒアリングをします。\n      課題を聞いてから、それに合った提案をします」\n\n山本先輩:「いいね。それが\"学び\"だ」", "duration": 40}, {"title": "シーン5: 失敗は授業料", "content": "山本先輩:「健太、失敗は\"授業料\"だと思え」\n\n健太:「授業料...？」\n\n山本先輩:「高い学費を払って、貴重な経験をした。\n         今回学んだことを次に活かせば、元が取れる。\n         \n         でも、何も学ばなかったら、\n         ただの損失で終わる。\n         \n         大事なのは、失敗しないことじゃない。\n         失敗から\"学ぶ\"ことだ」\n\n健太:「失敗は授業料...学べば元が取れる...」", "duration": 30}, {"title": "シーン6: 次の大型案件へ", "content": "（1ヶ月後。健太が新しい大型案件に臨む）\n\n健太:「本日はお時間いただきありがとうございます。\n      早速ですが、御社のことを教えていただけますか？\n      今、どのような課題をお持ちですか？」\n\n顧客:「実は、在庫の回転率が...」\n\n健太（心の声）:「今度は、ちゃんと聞く。\n         あの失敗が、今に活きてる——」\n\nナレーション:「失敗から学んだ健太。\n         同じ失敗は、二度としなかった」", "duration": 20}]}', '{"title": "失敗への2つのアプローチ", "content": "成長しない人:\n失敗 → 落ち込む → 忘れようとする → 同じ失敗を繰り返す\n\n成長する人:\n失敗 → 振り返る → 学びを抽出 → 次に活かす → 成長", "audioText": "失敗は授業料です。学べば元が取れます。大事なのは、失敗しないことじゃない。失敗から学ぶことです。", "highlight": "失敗そのものより「失敗から何も学ばない」方が問題"}', '[{"options": ["忘れようとする", "振り返って学びを抽出する"], "question": "失敗した時の正しい対処法は？", "explanation": "失敗から学ぶことで、同じ失敗を繰り返さなくなります。", "correctIndex": 1}, {"options": ["Key（鍵）", "Keep（続けること）", "Know（知る）", "Kind（種類）"], "question": "KPTの「K」は何の略？", "explanation": "K=Keep（続けること）、P=Problem（問題点）、T=Try（次に試すこと）です。", "correctIndex": 1}]', '{"text": "Success is not final, failure is not fatal: it is the courage to continue that counts.", "author": "ウィンストン・チャーチル", "textJa": "成功は終わりではなく、失敗は致命的ではない。大切なのは、続ける勇気だ。"}', '[{"options": [{"text": "落ち込んで、しばらく休む", "points": 0, "feedback": "落ち込む気持ちはわかりますが、学びを抽出しないともったいないです。", "isCorrect": false}, {"text": "「運が悪かった」と考えて、次に行く", "points": 5, "feedback": "他責にすると、同じ失敗を繰り返します。自分の行動を振り返りましょう。", "isCorrect": false}, {"text": "KPTで振り返り、次に活かす学びを抽出する", "points": 30, "feedback": "失敗は授業料。学べば元が取れます。振り返りから学びを得ましょう。", "isCorrect": true}, {"text": "上司に謝罪だけして、終わりにする", "points": 10, "feedback": "報告は大事ですが、自分なりの振り返りもしましょう。", "isCorrect": false}], "situation": "大型案件を失注しました。次にどうしますか？", "customerLine": ""}]', '{"question": "最近の失敗から、どんな学びを得ましたか？", "placeholder": "例: 顧客の課題を聞かずに説明を始めてしまった → 次は必ずヒアリングから"}', '["失敗したら必ずKPTで振り返る", "「失敗は授業料」と考えて、学びを抽出する", "同じ失敗を繰り返さないよう、学びをメモする"]', '{"title": "あなたの失敗をKPTで振り返ろう", "fields": [{"label": "何があった？（簡潔に）", "placeholder": "例: テレアポで100件かけてアポ0件だった"}, {"label": "K - Keep（良かったこと）", "placeholder": "例: 100件という行動量は確保できた"}, {"label": "P - Problem（問題点）", "placeholder": "例: トークが一方的だった、切り返しができなかった"}, {"label": "T - Try（次に試すこと）", "placeholder": "例: 切り返しのパターンを3つ用意しておく"}], "description": "最近の「うまくいかなかった経験」を振り返りましょう。"}', NULL, '2026-01-21 17:48:13.478956+00', '2026-01-21 17:48:13.478956+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (58, 30, '中古車業界の法規制', '知らなかったでは済まされない', '{"icon": "scale", "name": "コンプライアンスマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["整備・車検", "保険手数料", "車両販売粗利", "ローン手数料"], "question": "中古車販売店の収益で最も大きい割合は？", "explanation": "車両販売粗利が約70%を占めます。整備・車検は約20%です。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 古物営業法", "content": "山本先輩:「健太、法規制の話をしよう。\n\"知らなかった\"では済まされない話だ」\n\n健太:「法規制ですか」\n\n山本先輩:「中古車は\"古物\"に該当する。\nだから、古物営業法の規制を受ける」\n\n【古物営業法】\n目的: 盗品の流通防止、被害の迅速な回復\n\n古物商許可が必要:\n・都道府県公安委員会への届出\n・許可なく営業すると「3年以下の懲役または100万円以下の罰金」\n\n古物商の義務:\n①本人確認義務: 買取時に運転免許等で確認\n②取引記録義務: 古物台帳への記録（3年間保存）\n③不正品申告義務: 盗品の疑いがあれば警察に届出", "duration": 45}, {"title": "シーン2: 自動車登録制度", "content": "山本先輩:「次に自動車登録制度だ」\n\n【主な登録種類】\n\n①新規登録: 新車を初めて登録\n\n②移転登録（名義変更）★重要★\n所有者が変わった時（売買時）\n→ 15日以内に手続きが必要\n\n③変更登録: 住所変更、使用者変更等\n\n④抹消登録: 廃車、一時抹消\n\n【名義変更に必要な書類】\n・車検証\n・印鑑証明書（売主・買主）\n・譲渡証明書\n・委任状\n・車庫証明（使用の本拠が変わる場合）", "duration": 40}, {"title": "シーン3: 車庫証明", "content": "山本先輩:「車庫証明も覚えておけ」\n\n【車庫証明（自動車保管場所証明書）】\n\n条件:\n・使用の本拠から直線距離2km以内\n・道路以外の場所であること\n・車両の全体を収容できること\n・出入りに支障がないこと\n\n取得日数: 通常3〜5営業日\n\n💡 軽自動車は「届出」で証明書は不要（一部地域を除く）\n\n山本先輩:「納車までのスケジュールに影響するから、\n営業も知っておく必要がある」", "duration": 35}], "part2": [{"title": "シーン4: その他の関連法規制", "content": "山本先輩:「他にも関連する法律がある」\n\n【その他の関連法規制】\n\n①自動車リサイクル法\n使用済み自動車の適正処理義務\n\n②景品表示法\n不当な価格表示・おとり広告の禁止\n\n③消費者契約法\n重要事項の不実告知は契約取消可能\n\n④自動車公正競争規約\n中古車の表示に関する業界自主ルール\n\n⑤個人情報保護法\n顧客情報の適切な管理義務\n\n山本先輩:「販売店はこれだけの法規制の中で営業してる」", "duration": 40}, {"title": "シーン5: 営業としての心構え", "content": "健太:「複雑ですね...」\n\n山本先輩:「法律の専門家になる必要はない。\nでも、基本は知っておくべきだ」\n\n【営業として押さえておくべきポイント】\n\n①古物商許可は必須\n「許可証は掲示されてますか？」と確認できる\n\n②名義変更は15日以内\n納車スケジュールに影響\n\n③顧客情報の管理は重要\nSymphony導入のメリットにもなる\n\n山本先輩:「法規制を理解していると、\n顧客との会話の幅が広がる。\n\"この営業はわかってる\"と思ってもらえる」", "duration": 35}, {"title": "シーン6: 健太の理解", "content": "健太（心の声）:「知らなかったでは済まされない...\n\n古物営業法、自動車登録制度、車庫証明...\n販売店は多くの法規制の中で営業している。\n\nこの知識があれば、顧客の業務理解が深まる。\nそして、Symphonyの価値も伝えやすくなる」\n\n【今日の学び】\n・中古車販売には古物商許可が必須\n・名義変更は売買後15日以内\n・車庫証明は使用本拠から2km以内\n・法規制の基本知識は信頼構築に役立つ", "duration": 30}]}', '{"title": "中古車業界の主要法規制", "content": "【古物営業法】\n・古物商許可が必須\n・本人確認、取引記録の義務\n・違反: 3年以下の懲役または100万円以下の罰金\n\n【自動車登録】\n・移転登録は15日以内\n・車庫証明は2km以内\n\n【その他】\n景品表示法、消費者契約法、個人情報保護法 等", "audioText": "知らなかったでは済まされません。法規制の基本を押さえ、顧客との会話の幅を広げましょう。", "highlight": "法規制の基本を知っていると「業界をわかってる営業」になれる"}', '[{"options": ["掲載料金体系が大きく異なる", "対象エリアのカバー範囲が違う", "運営母体と歴史的背景が異なる", "掲載できる車種に制限がある"], "question": "カーセンサーとグーネットの特徴の違いとして正しいのはどれですか？", "explanation": "カーセンサーはリクルート系、グーネットはプロトコーポレーション系と運営母体が異なります。", "correctIndex": 2}, {"options": ["掲載台数を増やすこと", "写真の質と枚数を充実させる", "価格を競合より安く設定する", "更新頻度を高く維持する"], "question": "中古車ポータルサイトでの集客において最も重要なのはどれですか？", "explanation": "ユーザーは写真で車両状態を判断するため、写真の質と枚数が問い合わせ数に直結します。", "correctIndex": 1}, {"options": ["月間のページビュー数", "問い合わせ1件あたりの掲載コスト", "掲載車両の在庫日数", "サイト経由の来店率"], "question": "ポータルサイト掲載の費用対効果を測る指標として適切なのはどれですか？", "explanation": "問い合わせ獲得コスト（CPA）は掲載の費用対効果を測る基本的な指標です。", "correctIndex": 1}]', '{"text": "Compliance is not a constraint, it''s a foundation.", "author": "ビジネス格言", "textJa": "コンプライアンスは制約ではなく、基盤である。"}', '[{"options": [{"text": "何も言わずに商談を進める", "points": 0, "feedback": "コンプライアンス上の問題を見過ごしています。", "isCorrect": false}, {"text": "「古物商許可証の掲示は義務なので、確認された方がいいですよ」とさりげなく伝える", "points": 30, "feedback": "顧客のためになる情報提供です。信頼構築につながります。", "isCorrect": true}, {"text": "「違法ですね」と指摘する", "points": 10, "feedback": "正しいですが、伝え方が攻撃的です。", "isCorrect": false}, {"text": "警察に通報する", "points": 0, "feedback": "まずは顧客に確認を促すべきです。", "isCorrect": false}], "situation": "販売店訪問時、古物商許可証が掲示されていないことに気づきました。", "customerLine": ""}]', '{"question": "法規制の知識をどう営業に活かしますか？", "placeholder": "例: 顧客管理の重要性を伝える際に個人情報保護法に触れる"}', '["古物営業法の基本を覚える", "名義変更の流れを説明できるようにする", "法規制対応をSymphonyのメリットとして伝える"]', NULL, NULL, '2026-01-21 17:48:22.182034+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (49, 9, '顧客視点の習慣化', '顧客の靴を履いて歩け', '{"icon": "eye", "name": "顧客目線"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Point（ポイント）", "Problem（問題点）", "Plan（計画）", "Progress（進捗）"], "question": "KPTの「P」は何の略？", "explanation": "P=Problem（問題点）。失敗を振り返る時に使いましょう。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 提案資料作成", "content": "（健太がPCで資料を作成している）\n\n健太（心の声）:「よし、今度の提案は完璧だ！\n         Symphonyの全機能を網羅した資料...\n         これだけ詳しく書けば、絶対に伝わるはず！」\n\n（30ページの分厚い資料）\n\n山本先輩:「健太、何作ってるの？」\n\n健太:「明日の商談用の資料です。\n      Symphonyの機能を全部説明しようと思って」\n\n山本先輩:「30ページ？全機能？」\n\n健太:「はい！詳しい方がいいかと」\n\n山本先輩:「...ちょっと見せて」", "duration": 35}, {"title": "シーン2: 先輩のダメ出し", "content": "山本先輩:「（資料をめくりながら）在庫管理機能...\n         顧客管理機能...帳票出力機能...\n         健太、これ誰のための資料？」\n\n健太:「明日のお客様、山田モータースさんです」\n\n山本先輩:「山田モータースさんの課題は何だった？」\n\n健太:「えっと...ネット掲載の更新が追いつかない、と」\n\n山本先輩:「じゃあ、この帳票出力機能のページ、要る？」\n\n健太:「え...」\n\n山本先輩:「この顧客管理の5ページも、要る？」\n\n健太:「...要らない、かも」\n\n山本先輩:「この資料は\"健太が話したいこと\"であって、\n         \"お客様が知りたいこと\"じゃないんだよ」", "duration": 40}, {"title": "シーン3: 顧客視点の欠如", "content": "健太:「お客様が知りたいこと...」\n\n山本先輩:「健太、\"顧客の靴を履いて歩け\"って言葉知ってる？」\n\n健太:「顧客の靴...？」\n\n山本先輩:「相手の立場に立って考えるってこと。\n         \n         山田モータースの山田社長は、\n         毎日何に困ってる？\n         何を解決したい？\n         何があったら嬉しい？\n         \n         それを想像してから資料を作ってる？」\n\n健太:「...正直、自分が説明しやすいように作ってました」\n\n山本先輩:「だろうね。それが\"自分視点\"の罠だよ」", "duration": 35}], "part2": [{"title": "シーン4: 顧客の1日を想像する", "content": "山本先輩:「じゃあ、山田社長の1日を想像してみよう。\n         朝、何をしてる？」\n\n健太:「えっと...店を開けて...来店客対応？」\n\n山本先輩:「うん。その合間に何してる？」\n\n健太:「在庫のチェック...ネット掲載の更新...\n      でも、更新が追いつかないって言ってたから、\n      きっと焦ってる...」\n\n山本先輩:「そう。夜は？」\n\n健太:「また更新作業...でも疲れてて進まない...\n      『なんでこんなに大変なんだ』って思ってるかも」\n\n山本先輩:「いいね。その山田社長に、\n         \"30ページの全機能資料\"を見せたら？」\n\n健太:「...読む気にならない。\n      『また仕事が増える』と思うかも」\n\n山本先輩:「だろ？じゃあ、どんな資料だったら嬉しい？」\n\n健太:「...『ネット更新がこれだけ楽になります』って\n      1枚でわかる資料？」\n\n山本先輩:「それが\"顧客視点\"だよ」", "duration": 50}, {"title": "シーン5: 資料の作り直し", "content": "（健太が資料を作り直している）\n\n健太（心の声）:「山田社長の困りごとは、ネット更新が追いつかないこと。\n         知りたいのは、それがどう解決されるか。\n         \n         ...よし、ここにフォーカスしよう」\n\n（新しい資料: 5ページ、ネット更新効率化に特化）", "duration": 20}, {"title": "シーン6: 商談の結果", "content": "（商談後）\n\n山田社長:「これ、まさにうちが欲しかったやつだよ。\n         ネット更新、こんなに楽になるの？」\n\n健太:「はい。スマホで撮るだけで掲載完了です」\n\n山田社長:「いいね。前向きに検討するよ」\n\n健太（心の声）:「顧客の靴を履いて歩く...\n         相手の立場で考えると、響き方が全然違う」", "duration": 20}]}', '{"title": "自分視点 vs 顧客視点", "content": "自分視点:\n「この機能を説明したい」→ 相手に響かない\n\n顧客視点:\n「お客様は何に困っている？」→ 響く提案になる", "audioText": "自分が話したいことではなく、顧客が知りたいことを伝えましょう。顧客の立場に立って考えることが大切です。", "highlight": "顧客の靴を履いて歩け"}', '[{"options": ["自分が説明したい機能", "顧客が解決したい課題"], "question": "提案資料を作る時、最初に考えるべきことは？", "explanation": "顧客視点で考えましょう。顧客が知りたいことを伝えることが大切です。", "correctIndex": 1}, {"options": ["顧客と同じ靴を買う", "顧客の立場に立って考える"], "question": "「顧客の靴を履いて歩く」とはどういう意味？", "explanation": "顧客の視点で物事を見る、という意味です。", "correctIndex": 1}]', '{"text": "Walk a mile in someone else''s shoes before you criticize them.", "author": "ネイティブアメリカンのことわざ", "textJa": "批判する前に、相手の靴を履いて1マイル歩け。"}', '[{"options": [{"text": "商品の全機能を網羅した30ページの資料を作る", "points": 0, "feedback": "自分視点になっています。顧客の課題にフォーカスしましょう。", "isCorrect": false}, {"text": "顧客の課題に合った機能だけを5ページでまとめる", "points": 30, "feedback": "顧客視点です！顧客が知りたいことにフォーカスしています。", "isCorrect": true}, {"text": "価格の安さだけをアピールする資料を作る", "points": 5, "feedback": "価格だけでなく、課題解決を伝えましょう。", "isCorrect": false}, {"text": "競合他社の悪口を書いた資料を作る", "points": 0, "feedback": "ネガティブな内容は避けましょう。", "isCorrect": false}], "situation": "提案資料を作る時、どうしますか？", "customerLine": ""}]', '{"question": "明日から「顧客視点」を意識するために、何をしますか？", "placeholder": "提案前に顧客の1日を想像する、顧客の課題にフォーカスした資料を作る"}', '["提案前に「顧客の1日」を想像する", "資料は「顧客の課題」にフォーカスする", "「自分が話したいこと」ではなく「顧客が知りたいこと」を考える"]', '{"title": "顧客の1日を想像しよう", "fields": [{"label": "顧客名（仮名OK）", "placeholder": "例: 山田モータース"}, {"label": "朝（開店〜午前中）何をしている？何に困っている？", "placeholder": "例: 店を開けて、昨日の問い合わせ確認。来店客対応しながら、電話も取る。忙しい。"}, {"label": "昼（午後）何をしている？何を考えている？", "placeholder": "例: 来店客対応がピーク。事務作業は後回し。「今月の売上、大丈夫かな」と心配。"}, {"label": "夜（閉店後）何をしている？何を願っている？", "placeholder": "例: 溜まった事務作業。ネット更新もしないと。「もっと効率化できないかな」と思う。"}, {"label": "この顧客に提案するなら、何を伝えるべき？", "placeholder": "例: ネット更新の手間を減らせること"}], "description": "あなたがアプローチしている顧客の1日を想像してみましょう。"}', NULL, '2026-01-21 17:48:14.208359+00', '2026-01-21 17:48:14.208359+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (50, 10, '継続的学習のマインド', '学びを止めた時、成長が止まる', '{"icon": "book", "name": "学びの求道者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["顧客と同じ靴を買う", "顧客の立場に立って考える"], "question": "「顧客の靴を履いて歩く」とはどういう意味？", "explanation": "顧客視点で考えることが大切でしたね！", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 先輩の本棚", "content": "（山本先輩のデスク。本が山積み）\n\n健太:「先輩、この本全部読んだんですか？」\n\n山本先輩:「まあ、だいたいね」\n\n健太:「すごい...営業の本、交渉術、心理学...\n      先輩もうトップ営業なのに、まだ勉強してるんですか？」\n\n山本先輩:「むしろ、トップでい続けるために勉強してるんだよ」\n\n健太:「え？」\n\n山本先輩:「営業って、ゴールがないんだ。\n         お客様も変わる、市場も変わる、競合も変わる。\n         昨日の正解が、今日の正解とは限らない。\n         \n         だから、学び続けないと、すぐに追い抜かれる」", "duration": 40}, {"title": "シーン2: かつての山本先輩", "content": "山本先輩:「俺さ、5年前、一度スランプになったことがあるんだ」\n\n健太:「先輩がですか？」\n\n山本先輩:「3年目くらいで、そこそこ売れるようになった。\n         で、調子に乗って、勉強するのをやめた。\n         \n         『もう十分だろ』って。\n         \n         そしたら半年後、後輩に抜かれた。\n         新しい手法を取り入れた後輩にね」\n\n健太:「...」\n\n山本先輩:「その時に気づいたんだ。\n         \"学びを止めた時、成長が止まる\"って。\n         \n         それ以来、毎日30分は本を読むようにしてる。\n         週末はセミナーに行くこともある。\n         \n         学び続けることが、成長し続ける唯一の方法だから」", "duration": 45}, {"title": "シーン3: 健太の気づき", "content": "健太:「学びを止めた時、成長が止まる...」\n\n山本先輩:「健太、この3ヶ月でだいぶ成長したと思う。\n         でも、これがゴールじゃない。\n         \n         むしろ、ここからがスタートだ。\n         \n         今日学んだことを、明日の自分に活かす。\n         それを毎日続ける。\n         その積み重ねが、1年後、3年後の差になる」\n\n健太:「はい...先輩、俺、もっと勉強します」\n\n山本先輩:「いいね。で、何を学ぶ？」\n\n健太:「え、えっと...」\n\n山本先輩:「目標がないと学びも散漫になる。\n         次に何を身につけたいか、決めておこう」", "duration": 35}], "part2": [{"title": "シーン4: 継続的学習の3つの方法", "content": "山本先輩:「学び続けるには、3つの方法がある」\n\n【継続的学習の3つの方法】\n\n1. インプット（知識を入れる）\n   ・本を読む\n   ・セミナーに参加する\n   ・先輩の商談に同行する\n\n2. アウトプット（知識を出す）\n   ・学んだことを実践する\n   ・人に教える\n   ・自分の言葉で記録する\n\n3. フィードバック（振り返る）\n   ・うまくいったこと、いかなかったことを分析\n   ・上司・先輩にアドバイスをもらう\n   ・次の学習テーマを決める\n\n山本先輩:「インプット→アウトプット→フィードバック\n         このサイクルを回し続けることが大事だ」", "duration": 40}, {"title": "シーン5: 成長曲線", "content": "山本先輩:「成長曲線を見せてやろう」\n\n【成長曲線】\n学び続ける人: 時間と共に成長が加速\n学びを止めた人: ある地点で成長が止まる\n\n山本先輩:「最初は同じでも、3年後には大きな差になる。\n         毎日少しずつでも学び続ける人と、\n         途中で止める人では、\n         結果が全然違ってくるんだ」\n\n健太:「毎日少しずつ...」\n\n山本先輩:「1日15分でもいい。\n         通勤時間に本を読む、\n         昼休みにニュースをチェックする...\n         継続することが大事だ」", "duration": 30}, {"title": "シーン6: 学習計画", "content": "山本先輩:「じゃあ、健太の学習計画を立てよう。\n         次に身につけたいスキルは？」\n\n健太:「テレアポのスキルをもっと上げたいです。\n      切り返しのパターンを増やしたい」\n\n山本先輩:「いいね。どうやって学ぶ？」\n\n健太:「先輩のテレアポを聞かせてもらいたいです。\n      あと、テレアポの本を1冊読みます」\n\n山本先輩:「毎日どれくらい時間を使える？」\n\n健太:「通勤時間に30分くらい...」\n\n山本先輩:「十分だ。1ヶ月後の目標は？」\n\n健太:「切り返しパターンを10個覚えて、\n      アポ率を今の2倍にします！」\n\n山本先輩:「いい目標だ。頑張れ、健太」", "duration": 30}]}', '{"title": "成長曲線と学習の関係", "content": "学び続ける人: 成長が加速\n学びを止めた人: 成長が止まる\n\n最初は同じでも、3年後には大きな差に", "audioText": "営業にゴールはありません。学び続けることが、成長し続ける唯一の方法です。", "highlight": "学びを止めた時、成長が止まる"}', '[{"options": ["ある程度のところで満足する", "学び続けること"], "question": "成長し続けるために必要なことは？", "explanation": "学びを止めた時、成長が止まります。継続的に学び続けましょう。", "correctIndex": 1}, {"options": ["インプット→休憩→インプット", "インプット→アウトプット→フィードバック"], "question": "継続的学習の3ステップは？", "explanation": "知識を入れて、実践して、振り返る。このサイクルを回しましょう。", "correctIndex": 1}]', '{"text": "Live as if you were to die tomorrow. Learn as if you were to live forever.", "author": "マハトマ・ガンジー", "textJa": "明日死ぬかのように生きよ。永遠に生きるかのように学べ。"}', '[{"options": [{"text": "もう十分だから、勉強はやめる", "points": 0, "feedback": "学びを止めた時、成長が止まります。後輩に追い抜かれる可能性も...", "isCorrect": false}, {"text": "さらに上を目指して、学び続ける", "points": 30, "feedback": "トップでい続けるために学ぶ。山本先輩のように成長し続けましょう。", "isCorrect": true}, {"text": "今のやり方を変えない", "points": 5, "feedback": "市場も顧客も変わります。学び続けないと取り残されます。", "isCorrect": false}, {"text": "他の仕事に興味を持つ", "points": 5, "feedback": "まずは今の仕事を極めましょう。", "isCorrect": false}], "situation": "仕事に慣れてきて、そこそこ売れるようになりました。次にどうしますか？", "customerLine": ""}]', '{"question": "これから何を学び続けますか？", "placeholder": "テレアポのスキル、商談スキル、業界知識..."}', '["毎日15分、本やニュースで学ぶ時間を作る", "先輩の商談に同行させてもらう", "学んだことを実践し、振り返る習慣をつける"]', '{"title": "あなたの学習計画", "fields": [{"label": "次に身につけたいスキルは？", "placeholder": "例: テレアポのスキル、商談スキル、クロージングスキル"}, {"label": "どうやって学ぶ？", "placeholder": "例: 本を読む、先輩に同行、研修を続ける"}, {"label": "毎日どれくらい時間を使う？", "placeholder": "例: 通勤時間に30分、昼休みに15分"}, {"label": "1ヶ月後の目標は？", "placeholder": "例: テレアポで安定して週2件アポが取れるようになる"}], "description": "これからの学習計画を立てましょう。"}', NULL, '2026-01-21 17:48:14.92023+00', '2026-01-21 17:48:14.92023+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (51, 23, '中古車流通の全体像', '車は"流れ"の中で価値が変わる', '{"icon": "car", "name": "流通マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["約200万台", "約400万台", "約700万台", "約1,000万台"], "question": "日本の中古車登録台数は年間何台？", "explanation": "新車販売（約400万台）より多い！中古車市場は巨大なマーケットです。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 朝6時のオークション会場", "content": "ナレーション:「朝6時、まだ暗い中、鈴木店長は車を走らせていた」\n\n鈴木店長:「今日はUSS東京、いい出物があるはずだ」\n\n（オークション会場の様子：広大な敷地に並ぶ数千台の車）\n\nナレーション:「中古車の仕入れは、早朝から始まる。\n全国に約130か所あるオートオークション。\nここが中古車流通の\"心臓部\"だ」\n\n【数字で見る中古車オークション】\n・年間オークション流通台数: 約700万台\n・1日あたり: 約2万台が取引される", "duration": 40}, {"title": "シーン2: 下取り車の査定", "content": "お客様:「この車、乗り換えで下取りに出したいんですが...」\n\n山田社長:「ありがとうございます。拝見しますね」\n\n山田社長（心の声）:「走行8万キロ、内外装まあまあ。\n相場は40万前後か...でもこの傷、板金で5万はかかるな」\n\n山田社長:「35万円でいかがでしょうか」\n\nナレーション:「下取り・買取も重要な仕入れルート。\nお客様から直接仕入れることで、オークション手数料を節約できる」", "duration": 35}, {"title": "シーン3: 業販での仕入れ", "content": "鈴木店長:「社長、ワンプラで良い物件見つけました」\n\n山田社長:「お、この値段なら利益出せるな。陸送費は？」\n\n鈴木店長:「北海道からなので、3万円くらいですね」\n\n山田社長:「よし、押さえよう」\n\nナレーション:「業販プラットフォームを使えば、\nオークションに行かなくても全国から仕入れ可能。\n特に地方の販売店にとって、仕入れの幅が広がる」", "duration": 30}], "part2": [{"title": "シーン4: 整備と商品化", "content": "整備士:「社長、このエアコン、コンプレッサー交換必要ですね」\n\n山田社長:「うーん、5万か。仕入れ値考えると厳しいな...」\n\n山田社長（心の声）:「直さないと売れない。でも直すと利益が減る。\nいつもこのジレンマだ」\n\nナレーション:「仕入れた車をそのまま売ることはできない。\n点検、整備、清掃、写真撮影...この\"商品化\"に手間とコストがかかる」\n\n【平均商品化コスト: 5〜15万円/台】\n・整備費用\n・板金・塗装\n・内外装クリーニング\n・写真撮影・掲載", "duration": 40}, {"title": "シーン5: 健太、初めての訪問", "content": "健太:「こんにちは、ファブリカホールディングスの佐藤です」\n\n山田社長:「ああ、Symphonyの人だね。忙しいけど、少しなら」\n\n健太:「あの...中古車って、仕入れてそのまま売るんですよね？」\n\n山田社長:「（苦笑）君、業界のこと何も知らないでしょ」\n\n山田社長:「1台仕入れて売るまでに、どれだけの手間がかかるか。\nオークション会場まで往復3時間、整備に2日、写真撮影に半日、\nネット掲載の文章作成に1時間...\n在庫が30台あったら、管理だけで大変なんだよ」\n\n健太:「そ、そうなんですか...」\n\n山田社長:「システム売るなら、まず現場を知りなさい。話はそれからだ」", "duration": 45}, {"title": "シーン6: 健太の気づき", "content": "健太（心の声）:「俺、何も知らなかった...\n販売店の人たちは、こんなに大変な仕事をしてるんだ。\nまずは業界を知ろう。\nお客様の立場に立つって、こういうことか」\n\nナレーション:「営業の仕事は、製品を売ることではない。\n顧客の課題を理解し、解決策を提案すること。\nそのためには、まず\"現場を知る\"ことから始まる」\n\n【今日の学び】\n「車は\"流れ\"の中で価値が変わる」\n仕入れ → 在庫 → 販売\nこの一連の流れを効率化することが、販売店の利益に直結する", "duration": 35}]}', '{"title": "中古車流通の全体像", "content": "【仕入れルート】\n・オークション（70%）\n・下取り/買取（20%）\n・業販（10%）\n\n【販売ルート】\n・小売（一般顧客）\n・業販（業者間取引）\n・輸出\n・再オークション\n\n💡 在庫期間が長いほど、価値は下がる（相場変動リスク）", "audioText": "中古車は仕入れから販売までの流れの中で価値が変わります。この流れを効率化することが、販売店の利益に直結します。", "highlight": "仕入れ → 在庫 → 販売 この流れの効率化が利益に直結"}', '[{"options": ["約40%（小売中心の市場構造）", "約60%（卸売中心の市場構造）", "約80%（ほぼ全てがAA経由）", "約20%（直接仕入れが主流）"], "question": "日本の中古車市場において、AA（オートオークション）で取引される車両の割合は約何%ですか？", "explanation": "日本の中古車市場では約60%の車両がAAを経由して取引されており、卸売中心の市場構造となっています。", "correctIndex": 1}, {"options": ["年間の仕入台数を販売台数で割った値", "在庫が何回入れ替わったかを示す値", "在庫車両の平均走行距離の変化率", "月間の来店客数に対する成約率"], "question": "中古車ビジネスにおける「在庫回転率」とは何を表す指標ですか？", "explanation": "在庫回転率は一定期間に在庫が何回入れ替わったかを示す指標で、資金効率を測る重要な数値です。", "correctIndex": 1}, {"options": ["下取り（ディーラー・販売店）", "オートオークション（AA）", "業者間の直接取引", "個人からの買取専門店"], "question": "中古車の仕入れルートとして最も取引量が多いのはどれですか？", "explanation": "オートオークション（AA）は日本の中古車流通の中心であり、取引量が最も多いルートです。", "correctIndex": 1}]', '{"text": "To understand the customer, you must first understand their business.", "author": "ピーター・ドラッカー", "textJa": "顧客を理解するには、まず顧客のビジネスを理解せよ。"}', '[{"options": [{"text": "「そうですね、オークションの方が安いです」と認める", "points": 0, "feedback": "販売店の価値を伝えられていません。", "isCorrect": false}, {"text": "「当店では点検整備、保証、アフターサービスが含まれています。安心して乗れる状態でお渡しします」", "points": 30, "feedback": "販売店で買う「価値」を伝えることが重要です。整備・保証・サポートは価格に表れない価値です。", "isCorrect": true}, {"text": "「オークションは一般の方は参加できません」と断る", "points": 10, "feedback": "事実ですが、質問の本質に答えていません。", "isCorrect": false}, {"text": "「うちの利益分が乗ってるんです」と正直に言う", "points": 5, "feedback": "正直ですが、提供価値を伝えられていません。", "isCorrect": false}], "situation": "お客様から「この車、オークションで買えば安いんでしょ？なんでお店で買うと高くなるの？」と質問されました。", "customerLine": "オークションで直接買えば安いんじゃないの？"}]', '{"question": "中古車流通について学んで、どんな気づきがありましたか？", "placeholder": "例: 販売店の仕事は想像以上に大変だと分かった"}', '["商談で「仕入れから販売までの流れ」を意識して話す", "顧客の業務を理解するために、1日の流れを聞いてみる", "業界用語（AA、商品化、陸送など）を自然に使えるようにする"]', NULL, NULL, '2026-01-21 17:48:16.646772+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (52, 24, 'オートオークションの仕組み', 'オークションは"情報戦"', '{"icon": "gavel", "name": "オークションマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["下取り/買取", "オークション", "業販", "輸入"], "question": "中古車の仕入れルートで最も多い割合は？", "explanation": "オークションが約70%を占めます。中古車流通の心臓部ですね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: オークション会場の朝", "content": "（早朝5時30分、USS東京オークション会場）\n\n鈴木店長:「健太、今日は現場を見せてやる。オークション会場だ」\n\n健太:「わあ、すごい数の車...何台あるんですか？」\n\n鈴木店長:「今日は3,000台くらいかな。USSは最大手で、全国19会場ある」\n\n健太:「3,000台！？1日でこれだけ取引されるんですか？」\n\n鈴木店長:「ああ。全国で1日約2万台だ。\nここが中古車流通の心臓部なんだよ」", "duration": 35}, {"title": "シーン2: 評価点の見方", "content": "鈴木店長:「これ見てみろ。評価点だ」\n\n【オークション評価点】\n・S：新車同様（走行1万km未満、目立つ傷なし）\n・6：非常に良い（走行3万km未満）\n・5：良い（走行5万km未満、軽微な傷）\n・4.5：やや良い（走行10万km未満）\n・4：普通（一般的な中古車）\n・3.5：やや劣る（傷・へこみあり）\n・R：修復歴あり（事故車）\n\n鈴木店長:「小売向けは評価点4以上が目安だ。\n3.5以下は業販や輸出向けが多い」\n\n健太:「数字で品質がわかるんですね」", "duration": 40}, {"title": "シーン3: セリの現場", "content": "（セリ会場。電光掲示板に車両情報が表示される）\n\nアナウンス:「次、○○号車、プリウス、評価4.5、走行4万8千キロ」\n\n（バイヤーたちが端末を操作）\n\n鈴木店長:「相場は65万くらいだな...」\n\n（価格が上がっていく）\n60万... 62万... 64万... 66万...\n\n鈴木店長:「よし、ここまでだ」（入札をやめる）\n\n健太:「え、もう少しで落とせそうだったのに！」\n\n鈴木店長:「熱くなって予算オーバーは禁物だ。\n経験豊富なバイヤーほど、\"買わない判断\"が上手いんだよ」", "duration": 45}], "part2": [{"title": "シーン4: 情報戦の意味", "content": "鈴木店長:「オークションは\"情報戦\"だ」\n\n健太:「情報戦？」\n\n鈴木店長:「相場を知らないと、高値掴みする。\n逆に、相場より安く落とせれば利益が出る。\n\n【勝つための3つのポイント】\n1. 相場を知る: 過去の落札データを分析\n2. 現車を見る: 評価点だけでは分からない情報がある\n3. 引き際を決める: 熱くなって予算オーバーは禁物\n\n勝負は、セリが始まる前に決まってるんだ」\n\n健太:「事前準備が大事なんですね...」", "duration": 35}, {"title": "シーン5: 販売店の悩み", "content": "鈴木店長:「でもな、オークションにも課題がある」\n\n健太:「課題？」\n\n鈴木店長:「まず、時間がかかる。\n往復3時間、セリに半日...週1回行くと、丸1日潰れる。\n\n次に、体力勝負だ。\n早朝から会場を歩き回って、現車確認。\n体がきついんだよ、正直。\n\nそれに、行っても欲しい車がないこともある。\n空振りで帰ることもしょっちゅうだ」\n\n健太:「大変ですね...」\n\n鈴木店長:「だから、業販プラットフォームが注目されてるんだ。\nオークションに行かなくても仕入れができる」", "duration": 40}, {"title": "シーン6: 健太の学び", "content": "健太（心の声）:「オークションは情報戦...\n相場を知り、現車を見て、引き際を決める。\n\nでも、時間と体力の負担が大きい。\nだからワンプラのような業販が求められてるんだ。\n\n販売店の課題がわかると、\nSymphonyの価値も見えてくる」\n\n【今日の学び】\nオークションは中古車流通の心臓部。\nしかし、時間・体力の負担が大きい。\n業販プラットフォームが「第三の仕入れルート」として注目されている。", "duration": 30}]}', '{"title": "主要オークション会社", "content": "【USS（ユー・エス・エス）】業界最大手、全国19会場、年間約250万台\n【JU】業界団体系、全国約50会場、中小販売店に人気\n【HAA】関西圏に強み、神戸会場が有名\n【TAA】トヨタ系、品質に定評\n\n💡 評価点4以上が小売向けの目安", "audioText": "オークションは情報戦です。相場を知り、現車を見て、引き際を決める。この準備が成否を分けます。", "highlight": "オークションは情報戦。勝負はセリが始まる前に決まる"}', '[{"options": ["ボディカラーの人気度", "年式と走行距離のバランス", "前オーナーの使用目的", "車検の残り期間"], "question": "中古車の価格査定において、最も影響が大きい要素はどれですか？", "explanation": "年式と走行距離は中古車の価値を決める最も基本的な要素であり、相場形成の中心となります。", "correctIndex": 1}, {"options": ["インターネットの販売価格一覧", "オートオークションの落札データ", "メーカー発表の残価設定表", "買取専門店の査定価格"], "question": "「相場」を把握する際に最も信頼性が高い情報源はどれですか？", "explanation": "AAの落札データは実際の取引価格であり、市場の需給を正確に反映した相場情報となります。", "correctIndex": 1}, {"options": ["軽微な修復なら価値に影響しない", "修復箇所と程度で影響度が異なる", "修復歴があれば一律30%減額", "フレーム修正以外は告知不要"], "question": "修復歴がある車両の価値への影響について正しいのはどれですか？", "explanation": "修復歴の影響は修復箇所（フレーム・ピラー等）と程度によって大きく異なります。", "correctIndex": 1}]', '{"text": "In business, the competition will bite you if you keep running; if you stand still, they will swallow you.", "author": "ウィリアム・クナッセン", "textJa": "ビジネスでは、走り続ければ競争相手に噛まれるが、立ち止まれば飲み込まれる。"}', '[{"options": [{"text": "「大変ですよね」と共感だけする", "points": 10, "feedback": "共感は大切ですが、解決策の提案機会を逃しています。", "isCorrect": false}, {"text": "「ワンプラなら、オークションに行かなくても全国から仕入れできますよ」と提案する", "points": 30, "feedback": "顧客の課題を聞いて、解決策を提案しています。これが営業の仕事です。", "isCorrect": true}, {"text": "「でもオークションが一番ですよ」と反論する", "points": 0, "feedback": "顧客の悩みを否定しています。", "isCorrect": false}, {"text": "「他の販売店も同じです」と言う", "points": 5, "feedback": "解決策を提示できていません。", "isCorrect": false}], "situation": "販売店の社長から「オークションは大変で...」と愚痴を聞きました。どう返しますか？", "customerLine": "毎週オークション行くのも、正直しんどいんだよね"}]', '{"question": "オークションの仕組みを学んで、販売店の課題がどう見えましたか？", "placeholder": "例: 時間と体力の負担が大きいことが分かった"}', '["顧客に「オークションの負担」について聞いてみる", "評価点の見方を覚えて、商談で使えるようにする", "ワンプラの価値を「オークションの補完」として説明する"]', NULL, NULL, '2026-01-21 17:48:17.572337+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (53, 25, '業販プラットフォームの市場動向', '業販は"第三の仕入れルート"', '{"icon": "globe", "name": "業販マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["価格が高い", "品質が悪い", "時間と体力の負担が大きい", "車種が少ない"], "question": "オークションの課題は？", "explanation": "往復の移動時間、現車確認の体力など、負担が大きいのが課題です。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 業販とは", "content": "山本先輩:「健太、\"業販\"って知ってるか？」\n\n健太:「ぎょうはん...？」\n\n山本先輩:「業者間販売の略だ。\n中古車販売店同士が車を売買すること」\n\n健太:「販売店同士で売り買いするんですか？」\n\n山本先輩:「ああ。例えば、東京の店が北海道の店から車を買う。\nオークションを通さずに、直接取引するんだ」\n\n【業販のメリット】\n・オークションに行く必要なし\n・いつでもどこでも取引可能\n・価格交渉ができる", "duration": 35}, {"title": "シーン2: ワンプラの強み", "content": "山本先輩:「うちのワンプラは、その業販をオンラインで実現してる」\n\n健太:「オークションと何が違うんですか？」\n\n山本先輩:「まず、場所を選ばない。\nPCやスマホがあれば、どこでも仕入れができる。\n\n次に、時間を選ばない。\n24時間いつでも検索・交渉できる。\n\nそして、Symphony連携。\n在庫データを自動で出品できるから、手間が激減する」\n\n健太:「オークションの課題を解決してるんですね！」", "duration": 40}, {"title": "シーン3: 市場トレンド", "content": "山本先輩:「業販市場は今、急成長してる」\n\n【市場動向トレンド】\n\n①オンライン化の加速\nコロナ禍を経て、オンライン取引が一般化\n\n②地方販売店の利用増加\nオークション会場が遠い地方にとって「命綱」\n\n③専門店の増加\n輸入車専門、スポーツカー専門など、ニッチ市場で活躍\n\n④効率化ニーズ\n人手不足の中、「時間を買う」感覚で業販を活用\n\n山本先輩:「オークションを\"補完\"する第三の仕入れルートとして、\n存在感を増してるんだ」", "duration": 45}], "part2": [{"title": "シーン4: 具体的な活用シーン", "content": "山本先輩:「具体的にどう使われてるか、教えてやろう」\n\n【活用シーン①】地方の販売店\n「オークション会場まで片道2時間。毎週は行けない。\nワンプラなら、店にいながら全国から仕入れできる」\n\n【活用シーン②】専門店\n「ポルシェ専門店なんだけど、オークションだと出物が少ない。\nワンプラで全国の同業者から情報が入る」\n\n【活用シーン③】長期在庫の処分\n「3ヶ月売れない車がある。\nオークションに出すより、ワンプラで業販した方が手取りがいい」", "duration": 40}, {"title": "シーン5: Symphony連携の価値", "content": "山本先輩:「ワンプラの最大の強みは、Symphony連携だ」\n\n健太:「具体的にどういうことですか？」\n\n山本先輩:「Symphonyで在庫管理してる販売店は、\nボタン一つでワンプラに出品できる。\n\n車両情報、写真、全部自動連携。\n出品の手間が10分の1になる」\n\n健太:「だから、Symphonyとセットで提案するんですね」\n\n山本先輩:「その通り。\n販売管理で業務効率化、\nワンプラで仕入れ・販売チャネル拡大。\nこれがSymphonyの価値だ」", "duration": 35}, {"title": "シーン6: 健太の理解", "content": "健太（心の声）:「業販は第三の仕入れルート...\n\nオークションの課題を補完し、\nオンラインで効率的に取引できる。\n\nSymphony連携があるから、\nうちの強みが活きる。\n\nこれを顧客に伝えられるようになろう」\n\n【今日の学び】\n・業販＝業者間販売（販売店同士の取引）\n・オークションを「補完」する第三の仕入れルート\n・Symphony連携でワンプラの価値が最大化", "duration": 25}]}', '{"title": "オークション vs 業販プラットフォーム", "content": "【オークション】\n・会場に行く必要あり\n・早朝から時間を取られる\n・セリに参加（競争）\n\n【業販プラットフォーム】\n・PCやスマホで完結\n・いつでもどこでも取引可能\n・価格交渉可能\n・Symphony連携で出品の手間激減", "audioText": "業販プラットフォームは、オークションに行く時間がない販売店にとって、強力な仕入れルートになります。", "highlight": "業販はオークションを「補完」する第三の仕入れルート"}', '[{"options": ["5点（新車同等の状態）", "6点（ほぼ新車の状態）", "S点（特別評価の最高ランク）", "10点（完全無傷の状態）"], "question": "オートオークションの出品票に記載される「評価点」の最高点は何点ですか？", "explanation": "AAの評価点はS点が最高で、ほぼ新車同等の極めて良好な状態を示します。", "correctIndex": 2}, {"options": ["一度入札したら取り消しができない", "最高額を提示した会員が落札する", "出品者が希望価格以下なら流札となる", "応札は1台につき1回のみ可能"], "question": "AA会場での「応札」について正しい説明はどれですか？", "explanation": "AAは競り形式で行われ、最高額を提示した会員が落札者となります。", "correctIndex": 1}, {"options": ["落札後は一切のクレーム不可", "申告漏れは一定期間クレーム対象", "外装の傷は全てクレーム対象", "走行距離不明車はクレーム対象外"], "question": "AAの「瑕疵担保責任」について正しいのはどれですか？", "explanation": "出品票に記載されていない重大な瑕疵は、一定期間内であればクレーム対象となります。", "correctIndex": 1}]', '{"text": "Innovation is not about saying yes to everything. It''s about saying no to all but the most crucial features.", "author": "スティーブ・ジョブズ", "textJa": "イノベーションとは全てにYESと言うことではない。最も重要な機能以外にNOと言うことだ。"}', '[{"options": [{"text": "「近くのオークション会場を探しましょう」と提案する", "points": 5, "feedback": "根本的な解決になっていません。", "isCorrect": false}, {"text": "「ワンプラなら、店にいながら全国から仕入れできますよ」と提案する", "points": 30, "feedback": "顧客の課題に対して、最適な解決策を提案しています。", "isCorrect": true}, {"text": "「仕方ないですね」と同情する", "points": 0, "feedback": "解決策を提示できていません。", "isCorrect": false}, {"text": "「頑張って通いましょう」と励ます", "points": 0, "feedback": "顧客の負担を減らす提案ができていません。", "isCorrect": false}], "situation": "地方の販売店から「オークション会場が遠くて...」と相談されました。", "customerLine": "うちは田舎だから、オークション会場まで片道2時間かかるんだよ"}]', '{"question": "業販プラットフォームの価値をどう顧客に伝えますか？", "placeholder": "例: オークションに行く時間がない方に、全国から仕入れできる方法を提案する"}', '["顧客に「仕入れの課題」を聞いてみる", "ワンプラの活用事例を3つ覚える", "Symphony連携のメリットを説明できるようにする"]', NULL, NULL, '2026-01-21 17:48:18.27411+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (54, 26, '中古車販売店の経営課題', '規模で課題は変わる', '{"icon": "briefcase", "name": "経営理解マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["価格が安い", "いつでもどこでも取引可能", "審査不要", "無料で使える"], "question": "業販プラットフォームの最大のメリットは？", "explanation": "時間・場所を選ばずに取引できることが、業販プラットフォームの強みです。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 小規模店の世界", "content": "（カーショップ田中。在庫8台の家族経営店）\n\n田中社長:「いらっしゃい...あ、Symphonyの人？」\n\n健太:「はい、よろしくお願いします」\n\n田中社長:「悪いけど、今忙しいんだ。\n電話対応しながら、整備もやって、\nネット掲載の更新も追いつかなくて...」\n\n健太:「全部お一人でやられてるんですか？」\n\n田中社長:「うちは家族でやってるからね。\n人を雇う余裕もないし」\n\n【小規模店（在庫10台以下）の特徴】\n・家族経営、従業員1〜3名\n・社長が仕入れも整備も営業も全部やる\n・時間がない、資金繰りが厳しい", "duration": 40}, {"title": "シーン2: 中規模店の世界", "content": "（カーセンター鈴木。在庫40台、従業員10名）\n\n鈴木専務:「うちの課題？在庫管理だね」\n\n健太:「在庫管理ですか？」\n\n鈴木専務:「40台あると、どの車がいつ仕入れたか分からなくなる。\n3ヶ月経ってた、なんてことがザラにある。\n\nそれと、営業と整備の連携も悪い。\n『納車いつ？』『整備終わってないの？』って、\nお客様に迷惑かけることがある」\n\n【中規模店（在庫30〜50台）の特徴】\n・従業員5〜15名\n・部門分業が始まっている\n・在庫管理の複雑化、部門間連携が課題", "duration": 45}, {"title": "シーン3: 大規模店の世界", "content": "（オートモール山田。5店舗展開、在庫200台）\n\n山田部長:「うちは5店舗あるんだけど、\n各店舗の状況がリアルタイムで見えないのが課題だね」\n\n健太:「5店舗もあると大変そうですね」\n\n山田部長:「在庫が偏ってたり、\nどの店が好調でどの店が苦戦してるか、\n月末にならないと分からない。\n\nあと、システムがバラバラでね。\n販売管理、整備、会計、全部別々。\n二重入力が多くて、ミスも増える」\n\n【大規模店（在庫100台以上）の特徴】\n・多店舗展開\n・専門部署あり\n・統合管理、データ活用が課題", "duration": 45}], "part2": [{"title": "シーン4: 規模別の課題まとめ", "content": "山本先輩:「健太、今日の訪問でわかっただろ？」\n\n健太:「はい、規模によって課題が全然違いました」\n\n山本先輩:「そうだ。だから、同じシステム提案でも、\n刺さるポイントが違うんだ」\n\n【規模別の最優先課題】\n・小規模: 時間創出「これで時間が空きますよ」\n・中規模: 在庫管理「在庫の見える化ができますよ」\n・大規模: 統合管理「全店舗を一元管理できますよ」\n\n山本先輩:「顧客の規模を見て、課題を想定する。\nそれが\"顧客理解\"の第一歩だ」", "duration": 40}, {"title": "シーン5: ヒアリングのポイント", "content": "山本先輩:「でも、想定だけで決めつけるな。\n必ずヒアリングして確認しろ」\n\n健太:「どうやって聞けばいいですか？」\n\n山本先輩:「シンプルに聞けばいい。\n『今、一番お困りのことは何ですか？』\n『どこに一番時間がかかってますか？』\n『もし魔法の杖があったら、何を解決したいですか？』\n\n相手の言葉で課題を聞き出す。\nそれが営業の基本だ」\n\n健太:「想定して、確認する。そのサイクルですね」", "duration": 35}, {"title": "シーン6: 健太の気づき", "content": "健太（心の声）:「規模で課題は変わる...\n\n小規模店は時間がない。\n中規模店は管理が複雑。\n大規模店は統合が必要。\n\nでも、決めつけずにヒアリングで確認する。\nそれが顧客理解の基本だ」\n\n【今日の学び】\n・規模によって経営課題は異なる\n・提案のポイントも規模に応じて変える\n・想定して、ヒアリングで確認する", "duration": 30}]}', '{"title": "規模別・経営課題マップ", "content": "【小規模（在庫10台以下）】\n最優先: 時間創出\n提案: 「これで時間が空きますよ」\n\n【中規模（在庫30〜50台）】\n最優先: 在庫管理\n提案: 「在庫の見える化ができますよ」\n\n【大規模（在庫100台以上）】\n最優先: 統合管理\n提案: 「全店舗を一元管理できますよ」", "audioText": "顧客の規模を見て課題を想定し、ヒアリングで確認する。それが顧客理解の基本です。", "highlight": "同じシステム提案でも、刺さるポイントは規模で変わる"}', '[{"options": ["車両本体の販売利益", "整備・メンテナンス収益", "保険代理店手数料", "下取り車の転売利益"], "question": "中古車販売店の収益構造において、最も利益率が高いのはどれですか？", "explanation": "整備・メンテナンスは継続的な収益源であり、車両販売より利益率が高い傾向にあります。", "correctIndex": 1}, {"options": ["30日以内（高回転経営）", "60日以内（標準的な目標）", "90日以内（じっくり販売）", "120日以内（高額車向け）"], "question": "中古車販売店の「在庫日数」について適切な目標はどれですか？", "explanation": "一般的に在庫日数60日以内が健全な経営の目安とされています。", "correctIndex": 1}, {"options": ["オークション会費の高騰", "良質な下取り車の減少", "輸送コストの上昇", "査定人材の不足"], "question": "販売店が直面する「仕入れの課題」として最も深刻なのはどれですか？", "explanation": "新車販売の減少や買取専門店の台頭により、良質な下取り車の確保が困難になっています。", "correctIndex": 1}]', '{"text": "The customer rarely buys what the company thinks it''s selling.", "author": "ピーター・ドラッカー", "textJa": "顧客が買うものは、企業が売っていると思っているものとは違うことが多い。"}', '[{"options": [{"text": "「このシステムは高機能で、全ての業務をカバーできます」と説明する", "points": 5, "feedback": "機能の多さより、時間削減のメリットを伝えるべきです。", "isCorrect": false}, {"text": "「このシステムで、毎日30分の時間が空きます」と伝える", "points": 30, "feedback": "小規模店の課題「時間がない」に直接響く提案です。", "isCorrect": true}, {"text": "「他の販売店も同じです」と言う", "points": 0, "feedback": "解決策を提示できていません。", "isCorrect": false}, {"text": "「人を雇った方がいいですよ」とアドバイスする", "points": 0, "feedback": "顧客の状況を理解していない提案です。", "isCorrect": false}], "situation": "小規模店の社長から「忙しくて時間がない」と言われました。どう返しますか？", "customerLine": "全部自分でやってるから、システムを見る時間もないんだよ"}]', '{"question": "あなたが担当する顧客は、どの規模に当てはまりますか？その課題は？", "placeholder": "例: 中規模店が多い。在庫管理と部門間連携が課題になっている"}', '["訪問前に顧客の規模を確認し、課題を想定する", "ヒアリングで「一番お困りのこと」を必ず聞く", "規模に応じた提案ポイントを準備する"]', NULL, NULL, '2026-01-21 17:48:19.018735+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (55, 27, '在庫回転率と資金繰りの関係', '在庫は寝かせると腐る', '{"icon": "coins", "name": "財務理解マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["時間創出", "在庫管理", "統合管理", "人材採用"], "question": "大規模販売店の最大の課題は？", "explanation": "多店舗展開では、全店舗の状況を一元管理することが課題になります。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 在庫回転率とは", "content": "山本先輩:「健太、在庫回転率って知ってるか？」\n\n健太:「なんとなく...回転が早い方がいい、みたいな」\n\n山本先輩:「計算式を教えてやる」\n\n【在庫回転率の計算】\n在庫回転率 = 年間販売台数 ÷ 平均在庫台数\n\n例:\n・年間販売台数: 120台\n・平均在庫台数: 30台\n・在庫回転率 = 120 ÷ 30 = 4回転/年\n\n→ 在庫が年間4回入れ替わっている\n→ 1台あたり平均3ヶ月で売れている", "duration": 40}, {"title": "シーン2: なぜ回転率が重要か", "content": "山本先輩:「なぜ回転率が重要かわかるか？」\n\n健太:「早く売れた方がいいから...？」\n\n山本先輩:「それもあるが、本質は\"資金繰り\"だ」\n\n【在庫と資金の関係】\n在庫 = お金が車に変わっている状態\n\n100万円の車を10台仕入れ = 1,000万円が在庫に変換\nこの1,000万円は「動かせない」お金。\n売れるまで現金に戻らない。\n\n山本先輩:「在庫が増えると、現金が減る。\n現金が減ると、次の仕入れができない。\n仕入れができないと、売上が立たない。\n悪循環だ」", "duration": 45}, {"title": "シーン3: 在庫は寝かせると腐る", "content": "山本先輩:「もう一つ重要なこと。\n\"在庫は寝かせると腐る\"」\n\n健太:「腐る...？」\n\n山本先輩:「車は時間とともに相場が下がる。\n1ヶ月前に100万円で仕入れた車が、\n今の相場では90万円かもしれない。\n\n長期在庫は「値下げして売る」しかなくなる。\nつまり、利益が減る」\n\n【業界の目安】\n・6回転以上: 優良（平均2ヶ月以内で販売）\n・4〜6回転: 標準\n・4回転未満: 要改善（在庫が滞留）\n\n山本先輩:「在庫管理は、経営の生命線なんだ」", "duration": 40}], "part2": [{"title": "シーン4: 販売店の悩み", "content": "（カーショップ佐藤を訪問）\n\n佐藤社長:「うちの悩み？在庫だよ、在庫」\n\n健太:「どういうことですか？」\n\n佐藤社長:「気づいたら3ヶ月経ってる車がある。\nでも、忙しくて在庫日数なんて見てられない。\n\n結局、損切りで業販に出す。\n仕入れ値割れで売ることもある」\n\n健太（心の声）:「在庫管理ができていないと、\n利益が出ないんだ...」\n\n佐藤社長:「在庫日数を自動で教えてくれるシステムがあったら、\nすぐにでも使いたいね」", "duration": 40}, {"title": "シーン5: Symphonyの解決策", "content": "健太:「実は、Symphonyにはその機能があります」\n\n佐藤社長:「え、本当？」\n\n健太:「はい。在庫日数を自動計算して、\n30日、60日、90日でアラートを出せます。\n\n長期在庫をひと目で把握できるので、\n値下げや業販出品の判断が早くなります」\n\n佐藤社長:「それはいいね...\n今まで、感覚でやってたから」\n\n健太:「さらに、ワンプラ連携で、\n長期在庫をそのまま業販出品できます」\n\n佐藤社長:「ほう、それは便利だ」", "duration": 35}, {"title": "シーン6: 健太の学び", "content": "健太（心の声）:「在庫は寝かせると腐る...\n\n在庫回転率は経営の生命線。\nでも、忙しい社長は見る時間がない。\n\nSymphonyで自動化すれば、\n長期在庫を早期発見できる。\nそれが利益を守ることになる」\n\n【今日の学び】\n・在庫回転率 = 年間販売台数 ÷ 平均在庫台数\n・在庫は資金を固定する。回転率が低いと資金繰りが悪化\n・長期在庫は値下げ必至。早期発見が重要\n・Symphonyの在庫日数アラートで「腐る前」に対策", "duration": 30}]}', '{"title": "在庫回転率と経営への影響", "content": "【計算式】\n在庫回転率 = 年間販売台数 ÷ 平均在庫台数\n\n【目安】\n・6回転以上: 優良\n・4〜6回転: 標準\n・4回転未満: 要改善\n\n【在庫滞留の悪影響】\n資金固定 → 仕入れ減少 → 売上減少 → 利益減少", "audioText": "在庫回転率は経営の生命線です。長期在庫は値下げ必至。Symphonyの在庫日数アラートで早期発見しましょう。", "highlight": "在庫は寝かせると腐る。早期発見・早期対策が利益を守る"}', '[{"options": ["AI査定による価格算出", "オンラインオークション", "VR試乗体験の導入", "ブロックチェーン履歴管理"], "question": "中古車業界のDXにおいて、最も進んでいる領域はどれですか？", "explanation": "オンラインAAは既に広く普及しており、中古車業界のDXで最も進んだ領域です。", "correctIndex": 1}, {"options": ["通信技術の高速化", "コロナ禍での行動制限", "若年層の購買増加", "店舗コスト削減ニーズ"], "question": "オンライン商談が普及した背景として最も大きい要因はどれですか？", "explanation": "2020年以降のコロナ禍により、非対面での商談ニーズが急速に高まりました。", "correctIndex": 1}, {"options": ["車両情報の定期的な投稿", "スタッフの人柄が伝わる発信", "値引きキャンペーンの告知", "業界ニュースのシェア"], "question": "中古車販売におけるSNS活用で最も効果的なのはどれですか？", "explanation": "中古車は高額商品のため、スタッフへの信頼感が購買決定に大きく影響します。", "correctIndex": 1}]', '{"text": "Cash is king.", "author": "ビジネス格言", "textJa": "現金は王様だ。"}', '[{"options": [{"text": "「もっと頻繁にチェックした方がいいですよ」とアドバイスする", "points": 5, "feedback": "時間がないから追いつかないのです。解決策になっていません。", "isCorrect": false}, {"text": "「Symphonyなら在庫日数を自動計算し、アラートで通知できます」と提案する", "points": 30, "feedback": "顧客の課題「管理が追いつかない」に対する具体的な解決策を提示しています。", "isCorrect": true}, {"text": "「3ヶ月は長すぎますね」と指摘する", "points": 0, "feedback": "問題を指摘するだけで、解決策を示していません。", "isCorrect": false}, {"text": "「業界の平均は2ヶ月です」と教える", "points": 10, "feedback": "情報提供だけで、解決策を示していません。", "isCorrect": false}], "situation": "販売店社長から「在庫管理が追いつかない」と相談されました。", "customerLine": "気づいたら3ヶ月経ってる車があるんだよね"}]', '{"question": "在庫回転率の重要性をどう顧客に伝えますか？", "placeholder": "例: 長期在庫は値下げが必要になること、早期発見が利益を守ることを伝える"}', '["商談で「在庫日数」「回転率」について聞いてみる", "Symphonyの在庫アラート機能を説明できるようにする", "「在庫は寝かせると腐る」というキーフレーズを使う"]', NULL, NULL, '2026-01-21 17:48:19.737081+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (56, 28, '中古車の価格形成メカニズム', '相場は"需要と供給"で動く', '{"icon": "chart", "name": "相場マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["要改善", "標準", "優良", "異常"], "question": "在庫回転率6回転/年は、業界ではどの評価？", "explanation": "6回転以上は優良。平均2ヶ月以内で販売できているということです。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 価格を決める要素", "content": "山本先輩:「健太、中古車の価格は何で決まると思う？」\n\n健太:「年式とか走行距離ですか？」\n\n山本先輩:「それもあるが、もっと多くの要素がある」\n\n【価格を決める7つの要素】\n1. 車種・グレード: 人気車種は高値維持\n2. 年式: 新しいほど高い\n3. 走行距離: 少ないほど高い（5万km・10万kmが節目）\n4. ボディカラー: 白・黒・シルバーが人気\n5. 装備・オプション: ナビ、安全装備等\n6. 修復歴: あり→大幅減額\n7. 車検残: 長いほど有利\n\n山本先輩:「この7つを押さえておけ」", "duration": 45}, {"title": "シーン2: 季節変動", "content": "山本先輩:「次に、季節変動だ」\n\n【中古車相場の季節変動】\n\n高い時期:\n・1〜3月: 年度末需要（入学・就職・転勤）\n・7〜8月: ボーナス・夏休みレジャー需要\n\n低い時期:\n・4〜6月: 需要の谷間\n・10〜12月: 年末は新車に流れやすい\n\n山本先輩:「つまり、賢い仕入れは...」\n\n健太:「需要が高まる前に仕入れて、高い時期に売る！」\n\n山本先輩:「正解。12月〜1月に仕入れて、\n2月〜3月に売る。これが利益を最大化する」", "duration": 40}, {"title": "シーン3: 人気車種の傾向", "content": "山本先輩:「人気車種も覚えておけ」\n\n【値落ちしにくい車種（2025年）】\n・トヨタ ランドクルーザー（国内外で人気）\n・トヨタ アルファード/ヴェルファイア\n・スズキ ジムニー（需要＞供給）\n・ホンダ N-BOX（軽自動車の王者）\n・トヨタ プリウス（定番ハイブリッド）\n\n【値落ちしやすい車種】\n・高級輸入車（維持費・部品代が高い）\n・スポーツカー（需要層が限定的）\n・大型セダン（SUV人気で需要減）\n・マイナー車種（流通量が少なく売りにくい）\n\n山本先輩:「相場の傾向を知っていると、\nお客様との会話に深みが出る」", "duration": 45}], "part2": [{"title": "シーン4: 相場情報の入手方法", "content": "健太:「相場ってどうやって調べるんですか？」\n\n山本先輩:「いくつか方法がある」\n\n【相場情報の入手方法】\n①オークション相場: USS、JU等のデータ（会員のみ）\n②業者間価格: ワンプラ等の掲載価格\n③小売価格: カーセンサー、グーネット（一般向け）\n④買取相場: 買取業者の査定データ\n\n【価格の関係性】\nオークション ＜ 業販 ＜ 小売\n↑ 仕入れ価格　　↑ 販売価格\n\n山本先輩:「この\"差額\"が販売店の粗利になる」", "duration": 35}, {"title": "シーン5: 商談での活用", "content": "山本先輩:「相場知識は商談で使える」\n\n健太:「どう使うんですか？」\n\n山本先輩:「例えば、販売店社長との会話で...\n\n『最近、アルファードの相場が上がってますね』\n『ジムニーは在庫があればすぐ売れますよね』\n『輸入車は値落ちが早いですから、回転を意識されてますか？』\n\nこういう会話ができると、\n『この営業は業界をわかってる』と信頼される」\n\n健太:「業界の共通言語ですね」", "duration": 35}, {"title": "シーン6: 健太の理解", "content": "健太（心の声）:「相場は需要と供給で動く...\n\n車種、年式、季節、様々な要素が絡む。\nこの知識があれば、顧客と対等に会話できる。\n\n\"業界をわかってる営業\"になろう」\n\n【今日の学び】\n・価格は7つの要素で決まる\n・季節変動を理解し、仕入れ・販売タイミングを意識\n・人気車種の傾向を覚える\n・相場知識は信頼構築の武器になる", "duration": 30}]}', '{"title": "中古車価格を決める要素", "content": "【7つの決定要素】\n1. 車種・グレード\n2. 年式\n3. 走行距離\n4. ボディカラー\n5. 装備・オプション\n6. 修復歴\n7. 車検残\n\n【季節変動】\n高い: 1〜3月、7〜8月\n低い: 4〜6月、10〜12月", "audioText": "相場は需要と供給で動きます。この知識があれば、顧客と対等に会話でき、信頼を得られます。", "highlight": "相場知識は「業界をわかってる営業」の証。信頼構築の武器になる"}', '[{"options": ["大型セダン（高級車）", "軽自動車（実用車）", "スポーツカー（趣味車）", "ミニバン（ファミリー向け）"], "question": "近年の中古車市場で価格が上昇傾向にある車種はどれですか？", "explanation": "軽自動車は燃費の良さと維持費の安さから需要が高く、中古車価格も上昇傾向です。", "correctIndex": 1}, {"options": ["充電インフラの不足", "バッテリー劣化の評価", "デザインの陳腐化", "保険料の高さ"], "question": "電気自動車（EV）の中古車市場における課題はどれですか？", "explanation": "EVはバッテリーの劣化状態が価値に大きく影響しますが、その評価基準が確立されていません。", "correctIndex": 1}, {"options": ["中古車の流通量が増加する", "車両の品質が均一化する", "個人売買が減少する", "オークション相場が安定する"], "question": "サブスクリプションサービスが中古車市場に与える影響はどれですか？", "explanation": "サブスク終了車両が中古車市場に流入することで、流通量の増加が見込まれます。", "correctIndex": 0}]', '{"text": "Price is what you pay. Value is what you get.", "author": "ウォーレン・バフェット", "textJa": "価格は払うもの。価値は得るものだ。"}', '[{"options": [{"text": "「よくわかりません」と正直に言う", "points": 0, "feedback": "業界知識がないと信頼を得にくいです。", "isCorrect": false}, {"text": "「アルファードは相変わらず強いですね。ジムニーも在庫があればすぐ売れる状況が続いてますよね」", "points": 30, "feedback": "具体的な車種名を出して会話できると「業界をわかってる」と思われます。", "isCorrect": true}, {"text": "「上がってますよね」と曖昧に答える", "points": 10, "feedback": "具体性がなく、会話が深まりません。", "isCorrect": false}, {"text": "話題を変える", "points": 5, "feedback": "せっかくの信頼構築の機会を逃しています。", "isCorrect": false}], "situation": "販売店社長と雑談中、相場の話題になりました。", "customerLine": "最近の相場、どう思う？"}]', '{"question": "相場知識をどう商談に活かしますか？", "placeholder": "例: 人気車種の話題で共通の会話を作る、季節変動を踏まえた提案をする"}', '["人気車種5つを覚えて、商談で話題にする", "カーセンサーやグーネットで相場をチェックする習慣をつける", "季節変動を意識した提案をする"]', NULL, NULL, '2026-01-21 17:48:20.662825+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (57, 29, '整備・車検ビジネスの収益構造', '整備は"第二の収益源"', '{"icon": "wrench", "name": "整備ビジネスマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["1〜3月", "7〜8月", "4〜6月", "12月"], "question": "中古車相場が低くなる時期は？", "explanation": "4〜6月は年度末需要の後の谷間で、相場が低くなります。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 収益構造の全体像", "content": "山本先輩:「健太、販売店の収益構造を知ってるか？」\n\n健太:「車を売った利益...ですよね？」\n\n山本先輩:「それだけじゃない」\n\n【中古車販売店の収益内訳】\n・車両販売粗利: 70%\n・整備・車検: 20%\n・その他（保険、ローン手数料等）: 10%\n\n山本先輩:「車両販売は\"集客\"、整備は\"継続収益\"なんだ。\n\n車を売ったお客様が、整備・車検でリピートしてくれると、\n安定した収益基盤ができる」", "duration": 40}, {"title": "シーン2: 整備ビジネスの種類", "content": "山本先輩:「整備ビジネスの種類を教えてやる」\n\n【整備ビジネスの種類と収益性】\n\n①車検（2年に1回の法定検査）\n・単価: 5〜15万円\n・粗利率: 30〜50%\n★ 安定した収益源！\n\n②定期点検（12ヶ月、6ヶ月）\n・単価: 1〜3万円\n・顧客との接点を維持\n\n③一般整備（オイル交換、タイヤ等）\n・単価は小さいが頻度が高い\n・「ついで」の追加整備で単価アップ\n\n④修理・板金\n・単価: 数万円〜数十万円\n・技術力が必要", "duration": 45}, {"title": "シーン3: 整備部門の課題", "content": "山本先輩:「でも、整備部門には課題もある」\n\n【整備部門の主な課題】\n\n❶整備士不足\n若手のなり手が減少、離職率も高い\n\n❷業務効率の低さ\n見積もり作成に時間がかかる、手書き伝票、二重入力\n\n❸顧客管理の不備\n車検期限の把握ができていない、リマインド連絡が漏れる\n\n❹収益管理の曖昧さ\n整備単体での収益が見えない、どの作業が儲かっているか不明\n\n山本先輩:「これらの課題は、Symphony整備請求で解決できる」", "duration": 40}], "part2": [{"title": "シーン4: Symphony整備請求の価値", "content": "健太:「具体的にどう解決するんですか？」\n\n山本先輩:「こういう機能がある」\n\n【Symphony整備請求の機能】\n\n①見積もり・請求の効率化\n過去の整備履歴を参照して素早く見積もり\n\n②車検・点検リマインド\n顧客の車検期限を自動管理、期限前に自動リマインド\n\n③整備履歴管理\n過去の整備内容を一元管理、顧客ごとの整備カルテ\n\n④収益分析\n作業別、担当者別の売上集計、粗利率の可視化\n\n⑤販売管理との連携\n販売したお客様の情報が自動連携", "duration": 40}, {"title": "シーン5: 商談での活用", "content": "山本先輩:「整備部門を持ってる販売店には、\nこの視点で提案できる」\n\n健太:「どう切り出せばいいですか？」\n\n山本先輩:「例えば...\n\n『整備部門の収益、把握されてますか？』\n『車検のリマインド、どうされてますか？』\n『販売したお客様のフォロー、できてますか？』\n\n整備部門の課題を聞き出して、\nSymphony整備請求を提案する」\n\n健太:「販売管理だけじゃないんですね」\n\n山本先輩:「そう。トータルで提案できると、\n導入後の顧客満足度も高くなる」", "duration": 35}, {"title": "シーン6: 健太の理解", "content": "健太（心の声）:「整備は第二の収益源...\n\n車両販売で集客して、\n整備・車検でリピートしてもらう。\nこれが販売店の収益モデルだ。\n\nSymphony整備請求を提案できれば、\n顧客の経営課題をトータルで解決できる」\n\n【今日の学び】\n・整備は販売店の「第二の収益源」\n・車検は安定した継続収益\n・整備部門には効率化・顧客管理の課題がある\n・Symphony整備請求でトータル提案が可能", "duration": 30}]}', '{"title": "中古車販売店の収益構造", "content": "【収益内訳】\n・車両販売粗利: 70%\n・整備・車検: 20%\n・その他: 10%\n\n【整備部門の課題】\n・整備士不足\n・業務効率の低さ\n・顧客管理の不備\n・収益管理の曖昧さ\n\n→ Symphony整備請求で解決", "audioText": "整備は第二の収益源です。車を売ったお客様が整備・車検でリピートすると、安定した収益基盤ができます。", "highlight": "車両販売は「集客」、整備は「継続収益」。両輪で経営を支える"}', '[{"options": ["全国規模の店舗ネットワーク", "テレビCMによるブランド認知", "自社オークションの運営力", "IT投資によるデータ活用"], "question": "大手買取チェーンの競争優位性として最も重要なのはどれですか？", "explanation": "自社AAを持つことで仕入れと販売の両面で有利なポジションを確保できます。", "correctIndex": 2}, {"options": ["新車販売の減少を補完する", "整備入庫の機会を増やす", "認定中古車で利益率を上げる", "上記すべてが狙いである"], "question": "ディーラーの中古車事業強化の狙いとして正しいのはどれですか？", "explanation": "ディーラーの中古車強化には、収益補完・整備入庫・高利益率など複数の狙いがあります。", "correctIndex": 3}, {"options": ["手数料の価格設定", "品質保証の仕組み作り", "決済システムの構築", "出品車両数の確保"], "question": "個人間売買プラットフォームの課題として最も大きいのはどれですか？", "explanation": "個人間売買では品質トラブルのリスクがあり、保証の仕組みが重要な課題です。", "correctIndex": 1}]', '{"text": "The best way to predict the future is to create it.", "author": "ピーター・ドラッカー", "textJa": "未来を予測する最善の方法は、それを創ることだ。"}', '[{"options": [{"text": "「整備は大変ですよね」と共感する", "points": 10, "feedback": "共感だけで終わっています。", "isCorrect": false}, {"text": "「Symphony整備請求で、作業別の収益分析ができます。どの作業が儲かってるか見える化できますよ」", "points": 30, "feedback": "顧客の課題「儲かってる実感がない」に対する解決策を提示しています。", "isCorrect": true}, {"text": "「販売に集中した方がいいですよ」とアドバイスする", "points": 0, "feedback": "顧客の事業を否定しています。", "isCorrect": false}, {"text": "「整備士を増やしたらどうですか」と提案する", "points": 5, "feedback": "人手不足の中、現実的でない提案です。", "isCorrect": false}], "situation": "整備工場を持つ販売店を訪問。整備部門の話題になりました。", "customerLine": "整備部門、忙しいんだけど儲かってる実感がないんだよね"}]', '{"question": "整備部門を持つ顧客にどうアプローチしますか？", "placeholder": "例: 整備収益の見える化、車検リマインドの自動化を提案する"}', '["顧客に「整備部門の課題」を聞いてみる", "Symphony整備請求の機能を説明できるようにする", "販売管理と整備請求のセット提案を考える"]', NULL, NULL, '2026-01-21 17:48:21.586227+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (59, 31, '輸出市場と海外販路', '日本車は世界が欲しがる', '{"icon": "globe", "name": "輸出マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["使用本拠から5km以内", "使用本拠から2km以内", "使用本拠から10km以内", "距離制限なし"], "question": "車庫証明の条件で正しいのは？", "explanation": "車庫証明は使用の本拠から直線距離2km以内が条件です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 輸出市場の規模", "content": "山本先輩:「健太、日本の中古車輸出って知ってるか？」\n\n健太:「海外に売るってことですよね？」\n\n山本先輩:「年間約130万台が輸出されてる。\n巨大な市場だ」\n\n【日本の中古車輸出が人気の理由】\n✓ 品質が高い（日本の整備・車検制度）\n✓ 走行距離が少ない（平均1万km/年）\n✓ 右ハンドル（旧英連邦諸国で需要）\n✓ 4WD・SUVが豊富（アフリカで人気）\n✓ 信頼の「Made in Japan」ブランド\n\n山本先輩:「日本車は世界が欲しがってる」", "duration": 40}, {"title": "シーン2: 主要仕向地", "content": "山本先輩:「主要な仕向地を教えてやる」\n\n【主要仕向地と人気車種】\n\n🌍 アフリカ（最大市場）\n・主要国: ケニア、タンザニア、ウガンダ\n・人気車種: ランドクルーザー、ハイエース、ハイラックス\n・特徴: 悪路に強い車が圧倒的人気\n\n🌏 東南アジア\n・主要国: マレーシア、フィリピン、ミャンマー\n・人気車種: セダン、コンパクトカー\n・特徴: 右ハンドル国が多い\n\n🇷🇺 ロシア・中央アジア\n・人気車種: SUV、セダン\n・特徴: 寒冷地対応車が人気\n\n🇳🇿 オセアニア\n・人気車種: ファミリーカー、ハイブリッド\n・特徴: 右ハンドル、品質重視", "duration": 45}, {"title": "シーン3: 販売店の活用方法", "content": "健太:「販売店は輸出とどう関わるんですか？」\n\n山本先輩:「いくつかパターンがある」\n\n【販売店の輸出ビジネス活用】\n\n①輸出業者への売却\n国内で売れ残った車を輸出業者に販売\n→ 長期在庫の処分手段として活用\n\n②輸出サイトへの出品\nBE FORWARD、SBT等の輸出サイトに出品\n→ 海外バイヤーから直接注文\n→ ワンプラとの連携で出品も可能\n\n③自社で輸出（大規模店向け）\n→ 利益率は高いが、手間とリスクも大きい\n\n山本先輩:「国内で売れない車でも、海外では売れる。\nこれが輸出の価値だ」", "duration": 40}], "part2": [{"title": "シーン4: 輸出向けの車種", "content": "山本先輩:「どんな車が輸出向けか、覚えておけ」\n\n【輸出で高値がつく車種】\n・トヨタ ランドクルーザー（アフリカで神格化）\n・トヨタ ハイエース（世界中で人気）\n・トヨタ ハイラックス（耐久性が評価）\n・日産 サファリ/パトロール\n・三菱 パジェロ\n\n【輸出に向かない車種】\n・軽自動車（海外では需要少ない）\n・ハイブリッド車（整備インフラ不足）\n・高級輸入車（部品供給の問題）\n\n山本先輩:「国内相場と輸出相場は違う。\nこの知識があると、在庫処分の提案ができる」", "duration": 40}, {"title": "シーン5: 商談での活用", "content": "山本先輩:「輸出の話は商談でも使える」\n\n健太:「どう使うんですか？」\n\n山本先輩:「例えば、長期在庫の話になった時...\n\n『この車種、国内だと厳しいですけど、\n輸出なら需要ありますよ。\nワンプラ経由で輸出業者に流せます』\n\nこういう提案ができると、\n顧客の課題解決の幅が広がる」\n\n健太:「在庫処分の選択肢を増やせるんですね」\n\n山本先輩:「そう。国内だけで考えると行き詰まる車も、\n海外視点で見ると活路がある」", "duration": 35}, {"title": "シーン6: 健太の理解", "content": "健太（心の声）:「日本車は世界が欲しがる...\n\n輸出市場は年間130万台。\n国内で売れない車も、海外では売れる。\n\nこの視点を持っていると、\n顧客の在庫処分の相談に乗れる。\n提案の幅が広がる」\n\n【今日の学び】\n・日本の中古車輸出は年間約130万台\n・アフリカが最大市場、4WD・SUVが人気\n・長期在庫の処分手段として輸出を活用\n・ワンプラ経由で輸出業者に流せる", "duration": 30}]}', '{"title": "中古車輸出市場", "content": "【規模】年間約130万台\n\n【人気の理由】\n・高品質（車検制度）\n・低走行距離\n・右ハンドル需要\n・Made in Japanブランド\n\n【主要仕向地】\nアフリカ、東南アジア、ロシア、オセアニア", "audioText": "日本車は世界が欲しがっています。輸出市場を知っていると、顧客の在庫処分の相談に乗れます。", "highlight": "国内で売れない車も海外では売れる。輸出は在庫処分の選択肢"}', '[{"options": ["現状販売なら一切の責任を負わない", "隠れた瑕疵は契約内容に関わらず責任あり", "業者間取引には適用されない", "走行距離の誤差は瑕疵に当たらない"], "question": "中古車販売における「瑕疵担保責任」について正しいのはどれですか？", "explanation": "売主が知りながら告げなかった瑕疵については、免責特約があっても責任を負います。", "correctIndex": 1}, {"options": ["全車両の整備記録の保管", "本人確認と取引記録の保存", "第三者機関による品質検査", "瑕疵担保保険への加入"], "question": "古物営業法において中古車販売業者に義務付けられているのはどれですか？", "explanation": "古物商は取引の相手方の本人確認と、取引記録の保存が義務付けられています。", "correctIndex": 1}, {"options": ["購入後に価格が下がった場合", "重要事項について事実と異なる説明", "他店より高い価格で購入した場合", "納車が予定日より遅れた場合"], "question": "消費者契約法で「取消し可能」となるケースはどれですか？", "explanation": "重要事項について事実と異なる説明（不実告知）があった場合、契約を取り消せます。", "correctIndex": 1}]', '{"text": "Think globally, act locally.", "author": "ルネ・デュボス", "textJa": "グローバルに考え、ローカルに行動せよ。"}', '[{"options": [{"text": "「値下げしましょう」と提案する", "points": 10, "feedback": "利益が減る提案です。他の選択肢を検討すべきです。", "isCorrect": false}, {"text": "「ランドクルーザーはアフリカで人気です。輸出業者に流してみませんか？ワンプラ経由で出品できますよ」", "points": 30, "feedback": "輸出市場の知識を活かした提案です。顧客の課題解決につながります。", "isCorrect": true}, {"text": "「仕方ないですね」と同情する", "points": 0, "feedback": "解決策を提示できていません。", "isCorrect": false}, {"text": "「もう少し待ちましょう」とアドバイスする", "points": 5, "feedback": "在庫は寝かせると腐ります。積極的な対策が必要です。", "isCorrect": false}], "situation": "販売店社長から「3ヶ月売れないランドクルーザーがある」と相談されました。", "customerLine": "古いモデルだから国内じゃ厳しいんだよね"}]', '{"question": "輸出市場の知識をどう営業に活かしますか？", "placeholder": "例: 長期在庫の相談に対して、輸出という選択肢を提案する"}', '["輸出で人気の車種を覚える", "長期在庫の相談に「輸出」の選択肢を提案する", "ワンプラの輸出連携を説明できるようにする"]', NULL, NULL, '2026-01-21 17:48:23.86326+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (60, 32, '業界トレンド', '変化を恐れず、波に乗れ', '{"icon": "lightbulb", "name": "トレンドマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["約30万台", "約70万台", "約130万台", "約200万台"], "question": "日本の中古車輸出台数は年間約何万台？", "explanation": "年間約130万台が輸出されています。巨大な市場です。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: CASEとは", "content": "山本先輩:「健太、CASEって聞いたことあるか？」\n\n健太:「ケース...事例のことですか？」\n\n山本先輩:「違う。自動車業界の大変革を表す言葉だ」\n\n【CASE】\n\nC: Connected（コネクテッド）\n車がインターネットに常時接続、OTAでのソフトウェア更新\n\nA: Autonomous（自動運転）\nレベル1〜5の自動運転、運転支援機能の普及\n\nS: Shared（シェアリング）\nカーシェア、ライドシェア、「所有」から「利用」へ\n\nE: Electric（電動化）\nEV、HV、PHV、FCVの普及、2035年問題\n\n山本先輩:「この4つが業界を根本から変えようとしてる」", "duration": 45}, {"title": "シーン2: EVの現状と課題", "content": "山本先輩:「特にEVは注目だ」\n\n【EV（電気自動車）の現状】\n国内EV販売台数（2024年）: 約10万台（新車の約3%）\n\n【中古EV市場の課題】\n\n❶バッテリー劣化の懸念\n航続距離の低下、交換費用が高額（50〜100万円）\n\n❷残価予測が難しい\n技術進化が早く、旧型の価値下落が激しい\n\n❸充電インフラの問題\n充電スタンドの設置状況が地域で異なる\n\n❹整備ノウハウの不足\n高電圧を扱う専門資格が必要\n\n山本先輩:「中古EV市場はこれから伸びるが、課題も多い」", "duration": 45}, {"title": "シーン3: サブスクリプション", "content": "山本先輩:「もう一つ、サブスクも押さえておけ」\n\n【車のサブスクリプション】\n月額定額で車を「利用」するサービス\n例: KINTO（トヨタ）、SOMPOで乗ーる等\n\n市場規模（2024年）: 約2,000億円\n予測（2030年）: 約1兆円\n\n【中古車販売店への影響】\n\n⚠️ 脅威\n・「所有しない」顧客の増加\n・若年層の車離れ加速\n・サブスク落ち車両の大量流入\n\n✅ チャンス\n・サブスク落ち車両は状態が良い\n・新たな仕入れルートとして活用\n・自社でサブスク提供も可能", "duration": 40}], "part2": [{"title": "シーン4: 変化の時代を生き抜く戦略", "content": "山本先輩:「変化を恐れてたら、置いていかれる。\n波に乗る戦略が必要だ」\n\n【変化の時代を生き抜く4つの戦略】\n\n①デジタル化の推進\nオンライン商談、バーチャル展示、業務のIT化\n→ Symphonyの導入価値がここにある\n\n②顧客との長期関係構築\n車両販売だけでなく、整備・保険で継続接点\n→ LTV（顧客生涯価値）の最大化\n\n③新しい収益モデルの検討\n自社サブスクサービス、EV充電インフラ\n\n④専門性の強化\n特定車種への特化、EV整備の技術習得", "duration": 40}, {"title": "シーン5: Symphonyの価値", "content": "山本先輩:「これらの戦略に、Symphonyがどう貢献するか」\n\n健太:「教えてください」\n\n山本先輩:「デジタル化の基盤になる。\n在庫管理、顧客管理、整備管理...\n全てをデジタルで一元管理できる。\n\n変化の時代を乗り切るには、\nまず\"今の業務\"を効率化することが必要だ。\nそうしないと、新しいことに手が回らない」\n\n健太:「効率化して、余力を作る。\nその余力で新しい取り組みができる」\n\n山本先輩:「そう。Symphonyは変化対応の\"基盤\"になる」", "duration": 35}, {"title": "シーン6: カテゴリC完了", "content": "健太（心の声）:「変化を恐れず、波に乗れ...\n\nCASE、EV、サブスク...業界は大きく変わろうとしてる。\nでも、変化はチャンスでもある。\n\nSymphonyは、その変化に対応するための基盤。\nこれを顧客に伝えられるようになろう」\n\n【今日の学び】\n・CASEが自動車業界を根本から変える\n・中古EV市場は課題と可能性が共存\n・サブスクは脅威でありチャンス\n・Symphonyは変化対応の「基盤」になる\n\n🎊 カテゴリC「業界知識」コンプリート！\n10個のバッジを獲得しました！", "duration": 35}]}', '{"title": "CASE — 自動車業界の大変革", "content": "【C】Connected: 常時接続\n【A】Autonomous: 自動運転\n【S】Shared: シェアリング\n【E】Electric: 電動化\n\n【変化への対応戦略】\n①デジタル化の推進\n②顧客との長期関係構築\n③新しい収益モデルの検討\n④専門性の強化", "audioText": "CASEが自動車業界を変えています。変化を恐れず、波に乗りましょう。Symphonyはその基盤になります。", "highlight": "Symphonyは変化対応の「基盤」になる"}', '[{"options": ["個人所有ニーズが減少する", "中古車価格が全体的に上昇する", "車両の平均使用年数が伸びる", "輸入中古車の需要が増える"], "question": "MaaS（Mobility as a Service）が中古車市場に与える影響はどれですか？", "explanation": "MaaSの普及により「所有から利用へ」のシフトが進み、個人の車両所有が減少する可能性があります。", "correctIndex": 0}, {"options": ["中古車の需要が大幅に増加する", "技術の陳腐化で価値が下がりやすい", "整備ビジネスの収益が拡大する", "個人間売買が活発になる"], "question": "自動運転技術の普及が中古車市場に与える影響はどれですか？", "explanation": "自動運転技術は進化が早く、旧世代の技術搭載車は価値が下がりやすい傾向があります。", "correctIndex": 1}, {"options": ["大量仕入れによる価格競争力", "顧客との長期的な関係構築", "全国展開による規模の拡大", "専門特化による差別化"], "question": "中古車販売店が今後強化すべき領域として最も重要なのはどれですか？", "explanation": "価格競争には限界があり、アフターサービスを通じた顧客との長期関係が重要になります。", "correctIndex": 1}]', '{"text": "The only thing that is constant is change.", "author": "ヘラクレイトス", "textJa": "変化だけが唯一の不変である。"}', '[{"options": [{"text": "「大丈夫ですよ」と励ます", "points": 5, "feedback": "根拠のない励ましは不安を解消しません。", "isCorrect": false}, {"text": "「まずは今の業務を効率化して、変化に対応する余力を作りましょう。Symphonyでその基盤が作れます」", "points": 30, "feedback": "変化への具体的な対応策を提示しています。Symphonyの価値も伝わります。", "isCorrect": true}, {"text": "「確かに厳しいかもしれませんね」と同意する", "points": 0, "feedback": "不安を増幅させています。", "isCorrect": false}, {"text": "「EVに特化したらどうですか」とアドバイスする", "points": 10, "feedback": "唐突で現実的でない提案です。", "isCorrect": false}], "situation": "販売店社長から「業界の将来が不安」と相談されました。", "customerLine": "EVとかサブスクとか、うちみたいな小さい店はどうなるんだろうね"}]', '{"question": "業界トレンドをどう顧客との会話に活かしますか？", "placeholder": "例: 変化への不安を聞き出し、効率化による余力作りを提案する"}', '["CASEの意味を説明できるようにする", "業界ニュースを定期的にチェックする", "Symphonyを「変化対応の基盤」として提案する"]', NULL, NULL, '2026-01-21 17:48:24.65664+00', '2026-01-27 09:02:21.583262+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (61, 33, '影響力の6原則', '人の心を動かす科学を知る', '{"icon": "sparkles", "name": "影響力の使い手"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["売り込む", "説得する", "聴く", "押す"], "question": "営業で最も大切な姿勢は？", "explanation": "まず顧客の話を聴くことが信頼構築の第一歩でしたね。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: なぜか売れる先輩", "content": "（営業フロアで）\n\n健太:「山本先輩、また契約取れたんですか？」\n\n山本先輩:「ああ、さっきの商談でね」\n\n健太:「先輩の商談、見てると不思議なんです。\n　　強引に売り込んでるわけじゃないのに、\n　　なぜか顧客が『お願いします』って言う...」\n\n山本先輩:「それは『影響力の原則』を\n　　　　使ってるからだよ」\n\n健太:「影響力の原則...？」\n\n山本先輩:「心理学者チャルディーニが発見した、\n　　　　人の心を動かす6つの原則だ。\n　　　　これを知ってるかどうかで、\n　　　　営業の成果は大きく変わる」", "duration": 45}, {"title": "シーン2: チャルディーニの6原則", "content": "山本先輩:「チャルディーニの6原則を教えよう」\n\n【影響力の6原則】\n\n1️⃣ 返報性（Reciprocity）\n人は何かをもらうと、お返しをしたくなる\n\n2️⃣ 一貫性（Commitment & Consistency）\n人は自分の言動に一貫性を保とうとする\n\n3️⃣ 社会的証明（Social Proof）\n人は他者の行動を参考に判断する\n\n4️⃣ 好意（Liking）\n人は好きな人の言うことを聞きやすい\n\n5️⃣ 権威（Authority）\n人は専門家や権威者の言葉を信じやすい\n\n6️⃣ 希少性（Scarcity）\n人は手に入りにくいものに価値を感じる\n\n山本先輩:「この6つを理解すれば、\n　　　　なぜ人が動くかがわかる」", "duration": 55}, {"title": "シーン3: 営業での活用例", "content": "健太:「具体的にどう使うんですか？」\n\n山本先輩:「営業での使い方を見てみよう」\n\n【営業での活用例】\n\n返報性:\n→ 先に価値を提供する（情報、資料、サンプル）\n\n一貫性:\n→ 小さなYESを積み重ねる\n\n社会的証明:\n→ 「同業他社も導入しています」\n\n好意:\n→ 共通点を見つけ、信頼関係を築く\n\n権威:\n→ 専門知識、実績、資格を示す\n\n希少性:\n→ 「今月限定」「残り3枠」\n\n山本先輩:「ただし、悪用は厳禁だ。\n　　　　顧客のためになることに使う。\n　　　　それが長期的な成功の秘訣だ」", "duration": 50}], "part2": [{"title": "シーン4: 返報性の実践", "content": "山本先輩:「まずは『返報性』から実践してみよう」\n\n健太:「具体的に何を与えればいいですか？」\n\n山本先輩:「見返りを求めずに、まず与える」\n\n【与えられるもの】\n\n・業界の最新情報\n・競合の動向\n・成功事例\n・お役立ち資料\n・自分の時間と労力\n・紹介\n\n山本先輩:「重要なのは、\n　　　　売り込みの前に与えること。\n　　　　『この人は自分のために\n　　　　動いてくれる』と思ってもらえれば、\n　　　　顧客は自然と心を開く」", "duration": 45}, {"title": "シーン5: 健太の実践", "content": "（次の商談で）\n\n健太:「社長、今日は提案の前に、\n　　先日お話しされていた\n　　採用の件で情報をお持ちしました」\n\n社長:「おお、わざわざ調べてくれたのか」\n\n健太:「同業の方に聞いてみたら、\n　　こんな方法で成功されてて...」\n\n（資料を渡す）\n\n社長:「これは助かる！ありがとう。\n　　...ところで、今日の本題は何だった？」\n\n健太:「はい、新しいサービスのご提案です」\n\n社長:「いいよ、聞かせてくれ」\n\n（商談後）\n\n健太:「先輩！聴く姿勢が全然違いました！」", "duration": 50}, {"title": "シーン6: 影響力の責任", "content": "山本先輩:「どうだった？」\n\n健太:「返報性、すごいです！\n　　でも、これって操作してる感じが...」\n\n山本先輩:「いい質問だ。\n　　　　影響力の原則は『武器』だ。\n　　　　使い方次第で良くも悪くもなる」\n\n【影響力を使う際の倫理】\n\n✅ 顧客のためになることに使う\n✅ 嘘や誇張をしない\n✅ 長期的な関係を重視する\n✅ 顧客が後悔しない提案をする\n\n❌ 自分の利益だけを考える\n❌ 騙したり、煽ったりする\n❌ 短期的な成果だけを追う\n\n山本先輩:「顧客の人生を良くするために\n　　　　影響力を使う。\n　　　　それが営業の使命だ」\n\n【今日の学び】\n「人の心を動かす科学を知る」", "duration": 40}]}', '{"title": "チャルディーニの影響力6原則", "content": "1. 返報性 - 与えれば返ってくる\n2. 一貫性 - 言動の一致を求める\n3. 社会的証明 - 他者の行動を参考にする\n4. 好意 - 好きな人の話を聞く\n5. 権威 - 専門家を信じる\n6. 希少性 - 限られたものに価値を感じる", "audioText": "影響力の6原則を理解し、顧客のために正しく活用しましょう。", "highlight": "影響力は顧客のために使う。それが長期的な成功の秘訣"}', '[{"options": ["見返りを求めて与える", "先に価値を提供する", "値引きを要求する", "競合の悪口を言う"], "question": "返報性の原則を営業で活用するには？", "explanation": "見返りを求めずに先に与えることで、顧客は自然とお返しをしたくなります。", "correctIndex": 1}, {"options": ["自分の売上を上げること", "顧客のためになることに使うこと", "テクニックを磨くこと", "競合に勝つこと"], "question": "影響力の原則を使う際に最も大切なのは？", "explanation": "影響力は顧客のために使う。それが長期的な成功につながります。", "correctIndex": 1}]', '{"text": "Influence is not about manipulation; it''s about understanding how to communicate value effectively.", "author": "ロバート・チャルディーニ「影響力の武器」より", "textJa": "人を動かすには、まず相手の心を理解することから始めよ。"}', '[{"options": [{"text": "すぐに製品説明を始める", "points": 5, "feedback": "まず価値を提供してから提案しましょう。返報性の原則です。", "isCorrect": false}, {"text": "「まず、御社のお役に立てる情報をお持ちしました」と価値を先に提供", "points": 30, "feedback": "返報性の原則を活用した良いアプローチです。", "isCorrect": true}, {"text": "「今月限定のキャンペーンがあります」と希少性を煽る", "points": 10, "feedback": "関係構築前の希少性訴求は逆効果になることがあります。", "isCorrect": false}], "situation": "新規顧客との初回商談。何から始めますか？", "customerLine": "今日はどんなご提案ですか？"}, {"options": [{"text": "「A社は品質が悪いですよ」と競合を否定", "points": 0, "feedback": "競合の悪口は信頼を損ないます。", "isCorrect": false}, {"text": "「同業の○○社様も弊社を選ばれました」と社会的証明を示す", "points": 30, "feedback": "社会的証明は意思決定の後押しになります。", "isCorrect": true}, {"text": "「どちらでもいいと思います」と中立を装う", "points": 5, "feedback": "自社の価値を伝える機会を逃しています。", "isCorrect": false}], "situation": "顧客が競合製品と迷っています。", "customerLine": "A社の製品とどっちがいいか迷ってるんですよね..."}]', '{"question": "これまでの営業で、無意識に影響力の原則を使っていた場面はありますか？", "placeholder": "例: 事例を紹介して安心してもらった（社会的証明）、先に情報提供して信頼を得た（返報性）"}', '["商談前に顧客に提供できる価値を準備する", "導入事例を3つ以上用意しておく", "自分の専門性を明確に伝える", "影響力は顧客のために使うことを忘れない"]', '{"title": "影響力6原則の活用プラン", "fields": [{"label": "返報性：先に提供できる価値は？", "placeholder": "例: 業界レポート、成功事例資料、競合情報"}, {"label": "社会的証明：紹介できる導入事例は？", "placeholder": "例: 同業の○○社、同規模の△△社"}, {"label": "権威：示せる専門性・実績は？", "placeholder": "例: 業界10年の経験、○○件の導入実績"}], "description": "次の商談で使う影響力の原則を計画しましょう。"}', NULL, '2026-01-21 17:48:25.638423+00', '2026-01-21 17:48:25.638423+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (62, 34, '一貫性の原理とフット・イン・ザ・ドア', '小さなYESが大きなYESを生む', '{"icon": "check-circle", "name": "YESの達人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["一貫性", "返報性", "希少性", "権威"], "question": "影響力の6原則で「先に与える」のは？", "explanation": "返報性の原則は「先に与えることでお返しをもらえる」でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 突然のお願いは断られる", "content": "（テレアポ後、落ち込む健太）\n\n健太:「また断られた...\n　　『今は忙しい』って...」\n\n山本先輩:「どんな風にアポを取ろうとした？」\n\n健太:「『1時間ほどお時間いただけませんか』\n　　って言ったんですけど...」\n\n山本先輩:「いきなり1時間は\n　　ハードルが高すぎるな」\n\n健太:「でも、ちゃんと説明するには\n　　1時間必要ですよね？」\n\n山本先輩:「そこで『一貫性の原理』と\n　　　　『フット・イン・ザ・ドア』だ」", "duration": 45}, {"title": "シーン2: 一貫性の原理とは", "content": "山本先輩:「人間には『一貫性の原理』がある」\n\n【一貫性の原理】\n人は、一度取った立場や発言に\n一貫性を保とうとする心理傾向がある\n\n山本先輩:「例えば...」\n\n「環境問題に関心ありますか？」→「はい」\n「このエコ製品に興味ありますか？」→「はい」と言いやすい\n\n「健康に気を使ってますか？」→「はい」\n「このサプリに興味ありますか？」→「はい」と言いやすい\n\n山本先輩:「一度『はい』と言った人は、\n　　　　その後も『はい』と言いやすくなる。\n　　　　これを営業に活用するんだ」", "duration": 50}, {"title": "シーン3: フット・イン・ザ・ドア技法", "content": "山本先輩:「これを応用したのが\n　　　　『フット・イン・ザ・ドア』だ」\n\n【フット・イン・ザ・ドア技法】\nまず小さなお願いを承諾させ、\nその後で本命のお願いをする\n\n1965年、心理学者フリードマンとフレイザーの実験:\n「安全運転のステッカーを貼ってください」\n→ 承諾した人の76%が、後日\n　 大きな看板の設置にも同意\n\nいきなり看板をお願い → 17%しか同意しない\n\n山本先輩:「いきなり大きなお願いをするより、\n　　　　小さなお願いから始める方が\n　　　　成功率が格段に上がるんだ」", "duration": 50}], "part2": [{"title": "シーン4: 営業での活用", "content": "山本先輩:「営業での具体例を見てみよう」\n\n【フット・イン・ザ・ドアの営業活用】\n\n❌ いきなり大きなお願い\n「1時間の商談をお願いします」→ 断られやすい\n「このシステムを導入してください」→ ハードルが高い\n\n✅ 小さなお願いから始める\n「5分だけお話しできますか？」→ YES\n「資料だけお送りしてもいいですか？」→ YES\n「資料を見ていただけましたか？」→ YES\n「15分だけお時間いただけますか？」→ YES\n「デモをお見せしてもいいですか？」→ YES\n「検討いただけますか？」→ YES\n\n山本先輩:「小さなYESを積み重ねることで、\n　　　　最終的な大きなYESにつながるんだ」", "duration": 50}, {"title": "シーン5: 健太のリベンジ", "content": "（翌日のテレアポ）\n\n健太:「お忙しいところ恐れ入ります。\n　　5分だけお時間よろしいですか？」\n\n顧客:「5分なら...いいですよ」\n\n健太:「ありがとうございます。\n　　御社の業界で話題の事例がありまして、\n　　資料をお送りしてもよろしいですか？」\n\n顧客:「ああ、資料だけなら」\n\n健太:「ありがとうございます！\n　　来週、ご感想をお聞きするために\n　　お電話してもよろしいですか？」\n\n顧客:「...いいですよ」\n\n（1週間後、商談のアポ獲得成功！）\n\n健太:「先輩！アポ取れました！」", "duration": 45}, {"title": "シーン6: 質問でYESを積み重ねる", "content": "山本先輩:「商談中もYESを積み重ねろ」\n\n【商談中のYES積み重ね】\n\n「在庫管理、大変ですよね？」→ YES\n「手作業だと時間かかりますよね？」→ YES\n「ミスも起きやすいですよね？」→ YES\n「自動化できたら楽ですよね？」→ YES\n「弊社のシステム、試してみませんか？」→ YES\n\n山本先輩:「一貫性の原理で、\n　　　　YESを言い続けた人は\n　　　　最後もYESと言いやすい。\n　　　　これがクロージングの秘訣だ」\n\n健太:「小さなYESが大きなYESを生む...\n　　覚えておきます！」\n\n【今日の学び】\n「小さなYESが大きなYESを生む」", "duration": 45}]}', '{"title": "フット・イン・ザ・ドア技法", "content": "1. まず小さなお願いをする\n2. 承諾を得る（小さなYES）\n3. 少し大きなお願いをする\n4. 承諾を得る（中くらいのYES）\n5. 本命のお願いをする\n6. 承諾を得やすい（大きなYES）", "audioText": "小さなYESを積み重ねることで、最終的な成約につながりやすくなります。", "highlight": "一度YESと言った人は、一貫性を保つためにYESと言い続けやすい"}', '[{"options": ["大きなお願いから始める", "小さなお願いから始める", "何もお願いしない", "一度に全部お願いする"], "question": "フット・イン・ザ・ドア技法の基本は？", "explanation": "小さなお願いから始め、徐々に大きなお願いへと進めます。", "correctIndex": 1}, {"options": ["毎日同じことをする", "自分の言動に一貫性を保とうとする心理", "価格を一定に保つ", "品質を均一にする"], "question": "一貫性の原理とは？", "explanation": "人は一度取った立場や発言に一貫性を保とうとします。", "correctIndex": 1}]', '{"text": "A small yes leads to a bigger yes.", "author": "Symphony営業格言", "textJa": "小さなYESの積み重ねが、大きなYESへの階段となる。"}', '[{"options": [{"text": "「1時間の商談をお願いできませんか？」", "points": 5, "feedback": "いきなり大きなお願いはハードルが高すぎます。", "isCorrect": false}, {"text": "「5分だけお時間いただけますか？」", "points": 30, "feedback": "小さなお願いから始めるフット・イン・ザ・ドアです。", "isCorrect": true}, {"text": "「また電話します」と切る", "points": 10, "feedback": "チャンスを逃しています。小さなお願いを試しましょう。", "isCorrect": false}], "situation": "新規顧客にテレアポしています。", "customerLine": "今ちょっと忙しいんですけど..."}, {"options": [{"text": "「今日決めてください！」と押す", "points": 0, "feedback": "押しすぎると逆効果です。", "isCorrect": false}, {"text": "「まずは無料トライアルから始めてみませんか？」と小さなステップを提案", "points": 30, "feedback": "小さなYESから始める良いアプローチです。", "isCorrect": true}, {"text": "「わかりました」と諦める", "points": 5, "feedback": "諦めるのは早いです。小さなステップを提案しましょう。", "isCorrect": false}], "situation": "商談中、クロージングの場面です。", "customerLine": "うーん、まだ決められないな..."}]', '{"question": "過去に「いきなり大きなお願い」をして断られた経験はありますか？", "placeholder": "例: 初回電話でいきなり商談を申し込んで断られた。次回は資料送付から始める"}', '["テレアポは「5分だけ」から始める", "商談中、小さな質問でYESを積み重ねる", "いきなり契約ではなく、トライアルを提案する", "段階的なアプローチを設計する"]', '{"title": "YESの階段設計", "fields": [{"label": "最小のお願い（最初のYES）", "placeholder": "例: 5分だけお話しできますか？ / 資料をお送りしてもいいですか？"}, {"label": "中間のお願い（2-3番目のYES）", "placeholder": "例: 15分の打ち合わせ / デモのご覧いただく"}, {"label": "最終のお願い（ゴール）", "placeholder": "例: 本契約のご検討 / トライアル開始"}], "description": "商談でのYESの積み重ね方を設計しましょう。"}', NULL, '2026-01-21 17:48:26.335291+00', '2026-01-21 17:48:26.335291+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (63, 35, '返報性の原理', '与える者が受け取る', '{"icon": "gift", "name": "ギバー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["大きなお願いから", "小さなお願いから", "何もお願いしない", "一度に全部"], "question": "フット・イン・ザ・ドアの基本は？", "explanation": "小さなお願いから始め、徐々に大きなお願いへ進めましたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: デパートの試食", "content": "（休日、山本先輩と健太がデパートで）\n\n山本先輩:「健太、あの試食コーナー見てみろ」\n\n試食スタッフ:「いかがですか？新商品の\n　　　　　　チョコレートです」\n\n健太:「いただきます...おいしい！」\n\n試食スタッフ:「よかったら、お一ついかがですか？」\n\n健太:「...じゃあ、一箱ください」\n\n（購入後）\n\n健太:「あれ、買うつもりなかったのに...」\n\n山本先輩:「それが『返報性の原理』だ。\n　　　　何かをもらうと、お返しをしたくなる」", "duration": 45}, {"title": "シーン2: 返報性の科学", "content": "山本先輩:「返報性は人類共通の心理原則だ」\n\n【返報性の原理】\n人は何かをしてもらうと、\nお返しをしなければならないと感じる\n\n【なぜ返報性が存在するか】\n・人類の生存戦略として進化\n・社会的な協力関係の基盤\n・「借りを作る」という感覚\n\n【研究事例：コーラの実験】\n実験者が先にコーラをおごった場合、\nおごらなかった場合と比べて、\n宝くじの購入枚数が2倍に\n\n山本先輩:「先に与えることで、\n　　　　相手は自然と『お返し』を\n　　　　したくなるんだ」", "duration": 50}, {"title": "シーン3: 営業での返報性", "content": "山本先輩:「営業で返報性をどう使うか」\n\n【営業で与えられるもの】\n\n1. 情報\n・業界ニュース、トレンド\n・競合情報\n・成功事例\n\n2. 時間と労力\n・丁寧な対応\n・迅速なレスポンス\n・問題解決のサポート\n\n3. 物理的なもの\n・サンプル、試供品\n・資料、ノベルティ\n・お土産\n\n4. 人脈\n・専門家の紹介\n・パートナーの紹介\n\n山本先輩:「重要なのは、見返りを期待せずに\n　　　　与えること。\n　　　　下心が見えると逆効果だ」", "duration": 50}], "part2": [{"title": "シーン4: 与えるタイミング", "content": "健太:「いつ与えればいいですか？」\n\n山本先輩:「3つのタイミングがある」\n\n【与えるベストタイミング】\n\n1️⃣ 関係構築の初期\n→ 売り込む前に価値を提供\n→ 「この人は違う」という印象\n\n2️⃣ 困っている時\n→ 相手が困っている時に助ける\n→ 「恩」として強く記憶される\n\n3️⃣ 予想外のタイミング\n→ 誕生日、記念日\n→ 特別な存在として認識される\n\n山本先輩:「ポイントは、\n　　　　『何かを売りたい時』以外に\n　　　　与えること。\n　　　　売る時だけ連絡してくる営業は\n　　　　信頼されない」", "duration": 45}, {"title": "シーン5: 健太の実践", "content": "（1週間後）\n\n健太:「先輩、佐藤モータースの社長が\n　　『健太さんは違う』って言ってくれました！」\n\n山本先輩:「何をしたんだ？」\n\n健太:「この前の商談で、社長が\n　　人手不足で困ってるって言ってたので、\n　　知り合いの人材紹介会社を\n　　紹介したんです」\n\n山本先輩:「自分の商品じゃなく、\n　　　相手が本当に必要なものを提供した。\n　　　それが本当の『与える』だな」\n\n健太:「そしたら、『システムの件、\n　　真剣に検討するよ』って...」\n\n山本先輩:「返報性が働いたな。\n　　　見返りを求めなかったから、\n　　　より大きな信頼が得られた」", "duration": 50}, {"title": "シーン6: ギバーの成功", "content": "山本先輩:「与える人を『ギバー』と呼ぶ」\n\n【アダム・グラントの研究】\n組織で最も成功するのは「ギバー」\n→ 長期的に見ると、与える人が最も成果を上げる\n\n【ギバーの3つのルール】\n\n1. 見返りを期待しない\n→ 期待すると「取引」になる\n\n2. 相手が本当に必要なものを与える\n→ 自分があげたいものではない\n\n3. 継続的に与える\n→ 一度きりではなく、習慣にする\n\n山本先輩:「『与える者が受け取る』\n　　　　これが営業の真理だ」\n\n健太:「売り込む前に、まず与える。\n　　覚えておきます！」\n\n【今日の学び】\n「与える者が受け取る」", "duration": 45}]}', '{"title": "返報性の原理", "content": "人は何かをもらうと、お返しをしたくなる\n\n【営業で与えられるもの】\n・情報（業界ニュース、事例）\n・時間と労力（丁寧な対応）\n・人脈（専門家の紹介）", "audioText": "与える者が受け取る。見返りを求めずに、相手が本当に必要なものを提供しましょう。", "highlight": "見返りを期待せずに与える。下心が見えると逆効果"}', '[{"options": ["見返りを期待して与える", "見返りを期待せずに与える", "与えないで求める", "取引として与える"], "question": "返報性を営業で活用する際のポイントは？", "explanation": "見返りを期待せずに与えることで、より強い信頼関係が築けます。", "correctIndex": 1}, {"options": ["売りたい時だけ", "関係構築の初期、困っている時、予想外のタイミング", "契約後だけ", "年に1回"], "question": "与えるベストタイミングは？", "explanation": "売り込みたい時以外に与えることで、信頼が深まります。", "correctIndex": 1}]', '{"text": "The giver receives more than the taker.", "author": "Symphony営業格言", "textJa": "まず与えよ、さらば与えられん。営業の成功は、顧客への貢献から始まる。"}', '[{"options": [{"text": "「大変ですね。ところで本題ですが...」と商談を続ける", "points": 5, "feedback": "顧客の困りごとを無視しています。", "isCorrect": false}, {"text": "「採用に詳しい知り合いをご紹介しましょうか？」と助ける", "points": 30, "feedback": "自分の商品と関係なくても助ける。これが真の返報性です。", "isCorrect": true}, {"text": "「採用システムも弊社で扱っています」と売り込む", "points": 0, "feedback": "困っている時に売り込むのは逆効果です。", "isCorrect": false}], "situation": "顧客が「採用で困っている」と言いました。あなたの商品とは関係ありません。", "customerLine": "最近、人手不足で困っててね..."}, {"options": [{"text": "契約してから送る", "points": 10, "feedback": "契約前に価値を提供することで、返報性が働きます。", "isCorrect": false}, {"text": "見返りを期待せずに送る", "points": 30, "feedback": "先に与えることで、信頼関係が築けます。", "isCorrect": true}, {"text": "「レポートが欲しければ契約を」と条件にする", "points": 0, "feedback": "取引にすると返報性の効果が薄れます。", "isCorrect": false}], "situation": "まだ契約していない見込み客に、業界レポートを送ろうか迷っています。", "customerLine": "（まだ契約していない顧客）"}]', '{"question": "最近、顧客に「売り込み以外」で価値を提供したことはありますか？", "placeholder": "例: 業界ニュースを共有した、困っていることの相談に乗った、専門家を紹介した"}', '["売り込む前に、まず価値を提供する", "顧客が困っている時に助ける", "自分の商品と関係なくても、役立つ情報を共有する", "見返りを期待せずに与え続ける"]', '{"title": "ギバーの実践計画", "fields": [{"label": "提供できる情報・知識", "placeholder": "例: 業界レポート、競合動向、成功事例、ノウハウ記事"}, {"label": "提供できる時間・労力", "placeholder": "例: 迅速な対応、丁寧な説明、問題解決のサポート"}, {"label": "紹介できる人脈", "placeholder": "例: 専門家、パートナー企業、他の顧客"}], "description": "顧客に与えられるものを計画しましょう。"}', NULL, '2026-01-21 17:48:27.321246+00', '2026-01-21 17:48:27.321246+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (64, 36, '社会的証明', 'みんなが選ぶものは正しい', '{"icon": "users", "name": "事例の達人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["見返りを期待して与える", "見返りを期待せずに与える", "与えないで求める", "取引として与える"], "question": "返報性で重要なのは？", "explanation": "見返りを期待せずに与えることが大切でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 行列のできるラーメン店", "content": "（ランチタイム、健太と山本先輩）\n\n健太:「先輩、あの店すごい行列ですね」\n\n山本先輩:「食べたことある？」\n\n健太:「いえ、でも行列だから美味しいのかな...」\n\n山本先輩:「それが『社会的証明』だ」\n\n健太:「社会的証明？」\n\n山本先輩:「人は、他の人がやっていることを\n　　　　『正しい』と判断する傾向がある。\n　　　　行列を見ると『美味しいはず』と思う。\n　　　　これは営業でも強力に使えるんだ」", "duration": 45}, {"title": "シーン2: 社会的証明の科学", "content": "山本先輩:「社会的証明の研究を紹介しよう」\n\n【社会的証明の原理】\n人は不確実な状況で、\n他者の行動を参考に判断する\n\n【有名な実験：エレベーター】\nエレベーターに乗った人が、\n他の乗客（サクラ）が後ろを向くと、\nつられて後ろを向いてしまう\n\n【なぜ社会的証明が働くか】\n・情報収集の効率化\n・リスク回避（みんながやってるなら安全）\n・帰属欲求（仲間外れになりたくない）\n\n山本先輩:「人は『みんながやっている』ことを\n　　　　『正しい』と感じる生き物なんだ」", "duration": 50}, {"title": "シーン3: 営業での社会的証明", "content": "山本先輩:「営業での活用方法を見てみよう」\n\n【社会的証明の営業活用】\n\n1️⃣ 導入事例\n「○○社様にも導入いただいています」\n「同業の△△社様も使われています」\n\n2️⃣ 数字\n「累計1,000社以上にご導入」\n「顧客満足度95%」\n\n3️⃣ 推薦・レビュー\n「お客様の声」\n「専門家の推薦」\n\n4️⃣ メディア掲載\n「○○新聞に取り上げられました」\n「業界誌で紹介されました」\n\n山本先輩:「特に効果的なのは、\n　　　　顧客と『似た事例』を示すことだ。\n　　　　同業種、同規模、同じ課題を持つ事例が\n　　　　最も説得力がある」", "duration": 50}], "part2": [{"title": "シーン4: 効果的な事例の伝え方", "content": "健太:「事例はどう伝えればいいですか？」\n\n山本先輩:「3つのポイントがある」\n\n【事例の効果的な伝え方】\n\n1️⃣ 類似性を強調\n「御社と同じ業界の○○社様では...」\n「御社と同規模の△△社様では...」\n→ 自分に近い事例ほど参考にしやすい\n\n2️⃣ 具体的な成果\n「導入後、作業時間が50%削減」\n「売上が20%向上」\n→ 曖昧な「効果がありました」はNG\n\n3️⃣ ストーリーで語る\nBefore: 「以前は○○で困っていた」\nAfter: 「導入後、△△になった」\n→ 顧客が自分を重ねやすい\n\n山本先輩:「事例は『証拠』であると同時に\n　　　　『共感の物語』でもあるんだ」", "duration": 50}, {"title": "シーン5: 健太の実践", "content": "（商談中）\n\n健太:「社長、在庫管理のお悩み、\n　　よくわかります。\n　　実は、御社と同じく中古車販売をされている\n　　○○モータース様も同じ悩みをお持ちでした」\n\n社長:「○○モータース？知ってるよ」\n\n健太:「はい。導入前は月末の棚卸しに\n　　3日かかっていたそうです。\n　　でも今は、リアルタイムで在庫が把握でき、\n　　棚卸しが半日で終わるようになったと」\n\n社長:「半日？それはすごいな...\n　　うちも同じくらいの規模だから、\n　　同じ効果が出るかな？」\n\n健太:「はい、規模も課題も似ていますので、\n　　同様の効果が期待できます」\n\n社長:「詳しく聞かせてくれ」", "duration": 50}, {"title": "シーン6: 社会的証明の注意点", "content": "山本先輩:「社会的証明を使う時の注意点だ」\n\n【注意点】\n\n1️⃣ 嘘はつかない\n→ 架空の事例、誇張した数字はNG\n→ バレたら信頼を完全に失う\n\n2️⃣ 守秘義務を守る\n→ 顧客名を出す許可を取る\n→ 「同業他社様」という表現も可\n\n3️⃣ 事例を押し付けない\n→ 「○○社がやってるから」は強制的\n→ 「参考になれば」というスタンス\n\n山本先輩:「社会的証明は強力な武器だが、\n　　　　正しく使わないと逆効果になる。\n　　　　誠実に使うことが大切だ」\n\n【今日の学び】\n「みんなが選ぶものは正しい」", "duration": 40}]}', '{"title": "社会的証明の活用", "content": "1. 導入事例を準備する（特に類似企業）\n2. 具体的な数字を示す\n3. ストーリーで語る（Before → After）\n4. 顧客の許可を得て紹介する", "audioText": "同業種、同規模、同じ課題を持つ事例を準備し、具体的な成果と共に伝えましょう。", "highlight": "顧客と「似た事例」が最も説得力がある"}', '[{"options": ["有名企業の事例", "顧客と似た企業の事例", "最新の事例", "最も成功した事例"], "question": "社会的証明で最も効果的なのは？", "explanation": "顧客は自分に近い事例を最も参考にします。同業種・同規模の事例が効果的です。", "correctIndex": 1}, {"options": ["曖昧に伝える", "具体的な成果を数字で示す", "社名は隠す", "できるだけ短く"], "question": "事例を伝える際に大切なのは？", "explanation": "「作業時間50%削減」など、具体的な数字を示すことで説得力が増します。", "correctIndex": 1}]', '{"text": "People follow people.", "author": "Symphony営業格言", "textJa": "100の説明より、1つの事例。顧客は「自分と同じ人」の成功を信じる。"}', '[{"options": [{"text": "「大丈夫です、効果出ます！」と断言", "points": 5, "feedback": "根拠なく断言しても信頼されません。", "isCorrect": false}, {"text": "「御社と同じ業界の○○社様では、こんな成果が出ています」と事例を示す", "points": 30, "feedback": "類似企業の具体的な事例は最も説得力があります。", "isCorrect": true}, {"text": "「他社は関係ありません、御社は御社です」と言う", "points": 0, "feedback": "社会的証明の機会を逃しています。", "isCorrect": false}], "situation": "顧客が導入を迷っています。", "customerLine": "うちでも効果出るのかな..."}, {"options": [{"text": "「有名なA社、B社が使っています」と大企業名を出す", "points": 10, "feedback": "顧客と規模が違いすぎると参考になりません。", "isCorrect": false}, {"text": "「御社と同規模の○○社、△△社で導入いただいています」と類似企業を伝える", "points": 30, "feedback": "顧客に近い事例を伝えることで、自分事として捉えやすくなります。", "isCorrect": true}, {"text": "「守秘義務で言えません」と断る", "points": 5, "feedback": "言える範囲で事例を共有しましょう。", "isCorrect": false}], "situation": "導入実績を聞かれました。", "customerLine": "他にどんな会社が使ってるの？"}]', '{"question": "商談で事例を効果的に使えていますか？改善点は？", "placeholder": "例: 事例は紹介しているが、数字が曖昧だった。次回は具体的な成果を準備する"}', '["業界別・規模別の事例を3つ以上準備する", "事例には具体的な数字を入れる", "Before/Afterのストーリーで語る", "顧客の許可を得て、社名を出せる事例を増やす"]', '{"title": "社会的証明の準備", "fields": [{"label": "同業種の導入事例（3つ以上）", "placeholder": "例: ○○モータース、△△自動車、□□カーズ"}, {"label": "具体的な成果（数字で）", "placeholder": "例: 作業時間50%削減、売上20%向上、顧客満足度95%"}, {"label": "Before/Afterストーリー", "placeholder": "例: 導入前は月末棚卸しに3日→導入後は半日で完了"}], "description": "使える事例を整理しましょう。"}', NULL, '2026-01-21 17:48:28.068954+00', '2026-01-21 17:48:28.068954+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (65, 37, '希少性の原理', '手に入らないものほど欲しくなる', '{"icon": "clock", "name": "希少性マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["有名企業の事例", "顧客と似た企業の事例", "最新の事例", "最も成功した事例"], "question": "社会的証明で最も効果的なのは？", "explanation": "顧客は自分に近い事例を最も参考にしましたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 残り1点の魔力", "content": "（ECサイトを見ている健太）\n\n健太:「あ、このジャケット良いな...\n　　でも今すぐは...」\n\n（画面に「残り1点」の表示）\n\n健太:「...やっぱり買おう！」\n\n山本先輩:「何買ったんだ？」\n\n健太:「ジャケットです。\n　　残り1点だったんで、つい...」\n\n山本先輩:「それが『希少性の原理』だ。\n　　　　手に入りにくいものほど、\n　　　　人は価値を感じる」", "duration": 45}, {"title": "シーン2: 希少性の科学", "content": "山本先輩:「希少性の研究を紹介しよう」\n\n【希少性の原理】\n人は、手に入りにくいものに\nより高い価値を感じる\n\n【有名な実験：クッキーの味】\n同じクッキーでも、\n・10枚入りの瓶から取ったクッキー\n・2枚しか入っていない瓶から取ったクッキー\n→ 2枚の方が「おいしい」と評価された\n\n【希少性が働く理由】\n・手に入らなくなる恐怖（損失回避）\n・選択の自由が奪われる不快感\n・希少なもの = 価値があるという思い込み\n\n山本先輩:「人は『なくなるかも』と思うと、\n　　　　急いで行動したくなるんだ」", "duration": 50}, {"title": "シーン3: 営業での希少性", "content": "山本先輩:「営業での活用方法を見てみよう」\n\n【希少性の営業活用】\n\n1️⃣ 数量の限定\n「今回のキャンペーンは先着10社様まで」\n「サポート枠は残り3社です」\n\n2️⃣ 時間の限定\n「今月末までの特別価格です」\n「この条件は今週中にお返事いただければ」\n\n3️⃣ 条件の限定\n「新規導入のお客様限定」\n「○○業界のお客様だけの特別プラン」\n\n4️⃣ 機会の限定\n「この担当者がいる間だけの提案です」\n「今のタイミングだからできる条件です」\n\n山本先輩:「ただし、嘘の希少性は厳禁だ。\n　　　　本当に限られている時だけ使う」", "duration": 50}], "part2": [{"title": "シーン4: 正しい希少性の使い方", "content": "健太:「希少性を使う時の注意点は？」\n\n山本先輩:「3つのルールがある」\n\n【希少性を使う3つのルール】\n\n1️⃣ 嘘をつかない\n✅ 本当に数量限定、期間限定の時だけ\n❌ 「残りわずか」と言って実は在庫たっぷり\n→ バレたら信頼を完全に失う\n\n2️⃣ 理由を説明する\n✅ 「年度末の予算消化のため、今月だけの価格です」\n✅ 「サポートチームの人数の関係で、枠に限りがあります」\n→ 理由があると納得感が増す\n\n3️⃣ 押しすぎない\n✅ 情報として伝える\n❌ 「今決めないと損しますよ！」と煽る\n→ 煽ると逆効果、信頼を失う\n\n山本先輩:「希少性は『情報提供』として伝える。\n　　　　決断を急がせる道具ではない」", "duration": 50}, {"title": "シーン5: 健太の実践", "content": "（商談の終盤）\n\n健太:「社長、ご検討ありがとうございます。\n　　一点、お伝えしておきたいことがあります」\n\n社長:「何だい？」\n\n健太:「今回のキャンペーン価格は、\n　　弊社の年度末予算の関係で、\n　　今月末までとなっています。\n　　来月以降は通常価格に戻りますので、\n　　ご検討のタイミングの参考にしていただければ」\n\n社長:「なるほど、理由があるのか」\n\n健太:「はい。もちろん、\n　　御社のペースで決めていただければと思いますが、\n　　情報としてお伝えしておきたくて」\n\n社長:「正直に言ってくれてありがとう。\n　　今月中に検討するよ」", "duration": 50}, {"title": "シーン6: 希少性の本質", "content": "山本先輩:「どうだった？」\n\n健太:「煽らずに伝えたら、\n　　社長も前向きに検討してくれました」\n\n山本先輩:「そうだ。希少性は\n　　　　『煽りの道具』ではなく、\n　　　　『正直な情報提供』として使う。\n　　　　それが信頼につながる」\n\n【希少性の本質】\n\n希少性は「事実」を伝えること\n・本当に期限がある → 伝える\n・本当に枠が限られている → 伝える\n・顧客が損しないよう → 情報提供\n\n希少性は「操作」ではない\n・急がせるために嘘をつく → NG\n・決断を強要する → NG\n\n【今日の学び】\n「手に入らないものほど欲しくなる」", "duration": 40}]}', '{"title": "希少性の原理", "content": "【希少性の種類】\n・数量限定「先着10社まで」\n・時間限定「今月末まで」\n・条件限定「新規顧客限定」\n\n【3つのルール】\n1. 嘘をつかない\n2. 理由を説明する\n3. 押しすぎない", "audioText": "本当に限られている時だけ、理由と共に情報提供として伝えましょう。", "highlight": "希少性は「煽り」ではなく「正直な情報提供」として使う"}', '[{"options": ["とにかく急がせる", "嘘でも「残りわずか」と言う", "本当の情報だけを正直に伝える", "毎回使う"], "question": "希少性を使う際に最も大切なのは？", "explanation": "嘘の希少性は信頼を完全に失います。本当の情報だけを正直に伝えましょう。", "correctIndex": 2}, {"options": ["効果が薄れる", "納得感が増す", "断られやすくなる", "関係ない"], "question": "希少性の理由を説明すると？", "explanation": "「なぜ限定なのか」の理由があると、顧客の納得感が増します。", "correctIndex": 1}]', '{"text": "Scarcity is information, not manipulation.", "author": "Symphony営業格言", "textJa": "希少性は、顧客が判断するための情報。煽りの道具ではない。"}', '[{"options": [{"text": "「今決めないと損しますよ！」と煽る", "points": 0, "feedback": "煽ると信頼を失います。", "isCorrect": false}, {"text": "「今月末でキャンペーンが終了しますので、ご検討の参考にしてください」と情報提供", "points": 30, "feedback": "正直な情報提供として伝えるのが正しい使い方です。", "isCorrect": true}, {"text": "何も言わずに待つ", "points": 10, "feedback": "顧客が損をする可能性があります。情報は伝えましょう。", "isCorrect": false}], "situation": "キャンペーン終了が近づいています。", "customerLine": "もう少し考えたいな..."}, {"options": [{"text": "「残りわずかです！」と嘘をつく", "points": 0, "feedback": "嘘は絶対にNG。バレたら信頼を完全に失います。", "isCorrect": false}, {"text": "「はい、在庫は十分あります」と正直に答える", "points": 30, "feedback": "正直に答えることが長期的な信頼につながります。", "isCorrect": true}, {"text": "「確認します」と曖昧にする", "points": 10, "feedback": "正直に答えましょう。", "isCorrect": false}], "situation": "実際は在庫が十分あります。", "customerLine": "まだ在庫ありますか？"}]', '{"question": "過去に「嘘の希少性」を使ってしまったことはありますか？その結果は？", "placeholder": "例: 「今月だけ」と言って翌月も同じ条件を出した。顧客の信頼を失った"}', '["本当に期限がある時だけ希少性を伝える", "希少性には必ず理由を添える", "「情報提供」として伝え、煽らない", "嘘の希少性は絶対に使わない"]', '{"title": "希少性の正しい活用", "fields": [{"label": "本当に期限があるもの", "placeholder": "例: 年度末キャンペーン（3月末まで）、決算特価（今月限り）"}, {"label": "本当に数量が限られているもの", "placeholder": "例: サポート枠（月5社まで）、導入支援（先着10社）"}, {"label": "希少性の理由", "placeholder": "例: 年度予算の関係、サポートチームの人数制限"}], "description": "本当の希少性を整理しましょう。"}', NULL, '2026-01-21 17:48:29.615883+00', '2026-01-21 17:48:29.615883+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (66, 38, 'アンカリング効果', '最初の数字が基準になる', '{"icon": "anchor", "name": "価格戦略家"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["とにかく急がせる", "嘘でも「残りわずか」と言う", "本当の情報だけを正直に伝える", "毎回使う"], "question": "希少性を使う際に最も大切なのは？", "explanation": "本当の情報だけを正直に伝えることが大切でしたね。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: スーツの値段", "content": "（デパートで）\n\n店員:「このスーツ、定価10万円ですが、\n　　今日は50%オフで5万円です」\n\n健太:「5万円か...お得だな」\n\n（購入後）\n\n山本先輩:「いくらだった？」\n\n健太:「5万円です。定価10万円が半額で」\n\n山本先輩:「その『定価10万円』が\n　　　　アンカー（錨）になってるんだ」\n\n健太:「アンカー？」\n\n山本先輩:「最初に提示された数字が\n　　　　基準になって、\n　　　　その後の判断に影響を与える。\n　　　　これがアンカリング効果だ」", "duration": 45}, {"title": "シーン2: アンカリングの科学", "content": "山本先輩:「アンカリングの研究を紹介しよう」\n\n【アンカリング効果】\n最初に提示された数字（アンカー）が\nその後の判断の基準となる\n\n【有名な実験】\n「国連に加盟しているアフリカの国の割合は\n　ルーレットで出た数字より多いか少ないか？」\n\nルーレット10 → 回答の平均25%\nルーレット65 → 回答の平均45%\n\n→ 全く関係ない数字でも、\n　 判断に影響を与えた\n\n【なぜアンカリングが働くか】\n・情報処理の効率化（基準があると判断しやすい）\n・不確実性の軽減（手がかりを求める）\n\n山本先輩:「人は最初に見た数字を\n　　　　無意識に『基準』にしてしまう」", "duration": 55}, {"title": "シーン3: 価格提示の順序戦略", "content": "山本先輩:「営業での活用方法を見てみよう」\n\n【アンカリングの営業活用】\n\n1️⃣ 高い価格を先に見せる\n上位プランを先に → スタンダードプランが安く見える\n「プレミアムは月額10万円、\n　スタンダードは月額5万円です」\n\n2️⃣ 元の価格を伝える\n「通常100万円のところ、今回は80万円で」\n→ 80万円が「お得」に感じる\n\n3️⃣ 大きな数字を先に\n「競合他社は年間1,200万円の損失...\n　弊社なら年間100万円で解決」\n→ 100万円が「安い」と感じる\n\n山本先輩:「提示する順序を変えるだけで、\n　　　　同じ価格でも印象が変わるんだ」", "duration": 50}], "part2": [{"title": "シーン4: 比較対象を作る", "content": "健太:「具体的にどう使えばいいですか？」\n\n山本先輩:「比較対象を意図的に作るんだ」\n\n【比較対象の作り方】\n\n1️⃣ 3つのプランを用意\n・松（高い）: 10万円\n・竹（中間）: 6万円 ← 売りたいプラン\n・梅（安い）: 3万円\n\n→ 「松」がアンカーとなり、\n　 「竹」がお得に見える\n\n2️⃣ 課題のコストを先に計算\n「現状の問題で年間500万円の損失...\n　弊社のシステムは年間100万円です」\n\n→ 500万円がアンカーとなり、\n　 100万円が「安い投資」に見える\n\n3️⃣ 競合価格を伝える\n「A社は月額8万円ですが、\n　弊社は月額5万円です」\n\n→ 8万円がアンカーとなり、\n　 5万円が「お得」に見える", "duration": 50}, {"title": "シーン5: 健太の実践", "content": "（商談で価格提示）\n\n健太:「社長、まず現状のコストを\n　　計算させてください。\n　　手作業の在庫管理に月40時間、\n　　時給換算で年間約96万円のコストです」\n\n社長:「そんなにかかってるのか...」\n\n健太:「弊社のシステムは年間60万円です。\n　　つまり、年間36万円のコスト削減に加え、\n　　ミス削減や業務効率化のメリットもあります」\n\n社長:「96万円が60万円になるなら、\n　　確かに投資する価値はあるな...」\n\n（後日）\n\n山本先輩:「アンカリング、うまく使えたな」\n\n健太:「はい！先に大きな数字を見せることで、\n　　提案価格が『安く』感じてもらえました」", "duration": 50}, {"title": "シーン6: アンカリングの倫理", "content": "山本先輩:「アンカリングを使う時の注意点だ」\n\n【アンカリングの倫理的な使い方】\n\n✅ 正しい使い方\n・実際の価値を正確に伝える\n・比較対象は妥当なものを使う\n・顧客にとっての本当のメリットを示す\n\n❌ 間違った使い方\n・架空の「定価」を設定する\n・不当に高い比較対象を持ち出す\n・顧客を騙すために数字を操作する\n\n山本先輩:「アンカリングは\n　　　　『価値を正しく伝える』ためのツール。\n　　　　顧客を騙すためではない」\n\n【今日の学び】\n「最初の数字が基準になる」", "duration": 40}]}', '{"title": "アンカリング効果の活用", "content": "1. 高いプランを先に見せる\n2. 現状のコストを計算して見せる\n3. 3つのプランで比較対象を作る\n\n最初に見せる数字が「基準」になる", "audioText": "価格を提示する前に、まず大きな数字（現状コスト、上位プラン等）を見せましょう。", "highlight": "提示する順序を変えるだけで、同じ価格でも印象が変わる"}', '[{"options": ["安い価格を先に見せる", "高い価格を先に見せる", "価格を隠す", "値引きだけ伝える"], "question": "アンカリング効果を活用するには？", "explanation": "高い価格や大きな数字を先に見せることで、提案価格が相対的に安く感じられます。", "correctIndex": 1}, {"options": ["選択肢を増やすため", "中間のプランを売りやすくするため", "高いプランを売るため", "安いプランを売るため"], "question": "3つのプランを用意する理由は？", "explanation": "高いプランがアンカーとなり、中間のプランが「お得」に見えます。", "correctIndex": 1}]', '{"text": "The first number sets the stage.", "author": "Symphony営業格言", "textJa": "最初の一手が、交渉の流れを決める。提示する数字の順序を制する者が、商談を制す。"}', '[{"options": [{"text": "「月額5万円です」とだけ伝える", "points": 10, "feedback": "比較対象がないと、高いか安いか判断しにくいです。", "isCorrect": false}, {"text": "「現状のコスト年間100万円に対し、弊社は年間60万円です」と比較で伝える", "points": 30, "feedback": "アンカーを設定してから価格を伝えることで、お得感が伝わります。", "isCorrect": true}, {"text": "「とりあえず見積もり送ります」と後回し", "points": 5, "feedback": "口頭で説明する機会を活用しましょう。", "isCorrect": false}], "situation": "価格を提示しようとしています。", "customerLine": "で、いくらになるの？"}, {"options": [{"text": "安いプラン→中間→高いプランの順", "points": 10, "feedback": "安いプランがアンカーになり、他が高く感じます。", "isCorrect": false}, {"text": "高いプラン→中間→安いプランの順", "points": 30, "feedback": "高いプランがアンカーとなり、中間プランがお得に感じられます。", "isCorrect": true}, {"text": "中間プランだけ説明", "points": 5, "feedback": "比較対象がないと価値が伝わりにくいです。", "isCorrect": false}], "situation": "3つのプランを説明します。どの順番で説明しますか？", "customerLine": "プランの説明をお願いします"}]', '{"question": "価格提示で「高い」と言われた経験はありますか？アンカリングで改善できそうですか？", "placeholder": "例: いきなり価格だけ伝えて「高い」と言われた。次回は現状コストを先に計算して見せる"}', '["価格提示の前に、現状コストを計算して見せる", "3つのプランを用意し、高いプランから説明する", "競合価格を調査し、比較で自社の価値を示す", "架空のアンカーは使わない（倫理的に）"]', '{"title": "アンカリング戦略の設計", "fields": [{"label": "アンカーとなる大きな数字", "placeholder": "例: 現状コスト年間100万円、上位プラン月額10万円、競合価格月額8万円"}, {"label": "提案価格", "placeholder": "例: 月額5万円（年間60万円）"}, {"label": "伝える順序", "placeholder": "例: 現状コスト→競合価格→提案価格"}], "description": "価格提示のアンカリング戦略を設計しましょう。"}', NULL, '2026-01-21 17:48:30.339108+00', '2026-01-21 17:48:30.339108+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (67, 39, '損失回避バイアス', '人は得より損を恐れる', '{"icon": "shield-alert", "name": "損失回避の理解者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["安い価格を先に見せる", "高い価格を先に見せる", "価格を隠す", "値引きだけ伝える"], "question": "アンカリング効果を活用するには？", "explanation": "高い価格を先に見せることで、提案価格が相対的に安く感じられましたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 5万円の価値", "content": "（オフィスで）\n\n山本先輩:「健太、質問だ。\n　　　　今日、急に5万円もらえたらどう？」\n\n健太:「嬉しいですね！何かに使おうかな」\n\n山本先輩:「じゃあ、今日、急に5万円\n　　　　なくしたら？」\n\n健太:「えっ、それは最悪です...\n　　凹みますね」\n\n山本先輩:「同じ5万円なのに、\n　　　　失う方がずっと辛く感じるだろ？」\n\n健太:「確かに...」\n\n山本先輩:「これが『損失回避バイアス』だ。\n　　　　人は得より損を恐れる」", "duration": 45}, {"title": "シーン2: 損失回避の科学", "content": "山本先輩:「ノーベル経済学賞を受賞した\n　　　　カーネマンの研究を紹介しよう」\n\n【損失回避バイアス】\n人は、同じ金額の「得」と「損」を比べると、\n「損」の方を約2倍重く感じる\n\n【プロスペクト理論】\n5万円を得る喜び < 5万円を失う苦痛\n\n→ 損失の苦痛は、利得の喜びの\n　 約2〜2.5倍強い\n\n【なぜ損失回避が働くか】\n・生存本能（資源を失うと生き残れない）\n・所有効果（持っているものへの執着）\n・後悔回避（失って後悔したくない）\n\n山本先輩:「人は『得する』より\n　　　　『損しない』ことを優先する生き物だ」", "duration": 55}, {"title": "シーン3: 営業での活用", "content": "山本先輩:「営業での活用方法を見てみよう」\n\n【損失回避の営業活用】\n\n1️⃣ 機会損失を伝える\n❌ 「導入すると年間100万円お得です」\n✅ 「導入しないと年間100万円損しています」\n\n2️⃣ リスクを強調する\n「このまま放置すると...」\n「競合に先を越されると...」\n\n3️⃣ 限定オファーの終了\n「今月末でこの条件は終了です」\n「この機会を逃すと、次は1年後です」\n\n4️⃣ 現状維持のコストを可視化\n「今のやり方を続けると、\n　3年後には○○万円の差が...」\n\n山本先輩:「『得られる』ではなく\n　　　　『失わないために』という\n　　　　フレーミングが効果的だ」", "duration": 50}], "part2": [{"title": "シーン4: フレーミングの違い", "content": "健太:「具体的な言い方を教えてください」\n\n山本先輩:「同じ内容でも、伝え方で印象が変わる」\n\n【得フレーム vs 損フレーム】\n\n■ 効率化\n得: 「月20時間の効率化ができます」\n損: 「月20時間を無駄にしています」\n\n■ 売上向上\n得: 「売上が10%上がる可能性があります」\n損: 「10%の売上機会を逃しています」\n\n■ コスト削減\n得: 「年間100万円節約できます」\n損: 「年間100万円を損しています」\n\n■ 顧客満足\n得: 「顧客満足度が向上します」\n損: 「顧客離れのリスクがあります」\n\n山本先輩:「損フレームの方が\n　　　　行動を促しやすい。\n　　　　ただし、使いすぎると脅迫的になるので注意」", "duration": 50}, {"title": "シーン5: 健太の実践", "content": "（商談で）\n\n健太:「社長、御社の現状を分析しました。\n　　手作業の在庫管理で、\n　　月20時間、年間240時間が\n　　本来の営業活動から失われています」\n\n社長:「240時間も...」\n\n健太:「これを営業に充てられていたら、\n　　月2件の商談、年間24件の機会損失です。\n　　仮に成約率30%とすると、\n　　年間7〜8件の契約を逃している計算です」\n\n社長:「そんなに損してるのか...」\n\n健太:「はい。弊社のシステムで\n　　この損失を取り戻しませんか？」\n\n社長:「...詳しく聞かせてくれ」", "duration": 50}, {"title": "シーン6: 損失回避の倫理", "content": "山本先輩:「損失回避を使う時の注意点だ」\n\n【損失回避の倫理的な使い方】\n\n✅ 正しい使い方\n・実際の損失・リスクを正確に伝える\n・顧客が気づいていない損失を可視化\n・解決策と共に提示する\n\n❌ 間違った使い方\n・存在しないリスクを煽る\n・過度に恐怖を与える\n・解決策なしに不安だけ与える\n\n山本先輩:「損失回避は\n　　　　『気づいていない問題に気づかせる』\n　　　　ために使う。\n　　　　脅迫ではなく、情報提供だ」\n\n【今日の学び】\n「人は得より損を恐れる」", "duration": 40}]}', '{"title": "損失回避バイアス", "content": "損失の苦痛 = 利得の喜び × 2〜2.5倍\n\n【フレーミングの違い】\n得フレーム: 「100万円節約できます」\n損フレーム: 「100万円損しています」\n→ 損フレームの方が行動を促しやすい", "audioText": "人は得より損を恐れます。機会損失やリスクを正確に伝えましょう。", "highlight": "「得られる」より「失わないために」というフレーミングが効果的"}', '[{"options": ["損を避けて得を求める", "得より損を約2倍重く感じる", "損得を同じように感じる", "得の方が嬉しい"], "question": "損失回避バイアスとは？", "explanation": "人は同じ金額でも、損失の方を約2倍重く感じます。", "correctIndex": 1}, {"options": ["「100万円節約できます」", "「100万円損しています」", "「100万円お得です」", "「100万円の価値があります」"], "question": "損フレームの例として正しいのは？", "explanation": "損フレームは「失っている」「損している」という表現を使います。", "correctIndex": 1}]', '{"text": "Losses loom larger than gains.", "author": "ダニエル・カーネマン", "textJa": "人は得る喜びより、失う恐怖に強く反応する。これを理解することが、説得の第一歩だ。"}', '[{"options": [{"text": "「年間100万円の効率化ができます」（得フレーム）", "points": 15, "feedback": "得フレームも良いですが、損フレームの方が行動を促しやすいです。", "isCorrect": false}, {"text": "「今のままだと年間100万円を損し続けます」（損フレーム）", "points": 30, "feedback": "損フレームは行動を促す効果が高いです。", "isCorrect": true}, {"text": "「とにかく良いですよ」", "points": 5, "feedback": "具体的な数字で伝えましょう。", "isCorrect": false}], "situation": "システム導入のメリットを伝えています。", "customerLine": "導入するとどうなりますか？"}, {"options": [{"text": "「わかりました、来期お待ちしています」", "points": 5, "feedback": "機会損失を伝える良い機会です。", "isCorrect": false}, {"text": "「半年先延ばしにすると、○○円の機会損失が発生します」と損失を可視化", "points": 30, "feedback": "先延ばしの損失を具体的に伝えることで、行動を促せます。", "isCorrect": true}, {"text": "「今すぐ決めてください！」と急かす", "points": 0, "feedback": "根拠なく急かすのは逆効果です。", "isCorrect": false}], "situation": "顧客が検討を先延ばしにしています。", "customerLine": "来期に検討しようかな..."}]', '{"question": "提案時、「得フレーム」ばかり使っていませんか？「損フレーム」で言い換えられるものは？", "placeholder": "例: 「コスト削減できます」→「毎月○万円を損しています」に言い換える"}', '["提案内容を「損フレーム」でも表現できるようにする", "機会損失を具体的な数字で計算する", "現状維持のリスク・コストを可視化する", "恐怖を煽りすぎないよう、解決策と共に提示する"]', '{"title": "損失フレームの作成", "fields": [{"label": "得フレーム（現在の表現）", "placeholder": "例: 月20時間の効率化ができます / 売上が10%上がります"}, {"label": "損フレーム（損失として表現）", "placeholder": "例: 月20時間を無駄にしています / 売上機会の10%を逃しています"}, {"label": "具体的な損失額の計算", "placeholder": "例: 月20時間×時給2000円×12ヶ月=年間48万円の損失"}], "description": "提案内容を損失フレームで表現しましょう。"}', NULL, '2026-01-21 17:48:30.909429+00', '2026-01-21 17:48:30.909429+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (68, 40, '認知的不協和', '決断後の不安を解消する', '{"icon": "heart", "name": "安心の提供者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["「100万円節約できます」", "「100万円損しています」", "「100万円お得です」", "「100万円の価値があります」"], "question": "損フレームの例として正しいのは？", "explanation": "損フレームは「失っている」「損している」という表現でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 買った後の不安", "content": "（健太がスマホを買い替えた翌日）\n\n健太:「先輩、新しいスマホ買ったんですけど、\n　　なんか不安で...」\n\n山本先輩:「不安？気に入らなかった？」\n\n健太:「いや、気に入ってるんですけど、\n　　『本当にこれで良かったのかな』\n　　『他の機種の方が良かったんじゃ』\n　　って考えちゃって...」\n\n山本先輩:「それは『認知的不協和』だな」\n\n健太:「認知的不協和？」\n\n山本先輩:「人は決断した後に不安を感じる。\n　　　　その心理を理解することが、\n　　　　営業では重要なんだ」", "duration": 45}, {"title": "シーン2: 認知的不協和の科学", "content": "山本先輩:「認知的不協和の研究を紹介しよう」\n\n【認知的不協和とは】\n人が自分の信念や行動の間に矛盾を感じた時、\n不快感（不協和）が生じ、\nそれを解消しようとする心理\n\n【購入後の不協和】\n「この商品を買った」（行動）\n「本当に正しかったのか？」（疑念）\n→ この矛盾が不快感を生む\n\n【人が不協和を解消する方法】\n1. 決断を正当化する\n　 「やっぱりこれが一番良かった」\n2. 都合の悪い情報を避ける\n　 「他の商品のレビューは見ない」\n3. 決断を後悔する\n　 「買わなければよかった」\n\n山本先輩:「3番を防ぐのが、\n　　　　営業の重要な仕事だ」", "duration": 55}, {"title": "シーン3: 契約後のフォロー", "content": "山本先輩:「認知的不協和は契約直後が最も強い」\n\n【契約後に顧客が感じること】\n\n「本当にこの会社で良かったのか？」\n「他社の方が安かったのでは？」\n「うまく使いこなせるだろうか？」\n「周りに何て言われるだろう？」\n\n→ この不安を放置すると...\n・キャンセル\n・クレーム\n・悪い口コミ\n・リピートなし\n\n山本先輩:「契約後こそ、\n　　　　顧客に寄り添うことが大切だ」\n\n【契約後にすべきこと】\n・すぐにお礼の連絡\n・選択の正しさを伝える\n・導入サポートを約束\n・定期的なフォロー", "duration": 50}], "part2": [{"title": "シーン4: 選択を肯定する", "content": "健太:「具体的にどう伝えればいいですか？」\n\n山本先輩:「顧客の選択を肯定し、\n　　　不安を解消する言葉をかけるんだ」\n\n【選択を肯定するフレーズ】\n\n契約直後:\n「素晴らしいご決断です」\n「正しい選択をされましたね」\n「御社にぴったりだと思います」\n\n導入後:\n「○○社様も同じ選択をされて成功しています」\n「この機能が御社の課題にぴったりです」\n「導入いただいて本当に良かったです」\n\n問題が起きた時:\n「すぐに対応します」\n「選んでいただいた期待に応えます」\n「最後まで責任を持ちます」\n\n山本先輩:「顧客が自分の決断に自信を持てるよう\n　　　　サポートするんだ」", "duration": 50}, {"title": "シーン5: 健太の実践", "content": "（契約直後、健太から顧客へ電話）\n\n健太:「佐藤社長、本日はご契約いただき\n　　ありがとうございました」\n\n社長:「ああ、こちらこそ」\n\n健太:「改めてお伝えしたいのですが、\n　　御社の課題を伺った時から、\n　　弊社のシステムがぴったりだと\n　　確信していました」\n\n社長:「そうなんだ」\n\n健太:「同業の○○社様も同じ課題を解決され、\n　　今では『もっと早く導入すれば良かった』と\n　　おっしゃっています。\n　　御社も必ず同じ成果を出せると信じています」\n\n社長:「...ありがとう。安心したよ」\n\n健太:「導入まで、しっかりサポートしますので、\n　　何かあればいつでもご連絡ください」", "duration": 50}, {"title": "シーン6: 長期的な関係", "content": "山本先輩:「いいフォローだったな」\n\n健太:「社長の声、最初は少し不安そうでしたけど、\n　　最後は安心した様子でした」\n\n山本先輩:「認知的不協和を解消できたんだ。\n　　　　これが長期的な関係につながる」\n\n【認知的不協和の解消がもたらすもの】\n\n✅ キャンセル防止\n✅ クレーム減少\n✅ リピート購入\n✅ 紹介の獲得\n✅ 良い口コミ\n\n山本先輩:「契約がゴールじゃない。\n　　　　契約後のフォローが、\n　　　　顧客との長期的な関係を作る。\n　　　　それが営業の本当の仕事だ」\n\n【今日の学び】\n「決断後の不安を解消する」", "duration": 40}]}', '{"title": "認知的不協和への対応", "content": "【契約後に顧客が感じる不安】\n・本当にこれで良かったのか？\n・他社の方が良かったのでは？\n・うまく使いこなせるか？\n\n【営業がすべきこと】\n・選択の正しさを伝える\n・成功事例を共有する\n・導入サポートを約束する", "audioText": "認知的不協和を解消することで、キャンセル防止、リピート、紹介につながります。", "highlight": "契約がゴールではない。契約後のフォローが長期的な関係を作る"}', '[{"options": ["決断前の迷い", "決断後の不安・矛盾", "価格への不満", "品質への不満"], "question": "認知的不協和とは？", "explanation": "認知的不協和は、決断した後に「本当に正しかったのか」と感じる不安です。", "correctIndex": 1}, {"options": ["追加販売のため", "認知的不協和を解消し、キャンセルを防ぐため", "上司に報告するため", "競合を批判するため"], "question": "契約後に顧客の選択を肯定する理由は？", "explanation": "顧客の選択を肯定し、不安を解消することで、長期的な関係が築けます。", "correctIndex": 1}]', '{"text": "The sale begins when the customer says yes.", "author": "Symphony営業格言", "textJa": "契約は始まりであり、終わりではない。顧客が決断した後こそ、本当のサポートが始まる。"}', '[{"options": [{"text": "「もう契約したので、やるしかないですよ」と言う", "points": 0, "feedback": "不安を増大させ、キャンセルにつながる可能性があります。", "isCorrect": false}, {"text": "「素晴らしいご決断です。○○社様も同じ選択で成功されています」と選択を肯定する", "points": 30, "feedback": "認知的不協和を解消し、顧客を安心させる良い対応です。", "isCorrect": true}, {"text": "「不安ならキャンセルしますか？」と聞く", "points": 5, "feedback": "キャンセルを促してしまいます。まず不安を解消しましょう。", "isCorrect": false}], "situation": "契約直後、顧客から電話がありました。", "customerLine": "さっき契約したんだけど、本当にこれで良かったのかな..."}, {"options": [{"text": "「追加のご提案があるのですが...」と営業する", "points": 5, "feedback": "まず不安解消が先です。追加営業は信頼関係ができてから。", "isCorrect": false}, {"text": "「改めて、素晴らしいご決断でした。導入まで全力でサポートします」と伝える", "points": 30, "feedback": "選択の正しさを伝え、サポートを約束する良い対応です。", "isCorrect": true}, {"text": "「問題ないですか？」とだけ聞く", "points": 10, "feedback": "能動的に選択を肯定する言葉をかけましょう。", "isCorrect": false}], "situation": "契約後、フォローの電話をかけます。", "customerLine": "あ、どうも"}]', '{"question": "契約後、フォローせずに放置してしまった経験はありますか？その結果は？", "placeholder": "例: 契約後に連絡せず、クレームになった。次回から契約当日に必ず電話する"}', '["契約当日にお礼と選択の肯定を伝える", "類似企業の成功事例を共有する", "導入サポートを約束し、実行する", "定期的なフォローで長期的な関係を築く"]', '{"title": "契約後フォローの設計", "fields": [{"label": "契約直後（当日）にすること", "placeholder": "例: お礼の電話、選択の正しさを伝える、導入スケジュールの確認"}, {"label": "導入時にすること", "placeholder": "例: 丁寧な説明、初期サポート、疑問点の解消"}, {"label": "導入後にすること", "placeholder": "例: 1週間後フォロー、1ヶ月後フォロー、成果の確認"}], "description": "契約後のフォロープランを設計しましょう。"}', NULL, '2026-01-21 17:48:31.750302+00', '2026-01-21 17:48:31.750302+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (69, 41, 'ミラーリングとラポール構築', '人は自分に似た人を好きになる', '{"icon": "copy", "name": "ラポールの達人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["決断前の迷い", "決断後の不安・矛盾", "価格への不満", "品質への不満"], "question": "認知的不協和とは？", "explanation": "決断した後に「本当に正しかったのか」と感じる不安でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 波長が合う人", "content": "（商談後）\n\n健太:「あのお客さん、なんか話しやすかったな...\n　　波長が合うって感じで」\n\n山本先輩:「どんな感じだった？」\n\n健太:「話すテンポとか、座り方とか、\n　　なんか似てたような...」\n\n山本先輩:「それは『ミラーリング』だな」\n\n健太:「ミラーリング？」\n\n山本先輩:「人は、自分と似た人を好きになる。\n　　　　相手の動作や話し方を\n　　　　さりげなく真似ることで、\n　　　　信頼関係（ラポール）を築けるんだ」", "duration": 45}, {"title": "シーン2: ミラーリングの科学", "content": "山本先輩:「ミラーリングの研究を紹介しよう」\n\n【ミラーリングとは】\n相手の動作、姿勢、話し方などを\nさりげなく真似ること\n\n【なぜミラーリングが効果的か】\n\n1. ミラーニューロン\n人は他者の行動を見ると、\n自分も同じ動きをしているかのように\n脳が反応する\n\n2. 類似性の法則\n人は自分と似ている人を好む\n→ 似ていると感じると親近感が湧く\n\n3. 無意識の信頼\nミラーリングされると、\n無意識に「この人は味方だ」と感じる\n\n山本先輩:「仲の良いカップルや友人同士が\n　　　　自然と同じ動きをするのも\n　　　　ミラーリングの一種だ」", "duration": 55}, {"title": "シーン3: ミラーリングの実践", "content": "山本先輩:「営業でのミラーリングを見てみよう」\n\n【非言語のミラーリング】\n\n1️⃣ 姿勢\n相手が前のめり → 自分も前のめり\n相手が背もたれに寄りかかる → 自分も\n\n2️⃣ ジェスチャー\n相手が手を動かす → 自分も手を使う\n相手が腕を組む → 自分も（少し遅れて）\n\n3️⃣ 表情\n相手が笑う → 自分も笑う\n相手が真剣 → 自分も真剣に\n\n【言語のミラーリング】\n\n1️⃣ 話すスピード\n相手がゆっくり → 自分もゆっくり\n相手が早口 → 自分も少し早く\n\n2️⃣ 声のトーン\n相手が低い声 → 自分も落ち着いた声\n相手が明るい声 → 自分も明るく\n\n3️⃣ 言葉遣い\n相手が使った言葉を使う\n「効率化したい」→「効率化ですね」", "duration": 50}], "part2": [{"title": "シーン4: バックトラッキング", "content": "山本先輩:「言葉のミラーリングで\n　　　　特に効果的なのが『バックトラッキング』だ」\n\n【バックトラッキング（オウム返し）】\n相手の言葉をそのまま繰り返す技法\n\n顧客:「在庫管理が大変でね」\n営業:「在庫管理が大変なんですね」\n\n顧客:「残業が増えてしまって」\n営業:「残業が増えているんですね」\n\n【効果】\n・「聴いてもらえている」と感じる\n・自分の考えが整理される\n・話を続けたくなる\n\n【コツ】\n・そのまま繰り返す（言い換えない）\n・感情を込めて繰り返す\n・うなずきながら\n\n山本先輩:「シンプルだけど、\n　　　　信頼関係を築く最強の技術だ」", "duration": 50}, {"title": "シーン5: 健太の実践", "content": "（商談で）\n\n社長:「うちは小さい会社だから、\n　　なかなかシステム化が進まなくてね...」\n\n健太:「小さい会社だと、なかなか\n　　システム化が進まないですよね」\n　　（バックトラッキング）\n\n社長:「そうなんだよ。特に在庫管理が大変で」\n\n健太:（社長が腕を組んだのを見て、\n　　　少し遅れて自分も腕を組む）\n　　「在庫管理が大変なんですね。\n　　具体的にどんなことでお困りですか？」\n\n社長:「棚卸しに3日もかかるんだよ」\n\n健太:「3日も...（真剣な表情で）\n　　それは本当に大変ですね」\n\n社長:「そうなんだよ！わかってくれるか」", "duration": 50}, {"title": "シーン6: ミラーリングの注意点", "content": "山本先輩:「ミラーリングの注意点だ」\n\n【注意点】\n\n1️⃣ わざとらしくしない\n・完全に同じ動きをしない\n・少し遅れて、さりげなく\n・バレると逆効果\n\n2️⃣ やりすぎない\n・常にミラーリングしない\n・自然な範囲で\n・相手を観察する余裕を持つ\n\n3️⃣ 不快な動作は真似ない\n・貧乏ゆすりなど\n・相手が不快になる動作はNG\n\n山本先輩:「テクニックに走りすぎると\n　　　　不自然になる。\n　　　　大切なのは、\n　　　　『相手に興味を持つ』こと。\n　　　　その姿勢があれば、\n　　　　自然とミラーリングが起きる」\n\n【今日の学び】\n「人は自分に似た人を好きになる」", "duration": 40}]}', '{"title": "ミラーリングの技法", "content": "【非言語】\n・姿勢、ジェスチャー、表情\n\n【言語】\n・話すスピード、声のトーン\n・バックトラッキング（オウム返し）\n\n【コツ】\n・さりげなく、少し遅れて\n・わざとらしくしない", "audioText": "相手の動作や言葉をさりげなく真似ることで、信頼関係が築けます。", "highlight": "テクニックより「相手に興味を持つ」姿勢が大切"}', '[{"options": ["完全に同じ動きをする", "さりげなく、少し遅れて", "常にミラーリングする", "すぐに真似る"], "question": "ミラーリングで大切なのは？", "explanation": "さりげなく、少し遅れて行うことで自然なミラーリングになります。", "correctIndex": 1}, {"options": ["話を要約する", "相手の言葉をそのまま繰り返す", "自分の意見を言う", "話題を変える"], "question": "バックトラッキングとは？", "explanation": "相手の言葉をそのまま繰り返すことで、「聴いてもらえている」と感じさせます。", "correctIndex": 1}]', '{"text": "People like people who are like themselves.", "author": "Symphony営業格言", "textJa": "鏡のように相手に合わせることで、心の距離は縮まる。"}', '[{"options": [{"text": "「大丈夫ですよ！」と明るく言う", "points": 5, "feedback": "相手の感情に合わせていません。ミラーリングを意識しましょう。", "isCorrect": false}, {"text": "「売上が伸び悩んでいるんですね...」と同じトーンで繰り返す", "points": 30, "feedback": "バックトラッキングと感情のミラーリングができています。", "isCorrect": true}, {"text": "「それは弊社の製品で解決できます！」と売り込む", "points": 0, "feedback": "まず傾聴してから。すぐの売り込みは逆効果です。", "isCorrect": false}], "situation": "顧客が困った表情で話しています。", "customerLine": "最近、売上が伸び悩んでてね..."}, {"options": [{"text": "早口で製品の良さを説明する", "points": 0, "feedback": "相手のペースに合わせましょう。", "isCorrect": false}, {"text": "相手のペースに合わせてゆっくり話す", "points": 30, "feedback": "話すスピードのミラーリングができています。", "isCorrect": true}, {"text": "「早く決めた方がいいですよ」と急かす", "points": 0, "feedback": "相手のペースを尊重しましょう。", "isCorrect": false}], "situation": "顧客がゆっくり話しています。", "customerLine": "うちは...ゆっくり...考えて決めるタイプでね..."}]', '{"question": "「この人と話しやすい」と感じた相手との会話で、無意識にミラーリングしていましたか？", "placeholder": "例: 仲の良い顧客との会話で、自然と同じテンポで話していた気がする"}', '["相手の話すスピードに合わせる", "相手の言葉をバックトラッキングする", "姿勢やジェスチャーをさりげなく真似る", "テクニックより「相手に興味を持つ」ことを意識する"]', '{"title": "ミラーリング実践シート", "fields": [{"label": "観察するポイント", "placeholder": "例: 話すスピード、声のトーン、姿勢、ジェスチャー"}, {"label": "バックトラッキングで使うフレーズ", "placeholder": "例: 「○○なんですね」「○○ということですね」"}, {"label": "注意すること", "placeholder": "例: わざとらしくしない、少し遅れて真似る、やりすぎない"}], "description": "次の商談でミラーリングを実践しましょう。"}', NULL, '2026-01-21 17:48:33.292274+00', '2026-01-21 17:48:33.292274+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (70, 42, '選択のパラドックス', '選択肢は少ない方が決まりやすい', '{"icon": "list", "name": "選択の案内人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["話を要約する", "相手の言葉をそのまま繰り返す", "自分の意見を言う", "話題を変える"], "question": "バックトラッキングとは？", "explanation": "相手の言葉をそのまま繰り返すことで「聴いてもらえている」と感じさせましたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: ジャムの実験", "content": "（スーパーで）\n\n健太:「先輩、このジャム売り場、\n　　種類多すぎて選べないです...」\n\n山本先輩:「それが『選択のパラドックス』だ」\n\n健太:「選択のパラドックス？」\n\n山本先輩:「有名な実験がある。\n　　　　ジャムを6種類並べた時と、\n　　　　24種類並べた時、\n　　　　どっちが売れたと思う？」\n\n健太:「24種類の方が選べて嬉しいから...\n　　24種類？」\n\n山本先輩:「逆だ。6種類の方が10倍売れた」\n\n健太:「えっ！？」", "duration": 45}, {"title": "シーン2: 選択のパラドックスの科学", "content": "山本先輩:「選択のパラドックスを説明しよう」\n\n【選択のパラドックス】\n選択肢が多すぎると、\n人は選べなくなる（決定麻痺）\n\n【ジャムの実験（Iyengar & Lepper, 2000）】\n・24種類のジャム → 購入率3%\n・6種類のジャム → 購入率30%\n\n【なぜ選択肢が多いと選べないか】\n\n1. 比較疲れ\n選択肢が多いと、比較するのに疲れる\n\n2. 後悔への恐れ\n「もっと良いのがあったかも」と不安\n\n3. 決定の先延ばし\n「また今度考えよう」と後回し\n\n山本先輩:「選択肢を増やせば売れる、\n　　　　というのは間違いなんだ」", "duration": 55}, {"title": "シーン3: 営業での活用", "content": "山本先輩:「営業での活用方法を見てみよう」\n\n【選択肢の最適数】\n・2〜3が最適\n・最大でも5まで\n・それ以上は決定麻痺を招く\n\n【提案の構造化】\n\n❌ NG例\n「弊社にはA、B、C、D、E、F、Gの\n　7つのプランがあります。\n　どれが良いですか？」\n→ 顧客は選べない\n\n✅ OK例\n「御社に合うのはAかBです。\n　Aは○○が特徴、Bは△△が特徴。\n　どちらが御社に合いそうですか？」\n→ 顧客は選びやすい\n\n山本先輩:「営業の仕事は、\n　　　　選択肢を増やすことではなく、\n　　　　選択肢を絞ることだ」", "duration": 50}], "part2": [{"title": "シーン4: 推奨という導き", "content": "健太:「でも、絞りすぎると\n　　押し付けに見えませんか？」\n\n山本先輩:「だから『推奨』するんだ」\n\n【推奨の伝え方】\n\n1️⃣ 選択肢を2〜3に絞る\n「御社に合うのはAとBです」\n\n2️⃣ 違いを明確にする\n「Aは○○が強み、Bは△△が強み」\n\n3️⃣ 推奨を伝える\n「御社の課題を考えると、\n　私はAをお勧めします」\n\n4️⃣ 理由を添える\n「なぜなら、○○という課題に\n　Aの△△が最適だからです」\n\n5️⃣ 最終判断は顧客に\n「もちろん、最終判断は御社にお任せします」\n\n山本先輩:「推奨は押し付けではなく、\n　　　　『プロとしてのアドバイス』だ」", "duration": 50}, {"title": "シーン5: 健太の実践", "content": "（商談で）\n\n社長:「で、どのプランがいいの？\n　　色々あってよくわからないな...」\n\n健太:「はい、弊社には複数のプランがありますが、\n　　御社に合うのは2つです」\n\n社長:「2つ？」\n\n健太:「スタンダードプランと\n　　プレミアムプランです。\n　　スタンダードは基本機能に特化、\n　　プレミアムはサポートが手厚いです」\n\n社長:「うーん、どっちがいいかな...」\n\n健太:「私の推奨はスタンダードプランです。\n　　御社はシステムに詳しい方がいらっしゃるので、\n　　まずはスタンダードで十分だと思います。\n　　必要に応じてアップグレードも可能です」\n\n社長:「なるほど、じゃあスタンダードで」", "duration": 50}, {"title": "シーン6: 決断をサポートする", "content": "山本先輩:「どうだった？」\n\n健太:「選択肢を絞って、推奨したら\n　　すぐに決まりました！」\n\n山本先輩:「そうだ。営業の仕事は\n　　　　『売ること』だけじゃない。\n　　　　『決断をサポートする』ことだ」\n\n【営業の役割】\n\n情報の整理\n→ 複雑な選択肢をシンプルにする\n\n専門家としての推奨\n→ プロの視点でアドバイスする\n\n決断のサポート\n→ 顧客が安心して決められるようにする\n\n山本先輩:「選択肢を増やすのは簡単だが、\n　　　　絞るのはプロの仕事。\n　　　　顧客の決断を助けることが、\n　　　　営業の本当の価値だ」\n\n【今日の学び】\n「選択肢は少ない方が決まりやすい」", "duration": 40}]}', '{"title": "選択のパラドックス", "content": "【選択肢の最適数】\n2〜3が最適、最大5まで\nそれ以上は「決定麻痺」を招く\n\n【推奨の伝え方】\n1. 選択肢を絞る\n2. 違いを明確にする\n3. 推奨と理由を伝える\n4. 最終判断は顧客に任せる", "audioText": "選択肢が多すぎると決められなくなります。2〜3に絞り、推奨を伝えましょう。", "highlight": "選択肢を増やすのは簡単、絞るのはプロの仕事"}', '[{"options": ["1つ", "2〜3つ", "7つ以上", "多いほど良い"], "question": "選択肢の最適な数は？", "explanation": "2〜3つが最適です。多すぎると決定麻痺を招きます。", "correctIndex": 1}, {"options": ["売りたい商品を売るため", "顧客の決断をサポートするため", "説明を楽にするため", "在庫を減らすため"], "question": "営業が選択肢を絞る理由は？", "explanation": "選択肢を絞ることで、顧客が決断しやすくなります。", "correctIndex": 1}]', '{"text": "More is less.", "author": "Symphony営業格言", "textJa": "選択肢を絞ることは、顧客への最高のサービスである。"}', '[{"options": [{"text": "「全部説明しますね」と7つ全て説明", "points": 5, "feedback": "情報過多で決定麻痺を悪化させます。", "isCorrect": false}, {"text": "「御社に合うのはこの2つです」と絞る", "points": 30, "feedback": "選択肢を絞ることで、決断しやすくなります。", "isCorrect": true}, {"text": "「お好きなものを選んでください」と任せる", "points": 10, "feedback": "プロとしてのアドバイスを求めています。", "isCorrect": false}], "situation": "顧客が「プランがたくさんあって選べない」と言いました。", "customerLine": "プランが多すぎてよくわからないな..."}, {"options": [{"text": "「どちらでもいいと思います」と曖昧に", "points": 5, "feedback": "プロとしての推奨を伝えましょう。", "isCorrect": false}, {"text": "「御社の課題を考えると、私はAをお勧めします。なぜなら...」と推奨", "points": 30, "feedback": "推奨と理由を伝えることで、決断をサポートできます。", "isCorrect": true}, {"text": "「早く決めてください」と急かす", "points": 0, "feedback": "サポートではなく、プレッシャーになっています。", "isCorrect": false}], "situation": "2つに絞った後、顧客がまだ迷っています。", "customerLine": "AとB、どっちがいいかな..."}]', '{"question": "提案時、選択肢を多く出しすぎて顧客を迷わせた経験はありますか？", "placeholder": "例: 5つのプランを全部説明して「また検討します」と言われた。次回は2〜3に絞る"}', '["提案する選択肢は2〜3に絞る", "選択肢の違いを明確に説明する", "プロとして推奨を伝える", "推奨には必ず理由を添える"]', '{"title": "選択肢の絞り込み", "fields": [{"label": "全ての選択肢（プラン）", "placeholder": "例: スタンダード、プレミアム、エンタープライズ、カスタム"}, {"label": "絞った選択肢（2〜3）", "placeholder": "例: スタンダードとプレミアム"}, {"label": "推奨とその理由", "placeholder": "例: スタンダードを推奨。御社の規模と課題に最適だから"}], "description": "提案する選択肢を整理しましょう。"}', NULL, '2026-01-21 17:48:33.994838+00', '2026-01-21 17:48:33.994838+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (71, 43, '傾聴の技術', '聴くことは、最高の営業スキルである', '{"icon": "ear", "name": "傾聴マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["ジークムント・フロイト", "カール・ロジャーズ", "アルバート・バンデューラ", "ダニエル・カーネマン"], "question": "アクティブリスニング（積極的傾聴）を提唱した心理学者は誰でしょうか？", "explanation": "アクティブリスニングは1957年にカール・ロジャーズとリチャード・ファーソンによって提唱されました。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 一方的な商談", "content": "健太:「弊社のSymphonyは在庫管理、販売管理、整備管理が\n      一元化できるシステムでして...」\n店長:「...」\n健太:「導入実績も300社以上で、お客様満足度も95%以上です！」\n店長:「あー、そうなんだ」\n健太:「価格も月額3万円からとリーズナブルで...」\n店長:「今日は時間ないんだ。また今度ね」\n\n健太（心の声）:「あんなに説明したのに...\n         何がダメだったんだろう...」", "duration": 45}, {"title": "シーン2: 山本先輩の観察", "content": "山本先輩:「健太、さっきの商談見てたよ」\n健太:「すみません、ダメでした...」\n山本先輩:「何分話してた？」\n健太:「10分くらいですかね」\n山本先輩:「そのうち店長が話したのは？」\n健太:「えーと...ほとんど僕が...」\n山本先輩:「それが問題だよ。\n         『聴く』ことができてない」\n健太:「聴く...ですか？」", "duration": 45}, {"title": "シーン3: アクティブリスニングとは", "content": "山本先輩:「カール・ロジャーズって知ってる？」\n健太:「心理学者の...？」\n山本先輩:「そう。彼が提唱した『アクティブリスニング』、\n         積極的傾聴という技法がある」\n\n【アクティブリスニングの3要素】\n\n①共感的理解\n →相手の立場で感じ取る\n\n②無条件の肯定的配慮\n →評価・判断せず受け入れる\n\n③自己一致\n →本心と言動を一致させる\n\n山本先輩:「営業は『話す仕事』じゃない。\n         『聴く仕事』なんだ」", "duration": 30}], "part2": [{"title": "シーン4: 傾聴の実践", "content": "山本先輩:「次の商談、俺が見本を見せるから観察してて」\n\n山本先輩:「本日はお忙しい中ありがとうございます。\n        まず、今のお仕事で困っていることを\n        お聞かせいただけますか？」\n店長:「うーん、スタッフが辞めてね...」\n山本先輩:「スタッフが辞められた...（うなずく）」\n店長:「そう、ベテランの事務員が」\n山本先輩:「ベテランの方となると、\n        業務の引き継ぎも大変だったのでは？」\n店長:「そうなんだよ！誰もわからなくて...」", "duration": 45}, {"title": "シーン5: SOLERの姿勢", "content": "健太（観察メモ）:\n\n山本先輩の姿勢を観察...\n\nS（Squarely）: 体を店長に正対させている\nO（Open）: 腕を組まず、開いた姿勢\nL（Lean）: やや前傾で関心を示している\nE（Eye Contact）: 適度に目を合わせている\nR（Relaxed）: リラックスして自然体\n\n山本先輩:「毎日その状態だと、本当にお辛いですね...」\n店長:「わかってくれるか...実はもう限界で...」\n\n店長がどんどん話し始めた！", "duration": 30}, {"title": "シーン6: 振り返り", "content": "健太:「先輩、店長がすごく話してましたね」\n山本先輩:「俺がしたのは『聴く』ことだけ」\n健太:「でも、質問もしてましたよね？」\n山本先輩:「それは相手の話を深めるため。\n         自分が話すためじゃない」\n\n【ラッカムの研究結果】\n35,000件の商談分析\n・成功商談：営業30〜40%、顧客60〜70%\n・失敗商談：営業60%以上\n\n山本先輩:「トップセールスは、話すより聴く。\n         これが科学的にも証明されてるんだ」\n\n健太:「聴くことが、最高の営業スキル...」", "duration": 15}]}', '{"title": "アクティブリスニングの3要素", "content": "共感的理解 × 無条件の肯定的配慮 × 自己一致", "audioText": "アクティブリスニングとは、相手の言葉の背後にある感情や意図を理解しようと能動的に関わる聴き方です。カール・ロジャーズが提唱したこの技法は、営業においても顧客の本音を引き出す最強のスキルです。", "highlight": "トップセールスは話す30%、聴く70%"}', '[{"options": ["共感的理解", "無条件の肯定的配慮", "論理的説得", "自己一致"], "question": "アクティブリスニングの3要素に含まれないものは？", "explanation": "アクティブリスニングの3要素は「共感的理解」「無条件の肯定的配慮」「自己一致」です。論理的説得は含まれません。", "correctIndex": 2}, {"options": ["Listen（聴く）", "Lean（前傾する）", "Look（見る）", "Learn（学ぶ）"], "question": "SOLERの「L」が意味するものは？", "explanation": "SOLERの「L」はLean（適度に前傾する）を意味します。関心を示すために、やや前のめりの姿勢を取ることです。", "correctIndex": 1}, {"options": ["60〜70%", "50%", "30〜40%", "10〜20%"], "question": "ラッカムの研究によると、成功した商談での営業の発言割合は？", "explanation": "ニール・ラッカムの35,000件の商談分析によると、成功した商談では営業の発言は30〜40%、顧客の発言が60〜70%でした。", "correctIndex": 2}]', '{"text": "When you listen to someone, you should give up or put aside all your subjective experience and be completely present.", "author": "カール・ロジャーズ（Carl Rogers）", "textJa": "人の話を聴くとき、自分の主観的な経験を脇に置き、完全にその場に存在しなければならない。"}', '[{"options": [{"text": "そうですか。弊社のシステムなら仕入れ管理も簡単にできますよ！", "points": 0, "feedback": "相手の話を聴かずに、すぐに売り込みに入っています。まずは共感的理解を示しましょう。", "isCorrect": false}, {"text": "仕入れが大変...具体的にどのような点で大変なのですか？", "points": 30, "feedback": "素晴らしい！相手の言葉を繰り返し（オウム返し）、さらに深掘りする質問をしています。これがアクティブリスニングです。", "isCorrect": true}, {"text": "他の販売店さんも同じこと言ってますね。業界全体の問題ですよ。", "points": 5, "feedback": "一般論で片付けてしまっています。この顧客固有の状況を理解しようとしていません。", "isCorrect": false}], "situation": "顧客が「最近、仕入れが大変でね...」と言いました。", "customerLine": "最近、仕入れが大変でね..."}, {"options": [{"text": "いえいえ、小さい店舗こそシステム化のメリットが大きいんですよ！", "points": 0, "feedback": "相手の発言を否定しています。無条件の肯定的配慮ができていません。", "isCorrect": false}, {"text": "そうですよね。では失礼します。", "points": 5, "feedback": "諦めが早すぎます。相手の言葉の背後にある本当の気持ちを探りましょう。", "isCorrect": false}, {"text": "システムは必要ないとお感じなんですね。差し支えなければ、そう思われる理由を教えていただけますか？", "points": 30, "feedback": "相手の発言を受け入れた上で、その背景を探る質問をしています。これが共感的理解への第一歩です。", "isCorrect": true}], "situation": "顧客が「うちは小さい店だから、システムなんて必要ないよ」と言いました。", "customerLine": "うちは小さい店だから、システムなんて必要ないよ"}, {"options": [{"text": "そうですか。ところで本題に戻りますが...（話を遮る）", "points": 0, "feedback": "相手の話を遮ることは、信頼関係を損ないます。愚痴も大切な情報です。", "isCorrect": false}, {"text": "若い社員の教育、大変ですよね。社長がお一人で抱えていらっしゃるのでは？", "points": 30, "feedback": "感情に共感しながら、本質的な課題（人材・教育の問題）を探っています。この愚痴の中にニーズが隠れているかもしれません。", "isCorrect": true}, {"text": "（黙ってうなずきながら聞き続ける）", "points": 10, "feedback": "傾聴は大切ですが、適度な相槌や質問で会話を深めることも重要です。", "isCorrect": false}], "situation": "顧客が長々と愚痴を話し始め、本題から逸れてきました。", "customerLine": "それでね、最近の若い社員は本当に困るんだよ。挨拶もろくにできなくて..."}]', '{"question": "今日学んだ傾聴の技術を、明日からの営業活動でどう実践しますか？", "placeholder": "例: 商談の最初5分は自分から話さず、相手の話を聴くことに集中する"}', '["次の商談で、自分の発言を30%以下に抑えることを意識する", "SOLERの姿勢を鏡の前で練習する", "相手の言葉を「言い換え」て返す練習をする", "商談後に「顧客が何分話したか」を振り返る"]', '{"title": "傾聴フレーズ練習", "fields": [{"label": "顧客「最近売上が落ちてきてね...」への言い換え（Paraphrasing）", "placeholder": "例: 売上が落ちてきている...具体的にはいつ頃からですか？"}, {"label": "顧客「もう疲れたよ」への感情の反映（Reflecting）", "placeholder": "例: お疲れなんですね...毎日大変な状況が続いているのでしょうか"}, {"label": "長い話を聴いた後の要約（Summarizing）", "placeholder": "例: ここまでのお話をまとめると、①人手不足、②事務作業の負担、③将来への不安の3点が課題ということですね"}], "description": "以下の顧客の発言に対して、傾聴のテクニックを使った返答を考えてみましょう。"}', NULL, '2026-01-21 17:48:34.81451+00', '2026-01-21 17:48:34.81451+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (72, 44, '質問力①', '質問の質が、営業の質を決める', '{"icon": "help-circle", "name": "質問マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["クローズド質問", "オープン質問", "誘導質問", "確認質問"], "question": "相手が自由に答えられる質問を何と呼びますか？", "explanation": "オープン質問は「何」「なぜ」「どのように」で始まり、相手が自由に答えられる質問です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 質問が下手な健太", "content": "健太:「御社は在庫管理されていますか？」\n店長:「うん、してるよ」\n健太:「エクセルですか？」\n店長:「そうだね」\n健太:「困っていることはありますか？」\n店長:「まあ、あるかな...」\n\n健太（心の声）:「話が広がらない...\n         何を聞けばいいんだろう」", "duration": 30}, {"title": "シーン2: 山本先輩の指摘", "content": "山本先輩:「健太、今の質問、気づいたことある？」\n健太:「うーん...あまり話が広がらなかった気が」\n山本先輩:「全部『はい/いいえ』で\n         答えられる質問だったからだよ」\n\n【クローズド質問】\n・「はい/いいえ」で答えられる\n・確認には便利だが、情報が限られる\n\n山本先輩:「情報を引き出すには\n         別の質問が必要なんだ」", "duration": 30}, {"title": "シーン3: オープン質問とは", "content": "山本先輩:「オープン質問って聞いたことある？」\n\n【オープン質問】\n・「何」「なぜ」「どのように」で始まる\n・相手が自由に答えられる\n・情報収集・深掘りに有効\n\n例:\n❌「困っていますか？」（クローズド）\n✅「どのようなことでお困りですか？」（オープン）\n\n山本先輩:「同じことを聞いても、\n         質問の仕方で答えが全然違うんだ」", "duration": 30}], "part2": [{"title": "シーン4: 質問の漏斗技法", "content": "山本先輩:「効果的な質問には順序がある。\n         『漏斗（ファネル）』をイメージして」\n\n【質問の漏斗技法】\n広い → 狭い の順で質問する\n\n①広いオープン質問\n 「事業で困っていることは？」\n\n②絞り込みオープン質問\n 「在庫管理について詳しく教えてください」\n\n③具体化オープン質問\n 「月に何時間くらいかかっていますか？」\n\n④確認クローズド質問\n 「月20時間ということですね？」", "duration": 45}, {"title": "シーン5: 実践してみる", "content": "健太:「もう一度やらせてください」\n\n健太:「在庫管理について、\n      どのようにされていますか？」\n店長:「エクセルでやってるんだけどね、\n      毎月棚卸しが大変で...」\n健太:「棚卸しが大変というのは、\n      具体的にはどのような点でしょうか？」\n店長:「数が合わないことが多くてね。\n      原因を探すのに丸一日かかることもある」\n健太:「丸一日...それは大変ですね。\n      月に何回くらいありますか？」\n店長:「月末は毎回だね」\n\n話が広がり始めた！", "duration": 45}, {"title": "シーン6: 使い分けのコツ", "content": "山本先輩:「どうだ、違いがわかったか？」\n\n健太:「はい！オープン質問で聞くと、\n      相手が詳しく話してくれますね」\n\n山本先輩:「ただし、使い分けが大事だ」\n\n【使い分けの目安】\n・序盤：オープン質問で情報収集\n・中盤：オープン質問で深掘り\n・終盤：クローズド質問で確認\n・クロージング：クローズド質問で合意\n\n山本先輩:「質問の質が、営業の質を決める。\n         意識して練習しよう」", "duration": 30}]}', '{"title": "オープン質問 vs クローズド質問", "content": "オープン：何・なぜ・どのように → 情報収集\nクローズド：はい/いいえ → 確認・合意", "audioText": "オープン質問は情報を引き出し、クローズド質問は確認に使います。商談の序盤はオープン質問で広く聞き、終盤はクローズド質問で合意を取りましょう。", "highlight": "質問の漏斗：広く聞いてから、狭く絞る"}', '[{"options": ["オープン質問", "クローズド質問", "示唆質問", "解決質問"], "question": "「在庫管理でお困りですか？」はどちらの質問タイプ？", "explanation": "「はい/いいえ」で答えられるのでクローズド質問です。「どのようなことでお困りですか？」がオープン質問です。", "correctIndex": 1}, {"options": ["狭い→広い", "広い→狭い", "クローズド→オープン", "ランダム"], "question": "質問の漏斗技法で正しい順序は？", "explanation": "漏斗技法は「広い→狭い」の順序で質問します。まずオープン質問で広く聞き、徐々に絞り込みます。", "correctIndex": 1}, {"options": ["オープン質問", "クローズド質問", "誘導質問", "反語質問"], "question": "商談の終盤で使うべき質問タイプは？", "explanation": "商談の終盤では、クローズド質問で確認・合意を取ります。「来週火曜日でよろしいですか？」など。", "correctIndex": 1}]', '{"text": "Judge a man by his questions rather than by his answers.", "author": "ヴォルテール（Voltaire）", "textJa": "人を判断するには、その答えよりも、その質問を見よ。"}', '[{"options": [{"text": "「在庫管理システムを使っていますか？」", "points": 5, "feedback": "クローズド質問です。「はい」「いいえ」で終わってしまい、詳しい情報が得られません。", "isCorrect": false}, {"text": "「現在、在庫管理はどのようにされていますか？」", "points": 30, "feedback": "オープン質問です。相手が自由に答えられ、詳しい情報を引き出せます。", "isCorrect": true}, {"text": "「困っていることはありませんか？」", "points": 5, "feedback": "クローズド質問です。「特にない」と言われると話が終わってしまいます。", "isCorrect": false}], "situation": "初めて訪問した店舗で、店長に現状を聞きたい場面です。", "customerLine": "何か用？"}, {"options": [{"text": "「エクセルを使っていますか？」", "points": 5, "feedback": "クローズド質問で、話を狭めてしまっています。まだ広く聞く段階です。", "isCorrect": false}, {"text": "「大変なのは棚卸しですか？」", "points": 10, "feedback": "クローズド質問で、自分の推測を確認しようとしています。相手に語らせましょう。", "isCorrect": false}, {"text": "「具体的にはどのような点が大変ですか？」", "points": 30, "feedback": "オープン質問で深掘りしています。相手が自由に詳細を話せます。", "isCorrect": true}], "situation": "店長が「在庫管理が大変」と言いました。もっと詳しく聞きたい場面です。", "customerLine": "在庫管理が大変でね..."}, {"options": [{"text": "「他に困っていることはありますか？」", "points": 10, "feedback": "確認の場面でまた広げると、話がまとまりません。まず今の内容を確認しましょう。", "isCorrect": false}, {"text": "「つまり、月末の棚卸しに3日かかっているということですね？」", "points": 30, "feedback": "クローズド質問で確認しています。終盤での適切な使い方です。", "isCorrect": true}, {"text": "「なぜそんなにかかるのですか？」", "points": 15, "feedback": "オープン質問で深掘りを続けています。確認してから深掘りしましょう。", "isCorrect": false}], "situation": "詳しく話を聞いた後、内容を確認したい場面です。", "customerLine": "（詳しく話してくれた後）"}]', '{"question": "明日から、どのような場面でオープン質問を意識的に使いますか？", "placeholder": "例: 商談の最初の5分間は、必ず「どのように」「何が」で始まる質問をする"}', '["「どのように」「何が」で始まる質問を意識的に使う", "クローズド質問を使いそうになったら、オープン質問に言い換える", "商談後に「オープン/クローズドの比率」を振り返る", "質問の漏斗を意識して、広い質問から始める"]', '{"title": "質問の変換練習", "fields": [{"label": "「システムを導入していますか？」をオープン質問に", "placeholder": "例: 現在、業務管理はどのようにされていますか？"}, {"label": "「困っていますか？」をオープン質問に", "placeholder": "例: どのようなことでお困りですか？"}, {"label": "「忙しいですか？」をオープン質問に", "placeholder": "例: 最近のお仕事の状況はいかがですか？"}], "description": "以下のクローズド質問をオープン質問に変換してみましょう。"}', NULL, '2026-01-21 17:48:35.537877+00', '2026-01-21 17:48:35.537877+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (73, 45, '質問力②', '顧客は、自分で気づいた問題しか本気で解決しない', '{"icon": "target", "name": "SPINマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Information（情報）", "Implication（示唆）", "Interest（関心）", "Insight（洞察）"], "question": "SPIN話法の「I」は何を表しますか？", "explanation": "SPIN話法の「I」はImplication（示唆質問）で、問題を放置した場合の影響を考えさせる質問です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 課題を伝えても響かない", "content": "健太:「御社の在庫管理、月20時間もかかっていますよね。\n      これは大きな課題だと思います」\n店長:「まあ、そうかもしれないけど、\n      今までもそれでやってきたからね...」\n健太:「でも、効率化できれば\n      その時間を営業に使えますよ！」\n店長:「うーん、検討しておくよ」\n\n健太（心の声）:「課題を伝えているのに、\n         なぜ響かないんだろう...」", "duration": 30}, {"title": "シーン2: SPIN話法との出会い", "content": "山本先輩:「健太、課題は誰が見つけた？」\n健太:「え？僕が見つけて伝えました」\n山本先輩:「そこが問題なんだ。\n         人は『自分で気づいた問題』しか\n         本気で解決しようとしない」\n\n【SPIN話法とは】\nニール・ラッカムが35,000件の商談を\n分析して導き出した質問技法\n\nS = Situation（状況質問）\nP = Problem（問題質問）\nI = Implication（示唆質問）\nN = Need-payoff（解決質問）\n\n山本先輩:「質問で顧客自身に\n         気づかせるんだ」", "duration": 45}, {"title": "シーン3: S→P→I→N の流れ", "content": "【S: 状況質問】\n顧客の現状を把握する\n「現在の在庫管理方法は？」\n\n【P: 問題質問】\n課題・不満を引き出す\n「その方法で困っていることは？」\n\n【I: 示唆質問】★最重要\n問題の深刻さを認識させる\n「その状況が続くと、どんな影響が？」\n\n【N: 解決質問】\n解決策の価値を顧客に語らせる\n「もし自動化できたら、どうなりますか？」\n\n山本先輩:「特に『I』が大事だ。\n         問題を放置するリスクを\n         顧客自身に考えさせるんだ」", "duration": 45}], "part2": [{"title": "シーン4: SPIN実践例", "content": "山本先輩:「実際にやってみよう」\n\n【S: 状況質問】\n「現在、在庫管理はどのようにされていますか？」\n→「エクセルでやっています」\n\n【P: 問題質問】\n「エクセル管理で困っていることはありますか？」\n→「月末の棚卸しに3日かかるんですよ」\n\n【I: 示唆質問】\n「3日間、その業務に縛られると、\n 他の仕事にどんな影響がありますか？」\n→「営業に出られないし、\n  残業も増えて社員が疲弊してる...」\n\n【N: 解決質問】\n「もし棚卸しが1日で終わったら、\n 空いた2日間で何ができそうですか？」\n→「新規開拓に回せるな...売上も上がるかも」", "duration": 60}, {"title": "シーン5: 顧客自身が語る価値", "content": "山本先輩:「気づいたか？」\n健太:「最後、店長自身が\n      『売上も上がるかも』と言いました」\n山本先輩:「そう。俺は一度も\n         『売上が上がりますよ』とは言ってない」\n\n【SPIN話法の核心】\n・営業が価値を語る → 売り込みに聞こえる\n・顧客が価値を語る → 自分で気づいた発見\n\n山本先輩:「顧客は、自分で気づいた問題しか\n         本気で解決しようとしない。\n         SPIN話法は、その気づきを\n         質問で引き出す技術なんだ」", "duration": 30}, {"title": "シーン6: 示唆質問のパワー", "content": "山本先輩:「ラッカムの研究では、\n         トップセールスは示唆質問を\n         平均の4倍使うそうだ」\n\n【示唆質問（I）の例】\n・「その状況が続くと、どんな影響が？」\n・「それは他の業務にも影響していますか？」\n・「年間で考えると、どれくらいのロスですか？」\n・「社員の方のモチベーションにも影響が？」\n\n健太:「問題を大きく見せるんですね」\n山本先輩:「大きく『見せる』んじゃない。\n         『気づかせる』んだ。\n         本当に大きな問題なんだから」", "duration": 30}]}', '{"title": "SPIN話法の4ステップ", "content": "S(状況) → P(問題) → I(示唆) → N(解決)", "audioText": "SPIN話法は、状況質問で現状を把握し、問題質問で課題を引き出し、示唆質問で深刻さを認識させ、解決質問で顧客自身に価値を語らせる技法です。", "highlight": "トップセールスは示唆質問を4倍使う"}', '[{"options": ["状況質問", "問題質問", "示唆質問", "解決質問"], "question": "「その状況が続くと、どんな影響がありますか？」は何質問？", "explanation": "問題を放置した場合の影響を考えさせる質問なので、示唆質問（I）です。", "correctIndex": 2}, {"options": ["状況質問", "問題質問", "示唆質問", "解決質問"], "question": "SPIN話法で最も重要とされる質問は？", "explanation": "示唆質問（I）が最も重要です。トップセールスは平均の4倍使っています。", "correctIndex": 2}, {"options": ["状況質問", "問題質問", "示唆質問", "解決質問"], "question": "「もし解決できたら、どうなりますか？」は何質問？", "explanation": "解決後の価値を顧客自身に語らせる質問なので、解決質問（N）です。", "correctIndex": 3}]', '{"text": "Customers don''t buy products, they buy solutions to problems they have acknowledged.", "author": "ニール・ラッカム（Neil Rackham）", "textJa": "顧客は製品を買うのではない。自分で認めた問題の解決策を買うのだ。"}', '[{"options": [{"text": "「20時間もかかるんですか？それは大変ですね」", "points": 10, "feedback": "共感は良いですが、質問ではありません。示唆質問で深掘りしましょう。", "isCorrect": false}, {"text": "「その20時間、もし他の業務に使えたら、どんな影響がありますか？」", "points": 30, "feedback": "示唆質問です。問題を放置するコストを顧客自身に考えさせています。", "isCorrect": true}, {"text": "「弊社のシステムなら5時間に短縮できますよ！」", "points": 0, "feedback": "いきなり解決策を提示しています。顧客に気づきを与える前の売り込みは効果が薄いです。", "isCorrect": false}], "situation": "店長が「在庫管理に月20時間かかる」と言いました。示唆質問をしたい場面です。", "customerLine": "在庫管理に月20時間くらいかかってるかな"}, {"options": [{"text": "「他にも影響していることはありますか？」", "points": 15, "feedback": "まだ示唆質問を続けています。そろそろ解決質問に移りましょう。", "isCorrect": false}, {"text": "「もし在庫管理の時間が半分になったら、その時間で何ができそうですか？」", "points": 30, "feedback": "解決質問です。解決後の価値を顧客自身に語らせています。", "isCorrect": true}, {"text": "「だから弊社のシステムを導入すべきなんです」", "points": 0, "feedback": "売り込みになっています。まず顧客に解決策の価値を語らせましょう。", "isCorrect": false}], "situation": "店長が問題の深刻さに気づき始めました。解決質問をしたい場面です。", "customerLine": "確かに、営業に出る時間がないのは売上にも影響してるな..."}]', '{"question": "次の商談で、どのような示唆質問を使いますか？", "placeholder": "例: 「その状況が続くと、年間でどれくらいのコストになりますか？」という質問を使う"}', '["状況質問は最小限にして、問題質問・示唆質問を増やす", "「もし〜だったら、どうなりますか？」という解決質問を使う", "商談後、SPINのどの質問を使ったか振り返る", "示唆質問のバリエーションを5つ用意しておく"]', '{"title": "SPIN質問を作る練習", "fields": [{"label": "S（状況質問）：現状を把握する質問", "placeholder": "例: 現在、請求書はどのように作成されていますか？"}, {"label": "P（問題質問）：課題を引き出す質問", "placeholder": "例: 請求書作成で困っていることはありますか？"}, {"label": "I（示唆質問）：影響を考えさせる質問", "placeholder": "例: 請求書作成に時間がかかることで、他の業務にどんな影響がありますか？"}, {"label": "N（解決質問）：価値を語らせる質問", "placeholder": "例: もし請求書作成が自動化できたら、空いた時間で何ができそうですか？"}], "description": "「毎月の請求書作成に時間がかかる」という課題に対するSPIN質問を考えてみましょう。"}', NULL, '2026-01-21 17:48:36.376056+00', '2026-01-21 17:48:36.376056+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (74, 46, '雑談力', '雑談は、信頼関係を築く大切な投資時間', '{"icon": "smile", "name": "アイスブレイカー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["道路", "道楽・趣味", "どこか", "童話"], "question": "雑談のネタを覚える語呂合わせ「木戸に立てかけし衣食住」の「ど」は何を表す？", "explanation": "「ど」は道楽・趣味を表します。相手の趣味の話題は雑談で盛り上がりやすいです。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 沈黙の気まずさ", "content": "健太:「本日はお時間いただき\n      ありがとうございます」\n店長:「うん」\n健太:「えーと...（沈黙）」\n店長:「...」\n健太:「では、早速本題ですが...」\n店長:「...（なんか固いな）」\n\n健太（心の声）:「何を話せばいいか\n         わからない...緊張する...」", "duration": 30}, {"title": "シーン2: 雑談の目的", "content": "山本先輩:「健太、雑談は何のためにすると思う？」\n健太:「えーと...沈黙を埋めるため？」\n山本先輩:「それだけじゃない」\n\n【雑談の目的】\n1. 緊張をほぐす（自分も相手も）\n2. 相手との共通点を見つける\n3. 相手の人となりを知る\n4. 「話しやすい人」という印象を作る\n5. 本題に入りやすい雰囲気を作る\n\n山本先輩:「雑談は無駄話じゃない。\n         信頼関係を築く投資時間だ」", "duration": 45}, {"title": "シーン3: 鉄板ネタを覚えよう", "content": "山本先輩:「話題に困ったらこれを使え」\n\n【木戸に立てかけし衣食住】\nき：気候・季節\nど：道楽・趣味\nに：ニュース\nた：旅・旅行\nて：天気\nか：家族\nけ：健康\nし：仕事\n衣：ファッション\n食：食べ物\n住：住まい\n\n山本先輩:「全部覚えなくていい。\n         2〜3個使えるようになれば十分」", "duration": 30}], "part2": [{"title": "シーン4: 避けるべき話題", "content": "健太:「何でも話していいんですか？」\n山本先輩:「いや、避けるべき話題もある」\n\n【避けるべき話題】\n・政治、宗教（意見が分かれやすい）\n・他社の悪口、批判\n・プライベートすぎる話題（初対面では）\n・自分の話ばかり\n\n山本先輩:「特に政治と宗教は絶対NG。\n         どんなに盛り上がっても避けろ」\n\n健太:「自分の話ばかりもダメなんですね」\n山本先輩:「雑談は相手に興味を持つこと。\n         自分の話は聞かれた時だけでいい」", "duration": 30}, {"title": "シーン5: 雑談から本題への移行", "content": "山本先輩:「雑談の長さも大事だ」\n\n【適切な雑談の長さ】\n・初対面：2〜3分\n・2回目以降：1〜2分\n\n長すぎると「何しに来たの？」と思われる\n\n【移行フレーズ】\n「ところで、今日お伺いしたのは...」\n「さて、本題に入らせていただきますと...」\n「お忙しいところ恐れ入りますが、本日は...」\n\n山本先輩:「自然に本題に移る練習もしておこう」", "duration": 30}, {"title": "シーン6: 実践してみる", "content": "【翌日の商談】\n\n健太:「本日はありがとうございます。\n      外、暑いですね。\n      店内は涼しくて助かります」\n店長:「そうだね、今日は特に暑いから」\n健太:「この辺り、お昼に行ける\n      いいお店ありますか？」\n店長:「あー、隣の定食屋がうまいよ」\n健太:「へー！後で行ってみます。\n      さて、本日お伺いしたのは...」\n\n自然に本題に入れた！\n\n店長:（この子、話しやすいな）", "duration": 30}]}', '{"title": "雑談ネタの語呂合わせ", "content": "木戸に立てかけし衣食住\nき(気候)・ど(道楽)・に(ニュース)・た(旅)・て(天気)\nか(家族)・け(健康)・し(仕事)・衣・食・住", "audioText": "雑談は信頼関係を築くための投資時間です。木戸に立てかけし衣食住を覚えておけば、話題に困ることはありません。", "highlight": "雑談は2〜3分。長すぎず、短すぎず"}', '[{"options": ["30秒", "2〜3分", "10分", "本題まで入れない"], "question": "初対面の雑談の適切な長さは？", "explanation": "初対面では2〜3分が適切です。長すぎると「何しに来たの？」と思われます。", "correctIndex": 1}, {"options": ["天気の話", "趣味の話", "政治の話", "仕事の話"], "question": "雑談で避けるべき話題は？", "explanation": "政治や宗教は意見が分かれやすいため、ビジネスの雑談では避けるべきです。", "correctIndex": 2}]', '{"text": "雑談は無駄話ではない。信頼関係を築く大切な投資時間である。", "author": "Symphony営業格言", "textJa": "雑談は無駄話ではない。信頼関係を築く大切な投資時間である。"}', '[{"options": [{"text": "「早速ですが、弊社のシステムについてご説明させてください」", "points": 5, "feedback": "いきなり本題に入ると、固い印象を与えます。まず雑談で場を和ませましょう。", "isCorrect": false}, {"text": "「ありがとうございます。今日は暑いですね。この辺りでお昼にいい店ありますか？」", "points": 30, "feedback": "天気と食の話題で自然に雑談できています。相手に質問しているのも良いです。", "isCorrect": true}, {"text": "「私、最近引っ越しまして、大変だったんですよ...」", "points": 5, "feedback": "自分の話ばかりしています。雑談は相手に興味を持つことが大切です。", "isCorrect": false}], "situation": "初めて訪問した店舗。店長と名刺交換した直後です。", "customerLine": "（名刺交換後）どうぞお座りください"}, {"options": [{"text": "「へー、すごいですね。で、何の魚が釣れたんですか？」", "points": 5, "feedback": "雑談を続けています。5分以上は長すぎるので、そろそろ本題に移りましょう。", "isCorrect": false}, {"text": "「話を戻しますが、今日の本題は...」", "points": 15, "feedback": "「話を戻す」は少し唐突です。もう少し自然な移行フレーズを使いましょう。", "isCorrect": false}, {"text": "「釣りいいですね！さて、本日お伺いしたのは...」", "points": 30, "feedback": "相手の話を受け止めてから、自然に本題に移行できています。", "isCorrect": true}], "situation": "雑談が盛り上がり、5分以上経ちました。本題に移りたい場面です。", "customerLine": "そうそう、この前も釣りに行ってね..."}]', '{"question": "明日の商談で、どんな雑談ネタを使いますか？", "placeholder": "例: 訪問先の近くで見つけた美味しそうなお店の話から入る"}', '["「木戸に立てかけし衣食住」から3つ覚える", "訪問前に、その地域の話題を1つ調べておく", "相手に質問することを意識する（自分の話ばかりしない）", "本題への移行フレーズを3つ用意しておく"]', NULL, NULL, '2026-01-21 17:48:37.272616+00', '2026-01-21 17:48:37.272616+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (75, 47, '電話応対の基本', '電話の向こうにも、人がいる', '{"icon": "phone", "name": "電話マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["1コール", "3コール", "5コール", "10コール"], "question": "電話応対で、何コール以内に出るのが基本マナー？", "explanation": "3コール以内に出るのがビジネスマナーです。4コール以上かかった場合は「お待たせしました」を添えます。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 電話で失敗", "content": "【電話が鳴る】\n健太:「もしもし」\n相手:「...〇〇社の△△ですが」\n健太:「あ、はい。どちらさまですか？」\n相手:「...今、言いましたが。△△です」\n健太:「あ、すみません。\n      えーと、どのようなご用件ですか？」\n相手:「（この会社、大丈夫かな...）」\n\n山本先輩:「健太、今の電話、\n         いくつ問題があったかわかるか？」", "duration": 30}, {"title": "シーン2: 電話の基本マナー", "content": "山本先輩:「まず『もしもし』はNGだ」\n\n【電話の第一声】\n❌「もしもし」\n✅「お電話ありがとうございます。\n   ○○社の△△でございます」\n\n【電話応対の基本】\n・3コール以内に出る\n・メモを用意してから出る\n・相手の名前を復唱する\n・ゆっくり、明るい声で話す\n\n山本先輩:「電話は声だけが頼り。\n         対面より1.5倍丁寧に」", "duration": 45}, {"title": "シーン3: 声の印象", "content": "山本先輩:「電話で伝わる印象は何だと思う？」\n\n【電話での印象構成】\n対面：視覚55% / 聴覚38% / 言語7%\n電話：聴覚86% / 言語14%（視覚なし）\n\nつまり電話では「声」がほぼ全て\n\n【良い声の3要素】\n1. 明るいトーン：普段より少し高めに\n2. ゆっくり話す：対面の1.2倍遅く\n3. 笑声（えごえ）：笑顔で話すと声に表れる\n\n山本先輩:「電話でも『笑顔』は伝わる。\n         鏡を見ながら練習してみろ」", "duration": 30}], "part2": [{"title": "シーン4: 電話をかける時", "content": "山本先輩:「電話をかける時の流れも覚えよう」\n\n【電話をかける時の基本フロー】\n①名乗る\n 「○○社の△△と申します」\n②相手を確認\n 「□□様でいらっしゃいますか？」\n③用件を簡潔に\n 「○○の件でお電話しました」\n④都合を確認\n 「今、お時間よろしいでしょうか？」\n\n【NGパターン】\n・いきなり用件を話し始める\n・相手の都合を確認しない\n・長々と話す（電話は3分以内が目安）", "duration": 30}, {"title": "シーン5: 電話を受ける時", "content": "山本先輩:「受ける時の流れも確認しよう」\n\n【電話を受ける時の基本フロー】\n①3コール以内に出る\n （4コール以上→「お待たせしました」）\n②社名・名前を名乗る\n 「お電話ありがとうございます。\n  ○○社の△△でございます」\n③相手の名前を復唱\n 「□□社の△△様ですね」\n④用件を聞く\n 「どのようなご用件でしょうか」\n\n【取り次ぐ時】\n「○○でございますね。少々お待ちください」\n→保留→「○○様からお電話です」", "duration": 30}, {"title": "シーン6: NGパターンを避ける", "content": "山本先輩:「よくあるNGパターンも覚えておけ」\n\n【電話のNG行動】\n❌「もしもし」で始める\n❌ 相手の名前を聞き返しすぎる\n❌「わかりません」で終わる\n   →「確認してご連絡します」\n❌ 保留が長い（30秒以上）\n   →「折り返しお電話します」\n❌ ながら電話（キーボード音など）\n\n山本先輩:「電話の向こうにも人がいる。\n         顔が見えなくても、\n         心は通じるんだ」", "duration": 30}]}', '{"title": "電話応対の基本", "content": "3コール以内 × 明るい声 × ゆっくり話す", "audioText": "電話では視覚情報がないため、声の印象がほぼ全てを決めます。明るく、ゆっくり、笑顔で話すことを心がけましょう。", "highlight": "電話では声が86%の印象を決める"}', '[{"options": ["もしもし", "はい", "お電話ありがとうございます。○○社でございます", "お世話になっております"], "question": "ビジネス電話の第一声として適切なのは？", "explanation": "「もしもし」はビジネスでは不適切です。社名と名前を名乗りましょう。", "correctIndex": 2}, {"options": ["そのまま待ってもらう", "折り返し電話を提案する", "電話を切る", "早口で対応する"], "question": "電話で保留が長くなりそうな時の対応は？", "explanation": "保留が30秒以上になりそうな場合は、折り返し電話することを提案しましょう。", "correctIndex": 1}]', '{"text": "電話の向こうにも、人がいる。顔が見えなくても、心は通じる。", "author": "Symphony営業格言", "textJa": "電話の向こうにも、人がいる。顔が見えなくても、心は通じる。"}', '[{"options": [{"text": "「もしもし」", "points": 0, "feedback": "「もしもし」はビジネスでは不適切です。社名と名前を名乗りましょう。", "isCorrect": false}, {"text": "「はい」", "points": 5, "feedback": "「はい」だけでは不十分です。社名と名前を名乗りましょう。", "isCorrect": false}, {"text": "「お電話ありがとうございます。○○社の△△でございます」", "points": 30, "feedback": "正しい第一声です。社名と名前を明るい声で伝えましょう。", "isCorrect": true}], "situation": "電話が鳴りました。受話器を取ります。", "customerLine": "（プルルルル...）"}, {"options": [{"text": "「はい、どのようなご用件ですか？」（聞き取れないまま進める）", "points": 0, "feedback": "名前を聞き取れないまま進めると、後で困ります。丁寧に確認しましょう。", "isCorrect": false}, {"text": "「え？もう一回言ってもらえますか？」", "points": 5, "feedback": "言い方がカジュアルすぎます。丁寧な言葉で確認しましょう。", "isCorrect": false}, {"text": "「恐れ入ります。お名前をもう一度お伺いしてもよろしいでしょうか？」", "points": 30, "feedback": "丁寧に確認しています。クッション言葉を使うのも良いです。", "isCorrect": true}], "situation": "相手の名前が聞き取れませんでした。", "customerLine": "○×□△の山田ですが..."}]', '{"question": "明日から電話応対で意識することは何ですか？", "placeholder": "例: 電話を取る前にメモを用意し、3コール以内に明るい声で出る"}', '["鏡の前で笑顔を作りながら電話する練習をする", "電話の横にメモ帳とペンを常備する", "3コール以内に出ることを意識する", "ゆっくり話すことを意識する（急いで話さない）"]', NULL, NULL, '2026-01-21 17:48:38.200798+00', '2026-01-21 17:48:38.200798+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (76, 48, 'メール・チャットの書き方', '良いメールは、相手の時間を奪わない', '{"icon": "mail", "name": "ライティングマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["挨拶", "結論", "経緯の説明", "自己紹介"], "question": "ビジネスメールで最初に書くべきことは？", "explanation": "ビジネスメールは結論から書きます。相手が最も知りたいことを最初に伝えましょう。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 長すぎるメール", "content": "【健太が送ったメール】\n件名：先日の件\n\nいつもお世話になっております。\n先日はお忙しい中、お時間をいただき\nありがとうございました。\nさて、先日お話しした件ですが、\n社内で検討した結果、色々な意見が出まして、\n結論から申し上げますと...（長文が続く）\n\n山本先輩:「健太、このメール読むのに\n         何分かかると思う？」\n健太:「え...3分くらい？」\n山本先輩:「相手は忙しいんだぞ」", "duration": 30}, {"title": "シーン2: メールの基本構成", "content": "山本先輩:「メールには型がある」\n\n【ビジネスメールの基本構成】\n①件名：用件がわかる具体的な件名\n②宛名：会社名・部署名・氏名・敬称\n③挨拶：「お世話になっております」\n④本文：結論→詳細→依頼の順序\n⑤結び：「よろしくお願いいたします」\n⑥署名：会社名・部署・氏名・連絡先\n\n山本先輩:「特に大事なのは『件名』と『本文の順序』だ」", "duration": 30}, {"title": "シーン3: 結論から書く", "content": "山本先輩:「本文は結論から書け」\n\n【PREP法でメールを構成】\nP（結論）：「○○についてご連絡します」\nR（理由）：「理由は△△だからです」\nE（具体例）：「例えば□□です」\nP（結論）：「つきましては○○をお願いします」\n\n【悪い例】\n「先日お話しした件ですが、\n 社内で検討した結果、色々な意見が出て、\n 最終的には...」（結論が最後）\n\n【良い例】\n「先日のご提案、導入を決定しました。\n 理由は...」（結論が最初）", "duration": 45}], "part2": [{"title": "シーン4: 読みやすい文章のコツ", "content": "山本先輩:「読みやすさも大事だ」\n\n【読みやすい文章のポイント】\n・1文は50文字以内\n・漢字3割、ひらがな7割\n・箇条書きを活用\n・適度に改行を入れる\n\n【悪い例】\n先日ご依頼いただいた件について社内で\n検討した結果ご希望の納期での対応が\n可能であることが判明いたしました。\n\n【良い例】\n先日ご依頼の件について、\n社内で検討しました。\n\nご希望の納期で対応可能です。", "duration": 30}, {"title": "シーン5: 件名の付け方", "content": "山本先輩:「件名で用件がわかるのが理想だ」\n\n【悪い件名】\n❌「お世話になっております」\n❌「先日の件」\n❌「ご確認ください」\n❌「お願い」\n\n【良い件名】\n✅「【ご確認依頼】○月○日の打合せ日程について」\n✅「【○○社】お見積書送付のご連絡」\n✅「【至急】納期変更のお願い」\n\n山本先輩:「件名を見ただけで、\n         開封の優先度がわかるように」", "duration": 30}, {"title": "シーン6: 返信スピード", "content": "山本先輩:「返信のスピードも信頼に関わる」\n\n【返信スピードの目安】\n・社内メール：24時間以内\n・社外メール：当日中が理想、遅くとも翌営業日\n・緊急案件：「確認中です」と一報\n\n山本先輩:「すぐに回答できなくても、\n         『受領しました』だけでも返せ」\n\n【すぐ返せない時】\n「ご連絡ありがとうございます。\n 確認して○日までに回答いたします」\n\nこれだけで相手は安心する", "duration": 30}]}', '{"title": "メールの基本", "content": "件名で用件を明確に → 本文は結論から → 1文50文字以内", "audioText": "ビジネスメールは結論から書きましょう。件名で用件を明確にし、本文は簡潔に。相手の時間を奪わない配慮が信頼につながります。", "highlight": "良いメールは、相手の時間を奪わない"}', '[{"options": ["20文字以内", "50文字以内", "100文字以内", "制限なし"], "question": "ビジネスメールの1文の適切な長さは？", "explanation": "1文は50文字以内が読みやすいです。長い文は複数に分けましょう。", "correctIndex": 1}, {"options": ["1時間以内", "当日〜翌営業日", "1週間以内", "返信不要"], "question": "社外メールへの返信の目安は？", "explanation": "社外メールは当日中が理想、遅くとも翌営業日に返信しましょう。", "correctIndex": 1}]', '{"text": "良いメールは、相手の時間を奪わない。読む人への思いやりが文章に表れる。", "author": "Symphony営業格言", "textJa": "良いメールは、相手の時間を奪わない。読む人への思いやりが文章に表れる。"}', '[{"options": [{"text": "「お世話になっております」", "points": 0, "feedback": "用件がわかりません。件名で何のメールか伝えましょう。", "isCorrect": false}, {"text": "「見積書」", "points": 10, "feedback": "シンプルすぎます。もう少し具体的にしましょう。", "isCorrect": false}, {"text": "「【○○社】お見積書送付のご連絡」", "points": 30, "feedback": "用件が明確です。相手は件名だけで内容を把握できます。", "isCorrect": true}], "situation": "お客様にお見積書を送る件名を考えています。", "customerLine": "（メールの件名を入力する場面）"}, {"options": [{"text": "回答できるまで返信しない", "points": 0, "feedback": "返信がないと不安になります。まず受領の連絡をしましょう。", "isCorrect": false}, {"text": "「確認して、わかり次第ご連絡します」とすぐ返信", "points": 30, "feedback": "すぐに回答できなくても、受領と回答予定を伝えることで相手は安心します。", "isCorrect": true}, {"text": "「わかりません」と返信する", "points": 5, "feedback": "「わかりません」で終わらせず、確認して回答する姿勢を見せましょう。", "isCorrect": false}], "situation": "お客様から問い合わせメールが来ましたが、すぐに回答できる内容ではありません。", "customerLine": "○○について教えてください。"}]', '{"question": "明日から、メールで意識することは何ですか？", "placeholder": "例: 件名で用件を明確にし、本文は結論から書く"}', '["件名に【】をつけて用件を明確にする", "本文は結論→理由→詳細の順序で書く", "1文50文字以内を意識する", "受信したメールは24時間以内に返信する"]', NULL, NULL, '2026-01-21 17:48:40.042654+00', '2026-01-21 17:48:40.042654+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (77, 49, '非言語コミュニケーション', '言葉は嘘をつけるが、体は嘘をつかない', '{"icon": "eye", "name": "ボディランゲージマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["7%", "38%", "55%", "93%"], "question": "メラビアンの法則で、視覚情報が占める割合は？", "explanation": "メラビアンの法則では、視覚情報（表情・姿勢・視線）が55%を占めます。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 言葉と態度の矛盾", "content": "健太:「ぜひご検討ください！」\n      （腕を組み、目を逸らしながら）\n\n店長:「う〜ん...（この人、自信なさそうだな）」\n\n山本先輩:「健太、今の、何が問題かわかる？」\n健太:「え？ちゃんと言いましたよ？」\n山本先輩:「言葉はね。でも態度は\n         『自信がない』と言っていた」\n\n健太:「態度...？」", "duration": 30}, {"title": "シーン2: メラビアンの法則", "content": "山本先輩:「メラビアンの法則って知ってるか？」\n\n【メラビアンの法則（1967）】\n感情や態度の伝達における影響度\n\n言語情報（言葉の内容）：7%\n聴覚情報（声のトーン・速さ）：38%\n視覚情報（表情・姿勢・視線）：55%\n\n※矛盾したメッセージの場合に限定\n\n山本先輩:「言葉で『大丈夫です』と言っても、\n         表情が不安そうなら\n         『大丈夫じゃない』と伝わる」\n\n健太:「言葉より態度の方が\n      強く伝わるんですね...」", "duration": 45}, {"title": "シーン3: 表情のコントロール", "content": "山本先輩:「まず表情から見直そう」\n\n【表情の基本】\n✅ 笑顔：口角を上げ、目尻を下げる\n   ※「目が笑っていない笑顔」は逆効果\n✅ 真剣な表情：うなずきながら集中\n✅ 共感の表情：相手の感情に合わせる\n\n【NGな表情】\n❌ 無表情\n❌ 退屈そうな顔\n❌ 見下したような表情\n❌ 作り笑い（目が笑っていない）\n\n山本先輩:「鏡を見て練習しろ。\n         自分の表情を知ることが第一歩だ」", "duration": 30}], "part2": [{"title": "シーン4: 姿勢とジェスチャー", "content": "山本先輩:「次は姿勢だ」\n\n【良い姿勢】\n・背筋を伸ばす\n・やや前傾（関心を示す）\n・腕を組まない（オープンな姿勢）\n・相手に体を向ける\n\n【ジェスチャー】\n・手のひらを見せる（誠実さ）\n・適度な手の動き（熱意）\n・相手に合わせる（ミラーリング）\n\n【NGな姿勢】\n❌ 腕を組む（拒絶のサイン）\n❌ 足を組む（くだけすぎ）\n❌ 椅子にもたれる（偉そう）\n❌ そわそわする（落ち着きがない）", "duration": 45}, {"title": "シーン5: アイコンタクト", "content": "山本先輩:「アイコンタクトも大事だ」\n\n【適切なアイコンタクト】\n・会話時間の30〜60%程度\n・話す時より聞く時に多く\n・眉間〜鼻のあたりを見ると自然\n・3〜5秒見たら、一度外す\n\n【NGなアイコンタクト】\n❌ 凝視（威圧感を与える）\n❌ 目を合わせない（自信がない印象）\n❌ キョロキョロする（落ち着きがない）\n\n山本先輩:「日本人は目を合わせすぎると\n         威圧的に感じる人もいる。\n         適度なバランスが大事だ」", "duration": 30}, {"title": "シーン6: 実践と確認", "content": "【翌日の商談】\n\n健太:（背筋を伸ばし、やや前傾）\n   「ぜひご検討ください！」\n   （笑顔でアイコンタクト）\n\n店長:「うん、前向きに考えるよ」\n   （この子、自信があるな）\n\n山本先輩:「どうだった？」\n健太:「意識しただけで、反応が\n      全然違いました！」\n\n山本先輩:「言葉は嘘をつけるが、\n         体は嘘をつかない。\n         非言語を制する者が、\n         コミュニケーションを制するんだ」", "duration": 30}]}', '{"title": "メラビアンの法則", "content": "視覚55% × 聴覚38% × 言語7%", "audioText": "非言語コミュニケーションは、言葉以上に相手に伝わります。表情、姿勢、視線を意識的にコントロールすることで、信頼感を高めることができます。", "highlight": "言葉より態度が強く伝わる"}', '[{"options": ["関心がある", "リラックス", "拒絶・防衛", "熱意"], "question": "腕を組む姿勢が伝えるメッセージは？", "explanation": "腕を組む姿勢は「拒絶」「防衛」のサインと受け取られます。オープンな姿勢を心がけましょう。", "correctIndex": 2}, {"options": ["10%", "30〜60%", "80%", "100%"], "question": "アイコンタクトの適切な割合は？", "explanation": "会話時間の30〜60%程度が適切です。凝視は威圧的、目を合わせないのは自信がない印象を与えます。", "correctIndex": 1}]', '{"text": "The body says what words cannot.", "author": "マーサ・グラハム（Martha Graham）", "textJa": "体は、言葉が言えないことを語る。"}', '[{"options": [{"text": "椅子にもたれかかり、腕を組んで聞く", "points": 0, "feedback": "腕を組み、もたれかかる姿勢は「興味がない」「偉そう」と伝わります。", "isCorrect": false}, {"text": "背筋を伸ばし、やや前傾でうなずきながら聞く", "points": 30, "feedback": "前傾姿勢は関心を示し、うなずきは「聞いている」というサインになります。", "isCorrect": true}, {"text": "メモを取ることに集中して下を向く", "points": 10, "feedback": "メモは大切ですが、アイコンタクトも必要です。時々顔を上げましょう。", "isCorrect": false}], "situation": "商談中、お客様が大事な話をしています。あなたの姿勢は？", "customerLine": "実は、最近売上が落ちてきていて..."}, {"options": [{"text": "目を逸らしながら小声で「ご検討ください...」", "points": 0, "feedback": "目を逸らし小声だと、自信がない印象を与えます。言葉と態度を一致させましょう。", "isCorrect": false}, {"text": "相手の目を見て、笑顔で「ぜひご検討ください！」", "points": 30, "feedback": "アイコンタクトと笑顔で、言葉と態度が一致しています。自信が伝わります。", "isCorrect": true}, {"text": "机を叩きながら「絶対導入すべきです！」", "points": 5, "feedback": "熱意は大切ですが、威圧的になっています。適度な表現を心がけましょう。", "isCorrect": false}], "situation": "提案の最後に「ぜひご検討ください」と伝える場面です。", "customerLine": "（提案を聞き終わった）"}]', '{"question": "明日から、非言語コミュニケーションで意識することは？", "placeholder": "例: 商談中は腕を組まず、やや前傾姿勢を保つ"}', '["鏡の前で表情を確認する習慣をつける", "商談中は腕を組まない、足を組まないことを意識", "相手の話を聞く時は、やや前傾でうなずく", "アイコンタクトを30〜60%を目安に意識する"]', NULL, NULL, '2026-01-21 17:48:40.783723+00', '2026-01-21 17:48:40.783723+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (78, 50, '説明力', '結論から話せる人は、信頼される人', '{"icon": "message-square", "name": "説明マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Plan（計画）", "Point（結論）", "Problem（問題）", "Process（過程）"], "question": "PREP法の「P」は何を表す？", "explanation": "PREP法の「P」はPoint（結論）です。最初と最後に結論を述べます。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 話が長い健太", "content": "上司:「昨日の商談、どうだった？」\n健太:「えーと、昨日○○社に行ったんですけど、\n      最初は受付で待たされて、\n      それで店長が来て、話を聞いてくれたんですが、\n      途中で電話が入って中断して、\n      それで再開したんですけど...」\n上司:「...で、結論は？」\n健太:「あ、契約取れました」\n上司:「それを先に言ってくれ」", "duration": 30}, {"title": "シーン2: PREP法との出会い", "content": "山本先輩:「健太、話が長いって言われない？」\n健太:「よく言われます...」\n山本先輩:「PREP法を使えば解決する」\n\n【PREP法とは】\nP = Point（結論）：最も伝えたいこと\nR = Reason（理由）：なぜそう言えるのか\nE = Example（具体例）：イメージしやすい例\nP = Point（結論）：もう一度結論\n\n山本先輩:「結論を最初と最後に言う。\n         これだけで格段にわかりやすくなる」", "duration": 45}, {"title": "シーン3: PREP法の例", "content": "山本先輩:「さっきの報告をPREP法で言い直してみろ」\n\n【PREP法で言い直し】\nP：「昨日の○○社、契約取れました」\nR：「店長が在庫管理の課題を認識していたからです」\nE：「月末の棚卸しに3日かかっていて、\n   時間削減に興味を持ってくれました」\nP：「なので、契約が決まりました」\n\n上司:「おお、わかりやすい！\n      いくらの契約？」\n\n山本先輩:「ほら、話が進むだろ？」", "duration": 30}], "part2": [{"title": "シーン4: 提案での活用", "content": "山本先輩:「商談でも使えるぞ」\n\n【提案の説明（PREP法）】\nP：「Symphonyの導入をお勧めします」\nR：「御社の在庫管理の課題を解決できるからです」\nE：「同規模の○○モータース様では、\n   導入後に月20時間の業務削減ができました」\nP：「ですので、御社にもSymphonyを\n   お勧めします」\n\n山本先輩:「最初に結論を言うから、\n         相手は『何の話か』を\n         すぐに理解できる」", "duration": 30}, {"title": "シーン5: アンチパターン", "content": "山本先輩:「ダメなパターンも覚えておけ」\n\n【悪い説明（時系列）】\n「昨日、○○社に行ったんですけど、\n 最初は断られて、でも粘って話を聞いたら、\n 実は在庫管理で困っていて、\n それでうちのシステムを紹介したら\n 興味を持ってくれて...」\n\n【良い説明（PREP法）】\n「○○社に提案したいです。\n 在庫管理で困っていることがわかったからです。\n 具体的には月末の棚卸しに3日かかっているそうです。\n ですので、Symphonyを提案させてください」\n\n山本先輩:「時系列で話す癖がある人は要注意だ」", "duration": 30}, {"title": "シーン6: 1分で伝える", "content": "山本先輩:「PREP法を使うコツがある」\n\n【PREP法を使いこなすコツ】\n1. 最初の「P」を一文で言い切る\n2. 「なぜなら」「例えば」「ですので」を使う\n3. 具体例には数字を入れる\n4. 全体で1分以内に収める\n\n健太:「1分ですか？」\n山本先輩:「1分で要点が伝えられない人は、\n         そもそも何を言いたいか整理できていない」\n\n【練習】\n「結論は○○です。なぜなら△△だからです。\n 例えば□□です。ですので○○です」\n\nこれを30秒で言えるようになれ", "duration": 30}]}', '{"title": "PREP法", "content": "Point(結論) → Reason(理由) → Example(具体例) → Point(結論)", "audioText": "PREP法は、結論から話すことで相手の理解を助けるフレームワークです。報告、提案、説明のあらゆる場面で使えます。", "highlight": "1分で要点を伝える"}', '[{"options": ["経緯", "結論", "具体例", "理由"], "question": "PREP法で最初に言うべきことは？", "explanation": "PREP法では、最初に結論（Point）を述べます。相手は「何の話か」をすぐに理解できます。", "correctIndex": 1}, {"options": ["30秒以内", "1分以内", "5分以内", "制限なし"], "question": "PREP法の説明で適切な長さは？", "explanation": "PREP法を使った説明は1分以内が目安です。長いと要点がぼやけます。", "correctIndex": 1}]', '{"text": "話の長い人は、結論がない人。結論から話せる人は、信頼される人。", "author": "Symphony営業格言", "textJa": "話の長い人は、結論がない人。結論から話せる人は、信頼される人。"}', '[{"options": [{"text": "「昨日○○社に行って、最初は受付で...（経緯から話す）」", "points": 5, "feedback": "時系列で話しています。結論から話しましょう。", "isCorrect": false}, {"text": "「アポが取れました。店長が在庫管理に課題を感じていたからです」", "points": 30, "feedback": "PREP法で結論と理由を簡潔に伝えています。", "isCorrect": true}, {"text": "「まあまあでした」", "points": 0, "feedback": "曖昧すぎます。具体的な結論を伝えましょう。", "isCorrect": false}], "situation": "上司に「昨日の商談どうだった？」と聞かれました。", "customerLine": "昨日の商談どうだった？"}, {"options": [{"text": "「弊社のシステムには色々な機能がありまして...（機能説明から入る）」", "points": 5, "feedback": "機能説明から入ると、結論が後回しになります。", "isCorrect": false}, {"text": "「Symphonyの導入をお勧めします。御社の在庫管理を効率化できるからです」", "points": 30, "feedback": "結論と理由を最初に伝えています。PREP法の正しい使い方です。", "isCorrect": true}, {"text": "「とりあえず資料を見てください」", "points": 0, "feedback": "結論を先に伝えてから、資料で補足しましょう。", "isCorrect": false}], "situation": "お客様にシステムを提案する場面です。", "customerLine": "で、何を提案したいの？"}]', '{"question": "明日から、どのような場面でPREP法を使いますか？", "placeholder": "例: 朝礼での報告、上司への相談、お客様への提案説明"}', '["報告は必ず結論から話す", "「なぜなら」「例えば」「ですので」を意識的に使う", "説明は1分以内を目安にする", "具体例には必ず数字を入れる"]', '{"title": "PREP法で説明を作る", "fields": [{"label": "P（結論）：最も伝えたいことを一文で", "placeholder": "例: Symphonyの導入をお勧めします"}, {"label": "R（理由）：なぜそう言えるか", "placeholder": "例: 御社の在庫管理の課題を解決できるからです"}, {"label": "E（具体例）：数字を含む具体例", "placeholder": "例: 同規模の○○社様では、月20時間の業務削減ができました"}, {"label": "P（結論）：もう一度結論", "placeholder": "例: ですので、Symphonyの導入をお勧めします"}], "description": "以下のテーマについて、PREP法で説明を作ってみましょう（1分以内で話せる長さ）。"}', NULL, '2026-01-21 17:48:41.552891+00', '2026-01-21 17:48:41.552891+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (79, 51, '交渉の基本', '交渉は戦いではない。共に解決策を見つける共同作業', '{"icon": "handshake", "name": "交渉マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Win-Lose", "Lose-Win", "Win-Win", "Lose-Lose"], "question": "交渉で目指すべきパターンは？", "explanation": "Win-Winは双方が満足する結果で、長期的な関係構築につながります。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 値引き交渉に負ける", "content": "店長:「もっと安くならない？」\n健太:「えーと、では10%引きで...」\n店長:「もう少し何とかならない？」\n健太:「じゃあ15%引きで...」\n店長:「うーん...20%でどう？」\n健太:「わ、わかりました...」\n\n山本先輩:「健太、それじゃダメだ」\n健太:「でも、契約取れましたよ？」\n山本先輩:「取れたけど、利益がないだろ」", "duration": 30}, {"title": "シーン2: 交渉の4パターン", "content": "山本先輩:「交渉には4つのパターンがある」\n\n【交渉の4パターン】\nWin-Win：自分も相手も満足\n         →長期的な関係が続く\nWin-Lose：自分だけ満足\n         →相手は次から取引しない\nLose-Win：相手だけ満足\n         →自分が疲弊する ← 今の健太\nLose-Lose：両方不満足\n         →関係が終わる\n\n山本先輩:「営業で目指すべきはWin-Win。\n         一度の勝ちより、長期的な関係だ」", "duration": 45}, {"title": "シーン3: ハーバード流交渉術", "content": "山本先輩:「ハーバード流交渉術って知ってるか？」\n\n【ハーバード流交渉術の4原則】\n1. 人と問題を分離する\n   →感情的にならず、課題に集中\n\n2. 立場ではなく利害に焦点を当てる\n   →「値引きしろ」の背後にある本当のニーズ\n\n3. 双方に有利な選択肢を創造する\n   →「これかあれか」ではなく「第三の案」\n\n4. 客観的基準を用いる\n   →市場価格、業界慣行など\n\n出典: Fisher & Ury (1981)\n    \"Getting to Yes\"", "duration": 45}], "part2": [{"title": "シーン4: 利害に焦点を当てる", "content": "山本先輩:「値引き要求の背後を探れ」\n\n店長:「もっと安くして」\n健太:「安くしたい理由を教えていただけますか？」\n店長:「予算が厳しくてね...」\n健太:「予算に収まれば良いということですか？」\n店長:「そうだね」\n\n【気づき】\n・「値引き」は立場（Position）\n・「予算に収めたい」が利害（Interest）\n\n山本先輩:「利害がわかれば、\n         値引き以外の解決策も見つかる」", "duration": 30}, {"title": "シーン5: 第三の案を創造する", "content": "山本先輩:「値引き以外の選択肢を考えてみろ」\n\n【予算に収めるための選択肢】\n・機能を絞ったプランを提案\n・初年度だけ割引、2年目から通常価格\n・支払いを分割にする\n・一部機能を無料オプションに\n・導入時期をずらして来期予算で\n\n健太:「値引きしなくても、\n      予算に収める方法があるんですね」\n\n山本先輩:「そう。『安くしろ』vs『できない』\n         の対立から抜け出せる」", "duration": 30}, {"title": "シーン6: BATNAを持つ", "content": "山本先輩:「あと一つ大事な概念がある。BATNA」\n\n【BATNA】\nBest Alternative To a Negotiated Agreement\n（交渉が決裂した場合の最善の代替案）\n\n例：この交渉がまとまらなくても、\n   来月には別の見込み客がいる\n\n山本先輩:「BATNAがあると、\n         無理な譲歩をしなくて済む」\n\n健太:「『絶対に取らなきゃ』と思うと、\n      何でも受け入れちゃいますもんね」\n\n山本先輩:「交渉は戦いじゃない。\n         共に解決策を見つける共同作業だ」", "duration": 30}]}', '{"title": "Win-Win交渉", "content": "人と問題を分離 × 利害に焦点 × 選択肢を創造 × 客観的基準", "audioText": "Win-Win交渉は、双方が満足する結果を目指します。相手の立場ではなく利害を理解し、第三の案を一緒に創造しましょう。", "highlight": "交渉は共同作業、戦いではない"}', '[{"options": ["嫌がらせ", "予算の制約", "時間稼ぎ", "断る口実"], "question": "「もっと値引きして」の背後にある利害として考えられるのは？", "explanation": "「値引き」は立場であり、背後には「予算に収めたい」という利害がある可能性があります。", "correctIndex": 1}, {"options": ["最高の提案価格", "交渉決裂時の代替案", "妥協点", "最終期限"], "question": "BATNAとは何？", "explanation": "BATNAは「交渉が決裂した場合の最善の代替案」です。これがあると無理な譲歩を避けられます。", "correctIndex": 1}]', '{"text": "Negotiation is not a battle, it''s a journey together to find the best solution.", "author": "ウィリアム・ユーリー（William Ury）", "textJa": "交渉は戦いではない。最善の解決策を見つけるための共同の旅である。"}', '[{"options": [{"text": "「では10%引きで...」（すぐに譲歩）", "points": 5, "feedback": "すぐに値引きすると、さらなる要求を招きます。まず背後の利害を探りましょう。", "isCorrect": false}, {"text": "「これ以上は無理です」（拒否）", "points": 10, "feedback": "拒否だけでは交渉が終わってしまいます。代替案を探りましょう。", "isCorrect": false}, {"text": "「お値引きのご希望、理由を教えていただけますか？」", "points": 30, "feedback": "利害を探る質問です。予算制約なのか、他社比較なのかで対応が変わります。", "isCorrect": true}], "situation": "お客様から「もっと安くして」と言われました。", "customerLine": "もっと安くならないの？"}, {"options": [{"text": "「じゃあ諦めます」（撤退）", "points": 0, "feedback": "まだ解決策があります。第三の案を考えましょう。", "isCorrect": false}, {"text": "「機能を絞ったライトプランか、来期予算での導入はいかがですか？」", "points": 30, "feedback": "値引き以外の選択肢を提示しています。Win-Winの解決策を探る姿勢です。", "isCorrect": true}, {"text": "「では特別に半額で...」", "points": 5, "feedback": "大幅値引きは自社の利益を損ないます。まず代替案を検討しましょう。", "isCorrect": false}], "situation": "予算が厳しいとわかりました。値引き以外の解決策を提案したい場面です。", "customerLine": "今期の予算がどうしても足りなくて..."}]', '{"question": "次の交渉で、どのようにWin-Winを目指しますか？", "placeholder": "例: 値引き要求があったら、まず背後の利害を質問で探る"}', '["値引き要求には、まず理由を聞く", "「立場」ではなく「利害」に焦点を当てる", "値引き以外の選択肢を3つ用意しておく", "交渉前にBATNAを明確にしておく"]', NULL, NULL, '2026-01-21 17:48:42.776829+00', '2026-01-21 17:48:42.776829+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (80, 52, 'クレーム対応の基本', 'クレームは、改善のチャンス', '{"icon": "shield", "name": "クレーム対応マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["4%", "25%", "50%", "75%"], "question": "不満を持った顧客のうち、クレームを言う人の割合は？", "explanation": "グッドマンの法則によると、不満を持った顧客でクレームを言うのは4%だけ。残り96%は黙って離れます。", "correctIndex": 0}', '{"part1": [{"title": "シーン1: クレームを受ける", "content": "【電話が鳴る】\n健太:「お電話ありがとうございます」\n顧客:「ちょっと！この前買った商品、\n      全然動かないんだけど！」\n健太:「え、あ、すみません、\n      でも、それは使い方が...」\n顧客:「は？私の使い方が悪いって言うの！？」\n健太:「いえ、そういう意味では...」\n顧客:「もういい！上の人に代わって！」\n\n山本先輩:「...やってしまったな」", "duration": 30}, {"title": "シーン2: クレームの捉え方", "content": "山本先輩:「健太、クレームをどう思う？」\n健太:「怖いです...避けたいです」\n山本先輩:「実は、クレームはチャンスなんだ」\n\n【グッドマンの法則】\n不満を持った顧客のうち、\nクレームを言うのは4%だけ\n残り96%は黙って離れていく\n\n山本先輩:「つまりクレームを言ってくれる人は\n         『まだ関係を続けたい』と思ってる\n         貴重な存在なんだ」\n\n【クレーム対応の効果】\n適切に対応された顧客の再購入率は、\n不満のない顧客より高い", "duration": 45}, {"title": "シーン3: 最初の対応が全て", "content": "山本先輩:「さっきの何がダメだったかわかるか？」\n\n【健太のNG対応】\n❌ 言い訳から入った\n  「使い方が...」\n❌ 相手の話を遮った\n❌ 共感を示さなかった\n\n【正しい最初の対応】\n✅ まず謝る（感情に対して）\n  「ご不快な思いをさせて申し訳ございません」\n✅ 最後まで話を聞く\n✅ 共感を示す\n  「それは大変でしたね」\n\n山本先輩:「最初の30秒で、\n         事態が良くなるか悪くなるかが決まる」", "duration": 30}], "part2": [{"title": "シーン4: クレーム対応の5ステップ", "content": "山本先輩:「クレーム対応には型がある」\n\n【クレーム対応の5ステップ】\n\n①傾聴\n まず最後まで話を聞く。途中で反論しない\n 「おっしゃる通りです」「それは大変でしたね」\n\n②謝罪\n 事実確認前でも、感情に対して謝る\n 「ご不快な思いをさせて申し訳ございません」\n\n③事実確認\n 「詳しく状況を教えていただけますか？」\n 5W1Hで正確に把握\n\n④解決策提示\n 「○○させていただきます」と具体的に\n\n⑤感謝\n 「ご指摘いただきありがとうございました」", "duration": 45}, {"title": "シーン5: 二次クレームを防ぐ", "content": "山本先輩:「二次クレームって知ってるか？」\n\n【二次クレーム】\n最初のクレーム対応がまずくて、\nさらに怒りを買うこと\n\n【二次クレームを防ぐポイント】\n❌ たらい回しにしない\n  「担当者に確認します」で放置しない\n❌ 言い訳から入らない\n  「でも」「ただ」で始めない\n❌ 約束を破らない\n  「○時までに連絡します」と言ったら必ず守る\n❌ 上から目線にならない\n  「規定ですので」はNG\n\n山本先輩:「最初のクレームより\n         二次クレームの方が怖いぞ」", "duration": 30}, {"title": "シーン6: 実践してみる", "content": "【後日、同じような電話】\n\n顧客:「商品が動かないんですけど！」\n健太:「ご不快な思いをさせて\n      大変申し訳ございません」\n顧客:「...（少し落ち着く）」\n健太:「詳しい状況を教えていただけますか？」\n顧客:「買って3日で動かなくなったんです」\n健太:「3日で...それは驚かれましたよね。\n      すぐに交換品をお送りします。\n      本日中に手配いたします」\n顧客:「...わかった。ありがとう」\n\n山本先輩:「クレームは、改善のチャンス。\n         適切に対応すれば、\n         ファンになってくれるぞ」", "duration": 30}]}', '{"title": "クレーム対応5ステップ", "content": "傾聴 → 謝罪 → 事実確認 → 解決策 → 感謝", "audioText": "クレームは改善のチャンスです。まず傾聴と謝罪で感情を受け止め、事実確認後に解決策を提示し、最後に感謝を伝えましょう。", "highlight": "最初の30秒が全てを決める"}', '[{"options": ["言い訳する", "事実確認する", "傾聴・謝罪する", "上司に代わる"], "question": "クレーム対応で最初にすべきことは？", "explanation": "まず傾聴して謝罪することで、相手の感情を受け止めます。事実確認はその後です。", "correctIndex": 2}, {"options": ["傾聴", "謝罪", "たらい回し", "感謝"], "question": "二次クレームを防ぐために避けるべきことは？", "explanation": "たらい回し、言い訳、約束不履行は二次クレームの原因になります。", "correctIndex": 2}]', '{"text": "A customer who complains is my best friend.", "author": "スタンリー・マーカス（ニーマン・マーカス創業者）", "textJa": "クレームを言ってくれる顧客は、最高の友人である。"}', '[{"options": [{"text": "「それは配送中の事故かもしれませんね」", "points": 0, "feedback": "言い訳から入っています。まず謝罪と共感を示しましょう。", "isCorrect": false}, {"text": "「ご不快な思いをさせて大変申し訳ございません。詳しく状況を教えていただけますか？」", "points": 30, "feedback": "謝罪と傾聴の姿勢を示しています。正しい第一声です。", "isCorrect": true}, {"text": "「担当者に代わりますので少々お待ちください」", "points": 5, "feedback": "たらい回しは二次クレームの原因になります。まず自分で対応しましょう。", "isCorrect": false}], "situation": "お客様から「商品が壊れていた」とお電話がありました。", "customerLine": "買った商品が壊れてたんだけど！どういうこと！？"}, {"options": [{"text": "「規定では交換できないのですが...」", "points": 0, "feedback": "「規定」を盾にした上から目線の対応は、相手の怒りを増幅させます。", "isCorrect": false}, {"text": "「検討して後日連絡します」", "points": 10, "feedback": "曖昧な回答は不安を与えます。具体的な期限と対応を伝えましょう。", "isCorrect": false}, {"text": "「本日中に交換品を手配いたします。ご不便をおかけして申し訳ございませんでした」", "points": 30, "feedback": "具体的な解決策と謝罪を伝えています。お客様は安心できます。", "isCorrect": true}], "situation": "状況を確認しました。解決策を提示する場面です。", "customerLine": "（状況を説明し終わった）"}]', '{"question": "クレームを受けた時、最初に意識することは何ですか？", "placeholder": "例: まず謝罪と傾聴。言い訳や反論をしない"}', '["クレームを受けたら、まず「ご不快な思いをさせて申し訳ございません」と言う", "相手の話を最後まで聞く。途中で遮らない", "「でも」「ただ」で始める言い訳をしない", "約束した期限は必ず守る"]', '{"title": "クレーム対応フレーズ練習", "fields": [{"label": "最初の謝罪（感情に対して）", "placeholder": "例: ご不快な思いをさせて大変申し訳ございません"}, {"label": "共感を示すフレーズ", "placeholder": "例: それは驚かれましたよね。ご不便をおかけして申し訳ありません"}, {"label": "解決策を提示するフレーズ", "placeholder": "例: すぐに交換品をお送りします。本日中に手配いたします"}, {"label": "最後の感謝", "placeholder": "例: ご指摘いただきありがとうございました。今後の改善に活かします"}], "description": "以下の場面で使えるフレーズを考えてみましょう。"}', NULL, '2026-01-21 17:48:43.71776+00', '2026-01-21 17:48:43.71776+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (81, 53, '営業プロセスの全体設計', 'プロセスを管理する者が、結果をコントロールする', '{"icon": "map", "name": "プロセス設計者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["提案→ヒアリング→クロージング→リスト", "リスト→アプローチ→ヒアリング→提案→クロージング", "クロージング→提案→アプローチ→リスト", "ヒアリング→リスト→提案→アプローチ"], "question": "営業プロセスの標準的な順序として正しいものは？", "explanation": "営業プロセスは、リスト作成→アプローチ→ヒアリング→提案→クロージング→フォローアップの順序です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 闇雲に動く健太", "content": "健太:「今日は10件飛び込みしました！\n      でも全部断られました...」\n\n山本先輩:「健太、何件のリストから\n         10件を選んだ？」\n健太:「リスト？特に選んでないです。\n      目についた店に飛び込みました」\n\n山本先輩:「それが問題だ。\n         営業には『プロセス』がある。\n         闇雲に動いても成果は出ない」", "duration": 30}, {"title": "シーン2: 営業プロセスとは", "content": "山本先輩:「営業プロセスって知ってるか？」\n\n【営業プロセスの6ステップ】\n①リスト作成（ターゲット選定）\n②アプローチ（テレアポ・飛び込み）\n③ヒアリング（ニーズ把握）\n④提案（プレゼンテーション）\n⑤クロージング（契約締結）\n⑥フォローアップ（継続関係）\n\n山本先輩:「この流れを理解することで、\n         『今、何をすべきか』が\n         明確になるんだ」", "duration": 45}, {"title": "シーン3: ファネルの考え方", "content": "山本先輩:「営業は『ファネル（漏斗）』の形だ」\n\n【ファネルのイメージ】\nリスト100件\n  ↓\nアポ獲得20件\n  ↓\n商談10件\n  ↓\n提案5件\n  ↓\n成約2件\n\n山本先輩:「各ステップで絞り込まれる。\n         だから上流の『量と質』が\n         最終成果を左右するんだ」\n\n健太:「リスト作りが大事ってことですか」\n山本先輩:「そう。良いリストなしに\n         良い成果は出ない」", "duration": 30}], "part2": [{"title": "シーン4: 結果管理とプロセス管理", "content": "山本先輩:「売上だけを見ていないか？」\n健太:「毎月の売上は気にしています」\n\n山本先輩:「それは『結果管理』だ。\n         大事なのは『プロセス管理』」\n\n【結果管理】\n「今月の売上は100万円だった」\n→ 何が良くて100万円かわからない\n\n【プロセス管理】\n「アポ20件、商談10件、提案5件から\n 売上100万円だった」\n→ どこが上手くいっているかわかる\n→ 何を改善すべきかわかる", "duration": 30}, {"title": "シーン5: 転換率を測る", "content": "山本先輩:「各ステップの転換率を測れ」\n\n【転換率の例】\nリスト→アポ：20%\nアポ→商談：50%\n商談→提案：50%\n提案→成約：40%\n\n山本先輩:「どこの転換率が低い？」\n健太:「えーと、リスト→アポが20%ですね」\n\n山本先輩:「そこがボトルネックだ。\n         テレアポのスキルを上げるか、\n         リストの質を上げるか。\n         改善点が明確になるだろ？」", "duration": 30}, {"title": "シーン6: プロセスを意識する", "content": "健太:「なるほど...今まで感覚でやってました」\n\n山本先輩:「プロセスを管理すると、\n         再現性が生まれる」\n\n【プロセス管理のメリット】\n・今、何をすべきか明確になる\n・何が上手くいっているか分かる\n・何を改善すべきか分かる\n・将来の売上を予測できる\n・同じやり方で結果を再現できる\n\n山本先輩:「プロセスを管理する者が、\n         結果をコントロールする。\n         まずはファネルを意識しろ」", "duration": 30}]}', '{"title": "営業プロセスの6ステップ", "content": "リスト → アプローチ → ヒアリング → 提案 → クロージング → フォロー", "audioText": "営業プロセスは6つのステップで構成されています。各ステップの転換率を測定し、ボトルネックを特定して改善することで、成果を向上させることができます。", "highlight": "プロセスを管理すれば、結果をコントロールできる"}', '[{"options": ["クロージング", "提案", "リスト作成", "フォローアップ"], "question": "営業ファネルで上流に位置するのは？", "explanation": "リスト作成はファネルの上流です。上流の量と質が最終成果を左右します。", "correctIndex": 2}, {"options": ["改善点が明確になる", "結果を予測できる", "感覚で営業できる", "再現性が生まれる"], "question": "プロセス管理のメリットではないものは？", "explanation": "プロセス管理は感覚ではなく、データに基づいた営業活動を可能にします。", "correctIndex": 2}]', '{"text": "What gets measured gets managed.", "author": "ピーター・ドラッカー", "textJa": "測定されるものは管理される。"}', '[{"options": [{"text": "「なんとか頑張ります」", "points": 0, "feedback": "感覚的な回答です。具体的な数字で答えられるようにしましょう。", "isCorrect": false}, {"text": "「提案中の案件が5件あり、確度を加味すると約80万円の見込みです」", "points": 30, "feedback": "プロセスに基づいた回答です。案件状況から売上を予測しています。", "isCorrect": true}, {"text": "「先月と同じくらいだと思います」", "points": 5, "feedback": "根拠のない予測です。現在の案件状況から見込みを算出しましょう。", "isCorrect": false}], "situation": "上司から「今月の売上見込みは？」と聞かれました。", "customerLine": "今月の売上見込みを教えてくれ"}]', '{"question": "自分の営業活動で、どのプロセスがボトルネックになっていますか？", "placeholder": "例: アポ獲得の段階。テレアポの成功率が低いので、スクリプトを改善したい"}', '["営業プロセスの各ステップの件数を毎日記録する", "各ステップの転換率を計算し、ボトルネックを特定する", "ファネルの上流（リスト作成）の質を見直す", "週次で上司とプロセスレビューを行う"]', NULL, NULL, '2026-01-21 17:48:44.953193+00', '2026-01-21 17:48:44.953193+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (82, 54, 'ターゲットリストの作り方', '良いリストは、営業の半分を成功させる', '{"icon": "list", "name": "リストマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Important Customer Plan", "Ideal Customer Profile", "Internal Company Process", "Initial Contact Point"], "question": "ICPとは何の略称？", "explanation": "ICPはIdeal Customer Profile（理想顧客像）の略です。最も価値を得られる顧客の特徴を定義します。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 誰にでも売ろうとする健太", "content": "健太:「どの会社に営業すればいいですか？」\n山本先輩:「誰に売りたいと思ってる？」\n健太:「えーと、誰でも...\n      買ってくれる人なら誰でも」\n\n山本先輩:「それがダメなんだ。\n         『全員に売ろう』とすると、\n         誰にも売れない」\n\n健太:「でも、お客さんは多い方が...」\n山本先輩:「時間は有限だ。\n         確率の高い相手に集中しろ」", "duration": 30}, {"title": "シーン2: 80:20の法則", "content": "山本先輩:「パレートの法則を知ってるか？」\n\n【80:20の法則（パレートの法則）】\n売上の80%は、20%の顧客から生まれる\n\n山本先輩:「つまり、全員を狙うより\n         成約確率の高い20%を\n         最初から狙えば効率的だ」\n\n健太:「どうやってその20%を見つけるんですか？」\n山本先輩:「それが『ICP』だ」", "duration": 30}, {"title": "シーン3: ICP（理想顧客像）", "content": "山本先輩:「ICPを設定しよう」\n\n【ICP = Ideal Customer Profile】\n自社製品から最も価値を得られる顧客の特徴\n\n【SymphonyのICP例】\n・業種：自動車整備業\n・規模：従業員10〜50名\n・地域：関東圏\n・課題：在庫管理に困っている\n・IT意識：ホームページがある\n\n山本先輩:「このプロフィールに合う会社を\n         優先的に攻める。\n         的外れな会社に時間を使わない」", "duration": 45}], "part2": [{"title": "シーン4: リストの情報源", "content": "健太:「そういう会社のリストはどこで手に入りますか？」\n\n【リストの情報源】\n・業界団体・協会名簿\n・企業データベース（帝国データバンク等）\n・展示会・セミナー参加者\n・既存顧客からの紹介\n・Webからの問い合わせ\n・地域の商工会・商工会議所\n\n山本先輩:「特に『既存顧客からの紹介』は\n         最も質が高い。\n         成約した顧客には必ず\n         紹介を依頼しろ」", "duration": 30}, {"title": "シーン5: ABC分析で優先順位", "content": "山本先輩:「リストは優先順位をつける」\n\n【ABC分析】\nAランク：ICPに完全一致\n       → すぐにアプローチ\nBランク：ICPに部分一致\n       → Aの次にアプローチ\nCランク：可能性はあるが優先度低い\n       → 時間があればアプローチ\n\n健太:「全部Aランクにしたくなりますが...」\n山本先輩:「それだと優先順位の意味がない。\n         厳選しろ」", "duration": 30}, {"title": "シーン6: リストの質を上げる", "content": "山本先輩:「最後に、既存顧客を分析しろ」\n\n【既存顧客分析】\n成約した顧客の共通点は何か？\n・業種\n・規模\n・課題\n・決裁者の特徴\n・成約までの期間\n\n山本先輩:「共通点を見つけて、\n         ICPをより精緻化する。\n         これを繰り返すと、\n         リストの質がどんどん上がる」\n\n健太:「良いリストは、\n      営業の半分を成功させるんですね」", "duration": 30}]}', '{"title": "ICPとABC分析", "content": "ICP（理想顧客像）を設定 → ABC分析で優先順位 → Aランクから攻める", "audioText": "ターゲットリストは、ICPを設定してABC分析で優先順位をつけます。限られた時間を確率の高い顧客に集中させましょう。", "highlight": "80%の売上は20%の顧客から生まれる"}', '[{"options": ["電話帳", "既存顧客からの紹介", "飛び込みで見つけた会社", "ランダムなリスト"], "question": "リストの情報源で最も質が高いのは？", "explanation": "既存顧客からの紹介は、すでに信頼関係のベースがあるため、最も質が高いです。", "correctIndex": 1}]', '{"text": "良いリストは、営業の半分を成功させる。", "author": "Symphony営業格言", "textJa": "良いリストは、営業の半分を成功させる。"}', '[{"options": [{"text": "A社：自動車整備業、従業員30名、在庫管理に課題あり", "points": 30, "feedback": "ICPに完全一致するAランクです。最優先でアプローチすべきです。", "isCorrect": true}, {"text": "B社：飲食業、従業員100名、特に課題は聞いていない", "points": 5, "feedback": "業種がICPと異なり、課題も不明確。優先度は低いです。", "isCorrect": false}, {"text": "C社：自動車整備業、従業員5名、個人経営", "points": 10, "feedback": "業種は合っていますが、規模がICPより小さい。Bランクです。", "isCorrect": false}], "situation": "リストを作成しています。どの会社を優先すべきですか？", "customerLine": "（リストには3社の情報があります）"}]', '{"question": "あなたの担当エリアで、ICPに合致する会社の特徴は何ですか？", "placeholder": "例: 創業10年以上の自動車整備業で、従業員20〜50名、ホームページがある会社"}', '["自分の担当エリアのICPを明文化する", "既存顧客の共通点を分析し、ICPを精緻化する", "リストをABC分析で優先順位付けする", "成約した顧客に紹介を依頼する習慣をつける"]', NULL, NULL, '2026-01-21 17:48:45.854715+00', '2026-01-21 17:48:45.854715+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (83, 55, 'テレアポの極意', 'テレアポは、断られることを楽しむゲーム', '{"icon": "phone-call", "name": "テレアポマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["電話で契約を取ること", "電話で商品を説明すること", "アポイントを取ること", "電話で値引き交渉すること"], "question": "テレアポの目的として正しいのは？", "explanation": "テレアポの目的は「アポイントを取ること」です。電話で売り込まず、次の商談につなげます。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 電話が苦手な健太", "content": "健太:「テレアポ、苦手なんです...」\n山本先輩:「どこが苦手？」\n健太:「断られるのが辛くて。\n      100件かけても5件しか取れない...」\n\n山本先輩:「5件取れてるなら上出来だ」\n健太:「え？95件断られてますよ？」\n\n山本先輩:「テレアポの成功率は5〜10%。\n         90%以上は断られて当たり前。\n         断られることを楽しめ」", "duration": 30}, {"title": "シーン2: テレアポの目的", "content": "山本先輩:「まず目的を確認しよう」\n\n【テレアポの目的】\n✅ アポイントを取ること\n❌ 電話で商品を説明すること\n❌ 電話で契約を取ること\n\n山本先輩:「電話は『次の商談の約束を取る』\n         だけでいい。\n         説明も売り込みも、\n         会ってからだ」\n\n【ゴールの明確化】\n「○月○日○時に、30分お時間をいただく約束」\nこれ以上でも以下でもない", "duration": 30}, {"title": "シーン3: 基本スクリプト", "content": "山本先輩:「基本のスクリプトを覚えろ」\n\n【テレアポ基本スクリプト】\n\n①名乗り\n「お忙しいところ恐れ入ります。\n ○○社の△△と申します」\n\n②用件の明示\n「御社の在庫管理について\n お役に立てる情報をお伝えしたく\n お電話いたしました」\n\n③興味喚起\n「同業の○○様で、月20時間の\n 作業削減ができた事例がございます」\n\n④アポ打診\n「30分ほどお時間いただけませんか」\n\n⑤日程調整\n「来週の火曜か水曜、いかがですか」", "duration": 45}], "part2": [{"title": "シーン4: 断られた時の切り返し", "content": "健太:「断られた時はどうすれば...」\n\n【「忙しい」と言われたら】\n「お忙しいところ申し訳ございません。\n いつ頃でしたらお時間いただけますか」\n\n【「興味がない」と言われたら】\n「突然のお電話で失礼いたしました。\n 在庫管理でお困りのことはございませんか？」\n\n【「資料を送って」と言われたら】\n「承知いたしました。\n せっかくですので、15分だけ\n 直接ご説明させていただけませんか」\n\n山本先輩:「簡単に引き下がるな。\n         もう一押しだ」", "duration": 30}, {"title": "シーン5: 声のコツ", "content": "山本先輩:「電話は声が全てだ」\n\n【声のポイント】\n・明るいトーン（普段より少し高めに）\n・ゆっくり話す（対面の1.2倍遅く）\n・笑顔で話す（声に表れる）\n・立って電話する（声に張りが出る）\n\n【NGな声】\n・ボソボソ（自信がない）\n・早口（焦っている）\n・暗いトーン（やる気がない）\n\n山本先輩:「鏡を見ながら練習しろ。\n         笑顔は電話でも伝わる」", "duration": 30}, {"title": "シーン6: テレアポの心構え", "content": "山本先輩:「最後に心構えだ」\n\n【テレアポの心構え】\n・断られて当たり前（成功率5〜10%）\n・数をこなす（上手くなるには量が必要）\n・午前中が狙い目（決裁者がいる時間）\n・リストの質が結果を左右する\n・1件断られたら「次！」と切り替える\n\n健太:「断られても落ち込まないことですね」\n\n山本先輩:「テレアポは、\n         断られることを楽しむゲームだ。\n         『次は取れる』と思え」", "duration": 30}]}', '{"title": "テレアポ基本スクリプト", "content": "名乗り → 用件 → 興味喚起 → アポ打診 → 日程調整", "audioText": "テレアポの成功率は5〜10%です。断られて当たり前と割り切り、数をこなすことで上達します。明るい声で、アポを取ることだけに集中しましょう。", "highlight": "目的は「アポを取ること」。電話で売り込まない"}', '[{"options": ["すぐに資料を送って終わり", "「15分だけ直接説明させてください」と食い下がる", "「また連絡します」と電話を切る", "「興味がないんですね」と確認する"], "question": "「資料を送って」と言われた時の対応は？", "explanation": "資料だけでは読んでもらえないことが多いです。もう一押しして直接説明の機会を得ましょう。", "correctIndex": 1}]', '{"text": "テレアポは、断られることを楽しむゲームだ。", "author": "Symphony営業格言", "textJa": "テレアポは、断られることを楽しむゲームだ。"}', '[{"options": [{"text": "「わかりました。失礼します」（すぐに引き下がる）", "points": 0, "feedback": "簡単に引き下がりすぎです。もう一押ししましょう。", "isCorrect": false}, {"text": "「お忙しいところ申し訳ございません。いつ頃でしたらお時間いただけますか」", "points": 30, "feedback": "具体的な時期を聞いています。次のアプローチにつなげられます。", "isCorrect": true}, {"text": "「でも、本当に良い商品なんです！」（押し続ける）", "points": 5, "feedback": "電話で売り込むのはNGです。アポを取ることに集中しましょう。", "isCorrect": false}], "situation": "テレアポで「忙しいから」と言われました。", "customerLine": "忙しいから、また今度にして"}, {"options": [{"text": "「わかりました」（電話を切る）", "points": 5, "feedback": "もう一押し質問してみましょう。課題を引き出せる可能性があります。", "isCorrect": false}, {"text": "「突然のお電話で失礼いたしました。ちなみに、在庫管理で特にお困りのことはございませんか？」", "points": 30, "feedback": "課題を引き出す質問です。興味がないと言われても、課題があれば話が変わる可能性があります。", "isCorrect": true}, {"text": "「なぜ興味がないんですか？」（詰問する）", "points": 0, "feedback": "詰問は相手を不快にさせます。柔らかく質問しましょう。", "isCorrect": false}], "situation": "テレアポで「興味がない」と言われました。", "customerLine": "うちはそういうの興味ないんで"}]', '{"question": "明日のテレアポで、特に意識することは何ですか？", "placeholder": "例: 断られても「次！」と切り替えて、午前中に20件かける"}', '["基本スクリプトを声に出して練習する", "断られた時の切り返しフレーズを3つ準備する", "午前中の時間をテレアポに集中投下する", "立って電話し、鏡で自分の表情を確認する"]', '{"title": "テレアポスクリプトを作る", "fields": [{"label": "①名乗り（会社名・名前）", "placeholder": "例: お忙しいところ恐れ入ります。Symphony社の○○と申します"}, {"label": "②用件の明示（なぜ電話したか）", "placeholder": "例: 御社の在庫管理についてお役に立てる情報をお伝えしたくお電話いたしました"}, {"label": "③興味喚起（事例など）", "placeholder": "例: 同業の○○様で、月20時間の作業削減ができた事例がございます"}, {"label": "④アポ打診", "placeholder": "例: 詳しくご説明する機会をいただけないでしょうか。30分程度で結構です"}], "description": "自分用のテレアポスクリプトを作成してみましょう。"}', NULL, '2026-01-21 17:48:46.628818+00', '2026-01-21 17:48:46.628818+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (84, 56, '飛び込み営業の技術', '断られても、置き土産を残せ', '{"icon": "door-open", "name": "飛び込みマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["初回訪問で契約を取る", "名刺交換と次回訪問の約束", "商品を詳しく説明する", "見積書を出す"], "question": "飛び込み営業の現実的なゴールは？", "explanation": "飛び込み営業の現実的なゴールは「名刺交換と次回訪問の約束」です。初回で契約を狙いません。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 飛び込みが怖い", "content": "健太:「飛び込み営業って、効率悪くないですか？」\n山本先輩:「なぜそう思う？」\n健太:「だって、9割以上断られますよね」\n\n山本先輩:「その通り。断られて当然だ。\n         でも、正しいやり方を知れば\n         強力な武器になる」\n\n健太:「正しいやり方？」\n山本先輩:「まず、初回訪問で\n         契約を取ろうとするな」", "duration": 30}, {"title": "シーン2: 飛び込みの目的", "content": "山本先輩:「飛び込みの目的は何だと思う？」\n\n【飛び込み営業の目的】\n✅ 名刺交換し、次の訪問約束を取る\n✅ キーパーソン（決裁者）を特定する\n✅ 簡単なニーズをヒアリングする\n\n❌ 初回で契約を取る\n❌ 長時間の商談をする\n❌ 商品を詳しく説明する\n\n山本先輩:「初回は『顔見せ』でいい。\n         何か一つでも『置き土産』を残せ」", "duration": 30}, {"title": "シーン3: 基本フロー", "content": "山本先輩:「飛び込みの基本フローを覚えろ」\n\n【飛び込み営業の基本フロー】\n\n①入口で名乗る\n「お忙しいところ恐れ入ります。\n ○○社の△△と申します」\n\n②用件を伝える\n「御社のお役に立てる情報がありまして、\n ご挨拶に伺いました」\n\n③キーパーソンを聞く\n「こういったお話は、\n どなた様にさせていただければ？」\n\n④短く自己紹介\n「自動車整備業向けのシステムを\n 提供しております」\n\n⑤次回アポを取る\n「改めてお話しする機会をいただけませんか」", "duration": 45}], "part2": [{"title": "シーン4: 断られた時の対処", "content": "健太:「断られたらどうすれば...」\n\n【「社長は不在です」と言われたら】\n「承知いたしました。\n 名刺をお渡しいただけますでしょうか。\n また改めてお伺いします」\n\n【「うちは間に合っています」と言われたら】\n「承知いたしました。\n ご参考までに資料だけ\n お渡ししてもよろしいでしょうか」\n\n【「忙しい」と言われたら】\n「1分だけお時間いただけませんか。\n ダメでしたら名刺だけでも...」\n\n山本先輩:「必ず何かを残せ。\n         名刺、資料、次回訪問の約束。\n         手ぶらで帰るな」", "duration": 30}, {"title": "シーン5: 第一印象が勝負", "content": "山本先輩:「飛び込みは第一印象が全てだ」\n\n【第一印象のポイント】\n・笑顔（緊張していても笑顔）\n・清潔感（髪、服装、靴）\n・ハキハキした声（ボソボソはNG）\n・背筋を伸ばす（自信があるように）\n・アイコンタクト（目を見て話す）\n\n【滞在時間】\n初回は5分以内が目安。\n長居しない。\n\n山本先輩:「『また来てください』と\n         言わせれば勝ちだ」", "duration": 30}, {"title": "シーン6: 効率的な回り方", "content": "山本先輩:「最後に、効率的な回り方だ」\n\n【飛び込みの効率化】\n・1件行ったら、近くの3〜5件も回る\n・時間帯を選ぶ（10〜11時半、14〜16時）\n・訪問結果を必ずメモする\n・断られた理由を記録する\n・次回訪問のタイミングを決める\n\n健太:「100回断られて1回成功する\n      ゲームですね」\n\n山本先輩:「その通り。断られることを\n         恐れるな。行動した者だけが\n         チャンスを掴む」", "duration": 30}]}', '{"title": "飛び込み営業の心得", "content": "名乗り → 用件 → キーパーソン確認 → 自己紹介 → 次回アポ", "audioText": "飛び込み営業は100回断られて1回成功するゲームです。初回で契約を狙わず、名刺交換と次回訪問の約束を目指しましょう。", "highlight": "断られても「置き土産」を残す"}', '[{"options": ["契約書", "見積書", "名刺か資料", "長時間の説明"], "question": "飛び込み営業で断られた時、最低限残すべきものは？", "explanation": "断られても名刺や資料だけでも渡す「置き土産」を残しましょう。次の機会につながります。", "correctIndex": 2}]', '{"text": "飛び込み営業は、100回断られて1回成功するゲームだ。断られることを恐れるな。", "author": "Symphony営業格言", "textJa": "飛び込み営業は、100回断られて1回成功するゲームだ。断られることを恐れるな。"}', '[{"options": [{"text": "「わかりました。また来ます」（何も残さず帰る）", "points": 0, "feedback": "手ぶらで帰ってはいけません。何か「置き土産」を残しましょう。", "isCorrect": false}, {"text": "「30年のご経験は素晴らしいですね。そのやり方を『もっと楽にする』お手伝いができればと思います」", "points": 30, "feedback": "敬意を示しつつ、強化として提案する良い対応です。", "isCorrect": true}, {"text": "「じゃあ、あなたが決めてください」", "points": 0, "feedback": "失礼な対応です。相手の立場を尊重しましょう。", "isCorrect": false}], "situation": "飛び込み訪問で「社長は不在」と言われました。", "customerLine": "社長は今日いないんですよ"}]', '{"question": "飛び込み営業で、自分が改善すべき点は何ですか？", "placeholder": "例: 断られるとすぐに引き下がってしまう。もう一押しして「置き土産」を残す"}', '["飛び込み前に鏡で笑顔と姿勢を確認する", "断られた時の切り返しフレーズを準備する", "1件訪問したら、近くの3件も必ず回る", "訪問結果をノートに記録し、次回に活かす"]', NULL, NULL, '2026-01-21 17:48:47.436244+00', '2026-01-21 17:48:47.436244+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (85, 57, 'ヒアリング設計', 'ヒアリングなき提案は、診察なき処方', '{"icon": "clipboard-list", "name": "ヒアリングマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Action（行動）", "Authority（決裁権）", "Amount（金額）", "Approach（アプローチ）"], "question": "BANTの「A」は何を意味する？", "explanation": "BANTの「A」はAuthority（決裁権）です。誰が最終決定するかを把握することが重要です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 的外れな提案", "content": "健太:「すごく良い提案をしたのに、\n      『うちには合わない』と言われました...」\n\n山本先輩:「どんな提案をした？」\n健太:「在庫管理の効率化です」\n山本先輩:「顧客は在庫管理に困ってたのか？」\n健太:「...たぶん」\n\n山本先輩:「『たぶん』じゃダメだ。\n         ヒアリングなき提案は、\n         診察なき処方と同じだ」", "duration": 30}, {"title": "シーン2: ヒアリングの目的", "content": "山本先輩:「ヒアリングの目的は何だと思う？」\n\n【ヒアリングの目的】\n・顧客の現状を把握する\n・課題・ニーズを特定する\n・提案の方向性を決める\n・予算・スケジュール・決裁者を確認する\n\n山本先輩:「初回商談では、\n         ヒアリング7：提案3が目安だ」\n\n健太:「7割も聞くんですか？」\n山本先輩:「まず聞く。そして提案する。\n         順序が大事だ」", "duration": 30}, {"title": "シーン3: BANTを押さえる", "content": "山本先輩:「BANTって知ってるか？」\n\n【BANT】\nB = Budget（予算）\n 「ご予算はお決まりですか」\n\nA = Authority（決裁権）\n 「最終的にはどなたがお決めになりますか」\n\nN = Needs（ニーズ）\n 「どのような課題をお持ちですか」\n\nT = Timeline（時期）\n 「いつ頃の導入をお考えですか」\n\n山本先輩:「この4つは必ず押さえろ。\n         特に『誰が決めるか』は重要だ」", "duration": 45}], "part2": [{"title": "シーン4: ヒアリングシート", "content": "山本先輩:「ヒアリングシートを用意しろ」\n\n【ヒアリング項目例】\n\n■現状把握\n・現在の在庫管理方法は？\n・使用しているシステムは？\n・従業員数、拠点数は？\n\n■課題把握\n・在庫管理で困っていることは？\n・棚卸しにかかる時間は？\n・ミス・ロスの発生頻度は？\n\n■BANT\n・予算感は？\n・決裁者は？\n・導入希望時期は？\n\n山本先輩:「シートがあれば聞き漏れを防げる」", "duration": 30}, {"title": "シーン5: ヒアリングの進め方", "content": "山本先輩:「ヒアリングの流れを覚えろ」\n\n【ヒアリングの進め方】\n\n①オープニング\n アイスブレイク、本日の流れを説明\n\n②広い質問から\n 「まずは御社の状況を教えてください」\n\n③深掘り質問\n 「それはなぜですか」「具体的には？」\n\n④BANT確認\n 予算、決裁者、時期を自然に聞く\n\n⑤要約・確認\n 「つまり○○ということですね」\n\n⑥次のステップ\n 「○○を踏まえて提案を作成します」", "duration": 30}, {"title": "シーン6: 聞くことの力", "content": "健太:「聞くことで、何が変わりますか？」\n\n山本先輩:「聞くことで、こうなる」\n\n【聞くことの効果】\n・顧客の本当の課題がわかる\n・的を射た提案ができる\n・顧客が「この人はわかってくれる」と感じる\n・競合との差別化になる\n\n山本先輩:「多くの営業は、\n         聞かずに喋りすぎる。\n         聞くことで、むしろ信頼される。\n         ヒアリングは営業の武器だ」", "duration": 30}]}', '{"title": "BANT情報", "content": "B(予算) A(決裁者) N(ニーズ) T(時期)", "audioText": "ヒアリングなき提案は、診察なき処方です。BANTを押さえ、顧客の課題を深く理解してから提案しましょう。", "highlight": "初回商談はヒアリング7：提案3"}', '[{"options": ["ヒアリング3：提案7", "ヒアリング5：提案5", "ヒアリング7：提案3", "ヒアリング0：提案10"], "question": "初回商談でのヒアリングと提案の比率として適切なのは？", "explanation": "初回商談では、ヒアリング7：提案3が目安です。まず聞いてから提案しましょう。", "correctIndex": 2}]', '{"text": "顧客の話を聞かずに提案する営業は、患者を診ずに薬を出す医者と同じだ。", "author": "Symphony営業格言", "textJa": "顧客の話を聞かずに提案する営業は、患者を診ずに薬を出す医者と同じだ。"}', '[{"options": [{"text": "「弊社のシステムをご紹介します」（すぐに提案開始）", "points": 0, "feedback": "ヒアリング前に提案を始めています。まず顧客の状況を聞きましょう。", "isCorrect": false}, {"text": "「その前に、御社の状況を教えていただけますか」（ヒアリングから）", "points": 30, "feedback": "正しいアプローチです。まずヒアリングで顧客を理解してから提案しましょう。", "isCorrect": true}, {"text": "「見積もりを持ってきました」（いきなり見積もり）", "points": 0, "feedback": "ニーズを把握せずに見積もりを出しても的外れになります。", "isCorrect": false}], "situation": "初回商談で、顧客に最初に聞くべき質問は？", "customerLine": "今日はどんなご提案ですか？"}]', '{"question": "次回の商談で、必ず確認したいBANT情報は何ですか？", "placeholder": "例: 決裁者が誰か。前回は担当者としか話せなかったので、今回は決裁者に会いたい"}', '["BANTの4項目を必ず確認するチェックリストを作る", "ヒアリングシートを事前に準備して商談に臨む", "商談後に「聞き漏れがなかったか」を振り返る", "「なぜ？」「具体的には？」の深掘り質問を意識する"]', '{"title": "ヒアリングシートを作る", "fields": [{"label": "現状把握の質問（3つ）", "placeholder": "例: 現在の在庫管理方法は？/使用しているシステムは？/従業員数は？"}, {"label": "課題把握の質問（3つ）", "placeholder": "例: 在庫管理で困っていることは？/棚卸しにかかる時間は？/ミスの発生頻度は？"}, {"label": "BANTの質問（4つ）", "placeholder": "例: ご予算は？/最終決定者は？/なぜ今検討？/導入希望時期は？"}], "description": "自分の担当顧客向けのヒアリング項目を作成してみましょう。"}', NULL, '2026-01-21 17:48:48.388062+00', '2026-01-21 17:48:48.388062+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (86, 58, 'ニーズの顕在化', '顧客は、自分で気づいた問題しか本気で解決しない', '{"icon": "lightbulb", "name": "ニーズ発掘者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["顧客が明確に認識しているニーズ", "顧客自身が気づいていないニーズ", "競合が把握しているニーズ", "営業が作り出したニーズ"], "question": "潜在ニーズとは何か？", "explanation": "潜在ニーズとは、顧客自身がまだ気づいていない、言語化されていないニーズのことです。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 課題を伝えても響かない", "content": "健太:「御社は月20時間も\n      在庫管理に時間がかかっています。\n      これは大きな課題です」\n店長:「まあ、そうかもしれないけど、\n      今までもそれでやってきたし...」\n\n健太（心の声）:「課題を指摘しても\n         全然響かない...」\n\n山本先輩:「健太、課題は誰が見つけた？」\n健太:「僕が見つけて伝えました」\n山本先輩:「そこが問題だ」", "duration": 30}, {"title": "シーン2: 潜在ニーズと顕在ニーズ", "content": "山本先輩:「2種類のニーズを理解しろ」\n\n【顕在ニーズ】\n・顧客自身が認識しているニーズ\n・「○○が欲しい」と明確に言える\n・競合も対応できる\n\n【潜在ニーズ】\n・顧客自身が気づいていないニーズ\n・言語化されていない\n・顕在化させれば独占できる\n\n山本先輩:「顕在ニーズには競合も来る。\n         潜在ニーズを掘り起こせれば、\n         独占的なポジションが取れる」", "duration": 30}, {"title": "シーン3: 気づかせる技術", "content": "山本先輩:「営業が言うのと、\n         顧客が気づくのは全然違う」\n\n【営業が言う場合】\n「御社は年間100時間の無駄があります」\n→ 押し売りに聞こえる\n\n【顧客が気づく場合】\n「年間で考えると...\n 100時間くらいロスしてるかも」\n→ 自分で発見した問題として認識\n\n山本先輩:「顧客は、自分で気づいた問題しか\n         本気で解決しようとしない。\n         営業の役割は『引き出す』ことだ」", "duration": 30}], "part2": [{"title": "シーン4: SPIN話法で顕在化", "content": "山本先輩:「SPIN話法を使え」\n\n【S = Situation（状況質問）】\n「在庫管理はどのようにされていますか？」\n\n【P = Problem（問題質問）】\n「その方法で困っていることは？」\n\n【I = Implication（示唆質問）】★重要\n「その状況が続くと、どんな影響が？」\n\n【N = Need-payoff（解決質問）】\n「もし解決できたら、どうなりますか？」\n\n山本先輩:「特に『I』が大事だ。\n         問題の影響を顧客自身に\n         考えさせるんだ」", "duration": 45}, {"title": "シーン5: 示唆質問の威力", "content": "山本先輩:「示唆質問のバリエーションを覚えろ」\n\n【示唆質問の例】\n・「棚卸しに3日かかると、\n  その間の営業活動はどうなりますか？」\n  \n・「年間で考えると、\n  どれくらいのコストになりますか？」\n  \n・「スタッフの残業は\n  増えていませんか？」\n  \n・「事業が拡大した時、\n  この問題はさらに大きくなりませんか？」\n\n山本先輩:「問題を放置するリスクを\n         顧客自身に考えさせるんだ」", "duration": 30}, {"title": "シーン6: 実践してみる", "content": "【翌日の商談】\n\n健太:「棚卸しに3日かかるとのことですが、\n      その間、営業活動はどうされていますか？」\n店長:「営業に出られないんだよね...」\n健太:「それは月に何日くらいですか？」\n店長:「月末は丸々3日...\n      年間で36日も営業できてないのか」\n健太:「36日間の機会損失、\n      金額にするとどれくらいですか？」\n店長:「うーん...月商を考えると、\n      結構な金額だな...これは問題だ」\n\n顧客自身が問題の大きさに気づいた！", "duration": 30}]}', '{"title": "ニーズの顕在化", "content": "潜在ニーズ → SPIN話法 → 顧客自身が気づく → 顕在ニーズ", "audioText": "潜在ニーズを顕在化させるには、SPIN話法が有効です。特に示唆質問で、問題の影響を顧客自身に考えさせましょう。", "highlight": "顧客は自分で気づいた問題しか本気で解決しない"}', '[{"options": ["状況質問", "問題質問", "示唆質問", "解決質問"], "question": "SPIN話法で最も重要とされる質問は？", "explanation": "示唆質問が最も重要です。問題の影響を顧客自身に考えさせることで、行動への動機付けが生まれます。", "correctIndex": 2}]', '{"text": "顧客は自分で発見した問題しか、本気で解決しようとしない。", "author": "ニール・ラッカム", "textJa": "顧客は自分で発見した問題しか、本気で解決しようとしない。"}', '[{"options": [{"text": "「3日は多いですね。弊社のシステムなら1日で終わりますよ」", "points": 5, "feedback": "いきなり解決策を提示しています。まず示唆質問で問題の大きさを認識させましょう。", "isCorrect": false}, {"text": "「3日間、営業に出られないと、月にどれくらいの機会損失になりますか？」", "points": 30, "feedback": "示唆質問です。問題の影響を顧客自身に考えさせています。", "isCorrect": true}, {"text": "「大変ですね」", "points": 10, "feedback": "共感だけで終わっています。示唆質問で深掘りしましょう。", "isCorrect": false}], "situation": "顧客が「棚卸しに月3日かかる」と言いました。示唆質問をしたい場面です。", "customerLine": "棚卸しに月3日くらいかかってるかな"}]', '{"question": "次の商談で使いたい示唆質問は何ですか？", "placeholder": "例: 「この問題が続くと、年間でどれくらいのコストになりますか？」"}', '["示唆質問のバリエーションを5つ準備する", "商談で「営業が言う」ではなく「顧客に気づかせる」を意識", "問題の影響を金額・時間で考えさせる質問を使う", "SPIN話法のS→P→I→Nの順序を守る"]', NULL, NULL, '2026-01-21 17:48:49.280259+00', '2026-01-21 17:48:49.280259+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (87, 59, '提案書作成の基本', '良い提案書は、顧客が社内で営業してくれるツール', '{"icon": "file-text", "name": "提案書マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["費用→課題→解決策→効果", "課題→解決策→効果→費用", "解決策→課題→費用→効果", "効果→費用→解決策→課題"], "question": "提案書の構成として適切な順序は？", "explanation": "提案書は「課題→解決策→効果→費用」の順序が基本です。顧客の課題から始めましょう。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 読まれない提案書", "content": "健太:「提案書を送ったのに、\n      全然反応がありません...」\n\n山本先輩:「どんな提案書を送った？」\n健太:「会社紹介から始めて、\n      製品の機能を詳しく説明して...」\n\n山本先輩:「それが問題だ。\n         忙しい人は読まない。\n         特に最初のページが\n         自社紹介なら即閉じられる」\n\n健太:「じゃあ、何から書けば...」", "duration": 30}, {"title": "シーン2: 提案書の目的", "content": "山本先輩:「提案書の目的は何だと思う？」\n\n【提案書の目的】\n・顧客に行動してもらうこと\n・不在の決裁者に情報を届けること\n・顧客が社内で説明するツールになること\n\n山本先輩:「つまり、提案書は\n         『顧客が社内で営業してくれる\n          ツール』なんだ」\n\n健太:「担当者が上司に説明する時に\n      使うってことですか」\n\n山本先輩:「その通り。だから\n         担当者でも説明できる\n         シンプルさが必要だ」", "duration": 30}, {"title": "シーン3: 提案書の基本構成", "content": "山本先輩:「提案書の構成を覚えろ」\n\n【提案書の基本構成】\n①表紙\n②エグゼクティブサマリー（1ページで要約）\n③課題の整理\n④解決策の提示\n⑤導入効果（数字で）\n⑥導入事例\n⑦費用・スケジュール\n⑧次のステップ\n\n山本先輩:「特に大事なのは\n         『③課題の整理』から始めること。\n         自社紹介や機能説明からは\n         始めない」", "duration": 45}], "part2": [{"title": "シーン4: 顧客視点で書く", "content": "山本先輩:「提案書の書き方のコツだ」\n\n【顧客視点で書く】\n❌「弊社は創業30年の実績があり...」\n✅「御社の課題である○○について...」\n\n【数字で示す】\n❌「大幅に効率化できます」\n✅「月20時間の作業を削減できます」\n\n【結論を先に】\n❌「まず製品の背景から説明すると...」\n✅「結論として、○○を提案します」\n\n山本先輩:「常に『顧客にとって\n         どんな価値があるか』を書け」", "duration": 30}, {"title": "シーン5: 次のアクションを明示", "content": "山本先輩:「最後に大事なこと」\n\n【次のステップを明示する】\n❌「ご検討ください」\n✅「○月○日までにご回答ください」\n✅「来週、デモをご覧いただけますか」\n\n山本先輩:「『ご検討ください』で終わる\n         提案書は、何も起きない。\n         いつまでに何をすべきか\n         明確に示せ」\n\n健太:「期限を切るってことですか」\n山本先輩:「そう。期限がないと、\n         人は動かない」", "duration": 30}, {"title": "シーン6: NGな提案書", "content": "山本先輩:「NGな提案書の特徴を覚えておけ」\n\n【NGな提案書】\n・自社の歴史、組織図から始まる\n・製品の機能一覧が延々と続く\n・顧客の課題が書かれていない\n・数字がない（「大幅に」「かなり」）\n・事例がない\n・「ご検討ください」で終わる\n\n山本先輩:「要するに『自分が言いたいこと』\n         ではなく『顧客が知りたいこと』\n         を書け。それが提案書の鉄則だ」", "duration": 30}]}', '{"title": "提案書の基本構成", "content": "課題 → 解決策 → 効果 → 事例 → 費用 → 次のステップ", "audioText": "提案書は顧客が社内で営業してくれるツールです。課題から始め、数字で効果を示し、次のアクションを明確にしましょう。", "highlight": "顧客視点、数字、次のアクション明示"}', '[{"options": ["顧客の課題", "提案の要約", "自社の歴史・組織図", "導入効果"], "question": "提案書の最初のページに書くべきでないものは？", "explanation": "自社の歴史や組織図は顧客にとって興味がありません。課題や効果から始めましょう。", "correctIndex": 2}]', '{"text": "良い提案書は、顧客が社内で営業してくれるツールだ。", "author": "Symphony営業格言", "textJa": "良い提案書は、顧客が社内で営業してくれるツールだ。"}', '[{"options": [{"text": "会社概要と沿革", "points": 0, "feedback": "顧客は自社の歴史に興味がありません。課題や価値から始めましょう。", "isCorrect": false}, {"text": "製品の機能一覧", "points": 5, "feedback": "機能だけでは顧客に響きません。顧客の課題と解決策を先に。", "isCorrect": false}, {"text": "顧客の課題と提案の要約", "points": 30, "feedback": "正解です。顧客視点で始め、要点を最初に伝えましょう。", "isCorrect": true}], "situation": "提案書の最初のページに何を書くべきですか？", "customerLine": "（提案書を作成中）"}]', '{"question": "自分の提案書で改善すべき点は何ですか？", "placeholder": "例: 自社紹介から始めていた。顧客の課題から始めるようにする"}', '["提案書の最初のページを「顧客の課題」から始める", "数字（金額、時間、%）を必ず入れる", "「ご検討ください」ではなく期限を明示する", "事例を必ず1つ以上入れる"]', '{"title": "提案書の構成を考える", "fields": [{"label": "①顧客の課題（3つ）", "placeholder": "例: 棚卸しに月3日かかる/在庫切れが頻発/データ入力ミスが多い"}, {"label": "②解決策（Symphonyでどう解決するか）", "placeholder": "例: バーコード管理で棚卸し1日に短縮/自動発注で在庫切れ防止"}, {"label": "③導入効果（数字で）", "placeholder": "例: 月20時間削減/年間100万円コスト削減/ミス90%減少"}, {"label": "④次のステップ", "placeholder": "例: 来週デモを実施/○月○日までにご回答いただきたい"}], "description": "次回の提案書の構成を考えてみましょう。"}', NULL, '2026-01-21 17:48:50.007432+00', '2026-01-21 17:48:50.007432+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (88, 60, 'プレゼンテーションの技術', 'プレゼンは、スライドを読む場ではない', '{"icon": "presentation", "name": "プレゼンター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["最後の3分", "中盤の説明", "最初の3分", "質疑応答"], "question": "プレゼンで最も重要な時間は？", "explanation": "最初の3分で聴衆の興味を引けるかどうかが、プレゼンの成否を分けます。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 退屈なプレゼン", "content": "健太:「先日のプレゼン、\n      途中で寝てる人がいました...」\n\n山本先輩:「どんなプレゼンをした？」\n健太:「スライドを順番に読み上げて、\n      機能を一つずつ説明しました」\n\n山本先輩:「それが原因だ。\n         プレゼンは『スライドを読む場』\n         じゃない」\n\n健太:「じゃあ、何をする場なんですか？」\n山本先輩:「顧客の心を動かす場だ」", "duration": 30}, {"title": "シーン2: プレゼンの目的", "content": "山本先輩:「プレゼンの目的を確認しよう」\n\n【プレゼンの目的】\n・顧客を次のステップに進めること\n・提案内容を口頭で補足し、理解を深める\n・顧客の反応を見ながら調整する\n・熱意を伝え、信頼を獲得する\n\n山本先輩:「提案書は『読まれるもの』、\n         プレゼンは『体験させるもの』。\n         同じ内容でも伝え方が違う」\n\n健太:「体験させる...？」\n山本先輩:「ストーリーで伝えるんだ」", "duration": 30}, {"title": "シーン3: 最初の3分が勝負", "content": "山本先輩:「プレゼンは最初の3分で決まる」\n\n【オープニングでやること】\n・アイスブレイク（場を和ませる）\n・結論を先に伝える\n・価値を端的に示す\n・今日のアジェンダと所要時間を伝える\n\n【NGなオープニング】\n・「今日は弊社について説明します」\n・「このスライドから始めます」\n・いきなり機能説明\n\n山本先輩:「最初の3分で興味を引けないと、\n         残りの時間は聞いてもらえない」", "duration": 45}], "part2": [{"title": "シーン4: 聴衆を見て話す", "content": "山本先輩:「プレゼンの鉄則を教える」\n\n【聴衆を見て話す】\n・スライドではなく、人を見る\n・一人一人とアイコンタクト\n・反応を見ながら話す速度を調整\n・うなずいている人を見つける\n\n【一方的に話さない】\n・「ここまでよろしいですか？」\n・「ご質問ありますか？」\n・合間に確認を入れる\n\n山本先輩:「プレゼンは独演会じゃない。\n         双方向のコミュニケーションだ」", "duration": 30}, {"title": "シーン5: ストーリーで伝える", "content": "山本先輩:「機能説明じゃなくストーリーで伝えろ」\n\n【機能説明】（NG）\n「この機能は在庫を自動で計算します」\n\n【ストーリー】（OK）\n「以前、○○社の店長が\n 毎月3日徹夜で棚卸しをしていました。\n 導入後、たった1日で終わるようになり、\n 『家族との時間が増えた』と\n 喜んでいただきました」\n\n山本先輩:「人は機能を覚えられない。\n         でもストーリーは記憶に残る」", "duration": 30}, {"title": "シーン6: 質疑応答の対処", "content": "山本先輩:「質疑応答も大事だ」\n\n【質問への対応】\n・「良いご質問ですね」と受け止める\n・わからない時は正直に\n 「確認して後日ご回答します」\n\n【反論への対応】\n・「おっしゃる通りです」と一度受け止める\n・「一方で...」と反論する\n・感情的にならない\n\n【想定問答の準備】\n・事前に想定される質問を書き出す\n・回答を準備しておく\n\n山本先輩:「質疑応答は、\n         信頼を勝ち取るチャンスだ」", "duration": 30}]}', '{"title": "プレゼンの心得", "content": "最初の3分が勝負 / 聴衆を見る / ストーリーで伝える", "audioText": "プレゼンは最初の3分で決まります。スライドを読むのではなく、聴衆を見てストーリーで伝えましょう。", "highlight": "プレゼンは顧客の心を動かす場"}', '[{"options": ["スライド", "手元のメモ", "聴衆の顔", "時計"], "question": "プレゼン中に見るべきものは？", "explanation": "聴衆の顔を見て反応を確認しながら話しましょう。スライドを読むのはNGです。", "correctIndex": 2}]', '{"text": "プレゼンは、スライドを読み上げる場ではない。顧客の心を動かす場だ。", "author": "Symphony営業格言", "textJa": "プレゼンは、スライドを読み上げる場ではない。顧客の心を動かす場だ。"}', '[{"options": [{"text": "気にせずスライドを進める", "points": 0, "feedback": "聴衆の反応を無視しています。確認を入れましょう。", "isCorrect": false}, {"text": "「ここまでで、ご不明な点はございますか？」と確認する", "points": 30, "feedback": "聴衆の反応を見て対応しています。双方向のコミュニケーションが大切です。", "isCorrect": true}, {"text": "早口でスライドを終わらせる", "points": 0, "feedback": "逆効果です。聴衆のペースに合わせましょう。", "isCorrect": false}], "situation": "プレゼン中に「よくわからない」という顔をしている人がいます。", "customerLine": "（難しそうな顔をしている）"}, {"options": [{"text": "「たぶん、すごく速いと思います」", "points": 0, "feedback": "曖昧な回答は信頼を損ないます。わからないなら正直に。", "isCorrect": false}, {"text": "「確認して後日ご回答いたします」", "points": 30, "feedback": "正直に答え、フォローアップを約束しています。信頼につながります。", "isCorrect": true}, {"text": "「それは重要ではありません」", "points": 0, "feedback": "顧客の質問を軽視しています。誠実に対応しましょう。", "isCorrect": false}], "situation": "質疑応答で答えられない質問をされました。", "customerLine": "この機能の処理速度は具体的にどれくらいですか？"}]', '{"question": "次回のプレゼンで、特に意識したいことは何ですか？", "placeholder": "例: 最初の3分で結論と価値を伝える。スライドではなく聴衆を見る"}', '["プレゼン前に必ずリハーサルを行う", "最初の3分の原稿を作成し、暗記する", "想定問答を5つ以上準備する", "事例・ストーリーを必ず1つ入れる"]', NULL, NULL, '2026-01-21 17:48:50.658775+00', '2026-01-21 17:48:50.658775+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (89, 61, 'クロージングの技術', 'クロージングを恐れるな。顧客は後押しを待っている', '{"icon": "check-circle", "name": "クローザー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["強引に押し切ること", "顧客を騙すこと", "顧客の決断を後押しすること", "何度も電話すること"], "question": "クロージングとして正しい考え方は？", "explanation": "クロージングは「顧客の決断を後押しすること」です。強引さや騙しではありません。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: クロージングが怖い", "content": "健太:「いい感じの商談だったのに、\n      結局契約に至りませんでした...」\n\n山本先輩:「クロージングはしたのか？」\n健太:「いや、タイミングが分からなくて...\n      『ご検討ください』と言って終わりました」\n\n山本先輩:「それが原因だ。\n         クロージングしないと、\n         顧客は決められない」\n\n健太:「でも、押し売りみたいで...」", "duration": 30}, {"title": "シーン2: クロージングの誤解", "content": "山本先輩:「クロージングを誤解してるな」\n\n【クロージングの誤解】\n❌ 強引に押し切ること\n❌ 顧客を騙すこと\n❌ しつこく迫ること\n\n【クロージングの本質】\n✅ 顧客が決断しやすいよう、後押しすること\n\n山本先輩:「顧客は迷ってるだけなんだ。\n         背中を押してほしいと\n         思ってることも多い」\n\n健太:「後押し...ですか」", "duration": 30}, {"title": "シーン3: 買いシグナルを見逃すな", "content": "山本先輩:「クロージングのタイミングを教える」\n\n【買いシグナルの例】\n・「導入後のサポートは？」\n・「他社の事例は？」\n・「値引きは可能？」\n・「いつから使える？」\n・具体的な質問が増えてきた\n・資料を熱心に見ている\n\n山本先輩:「こういう発言が出たら、\n         顧客は前向きに検討している証拠。\n         クロージングのタイミングだ」\n\n健太:「質問が増えたらチャンスなんですね」", "duration": 45}], "part2": [{"title": "シーン4: クロージングの技法", "content": "山本先輩:「クロージングの技法を覚えろ」\n\n【直接クロージング】\n「では、ご契約いただけますか」\n→ シンプルに聞く\n\n【選択肢クロージング】\n「月額と年額、どちらがよろしいですか」\n→ Yes/Noではなく選択肢を提示\n\n【仮定クロージング】\n「導入するとしたら、いつ頃が？」\n→ 導入を前提にした質問\n\n【期限クロージング】\n「今月中でしたら○○の特典があります」\n→ 期限を設けて決断を促す", "duration": 30}, {"title": "シーン5: 断られた時の対応", "content": "山本先輩:「断られた時の対応も大事だ」\n\n【「検討します」と言われたら】\n「ありがとうございます。\n ちなみに、ご検討のポイントは何でしょうか」\n→ 懸念を特定し、解消を試みる\n\n【「上に相談します」と言われたら】\n「承知いたしました。\n 上の方にご説明する機会をいただけますか」\n→ 決裁者へのアプローチを試みる\n\n【「予算がない」と言われたら】\n「予算確保の可能性があるのはいつ頃ですか」\n→ 時期をずらす提案", "duration": 30}, {"title": "シーン6: 関係を維持する", "content": "山本先輩:「断られても終わりじゃない」\n\n【断られても関係を維持】\n・今回ダメでも、次の機会につながる\n・感謝を伝えて丁寧に終わる\n・定期的に情報提供を続ける\n・状況が変わった時に声をかけてもらえる\n\n山本先輩:「クロージングを恐れるな。\n         顧客は、決断を後押ししてほしいと\n         思っている。\n         勇気を持って聞け」\n\n健太:「わかりました！」", "duration": 30}]}', '{"title": "クロージングの技法", "content": "直接 / 選択肢 / 仮定 / 期限", "audioText": "クロージングは顧客の決断を後押しすることです。買いシグナルを見逃さず、適切なタイミングで勇気を持って聞きましょう。", "highlight": "買いシグナルを見逃さず、勇気を持って聞く"}', '[{"options": ["「わかりました」と引き下がる", "「ご検討のポイントは何ですか」と聞く", "「今日決めてください」と押す", "次回の連絡を待つ"], "question": "「検討します」と言われた時の適切な対応は？", "explanation": "検討のポイント（懸念点）を聞くことで、それを解消するチャンスが生まれます。", "correctIndex": 1}]', '{"text": "クロージングを恐れるな。顧客は、決断を後押ししてほしいと思っている。", "author": "Symphony営業格言", "textJa": "クロージングを恐れるな。顧客は、決断を後押ししてほしいと思っている。"}', '[{"options": [{"text": "「来月から使えます」とだけ答える", "points": 10, "feedback": "質問には答えていますが、クロージングにつなげていません。", "isCorrect": false}, {"text": "「来月から使えます。では、来月からの導入でよろしいでしょうか」", "points": 30, "feedback": "買いシグナルを捉え、クロージングにつなげています。", "isCorrect": true}, {"text": "「その前に、もう一度機能を説明させてください」", "points": 0, "feedback": "クロージングのタイミングを逃しています。顧客は前向きです。", "isCorrect": false}], "situation": "顧客が「いつから使えますか」と聞いてきました。これは買いシグナルです。", "customerLine": "導入するとしたら、いつから使えますか？"}, {"options": [{"text": "「わかりました。ご連絡お待ちしています」", "points": 5, "feedback": "簡単に引き下がっています。懸念点を確認しましょう。", "isCorrect": false}, {"text": "「ありがとうございます。ご検討のポイントは何でしょうか」", "points": 30, "feedback": "懸念点を確認しています。それを解消できればクロージングにつながります。", "isCorrect": true}, {"text": "「今日決めていただかないと、この価格では難しいです」", "points": 0, "feedback": "強引すぎます。顧客との関係を損なう可能性があります。", "isCorrect": false}], "situation": "「検討します」と言われました。", "customerLine": "ちょっと検討させてください"}]', '{"question": "クロージングで、自分が改善すべき点は何ですか？", "placeholder": "例: 買いシグナルを見逃していた。質問が増えてきたらクロージングのタイミングだと意識する"}', '["買いシグナルのリストを覚え、意識して商談に臨む", "「では、ご契約いただけますか」と直接聞く練習をする", "「検討します」と言われた時の切り返しを準備する", "断られても関係を維持し、次の機会につなげる"]', NULL, NULL, '2026-01-21 17:48:51.965429+00', '2026-01-21 17:48:51.965429+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (90, 62, '契約手続きとオンボーディング', '契約はゴールではなく、スタートライン', '{"icon": "rocket", "name": "オンボーディングマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["契約書を作成すること", "顧客がサービスを使いこなせるよう支援すること", "請求書を送ること", "競合を排除すること"], "question": "オンボーディングとは何か？", "explanation": "オンボーディングは「顧客がサービスを使いこなせるようになるまでの導入支援」です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 契約後のトラブル", "content": "健太:「やったー！契約取れました！」\n山本先輩:「おめでとう。で、その後は？」\n健太:「...その後？」\n\n山本先輩:「契約手続きはスムーズに進んでる？\n         顧客の導入準備は？」\n\n健太:「あ、まだ何も...」\n\n山本先輩:「契約はゴールじゃない。\n         むしろここからがスタートだ」", "duration": 30}, {"title": "シーン2: 契約手続きの重要性", "content": "山本先輩:「契約手続きで起こりがちな問題を知っておけ」\n\n【契約手続きで起こる問題】\n・必要書類が揃わない\n・決裁者の承認が遅れる\n・法務チェックで止まる\n・支払い条件で折り合わない\n・社内の反対者が現れる\n\n山本先輩:「こういう問題で、\n         せっかくの成約が流れることがある。\n         契約完了まで気を抜くな」", "duration": 30}, {"title": "シーン3: 契約手続きの基本フロー", "content": "山本先輩:「契約手続きの流れを覚えろ」\n\n【契約手続きの基本フロー】\n①契約条件の最終確認\n （価格、支払い条件、契約期間）\n②契約書の作成・送付\n③相手企業の法務チェック\n④必要に応じて修正・調整\n⑤署名・捺印\n⑥契約書の保管\n\n山本先輩:「途中でストップしないよう、\n         こまめに進捗を確認しろ」", "duration": 45}], "part2": [{"title": "シーン4: オンボーディングとは", "content": "山本先輩:「契約後はオンボーディングだ」\n\n【オンボーディングとは】\n顧客がサービスを使いこなせるようになるまでの\n導入支援プロセス\n\n【オンボーディングの目的】\n・顧客がサービスの価値を実感できるようにする\n・初期の疑問・不安を解消する\n・長期的な利用・リピートにつなげる\n\n山本先輩:「最初の90日で顧客の満足度が決まる。\n         オンボーディングが不十分だと\n         解約につながる」", "duration": 30}, {"title": "シーン5: Symphonyのオンボーディング", "content": "山本先輩:「Symphonyでのオンボーディング例を見せる」\n\n【Symphonyオンボーディングの流れ】\n\n①キックオフミーティング\n 導入スケジュールの説明\n\n②初期設定サポート\n マスタデータの登録支援\n\n③操作トレーニング\n 実際の画面で操作方法を説明\n\n④運用開始\n 本番利用スタート、質問対応\n\n⑤1週間後フォロー\n 困りごとがないか確認\n\n⑥1ヶ月後レビュー\n 利用状況確認、活用アドバイス", "duration": 30}, {"title": "シーン6: 成功体験を早期に", "content": "山本先輩:「オンボーディングで大事なこと」\n\n【成功体験を早期に提供する】\n・最初の1週間で「これは便利だ」と感じてもらう\n・小さな成功を積み重ねる\n・困っている時にすぐサポート\n\n山本先輩:「最初の印象が悪いと、\n         ずっと使われなくなる。\n         逆に最初に成功体験があれば、\n         ファンになってくれる」\n\n健太:「契約がスタートラインですね！」", "duration": 30}]}', '{"title": "オンボーディングの流れ", "content": "キックオフ → 初期設定 → トレーニング → 運用開始 → フォロー", "audioText": "契約はゴールではなくスタートラインです。オンボーディングで早期に成功体験を提供し、顧客満足度を高めましょう。", "highlight": "最初の90日で顧客満足度が決まる"}', '[{"options": ["契約書を早く回収する", "追加の商品を売る", "早期に成功体験を提供する", "次の顧客を探す"], "question": "オンボーディングで最も重要なことは？", "explanation": "オンボーディングでは、顧客に早期に成功体験を提供することが最も重要です。", "correctIndex": 2}]', '{"text": "契約はゴールではなく、顧客との関係のスタートラインだ。", "author": "Symphony営業格言", "textJa": "契約はゴールではなく、顧客との関係のスタートラインだ。"}', '[{"options": [{"text": "次の見込み客に集中する", "points": 0, "feedback": "契約後の顧客を放置しています。オンボーディングが必要です。", "isCorrect": false}, {"text": "キックオフミーティングの日程を調整する", "points": 30, "feedback": "オンボーディングの第一歩です。導入スケジュールを確認しましょう。", "isCorrect": true}, {"text": "追加の製品を提案する", "points": 5, "feedback": "まずは契約した製品の導入支援が優先です。", "isCorrect": false}], "situation": "契約が完了し、来週から導入開始です。最初にすべきことは？", "customerLine": "（契約書に署名完了）"}]', '{"question": "契約後の顧客に対して、改善したいことは何ですか？", "placeholder": "例: 契約後のフォローが不十分だった。1週間後と1ヶ月後のフォローを必ず行う"}', '["契約手続きのチェックリストを作成する", "オンボーディングのスケジュールテンプレートを用意する", "導入1週間後のフォロー電話を必ず行う", "導入1ヶ月後に利用状況レビューを実施する"]', NULL, NULL, '2026-01-21 17:48:52.652929+00', '2026-01-21 17:48:52.652929+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (91, 63, 'フォローアップ設計', '売った後にどれだけ関われるかが、営業の真価', '{"icon": "heart-handshake", "name": "リレーションシップビルダー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["2倍", "3倍", "5倍", "10倍"], "question": "新規顧客獲得コストは、既存顧客維持コストの何倍？", "explanation": "新規顧客獲得コストは、既存顧客維持コストの5倍かかると言われています（1:5の法則）。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 既存顧客を忘れている", "content": "健太:「新規開拓、なかなか成果が出ません...」\n山本先輩:「ところで、既存顧客はどうしてる？」\n健太:「既存顧客...？\n      一度契約したら、終わりじゃないですか？」\n\n山本先輩:「それは大きな間違いだ。\n         既存顧客こそ、宝の山だ」\n\n健太:「どういうことですか？」", "duration": 30}, {"title": "シーン2: 1:5の法則", "content": "山本先輩:「1:5の法則を知っているか？」\n\n【1:5の法則】\n新規顧客獲得コストは、\n既存顧客維持コストの5倍かかる\n\n【5:25の法則】\n顧客離れを5%改善すれば、\n利益は25%以上向上する\n\n山本先輩:「つまり、新規を追いかけるより\n         既存顧客を大事にする方が\n         効率的なんだ」", "duration": 30}, {"title": "シーン3: 既存顧客の価値", "content": "山本先輩:「既存顧客の価値を整理しよう」\n\n【既存顧客の価値】\n・リピート購入の可能性\n・アップセル・クロスセルの機会\n・紹介による新規顧客獲得\n・長期的な安定収益\n・フィードバックによる製品改善\n\n山本先輩:「一度信頼関係ができれば、\n         追加提案も通りやすい。\n         紹介ももらえる。\n         だからフォローアップが大事なんだ」", "duration": 45}], "part2": [{"title": "シーン4: フォローのタイミング", "content": "山本先輩:「フォローアップのタイミングを覚えろ」\n\n【フォローアップのタイミング】\n\n■導入直後\n困りごとがないか確認\n\n■1週間後\n使い始めて出てきた疑問に対応\n\n■1ヶ月後\n利用状況を確認、活用サポート\n\n■3ヶ月後\n導入効果を数値で確認\n\n■契約更新前\n更新の意思確認、追加ニーズヒアリング\n\n■定期的\n年に2〜4回は接点を持つ", "duration": 30}, {"title": "シーン5: フォローの内容", "content": "山本先輩:「フォローで何を話すか」\n\n【フォローアップの内容】\n・「システムは問題なくお使いですか」\n  →利用状況の確認\n・「導入前と比べて、変化はありましたか」\n  →効果の確認\n・「他にお困りのことはございませんか」\n  →追加ニーズの確認\n・「新機能のご案内です」\n  →情報提供\n・「お知り合いで同じ課題をお持ちの方は」\n  →紹介依頼\n\n山本先輩:「フォローは『売り込み』じゃなく\n         『価値提供』だ」", "duration": 30}, {"title": "シーン6: 接点を増やす工夫", "content": "山本先輩:「接点を増やす工夫も大事だ」\n\n【接点を増やす方法】\n・ニュースレター、メルマガの配信\n・新機能のお知らせ\n・業界ニュースの共有\n・季節の挨拶（年賀状、暑中見舞い）\n・ユーザー会の開催\n・活用セミナーへの招待\n\n山本先輩:「売った後にどれだけ関われるかが、\n         営業の真価を問われる。\n         既存顧客を大事にしろ」", "duration": 30}]}', '{"title": "フォローアップのタイミング", "content": "導入直後 → 1週間 → 1ヶ月 → 3ヶ月 → 定期的", "audioText": "フォローアップは売り込みではなく価値提供です。既存顧客を大事にすることで、リピート・紹介・安定収益につながります。", "highlight": "新規獲得より既存顧客維持が5倍効率的"}', '[{"options": ["追加商品を売り込む", "価値を提供する", "問題を指摘する", "競合の悪口を言う"], "question": "フォローアップで大切な姿勢は？", "explanation": "フォローアップは売り込みではなく、顧客に価値を提供することが大切です。", "correctIndex": 1}]', '{"text": "売った後にどれだけ関われるかが、営業の真価を問われる。", "author": "Symphony営業格言", "textJa": "売った後にどれだけ関われるかが、営業の真価を問われる。"}', '[{"options": [{"text": "「追加で別の製品もいかがですか」", "points": 0, "feedback": "いきなり売り込みはNGです。まず利用状況を確認しましょう。", "isCorrect": false}, {"text": "「システムは問題なくお使いいただけていますか」", "points": 30, "feedback": "利用状況の確認から始めています。顧客を気遣う姿勢が大切です。", "isCorrect": true}, {"text": "「特に用事はないんですが、お元気ですか」", "points": 5, "feedback": "目的のない電話は相手の時間を奪います。価値のある情報を提供しましょう。", "isCorrect": false}], "situation": "導入1ヶ月後の顧客にフォロー電話をします。何を聞きますか？", "customerLine": "お電話ありがとうございます"}]', '{"question": "既存顧客へのフォローで、改善したいことは何ですか？", "placeholder": "例: 導入後3ヶ月フォローができていなかった。カレンダーにリマインダーを設定する"}', '["既存顧客のフォロースケジュールを作成する", "導入1週間後のフォロー電話を必ず行う", "年に2回は全顧客に接点を持つ", "満足している顧客に紹介を依頼する"]', NULL, NULL, '2026-01-21 17:48:53.415664+00', '2026-01-21 17:48:53.415664+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (92, 64, '案件管理（パイプライン）', '測定できないものは、改善できない', '{"icon": "bar-chart-2", "name": "パイプラインマネージャー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["顧客を監視する", "案件の進捗と売上を予測する", "競合を分析する", "製品を改善する"], "question": "パイプライン管理の目的として正しいのは？", "explanation": "パイプライン管理の目的は「案件の進捗を段階ごとに管理し、売上を予測すること」です。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 売上が読めない", "content": "マネージャー:「健太、今月の売上見込みは？」\n健太:「えーと...頑張れば\n      100万円くらいいくかもしれません」\n\nマネージャー:「『頑張れば』『かもしれません』\n         って、根拠は何だ？」\n\n健太:「...感覚です」\n\n山本先輩:「健太、それじゃダメだ。\n         案件を『数字』で管理しろ」", "duration": 30}, {"title": "シーン2: パイプライン管理とは", "content": "山本先輩:「パイプライン管理を教えよう」\n\n【パイプライン管理とは】\n商談の進捗を段階ごとに管理し、\n売上を予測する手法\n\n【パイプラインのイメージ】\nリード → アポ → 商談 → 提案 → 交渉 → 成約\n\n【パイプライン管理のメリット】\n・現在の案件状況が一目でわかる\n・将来の売上を予測できる\n・ボトルネックを特定できる\n・優先すべき案件が明確になる", "duration": 30}, {"title": "シーン3: パイプラインの段階", "content": "山本先輩:「パイプラインの段階を決めておく」\n\n【パイプラインの段階例】\n①リード：見込み客を特定した段階\n②アポ獲得：商談の約束を取り付けた\n③初回商談：初めて顧客と商談した\n④ニーズ把握：課題・ニーズを把握した\n⑤提案：提案書を提出した\n⑥交渉：価格・条件を交渉中\n⑦成約：契約が締結された\n⑧失注：案件が失われた（理由を記録）\n\n山本先輩:「各案件が今どの段階にあるか、\n         常に把握しておけ」", "duration": 45}], "part2": [{"title": "シーン4: 確度と加重金額", "content": "山本先輩:「案件の評価指標を覚えろ」\n\n【案件の評価指標】\n・金額：予想売上金額\n・確度：成約の確率（%）\n・予想時期：成約が見込まれる時期\n・加重金額：金額×確度\n\n【確度の目安】\n10%：ニーズ確認前\n30%：ニーズ確認済み\n50%：提案済み\n80%：交渉中\n100%：成約\n\n【例】\n案件A：100万円×80%=80万円（加重金額）\n案件B：200万円×30%=60万円（加重金額）", "duration": 30}, {"title": "シーン5: パイプライン管理の実践", "content": "山本先輩:「実践のポイントを教える」\n\n【パイプライン管理の実践】\n\n■毎日更新\n案件の進捗を毎日記録。放置しない\n\n■週次レビュー\n週に1回、全案件を見直す\n\n■停滞案件への対処\n2週間動きがない案件はアクションを起こす\n\n■パイプラインの健全性\n各段階に適切な数の案件があるか確認\n\n山本先輩:「パイプラインが枯れると、\n         数ヶ月後の売上が消える」", "duration": 30}, {"title": "シーン6: 売上予測を報告", "content": "【1週間後】\n\nマネージャー:「健太、今月の売上見込みは？」\n\n健太:「提案中の案件が3件あります。\n      A社100万円×80%で80万円、\n      B社50万円×50%で25万円、\n      C社80万円×30%で24万円。\n      加重金額の合計は約130万円です」\n\nマネージャー:「なるほど、根拠がある数字だな。\n         A社を確実に決めて、\n         B社の確度を上げることを優先しよう」\n\n山本先輩:「これがプロの営業の報告だ」", "duration": 30}]}', '{"title": "パイプライン管理", "content": "リード → アポ → 商談 → 提案 → 交渉 → 成約", "audioText": "パイプライン管理で案件を数字で把握しましょう。加重金額を使えば、精度の高い売上予測ができます。", "highlight": "金額×確度＝加重金額で売上予測"}', '[{"options": ["20万円", "80万円", "100万円", "180万円"], "question": "案件A（100万円、確度80%）の加重金額は？", "explanation": "加重金額は金額×確度です。100万円×80%＝80万円となります。", "correctIndex": 1}]', '{"text": "測定できないものは、改善できない。案件を数値で管理せよ。", "author": "ピーター・ドラッカー（意訳）", "textJa": "測定できないものは、改善できない。案件を数値で管理せよ。"}', '[{"options": [{"text": "「頑張って100万円くらいです」", "points": 0, "feedback": "根拠のない数字です。案件ごとの確度を計算して報告しましょう。", "isCorrect": false}, {"text": "「交渉中が2件で加重金額100万円、提案中が3件で60万円、合計160万円の見込みです」", "points": 30, "feedback": "案件ごとの確度と加重金額に基づいた報告です。", "isCorrect": true}, {"text": "「まだわかりません」", "points": 5, "feedback": "案件を管理していれば予測は可能です。パイプラインを整理しましょう。", "isCorrect": false}], "situation": "上司から「来月の売上見込みは？」と聞かれました。", "customerLine": "来月の売上見込みを教えてくれ"}]', '{"question": "自分のパイプラインで、最も注力すべき案件はどれですか？", "placeholder": "例: A社。確度80%で金額も大きいので、今月中に確実に決めたい"}', '["全案件を洗い出し、段階と確度を記録する", "週に1回、パイプラインをレビューする", "2週間以上停滞している案件にアクションを起こす", "加重金額を計算して売上予測を立てる"]', '{"title": "パイプラインを整理する", "fields": [{"label": "案件1（会社名、金額、確度、加重金額）", "placeholder": "例: A社、100万円、80%、80万円"}, {"label": "案件2（会社名、金額、確度、加重金額）", "placeholder": "例: B社、50万円、50%、25万円"}, {"label": "案件3（会社名、金額、確度、加重金額）", "placeholder": "例: C社、80万円、30%、24万円"}, {"label": "加重金額の合計", "placeholder": "例: 129万円"}], "description": "自分の案件を整理し、加重金額を計算してみましょう。"}', NULL, '2026-01-21 17:48:54.149337+00', '2026-01-21 17:48:54.149337+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (93, 65, '反論対処の基本フレームワーク', '反論は拒絶ではなく関心のサイン', '{"icon": "shield", "name": "反論マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["金額÷確度", "金額×確度", "金額+確度", "金額−確度"], "question": "案件管理で使う「加重金額」の計算式として正しいものは？", "explanation": "加重金額＝金額×確度（%）です。100万円の案件で確度50%なら、50万円として計算します。", "correctIndex": 1}', '{"part1": [{"title": "反論に萎縮する健太", "content": "営業3ヶ月目の健太は、大型商談から帰ってきた。\n\n健太「山本先輩...今日の商談、ダメでした」\n\n山本「どうした、そんな落ち込んで」\n\n健太「お客様に『高いですね』『検討します』と言われて...\n何も返せなかったんです。反論されると頭が真っ白に...」\n\n山本「なるほどな。でも健太、それは良いサインかもしれないぞ」\n\n健太「え？断られそうなのに良いサイン？」"}, {"title": "反論の本当の意味", "content": "山本「考えてみろ。本当に興味がなければ、\n最初から『結構です』と断るだろ？」\n\n健太「...確かに」\n\n山本「『高い』『検討します』と言ったってことは、\n話を聞いてくれた証拠だ。\nつまり、関心はあるけど何か障壁があるってことだな」\n\n健太「障壁...ですか」\n\n山本「そう。その障壁が何かを特定して、\n解消できれば成約につながる。\n反論は『拒絶』じゃない。『対話の始まり』なんだ」"}], "part2": [{"title": "LSCPA法を学ぶ", "content": "山本「反論対処には『LSCPA法』というフレームワークがある」\n\nL = Listen（傾聴）：まず最後まで聞く\nS = Share（共感）：気持ちに寄り添う  \nC = Clarify（明確化）：真の懸念を特定\nP = Present（提示）：解決策を提案\nA = Ask（確認）：合意を確認\n\n山本「ポイントは、すぐに反論しないことだ。\nまず聞いて、共感して、それから対応する」\n\n健太「なるほど...反射的に反論してました」"}]}', '{"title": "LSCPA法", "content": "L = Listen（傾聴）：まず最後まで聞く\nS = Share（共感）：気持ちに寄り添う\nC = Clarify（明確化）：真の懸念を特定\nP = Present（提示）：解決策を提案\nA = Ask（確認）：合意を確認", "audioText": "反論対処の基本はLSCPA。傾聴、共感、明確化、提示、確認の5ステップで対応します。", "highlight": "即座に反論せず、まず聞いて共感する"}', '[{"options": ["Solution（解決）", "Share（共感）", "Sell（販売）", "Stop（停止）"], "question": "LSCPA法の「S」は何を表す？", "explanation": "Sは Share（共感）です。反論を受けたら、まず顧客の気持ちに共感することが重要です。", "correctIndex": 1}]', '{"text": "反論は購買の始まり。沈黙は拒絶の始まり。", "author": "営業の格言", "textJa": "反論は購買の始まり。沈黙こそが本当の拒絶である。"}', '[{"options": [{"text": "「いえ、他社と比べれば全然高くないですよ」", "points": 0, "feedback": "即座に反論すると、顧客の心理的リアクタンスを招きます。まず共感しましょう。", "isCorrect": false}, {"text": "「おっしゃる通り、決して安くはないですよね。具体的にはどの点が気になりますか？」", "points": 30, "feedback": "共感してから明確化する、LSCPA法の正しい流れです。", "isCorrect": true}, {"text": "「では値引きしましょうか？」", "points": 5, "feedback": "真の懸念を確認せずに値引きすると、価値を下げてしまいます。", "isCorrect": false}], "situation": "顧客から「ちょっと高いですね...」と言われました。", "customerLine": "ちょっと高いですね..."}]', '{"question": "これまで反論を受けた時、どのような対応をしていましたか？改善点は？", "placeholder": "例: すぐに反論していた。まず共感することから始めたい"}', '["次に反論を受けたら、まず「おっしゃる通りですね」と共感する", "反論の背後にある「真の懸念」を質問で探る", "LSCPA法の5ステップを意識して対応する", "よくある反論への回答を事前に準備する"]', '{"title": "よくある反論をリストアップ", "fields": [{"label": "反論1と真の懸念", "placeholder": "例: 「高い」→価値が見えていない/予算がない"}, {"label": "反論2と真の懸念", "placeholder": "例: 「検討します」→決断が怖い/上司の承認が必要"}, {"label": "反論3と真の懸念", "placeholder": "例: 「今は必要ない」→緊急性を感じていない"}], "description": "自分がよく受ける反論を3つ挙げ、それぞれの「真の懸念」を考えてみましょう。"}', NULL, '2026-01-21 17:48:55.073331+00', '2026-01-21 17:48:55.073331+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (94, 66, '「高い」と言われた時の対処法', '価格ではなく価値で勝負する', '{"icon": "sparkles", "name": "価値伝道師"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["Close（クロージング）", "Clarify（明確化）", "Communicate（伝達）", "Control（制御）"], "question": "LSCPA法の「C」は何を表す？", "explanation": "CはClarify（明確化）です。顧客の真の懸念を質問で特定することが重要です。", "correctIndex": 1}', '{"part1": [{"title": "価格への不安", "content": "健太は再び商談に挑んだ。提案は順調に進んだが...\n\n顧客「なるほど、良さそうですね。\nただ、正直この価格はちょっと高いかな...」\n\n健太（心の声）「また『高い』と言われた...\nでも今回はLSCPA法を使ってみよう」\n\n健太「おっしゃる通り、決して安くはないですよね」\n\n顧客「え？そう思います？」"}, {"title": "真意を探る", "content": "健太「ちなみに、『高い』というのは\n何と比較してのご印象でしょうか？」\n\n顧客「うーん...競合のA社は20%くらい安かったかな」\n\n健太「なるほど、A社様との比較ですね。\n価格差の理由をご説明してもよろしいですか？」\n\n健太は「高い」の背後にある真意を探ることができた。\n単なる価格交渉ではなく、競合比較が原因だったのだ。"}], "part2": [{"title": "価値で説明する", "content": "健太「A社様との違いは、導入後のサポート体制です。\n弊社は24時間対応で、専任担当がつきます。\n\n3年間のトータルコストで計算すると、\n実は弊社の方がお得になるケースが多いんです」\n\n顧客「なるほど...トータルで考えると違うのか」\n\n健太「はい。価格だけでなく、\n御社の課題解決にどちらが貢献できるか、\nという視点でご検討いただければ嬉しいです」"}]}', '{"title": "「高い」の3つの意味と対応", "content": "1. 予算がない → 支払い条件の調整、分割、スコープ縮小\n2. 価値が見えない → ROI説明、事例、TCO比較\n3. 交渉のポーズ → 価値を再度訴求、条件付き譲歩", "audioText": "高いと言われたら、まず真意を確認。予算、価値、交渉のどれかを見極めて対応します。", "highlight": "「何と比較しての印象でしょうか？」で真意を探る"}', '[{"options": ["すぐに値引きを提案する", "競合の悪口を言う", "真意を確認する質問をする", "諦めて引き下がる"], "question": "「高い」と言われた時、最初にすべきことは？", "explanation": "まず「何と比較しての印象でしょうか？」など、真意を確認する質問が重要です。", "correctIndex": 2}]', '{"text": "価格で負ける営業は、価値を伝えきれていないだけだ。", "author": "営業の格言", "textJa": "価格で負ける営業は、価値を伝えきれていないだけだ。"}', '[{"options": [{"text": "「では20%値引きします」", "points": 5, "feedback": "すぐに値引きすると利益が大幅に減少します。他の選択肢を探りましょう。", "isCorrect": false}, {"text": "「ご予算はどのくらいでしょうか？その範囲で実現できる方法を一緒に考えませんか」", "points": 30, "feedback": "予算を確認し、スコープ調整や支払い条件で対応する姿勢が良いです。", "isCorrect": true}, {"text": "「この価格が限界です」", "points": 0, "feedback": "対話を閉ざしてしまいます。代替案を一緒に考える姿勢が重要です。", "isCorrect": false}], "situation": "顧客：「正直、この価格だと予算オーバーなんですよね...」", "customerLine": "正直、この価格だと予算オーバーなんですよね..."}]', '{"question": "「高い」と言われた時、これまでどう対応していましたか？", "placeholder": "例: すぐに値引きを提案していた。価値訴求を強化したい"}', '["「何と比較しての印象でしょうか？」と質問する習慣をつける", "ROI計算書を準備して、投資対効果を見える化する", "TCO（総所有コスト）で比較する資料を作る", "値引きの代わりに、付加価値の追加を提案する"]', '{"title": "価値訴求のトーク準備", "fields": [{"label": "製品価格", "placeholder": "例: 月額10万円"}, {"label": "顧客が得られる価値（数字で）", "placeholder": "例: 月20時間の業務削減、人件費換算で月30万円相当"}, {"label": "ROI説明トーク", "placeholder": "例: 初期投資は○○ですが、3ヶ月で元が取れます"}], "description": "自社製品の価値を、ROIや具体的数字で説明するトークを準備しましょう。"}', NULL, '2026-01-21 17:48:55.634201+00', '2026-01-21 17:48:55.634201+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (95, 67, '「検討します」を突破する技術', '曖昧な約束を具体的なコミットメントに', '{"icon": "target", "name": "コミットメントハンター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["すぐに値引きを提案する", "競合の悪口を言う", "真意を確認する質問をする", "諦めて引き下がる"], "question": "「高い」と言われた時、最初にすべきことは？", "explanation": "まず「何と比較しての印象でしょうか？」など、真意を確認する質問が重要です。", "correctIndex": 2}', '{"part1": [{"title": "「検討します」の壁", "content": "健太「今日も『検討します』で終わりました...\nその後連絡しても『まだ検討中です』って...」\n\n山本「『検討します』で帰ってきたら、それは負けだ」\n\n健太「え？でも、検討してくれるって...」\n\n山本「『検討します』は『やんわり断りたい』『決断を先延ばししたい』\nという意味かもしれない。\n曖昧な返事を具体的な約束に変えないと、案件は進まないぞ」"}, {"title": "具体化の技術", "content": "山本「『検討します』と言われたら、こう聞け」\n\n・「何を検討されますか？」\n・「いつ頃までにご判断されますか？」\n・「他にご確認が必要な点はありますか？」\n\n山本「そして必ず『次のアクション』を約束して帰る。\n『来週水曜日にお電話します』とか\n『金曜日にご回答いただけますか』とかな」\n\n健太「なるほど、具体的な約束を取り付けるんですね」"}], "part2": [{"title": "二者択一法", "content": "山本「もう一つ、『二者択一法』も有効だ」\n\n健太「二者択一？」\n\n山本「『来週お電話していいですか？』と聞くと、\n『忙しいから...』と断られやすい。\n\nでも『来週の火曜日と木曜日、どちらがご都合いいですか？』\nと聞けば、どちらかを選んでくれる」\n\n健太「Yes/Noじゃなくて、A or Bで聞くんですね」"}]}', '{"title": "「検討します」への対応", "content": "1. 真意を確認「何が気になりますか？」\n2. 期限を設定「いつ頃までに？」\n3. 次のアクション「○日に改めてご連絡します」\n4. 障壁を特定「他にご確認が必要な点は？」", "audioText": "検討しますと言われたら、何を、いつまでに、誰と検討するかを明確にしましょう。", "highlight": "必ず「次のアクション」を約束して帰る"}', '[{"options": ["「わかりました」と引き下がる", "何度もしつこく確認する", "具体的な検討内容と期限を確認する", "すぐに値引きを提案する"], "question": "「検討します」と言われた時の適切な対応は？", "explanation": "「何を」「いつまでに」検討するのか、具体的に確認することが重要です。", "correctIndex": 2}]', '{"text": "曖昧な約束は、約束ではない。", "author": "営業の格言", "textJa": "曖昧な約束は、約束ではない。具体的な次のステップを握れ。"}', '[{"options": [{"text": "「わかりました。お待ちしています」", "points": 5, "feedback": "これでは主導権を顧客に渡してしまいます。具体的な約束を取り付けましょう。", "isCorrect": false}, {"text": "「ありがとうございます。いつ頃社内でお話しされますか？私からも○日にご連絡させてください」", "points": 30, "feedback": "期限と次のアクションを明確にした良い対応です。", "isCorrect": true}, {"text": "「検討しないで今日決めてください」", "points": 0, "feedback": "押し付けは逆効果です。顧客のプロセスを尊重しつつ、具体化しましょう。", "isCorrect": false}], "situation": "顧客：「社内で検討して、また連絡しますね」", "customerLine": "社内で検討して、また連絡しますね"}]', '{"question": "「検討します」で終わった商談を思い出し、何ができたか考えてみましょう。", "placeholder": "例: 具体的な期限を確認せずに帰ってきてしまった"}', '["「いつまでにご判断されますか」と必ず聞く", "「次回は○日にご連絡します」と自分からアクションを設定する", "「他にご確認が必要な点は？」と追加の懸念を探る", "二者択一法で選びやすくする「火曜と木曜どちらがいいですか」"]', '{"title": "「検討します」への切り返し準備", "fields": [{"label": "「社内で検討します」への返答", "placeholder": "例: いつ頃、どなたとご相談されますか？"}, {"label": "「資料を見て検討します」への返答", "placeholder": "例: ご質問にお答えする機会をいただけますか？"}, {"label": "「他社も見て検討します」への返答", "placeholder": "例: 比較のポイントを教えていただけますか？"}], "description": "パターン別の切り返しトークを準備しましょう。"}', NULL, '2026-01-21 17:48:56.325546+00', '2026-01-21 17:48:56.325546+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (96, 68, '「他社と比較したい」への対応', '比較の軸をコントロールせよ', '{"icon": "eye", "name": "差別化マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["わかりましたと引き下がる", "しつこく確認する", "具体的な検討内容と期限を確認する", "すぐに値引きを提案する"], "question": "「検討します」と言われた時の適切な対応は？", "explanation": "「何を」「いつまでに」検討するのか、具体的に確認することが重要です。", "correctIndex": 2}', '{"part1": [{"title": "競合との戦い", "content": "顧客「良いお話でした。ただ、A社さんの提案も聞いてから決めたいんです」\n\n健太（心の声）「また競合か...負けるかも」\n\n山本「競合比較と言われて落ち込んでるな。\nでもそれは良いサインだぞ」\n\n健太「え？競合に取られるかもしれないのに？」\n\n山本「比較するってことは、買う気があるってことだ。\n買う気がなければ、比較なんてしない」"}, {"title": "比較軸をコントロール", "content": "山本「大事なのは『何で比較するか』だ。\n価格だけで比較されたら負けるかもしれないが、\nサポート体制や導入実績で比較されたら勝てるだろ？」\n\n健太「比較の軸を自分で提案するんですか？」\n\n山本「そうだ。『比較される時は、\nぜひこの3点もご確認ください』と伝える。\n自社が強い部分で比較してもらうんだ」"}], "part2": [{"title": "競合を批判しない", "content": "山本「あと、絶対に競合の悪口は言うなよ」\n\n健太「でも、弱点を指摘すれば...」\n\n山本「逆効果だ。品位を疑われるし、\n顧客がその競合を擁護し始めることもある。\n\n代わりに『A社さんは確かに良い製品ですね。\nただ弊社は○○に特に強みがあります』と言え。\n褒めてから差別化する」"}]}', '{"title": "競合比較への対応", "content": "1. 比較を歓迎「ぜひ比較してください」\n2. 軸を提案「この3点で比較されると良いですよ」\n3. 差別化を強調「弊社の強みは○○です」\n4. フォロー継続「検討中も情報提供します」", "audioText": "競合比較は購入意思の表れ。比較の軸を自社有利な方向にコントロールしましょう。", "highlight": "比較の「軸」をコントロールする"}', '[{"options": ["競合の悪口を言う", "比較を歓迎し、自社有利な比較軸を提案する", "比較しないよう説得する", "諦めて引き下がる"], "question": "競合比較を求められた時の適切な対応は？", "explanation": "比較を歓迎しつつ、自社に有利な比較軸（サポート、実績など）を提案します。", "correctIndex": 1}]', '{"text": "敵を知り己を知れば百戦殆からず。", "author": "孫子", "textJa": "敵を知り己を知れば百戦殆からず。競合を研究し、差別化せよ。"}', '[{"options": [{"text": "「A社はサポートが悪いと聞きますよ」", "points": 0, "feedback": "競合の悪口は逆効果。信頼を失います。", "isCorrect": false}, {"text": "「もちろんです。比較の際は、導入後のサポート体制と実績も確認されることをお勧めします」", "points": 30, "feedback": "比較を歓迎しつつ、自社が強い軸を提案しています。", "isCorrect": true}, {"text": "「弊社だけで決めていただけませんか」", "points": 5, "feedback": "比較を避けようとすると、かえって不信感を招きます。", "isCorrect": false}], "situation": "顧客：「A社さんの提案も聞いてから決めたいんです」", "customerLine": "A社さんの提案も聞いてから決めたいんです"}]', '{"question": "競合に負けた経験を思い出し、何が決め手だったか分析してみましょう。", "placeholder": "例: 価格で負けた。価値訴求が足りなかった"}', '["主要競合3社の強み・弱みを調査する", "自社が勝てる比較軸を3つ明確にする", "競合から乗り換えた顧客の声を集める", "比較検討中の顧客に定期的にフォローする"]', '{"title": "競合比較表の作成", "fields": [{"label": "競合A社との違い", "placeholder": "例: 価格は同等だが、サポート対応時間が弊社は24時間"}, {"label": "競合B社との違い", "placeholder": "例: 機能は少ないが、導入実績が3倍"}, {"label": "自社の最大の強み", "placeholder": "例: 業界特化の専門知識とカスタマイズ対応力"}], "description": "主要競合との比較表を作成し、自社の強みを整理しましょう。"}', NULL, '2026-01-21 17:48:57.216594+00', '2026-01-21 17:48:57.216594+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (97, 69, '「今は必要ない」を覆す方法', '潜在ニーズを顕在化させる', '{"icon": "search", "name": "ニーズ発掘者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["競合の悪口を言う", "比較を歓迎し自社有利な比較軸を提案", "比較しないよう説得する", "諦めて引き下がる"], "question": "競合比較を求められた時の適切な対応は？", "explanation": "比較を歓迎しつつ、サポートや実績など自社に有利な比較軸を提案しましょう。", "correctIndex": 1}', '{"part1": [{"title": "困っていないと言われる", "content": "顧客「今のやり方で特に困っていないんですよね」\n\n健太（心の声）「困っていないなら、提案しても無駄かな...」\n\n山本「『困っていない』で引き下がったのか？」\n\n健太「はい...必要ないなら無理に売り込むべきじゃないと思って」\n\n山本「その姿勢は正しい。でもな、\n『困っていない』と『気づいていない』は違うぞ」"}, {"title": "気づいていないだけ", "content": "山本「顧客は自分の問題に気づいていないことが多い。\n今のやり方が『普通』だと思っているからな」\n\n健太「どうすれば気づいてもらえますか？」\n\n山本「質問するんだ。SPIN話法の示唆質問を使え。\n\n『今のやり方で、月どれくらい時間がかかっていますか？』\n『その時間、年間だと何日になりますか？』\n『その時間を他のことに使えたら、何をしますか？』\n\n数字で見せると、問題の大きさに気づくことがある」"}], "part2": [{"title": "長期的な視点", "content": "山本「ただし、本当に必要ないこともある。\nその場合は無理に売り込まない」\n\n健太「どう判断するんですか？」\n\n山本「質問して、一緒に考えて、\nそれでも必要なければ素直に引く。\nでも関係は維持しておけ。\n\n『状況が変わったらまたご連絡ください』と伝えて、\n半年後にフォローする。\n30%の案件は1年以内に再検討されるからな」"}]}', '{"title": "「今は必要ない」への対応", "content": "1. 現状の確認「今はどのように対応されていますか？」\n2. 影響の示唆「それによる影響はありますか？」\n3. 数字で見える化「年間だと○○時間/○○円になりますね」\n4. 緊急性の創出「今始めると○○のメリットが」", "audioText": "今は必要ないと言われたら、問題に気づいていないだけかもしれません。質問で潜在ニーズを引き出しましょう。", "highlight": "潜在ニーズを顕在化させる質問がカギ"}', '[{"options": ["諦めて帰る", "無理に売り込む", "質問で潜在的な問題を探る", "大幅値引きを提案する"], "question": "「今は困っていない」と言われた時の適切な対応は？", "explanation": "「困っていない」は「気づいていない」可能性があります。質問で潜在ニーズを探りましょう。", "correctIndex": 2}]', '{"text": "顧客は自分が何を必要としているか知らないことがある。", "author": "スティーブ・ジョブズ（意訳）", "textJa": "顧客は自分が何を必要としているか知らないことがある。"}', '[{"options": [{"text": "「そうですか、では失礼します」", "points": 5, "feedback": "潜在ニーズを探る機会を逃しています。もう少し質問してみましょう。", "isCorrect": false}, {"text": "「なるほど。ちなみに、今の方法でどれくらいの時間がかかっていますか？」", "points": 30, "feedback": "状況質問から始めて、問題を探る良いアプローチです。", "isCorrect": true}, {"text": "「絶対に必要ですよ！」", "points": 0, "feedback": "押し付けは逆効果です。顧客自身に気づいてもらうことが大切です。", "isCorrect": false}], "situation": "顧客：「今のやり方で特に困っていないんですよね」", "customerLine": "今のやり方で特に困っていないんですよね"}]', '{"question": "「必要ない」と言われて引き下がった案件で、本当に必要なかったのか振り返ってみましょう。", "placeholder": "例: もっと質問していれば、隠れた課題が見つかったかもしれない"}', '["SPIN話法の示唆質問を5つ準備する", "問題を数字で見える化する資料を作る", "「今始めるメリット」を明確にする", "長期的なフォロー計画を立てる"]', '{"title": "潜在ニーズを引き出す質問準備", "fields": [{"label": "状況質問", "placeholder": "例: 今はどのような方法で対応されていますか？"}, {"label": "問題質問", "placeholder": "例: その方法で困ることはありますか？"}, {"label": "示唆質問", "placeholder": "例: その作業時間を他のことに使えたら？"}], "description": "顧客が気づいていない問題を引き出す質問を準備しましょう。"}', NULL, '2026-01-21 17:48:58.014356+00', '2026-01-21 17:48:58.014356+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (98, 70, '「上に相談しないと」への対応', '決裁者へのアプローチを支援する', '{"icon": "users", "name": "決裁攻略者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["すぐに引き下がる", "潜在ニーズを探る質問をする", "値引きを提案する", "諦めて帰る"], "question": "「今は必要ない」と言われた時の対応で正しいのは？", "explanation": "潜在ニーズを探り、顧客が気づいていない課題を発見することが重要です。", "correctIndex": 1}', '{"part1": [{"title": "決裁者の壁", "content": "健太「いい感触だったのに、最後に『上に相談しないと』と言われました...」\n\n山本「それ、よくあるパターンだな。担当者は良いと思っても、決裁者がNOと言えば終わりだ」\n\n健太「でも、決裁者には会えないんです」\n\n山本「直接会えなくても、担当者を通じてアプローチする方法がある。担当者を\"社内営業マン\"にするんだ」"}, {"title": "社内営業を支援する", "content": "山本「担当者が上司を説得しやすい武器を渡せ」\n\n【決裁者攻略の3つの武器】\n\n1. 数字で語れる資料\n  「上司は数字が好きだ。ROIや削減額を一枚にまとめろ」\n\n2. 想定質問と回答集\n  「上司が聞きそうな質問とその回答を準備しておく」\n\n3. 他社の導入事例\n  「同業他社の事例があると、決裁者は安心する」\n\n山本「担当者に『これを見せれば大丈夫です』と言える資料を渡すんだ」"}], "part2": [{"title": "決裁者との接点を作る", "content": "山本「できれば決裁者に直接会う機会を作りたい」\n\n【決裁者へのアプローチ法】\n\n・経営者向けセミナーへの招待\n・業界レポートの持参（担当者経由で）\n・「ご挨拶だけでも」と短時間の面談依頼\n\n山本「いきなり売り込むんじゃない。まず関係を作れ。決裁者が『この人なら話を聞いてもいい』と思ってくれたら勝ちだ」\n\n健太「担当者だけでなく、決裁者も見据えて動くんですね」"}]}', '{"title": "決裁者攻略の3つの武器", "content": "1. 数字で語れる資料（ROI、削減額）\n2. 想定質問と回答集\n3. 他社の導入事例", "audioText": "決裁者に直接会えなくても、担当者に武器を渡せば社内で営業してくれます。", "highlight": "担当者を社内営業マンにする"}', '[{"options": ["値引き提案書", "決裁者を説得できる資料", "催促のメール", "競合比較表"], "question": "「上に相談しないと」と言われた時、渡すべきものは？", "explanation": "担当者が決裁者を説得できる「武器」を渡すことが重要です。", "correctIndex": 1}]', '{"text": "The key to success is to focus on goals, not obstacles.", "author": "不明", "textJa": "成功の鍵は、障害ではなく目標に集中することだ。"}', '[{"options": [{"text": "「ありがとうございます。お待ちしています」", "points": 10, "feedback": "待つだけでは不十分。支援を申し出ましょう。", "isCorrect": false}, {"text": "「ありがとうございます。上長様を説得しやすい資料をお作りしましょうか？」", "points": 30, "feedback": "担当者の社内営業を支援する良い対応です。", "isCorrect": true}, {"text": "「上長様に直接ご説明させてください」", "points": 5, "feedback": "いきなり決裁者へのアプローチは警戒されます。", "isCorrect": false}], "situation": "担当者から「上に相談します」と言われました。", "customerLine": "いい提案だと思うので、上に相談してみますね"}]', '{"question": "過去に「上に相談する」と言われて止まった案件を振り返り、何ができたか考えてみましょう。", "placeholder": "例: 決裁者向けの資料を用意していれば、話が進んだかもしれない"}', '["決裁者向けの1枚サマリーを作成する", "想定質問リストを10個作る", "同業他社の事例を3つ集める", "次回は「上長様のご関心事」を事前に聞く"]', '{"title": "決裁者向け資料の準備", "fields": [{"label": "ROI/効果の数字", "placeholder": "例: 年間500万円のコスト削減"}, {"label": "想定質問と回答", "placeholder": "例: Q.導入リスクは？ A.トライアル期間があります"}, {"label": "同業他社の事例", "placeholder": "例: 同業のA社様も導入済みで成果を出されています"}], "description": "担当者が決裁者を説得するための資料を準備しましょう。"}', NULL, '2026-01-21 17:48:58.78033+00', '2026-01-21 17:48:58.78033+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (99, 71, '価格交渉の原則', '値引きせずに合意を目指す', '{"icon": "badge-dollar-sign", "name": "価格交渉マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["ひたすら待つ", "担当者に決裁者を説得できる資料を渡す", "決裁者に直接電話する", "諦める"], "question": "「上に相談しないと」と言われた時の対応で正しいのは？", "explanation": "担当者を社内営業マンにするため、説得材料を渡すことが重要です。", "correctIndex": 1}', '{"part1": [{"title": "値引き要求の罠", "content": "顧客「もう少し安くならない？」\n\n健太「わかりました、10%引きでいかがでしょうか」\n\n顧客「うーん、もうちょっと...」\n\n健太「では15%で...」\n\n山本「おい健太、また値引きしたのか」\n\n健太「お客様が安くしてほしいと...」\n\n山本「値引きは最後の手段だ。簡単に応じると、価値を下げることになるぞ」"}, {"title": "価格交渉の4原則", "content": "山本「価格交渉には原則がある」\n\n【価格交渉の4原則】\n\n1. すぐに値引きしない\n  「値引きを要求されても、まず理由を聞け」\n\n2. 価値で勝負する\n  「価格ではなく、得られる価値を伝えろ」\n\n3. 条件を交換する\n  「値引きするなら、何かをもらえ。契約期間延長とか」\n\n4. 最終ラインを決めておく\n  「これ以上は下げられないという限界を事前に決めておけ」"}], "part2": [{"title": "価値を再確認させる", "content": "山本「値引き要求が来たら、まず価値を再確認させるんだ」\n\n【価値の再確認トーク】\n\n「ご予算のことは理解しました。\nただ、改めて確認させてください。\nこの投資で得られるのは...\n・年間○○時間の削減\n・○○万円のコスト削減\n・○○%の効率化\nこれらを考えると、むしろお得だと思いませんか？」\n\n山本「それでも値引きを求められたら、条件交換だ。何かをもらう代わりに値引きする」"}]}', '{"title": "価格交渉の4原則", "content": "1. すぐに値引きしない\n2. 価値で勝負する\n3. 条件を交換する\n4. 最終ラインを決めておく", "audioText": "安易な値引きは価値を下げます。まず価値で勝負し、条件交換を提案しましょう。", "highlight": "値引きせずに合意を目指す"}', '[{"options": ["すぐに応じる", "価値を再確認させる", "上司に相談する", "断る"], "question": "値引きを要求された時、最初にすべきことは？", "explanation": "まず価値を再確認させ、価格以上の価値があることを伝えましょう。", "correctIndex": 1}]', '{"text": "Price is what you pay. Value is what you get.", "author": "ウォーレン・バフェット", "textJa": "価格は支払うもの。価値は得るものだ。"}', '[{"options": [{"text": "「わかりました、10%引きでいかがでしょうか」", "points": 0, "feedback": "すぐに値引きすると価値を下げることになります。", "isCorrect": false}, {"text": "「ご予算のことは理解しました。改めて得られる価値を確認させてください」", "points": 30, "feedback": "価値を再確認させる良い対応です。", "isCorrect": true}, {"text": "「これ以上は無理です」", "points": 5, "feedback": "交渉の余地を完全に閉ざすのはNGです。", "isCorrect": false}], "situation": "顧客から「もう少し安くならない？」と言われました。", "customerLine": "いい提案だけど、もう少し安くならない？"}]', '{"question": "過去に値引きで後悔した経験はありますか？振り返ってみましょう。", "placeholder": "例: すぐに値引きしたら、もっと下げろと言われた"}', '["価値を数字で表現した資料を作る", "値引きの最終ラインを上司と決めておく", "条件交換のパターンを3つ用意する", "価格ではなく価値で説明する練習をする"]', '{"title": "価値の可視化", "fields": [{"label": "時間削減効果", "placeholder": "例: 月20時間の作業時間削減"}, {"label": "コスト削減効果", "placeholder": "例: 年間300万円のコスト削減"}, {"label": "その他の価値", "placeholder": "例: 従業員満足度向上、ミス削減"}], "description": "自社サービスの価値を数字で表現してみましょう。"}', NULL, '2026-01-21 17:49:00.206728+00', '2026-01-21 17:49:00.206728+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (100, 72, '競合プレゼン対策', '後出しで勝つ戦略', '{"icon": "target", "name": "競合攻略者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["すぐに値引きしない", "価値で勝負する", "すぐに最大の値引きを提示", "条件を交換する"], "question": "価格交渉の4原則で正しくないのは？", "explanation": "すぐに最大の値引きを提示すると、さらなる値引きを要求されます。", "correctIndex": 2}', '{"part1": [{"title": "競合との戦い", "content": "健太「競合も提案しているらしくて、比較されています...」\n\n山本「競合がいるのは普通のことだ。問題は、どう差別化するかだな」\n\n健太「価格で負けそうなんです...」\n\n山本「価格だけで比較されると厳しい。比較の軸を変えるんだ」"}, {"title": "比較軸を変える", "content": "山本「競合比較では、自社が有利な軸で比較させるのがコツだ」\n\n【比較軸を変えるポイント】\n\n・価格→トータルコスト（導入費+運用費+サポート費）\n・機能数→実際に使う機能の品質\n・導入実績→同業種での実績\n・会社規模→サポート体制\n\n山本「例えば『価格は高いですが、サポートは業界No.1です。トラブル時の対応を考えると、トータルでは安くなります』と伝える」"}], "part2": [{"title": "後出しの優位性", "content": "山本「プレゼンの順番も重要だ。できれば最後にプレゼンしたい」\n\n【後出しの優位性】\n\n・競合の提案内容を把握できる\n・顧客の反応や懸念を知った上で提案できる\n・最後の印象が残りやすい\n\n山本「もし先にプレゼンする場合は、競合が言いそうなことを先に潰しておけ。『他社さんは○○とおっしゃるかもしれませんが...』とな」"}]}', '{"title": "比較軸を変える戦略", "content": "価格→トータルコスト\n機能数→機能の品質\n導入実績→同業種実績\n会社規模→サポート体制", "audioText": "競合との比較では、自社が有利な軸で比較されるよう誘導することが重要です。", "highlight": "自社が有利な軸で比較させる"}', '[{"options": ["値引きする", "比較の軸を変える", "諦める", "競合の悪口を言う"], "question": "競合と価格で負けそうな時、どうすべき？", "explanation": "価格以外の軸（サポート、品質など）で比較されるよう誘導しましょう。", "correctIndex": 1}]', '{"text": "If you can''t win by the rules of the game, change the game.", "author": "ビジネス格言", "textJa": "ゲームのルールで勝てないなら、ゲームを変えろ。"}', '[{"options": [{"text": "「うちも値引きします」", "points": 0, "feedback": "価格競争に巻き込まれます。", "isCorrect": false}, {"text": "「価格だけでなく、トータルコストで比較してみてください。サポート費や運用コストを含めると...」", "points": 30, "feedback": "比較軸を変える良い対応です。", "isCorrect": true}, {"text": "「競合さんはサポートが悪いですよ」", "points": 0, "feedback": "競合の悪口は信頼を失います。", "isCorrect": false}], "situation": "顧客から「競合さんの方が安いんですが」と言われました。", "customerLine": "競合さんの方が安いんですが、どう違うんですか？"}]', '{"question": "競合に負けた経験を振り返り、何が原因だったか考えてみましょう。", "placeholder": "例: 価格だけで比較されてしまった。比較軸を変えるべきだった"}', '["競合との差別化ポイントを3つ明確にする", "比較軸を変えるトークを練習する", "トータルコスト比較の資料を作る", "競合情報を定期的に収集する"]', '{"title": "自社の差別化ポイント整理", "fields": [{"label": "自社が有利な比較軸", "placeholder": "例: サポート体制、導入実績、品質"}, {"label": "その軸での具体的な強み", "placeholder": "例: 24時間サポート、同業種100社導入"}, {"label": "比較軸を変えるトーク", "placeholder": "例: 価格だけでなくトータルコストで比較すると..."}], "description": "競合と比較した時の自社の強みを整理しましょう。"}', NULL, '2026-01-21 17:49:00.740397+00', '2026-01-21 17:49:00.740397+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (101, 73, '膠着状態の打開', '交渉のデッドロックを解消する', '{"icon": "unlock", "name": "交渉ブレイカー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["最初にプレゼンする", "最後にプレゼンする", "競合の悪口を言う", "価格を最安にする"], "question": "競合プレゼンで有利になるのは？", "explanation": "後出しなら競合の提案内容や顧客の懸念を把握した上で提案できます。", "correctIndex": 1}', '{"part1": [{"title": "動かない商談", "content": "健太「もう3ヶ月も検討中のままで、全然進みません...」\n\n山本「膠着状態か。何が原因だ？」\n\n健太「お客様は『良いと思う』と言うんですが、決断しないんです」\n\n山本「それは、決断しない理由があるんだ。その理由を見つけて、取り除く必要がある」"}, {"title": "膠着の原因を探る", "content": "山本「膠着状態にはパターンがある」\n\n【膠着の主な原因】\n\n1. 隠れた反対者がいる\n  →「他にご確認が必要な方はいらっしゃいますか？」\n\n2. 優先度が低い\n  →「他のプロジェクトと比べていかがですか？」\n\n3. リスクへの不安\n  →「ご不安な点は何でしょうか？」\n\n4. 比較検討中\n  →「他にご検討中のものはありますか？」\n\n山本「原因によって打ち手が変わる。まず原因を特定しろ」"}], "part2": [{"title": "デッドロック解消法", "content": "山本「膠着状態を打開する方法を教えよう」\n\n【デッドロック解消の4つの手法】\n\n1. 期限を設ける\n  「この特典は今月末までです」\n\n2. 小さなYESから始める\n  「まずはトライアルから始めませんか？」\n\n3. 第三者を入れる\n  「上司を連れてきて説明させてください」\n\n4. 条件を変える\n  「分割払いなら、いかがでしょうか？」\n\n山本「ただ待っていても状況は変わらない。何かアクションを起こせ」"}]}', '{"title": "デッドロック解消の4つの手法", "content": "1. 期限を設ける\n2. 小さなYESから始める\n3. 第三者を入れる\n4. 条件を変える", "audioText": "膠着状態を打開するには、原因を特定し、積極的にアクションを起こすことが重要です。", "highlight": "待っていても状況は変わらない"}', '[{"options": ["値引きを提案する", "原因を特定する", "諦める", "待つ"], "question": "商談が膠着状態になった時、最初にすべきことは？", "explanation": "まず膠着の原因を特定し、それに応じた打ち手を考えましょう。", "correctIndex": 1}]', '{"text": "In the middle of difficulty lies opportunity.", "author": "アルベルト・アインシュタイン", "textJa": "困難の中にこそ、機会がある。"}', '[{"options": [{"text": "「わかりました、お待ちしています」", "points": 0, "feedback": "待っていても状況は変わりません。", "isCorrect": false}, {"text": "「率直にお聞きしますが、決断を躊躇されている理由は何でしょうか？」", "points": 30, "feedback": "膠着の原因を探る良い質問です。", "isCorrect": true}, {"text": "「今月中に決めてもらわないと困ります」", "points": 5, "feedback": "押し付けは逆効果です。", "isCorrect": false}], "situation": "顧客が3ヶ月も「検討中」のままです。", "customerLine": "いい提案だと思うんですが、まだ検討中で..."}]', '{"question": "過去に膠着状態を打開できた経験、できなかった経験を振り返ってみましょう。", "placeholder": "例: トライアルを提案したら動いた / 待ち続けて結局失注した"}', '["膠着中の案件の原因を分析する", "期限付きの特典を提案する", "トライアルや分割など条件変更を提案する", "上司や専門家の同行を依頼する"]', '{"title": "膠着案件の分析", "fields": [{"label": "膠着している案件", "placeholder": "例: A社の○○案件"}, {"label": "想定される原因", "placeholder": "例: 隠れた反対者がいる可能性"}, {"label": "打開のアクション", "placeholder": "例: 他に確認が必要な方を聞いてみる"}], "description": "現在膠着している案件の原因と打ち手を考えましょう。"}', NULL, '2026-01-21 17:49:01.474459+00', '2026-01-21 17:49:01.474459+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (102, 74, '「NO」と言われた後の関係維持', '失注しても関係は続く', '{"icon": "handshake", "name": "リレーション維持者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["ひたすら待つ", "原因を特定してアクションを起こす", "諦めて撤退する", "毎日電話する"], "question": "膠着状態を打開する方法で適切なのは？", "explanation": "膠着の原因を特定し、それに応じた打ち手でアクションを起こしましょう。", "correctIndex": 1}', '{"part1": [{"title": "失注のショック", "content": "健太「3ヶ月かけた案件、結局失注しました...」\n\n山本「そうか。残念だったな。でも、これで終わりじゃない」\n\n健太「え？もう断られたんですよ」\n\n山本「今回は縁がなかっただけだ。関係を維持しておけば、次のチャンスが来る。失注後の対応こそが、営業の真価を問われるんだ」"}, {"title": "失注後の3原則", "content": "山本「失注後にやるべきことが3つある」\n\n【失注後の3原則】\n\n1. 理由を聞く\n  「今後の参考にさせてください。決め手は何でしたか？」\n\n2. 感謝を伝える\n  「検討いただきありがとうございました」\n\n3. 関係を維持する\n  「また何かあればお声がけください」\n\n山本「特に理由を聞くのは重要だ。次に活かせる学びがある」"}], "part2": [{"title": "長期的な関係構築", "content": "山本「失注した顧客とも、関係を維持する方法がある」\n\n【関係維持のアクション】\n\n・定期的な情報提供（売り込みではなく）\n・業界ニュースや役立つ記事のシェア\n・年賀状や季節の挨拶\n・セミナーや展示会への招待\n\n山本「大切なのは、売り込みではなく\"価値提供\"として接点を持つことだ。『この人は役に立つ』と思ってもらえれば、次の機会が来る」"}]}', '{"title": "失注後の3原則", "content": "1. 理由を聞く\n2. 感謝を伝える\n3. 関係を維持する", "audioText": "失注後も関係を維持することで、将来の案件につながる可能性があります。", "highlight": "失注しても関係は続く"}', '[{"options": ["すぐに次の顧客を探す", "理由を聞いて感謝を伝える", "競合の悪口を言う", "連絡を断つ"], "question": "失注後にまずすべきことは？", "explanation": "理由を聞いて学び、感謝を伝えることで関係維持につながります。", "correctIndex": 1}]', '{"text": "Every ending is a new beginning.", "author": "ことわざ", "textJa": "すべての終わりは、新しい始まりである。"}', '[{"options": [{"text": "「わかりました」と電話を切る", "points": 0, "feedback": "関係が途切れてしまいます。", "isCorrect": false}, {"text": "「ご検討いただきありがとうございました。今後の参考に、決め手を教えていただけますか？」", "points": 30, "feedback": "感謝を伝え、学びを得る良い対応です。", "isCorrect": true}, {"text": "「なぜですか？うちの方がいいのに」", "points": 0, "feedback": "押し付けは関係を悪化させます。", "isCorrect": false}], "situation": "顧客から「今回は他社さんに決めました」と言われました。", "customerLine": "今回は他社さんに決めました。すみません。"}]', '{"question": "失注後に関係を維持して、後日成約につながった経験はありますか？", "placeholder": "例: 半年後に競合のサポートに不満が出て、再度声がかかった"}', '["失注顧客リストを作成する", "定期的な情報提供の仕組みを作る", "失注理由を分析して改善に活かす", "半年後、1年後のフォロー予定をカレンダーに入れる"]', '{"title": "失注後のフォロープラン", "fields": [{"label": "失注した顧客", "placeholder": "例: A社 田中様"}, {"label": "失注理由（わかれば）", "placeholder": "例: 価格が合わなかった"}, {"label": "関係維持のアクション", "placeholder": "例: 四半期に1回、業界情報をメールで送る"}], "description": "失注した顧客との関係維持計画を立てましょう。"}', NULL, '2026-01-21 17:49:02.455868+00', '2026-01-21 17:49:02.455868+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (103, 75, 'DiSC理論による顧客タイプ分類', '相手のタイプを見極め、対応を変える', '{"icon": "eye", "name": "タイプ診断士"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["二度と連絡しない", "すぐに再提案する", "定期的に情報提供を続ける", "競合の悪口を言う"], "question": "失注後の関係維持として適切なのは？", "explanation": "売り込みではなく、価値ある情報提供として関係を維持することが重要です。", "correctIndex": 2}', '{"part1": [{"title": "同じトークなのに結果が違う", "content": "健太は不思議に思っていた。\n\n健太「先輩、同じトークをしてるのに、\nうまくいく人とそうでない人がいるんです...」\n\n山本「それは当然だな。人には\"タイプ\"があるんだ」\n\n健太「タイプ？」\n\n山本「DiSC理論って聞いたことあるか？\n人の行動特性を4つのタイプに分類したものだ。\n相手のタイプに合わせて対応を変えると、\nグッと成約率が上がる」", "duration": 30}, {"title": "DiSC理論とは", "content": "山本「DiSCは4つの行動特性の頭文字だ」\n\nD = Dominance（主導型）\n  → 結果重視、決断が速い、競争好き\n\ni = Influence（感化型）\n  → 社交的、楽観的、人間関係重視\n\nS = Steadiness（安定型）\n  → 協調的、慎重、変化を好まない\n\nC = Conscientiousness（慎重型）\n  → 分析的、正確さ重視、データ好き\n\n山本「人はこの4つのどれかが強く出る傾向がある。\n相手のタイプを見極めて、対応を変えるんだ」", "duration": 45}], "part2": [{"title": "タイプの見分け方", "content": "健太「どうやってタイプを見分けるんですか？」\n\n山本「話し方と関心事で見分けられる」\n\n【見分けるポイント】\n\nD型：話が早い、結論から聞きたがる、「で、いくら？」\ni型：雑談好き、表情豊か、「面白そう！」\nS型：穏やか、じっくり聞く、「皆さんはどうしてます？」\nC型：質問が多い、資料を読み込む、「根拠は？」\n\n山本「最初の5分の会話で、だいたいわかるようになる。\n今日から意識して観察してみろ」", "duration": 35}]}', '{"title": "DiSC理論の4タイプ", "content": "D（主導型）：結果重視、決断が速い\ni（感化型）：社交的、人間関係重視\nS（安定型）：協調的、変化を好まない\nC（慎重型）：分析的、データ重視", "audioText": "DiSC理論では人を4つのタイプに分類します。相手のタイプに合わせた対応が成約率を上げます。", "highlight": "相手のタイプを見極め、対応を変える"}', '[{"options": ["D（主導型）", "i（感化型）", "S（安定型）", "C（慎重型）"], "question": "「で、結論は？いくらなの？」と聞いてくる顧客のタイプは？", "explanation": "結論を急ぎ、決断が速いのはD（主導型）の特徴です。", "correctIndex": 0}]', '{"text": "Treat others the way they want to be treated.", "author": "プラチナルール", "textJa": "相手が望むように相手を扱え。"}', '[{"options": [{"text": "「では詳細な資料をお送りします」", "points": 10, "feedback": "i型には堅苦しい資料より、会話を続ける方が効果的です。", "isCorrect": false}, {"text": "「ありがとうございます！皆さんで一緒にご覧いただける機会を作りませんか？」", "points": 30, "feedback": "i型は人を巻き込むことが好き。その特性に合わせた提案です。", "isCorrect": true}, {"text": "「投資対効果を計算してお持ちします」", "points": 5, "feedback": "これはC型向けの対応です。i型にはもっと楽しさを伝えましょう。", "isCorrect": false}], "situation": "顧客が「面白そうだね！うちのスタッフにも紹介したいな」と言っています。", "customerLine": "面白そうだね！うちのスタッフにも紹介したいな"}]', '{"question": "自分自身は4つのタイプのうち、どれに近いと思いますか？", "placeholder": "例: i型に近い。人と話すのが好きで、細かい数字は苦手"}', '["次の商談で、顧客のタイプを観察する", "自分のタイプを把握し、苦手なタイプを意識する", "各タイプ別の対応トークを準備する", "同僚とお互いのタイプを確認し合う"]', '{"title": "顧客タイプの分析", "fields": [{"label": "顧客名（イニシャル可）", "placeholder": "例: A社 田中社長"}, {"label": "推測するタイプと根拠", "placeholder": "例: D型。話が早く、結論から聞きたがる"}, {"label": "次回の対応で意識すること", "placeholder": "例: 結論から伝え、選択肢を提示する"}], "description": "担当している顧客を思い浮かべ、DiSCタイプを推測してみましょう。"}', NULL, '2026-01-21 17:49:03.387286+00', '2026-01-21 17:49:03.387286+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (104, 76, '主導型（D）オーナーへの対応', '結論から、端的に、選択肢を', '{"icon": "flame", "name": "Dタイプマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["D（主導型）", "i（感化型）", "S（安定型）", "C（慎重型）"], "question": "DiSC理論で「結論から聞きたがる、決断が速い」のは何型？", "explanation": "D型（主導型）は結果重視で、スピーディーな意思決定を好みます。", "correctIndex": 0}', '{"part1": [{"title": "せっかちな社長", "content": "健太は大手企業の社長との商談に臨んだ。\n\n社長「で、何の用？手短にね」\n\n健太「はい、弊社の製品についてご説明を...\nまず会社概要からですが—」\n\n社長「会社概要はいいから。で、何ができるの？\nいくらなの？うちに何のメリットがあるの？」\n\n健太「え、えっと...順番にご説明しますと...」\n\n社長「（時計を見る）...もういいよ、忙しいから」", "duration": 30}, {"title": "D型への対応法", "content": "山本「D型の特徴は\"結果志向\"と\"効率重視\"だ。\n回りくどい説明は嫌われる」\n\n【D型への対応ポイント】\n\n1. 結論から話す\n  ×「まず背景からご説明すると...」\n  ○「結論から申し上げます。○○です」\n\n2. 端的に、要点だけ\n  ×「様々な機能がございまして...」\n  ○「主なメリットは3点です」\n\n3. 選択肢を提示して選ばせる\n  ×「いかがでしょうか？」\n  ○「AとB、どちらがよろしいですか？」\n\n4. 決断を急かさない（自分で決めたい）\n  ×「今日決めてください」\n  ○「ご判断材料は揃いましたでしょうか」", "duration": 45}], "part2": [{"title": "リベンジ商談", "content": "健太「社長、お時間いただきありがとうございます。\n結論から申し上げます。\n\n弊社サービスで、御社の○○コストを\n年間500万円削減できます。\n\nメリットは3点。\n1. コスト削減\n2. 業務効率化\n3. 競合優位性\n\n投資額は300万円。2年で回収できます。\nAプランとBプラン、どちらをご検討されますか？」\n\n社長「...ほう、わかりやすいな。Aプランについて詳しく」\n\n健太「（心の声）話を聞いてもらえた！」", "duration": 35}]}', '{"title": "D型（主導型）への対応", "content": "特徴：結果志向、効率重視、競争好き\nNG：回りくどい説明、曖昧な表現\nOK：結論から、端的に、選択肢を提示\n決断：自分で決めたいので選ばせる", "audioText": "D型には結論から話し、端的に要点を伝え、選択肢を提示して選ばせることがポイントです。", "highlight": "結論から、端的に、選択肢を"}', '[{"options": ["会社概要の説明", "結論とメリット", "詳細な背景説明", "世間話"], "question": "D型の社長に最初に言うべきことは？", "explanation": "D型は効率重視。まず結論とメリットを伝えましょう。", "correctIndex": 1}]', '{"text": "Time is money.", "author": "ベンジャミン・フランクリン", "textJa": "時は金なり。"}', '[{"options": [{"text": "「価格の前に、まず機能をご説明させてください」", "points": 0, "feedback": "D型は回りくどいのを嫌います。質問には直接答えましょう。", "isCorrect": false}, {"text": "「300万円です。2年で回収できます」", "points": 30, "feedback": "端的に価格と投資回収を伝えた良い対応です。", "isCorrect": true}, {"text": "「お見積りを後日お送りします」", "points": 5, "feedback": "D型はその場で判断したい。今答えられることは今答えましょう。", "isCorrect": false}], "situation": "D型の社長から「で、いくらなの？」と聞かれました。", "customerLine": "で、いくらなの？"}]', '{"question": "あなたの担当顧客でD型と思われる人はいますか？どう対応を変えますか？", "placeholder": "例: ○○社長がD型。次回は結論から話すようにする"}', '["D型顧客向けの1分エレベーターピッチを作る", "結論→理由→詳細の順で話す練習をする", "選択肢を2〜3つ用意して商談に臨む", "要点を箇条書きにした1枚資料を準備する"]', '{"title": "D型向けトークの準備", "fields": [{"label": "結論（一言で）", "placeholder": "例: 年間500万円のコスト削減ができます"}, {"label": "メリット3点", "placeholder": "例: 1.コスト削減 2.効率化 3.競合優位"}, {"label": "選択肢の提示", "placeholder": "例: AプランとBプラン、どちらがよろしいですか？"}], "description": "D型顧客向けに、結論から伝えるトークを準備しましょう。"}', NULL, '2026-01-21 17:49:04.106504+00', '2026-01-21 17:49:04.106504+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (105, 77, '感化型（i）オーナーへの対応', '関係性を築き、ビジョンを共有する', '{"icon": "sparkles", "name": "iタイプマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["詳細な背景説明から始める", "結論から端的に伝える", "雑談を長めにする", "資料を読み込む時間を与える"], "question": "D型への対応で正しいのは？", "explanation": "D型は効率重視。結論から端的に伝えることがポイントです。", "correctIndex": 1}', '{"part1": [{"title": "話好きな社長", "content": "健太はi型と思われる社長との商談に臨んだ。\n\n社長「いやー、最近ゴルフ始めてさ！」\n\n健太「（心の声）早く本題に入らないと...」\n健太「あ、そうですか。では本題に入らせていただいて...」\n\n社長「え、もう？まあいいけど...（つまらなそう）」\n\n商談は進んだが、社長の反応は薄かった。\n\n社長「まあ、検討しとくよ」\n健太「（心の声）なんか手応えがなかったな...」", "duration": 30}, {"title": "i型への対応法", "content": "山本「i型の特徴は\"人間関係重視\"と\"楽しさ優先\"だ。\nいきなり本題に入ると、冷めてしまう」\n\n【i型への対応ポイント】\n\n1. 雑談を大切にする\n  ×「では早速本題に...」\n  ○「ゴルフいいですね！どちらでプレーされるんですか？」\n\n2. ビジョンを共有する\n  ×「コスト削減できます」\n  ○「御社がもっと輝く未来を一緒に作りたいんです」\n\n3. 褒める、認める\n  ○「さすがですね」「素晴らしいご判断です」\n\n4. 人を巻き込む提案\n  ○「スタッフの皆さんにも喜ばれると思います」", "duration": 45}], "part2": [{"title": "関係性を築く商談", "content": "健太「社長、ゴルフ始められたんですね！\nどちらのコースでプレーされるんですか？」\n\n社長「○○カントリーだよ！先週初めて100切ったんだ」\n\n健太「100切り！すごいですね、始めたばかりで！」\n\n社長「いやー、まだまだだけどね（嬉しそう）」\n\n（15分後）\n\n社長「で、今日は何の話だっけ？」\n\n健太「はい、御社がさらに発展されるための\nお手伝いができればと思いまして。\nスタッフの皆さんにも喜んでいただける\nサービスなんです」\n\n社長「へえ、面白そうだね！詳しく聞かせて」", "duration": 40}]}', '{"title": "i型（感化型）への対応", "content": "特徴：社交的、楽観的、人間関係重視\nNG：いきなり本題、数字ばかり、堅苦しい\nOK：雑談、ビジョン共有、褒める、巻き込む\n決断：楽しそう、面白そうで動く", "audioText": "i型には雑談を大切にし、関係性を築いてからビジョンを共有することがポイントです。", "highlight": "関係性を築き、ビジョンを共有する"}', '[{"options": ["早く本題に戻す", "一緒に楽しんで関係性を築く", "資料を見せる", "黙って聞く"], "question": "i型の社長が雑談を始めたら？", "explanation": "i型は人間関係重視。雑談を通じて関係性を築くことが大切です。", "correctIndex": 1}]', '{"text": "People don''t care how much you know until they know how much you care.", "author": "セオドア・ルーズベルト", "textJa": "人は、あなたがどれだけ気にかけているかを知るまで、あなたがどれだけ知っているかには関心を持たない。"}', '[{"options": [{"text": "「はい、忙しいです。では本題に入らせてください」", "points": 0, "feedback": "i型との雑談を切り上げると関係性が築けません。", "isCorrect": false}, {"text": "「おかげさまで！社長こそお忙しいでしょう？最近何かいいことありました？」", "points": 30, "feedback": "雑談を楽しみ、相手に関心を示す良い対応です。", "isCorrect": true}, {"text": "「まあまあです」で終わる", "points": 5, "feedback": "会話が続きません。相手に質問を返しましょう。", "isCorrect": false}], "situation": "i型の社長から「最近どう？忙しい？」と聞かれました。", "customerLine": "最近どう？忙しい？"}]', '{"question": "あなたの担当顧客でi型と思われる人はいますか？どう対応を変えますか？", "placeholder": "例: ○○社長がi型。次回は雑談を楽しんでから本題に入る"}', '["i型顧客の趣味や関心事を事前にリサーチする", "雑談のネタを3つ準備して商談に臨む", "ビジョンを語るトークを練習する", "「面白そう」「楽しそう」と思わせる提案を考える"]', '{"title": "i型向けトークの準備", "fields": [{"label": "アイスブレイクの話題", "placeholder": "例: 趣味、最近の出来事、お店の様子など"}, {"label": "ビジョン共有トーク", "placeholder": "例: 御社がさらに輝く未来を一緒に作りたいんです"}, {"label": "巻き込む提案", "placeholder": "例: スタッフの皆さんにも喜んでいただけます"}], "description": "i型顧客向けに、関係性を築くトークを準備しましょう。"}', NULL, '2026-01-21 17:49:04.807031+00', '2026-01-21 17:49:04.807031+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (106, 78, '安定型（S）オーナーへの対応', '安心感を与え、ゆっくり寄り添う', '{"icon": "shield", "name": "Sタイプマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["結論から端的に", "雑談を大切にし関係性を築く", "データと根拠を示す", "検討時間を十分に与える"], "question": "i型への対応で正しいのは？", "explanation": "i型は人間関係重視。雑談を通じて関係性を築くことが大切です。", "correctIndex": 1}', '{"part1": [{"title": "慎重な店長", "content": "健太はS型と思われる店長との商談に臨んだ。\n\n健太「このシステム、本当にオススメなんです！\n今月中にご決断いただければ特典もあります！」\n\n店長「うーん...今のやり方で困ってないしなあ...」\n\n健太「でも、導入すればもっと良くなりますよ！」\n\n店長「急に言われても...他の人はどうしてるの？」\n\n健太「他の人より、御社に合うかどうかが大事です！」\n\n店長「...ちょっと考えさせて」\n\n健太「（心の声）なんでダメなんだ...」", "duration": 30}, {"title": "S型への対応法", "content": "山本「S型の特徴は\"安定志向\"と\"協調性\"だ。\n変化を押し付けると引いてしまう」\n\n【S型への対応ポイント】\n\n1. 急かさない、ゆっくり\n  ×「今月中に！」\n  ○「ご納得いくまでお時間かけてください」\n\n2. 他社事例を伝える\n  ×「御社に合うかが大事」\n  ○「同業の○○さんもご利用されてます」\n\n3. リスクを最小化\n  ○「サポート体制は万全です」\n  ○「トライアル期間があります」\n\n4. 寄り添う姿勢\n  ○「一緒に考えていきましょう」\n  ○「ご不安な点は何でもおっしゃってください」", "duration": 45}], "part2": [{"title": "安心感を与える商談", "content": "健太「店長、今のやり方で大きく困ってはいらっしゃらないんですよね。\n急ぐ必要は全くありません」\n\n店長「うん...でも気になる部分もあって」\n\n健太「どんな点が気になりますか？」\n\n店長「スタッフが使いこなせるかな...」\n\n健太「ご安心ください。同業の○○店さんも\n最初は同じご心配でしたが、今では全員使いこなしてます。\n導入後3ヶ月は専任サポートがつきますし、\nまずは1ヶ月のトライアルもできます」\n\n店長「トライアルがあるなら...試してみようかな」", "duration": 35}]}', '{"title": "S型（安定型）への対応", "content": "特徴：協調的、慎重、変化を好まない\nNG：急かす、変化を押し付ける、圧をかける\nOK：ゆっくり、他社事例、サポート、寄り添い\n決断：安心できたら動く", "audioText": "S型には急かさず、安心感を与えて、ゆっくり寄り添うことがポイントです。", "highlight": "安心感を与え、ゆっくり寄り添う"}', '[{"options": ["今月中の特典を強調", "他社事例とサポート体制を伝える", "競合との差を強調", "決断を迫る"], "question": "S型の店長への効果的なアプローチは？", "explanation": "S型は安心感を重視。他社事例やサポート体制が効果的です。", "correctIndex": 1}]', '{"text": "People don''t resist change. They resist being changed.", "author": "ピーター・センゲ", "textJa": "人は変化に抵抗するのではない。変えられることに抵抗するのだ。"}', '[{"options": [{"text": "「他店より御社のことを考えましょう」", "points": 5, "feedback": "S型は他者の動向が気になります。事例を伝えましょう。", "isCorrect": false}, {"text": "「同業の○○店さんも導入されて、スタッフさんに好評だそうです」", "points": 30, "feedback": "他社事例を伝えて安心感を与える良い対応です。", "isCorrect": true}, {"text": "「皆さん導入されてますよ、早く決めないと遅れますよ」", "points": 0, "feedback": "急かすとS型は引いてしまいます。", "isCorrect": false}], "situation": "S型の店長から「他のお店はどうしてるの？」と聞かれました。", "customerLine": "他のお店はどうしてるの？"}]', '{"question": "あなたの担当顧客でS型と思われる人はいますか？どう対応を変えますか？", "placeholder": "例: ○○店長がS型。次回は急かさずゆっくり説明する"}', '["S型顧客には「急ぎません」と伝える", "他社事例を3つ以上準備する", "サポート体制を詳しく説明できるようにする", "トライアルや段階的導入を提案する"]', '{"title": "S型向けトークの準備", "fields": [{"label": "他社事例", "placeholder": "例: 同業の○○店さんも導入されています"}, {"label": "サポート体制", "placeholder": "例: 導入後3ヶ月は専任サポートがつきます"}, {"label": "リスク軽減の提案", "placeholder": "例: まずは1ヶ月のトライアルから始められます"}], "description": "S型顧客向けに、安心感を与えるトークを準備しましょう。"}', NULL, '2026-01-21 17:49:05.506678+00', '2026-01-21 17:49:05.506678+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (107, 79, '慎重型（C）オーナーへの対応', 'データと根拠で論理的に説得', '{"icon": "search", "name": "Cタイプマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["結論から端的に", "今月中の特典を強調", "安心感を与えゆっくり寄り添う", "ビジョンを共有"], "question": "S型への対応で正しいのは？", "explanation": "S型は安定志向。急かさず、安心感を与えて寄り添うことが大切です。", "correctIndex": 2}', '{"part1": [{"title": "質問が多い社長", "content": "健太はC型と思われる社長との商談に臨んだ。\n\n社長「この数字の根拠は？」\n\n健太「えーと、だいたいこれくらいです」\n\n社長「\"だいたい\"？具体的な計算式は？」\n\n健太「実績ベースで...」\n\n社長「実績のサンプル数は？統計的な有意性は？」\n\n健太「え...ちょっと今は...」\n\n社長「データがないと判断できないな」\n\n健太「（心の声）質問攻めだ...」", "duration": 30}, {"title": "C型への対応法", "content": "山本「C型の特徴は\"分析的\"と\"正確さ重視\"だ。\n曖昧な説明は信用されない」\n\n【C型への対応ポイント】\n\n1. データと根拠を示す\n  ×「だいたい」「たぶん」\n  ○「○○のデータによると、具体的には...」\n\n2. 詳細な資料を用意\n  ○ 計算式、グラフ、出典を明記\n\n3. 質問には正確に答える\n  ×「わかりません」で終わる\n  ○「確認して○日までにご回答します」\n\n4. 検討時間を与える\n  ○「資料をお持ち帰りいただき、ご検討ください」", "duration": 45}], "part2": [{"title": "データで説得する商談", "content": "健太「社長、前回のご質問についてお答えします。\n\nコスト削減効果の根拠は、\n導入企業50社の実績データです。\n（グラフを見せる）\n\n平均削減率は23.5%、\n95%信頼区間で18〜29%となっています。\n計算式と出典はこちらの資料に記載しています」\n\n社長「...ほう、ちゃんと調べてきたな」\n\n健太「御社の場合のシミュレーションも作成しました。\nお持ち帰りいただき、ご検討ください」\n\n社長「わかった。来週また話を聞こう」", "duration": 35}]}', '{"title": "C型（慎重型）への対応", "content": "特徴：分析的、正確さ重視、データ好き\nNG：曖昧な表現、感覚的な説明、根拠なし\nOK：データ、計算式、出典、詳細資料\n決断：論理的に納得できたら動く", "audioText": "C型にはデータと根拠を示し、詳細な資料で論理的に説得することがポイントです。", "highlight": "データと根拠で論理的に説得"}', '[{"options": ["ビジョンを熱く語る", "他社事例を伝える", "データと計算根拠を示す", "今すぐ決断を迫る"], "question": "C型の社長への効果的なアプローチは？", "explanation": "C型は分析的で正確さ重視。データと根拠が効果的です。", "correctIndex": 2}]', '{"text": "In God we trust; all others must bring data.", "author": "W・エドワーズ・デミング", "textJa": "神は信じる。それ以外はデータを持ってこい。"}', '[{"options": [{"text": "「経験上、だいたいこれくらいです」", "points": 0, "feedback": "C型に曖昧な説明はNG。具体的な根拠が必要です。", "isCorrect": false}, {"text": "「導入50社の実績データから算出しています。詳細はこちらの資料をご覧ください」", "points": 30, "feedback": "データと根拠を示した良い対応です。", "isCorrect": true}, {"text": "「皆さんそうおっしゃいます」", "points": 5, "feedback": "C型は他人の意見より客観的データを重視します。", "isCorrect": false}], "situation": "C型の社長から「この効果の計算根拠は？」と聞かれました。", "customerLine": "この効果の計算根拠は？"}]', '{"question": "あなたの担当顧客でC型と思われる人はいますか？どう対応を変えますか？", "placeholder": "例: ○○社長がC型。次回はデータと計算根拠を準備していく"}', '["効果の計算根拠を明確にした資料を作る", "導入企業の実績データを収集する", "質問リストを想定して回答を準備する", "「確認してご回答します」の姿勢を持つ"]', '{"title": "C型向け資料の準備", "fields": [{"label": "効果の数値と根拠", "placeholder": "例: 削減率23.5%（導入50社の実績データより）"}, {"label": "計算式・シミュレーション", "placeholder": "例: 御社の場合、年間○○円×削減率○%=○○円"}, {"label": "出典・参考資料", "placeholder": "例: ○○調査レポート2024年版より"}], "description": "C型顧客向けに、データと根拠を整理しましょう。"}', NULL, '2026-01-21 17:49:06.0394+00', '2026-01-21 17:49:06.0394+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (108, 80, '世代別コミュニケーション', '敬意と経験への尊重を示す', '{"icon": "medal", "name": "ベテラン対応マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["熱意で押す", "データと根拠を示す", "雑談を大切に", "急かして決断を迫る"], "question": "C型への対応で正しいのは？", "explanation": "C型は分析的で正確さ重視。データと根拠が効果的です。", "correctIndex": 1}', '{"part1": [{"title": "ベテラン経営者との溝", "content": "健太は60代のベテラン経営者との商談に臨んだ。\n\n健太「社長、このDXツールで業務効率化できます！\nクラウドでデータを一元管理して...」\n\n社長「ディーエックス？クラウド？\n何を言ってるかわからんな」\n\n健太「えっと、つまりパソコンで...」\n\n社長「うちは30年やってきた。今のやり方で十分だ。\n若い人の言うことはよくわからん」\n\n健太「（心の声）世代が違うと話が通じない...」"}, {"title": "ベテラン経営者への対応法", "content": "山本「ベテラン経営者には、まず敬意を示すことが大事だ。\nカタカナ用語も避けた方がいい」\n\n【ベテラン経営者への対応ポイント】\n\n1. 敬意と経験への尊重\n  ○「30年のご経験、素晴らしいですね」\n  ○「長年培われたノウハウは財産です」\n\n2. カタカナ用語を避ける\n  ×「DX」「クラウド」「IoT」\n  ○「事務作業の手間を減らす」「情報を一か所にまとめる」\n\n3. 変化ではなく「強化」として提案\n  ×「やり方を変えましょう」\n  ○「今のやり方をもっと楽にする方法があります」\n\n4. 若者の立場を活かす\n  ○「教えていただけますか」（学ぶ姿勢）"}], "part2": [{"title": "敬意を示す商談", "content": "健太「社長、30年も経営されているんですね。\nその間に積み上げてこられたノウハウは\n本当に価値あるものだと思います」\n\n社長「まあ、それなりに苦労してきたからな」\n\n健太「そのノウハウを活かしながら、\n事務作業の手間だけを減らせる方法があるんです。\nやり方を変えるというより、今のやり方を\"楽にする\"イメージです」\n\n社長「楽にする？どういうことだ？」\n\n健太「例えば、毎月の集計作業。\n今は手書きで2時間かかっていますよね。\nこれが10分で終わるようになります」\n\n社長「それは助かるな...詳しく聞かせてくれ」"}]}', '{"title": "ベテラン経営者への対応", "content": "ポイント1：敬意と経験への尊重を示す\nポイント2：カタカナ用語を避け、わかりやすく\nポイント3：変化ではなく「強化」として提案\nポイント4：学ぶ姿勢を見せる", "audioText": "ベテラン経営者には敬意を示し、カタカナ用語を避け、今のやり方を強化する提案が効果的です。", "highlight": "敬意と経験への尊重を示す"}', '[{"options": ["最新のDX用語で説明", "経験を尊重し、わかりやすい言葉で", "変化の必要性を強調", "若者の視点を押し付ける"], "question": "ベテラン経営者への効果的なアプローチは？", "explanation": "ベテランには敬意を示し、カタカナ用語を避けてわかりやすく説明します。", "correctIndex": 1}]', '{"text": "Experience is the teacher of all things.", "author": "ユリウス・カエサル", "textJa": "経験はすべてのことの師である。"}', '[{"options": [{"text": "「時代は変わりました。変化しないと取り残されます」", "points": 0, "feedback": "経験を否定すると反発を招きます。", "isCorrect": false}, {"text": "「30年のご経験は素晴らしいですね。そのやり方をもっと楽にするお手伝いができればと思います」", "points": 30, "feedback": "敬意を示しつつ、強化として提案する良い対応です。", "isCorrect": true}, {"text": "「でもDXは必須ですよ」", "points": 0, "feedback": "カタカナ用語と押し付けはNGです。", "isCorrect": false}], "situation": "ベテラン経営者から「今のやり方で30年やってきた」と言われました。", "customerLine": "今のやり方で30年やってきた。何が不満なんだ？"}]', '{"question": "ベテラン経営者との商談で、うまくいったこと・いかなかったことは？", "placeholder": "例: カタカナ用語を使いすぎていた。次回は言い換えを意識する"}', '["カタカナ用語の言い換え表を作る", "敬意を示すフレーズを準備する", "「変化」ではなく「強化」として提案する", "ベテランの経験談を聞く時間を作る"]', '{"title": "ベテラン向けトークの言い換え", "fields": [{"label": "DX →", "placeholder": "例: 事務作業の手間を減らすこと"}, {"label": "クラウド →", "placeholder": "例: 情報を一か所にまとめて、どこからでも見られる仕組み"}, {"label": "業務効率化 →", "placeholder": "例: 今の仕事をもっと楽に、早く終わらせること"}], "description": "カタカナ用語をわかりやすい言葉に言い換えましょう。"}', NULL, '2026-01-21 17:49:07.093359+00', '2026-01-21 17:49:07.093359+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (109, 81, '世代別コミュニケーション', 'スピードと新しさで共感を得る', '{"icon": "zap", "name": "若手対応マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["DXの必要性を強調", "敬意を示しカタカナ用語を避ける", "変化を押し付ける", "最新トレンドを紹介"], "question": "ベテラン経営者への対応で正しいのは？", "explanation": "ベテランには敬意を示し、わかりやすい言葉で説明することが大切です。", "correctIndex": 1}', '{"part1": [{"title": "若手経営者との商談", "content": "健太は30代の若手経営者との商談に臨んだ。\n\n健太「社長、弊社のシステムについてご説明します。\nまず会社概要から—」\n\n社長「会社概要はHPで見た。で、何ができるの？」\n\n健太「はい、順番にご説明しますと...」\n\n社長「あ、ごめん。30分後に次の予定あるから、\n要点だけ教えて。あとでSlackで資料送ってくれる？」\n\n健太「スラック...？」\n\n社長「え、Slack使ってないの？じゃあLINEでいいや」"}, {"title": "若手経営者への対応法", "content": "山本「若手経営者はスピードと効率を重視する。\n長い説明は嫌われるぞ」\n\n【若手経営者への対応ポイント】\n\n1. スピード重視\n  ×「順番にご説明します」\n  ○「3分で要点をお伝えします」\n\n2. デジタルツールに対応\n  ○ Slack、LINE、Zoomなどを使いこなす\n  ○ 資料はPDFやURLで共有\n\n3. トレンドや新しさをアピール\n  ○「最新の○○を導入している企業が増えています」\n  ○「業界で先進的な取り組みです」\n\n4. 対等な立場でビジネスパートナーとして\n  ○ 敬語は使うが、堅すぎない\n  ○ 一緒に成長するパートナーとして提案"}], "part2": [{"title": "スピード感のある商談", "content": "健太「社長、30分ですね。\nでは3分で要点をお伝えして、\n残りはご質問の時間にさせてください」\n\n社長「いいね、それがいい」\n\n健太「結論から。御社の○○課題を解決できます。\nポイントは3つ。詳細資料はLINEでお送りします」\n\n社長「（スマホをチェックしながら）なるほど。\nで、他社と何が違うの？」\n\n健太「業界で最も先進的な○○機能を搭載しています。\n導入企業の成長率は平均1.5倍です」\n\n社長「面白いね。来週Zoomで詳しく聞かせて。\nURL送っておいて」\n\n健太「承知しました！」"}]}', '{"title": "若手経営者への対応", "content": "ポイント1：スピード重視、要点を端的に\nポイント2：デジタルツールに対応\nポイント3：トレンドや新しさをアピール\nポイント4：対等なパートナーとして提案", "audioText": "若手経営者にはスピード重視で要点を伝え、デジタルツールを活用し、新しさをアピールします。", "highlight": "スピードと新しさで共感を得る"}', '[{"options": ["丁寧に順番通り説明", "スピード重視で要点を端的に", "敬意を込めて丁寧語で", "紙の資料を渡す"], "question": "若手経営者への効果的なアプローチは？", "explanation": "若手はスピードと効率を重視。要点を端的に伝えましょう。", "correctIndex": 1}]', '{"text": "Move fast and break things.", "author": "マーク・ザッカーバーグ", "textJa": "素早く動き、破壊せよ。"}', '[{"options": [{"text": "「3分では難しいので、30分ください」", "points": 0, "feedback": "若手のスピード感に合わせましょう。", "isCorrect": false}, {"text": "「結論から。御社の○○課題を解決できます。ポイントは3つ」", "points": 30, "feedback": "スピード感に合わせた良い対応です。", "isCorrect": true}, {"text": "「まず会社概要からご説明します」", "points": 0, "feedback": "若手は会社概要より結論を求めています。", "isCorrect": false}], "situation": "若手経営者から「要点だけ3分で教えて」と言われました。", "customerLine": "要点だけ3分で教えて"}]', '{"question": "若手経営者との商談で、スピード感に対応できていますか？", "placeholder": "例: デジタルツールをもっと使いこなせるようになりたい"}', '["Slack、Zoom、LINEを使いこなせるようにする", "3分で要点を伝える練習をする", "資料はPDFやURLで共有できるよう準備", "最新トレンドの情報を常にキャッチアップする"]', '{"title": "3分エレベーターピッチの作成", "fields": [{"label": "結論（30秒）", "placeholder": "例: 御社の○○課題を解決できます"}, {"label": "ポイント3つ（1分30秒）", "placeholder": "例: 1.コスト削減 2.効率化 3.競合優位"}, {"label": "次のアクション（30秒）", "placeholder": "例: 来週Zoomで詳細をご説明します。URLをお送りしますね"}], "description": "若手経営者向けに、3分で要点を伝えるトークを作りましょう。"}', NULL, '2026-01-21 17:49:08.341168+00', '2026-01-21 17:49:08.341168+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (110, 82, '複数キーパーソンへの対応', '全員を味方につけ、反対者をなくす', '{"icon": "megaphone", "name": "組織攻略マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["丁寧に順番通り説明", "スピード重視で要点を端的に", "紙の資料を渡す", "敬語を多用"], "question": "若手経営者への対応で正しいのは？", "explanation": "若手はスピードと効率を重視。要点を端的に伝えましょう。", "correctIndex": 1}', '{"part1": [{"title": "社内政治に巻き込まれる", "content": "健太は中堅企業への提案を進めていた。\n\n担当部長「いい提案だね。社長に話を通そう」\n\n（1週間後）\n\n担当部長「ごめん、経理部長が反対してて...」\n\n健太「え？経理部長？」\n\n担当部長「『コストがかかりすぎる』って。\nあと、システム部長も『うちのシステムで十分』って...」\n\n健太「（心の声）知らない人たちが反対してる...\nどうすればいいんだ...」"}, {"title": "複数キーパーソンの把握", "content": "山本「企業には複数のキーパーソンがいる。\n全員を把握して、それぞれに対応しないと」\n\n【キーパーソンの種類】\n\n・決裁者：最終的に承認する人（社長など）\n・推進者：導入を推進してくれる人（担当部長など）\n・影響者：意見を求められる人（各部門長など）\n・反対者：導入に反対する人（経理、システムなど）\n・使用者：実際に使う人（現場スタッフなど）\n\n山本「特に『反対者』を放置すると、\n最後にひっくり返される。\n事前に懸念を把握して、対策を打っておくんだ」"}], "part2": [{"title": "全員を味方にする戦略", "content": "健太「経理部長と話す機会をいただけますか？」\n\n（経理部長との面談）\n\n経理部長「コストがかかりすぎる」\n\n健太「ご懸念はごもっともです。\nROI計算書を作成しました。\n2年で投資回収できます」\n\n（システム部長との面談）\n\nシステム部長「うちのシステムで十分だ」\n\n健太「御社のシステムを活かす形で連携できます。\n置き換えではなく、強化のご提案です」\n\n（最終プレゼン）\n\n社長「経理もシステムも問題ないと言っている。\n進めていいぞ」\n\n健太「ありがとうございます！」"}]}', '{"title": "複数キーパーソンへの対応", "content": "5種類のキーパーソン\n・決裁者：最終承認者\n・推進者：導入を推進\n・影響者：意見を求められる人\n・反対者：導入に反対\n・使用者：実際に使う人", "audioText": "企業には複数のキーパーソンがいます。特に反対者には事前に会い、懸念を解消しておくことが重要です。", "highlight": "全員を味方につけ、反対者をなくす"}', '[{"options": ["決裁者だけに集中", "反対者の懸念を事前に把握し対策", "推進者に任せる", "使用者を無視"], "question": "複数キーパーソンがいる場合、特に注意すべきは？", "explanation": "反対者を放置すると最後にひっくり返されます。事前に懸念を把握して対策しましょう。", "correctIndex": 1}]', '{"text": "Keep your friends close and your enemies closer.", "author": "孫子（映画ゴッドファーザーより引用）", "textJa": "友は近くに、敵はもっと近くに置け。"}', '[{"options": [{"text": "「担当部長から説得してもらえませんか？」", "points": 10, "feedback": "他人任せではなく、自分で対応しましょう。", "isCorrect": false}, {"text": "「経理部長とお会いする機会をいただけますか？直接ご説明したいのですが」", "points": 30, "feedback": "反対者に直接会って懸念を聞く良い対応です。", "isCorrect": true}, {"text": "「経理部長抜きで進められませんか？」", "points": 0, "feedback": "反対者を無視すると後で問題になります。", "isCorrect": false}], "situation": "担当部長から「経理部長が反対している」と聞きました。", "customerLine": "経理部長が『コストがかかりすぎる』って反対してるんだ..."}]', '{"question": "あなたの担当案件で、キーパーソンを全員把握できていますか？", "placeholder": "例: 担当者としか話していなかった。他の部門の人も把握する必要がある"}', '["担当案件のキーパーソンマップを作成する", "反対者になりそうな人を事前に把握する", "各キーパーソンの懸念と対策を準備する", "担当者に他のキーパーソンを紹介してもらう"]', '{"title": "キーパーソンマップの作成", "fields": [{"label": "決裁者と推進者", "placeholder": "例: 決裁者=社長、推進者=営業部長"}, {"label": "影響者（意見を求められる人）", "placeholder": "例: 経理部長、システム部長、現場主任"}, {"label": "想定される反対者と懸念", "placeholder": "例: 経理部長→コスト懸念、システム部長→既存システムとの競合"}], "description": "担当案件のキーパーソンを整理しましょう。"}', NULL, '2026-01-21 17:49:09.230219+00', '2026-01-21 17:49:09.230219+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (111, 83, '戦略的アカウントプランニング', '重要顧客には戦略を持って挑め', '{"icon": "map", "name": "戦略家"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["決裁者", "推進者", "反対者", "使用者"], "question": "キーパーソンの中で特に注意すべき人は？", "explanation": "反対者を放置すると最後にひっくり返されます。事前に対策が必要でしたね。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 大口顧客の失注", "content": "（月末の営業会議）\n\n鈴木課長:「山田自動車との契約、更新されなかったな」\n健太:「え...！あの大口顧客が...」\n山本先輩:「3年間の取引があったのに...何があった？」\n\n担当営業:「わかりません...先月までは順調だったのに\n　　　急に競合に切り替えると言われて...」\n\n鈴木課長:「『急に』じゃない。\n　　　予兆を見逃していたんだ。\n　　　場当たり的な対応をしていたからだ」", "duration": 45}, {"title": "シーン2: アカウントプランニングとは", "content": "山本先輩:「健太、大口顧客には\n　　　『アカウントプラン』が必要なんだ」\n\n健太:「アカウントプラン...？」\n\n山本先輩:「重要顧客に対して、戦略的・計画的に\n　　　アプローチするための年間計画だよ」\n\n【一般的な営業 vs 戦略的アカウント営業】\n\n一般的な営業:\n・製品を売ることが目的\n・商談単位で考える\n・短期的な売上重視\n\n戦略的アカウント:\n・顧客の成功が目的\n・年間計画で考える\n・長期的な関係重視\n\n山本先輩:「大口顧客の20%が売上の80%を生む。\n　　　その20%には戦略的に取り組まないと」", "duration": 50}, {"title": "シーン3: アカウントプランの5要素", "content": "山本先輩:「アカウントプランには5つの要素がある」\n\n【アカウントプランの5要素】\n\n1. 顧客プロファイル\n　・企業情報、組織図、キーパーソン\n　・意思決定プロセス、現在の課題\n\n2. 関係性マップ\n　・誰が意思決定者か\n　・誰が影響力を持つか\n　・誰が協力者になりうるか\n\n3. 機会分析\n　・現在の取引状況、拡大余地\n　・クロスセル/アップセル機会\n\n4. 目標設定\n　・売上目標、関係深化目標\n　・具体的なマイルストーン\n\n5. アクションプラン\n　・四半期ごとのアクション\n　・接点計画、提案タイミング", "duration": 45}], "part2": [{"title": "シーン4: チャンピオンを見つける", "content": "山本先輩:「特に大事なのは『チャンピオン』を見つけることだ」\n\n健太:「チャンピオン？」\n\n山本先輩:「社内で君の提案を推進してくれる協力者のことだ」\n\n【関係性マップの作り方】\n\n意思決定者（Decision Maker）: 最終決裁権を持つ人\n影響者（Influencer）: 意思決定に影響を与える人\n推進者（Champion）: 社内で推進してくれる協力者 ★最重要\n利用者（User）: 実際に製品を使う人\n門番（Gatekeeper）: 情報をコントロールする人\n\n山本先輩:「チャンピオンがいれば、\n　　　社内の情報が入ってくる。\n　　　競合の動きも事前にわかる。\n　　　山田自動車では、チャンピオンがいなかったんだろう」", "duration": 50}, {"title": "シーン5: 健太のアカウントプラン作成", "content": "（1週間後）\n\n健太:「先輩、佐藤モータースのアカウントプラン作りました」\n\n山本先輩:「見せてくれ」\n\n【健太のアカウントプラン】\n・顧客プロファイル: 中古車販売店、従業員15名\n・チャンピオン: 営業部長の田中さん\n・今期目標: ワンプラ導入 + Symphony検討開始\n・Q1: 月1回の情報提供訪問\n・Q2: 業界セミナーへの招待\n・Q3: Symphony提案\n・Q4: 来期契約更新 + 紹介依頼\n\n山本先輩:「いいじゃないか。\n　　　田中さんとの関係をしっかり深めろ。\n　　　彼がチャンピオンになってくれれば、\n　　　この案件は安泰だ」", "duration": 45}, {"title": "シーン6: 成果と学び", "content": "（半年後）\n\n健太:「先輩！佐藤モータースから\n　　紹介で2社契約が決まりました！」\n\n山本先輩:「チャンピオンの田中さんが\n　　紹介してくれたのか？」\n\n健太:「はい！『健太さんなら安心』って\n　　言ってくれて...」\n\n山本先輩:「それがアカウントプランニングの成果だよ。\n　　　場当たり的にやっていたら、\n　　　紹介なんてもらえない。\n　　　戦略的に関係を築いたから、\n　　　こうやって広がるんだ」\n\n【今日の学び】\n「重要顧客には戦略を持って挑め」", "duration": 30}]}', '{"title": "アカウントプランの5要素", "content": "1. 顧客プロファイル\n2. 関係性マップ\n3. 機会分析\n4. 目標設定\n5. アクションプラン", "audioText": "重要顧客には年間計画を持って戦略的にアプローチしましょう。特にチャンピオンの存在が成功を左右します。", "highlight": "チャンピオン（推進者）を見つけ、育てることが成功の鍵"}', '[{"options": ["決裁者", "チャンピオン（推進者）", "利用者", "門番"], "question": "アカウントプランニングで最も重要な人物は？", "explanation": "チャンピオンは社内で提案を推進し、情報を提供してくれる重要な協力者です。", "correctIndex": 1}, {"options": ["全顧客の80%", "全顧客の50%", "全顧客の20%", "新規顧客"], "question": "パレートの法則によると、売上の80%を生むのは？", "explanation": "重要な20%の顧客が売上の80%を生みます。この20%に戦略的に取り組むことが重要です。", "correctIndex": 2}]', '{"text": "The 20% of customers generate 80% of the revenue. Focus strategically on that 20%.", "author": "パレートの法則", "textJa": "20%の顧客が80%の売上を生む。その20%に戦略的に取り組むことが成功への道だ。"}', '[{"options": [{"text": "「弊社の方が安くしますよ！」と価格交渉を始める", "points": 0, "feedback": "価格だけの勝負は長期的な関係を損ないます。", "isCorrect": false}, {"text": "「この1年の成果を振り返り、来期のプランをご提案させてください」", "points": 30, "feedback": "成果の振り返りと将来プランの提示で、関係を深められます。", "isCorrect": true}, {"text": "「競合の提案内容を教えてください」", "points": 5, "feedback": "競合情報を直接聞くのは失礼です。価値で勝負しましょう。", "isCorrect": false}], "situation": "重要顧客との年間契約更新が近づいています。", "customerLine": "来月で契約更新だけど、競合からも提案が来てるんだよね"}, {"options": [{"text": "すぐに製品提案のアポを取る", "points": 5, "feedback": "まず顧客理解が先です。アカウントプランを作成しましょう。", "isCorrect": false}, {"text": "顧客プロファイルと関係性マップを作成する", "points": 30, "feedback": "戦略的アプローチの第一歩です。", "isCorrect": true}, {"text": "前任者の対応をそのまま続ける", "points": 10, "feedback": "前任者の情報は参考にしつつ、自分のプランを作りましょう。", "isCorrect": false}], "situation": "新しい大口顧客を担当することになりました。最初に何をしますか？", "customerLine": "（上司から引き継ぎを受けた場面）"}]', '{"question": "あなたの重要顧客に「チャンピオン」はいますか？いない場合、誰をチャンピオンにしますか？", "placeholder": "例: 現在チャンピオンがいない。営業部長の鈴木さんに定期的に情報提供して関係を深めたい"}', '["重要顧客のアカウントプランを作成する", "チャンピオン候補を特定し、関係を深める", "四半期ごとのアクションプランを立てる", "顧客の組織図と関係性マップを作成する"]', '{"title": "アカウントプラン作成ワーク", "fields": [{"label": "顧客名と基本情報", "placeholder": "例: 佐藤モータース、中古車販売、従業員15名、年間売上3億円"}, {"label": "チャンピオン候補", "placeholder": "例: 営業部長の田中さん。弊社製品に好意的、社内での発言力あり"}, {"label": "今期の目標と四半期アクション", "placeholder": "例: Q1訪問4回、Q2セミナー招待、Q3新サービス提案、Q4更新+紹介依頼"}], "description": "担当する重要顧客のアカウントプランを作成しましょう。"}', NULL, '2026-01-21 17:49:10.203285+00', '2026-01-21 17:49:10.203285+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (112, 84, 'ソリューションセリング', '製品ではなく価値を売れ', '{"icon": "lightbulb", "name": "課題解決者"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["決裁者", "チャンピオン", "利用者", "門番"], "question": "アカウントプランで最も重要な人物は？", "explanation": "チャンピオンは社内で提案を推進してくれる重要な協力者でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 機能説明の限界", "content": "（商談後、落ち込む健太）\n\n健太:「また断られた...\n　　機能は全部説明したのに...」\n\n山本先輩:「どんな説明をした？」\n\n健太:「ワンプラの機能を全部説明しました。\n　　在庫管理も、顧客管理も、売上分析も...」\n\n山本先輩:「それが問題だよ」\n\n健太:「え？機能を説明するのがダメなんですか？」\n\n山本先輩:「お客さんは機能が欲しいんじゃない。\n　　　『問題を解決したい』んだ。\n　　　機能の説明と、ソリューションの提案は違う」", "duration": 45}, {"title": "シーン2: 製品営業 vs ソリューション営業", "content": "山本先輩:「製品営業とソリューション営業の違いを教えよう」\n\n【製品営業のアプローチ】❌\n「この製品はこんな機能があります」\n「今ならお得なキャンペーン中です」\n「競合より安いです」\n→ 価格競争に巻き込まれる\n\n【ソリューション営業のアプローチ】✅\n「御社の課題は何ですか？」\n「その課題が解決されると、どのような効果がありますか？」\n「最適な解決策を一緒に考えましょう」\n→ 価値で選ばれる\n\n山本先輩:「ドリルを売るな、穴を売れ。\n　　　お客さんが欲しいのはドリルじゃなく、\n　　　穴なんだ」", "duration": 50}, {"title": "シーン3: ソリューションセリングの4ステップ", "content": "山本先輩:「ソリューションセリングには4つのステップがある」\n\n【ソリューションセリングの4ステップ】\n\n1️⃣ 課題発見\n顧客が認識している課題だけでなく、\n潜在的な課題も発見する。\n「なぜ？」を5回繰り返して本質に迫る\n\n2️⃣ 課題の定量化\n課題を数値化し、ビジネスインパクトを明確にする\n「この課題で年間いくらの損失が出ていますか？」\n\n3️⃣ ソリューション設計\n製品・サービスを組み合わせて最適な解決策を設計\n顧客と共に創り上げる意識が重要\n\n4️⃣ 価値の証明\n投資対効果（ROI）を明確にする\n事例やシミュレーションを活用", "duration": 50}], "part2": [{"title": "シーン4: 課題を深掘りする質問", "content": "山本先輩:「課題を深掘りする質問パターンを覚えよう」\n\n【課題深掘りの質問パターン】\n\n状況質問:\n「現在、○○についてどのように対応されていますか？」\n\n問題質問:\n「○○について、困っていることはありますか？」\n\n示唆質問:\n「もしこの状況が続くと、どのような影響がありますか？」\n\n解決質問:\n「もしこの課題が解決されたら、どのような効果がありますか？」\n\n山本先輩:「ポイントは、顧客自身に課題の重要性を\n　　　認識してもらうことだ。\n　　　こちらから『大変ですね』と言うより、\n　　　顧客自身が『これは大変だ』と気づく方が\n　　　成約率は格段に上がる」", "duration": 50}, {"title": "シーン5: リベンジ商談", "content": "（新規商談。健太は質問から始める）\n\n健太:「現在、売上管理はどのようにされていますか？」\n\n店長:「エクセルで手入力してるよ」\n\n健太:「入力にどのくらい時間がかかりますか？」\n\n店長:「毎日1時間くらいかな...」\n\n健太:「年間で約365時間ですね。\n　　もしこの時間を接客に使えたら、\n　　どのくらい売上に影響しますか？」\n\n店長:「そうだな...月に2〜3台は多く売れるかも...\n　　年間だと24〜36台...結構なインパクトだな」\n\n健太:「その課題を解決できるご提案があります」\n\n店長:「ぜひ聞かせてくれ」", "duration": 45}, {"title": "シーン6: 成約と学び", "content": "（契約締結後）\n\n店長:「正直、最初は別のシステムを検討してたんだ。\n　　でも、健太さんは機能の説明じゃなく、\n　　うちの課題をしっかり聞いてくれた。\n　　それが決め手だったよ」\n\n健太:「ありがとうございます！」\n\n（オフィスに戻って）\n\n山本先輩:「どうだった？」\n\n健太:「成約できました！課題を深掘りしたら、\n　　お客さん自身が『これは解決すべきだ』と\n　　気づいてくれました」\n\n山本先輩:「それがソリューションセリングだ。\n　　　製品を売るな、価値を売れ。」\n\n【今日の学び】\n「製品ではなく価値を売れ」", "duration": 35}]}', '{"title": "ソリューションセリングの4ステップ", "content": "1. 課題発見 - 潜在課題も含めて発見\n2. 課題の定量化 - ビジネスインパクトを数値化\n3. ソリューション設計 - 最適な解決策を共創\n4. 価値の証明 - ROIを明確に示す", "audioText": "製品の機能ではなく、顧客の課題解決という価値を提案しましょう。", "highlight": "顧客は4分の1インチのドリルが欲しいのではない。4分の1インチの穴が欲しいのだ。"}', '[{"options": ["製品の機能説明", "価格提示", "課題発見", "デモンストレーション"], "question": "ソリューションセリングで最初にすべきことは？", "explanation": "まず顧客の課題を発見し、深掘りすることがソリューションセリングの出発点です。", "correctIndex": 2}, {"options": ["こちらから課題を指摘する", "顧客自身に課題の重要性を認識してもらう"], "question": "課題の深掘りで重要なポイントは？", "explanation": "顧客自身が「これは解決すべきだ」と気づくことで、成約率が格段に上がります。", "correctIndex": 1}]', '{"text": "People don''t want to buy a quarter-inch drill. They want a quarter-inch hole.", "author": "セオドア・レビット（ハーバード・ビジネススクール教授）", "textJa": "顧客は4分の1インチのドリルが欲しいのではない。4分の1インチの穴が欲しいのだ。"}', '[{"options": [{"text": "「弊社の在庫管理機能は業界最高です！」", "points": 5, "feedback": "機能の説明になっています。まず課題を深掘りしましょう。", "isCorrect": false}, {"text": "「具体的に何に一番時間がかかっていますか？」", "points": 30, "feedback": "課題を深掘りする良い質問です。", "isCorrect": true}, {"text": "「それは大変ですね。すぐ導入しましょう！」", "points": 0, "feedback": "課題を理解する前に提案するのは早すぎます。", "isCorrect": false}], "situation": "店長から「在庫管理が大変」と言われました。", "customerLine": "在庫管理が大変でね..."}, {"options": [{"text": "「年間で約730時間ですね。時給換算でいくらの損失になりますか？」", "points": 30, "feedback": "課題を定量化する良いアプローチです。", "isCorrect": true}, {"text": "「弊社なら30分に短縮できます！」", "points": 10, "feedback": "定量化する前に解決策を提示しています。順序が大切です。", "isCorrect": false}, {"text": "「他社さんも同じ悩みを持っています」", "points": 5, "feedback": "共感は大切ですが、定量化に進みましょう。", "isCorrect": false}], "situation": "課題が明確になりました。次に何をしますか？", "customerLine": "毎日2時間、在庫チェックに時間を取られてるんだ"}]', '{"question": "最近の商談で「製品営業」になっていませんでしたか？どう改善しますか？", "placeholder": "例: 機能説明から入っていた。次回は質問から始めて、課題を深掘りしてから提案する"}', '["商談の最初は質問から始める", "課題を定量化してビジネスインパクトを示す", "「なぜ？」を5回繰り返して本質に迫る", "顧客自身に課題の重要性を認識してもらう"]', '{"title": "課題深掘り質問の準備", "fields": [{"label": "状況質問（現状を把握する）", "placeholder": "例: 現在、○○についてどのように対応されていますか？"}, {"label": "問題質問（課題を引き出す）", "placeholder": "例: ○○について、困っていることはありますか？"}, {"label": "示唆質問（影響を考えさせる）", "placeholder": "例: この状況が続くと、どのような影響がありますか？"}], "description": "次回の商談で使う課題深掘り質問を準備しましょう。"}', NULL, '2026-01-21 17:49:10.913596+00', '2026-01-21 17:49:10.913596+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (113, 85, 'コンサルティブセリング', '売る人から相談される人へ', '{"icon": "handshake", "name": "信頼のアドバイザー"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["製品説明", "価格提示", "課題発見", "デモ"], "question": "ソリューションセリングで最初にすべきことは？", "explanation": "まず顧客の課題を発見し、深掘りすることが出発点でしたね。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 指名される営業", "content": "（商談から戻った山本先輩）\n\n健太:「先輩、今日の商談どうでした？」\n\n山本先輩:「契約取れたよ。実は先方から\n　　　『山本さんにお願いしたい』って\n　　　指名があったんだ」\n\n健太:「指名...！すごいですね。\n　　どうしたらそうなれるんですか？」\n\n山本先輩:「俺は『営業』じゃなく、\n　　　『アドバイザー』として接してるからかな」\n\n健太:「アドバイザー...？」\n\n山本先輩:「単なる売り手じゃなく、\n　　　『この人に相談したい』と\n　　　思ってもらえる存在になることだよ」", "duration": 45}, {"title": "シーン2: 信頼されるアドバイザーの条件", "content": "山本先輩:「信頼されるアドバイザーには4つの条件がある」\n\n【信頼されるアドバイザーの4条件】\n\n1️⃣ 専門性（Expertise）\n業界知識、製品知識、課題解決の知見\n\n2️⃣ 誠実さ（Integrity）\n顧客の利益を最優先に考え、正直に行動\n\n3️⃣ 親密さ（Intimacy）\n顧客のビジネスと個人的な関心事を深く理解\n\n4️⃣ 自己利益の低さ（Low Self-Orientation）\n自分の売上より顧客の成功を優先\n\n山本先輩:「これを方程式にすると...\n\n【信頼の方程式】\n信頼 = (専門性 + 誠実さ + 親密さ) ÷ 自己利益\n\n分子を大きく、分母を小さくすることで\n信頼が高まるんだ」", "duration": 50}, {"title": "シーン3: 自己利益が高い行動とは", "content": "健太:「自己利益が低いって、\n　　具体的にどういうことですか？」\n\n山本先輩:「自己利益が高い行動と低い行動を比べてみよう」\n\n【自己利益が高い行動】❌\n・自社製品を強引に勧める\n・顧客の話を聞かずに説明する\n・短期的な売上を優先する\n・デメリットを隠す\n\n【自己利益が低い行動】✅\n・時には競合製品を勧めることも\n・売れなくても正直にデメリットを伝える\n・長期的な関係を重視する\n・顧客の成功を一番に考える\n\n山本先輩:「今月の数字より、\n　　　10年後も付き合える関係を選ぶ。\n　　　それがアドバイザーだ」", "duration": 45}], "part2": [{"title": "シーン4: 売らない勇気", "content": "（健太の商談）\n\n店長:「このシステム、導入したいんだけど...」\n\n健太:「ありがとうございます！...ただ、\n　　正直に申し上げると、御社の規模だと\n　　オーバースペックかもしれません」\n\n店長:「え？売り込まないの？」\n\n健太:「御社の課題を考えると、\n　　まずは簡易版で十分だと思います。\n　　3ヶ月使ってみて、必要になったら\n　　アップグレードしませんか？」\n\n店長:「...正直だな。信頼できる。\n　　じゃあ、その簡易版でお願いするよ。\n　　何かあったら、まず君に相談する」\n\n健太:「ありがとうございます！」", "duration": 50}, {"title": "シーン5: アドバイザーとしての価値提供", "content": "山本先輩:「アドバイザーは製品以外の価値も提供する」\n\n【アドバイザーとして価値を提供する方法】\n\n1. 業界トレンドの情報提供\n「最近の業界動向として...」\n\n2. 他社事例の共有（守秘義務の範囲で）\n「似たような課題を持つA社では...」\n\n3. 客観的な視点の提供\n「外から見ると、御社の強みは...」\n\n4. 人脈の紹介\n「○○にお詳しい方をご紹介しましょうか」\n\n5. 製品を超えた相談対応\n「その件は私の専門外ですが、調べてみます」\n\n山本先輩:「製品を買わなくても\n　　　価値を感じてもらえる。\n　　　だから相談される存在になれるんだ」", "duration": 45}, {"title": "シーン6: 成果と学び", "content": "（3ヶ月後）\n\n店長:「健太さん、例のシステム、\n　　アップグレードしたいんだ。\n　　あと、取引先の田中さんも興味あるって」\n\n健太:「ありがとうございます！\n　　紹介までいただけるなんて...」\n\n店長:「君は正直だから、安心して紹介できる。\n　　自分の売上より、こっちのことを\n　　考えてくれてるのが伝わるからね」\n\n（オフィスで）\n\n山本先輩:「紹介もらえたのか。\n　　　売らない勇気が、結果的に\n　　　売上を生んだな」\n\n【今日の学び】\n「売る人から相談される人へ」", "duration": 35}]}', '{"title": "信頼の方程式", "content": "信頼 = (専門性 + 誠実さ + 親密さ) ÷ 自己利益\n\n分子を大きく、分母を小さくする", "audioText": "信頼されるアドバイザーになるには、自分の売上より顧客の成功を優先することが大切です。", "highlight": "顧客の利益を最優先に。時には売らない勇気も必要"}', '[{"options": ["専門性", "誠実さ", "親密さ", "自己利益"], "question": "信頼の方程式で、分母（小さくすべきもの）は？", "explanation": "自己利益を小さくすることで、信頼が高まります。", "correctIndex": 3}, {"options": ["とにかく製品を売る", "顧客に合わない製品でも勧める", "正直にデメリットを伝える", "競合の悪口を言う"], "question": "アドバイザーとしての正しい行動は？", "explanation": "正直にデメリットを伝えることで、長期的な信頼関係が築けます。", "correctIndex": 2}]', '{"text": "People don''t care how much you know until they know how much you care.", "author": "セオドア・ルーズベルト", "textJa": "人は、あなたが自分のことをどれだけ気にかけているかを知るまで、あなたがどれだけ知っているかなど気にしない。"}', '[{"options": [{"text": "「ありがとうございます！すぐ契約しましょう！」", "points": 0, "feedback": "短期的な売上を優先しています。自己利益が高い行動です。", "isCorrect": false}, {"text": "「御社の規模を考えると、まずは中間プランをお勧めします」", "points": 30, "feedback": "顧客の利益を優先した誠実な対応です。", "isCorrect": true}, {"text": "「なぜ一番高いプランをご希望ですか？」", "points": 15, "feedback": "質問は良いですが、その後アドバイスが必要です。", "isCorrect": false}], "situation": "顧客が明らかにオーバースペックな製品を希望しています。", "customerLine": "一番高いプランでお願いしたいんだけど"}, {"options": [{"text": "「弊社では対応できません」と断る", "points": 10, "feedback": "正直ですが、価値提供が足りません。", "isCorrect": false}, {"text": "「弊社製品でも何とかなります！」と無理に売り込む", "points": 0, "feedback": "誠実さに欠ける対応です。", "isCorrect": false}, {"text": "「弊社では難しいですが、その分野に強い会社をご紹介しましょうか」", "points": 30, "feedback": "顧客の成功を優先した、アドバイザーらしい対応です。", "isCorrect": true}], "situation": "顧客の課題に対して、自社製品では対応できないとわかりました。", "customerLine": "この課題を解決できるシステムはありますか？"}]', '{"question": "最近、「自己利益が高い行動」をしていませんでしたか？どう改善しますか？", "placeholder": "例: 月末の数字を気にして、少し強引に売り込んでいた。顧客の本当のニーズを優先したい"}', '["製品以外の価値を毎回1つ提供する", "デメリットも正直に伝える", "長期的な関係を優先する", "顧客の業界情報を常にアップデートする"]', '{"title": "アドバイザーとしての価値提供プラン", "fields": [{"label": "提供できる業界情報・トレンド", "placeholder": "例: EV化の動向、中古車相場の変動、新しい補助金制度"}, {"label": "紹介できる人脈・パートナー", "placeholder": "例: 整備工場の社長、WEBマーケティング会社、行政書士"}, {"label": "製品を超えた相談に応えられる分野", "placeholder": "例: 採用の悩み、集客方法、業務効率化のアイデア"}], "description": "製品以外で顧客に提供できる価値を考えましょう。"}', NULL, '2026-01-21 17:49:11.636792+00', '2026-01-21 17:49:11.636792+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (114, 86, '大型案件の進め方', '組織を動かして大きく勝つ', '{"icon": "building", "name": "大型案件マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["専門性", "誠実さ", "親密さ", "自己利益"], "question": "信頼の方程式で分母（小さくすべきもの）は？", "explanation": "自己利益を小さくすることで信頼が高まりましたね。", "correctIndex": 3}', '{"part1": [{"title": "シーン1: 大型案件の発生", "content": "（朝礼で）\n\n鈴木課長:「山本、健太。大手ディーラーグループの\n　　　　山田オートから引き合いが来た。\n　　　　全30店舗へのシステム導入だ」\n\n健太:「30店舗...！すごい案件ですね！」\n\n山本先輩:「金額にすると年間3000万円規模か...\n　　　　これは簡単にはいかないぞ」\n\n健太:「え？大きいからいい案件じゃないですか？」\n\n山本先輩:「大きい案件は、\n　　　　意思決定者が複数いる。\n　　　　検討期間も長い。競合も本気で来る。\n　　　　普通の営業とは全く違うアプローチが必要だ」", "duration": 45}, {"title": "シーン2: 大型案件の特徴", "content": "山本先輩:「大型案件の特徴を整理しよう」\n\n【大型案件の5つの特徴】\n\n1️⃣ 意思決定者が複数\n　担当者、上司、経営層、財務、IT部門など\n\n2️⃣ 意思決定プロセスが複雑\n　稟議、会議、承認フローが多い\n\n3️⃣ 検討期間が長い\n　数ヶ月〜1年以上かかることも\n\n4️⃣ 競合が本気で狙ってくる\n　価格競争、提案競争が激化\n\n5️⃣ リスクが大きい\n　顧客も失敗できないプレッシャーを抱えている\n\n山本先輩:「これを理解した上で、\n　　　　戦略的に進めないと、\n　　　　最後にひっくり返されるぞ」", "duration": 50}, {"title": "シーン3: 大型案件を進める5ステップ", "content": "山本先輩:「大型案件は5ステップで進める」\n\n【大型案件を進める5ステップ】\n\n1️⃣ 意思決定マップの作成\n誰が意思決定に関わるか、\nそれぞれの関心事・懸念点を把握\n\n2️⃣ 推進者（チャンピオン）の確保\n社内で案件を推進してくれる人を見つけ、育てる\n\n3️⃣ 競合分析\n競合の強み・弱みを把握し、差別化ポイントを明確に\n\n4️⃣ リスク対策\n顧客の不安・懸念を先回りして解消\n導入実績、保証、サポート体制など\n\n5️⃣ タイムラインの管理\n顧客の意思決定スケジュールに合わせて、\n適切なタイミングで情報提供・提案", "duration": 50}], "part2": [{"title": "シーン4: 意思決定者別のアプローチ", "content": "山本先輩:「意思決定者によって、\n　　　　関心事が全く違うんだ」\n\n【意思決定者別のアプローチ】\n\n👔 経営層（社長・役員）\n関心: ROI、競争優位性、リスク\n→ ビジネス成果を強調\n\n💰 財務担当\n関心: コスト、投資回収期間\n→ 費用対効果を数字で示す\n\n👷 現場担当\n関心: 使いやすさ、業務改善\n→ デモ、トライアルで体験させる\n\n💻 IT担当\n関心: 技術仕様、セキュリティ、連携\n→ 技術資料、検証環境を提供\n\n山本先輩:「全員に同じ説明をしても響かない。\n　　　　それぞれの関心事に合わせて\n　　　　メッセージをカスタマイズするんだ」", "duration": 50}, {"title": "シーン5: 山田オートへの戦略的アプローチ", "content": "（2週間後、戦略ミーティング）\n\n健太:「意思決定マップを作りました。\n　　社長、経営企画部長、IT部長、\n　　店舗運営部長、経理部長が関わります」\n\n山本先輩:「チャンピオンは？」\n\n健太:「店舗運営部長の鈴木さんです。\n　　現場の効率化に強い関心があります」\n\n山本先輩:「よし。鈴木さん経由で\n　　　他の部長との面談をセッティングしよう。\n　　　IT部長には技術資料、\n　　　経理部長にはROI計算書を準備だ」\n\n健太:「競合はA社が提案中です。\n　　価格は安いですが、サポート体制が弱い」\n\n山本先輩:「なら、サポート体制を徹底的にアピールしよう。\n　　　　導入後の安心感で差別化だ」", "duration": 50}, {"title": "シーン6: 成約と学び", "content": "（3ヶ月後、最終プレゼン後）\n\n山田オート社長:「山本さん、御社に決めました。\n　　　　　　　価格はA社の方が安かったですが、\n　　　　　　　各部門の懸念に丁寧に対応いただき、\n　　　　　　　安心してお任せできると判断しました」\n\n山本先輩:「ありがとうございます！」\n\n（オフィスで）\n\n健太:「先輩、すごいです！」\n\n山本先輩:「健太がマップを作って、\n　　　　各部門を攻略したからだよ。\n　　　　大型案件は一人で勝てない。\n　　　　組織で動いて、組織を動かす。\n　　　　それが大型案件の進め方だ」\n\n【今日の学び】\n「組織を動かして大きく勝つ」", "duration": 35}]}', '{"title": "大型案件を進める5ステップ", "content": "1. 意思決定マップの作成\n2. チャンピオンの確保\n3. 競合分析\n4. リスク対策\n5. タイムラインの管理", "audioText": "大型案件は複数の意思決定者が関わります。チャンピオンを確保し、各部門の懸念に対応することが成功の鍵です。", "highlight": "意思決定者ごとに関心事が異なる。それぞれに合わせたアプローチが必要"}', '[{"options": ["決裁者だけに集中する", "チャンピオン（推進者）を確保する"], "question": "大型案件で特に重要な役割は？", "explanation": "チャンピオンが社内で案件を推進し、情報を提供してくれます。", "correctIndex": 1}, {"options": ["技術仕様", "費用対効果とビジネス成果", "操作の簡単さ", "価格の安さ"], "question": "経営層への提案で強調すべきは？", "explanation": "経営層はROI、競争優位性、リスクに関心があります。", "correctIndex": 1}]', '{"text": "In complex sales, you need to win over the entire organization, not just one person.", "author": "ニール・ラッカム（SPIN Selling著者）", "textJa": "大型案件を成功させるには、一人の味方ではなく、組織全体を味方につける必要がある。"}', '[{"options": [{"text": "「大丈夫です！問題ありません！」と安心させる", "points": 0, "feedback": "根拠のない安心感は信頼を損ないます。", "isCorrect": false}, {"text": "「IT部長と直接お会いして、技術資料をもとにご説明させてください」", "points": 30, "feedback": "懸念を持つ人に直接対応する良いアプローチです。", "isCorrect": true}, {"text": "「担当者の方からIT部長にお伝えください」", "points": 5, "feedback": "重要な懸念は直接対応しましょう。", "isCorrect": false}], "situation": "大型案件の担当者から「IT部長が技術面で不安を持っている」と聞きました。", "customerLine": "IT部長が『セキュリティは大丈夫か』って心配してるんです"}, {"options": [{"text": "「うちも同じ価格に下げます！」", "points": 0, "feedback": "安易な値下げは利益を損ない、価値を下げます。", "isCorrect": false}, {"text": "「価格だけでなく、導入後のサポート体制とトータルコストで比較いただけますか」", "points": 30, "feedback": "価格以外の価値で差別化する良い対応です。", "isCorrect": true}, {"text": "「A社さんで良いと思います」と諦める", "points": 0, "feedback": "諦めるのは早すぎます。差別化ポイントをアピールしましょう。", "isCorrect": false}], "situation": "競合A社が価格を大幅に下げてきました。", "customerLine": "A社さんが御社より20%安い見積もりを出してきたんですが..."}]', '{"question": "過去の大型案件で「意思決定者を把握できていなかった」経験はありますか？", "placeholder": "例: 担当者だけと話していて、最後に経理部長の反対で失注した。次回は全員を把握したい"}', '["大型案件の意思決定マップを作成する", "チャンピオン候補を特定し、関係を構築する", "各意思決定者の関心事に合わせた資料を準備する", "競合分析を行い、差別化ポイントを明確にする"]', '{"title": "大型案件の意思決定マップ作成", "fields": [{"label": "関わる意思決定者（役職と名前）", "placeholder": "例: 社長-山田氏、経営企画部長-佐藤氏、IT部長-田中氏、現場責任者-鈴木氏"}, {"label": "チャンピオン候補とその理由", "placeholder": "例: 現場責任者の鈴木氏。効率化に強い関心があり、社内での発言力もある"}, {"label": "各意思決定者の関心事と対策", "placeholder": "例: 社長→ROI（3年で回収を提示）、IT部長→セキュリティ（技術資料提供）"}], "description": "担当する大型案件（または想定案件）の意思決定マップを作成しましょう。"}', NULL, '2026-01-21 17:49:12.922204+00', '2026-01-21 17:49:12.922204+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (115, 87, '紹介営業の極意', '最強の営業は紹介で始まる', '{"icon": "users", "name": "紹介マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["決裁者のみ", "チャンピオン（推進者）", "使用者のみ", "門番"], "question": "大型案件で特に重要な役割は？", "explanation": "チャンピオンが社内で案件を推進してくれましたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: 紹介案件の威力", "content": "（営業会議で）\n\n鈴木課長:「今月のトップは山本だ。\n　　　　契約5件、うち4件が紹介案件」\n\n健太:「紹介が4件...！」\n\n山本先輩:「紹介案件は成約率が違うからな」\n\n健太:「先輩、どうやってそんなに\n　　紹介をもらえるんですか？」\n\n山本先輩:「仕組みを作ってるんだよ」\n\n【紹介営業の成約率】\n通常の新規営業: 10-20%\n紹介案件: 30-50%\n\n山本先輩:「紹介は最強のリード獲得方法だ。\n　　　　成約率が高く、信頼もスタートから得られる」", "duration": 45}, {"title": "シーン2: 紹介営業のメリット", "content": "山本先輩:「紹介営業のメリットを整理しよう」\n\n【紹介営業の5つのメリット】\n\n1️⃣ 成約率が高い\n紹介案件の成約率は通常の2〜3倍\n\n2️⃣ 信頼のスタート\n紹介者の信頼が引き継がれる\n\n3️⃣ 営業コストが低い\n広告費、テレアポ工数が不要\n\n4️⃣ 質の高い見込み客\n紹介者がスクリーニングしてくれている\n\n5️⃣ 価格競争になりにくい\n信頼で選ばれるため値引き交渉が少ない\n\n山本先輩:「一件の紹介は、\n　　　　100件のテレアポより価値がある。\n　　　　だから紹介を増やす仕組みが大事なんだ」", "duration": 45}, {"title": "シーン3: 紹介を生む3つの条件", "content": "山本先輩:「紹介を生むには3つの条件がある」\n\n【紹介を生む3つの条件】\n\n1️⃣ 圧倒的な顧客満足\n期待を上回る価値提供\n「この営業は良い」と思ってもらうことが前提\n\n2️⃣ 紹介しやすい状況\n・紹介者にリスクがないこと\n・紹介先にメリットがあること\n→「紹介して恥をかかない」という安心感\n\n3️⃣ きっかけの提供\n満足していても、きっかけがないと紹介は生まれない\n→ こちらからお願いする\n\n山本先輩:「満足してるお客さんも、\n　　　　言われないと紹介しないんだ。\n　　　　だから『お願い』が必要なんだよ」", "duration": 50}], "part2": [{"title": "シーン4: 紹介依頼の5ステップ", "content": "山本先輩:「紹介依頼には5つのステップがある」\n\n【紹介依頼の5ステップ】\n\n① タイミングを見極める\n顧客満足が高まっている時\n（導入成功、成果報告、感謝の言葉をいただいた時）\n\n② 正面からお願いする\n「ご紹介いただけませんか」と直接依頼\n遠慮すると伝わらない\n\n③ 具体的に依頼する\n「○○業界の方」「○○にお困りの方」など\n紹介しやすい条件を伝える\n\n④ ハードルを下げる\n「名前だけ教えていただければ」\n「一度話を聞いてもらえれば」\n\n⑤ 紹介者を守る\n紹介先へは丁寧に対応し、紹介者の顔を潰さない\n結果を必ず報告する", "duration": 50}, {"title": "シーン5: 健太の紹介依頼", "content": "（成果報告の商談後）\n\n店長:「健太さんのおかげで、\n　　売上管理が本当に楽になったよ」\n\n健太:「ありがとうございます！\n　　お役に立てて嬉しいです」\n\n（ここがタイミングだ...!）\n\n健太:「店長、一つお願いがあるのですが...\n　　もし同じように売上管理で\n　　お困りの方がいらっしゃったら、\n　　ご紹介いただけませんか？」\n\n店長:「そうだな...隣町の田中さんが\n　　同じこと言ってたな」\n\n健太:「ありがとうございます！\n　　田中さんには丁寧にご対応します。\n　　結果は必ずご報告しますね」", "duration": 45}, {"title": "シーン6: 紹介の連鎖", "content": "（1ヶ月後）\n\n健太:「先輩！田中さんから契約いただけました！」\n\n山本先輩:「おお、紹介からの成約か」\n\n健太:「しかも、田中さんからさらに\n　　2社紹介いただきました！」\n\n山本先輩:「紹介の連鎖が始まったな。\n　　　　満足した顧客が、次の顧客を連れてくる。\n　　　　これが紹介営業の威力だ」\n\n健太:「最初に紹介をお願いするの、\n　　正直勇気がいりましたけど...」\n\n山本先輩:「遠慮してたら紹介はもらえない。\n　　　　正面からお願いして、\n　　　　紹介者の顔を絶対に潰さない。\n　　　　それが紹介営業の極意だ」\n\n【今日の学び】\n「最強の営業は紹介で始まる」", "duration": 40}]}', '{"title": "紹介を生む3つの条件", "content": "1. 圧倒的な顧客満足\n2. 紹介しやすい状況\n3. きっかけの提供\n\n→ 満足していても、お願いしないと紹介は生まれない", "audioText": "紹介は最も成約率が高いリード獲得方法です。顧客満足を提供し、正面からお願いすることが大切です。", "highlight": "正面からお願いし、紹介者の顔を潰さない対応を徹底する"}', '[{"options": ["顧客満足が高い", "紹介しやすい状況", "自然に紹介を待つ", "きっかけを提供する"], "question": "紹介を生む条件として正しくないのは？", "explanation": "満足していても、きっかけがないと紹介は生まれません。こちらからお願いすることが必要です。", "correctIndex": 2}, {"options": ["契約直後", "顧客満足が高まっている時", "月末", "いつでも同じ"], "question": "紹介依頼のベストタイミングは？", "explanation": "成果報告や感謝の言葉をいただいた時など、満足度が高い時がベストです。", "correctIndex": 1}]', '{"text": "The best advertising is a satisfied customer.", "author": "フィリップ・コトラー", "textJa": "最高の広告は、満足した顧客である。"}', '[{"options": [{"text": "「ありがとうございます！」で終わる", "points": 10, "feedback": "感謝を伝えるのは良いですが、紹介依頼のチャンスを逃しています。", "isCorrect": false}, {"text": "「ありがとうございます！同じようにお困りの方がいたらご紹介いただけますか？」", "points": 30, "feedback": "顧客満足が高いベストタイミングで紹介を依頼できています。", "isCorrect": true}, {"text": "「そのうち紹介お願いしますね」と軽く言う", "points": 5, "feedback": "曖昧な依頼は伝わりません。正面からお願いしましょう。", "isCorrect": false}], "situation": "顧客から「導入して本当に良かった」と言われました。", "customerLine": "健太さんのおかげで業務が楽になりました。ありがとう！"}, {"options": [{"text": "紹介者に結果を報告しない", "points": 0, "feedback": "報告しないと紹介者が不安になり、次の紹介がなくなります。", "isCorrect": false}, {"text": "紹介者に「おかげさまで契約いただけました。ありがとうございました」と報告する", "points": 30, "feedback": "紹介者への報告は必須です。次の紹介にもつながります。", "isCorrect": true}, {"text": "契約書のコピーを紹介者に送る", "points": 5, "feedback": "契約内容の共有は守秘義務違反になる可能性があります。結果の報告だけで十分です。", "isCorrect": false}], "situation": "紹介された見込み客との商談が成功しました。", "customerLine": "（紹介先との商談後）"}]', '{"question": "最近、紹介依頼をしていますか？していない場合、何が障壁になっていますか？", "placeholder": "例: 遠慮して依頼できていなかった。次回から感謝された時に正面からお願いする"}', '["顧客満足が高い時に紹介を依頼する", "紹介依頼は正面からお願いする", "紹介しやすい条件を具体的に伝える", "紹介先への結果を必ず紹介者に報告する"]', '{"title": "紹介依頼スクリプト作成", "fields": [{"label": "紹介をお願いするフレーズ", "placeholder": "例: 同じように○○でお困りの方がいらっしゃったら、ご紹介いただけませんか？"}, {"label": "紹介しやすい条件の伝え方", "placeholder": "例: 中古車販売店の社長様、売上管理に課題を感じている方"}, {"label": "紹介者を安心させるフレーズ", "placeholder": "例: 丁寧にご対応します。結果は必ずご報告しますね"}], "description": "紹介を依頼するスクリプトを準備しましょう。"}', NULL, '2026-01-21 17:49:13.668222+00', '2026-01-21 17:49:13.668222+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (116, 88, '失注分析と勝率向上', '負けから学び、次は勝つ', '{"icon": "chart", "name": "分析の達人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["顧客満足", "紹介しやすい状況", "自然に待つ", "きっかけ提供"], "question": "紹介を生む条件として正しくないのは？", "explanation": "満足していても、こちらからお願いしないと紹介は生まれませんでしたね。", "correctIndex": 2}', '{"part1": [{"title": "シーン1: 連続失注の健太", "content": "（営業会議後、落ち込む健太）\n\n鈴木課長:「健太、今月3件連続で失注か。\n　　　　何が起きてる？」\n\n健太:「すみません...\n　　よくわからないんです...\n　　いい感じだったのに、急にダメになって...」\n\n鈴木課長:「『よくわからない』じゃダメだ。\n　　　　失注には必ず理由がある。\n　　　　それを分析しないと、同じ失敗を繰り返すぞ」\n\n山本先輩:「健太、失注分析の仕方を教えようか」\n\n健太:「お願いします...」", "duration": 45}, {"title": "シーン2: 失注原因の分類", "content": "山本先輩:「失注原因は5つに分類できる」\n\n【失注原因の5分類】\n\n1️⃣ 価格要因\n競合より高い、予算オーバー、費用対効果が不明確\n\n2️⃣ 製品要因\n機能不足、ニーズとのミスマッチ、使い勝手の懸念\n\n3️⃣ 営業要因\n提案内容、対応スピード、信頼関係構築の不足\n\n4️⃣ タイミング要因\n検討時期が早すぎた/遅すぎた、他の優先事項\n\n5️⃣ 組織要因\n意思決定者へのアプローチ不足、チャンピオン不在\n\n山本先輩:「どの要因かを特定することで、\n　　　　次のアクションが変わる」", "duration": 50}, {"title": "シーン3: 失注分析の3ステップ", "content": "山本先輩:「失注分析は3ステップで行う」\n\n【失注分析の3ステップ】\n\n① 事実の収集\n失注直後に顧客にヒアリング\n「差し支えなければ、今回見送られた理由を\n　教えていただけますか？」\n→ 非難せず、感謝の姿勢で聞く\n\n② 原因の深掘り\n「なぜ」を繰り返して本質的な原因を探る\n表面的な理由（価格が高い）\n→ 本質的な原因（価値が伝わっていなかった）\n\n③ 改善策の立案\n原因ごとに具体的な改善策を決める\n→「自分がコントロールできること」に絞る\n\n山本先輩:「『運が悪かった』で終わらせない。\n　　　　必ず学びを得るんだ」", "duration": 50}], "part2": [{"title": "シーン4: 健太の失注分析", "content": "（健太が失注案件を分析中）\n\n健太:「失注した佐藤モータースさんに\n　　電話してみました」\n\n山本先輩:「何て言ってた？」\n\n健太:「『価格が高かった』って...」\n\n山本先輩:「それが本当の理由か？\n　　　深掘りしてみろ」\n\n健太:「そういえば、\n　　『A社は導入事例をたくさん見せてくれた』\n　　とも言ってました...」\n\n山本先輩:「それだ。価格じゃなく、\n　　　『価値が伝わっていなかった』のが本質だ。\n　　　事例を見せて安心させれば、\n　　　価格差は問題にならなかったかもしれない」", "duration": 50}, {"title": "シーン5: 失注後のフォロー", "content": "山本先輩:「失注しても、関係は続けろ」\n\n【失注後のフォロー】\n\n1. 感謝を伝える\n検討いただいたことへのお礼。ドアを閉めない\n\n2. 関係を維持する\n定期的な情報提供、業界動向の共有\n\n3. 再提案の機会を探る\n状況が変わった時、再度チャンスがある\n\n4. 競合の動向を観察\n採用された競合の対応をウォッチ\n\n山本先輩:「今回は負けても、\n　　　　1年後にリベンジできることもある。\n　　　　失注した顧客を放置するな」", "duration": 40}, {"title": "シーン6: リベンジ成功", "content": "（半年後）\n\n佐藤モータース店長から電話:\n「健太さん、A社のシステム、\n　サポートが全然ダメでね...\n　改めて御社を検討したいんだけど」\n\n健太:「ありがとうございます！\n　　今度は導入事例も含めて\n　　しっかりご説明させてください」\n\n（商談後、成約）\n\n山本先輩:「リベンジ成功だな」\n\n健太:「あの時の失注分析がなかったら、\n　　同じ失敗をしてました。\n　　『負けから学ぶ』って大事ですね」\n\n【今日の学び】\n「負けから学び、次は勝つ」", "duration": 35}]}', '{"title": "失注分析の3ステップ", "content": "1. 事実の収集 - 顧客にヒアリング\n2. 原因の深掘り - 「なぜ」を繰り返す\n3. 改善策の立案 - コントロール可能なことに絞る", "audioText": "失注には必ず理由があります。「なぜ」を繰り返して本質的な原因を特定し、次に活かしましょう。", "highlight": "表面的な理由から本質的な原因を探る"}', '[{"options": ["価格設定が間違っている", "値引きが足りなかった", "価値が伝わっていなかった可能性", "競合が安すぎる"], "question": "「価格が高い」と言われた時、本質的な原因は？", "explanation": "「価格が高い」は表面的な理由。価値が十分に伝わっていれば、価格差は問題にならないことが多いです。", "correctIndex": 2}, {"options": ["すぐに忘れる", "顧客との関係を維持する", "二度と連絡しない", "上司に報告しない"], "question": "失注後にすべきことは？", "explanation": "失注しても関係を維持することで、再提案の機会を得られることがあります。", "correctIndex": 1}]', '{"text": "Those who learn from defeat will eventually win. Those who learn nothing from victory will eventually lose.", "author": "孫子の兵法より", "textJa": "負けから学ぶ者は、いつか必ず勝つ。勝ちから何も学ばない者は、いつか必ず負ける。"}', '[{"options": [{"text": "「わかりました」と電話を切る", "points": 0, "feedback": "失注理由を聞く機会を逃しています。", "isCorrect": false}, {"text": "「なぜ弊社じゃダメだったんですか！」と詰め寄る", "points": 0, "feedback": "感情的になると関係が悪化し、今後のチャンスも失います。", "isCorrect": false}, {"text": "「ご検討いただきありがとうございました。差し支えなければ、今回の決め手を教えていただけますか？」", "points": 30, "feedback": "感謝を伝えながら、学びを得る良い対応です。", "isCorrect": true}], "situation": "商談で負けました。顧客に失注理由を聞きます。", "customerLine": "今回は他社さんにお願いすることにしました"}, {"options": [{"text": "「そうですか、価格は難しいですね」で終わる", "points": 5, "feedback": "表面的な理由で終わっています。深掘りしましょう。", "isCorrect": false}, {"text": "「価格の他に、何か気になった点はありましたか？」と深掘りする", "points": 30, "feedback": "本質的な原因を探る良い質問です。", "isCorrect": true}, {"text": "「今からでも値引きします！」", "points": 5, "feedback": "価格だけの問題ではないかもしれません。まず深掘りしましょう。", "isCorrect": false}], "situation": "失注理由を聞いたところ「価格が高かった」と言われました。", "customerLine": "やっぱり価格がね...ちょっと高かったんだよね"}]', '{"question": "最近の失注を振り返り、「自分がコントロールできた」要因は何でしたか？", "placeholder": "例: 事例の準備不足だった。次回は業界・規模が近い事例を3つ準備する"}', '["失注したら必ず理由をヒアリングする", "「なぜ」を繰り返して本質的な原因を探る", "失注顧客との関係を維持する", "失注分析を毎月振り返る習慣をつける"]', '{"title": "失注分析シート作成", "fields": [{"label": "失注案件の概要", "placeholder": "例: 佐藤モータース、中古車販売システム、3月に失注"}, {"label": "表面的な失注理由", "placeholder": "例: 価格が高い"}, {"label": "本質的な原因（なぜを繰り返す）", "placeholder": "例: 価格が高い→なぜ高いと感じた？→事例不足で価値が伝わらなかった"}, {"label": "次回への改善策", "placeholder": "例: 提案前に3つ以上の導入事例を準備する"}], "description": "最近の失注案件を分析しましょう。"}', NULL, '2026-01-21 17:49:15.096241+00', '2026-01-21 17:49:15.096241+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (117, 89, 'ハイパフォーマーの習慣', '才能ではなく習慣が結果を作る', '{"icon": "trophy", "name": "習慣の達人"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["運のせいにする", "「なぜ」を繰り返す", "すぐ忘れる", "値引きを提案"], "question": "失注分析で大切なのは？", "explanation": "「なぜ」を繰り返して本質的な原因を探ることが大切でしたね。", "correctIndex": 1}', '{"part1": [{"title": "シーン1: トップセールスの秘密", "content": "（年間表彰式で）\n\n司会:「今年の年間MVP、山本さん！」\n　　　（拍手）\n\n健太:「先輩、すごい！3年連続MVP...」\n\n山本先輩:「ありがとう」\n\n健太:「先輩って、やっぱり才能ですよね...\n　　僕には無理かな...」\n\n山本先輩:「才能？違うよ。\n　　　俺が特別なわけじゃない。\n　　　ただ、習慣が違うだけだ」\n\n健太:「習慣...？」\n\n山本先輩:「トップセールスの成功要因を調べると、\n　　　『才能』より『習慣』の影響が\n　　　圧倒的に大きいんだ」", "duration": 45}, {"title": "シーン2: 才能 vs 習慣", "content": "山本先輩:「成功要因の内訳を見てみろ」\n\n【成功要因の内訳】\n\n才能（変えられない）: 10〜20%\n習慣・行動（変えられる）: 80〜90%\n\n山本先輩:「つまり、正しい習慣を身につければ、\n　　　　誰でもハイパフォーマーになれる」\n\n健太:「誰でも...？」\n\n山本先輩:「もちろん。\n　　　俺も最初から売れてたわけじゃない。\n　　　先輩から習慣を学んで、\n　　　毎日続けただけだ。\n　　　その積み重ねが今の結果になってる」", "duration": 40}, {"title": "シーン3: ハイパフォーマーの7つの習慣", "content": "山本先輩:「トップセールスに共通する7つの習慣を教えよう」\n\n【ハイパフォーマーの7つの習慣】\n\n1️⃣ 徹底した準備\n商談前の情報収集、シナリオ想定、質問の準備\n→ 準備に時間の50%を使う\n\n2️⃣ 高い行動量\n量が質を生む。打席に立つ回数が多いから、ヒットも多い\n\n3️⃣ 速いレスポンス\n顧客からの問い合わせに即レス。スピード＝信頼\n\n4️⃣ 継続的な学習\n業界知識、製品知識、営業スキルを常にアップデート\n\n5️⃣ 振り返りの習慣\n毎日/毎週の振り返りで、小さな改善を積み重ねる\n\n6️⃣ 健康管理\n体調管理、睡眠、運動。心身のコンディションが成果に直結\n\n7️⃣ ポジティブ思考\n困難を成長の機会と捉え、前向きに行動する", "duration": 55}], "part2": [{"title": "シーン4: 山本先輩の1日", "content": "健太:「先輩の1日を教えてください」\n\n【山本先輩の1日】\n\n6:00 起床、軽い運動\n6:30 業界ニュースチェック\n7:00 今日の商談準備（シナリオ作成）\n8:30 出社、メール返信（即レス）\n9:00 商談①\n12:00 昼食（顧客と）\n13:00 商談②\n15:00 商談③\n17:00 事務作業、振り返り\n18:00 明日の準備\n19:00 退社\n21:00 読書（営業本、業界本）\n\n山本先輩:「特別なことはしてない。\n　　　　基本を毎日続けてるだけだ。\n　　　　この『毎日続ける』が難しいんだけどな」", "duration": 50}, {"title": "シーン5: 習慣化の3つのコツ", "content": "健太:「毎日続けるって難しいですよね...\n　　どうやって習慣にするんですか？」\n\n山本先輩:「習慣化には3つのコツがある」\n\n【習慣化の3つのコツ】\n\n1️⃣ 小さく始める\nいきなり大きな変化を求めず、まず1つの習慣から\n例: 「毎日10件テレアポ」→「毎日3件から」\n\n2️⃣ トリガーを設定\n「○○したら、△△する」というルールを作る\n例: 「朝コーヒーを飲んだら、業界ニュースを読む」\n\n3️⃣ 記録する\n習慣の実行を記録し、可視化する\n達成感がモチベーションになる\n\n山本先輩:「最初から完璧を目指すな。\n　　　　小さく始めて、徐々に増やす。\n　　　　それが習慣化のコツだ」", "duration": 45}, {"title": "シーン6: 健太の習慣改革", "content": "（3ヶ月後）\n\n健太:「先輩、今月の成績、\n　　過去最高でした！」\n\n山本先輩:「何を変えた？」\n\n健太:「毎朝、商談の準備を30分するようにしました。\n　　あと、商談後は必ず5分振り返りを...」\n\n山本先輩:「習慣が変わったな」\n\n健太:「最初は3日坊主になりそうでしたけど、\n　　『小さく始める』を意識したら続きました。\n　　才能じゃなく、習慣なんですね」\n\n山本先輩:「そうだ。続けた者が勝つ。\n　　　　それがハイパフォーマーの真実だ」\n\n【今日の学び】\n「才能ではなく習慣が結果を作る」", "duration": 35}]}', '{"title": "ハイパフォーマーの7つの習慣", "content": "1. 徹底した準備\n2. 高い行動量\n3. 速いレスポンス\n4. 継続的な学習\n5. 振り返りの習慣\n6. 健康管理\n7. ポジティブ思考", "audioText": "トップセールスの成功要因は才能ではなく習慣です。小さく始めて、毎日続けることが大切です。", "highlight": "成功の80-90%は習慣。正しい習慣を身につければ誰でもハイパフォーマーになれる"}', '[{"options": ["10-20%", "30-40%", "50-60%", "80-90%"], "question": "成功要因のうち「習慣・行動」が占める割合は？", "explanation": "才能は10-20%、習慣・行動が80-90%を占めます。習慣で結果は変わります。", "correctIndex": 3}, {"options": ["最初から大きく始める", "小さく始める", "一度にたくさんの習慣を始める", "記録しない"], "question": "習慣化のコツとして正しいのは？", "explanation": "小さく始めて、徐々に増やすことが習慣化のコツです。", "correctIndex": 1}]', '{"text": "We are what we repeatedly do. Excellence, then, is not an act, but a habit.", "author": "アリストテレス", "textJa": "私たちは繰り返し行うことの結果である。したがって、優秀さとは行為ではなく、習慣なのだ。"}', '[{"options": [{"text": "SNSをチェックする", "points": 0, "feedback": "朝の時間を有効に使いましょう。業界ニュースや商談準備がおすすめです。", "isCorrect": false}, {"text": "メールを全て読んでから対応を考える", "points": 10, "feedback": "メールに即レスすることで信頼が高まります。", "isCorrect": false}, {"text": "業界ニュースをチェックし、今日の商談準備をする", "points": 30, "feedback": "ハイパフォーマーの朝の習慣です。準備に時間を使いましょう。", "isCorrect": true}], "situation": "朝、出社しました。最初に何をしますか？", "customerLine": "（朝の行動を選ぶ場面）"}, {"options": [{"text": "すぐ次の予定に移動する", "points": 5, "feedback": "振り返りの時間を取らないと、改善点を見逃します。", "isCorrect": false}, {"text": "5分間、商談の振り返りをメモする", "points": 30, "feedback": "振り返りの習慣が成長を加速させます。", "isCorrect": true}, {"text": "同僚と雑談する", "points": 5, "feedback": "リフレッシュも大切ですが、まず振り返りをしましょう。", "isCorrect": false}], "situation": "商談が終わりました。次に何をしますか？", "customerLine": "（商談後の行動を選ぶ場面）"}]', '{"question": "7つの習慣の中で、自分に最も足りていないのはどれですか？", "placeholder": "例: 振り返りの習慣が足りない。毎日5分の振り返りを始めたい"}', '["毎朝30分の商談準備をする", "商談後5分の振り返りをする", "顧客への返信は即レスを心がける", "習慣の実行を記録し、可視化する"]', '{"title": "習慣改善プラン作成", "fields": [{"label": "身につけたい習慣（1つ選ぶ）", "placeholder": "例: 毎朝30分の商談準備"}, {"label": "小さく始めるバージョン", "placeholder": "例: まずは毎朝10分から始める"}, {"label": "トリガー（いつやるか）", "placeholder": "例: 朝コーヒーを入れたら、すぐに準備を始める"}], "description": "身につけたい習慣と習慣化の計画を立てましょう。"}', NULL, '2026-01-21 17:49:15.696165+00', '2026-01-21 17:49:15.696165+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (118, 90, 'スランプ脱出法', 'スランプは成長の前兆', '{"icon": "flame", "name": "不屈の営業"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の15分で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の15分で少し元気になれるよ。"}]', '{"options": ["10-20%", "30-40%", "50-60%", "80-90%"], "question": "成功要因のうち習慣・行動が占める割合は？", "explanation": "才能は10-20%、習慣・行動が80-90%でしたね。", "correctIndex": 3}', '{"part1": [{"title": "シーン1: 健太のスランプ", "content": "（月末の営業会議）\n\n鈴木課長:「健太、今月も未達か。\n　　　　3ヶ月連続だぞ」\n\n健太:「すみません...」\n\n（会議後、一人で落ち込む健太）\n\n健太:「何をやってもうまくいかない...\n　　努力してるのに...\n　　俺、もう向いてないのかな...」\n\n山本先輩:「健太、ちょっと話そうか」\n\n健太:「先輩...」\n\n山本先輩:「スランプだな。\n　　　俺も経験あるよ」", "duration": 45}, {"title": "シーン2: スランプの正体", "content": "山本先輩:「スランプの正体を理解しよう」\n\n【スランプとは】\n努力しているのに成果が出ない状態\n\n【スランプの原因は5つ】\n\n1️⃣ 行動量の低下\n忙しさを言い訳に、行動量が減っている\n\n2️⃣ スキルの停滞\n同じやり方を繰り返し、成長が止まっている\n\n3️⃣ メンタルの低下\n自信喪失、モチベーション低下\n\n4️⃣ 外部環境の変化\n市場の変化、競合の台頭に対応できていない\n\n5️⃣ 運の要素\n短期的には運に左右されることもある\n\n山本先輩:「まず、どれが原因か特定することが大事だ」", "duration": 50}, {"title": "シーン3: スランプ脱出の5ステップ", "content": "山本先輩:「スランプ脱出には5つのステップがある」\n\n【スランプ脱出の5ステップ】\n\n1️⃣ 数字で現状を把握する\n感覚ではなく、ファクトで状況を確認\n行動量、商談数、成約率などを数値化\n\n2️⃣ 原因を特定する\nどの数字が悪いのか？それはなぜか？\n\n3️⃣ 基本に立ち返る\n複雑なことを考えず、営業の基本動作を徹底\n量をこなす\n\n4️⃣ 小さな成功を積む\n大きな成約を狙わず、小さな成功体験を積み重ねて\n自信を回復\n\n5️⃣ 環境を変える\n担当エリア、アプローチ方法、時間帯などを変えてみる", "duration": 50}], "part2": [{"title": "シーン4: 健太の数字を分析", "content": "山本先輩:「健太、この3ヶ月の数字を出してみろ」\n\n【健太の3ヶ月の数字】\n　　　　3ヶ月前　　2ヶ月前　　先月\nテレアポ　120件　　　80件　　　50件\n訪問　　　15件　　　10件　　　6件\n成約　　　2件　　　 1件　　　 0件\n\n健太:「...行動量が落ちてる...」\n\n山本先輩:「原因はこれだ。\n　　　成約率は悪くない。\n　　　単純に打席に立つ回数が減ってる」\n\n健太:「言い訳ですけど、\n　　既存顧客の対応が増えて...」\n\n山本先輩:「それも大事だけど、\n　　　新規の行動量を減らしたら、\n　　　成果は出ないぞ」", "duration": 50}, {"title": "シーン5: 基本に立ち返る", "content": "山本先輩:「今月は基本に戻ろう。\n　　　難しいことは考えず、行動量を戻す」\n\n【健太の回復プラン】\n・テレアポ: 毎日20件（以前のペース）\n・訪問目標: 週5件\n・小さな成功: アポ1件取れたら自分を褒める\n\n山本先輩:「あと、メンタルケアも大事だ」\n\n【スランプ時のメンタルケア】\n・自分を責めすぎない: スランプは誰にでも起こる\n・過去の成功を思い出す: 以前の自分を思い出す\n・人に話す: 上司、同僚に相談する\n・休息を取る: 疲労が原因のこともある\n\n山本先輩:「スランプは成長の前兆だ。\n　　　乗り越えた先には、新しいステージがある」", "duration": 45}, {"title": "シーン6: スランプ脱出", "content": "（1ヶ月後）\n\n健太:「先輩！今月3件成約しました！」\n\n山本先輩:「おお、復活したな！何が効いた？」\n\n健太:「とにかく行動量を戻しました。\n　　考えすぎず、基本に集中して...\n　　そしたら、自信も戻ってきました」\n\n山本先輩:「スランプの経験は財産だぞ。\n　　　自分の弱点がわかった。\n　　　次にスランプが来ても、脱出法がわかってる」\n\n健太:「はい！スランプは成長の前兆ですね」\n\n山本先輩:「その通り。\n　　　乗り越えた君は、もう一段上のステージだ」\n\n【今日の学び】\n「スランプは成長の前兆」", "duration": 35}]}', '{"title": "スランプ脱出の5ステップ", "content": "1. 数字で現状を把握する\n2. 原因を特定する\n3. 基本に立ち返る\n4. 小さな成功を積む\n5. 環境を変える", "audioText": "スランプの原因は行動量・スキル・メンタル・環境・運の5つ。数字で把握し、基本に立ち返ることが脱出の鍵です。", "highlight": "感覚ではなく数字で把握し、基本に立ち返る"}', '[{"options": ["がむしゃらに頑張る", "数字で現状を把握する", "転職を考える", "休みを取る"], "question": "スランプ脱出の第一歩は？", "explanation": "感覚ではなく、数字で現状を把握することが脱出の第一歩です。", "correctIndex": 1}, {"options": ["新しい手法をたくさん試す", "基本に立ち返り、量をこなす", "複雑な戦略を立てる", "成果が出るまで待つ"], "question": "スランプ時に有効な対策は？", "explanation": "複雑なことを考えず、基本動作を徹底し、量をこなすことが効果的です。", "correctIndex": 1}]', '{"text": "Success is not final, failure is not fatal: it is the courage to continue that counts.", "author": "ウィンストン・チャーチル", "textJa": "成功は最終的なものではなく、失敗は致命的ではない。大切なのは続ける勇気だ。"}', '[{"options": [{"text": "「運が悪いだけ」と考えて同じことを続ける", "points": 0, "feedback": "原因を分析せずに同じことを続けても、結果は変わりません。", "isCorrect": false}, {"text": "「向いてない」と諦める", "points": 0, "feedback": "スランプは誰にでも起こります。諦めるのは早すぎます。", "isCorrect": false}, {"text": "数字を分析して原因を特定し、基本に立ち返る", "points": 30, "feedback": "スランプ脱出の正しいアプローチです。", "isCorrect": true}], "situation": "3ヶ月連続で目標未達です。どうしますか？", "customerLine": "（自分で行動を選ぶ場面）"}, {"options": [{"text": "明日から倍の行動量を目指す", "points": 10, "feedback": "急激な変化は続きません。元のペースに戻すことから始めましょう。", "isCorrect": false}, {"text": "まず元のペースに戻し、小さな成功を積み重ねる", "points": 30, "feedback": "現実的で効果的なアプローチです。", "isCorrect": true}, {"text": "行動量より質を上げることに集中する", "points": 10, "feedback": "質も大事ですが、まずは量を確保することが先です。", "isCorrect": false}], "situation": "分析の結果、行動量が落ちていることがわかりました。", "customerLine": "（次の行動を選ぶ場面）"}]', '{"question": "過去にスランプを経験したことはありますか？どうやって抜け出しましたか？", "placeholder": "例: 入社2年目にスランプを経験。先輩に相談して、基本に立ち返ったら回復した"}', '["自分の数字を毎週チェックする", "行動量が落ちていたら、すぐに元に戻す", "小さな成功を自分で認め、褒める", "スランプを感じたら、早めに上司・先輩に相談する"]', '{"title": "スランプ分析シート", "fields": [{"label": "直近3ヶ月の行動量（テレアポ、訪問、商談数）", "placeholder": "例: 3ヶ月前120件→2ヶ月前80件→先月50件"}, {"label": "特定した原因", "placeholder": "例: 既存対応に時間を取られ、新規行動量が低下"}, {"label": "改善アクション", "placeholder": "例: 毎日テレアポ20件を必ず実行。午前中に新規活動を優先"}], "description": "現在の状況を数字で把握し、改善計画を立てましょう。"}', NULL, '2026-01-21 17:49:16.392844+00', '2026-01-21 17:49:16.392844+00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (164, 13, 'Symphony整備請求マスター', '販売後も、つながり続ける', '{"icon": "wrench", "name": "整備マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', NULL, '{"part1": [{"title": "整備部門の悩み", "content": "中古車販売店の鈴木さんは、整備部門の管理に悩んでいました。見積書は手書き、請求書はエクセル、顧客情報は別のノート...車検時期の管理も漏れがち。「せっかく車を買ってくれたお客様との関係が、納車後に途切れてしまう」", "duration": 30}], "part2": [{"title": "整備が第二の収益源に", "content": "Symphony整備請求を導入した鈴木さん。見積から請求まで一元管理、車検時期は自動アラート。販売管理との連携で、顧客情報も引き継がれます。「車を売って終わりじゃない。整備で長くお付き合いできるようになりました」リピート率は15%向上、整備売上も大幅アップ。", "duration": 30}]}', NULL, '[{"options": ["コストが下がる", "顧客情報の共有とLTV最大化", "デザインが統一される", "操作が簡単になる"], "question": "Symphony整備請求と販売管理を連携するメリットとして、最も重要なのは？", "explanation": "販売管理との連携により、顧客情報が共有され、販売→整備→再販売のサイクルでLTV（顧客生涯価値）を最大化できます。", "correctIndex": 1}]', '{"text": "車を売って終わりじゃない。整備で長くお付き合いする。", "author": "導入店舗オーナー様の声"}', '[{"options": [{"text": "手帳にメモして、自分で管理しておきます", "isCorrect": false}, {"text": "Symphony整備請求で自動通知できます", "isCorrect": true}, {"text": "お客様ご自身で覚えておいてください", "isCorrect": false}], "situation": "車検フォローの場面", "explanation": "Symphony整備請求には車検時期を自動で管理し、時期が近づくとアラートで通知する機能があります。", "customerLine": "車検の時期が近づいたら連絡してほしいんですが..."}]', NULL, NULL, '{"hints": ["購入時からの関係性を強調", "データに基づくメンテナンス提案", "長期的なメリットを伝える"], "title": "整備ビジネスの価値を説明する", "prompt": "以下の観点で、整備サービス継続のメリットを説明してください：\n1. 車両の状態を熟知したスタッフが担当する安心感\n2. 整備履歴の一元管理による適切なメンテナンス提案\n3. 販売時の下取り評価への好影響", "timeLimit": 180, "description": "お客様に整備・車検の継続利用を促す説明を考えてみましょう"}', NULL, '2026-02-04 03:19:40.819991+00', '2026-02-04 03:56:52.154357+00', '[{"title": "整備請求の価値説明練習", "dialogue": [{"line": "整備請求は見積書や請求書が簡単に作れます", "speaker": "kenta"}, {"line": "それは機能だね。整備工場さんの困りごとは何だと思う？", "speaker": "senior"}, {"line": "うーん...手書きで時間がかかる？計算ミスがある？", "speaker": "kenta"}, {"line": "そう！あと車検時期の管理も大変なんだよ。それを踏まえて説明してみて", "speaker": "senior"}, {"line": "車検時期を自動管理して、時期が近いお客様にDMを送れます。整備の予約が増えて売上アップにつながります！", "speaker": "kenta"}, {"line": "いいね！販売管理との連携メリットも伝えられるともっといいよ", "speaker": "senior"}], "keyPoints": ["整備工場特有の課題を理解する", "車検管理→DM→予約増→売上UPの流れ", "販売管理との連携価値も伝える"], "situation": "健太が先輩に、Symphony整備請求を整備工場に提案する練習をしている場面", "seniorOpening": "整備工場のお客様に整備請求を提案するなら、何から話す？", "successCriteria": "整備工場の業務フローを理解した提案ができるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (165, 15, 'ワンプラ競合比較マスター', '選ばれる理由を、数字で語る', '{"icon": "scale", "name": "比較分析マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', NULL, '{"part1": [{"title": "競合との比較で迷う", "content": "営業の田中さんは商談で困っていました。「他社のサービスも検討しているんだけど、ワンプラは何が違うの？」というお客様の質問に、うまく答えられなかったのです。「なんとなく良いと思うんですが...」では説得力がありません。", "duration": 30}], "part2": [{"title": "数字で語る差別化", "content": "競合比較を学んだ田中さん。「ワンプラは出品成約料と落札料のみで固定費ゼロ。他社A社は月額費用がかかります。例えば月10台取引なら、年間で約○万円の差になります」と具体的に説明。「Symphony連携で二重入力も不要です」お客様は納得してワンプラを選んでくれました。", "duration": 30}]}', NULL, '[{"options": ["デザインが良い", "固定費ゼロ、Symphony連携による業務効率化", "歴史が長い", "サポートが日本語"], "question": "ワンプラの競合優位性として、最も強調すべきポイントは？", "explanation": "ワンプラは成約時のみ手数料発生（出品成約料・落札料）で固定費ゼロ、さらにSymphony連携で在庫データの自動出品ができる点が最大の差別化ポイントです。", "correctIndex": 1}]', '{"text": "数字は嘘をつかない。具体的に比較すれば、顧客は納得する。", "author": "Symphony営業格言"}', '[{"options": [{"text": "他社より安いのでお得ですよ", "isCorrect": false}, {"text": "手数料と連携メリットで比較しましょう", "isCorrect": true}, {"text": "とにかく一度使ってみてください", "isCorrect": false}], "situation": "競合サービスとの比較質問", "explanation": "具体的な数字（手数料の差額）とSymphony連携による業務効率化を示すことで、論理的に優位性を伝えられます。", "customerLine": "他社の業販サービスも検討しているんですが、ワンプラは何が違うんですか？"}]', NULL, NULL, '{"hints": ["具体的な金額差を示す", "年間コストで比較する", "連携による時間削減も金額換算"], "title": "競合比較トークを作る", "prompt": "以下の情報を使って、お客様への説明トークを作成してください：\n\n【ワンプラの強み】\n・固定費ゼロ（出品成約料・落札料のみ）\n・7万台の共有在庫\n・Symphony連携で自動出品\n・24時間利用可能\n\n【想定する競合の特徴】\n・月額固定費あり\n・システム連携なし", "timeLimit": 240, "description": "お客様に響く競合比較の説明を作成しましょう"}', NULL, '2026-02-04 03:19:40.819991+00', '2026-02-04 03:56:52.154357+00', '[{"title": "競合との差別化説明練習", "dialogue": [{"line": "えーと...手数料が安い...ですか？", "speaker": "kenta"}, {"line": "それだけだと弱いな。ワンプラならではの強みは？", "speaker": "senior"}, {"line": "Symphony販売管理と連携できて、顧客データと紐づけられます！", "speaker": "kenta"}, {"line": "いいね！それによってお客様はどう嬉しい？", "speaker": "senior"}, {"line": "仕入れた車を誰に売るか、過去の購入履歴から最適なお客様がすぐわかります", "speaker": "kenta"}, {"line": "完璧！システム連携による業務効率化が最大の差別化ポイントだね", "speaker": "senior"}], "keyPoints": ["単体機能ではなくシステム連携が強み", "データ連携による業務効率化", "仕入れから販売までのワンストップ"], "situation": "健太が先輩に、ワンプラと競合サービスの違いを説明する練習をしている場面", "seniorOpening": "お客様から「他のオークションと何が違うの？」と聞かれたら？", "successCriteria": "競合との明確な差別化ポイントを説明できるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (166, 17, '小規模店舗への提案マスター', '時間を作る、売上を作る', '{"icon": "store", "name": "小規模店舗スペシャリスト"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', NULL, '{"part1": [{"title": "小規模店舗の課題", "content": "オーナー1人で経営するA店。在庫8台、手書きの在庫管理、各広告サイトへの個別入力で1日3時間以上を事務作業に費やしていました。「本当は接客に時間を使いたいのに...」売上を伸ばしたくても、時間が足りない状況でした。", "duration": 30}], "part2": [{"title": "事務作業から接客へ", "content": "Symphony販売管理を導入したA店。広告掲載作業が1/3に短縮、手書き管理から解放され、粗利計算も自動化。空いた時間で来店接客を強化し、成約率が15%向上。「これだけで中古車販売ができます」オーナーは笑顔で語ります。", "duration": 30}]}', NULL, '[{"options": ["最新のテクノロジー", "事務作業削減で接客時間が増え、売上アップにつながる", "大企業も使っている", "デザインが綺麗"], "question": "小規模店舗へのSymphony提案で、最も響くポイントは？", "explanation": "小規模店舗は時間がない中で全業務をこなしています。事務作業削減→接客強化→売上アップのストーリーが最も響きます。", "correctIndex": 1}]', '{"text": "小さく始めて、大きく育てる。まずは時間を作ることから。", "author": "Symphony営業格言"}', '[{"options": [{"text": "確かに小規模店には不要かもしれません", "isCorrect": false}, {"text": "小さい店舗だからこそ時間が大切です", "isCorrect": true}, {"text": "将来のために今から導入しましょう", "isCorrect": false}], "situation": "小規模店舗オーナーとの商談", "explanation": "小規模店舗こそ、オーナー1人で全業務をこなすため時間が最も貴重です。事務作業削減で接客時間を増やせます。", "customerLine": "うちは小さい店だから、そんな大げさなシステムは要らないよ"}]', NULL, NULL, '{"hints": ["削減時間 = (3時間-1時間) × 20日", "月間コスト = 削減時間 × 時給", "年間 = 月間 × 12"], "title": "小規模店舗向けROI試算", "prompt": "以下の条件で、Symphony導入のROIを試算してください：\n\n【現状】\n・オーナー1人で運営\n・事務作業：1日3時間\n・時給換算：1,500円\n・月間営業日：20日\n\n【導入後の見込み】\n・事務作業：1日1時間に短縮\n\n計算してほしい項目：\n1. 月間削減時間\n2. 月間削減コスト（時給換算）\n3. 年間効果", "timeLimit": 180, "description": "実際の数字を使って投資対効果を計算しましょう"}', NULL, '2026-02-04 03:19:40.819991+00', '2026-02-04 03:56:52.154357+00', '[{"title": "小規模店舗への提案練習", "dialogue": [{"line": "うーん...小規模だからこそ効率化が大事、とか？", "speaker": "kenta"}, {"line": "そうそう！具体的な事例で説明してみて", "speaker": "senior"}, {"line": "3名の店舗様が導入して、月に10時間の事務作業を削減できた事例があります", "speaker": "kenta"}, {"line": "いいね！10時間あったら何ができる？", "speaker": "senior"}, {"line": "その時間でお客様対応や営業活動ができます。実際にその店舗様は月2台販売が増えました！", "speaker": "kenta"}, {"line": "完璧！時間削減→本業集中→売上アップの流れで説明できてるね", "speaker": "senior"}], "keyPoints": ["小規模だからこそ効率化が重要", "具体的な数字（時間・台数）で説明", "時間削減→売上アップのストーリー"], "situation": "健太が先輩に、小規模店舗（従業員3名）への提案を練習している場面", "seniorOpening": "小規模店舗のお客様が「うちは小さいから不要」と言ったら？", "successCriteria": "小規模店舗の状況に合わせた事例提案ができるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (167, 18, '中規模店舗への提案マスター', '情報を共有し、成長を加速する', '{"icon": "building", "name": "中規模店舗スペシャリスト"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', NULL, '{"part1": [{"title": "中規模店舗の課題", "content": "在庫40台、スタッフ7名のB店。営業と整備の情報共有ができず、顧客フォロー漏れが頻発。仕入れはオークションのみで、欲しい車が見つからないことも多い状況でした。「店舗が大きくなるにつれ、管理が追いつかなくなってきた...」", "duration": 30}], "part2": [{"title": "情報共有で成長加速", "content": "Symphony販売管理とワンプラを導入したB店。顧客情報の一元管理でフォロー漏れが激減、ワンプラで仕入れルートも拡大。在庫回転率が25%向上し、年間売上が1.3倍に成長。「スタッフ全員が同じ情報を見られるのが大きい」", "duration": 30}]}', NULL, '[{"options": ["価格が安い", "スタッフ間の情報共有と在庫回転率向上", "個人でも使える", "海外でも使える"], "question": "中規模店舗へのSymphony提案で、最も重要な訴求ポイントは？", "explanation": "中規模店舗は情報共有と在庫回転が課題。販売管理での一元管理とワンプラでの仕入れ・業販拡大を提案しましょう。", "correctIndex": 1}]', '{"text": "成長には痛みが伴う。でもSymphonyがあれば、その痛みを最小化できる。", "author": "Symphony営業格言"}', '[{"options": [{"text": "まずワンプラで仕入れを効率化しましょう", "isCorrect": false}, {"text": "販売管理で顧客情報を一元管理しましょう", "isCorrect": true}, {"text": "整備請求で車検管理を始めましょう", "isCorrect": false}], "situation": "中規模店舗での情報共有課題", "explanation": "情報共有の課題には、Symphony販売管理の顧客管理（CRM）機能が最適です。全スタッフが同じ情報を見られます。", "customerLine": "スタッフ間で顧客情報がうまく共有できなくて、フォロー漏れが多いんです"}]', NULL, NULL, '{"hints": ["現状の課題を確認してから提案", "連携による二重入力削減を強調", "具体的な効果を数字で示す"], "title": "中規模店舗向けクロスセル提案", "prompt": "Symphony販売管理を導入済みの中規模店舗（在庫40台）に、ワンプラを追加提案するトークを作成してください：\n\n【現状の課題（ヒアリング済み）】\n・オークションだけでは欲しい車が見つからない\n・長期在庫が10台ほどある\n・仕入れコストを下げたい\n\n【提案のポイント】\n・販売管理との連携メリット\n・仕入れルート拡大\n・長期在庫の業販出品", "timeLimit": 240, "description": "販売管理導入後のクロスセル提案を考えましょう"}', NULL, '2026-02-04 03:19:40.819991+00', '2026-02-04 03:56:52.154357+00', '[{"title": "中規模店舗への提案練習", "dialogue": [{"line": "スタッフ間の情報共有...ですか？", "speaker": "kenta"}, {"line": "そう！人が増えると情報がバラバラになりがち。どう解決する？", "speaker": "senior"}, {"line": "販売管理で顧客情報を一元管理すれば、誰でも同じ情報を見られます", "speaker": "kenta"}, {"line": "いいね！導入事例ではどんな効果があった？", "speaker": "senior"}, {"line": "10名の店舗様で、引き継ぎミスがゼロになって、顧客満足度が20%向上しました！", "speaker": "kenta"}, {"line": "いいね！中規模は情報共有と属人化防止がキーワードだよ", "speaker": "senior"}], "keyPoints": ["情報共有の課題を解決", "属人化を防いで誰でも対応可能に", "引き継ぎミス削減→顧客満足度向上"], "situation": "健太が先輩に、中規模店舗（従業員10名）への提案を練習している場面", "seniorOpening": "中規模店舗でよくある課題って何だと思う？", "successCriteria": "中規模店舗の組織課題に合わせた提案ができるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (168, 19, '大規模・多店舗への提案マスター', '全店舗を、ひとつに', '{"icon": "buildings", "name": "エンタープライズスペシャリスト"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', NULL, '{"part1": [{"title": "多店舗管理の課題", "content": "3店舗・在庫150台・スタッフ25名のC社。店舗ごとで在庫・顧客管理がバラバラ、店舗間の在庫移動に手間がかかり機会損失が発生。本部での売上・在庫の把握にもタイムラグ。「全体を見渡せない経営は不安だ...」", "duration": 30}], "part2": [{"title": "一元管理で経営が変わる", "content": "全製品をフル導入したC社。全店舗のデータをリアルタイムで一元管理、店舗間在庫共有で機会損失が大幅減。本部でのデータ分析により、仕入れ・価格戦略の精度が向上。グループ全体で年商20%増を達成。「データに基づく経営判断ができるようになった」", "duration": 30}]}', NULL, '[{"options": ["個人でも使いやすい", "全店舗の一元管理とデータに基づく経営判断", "無料で始められる", "シンプルな機能"], "question": "大規模・多店舗企業へのSymphony提案で、最も重要な訴求ポイントは？", "explanation": "大規模企業は一元管理と経営判断のスピードが課題。全製品フル導入で最大効果を提案しましょう。", "correctIndex": 1}]', '{"text": "大きな船を動かすには、小さな舵から。パイロットで成功を証明せよ。", "author": "Symphony営業格言"}', '[{"options": [{"text": "全店舗に一斉導入を提案する", "isCorrect": false}, {"text": "1店舗でパイロット導入を提案する", "isCorrect": true}, {"text": "本部用の管理ツールだけ提案する", "isCorrect": false}], "situation": "多店舗展開企業への提案", "explanation": "大規模導入はリスクが高いため、まず1店舗でパイロット導入し、効果を実証してから展開します。", "customerLine": "3店舗あるけど、店舗ごとにバラバラのシステムで困っている"}]', NULL, NULL, '{"hints": ["現状課題の整理", "解決策と期待効果", "導入スケジュール（パイロット→展開）", "投資対効果（ROI）"], "title": "大規模導入の提案書構成", "prompt": "3店舗展開の中古車販売グループに対する提案書の構成を作成してください：\n\n【顧客情報】\n・3店舗（A店40台、B店50台、C店60台）\n・スタッフ計25名\n・現状：各店舗バラバラのシステム\n\n【課題】\n・店舗間の在庫共有ができない\n・本部での売上把握に時間がかかる\n・顧客情報の引継ぎができない\n\n提案書に含めるべき項目を挙げてください。", "timeLimit": 300, "description": "多店舗企業への提案書の構成を考えましょう"}', NULL, '2026-02-04 03:19:40.819991+00', '2026-02-04 03:56:52.154357+00', '[{"title": "大規模・多店舗への提案練習", "dialogue": [{"line": "各店舗でSymphonyを使ってもらう...？", "speaker": "kenta"}, {"line": "それだと各店舗バラバラだね。多店舗ならではの価値は？", "speaker": "senior"}, {"line": "あ、本部で全店舗のデータを一元管理できます！", "speaker": "kenta"}, {"line": "そう！具体的にはどんなことができる？", "speaker": "senior"}, {"line": "全店舗の在庫状況をリアルタイムで把握して、店舗間で在庫を融通できます。A店で売れない車をB店で売れる！", "speaker": "kenta"}, {"line": "いいね！スケールメリットを活かした提案ができてるよ", "speaker": "senior"}], "keyPoints": ["本部での一元管理", "店舗間の在庫融通", "全店舗データの分析・活用"], "situation": "健太が先輩に、大規模・多店舗（5店舗展開）への提案を練習している場面", "seniorOpening": "多店舗展開のお客様には何を提案する？", "successCriteria": "多店舗展開のスケールメリットを活かした提案ができるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (159, 11, 'Symphonyシリーズ全体像', 'すべての業務が、つながる', '{"icon": "sparkles", "name": "Symphony入門"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', '{"options": ["人手が余っている", "入力作業の二重手間", "在庫が多すぎる", "お客様が多すぎる"], "question": "中古車販売店の主な課題として多いのは？", "explanation": "中古車販売店では、複数システムへの二重入力、手書き管理の非効率さが大きな課題です。", "correctIndex": 1}', '{"part1": [{"title": "ある日の営業シーン", "content": "田中さんは中古車販売店「カーライフ山田」を訪問しました。\n\n店長の山田さん：「最近、業務が回らなくて困っているんだよね。在庫管理、広告掲載、顧客管理...全部バラバラのシステムで、二度手間三度手間だよ。」\n\n田中さん：「山田さん、そのお悩み、よく分かります。実は今日ご紹介したいのが、まさにその課題を解決するSymphonyシリーズなんです。」"}], "part2": [{"title": "Symphonyの価値を伝える", "content": "田中さん：「Symphonyシリーズは『分かりやすい』『つながる』『売上が伸びる』の3つの価値を提供します。\n\n一度入力すれば、在庫管理から広告掲載、顧客管理まで全てが連携します。」\n\n山田さん：「へぇ、それは便利そうだね。具体的にはどんな製品があるの？」\n\n田中さん：「販売管理を中心に、整備請求、ワンプラという在庫共有サービスがあります。お店の課題に合わせて組み合わせられるんです。」"}]}', '{"title": "Symphonyシリーズの3つの価値", "content": "┌─────────────────────────────┐\n│     分かりやすい     │\n│  ワンストップで完結  │\n│  誰でもすぐ使える    │\n└─────────────────────────────┘\n           ↓\n┌─────────────────────────────┐\n│      つながる        │\n│  全国の業者と仕入れ  │\n│  10+メディアに一括   │\n└─────────────────────────────┘\n           ↓\n┌─────────────────────────────┐\n│    売上が伸びる      │\n│  在庫回転率アップ    │\n│  整備で収益源追加    │\n└─────────────────────────────┘", "audioText": "Symphonyは単なるシステムではなく、中古車販売店の経営を変える統合プラットフォームです。", "highlight": "すべての業務が、つながる。すべてのデータが、活きる。"}', '[{"options": ["安い・早い・うまい", "分かりやすい・つながる・売上が伸びる", "品質・価格・サービス", "信頼・実績・サポート"], "question": "Symphonyシリーズの3つの価値は？", "explanation": "Symphonyは「分かりやすい」「つながる」「売上が伸びる」の3つの価値を提供します。", "correctIndex": 1}]', '{"text": "The whole is greater than the sum of its parts.", "author": "アリストテレス", "textJa": "全体は部分の総和以上である"}', '[{"options": [{"text": "Symphony販売管理を提案", "feedback": "正解です！まずは販売管理で業務効率化を実現し、成功体験を作りましょう。", "isCorrect": true}, {"text": "全製品をセットで提案", "feedback": "いきなり全製品は負担が大きいです。まずは核となる販売管理から始めましょう。", "isCorrect": false}, {"text": "ワンプラだけを提案", "feedback": "ワンプラは仕入れ・業販に特化しています。業務管理の課題には販売管理が適切です。", "isCorrect": false}], "situation": "顧客の課題に応じた製品提案", "customerLine": "在庫30台の中古車販売店。オーナー1人で運営。手書き管理に限界を感じている。"}]', '{"question": "Symphonyを提案する際、最初に確認すべきことは何だと思いますか？", "placeholder": "例：お客様の現状のシステムや業務フローを聞く..."}', '["お客様の現状システムを必ず確認する", "3つの価値（分かりやすい・つながる・売上が伸びる）を説明できるようにする", "小さく始める提案を準備する", "導入事例を1つ覚える"]', '{"title": "Symphonyシリーズ 製品マップ作成", "fields": [{"label": "入力作業が大変な店舗に提案する製品", "placeholder": "製品名と理由を書いてください"}, {"label": "仕入れルートを増やしたい店舗に提案する製品", "placeholder": "製品名と理由を書いてください"}, {"label": "整備収益を増やしたい店舗に提案する製品", "placeholder": "製品名と理由を書いてください"}], "description": "お客様の課題と製品を紐づけて整理しましょう"}', NULL, '2026-02-04 03:02:42.002607+00', '2026-02-04 03:56:52.154357+00', '[{"title": "Symphonyシリーズの紹介練習", "dialogue": [{"line": "えっと...Symphonyは販売管理と整備請求とワンプラがあって...", "speaker": "kenta"}, {"line": "うん、それだけだとお客様に刺さらないな。3つの価値で説明してみて", "speaker": "senior"}, {"line": "3つの価値...売上を上げる、コストを下げる、リスクを減らす、ですね！", "speaker": "kenta"}, {"line": "そうそう！具体的にはどう説明する？", "speaker": "senior"}, {"line": "販売管理で顧客情報を一元管理して売上アップ、整備請求で業務効率化してコスト削減、ワンプラで仕入れ・販売のリスクを軽減します！", "speaker": "kenta"}, {"line": "いいね！お客様の課題に合わせて、どの価値を強調するか変えていこう", "speaker": "senior"}], "keyPoints": ["3つの価値（売上UP・コスト削減・リスク軽減）で説明する", "お客様の課題に合わせて強調点を変える", "製品名の羅列ではなく価値で語る"], "situation": "健太が先輩に、Symphonyシリーズの全体像を説明する練習をしている場面", "seniorOpening": "じゃあ健太、お客様にSymphonyシリーズを紹介するとしたら、どう説明する？", "successCriteria": "製品の機能ではなく、お客様への価値で説明できるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (160, 12, 'Symphony販売管理', '一度の入力で、すべて完結', '{"icon": "target", "name": "販売管理マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', '{"options": ["シンフォニーワンプラ", "Symphony販売管理", "Symphony整備請求", "Symphonyオークション"], "question": "Symphonyシリーズで中心となる製品は？", "explanation": "販売管理が中心製品で、ワンプラや整備請求と連携してさらに価値を発揮します。", "correctIndex": 1}', '{"part1": [{"title": "販売管理の価値を伝える", "content": "山田さん：「販売管理って具体的に何ができるの？」\n\n田中さん：「一言で言うと『一度の入力で、すべて完結』です。\n\n車両情報を登録すれば、カーセンサー、グーネット、Yahoo!オークションなど10以上のメディアに一括掲載できます。」\n\n山田さん：「え、今は各サイトに別々に入力してるよ...それだけで1日2時間はかかってる。」"}], "part2": [{"title": "競合優位性を説明", "content": "田中さん：「他社システムとの違いは、Symphonyシリーズ全体との連携です。\n\n販売管理で登録した車両は、ワンプラで業販出品もできます。整備請求と連携すれば、販売した顧客の車検時期も自動でフォローできます。」\n\n山田さん：「なるほど、単体じゃなくて、全体で価値が出るってことか。」\n\n田中さん：「その通りです！1+1を3にする。それがSymphony連携の価値です。」"}]}', '{"title": "Symphony販売管理 6つの機能", "content": "┌────────────────────────────────┐\n│   🚗 車両管理                 │\n│   写真・スペック一元管理      │\n├────────────────────────────────┤\n│   📢 広告連携                 │\n│   10+メディア一括掲載         │\n├────────────────────────────────┤\n│   👥 顧客管理（CRM）          │\n│   商談履歴・フォロー管理      │\n├────────────────────────────────┤\n│   📝 契約書作成               │\n│   ペーパーレス化              │\n├────────────────────────────────┤\n│   🚚 納車管理                 │\n│   スケジュール・ToDo          │\n├────────────────────────────────┤\n│   💰 粗利計算                 │\n│   仕入れ〜販売を自動計算      │\n└────────────────────────────────┘", "audioText": "販売管理は単なる業務効率化ツールではありません。空いた時間で接客を増やし、売上アップにつなげるためのツールです。", "highlight": "一度の入力で、すべて完結。本質的な営業活動に集中できます。"}', '[{"options": ["3サイト以上", "5サイト以上", "10サイト以上", "20サイト以上"], "question": "Symphony販売管理で一括掲載できるメディア数は？", "explanation": "カーセンサー、グーネット、Yahoo!オークションなど10以上のメディアに一括掲載できます。", "correctIndex": 2}]', '{"text": "Simplicity is the ultimate sophistication.", "author": "レオナルド・ダ・ヴィンチ", "textJa": "シンプルさは究極の洗練である"}', '[{"options": [{"text": "「入力作業が約50%削減できます」と数字で伝える", "feedback": "正解！具体的な数字で効果を伝えることで説得力が増します。", "isCorrect": true}, {"text": "「便利になります」と抽象的に伝える", "feedback": "抽象的な表現より、具体的な数字で伝えましょう。", "isCorrect": false}, {"text": "「他社より安いです」と価格を強調", "feedback": "価格より先に、課題解決の価値を伝えましょう。", "isCorrect": false}], "situation": "販売管理の導入効果を説明", "customerLine": "1日2時間を広告掲載作業に費やしている店舗オーナー"}]', '{"question": "販売管理を提案する際、最も効果的なアピールポイントは何だと思いますか？", "placeholder": "例：入力時間の削減効果を具体的な数字で示す..."}', '["「一度の入力で全メディア掲載」を必ず伝える", "入力時間の削減効果（83%削減）を数字で示す", "他製品との連携メリットを説明する", "導入サポート体制を説明できるようにする"]', '{"title": "販売管理の競合比較シート作成", "fields": [{"label": "販売管理の最大の強みは？", "placeholder": "一番のアピールポイントを書いてください"}, {"label": "競合製品にない機能は？", "placeholder": "差別化ポイントを書いてください"}, {"label": "お客様の不安への対処法は？", "placeholder": "「使いこなせるか不安」への回答を書いてください"}], "description": "販売管理の強みを整理しましょう"}', NULL, '2026-02-04 03:02:42.002607+00', '2026-02-04 03:56:52.154357+00', '[{"title": "販売管理の機能説明練習", "dialogue": [{"line": "顧客管理、在庫管理、売上分析ができます", "speaker": "kenta"}, {"line": "機能の羅列だね。お客様の困りごとに紐づけて説明してみて", "speaker": "senior"}, {"line": "えーと...お客様情報がバラバラで困っていませんか？販売管理なら一元管理できます", "speaker": "kenta"}, {"line": "いいね！もう一歩踏み込んで、それによってどうなる？", "speaker": "senior"}, {"line": "過去の購入履歴がすぐ見れるので、お客様に合った提案ができて、リピート率が上がります！", "speaker": "kenta"}, {"line": "完璧！課題→解決策→効果の流れで説明できてるね", "speaker": "senior"}], "keyPoints": ["機能ではなく課題解決で説明する", "課題→解決策→効果の流れを意識", "具体的な効果を伝える"], "situation": "健太が先輩に、Symphony販売管理の主要機能を説明する練習をしている場面", "seniorOpening": "お客様から「販売管理って何ができるの？」と聞かれたら？", "successCriteria": "お客様の課題に紐づけて機能を説明できるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (161, 14, 'シンフォニーワンプラ', '在庫を流動化、コストを最小化', '{"icon": "flame", "name": "ワンプラエキスパート"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', '{"options": ["約1万台", "約3万台", "約7万台", "約10万台"], "question": "シンフォニーワンプラの共有在庫数は？", "explanation": "シンフォニーワンプラは約7万台の共有在庫から仕入れができます。", "correctIndex": 2}', '{"part1": [{"title": "仕入れの課題", "content": "山田さん：「最近、オークションだけじゃ欲しい車が見つからなくてね。」\n\n田中さん：「そのお悩み、シンフォニーワンプラで解決できます。\n\n全国の中古車販売店をつなぐ在庫共有プラットフォームで、7万台の共有在庫から24時間いつでも仕入れができます。」\n\n山田さん：「7万台！それはすごいね。手数料は高いの？」"}], "part2": [{"title": "手数料体系の説明", "content": "田中さん：「ワンプラの手数料は業界最安水準です。\n\n出品成約料と落札料の2種類があり、成約時のみ発生します。固定費はゼロなので、リスクなく始められます。」\n\n山田さん：「固定費ゼロは嬉しいね。売れない在庫の処分にも使える？」\n\n田中さん：「はい！仕入れだけでなく、長期在庫を全国の業者に業販出品することもできます。在庫回転率アップに貢献します。」"}]}', '{"title": "ワンプラ手数料体系", "content": "┌─────────────────────────────────────┐\n│   💰 手数料体系（2種類のみ）    │\n├─────────────────────────────────────┤\n│                                   │\n│  【出品成約料】                   │\n│   出品した車が売れた時に発生      │\n│                                   │\n│  【落札料】                       │\n│   他店の車を仕入れた時に発生      │\n│                                   │\n├─────────────────────────────────────┤\n│   ✓ 固定費ゼロ                   │\n│   ✓ 成約時のみ手数料発生         │\n│   ✓ 業界最安水準                 │\n└─────────────────────────────────────┘\n\n★ オークション会費・出品料不要！", "audioText": "ワンプラの手数料は出品成約料と落札料の2種類のみ。固定費がかからないので、気軽に始められます。", "highlight": "シンプルな料金体系：出品成約料と落札料のみ。固定費ゼロで始められます。"}', '[{"options": ["月額固定費のみ", "出品成約料と落札料（成約時のみ）", "年会費制", "売上の一定割合"], "question": "シンフォニーワンプラの手数料体系は？", "explanation": "ワンプラは出品成約料と落札料の2種類で、成約時のみ発生。固定費はゼロです。", "correctIndex": 1}]', '{"text": "In the middle of difficulty lies opportunity.", "author": "アルベルト・アインシュタイン", "textJa": "困難の中に機会がある"}', '[{"options": [{"text": "「仕入れと業販出品、両方できます」と提案", "feedback": "正解！ワンプラは仕入れにも在庫処分にも使える一石二鳥のサービスです。", "isCorrect": true}, {"text": "「仕入れ専用のサービスです」と説明", "feedback": "ワンプラは仕入れだけでなく、業販出品もできます。", "isCorrect": false}, {"text": "「オークションの代わりです」と説明", "feedback": "ワンプラはオークションを「補完」するサービスで、代替ではありません。", "isCorrect": false}], "situation": "ワンプラの2つの使い方を提案", "customerLine": "仕入れルートを増やしたい、長期在庫も処分したい店舗"}]', '{"question": "ワンプラを提案する際、最も響くポイントは何だと思いますか？", "placeholder": "例：オークションで見つからない車の仕入れ先として..."}', '["手数料体系（出品成約料・落札料）を説明できるようにする", "「オークションの補完」という位置づけで提案する", "仕入れと業販の両方のメリットを伝える", "固定費ゼロで始められることを強調する"]', '{"title": "ワンプラ提案シート作成", "fields": [{"label": "ワンプラの手数料を説明してください", "placeholder": "出品成約料と落札料について説明を書いてください"}, {"label": "「仕入れ」で使うメリットは？", "placeholder": "オークションと比較したメリットを書いてください"}, {"label": "「業販出品」で使うメリットは？", "placeholder": "長期在庫処分のメリットを書いてください"}], "description": "ワンプラの提案ポイントを整理しましょう"}', NULL, '2026-02-04 03:02:42.002607+00', '2026-02-04 03:56:52.154357+00', '[{"title": "ワンプラの使い方説明練習", "dialogue": [{"line": "仕入れと業販ができます！", "speaker": "kenta"}, {"line": "もう少し具体的に。どんなお客様にどっちを勧める？", "speaker": "senior"}, {"line": "在庫を増やしたいお客様には仕入れ、在庫を減らしたいお客様には業販ですね", "speaker": "kenta"}, {"line": "そうそう！手数料体系は説明できる？", "speaker": "senior"}, {"line": "仕入れは落札料がかかって、業販は出品成約料がかかります", "speaker": "kenta"}, {"line": "いいね！手数料を払っても得になる理由も説明できるといいよ", "speaker": "senior"}], "keyPoints": ["仕入れ＝在庫を増やす、業販＝在庫を減らす", "手数料体系（出品成約料・落札料）を正確に説明", "手数料以上のメリットを伝える"], "situation": "健太が先輩に、シンフォニーワンプラの2つの使い方を説明する練習をしている場面", "seniorOpening": "ワンプラの2つの使い方、説明してみて", "successCriteria": "お客様の状況に合わせて最適な使い方を提案できるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (162, 16, '製品間連携の価値', '1+1を3にする', '{"icon": "sparkles", "name": "クロスセルマスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', '{"options": ["割引がある", "データが連携して二重入力が不要になる", "サポートが手厚くなる", "特になし"], "question": "Symphony製品を複数導入するメリットは？", "explanation": "製品間でデータが連携し、二重入力が解消されることが最大のメリットです。", "correctIndex": 1}', '{"part1": [{"title": "連携の価値を実感", "content": "3ヶ月後、山田さんの店舗を再訪問。\n\n山田さん：「田中さん、販売管理を導入してから本当に楽になったよ！」\n\n田中さん：「それは良かったです！実は今日は、さらに効果を高める提案があるんです。」\n\n山田さん：「ほう、何だい？」\n\n田中さん：「ワンプラとの連携です。販売管理の在庫データを自動でワンプラに出品できるので、業販の手間がゼロになります。」"}], "part2": [{"title": "クロスセルの成功", "content": "山田さん：「自動連携か...確かに今は手動で出品してるから面倒だったんだよね。」\n\n田中さん：「さらに、整備請求を追加すれば、販売した顧客の車検時期を自動フォローできます。リピート率が15%向上した店舗もあります。」\n\n山田さん：「車検の案内、今は手書きでやってるよ...全部連携したら、どれくらい効率上がるかな？」\n\n田中さん：「ROI試算をしてみましょう！」"}]}', '{"title": "製品連携マップ", "content": "       ┌─────────────────┐\n       │  Symphony販売管理 │ ← 中心\n       └────────┬────────┘\n                │\n     ┌──────────┼──────────┐\n     ↓          ↓          ↓\n┌─────────┐ ┌─────────┐ ┌─────────┐\n│ワンプラ │ │整備請求 │ │データ分析│\n│         │ │         │ │(将来)   │\n└─────────┘ └─────────┘ └─────────┘\n\n【連携効果】\n販売管理×ワンプラ → 在庫自動出品\n販売管理×整備請求 → 顧客情報共有\n全製品連携 → 入力作業50%削減", "audioText": "単体でも価値がありますが、連携することで価値が何倍にもなります。", "highlight": "1+1を3にする。それがSymphony連携の価値。"}', '[{"options": ["価格が安くなる", "データの自動連携で二重入力が不要になる", "サポートが手厚くなる", "機能が減る"], "question": "製品連携の効果として正しいものは？", "explanation": "製品連携により、データが自動連携され、二重入力が不要になります。", "correctIndex": 1}]', '{"text": "The whole is greater than the sum of its parts.", "author": "アリストテレス", "textJa": "全体は部分の総和以上である"}', '[{"options": [{"text": "成功体験を確認してから次の製品を提案", "feedback": "正解！現製品で成功を実感してから、次の課題解決を提案するのが効果的です。", "isCorrect": true}, {"text": "導入初日に全製品を提案", "feedback": "まずは1つの製品で成功体験を作ることが重要です。", "isCorrect": false}, {"text": "顧客から連絡があるまで待つ", "feedback": "能動的にフォローし、タイミングを見て提案しましょう。", "isCorrect": false}], "situation": "クロスセルのタイミング判断", "customerLine": "販売管理を3ヶ月利用し、効果を実感している店舗"}]', '{"question": "クロスセル提案で最も大切なことは何だと思いますか？", "placeholder": "例：お客様の課題を理解してから提案する..."}', '["まず1製品で成功体験を作ってから追加提案", "製品連携の具体的なメリットを説明できるようにする", "段階的な導入プランを提案できるようにする", "お客様の成長に合わせたタイミングで提案"]', '{"title": "クロスセル提案シナリオ作成", "fields": [{"label": "販売管理導入済み店舗への追加提案は？", "placeholder": "ワンプラまたは整備請求の提案シナリオを書いてください"}, {"label": "製品連携の具体的メリットは？", "placeholder": "数字を使って説明してください"}, {"label": "段階的導入の提案方法は？", "placeholder": "お客様の不安を和らげる提案を書いてください"}], "description": "製品連携の提案シナリオを作りましょう"}', NULL, '2026-02-04 03:02:42.002607+00', '2026-02-04 03:56:52.154357+00', '[{"title": "クロスセル提案練習", "dialogue": [{"line": "整備請求も便利ですよ、って言います", "speaker": "kenta"}, {"line": "それだと「今は必要ない」で終わっちゃう。連携のメリットは？", "speaker": "senior"}, {"line": "販売管理の顧客データと整備請求が連携して...二重入力が不要になります！", "speaker": "kenta"}, {"line": "いいね！もう一つ、顧客フォローの観点では？", "speaker": "senior"}, {"line": "販売したお客様の車検時期が自動で管理されて、フォローのタイミングを逃しません！", "speaker": "kenta"}, {"line": "そう！売って終わりじゃなく、長期的な関係構築ができることを伝えよう", "speaker": "senior"}], "keyPoints": ["二重入力不要で業務効率化", "顧客フォローの自動化", "長期的な顧客関係構築"], "situation": "健太が先輩に、複数製品の連携価値を説明するクロスセル提案の練習をしている場面", "seniorOpening": "販売管理を使っているお客様に、整備請求を追加提案するなら？", "successCriteria": "単品ではなく連携価値でクロスセル提案ができるようになろう"}]') ON CONFLICT DO NOTHING;
INSERT INTO public.session_contents (id, training_id, title, key_phrase, badge, mood_options, review_quiz, story, infographic, quick_check, quote, simulation, reflection, action_options, work, deep_dive, created_at, updated_at, roleplay) VALUES (163, 20, 'ROI計算の実践', '数字で語れば、顧客は動く', '{"icon": "target", "name": "ROI計算マスター"}', '[{"emoji": "😤", "label": "気合い十分！", "response": "その調子！今日も全力でいきましょう！"}, {"emoji": "😊", "label": "まあまあ", "response": "いい感じですね。今日の研修で更にパワーアップしましょう！"}, {"emoji": "😴", "label": "ちょっと眠い...", "response": "大丈夫、今日の研修で目が覚めますよ！"}, {"emoji": "😰", "label": "正直キツい", "response": "そんな日もある。今日の研修で少し元気になれるよ。"}]', '{"options": ["Return On Investment", "Rate Of Interest", "Revenue Of Income", "Result Of Implementation"], "question": "ROIとは何の略？", "explanation": "ROIはReturn On Investment（投資対効果）の略で、投資に対するリターンを示す指標です。", "correctIndex": 0}', '{"part1": [{"title": "ROIの重要性", "content": "田中さんは新人の佐藤さんに教えています。\n\n田中さん：「佐藤さん、ROI計算はできる？」\n\n佐藤さん：「ROI...投資対効果ですよね。なんとなくは分かりますが...」\n\n田中さん：「『いくら儲かるのか』『いつ回収できるのか』を具体的な数字で示せると、お客様の意思決定を後押しできるんだ。」"}], "part2": [{"title": "ROI計算の実践", "content": "田中さん：「例えば、在庫30台の店舗で、入力作業に1日2時間かかっているとする。\n\nSymphony導入で50%削減できれば、月20時間の削減。時給1,500円で計算すると月3万円の効果だね。」\n\n佐藤さん：「なるほど、時間を金額に換算するんですね！」\n\n田中さん：「そう。さらに在庫回転率向上による売上増も加えると、数ヶ月で投資回収できることが多いよ。」"}]}', '{"title": "ROI計算の基本式", "content": "┌─────────────────────────────────────┐\n│         ROI計算式                  │\n├─────────────────────────────────────┤\n│                                     │\n│  ROI = (効果 - コスト) ÷ コスト × 100% │\n│                                     │\n│  回収期間 = コスト ÷ 月間効果       │\n│                                     │\n├─────────────────────────────────────┤\n│         効果の算出項目              │\n├─────────────────────────────────────┤\n│  1. 時間削減効果                    │\n│     削減時間 × 時給 = 金額          │\n│                                     │\n│  2. 売上増加効果                    │\n│     成約率向上 × 平均単価           │\n│                                     │\n│  3. コスト削減効果                  │\n│     手数料削減、人件費削減など      │\n└─────────────────────────────────────┘", "audioText": "ROI計算は難しくありません。お客様の現状を聞いて、効果を数字に変換するだけです。", "highlight": "数字で語れば、顧客は動く。感覚ではなく投資として判断してもらう。"}', '[{"options": ["競合の価格", "時間削減・売上増加・コスト削減", "従業員の満足度", "会社の知名度"], "question": "ROI計算で効果を算出する主な項目は？", "explanation": "ROI計算では、時間削減効果、売上増加効果、コスト削減効果を金額換算します。", "correctIndex": 1}]', '{"text": "In God we trust; all others must bring data.", "author": "W・エドワーズ・デミング", "textJa": "神は信じる。それ以外は数字を持ってこい"}', '[{"options": [{"text": "「ROI試算では○ヶ月で回収できます」と具体的に説明", "feedback": "正解！具体的な数字でROIを示すことで、投資判断を後押しできます。", "isCorrect": true}, {"text": "「きっと元が取れますよ」と曖昧に説明", "feedback": "曖昧な説明より、具体的な数字で示しましょう。", "isCorrect": false}, {"text": "「コストの話は後で」と避ける", "feedback": "コストへの懸念には正面から向き合い、ROIで説明しましょう。", "isCorrect": false}], "situation": "顧客へのROI説明", "customerLine": "導入コストを気にしている見込み客"}]', '{"question": "ROI計算を使った提案で、最も大切なことは何だと思いますか？", "placeholder": "例：お客様と一緒に数字を確認すること..."}', '["お客様の現状を数字で把握する習慣をつける", "ROI計算シートを使いこなせるようにする", "効果の根拠（実績）を説明できるようにする", "「試算」と「実績」を区別して説明する"]', '{"title": "ROI試算練習", "fields": [{"label": "【設定】在庫20台、車両登録に1台30分かかっている店舗の時間削減効果は？", "placeholder": "計算式と結果を書いてください（時給1,500円で計算）"}, {"label": "その他に見込める効果は？", "placeholder": "売上増加、コスト削減など"}, {"label": "投資回収期間の説明方法は？", "placeholder": "お客様にどう説明するか書いてください"}], "description": "架空の店舗でROI計算を練習しましょう"}', NULL, '2026-02-04 03:02:42.002607+00', '2026-02-04 03:56:52.154357+00', '[{"title": "ROI説明練習", "dialogue": [{"line": "月額費用と削減できる時間で計算します...", "speaker": "kenta"}, {"line": "いいね！具体的な数字で説明してみて", "speaker": "senior"}, {"line": "月額3万円で、事務作業が月10時間削減。時給2000円なら2万円の削減です", "speaker": "kenta"}, {"line": "それだとマイナス1万円だね。他に効果は？", "speaker": "senior"}, {"line": "あ、売上アップ効果もあります！顧客フォローで月1台増えれば、粗利10万円で大幅プラスです！", "speaker": "kenta"}, {"line": "そう！コスト削減だけでなく売上効果も含めて計算しよう", "speaker": "senior"}], "keyPoints": ["コスト削減効果と売上アップ効果の両面で計算", "具体的な数字で説明する", "お客様の状況に合わせて試算"], "situation": "健太が先輩に、投資対効果（ROI）の説明練習をしている場面", "seniorOpening": "お客様から「費用対効果は？」と聞かれたら、どう計算する？", "successCriteria": "費用対効果を数字で説明できるようになろう"}]') ON CONFLICT DO NOTHING;
